INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (75, 8803, 'Check in with Mariam, a Tollan ally in the settlement. She might know what is causing negative rumblings. Op-CORE doesn''t need any complications from discontented Tollans.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (76, 8790, '[Player name], the Rebels are proving to be a problem for us. Use our contacts to investigate them further.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (77, 8818, 'Discover how the Rebels are supported
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (78, 8956, 'Hey, uh, [player name]. I''m glad you could come. I''ve found the location of a rebel weapon''s cache. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (79, 8962, '[Player name], I heard some disturbing rumors. The Rebels are plotting to attack the Internment camp. I''m giving this to you for free because neither of us wants Svarog''s Jaffa to stick their noses in our business. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (80, 9010, '[Player name]! I got one of the recordings that Narim''s people are passing around. I''ve already listened to this one, take it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (81, 9057, 'Some of the children were playing a little too far outside the settlement. A patrol of Svarog''s Jaffa took them. We think they''re being taken to the retreat. I don''t even want to think about what could happen there. [Player name] can you help us get them back? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (82, 9103, '[Player name.] I''m sending Bench on an intel gathering mission. I have concerns about how little we actually know about the Lucians. Go with Bench to see Machra. Make sure he doesn''t have any trouble.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (83, 9240, 'I believe we can begin by trying getting some quality of life improvements for the people. Caring for their needs wins their hearts. For me to accomplish anything with the Curia, I need the Tollan people', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (84, 9315, '[Player name]! Hey! Rinak''s got passes to Svarog''s retreat. I''ve been listening while I''ve been here at the Curia and there are some Hieroglyphs there that might give us some valuable information about Svaorg. Do you think you can Convince Coppelmann it''s worth checking out? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (85, 9372, '[Player name]! Good to see you again. Ready to get going? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (86, 9394, '[player name], I am investigating Ion Cannons for technology that Op-CORE can use. I need you to assist by checking out a number of locations', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (87, 9403, '[Player name], I believe that the Lucians might know information about the Ion Canons. They''ve been looting this planet for longer than we''ve been here after all. Op-CORE needs you to use your connections to bring me more data ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (88, 9427, '[Player name]. We have a situation and a possible solution. One of our teams was captured but the Goa''uld. They''re in Camp Barh''nur. Dr. Zuritska has also finished his weapon. We''re going to kill two birds on this one, Soldier. Get the prototype from Zuritska and get our people back.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (89, 9489, '[Player name] you got me into this mess and now you have to help. The Lucians here don''t respect me like they did Brill. Help me gain control of the Lucians on Tollana. I''ll make it worth your while.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (90, 9492, 'I need a hand, [player name]. My Boss isn''t sure I''m cut out for Brill''s job. If could get something really valuable, it''d go a lot want to proving I can take care of business here. I need something like.a Goa''uld drone. Those are valuable enough. If I can send one of those back, Natan would back off
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (91, 9505, 'Rival Lucians are muscling in on my territory. I need you to take care of them. If you steal any tech they''ve managed to grab, I''ll pay you for it. They''ve got a landing site west of the Tollan Settlement. Their drop ship should be full of technology.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (92, 9522, 'To find the Book of Gates, we''ll need Travell. Travell will need the people. Check in with her. And Mariam as well. See how Travell is doing in public opinion.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (93, 9566, '[Player name], I have a task for you. Councilmember Rinak disappears for a private meditative walk each day. I have concerns about who he may be meeting with. I worry for the people of Tollana if he is meeting with the enemy, but I need confirmation. I wouldn''t want to mistakenly accuse the council member of anything', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110765, 'I sort of sold it. But I know where you can get one. Actually it''s Morkin''s because I sold it there. It''s all a big circle. There''s a junkyard to the...', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (94, 9587, '[Player name], I have a task I would like for you to do. Though it is terrible that Rinak was willing to sell out his own people, some still cling to the misguided idea that he should be supported. They are currently holding demonstrations at his outpost. I would like you to stop them. By any means necessary. We cannot have them turn violent and spread out across the world, after all', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (95, 9596, '[Player name], there is a group of Rebels being held at Camp Barh''nur. While they are contained for now, they still pose a threat to my interests. Threats to my interests are threats to Op-CORE''s interests. I want this group eliminated, immediately and quietly.', 0, 0);
