INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (127, 102457, 'Locate the missing team members and the Superstring Resonance Inverter.', 512, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (128, 102641, 'Find out Laro''s requirements for finishing the weapon.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (129, 102697, 'Examine the damaged holorecording you''ve found.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (130, 102726, 'Resolve the problem with the Atmosphere Facility on Agnos before it''s too late.', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (131, 68068, 'Head to the Vault and find out what it holds.', 0, 0);
