INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (134, 102846, 'Collect the Inverse Straegis Crystal for Goldam.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (135, 102870, 'Remove Laro''s data blocks for Goldam', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (136, 102989, 'Go to the Vault and retrieve a power source for Goldam''s Anti-Straegis weapon', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (137, 102991, 'Get Goldam''s schematics to the Praxis and report the Straegis presence on Agnos', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (138, 103007, 'Help Goldam determine what the Straegis are doing at the Comm Grid. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (139, 103069, 'Gather a cohesive energy being sample for Goldam.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (140, 103090, 'Find out the status of Ra''s attack on the Tower of Ascendancy. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (141, 103205, 'Deprive the Straegis of parts to reassemble the Tower by taking out the Power Manufacturing Plant.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (142, 103287, 'Return to Agnos and deal with Laro''s rebuilding of the power manufacturing facility', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (143, 103296, 'Attack Laro''s repair center in hopes of drawing its energy away from the Tower.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (144, 103297, 'Attack the Straegis in order to draw them away from the Tower.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (145, 103330, 'Deliver the nanophage to destroy Laro and render the Tower useless to the Straegis', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (146, 75273, 'Figure out what Burtonol is up to on Agnos. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (147, 108598, 'Find out how Burtonol discovered the Agnos gate address. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (148, 106969, 'Recover Agnos android components for Opheltes.', 964, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (149, 107001, 'Recover organic specimens from the unusual "greenhouse" on Agnos.', 970, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (150, 107011, 'Seek out the odd plant in your vision.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (151, 107041, 'Return to Harset and make sure the plant you gave Morrigan isn''t feral.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (152, 107082, 'Recover a mature sample of the telepathic plants for future study.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (153, 107198, 'Remove Alteran remains from the stasis pods inside the Vault for genetic study.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (154, 107285, 'Loot Ancient manufacturing technology from Agnos.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (155, 107295, 'Investigate a means by which Agnos could be destroyed in a worst case scenario.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (156, 107377, 'Prepare a failsafe device so the Praxis can eliminate Agnos as a threat if required.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (157, 107388, 'Create an antidote to the controlling energies of the Plasma Creatures.', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (158, 107414, 'Thin the Straegis who''ve remained at the Tower.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (159, 75213, 'Gather Straegis "Themes" for Goldam. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (160, 108629, 'Get to the bottom of the Atmosphere plant''s failure.', 2719, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (161, 108634, 'Figure out why this node caused the failure of the Atmosphere Generators.', 587, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (162, 108635, 'Find an Energy Conditioner so you can fix the Atmosphere Generation Plant. ', 587, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (163, 107444, 'Remove the android presence from the Research Facility.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (164, 107587, 'Gather equipment for Goldam to continue his research.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (165, 107697, 'Unlock the message within this Ancient recording.', 586, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (166, 107715, 'Gain access to the Broken Holorecord''s backup by going around Goldam.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (167, 7328, 'Welcome, [Player name]. This is my son, Hasek. He will take you around the settlement.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (168, 8804, 'Hi, [Player name]! There is a meeting of Refugees nearby. Mom thought you''d want to hear. She wanted me to give you this directional mic.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (172, 109906, 'Find Zohar and recover his credentials', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (173, 109920, 'I''m always willing to help old friends like the Colonel. What can I do for you?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (173, 109921, 'I need information. We found this...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (173, 109922, 'Wow, that is quite something... Exotic, isn''t it? You know, I have seen something very similar. It''s called the Rimal and some very bad boys from the Green Boot faction took it from me. Perhaps you can help me recover my baby and we can compare the two pieces?', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (173, 109923, 'Sounds reasonable.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (173, 109924, '"Reasonable." You''ve got such a serious face all the time, don''t you? Anyway, the Green Boots are very security conscious. We''re in for a bit of luck however, because just this morning a rather brutish man named Zohar approached me, showing Green Boot credentials and looking for their base. If we could get those credentials...', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (173, 109925, 'It would make getting to the Rimal easier.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (173, 109926, 'Precisely. I sent Zohar off on a wild goose chase to a local slum - if you hurry you might still find him there...', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (177, 109927, 'Find your way into the Green Boot Basecamp.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (178, 109928, 'With those credentials you should have no trouble getting past the checkpoint at the Kassa farm. Once inside no one will bother you. If I know Netan, my Rimal will probably be stored somewhere protected by a security system.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (178, 109929, 'I can handle that.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (178, 109930, 'Be careful, $name$. Netan and his faction are very serious people. We want you coming back in one piece. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (180, 90543, 'Zohar from Pen Lai... I don''t believe we''ve ever met, but you are on my list. You''re a little late.', 211, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (180, 90544, 'I got held up.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (180, 90545, 'Netan has been looking forward to your visit. If you''d like I could take you to him...', 211, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (180, 90546, 'I know the way, thanks...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109958, 'Look what the cat dragged in... We haven''t had the pleasure, $name$. I am Netan, and we''ve been expecting you.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109959, 'Expecting me?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109960, 'Of course. You don''t think I ignore Vala, do you? She''s under constant surveillance - she''s after my Rimal. I''d be a fool to ignore a mind like hers. You learned this the hard way. Vala, bless her heart, can never be trusted. She''s put you in quite the predicament. Here you are, on my Kassa farm, trying to steal from me...', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109961, 'Awkward moment.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109962, 'Indeed. But, you''re in luck, because I actually wanted to meet you. Your organization - the Praxis - intrigues me. I think we could benefit each other. ', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109963, 'I''m listening.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109964, 'The Praxis can help me get my business to others. Simple commerce. You can arrange a meeting with your superiors...', 209, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109965, 'They wouldn''t be interested unless you can prove you can deliver.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (181, 109966, 'What if I could get you information about that technology you''re carrying? Come... let''s talk business.', 209, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (182, 8806, 'Dialogue Conversation Hasek and Disgruntled Refugee:
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (183, 110025, 'Meet with Netan''s man Kefflin in the slums.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (184, 110026, 'A former associate of mine, Podhertz, collected pieces similar to that one... A conversation with him might prove fruitful.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (184, 110027, 'Where is he?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (184, 110028, 'That''s a very good question. I have heard rumors that he is now working for my competition, the Mathas brothers. If you can help me find him, I''ll make sure you get "alone time" with him.', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (184, 110029, 'You''re sure he won''t put up a fight?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (184, 110030, 'Podhertz is an intellectual of no discernable courage. If we get to him he will try and talk his way out of it - that is a guarantee. I have a man, Kefflin, looking for him as we speak. You can work with Kefflin in his search.', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (187, 110031, 'Netan said you were coming... Finding the Mathas brothers won''t be easy. They move around a lot and hide. ', 389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (187, 110032, 'How do we get to them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (187, 110033, 'We work our way backwards. We''ll start with their dealers. They sell a lot of product in these slums... Maybe we can get some information off one of their dealers...', 389, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (188, 110035, 'This thing you found makes me think these dealers get their product from Sewer Falls... If I''m reading this right, they might actually have distribution outposts set up... They''ve really expanded their operation.', 389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (189, 8802, '[Player name]. I''d like you to go speak with Mariam. She''s our Tollan contact in the Settlement. Op-CORE''s job will be harder if the people are against us.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (190, 498, 'Give KA Bar', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (191, 110126, 'Go to Sewer Falls and dismantle the Mathas brothers'' distribution network there.', 389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (192, 110123, 'Maybe a lead on where the Mathas base is hidden could come from one of these Sewer Falls "distribution areas". You should check those out for leads... And mess them up in the process. ', 389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (192, 110124, 'What are you going to be doing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (192, 110125, 'I''m going to check out another slum to the east and see if they have cut into our operation out there. Netan isn''t going to be happy hearing that he lost Sewer Falls... ', 389, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (196, 110713, 'Clean out the Mathas brothers'' drug lab and find Podhertz', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (197, 110714, 'The documents you recovered from the distribution site indicate that the Mathas brothers'' most recent Kassa processing lab is somewhere in Sewer Falls itself. It is likely Podhertz is there, overseeing the making of the drug. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (198, 9785, 'Hmm. It seems these Rebels are at the heart of the Tollan mistrust. Good work [Player Name]
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90579, 'Don''t kill me! Please! I''m not with them! I''m an independent contractor!', 706, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90580, 'I didn''t come here to kill anyone... I came here looking for you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90581, 'You want my formulas... That makes sense. Given your... Skill set... If you''re after my formulas, I''m sure we could certainly do business together.', 706, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90582, 'I''m not interested in your ability to make drugs, Podhertz. I want you to tell me about this...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90583, 'Ra technology? That is a lovely piece... Crystalline tech design. Patently Goa''uld - they always seem to have the easiest time understanding Ra''s tech for some reason... ', 706, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90584, 'What does it do?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110766, 'A junkyard?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90585, 'Waffle maker? Ha-ha-heh... You''re not smiling. I have no idea what it does. I''ve never seen any of Ra''s technology in this condition - it''s truly amazing. You might want to run this by the Goa''uld Opheltes - the slave trader. He''s a collector. I can take you there...', 706, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90586, 'I need you to stay here. My people are on the way... I''ll need you to brief them on what went on here.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90587, 'Who are your people?', 706, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90588, 'You ask a lot of questions, you know that? ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (201, 90589, 'Sorry. I''ll just hunker down here, then... Amongst all the dead people... ', 706, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (202, 110245, 'Wait a second. You mean to tell me that you took apart the whole gang?', 389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (202, 110246, 'I left Podhertz there for you. That was our deal. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (202, 110247, 'Yes it was, $name$. Yes it was...', 389, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (203, 110715, 'Trade Vala the Rimal in order to get an audience with the Goa''uld Opheltes', 389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (204, 110716, 'Netan will want to see you...', 389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (204, 110717, 'I need to see Opheltes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (204, 110718, 'You''ll never get to him. His security is very tight. ', 389, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (204, 110719, 'I can get to anyone.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (204, 110720, 'I see that. But Opheltes isn''t a typical tough. He''s smart and his Jaffazons are fanatically loyal. Besides, he can be useful if he''s your ally. ', 389, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (204, 110721, 'How do I see him?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (204, 110722, 'Netan might know. ', 389, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (206, 110256, 'There you are! I was starting to get worried about you. You were gone such a long time I was losing hope...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (206, 110257, 'I got your jewel...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (206, 110258, 'You got the Rimal for me!!! Well aren''t you the resourceful one... Can I see it?', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (206, 110259, 'No. Not until you do something for me. I need an audience with Opheltes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (206, 110260, 'You want to see Opheltes? I can certainly arrange that. The little fellow adores me. Go on to his outpost. They''ll be expecting you. In fact, could you do me a little favor when you''re there?', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (206, 110261, 'What is it?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (206, 110262, 'Could you deliver him the Rimal - with my love, of course. It was his in the first place... ', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (207, 110273, 'Vala said you wanted to see me? This better be worth my time.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (207, 110274, 'Vala asked that I deliver this to you... With her "love".', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (207, 110275, 'Isn''t she adorable? She''s a smart one, that Vala, but she likes to live on the edge. My patience had almost waned... It would have been a terrible shame to have to have her killed... ', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (208, 3513, 'start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (209, 110723, 'Help Opheltes figure out who freed some of his slaves.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (210, 110724, 'That artifact - the Reins of the Sun Chariot - I can help you with it.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (210, 110725, 'But...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (210, 110726, 'Nothing in life is free. I recently lost some slaves to vandals. My Jaffazons, while loyal, are not effective detectives. Help me solve my slave problem and I can help you with your artifact. ', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (210, 110727, 'Define "help".', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (210, 110728, 'Do you see this?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (210, 110729, 'Where do we start?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (210, 110730, 'Make your way to the slave cages. The vandals were there just hours ago.', 399, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (213, 110731, 'Copplemann here.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (213, 110732, 'Captain, I need some help... I''m uploading data now...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (213, 110733, 'These readings imply this is an explosive... Although it''s a crude one. This is a really odd chemical mixture.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (213, 110734, 'Can we find a way to trace it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (213, 110735, 'Certainly. Uploading now... Your PDA will identify any traces of that compound on Lucia that exceeds .3 grams. ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (214, 110737, 'Evron was the culprit? Predictable. However, his death doesn''t replace my losses...', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (215, 110738, 'Go to Opheltes'' cargo container and acquire a slave injector.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (216, 110739, 'Evron''s attempts to destroy my business were minor, but there was cost. I lost two slaves from those pens. ', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (216, 110740, 'That''s not my concern...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (216, 110741, 'Actually it is. I told you that you can use my Scarab of Ra once my slave problem was solved. I chose my words carefully, for a reason. My problem is not solved. ', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (216, 110742, 'You want me to collect slaves?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (216, 110743, 'Two, to be precise. I have a pressing order due this month and I needed the two that Evron freed. The process is actually very simple. Find a target, inject them with Chemorol, and then lead them to the pens. The Chemorol makes them remarkably docile - they''ll simply follow you once injected.', 399, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (216, 110744, 'And after I gather your two slaves?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (216, 110745, 'You can use the Scarab of Ra. ', 399, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (219, 90655, 'You have proven yourself most useful. It''s time I fulfill my end of the bargain.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (220, 110746, 'Use the Scarab of Ra to analyze the Reins of the Sun Chariot.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (221, 110747, 'Are you willing to sell the Reins? I can give you almost anything you desire... Human pleasures of the flesh, money... ', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (221, 110748, 'There''s no negoatiation, Opheltes. Give me the Scarab.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (221, 110749, 'As you wish.', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (223, 110517, 'The Scarab is clearly Ra''s tech, but how it actually works is a mystery. When you place it near the Reins you begin to slowly understand - almost as if the information is being fed directly into your mind. Quickly it becomes clear that the Reins of the Sun Chariot is a tool that controls an army: An army of vast proportions. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (223, 110518, 'The moments of clarity are fleeting... The Scarab seems to respond to your questions with questions of its own. Activation of the Reins is a mystery - you get the sense that it will actually turn on at the appropriate moment. Clearly this is something you should bring to the Command Center.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (224, 3516, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (225, 3518, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (226, 110760, 'Go to the Junkyard and get Vala a Geothermal Imager.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110761, 'It just so happens that I do have a contact within Burtonol. His name is Morkin, he''s dark and handsome and dreamy... But...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110762, 'But?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110763, 'Well, he might be a bit cross with me. You see I borrowed something from him and I haven''t returned it yet.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110764, 'I''ll return it for you.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110767, 'But they have my imager... You''ll just need to find a few extra parts there - and where better to get parts than a junkyard? Simply assemble my Geothermal Imager and take it to Morkin. He''ll be puddy in your hands. Easy-peasy.', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110768, 'Vala... You test me.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (227, 110769, 'You know you love me.', 156, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (231, 110770, 'Vala Mal Doran sent you - and you''re carrying my Geothermal Imager... Of all the things I never expected to see, it was that thing again. ', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (231, 110771, 'She sends her love.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (231, 110772, 'Of course she does. Well, I appreciate the delivery... What happened to this thing, it looks like someone took a lead pipe to it?', 157, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (231, 110773, 'It''s fully functional. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (231, 110774, 'I''ll take your word for it.', 157, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (232, 110775, 'Locate blackmail material on Jordin, a local leader causing trouble for Burtonol', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110776, 'You don''t look like a typical messenger. What''s your angle?', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110777, 'I just wanted a contact with Burtonol.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110778, 'Who doesn''t? We''re the most lucrative subsidiary in the entire Tech Con family of corporations. However, we''re also the most private... We don''t let outsiders in.', 157, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110779, 'Everything I ask will be off the record.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110780, 'I doesn''t work like that. Talking to you about company business is a fast way to the unemployment line. ', 157, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110781, 'Not if I''m working for you... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110782, 'You want a job?', 157, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110783, 'If that gets me inside, yes.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (233, 110784, 'Before I can recommend you to my superiors, you need to prove yourself. Burtonol doesn''t hire chaff. There''s a do-gooder over in the Lucian Plains called Jordin. She''s stirring up trouble, rallying the locals to protect their land, that kind of stuff. Get me something useful on her - depending on how you do, I can recommend you with corporate.', 157, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (236, 110990, 'Visit Fletcher in Compost Flats for information on the Reins of the Sun Chariot', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (237, 90779, 'Fletcher is working out in Compost Flats. He''s expecting you.', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (240, 111004, 'Morkin here tells me that you have something that the company might be interested in.', 197, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (240, 111005, 'I came here for information.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (240, 111006, 'And that was a mistake, $name$, because this is going to play a little differently than you thought. You''re going to give us that fancy widget you''re carrying and then you''re going to disappear. ', 197, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (240, 111007, 'I''m sorry, $name$. The company comes first.', 157, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (240, 111008, 'I''m not giving either of you anything.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (240, 111009, 'Then this gets messy.', 197, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (241, 34507, 'Mind doing me a favor on your way through Compost Flats?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90761, 'You''re a useful character, <<Playername>>. Burtonol can use operatives like you. Beam your information over to me and I''ll see what I can do...', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90762, 'I''m in a bit of a hurry.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90763, 'People have schedules. If you don''t follow channels you will never get a job with us. We''re a process-oriented company.', 157, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90764, 'I want information, Morkin. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90765, 'Information about what?', 157, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90766, 'Crystal technology.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90767, 'That''s crystal technology.', 157, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90768, 'Your company deals in it.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90769, 'Yes, we do. I''ll tell you what... I have to put up some eviction notices on properties we''ve requisitioned. Take care of that for me and I''ll set up a meeting for you with my supervisor, Fletcher. He should be able to help you with deciphering that technology. That''s the best I can do. ', 157, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (242, 90770, 'That will work.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (246, 90771, 'Well done. I''ve set up your meeting with Fletcher.', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (247, 111010, 'See Netan about Burtonol', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (248, 111011, 'The direct approach doesn''t appear to be the most efficient way to crack the mystery of Burtonol. Perhaps Netan may have some ideas about what Burtonol is up to on Lucia...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (250, 111012, 'You should have come to me about Burtonol. I could have warned you. They are worse than any of the local factions - they''re ruthless. ', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (250, 111013, 'I just need information...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (250, 111014, 'You''ll never get anything from their people. They''re incredibly loyal - it''s like a cult. You''d have to access their property directly and hack their network.', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (250, 111015, 'If you me get inside their Campus in The Zone I can guarantee you a seat at the Praxis table.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (250, 111016, 'That would be suicide for us. Burtonol has no interest in my business - they leave my people alone. If I were to do something like that I''d be painting a target on my back. Taking on Burtonol is not good business.', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111017, 'I heard about Morkin... I hope you didn''t have something to do with that.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111018, 'How can I convince Netan to move against Burtonol? ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111019, 'Oh, he will never do that on his own. Netan is, at his core, a bit of a conservative thinker. Burtonol scares him - they scare all the faction leaders on Lucia. Unless he thought they were after him he wouldn''t... Wait a second...', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111020, 'What?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111021, 'Netan absolutely hates the Red Collar faction - a group of particularly brutish gun runners. Flax, their leader, has an outstanding bounty on Netan''s head. It''s all rather uncivil... If Netan thought that Flax and his Neanderthals were in cahoots with Burtonol...', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111022, 'He''d be forced to act.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111023, 'And I have just the thing to get him suspicious. I came across some Burtonol cargo manifests the other day - don''t ask how I got them - and I noticed that they were coming through the Spaceport. Flax''s Spaceport. ', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111024, 'This would be evidence of a relationship.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (251, 111025, 'And, since you''re going there anyway - why don''t you secure a specific shipment for me. I''ll upload the manifest number into your PDA. Call it a consulting fee. ', 156, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (252, 111029, 'Take the Manifest and the False Plans to Netan.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (253, 111030, 'While you were getting my cargo I was doing you a favor - because I adore you... I''ve made you some "plans".', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (253, 111031, 'Plans?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (253, 111032, 'Written by Flax, in his script - or as close as I could come to mimicking it. The plans detail an assault by the Red Collars on Netan with support from Burtonol... It''s all fantasy, mind you, but it is believable enough... Give him this and my cargo manifest and he''ll probably listen to anything.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (253, 111033, 'Impressive.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (253, 111034, 'I know. It''s a gift. ', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111035, 'The Red Collars control the Spaceport. But why come after me? It has to be Flax behind this. I didn''t think he was this smart... But why else would he be at the Test Fields and not secure within the Red Base itself?', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111036, 'Maybe you should hit Burtonol, preemptively?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111037, 'That''s beyond my means. If I could get to Flax it would cause turmoil in the Red Collars. I could probably fill the leadership void with one of my people. Then I''d have a real alliance to face off against Burtonol.', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111038, 'Then let''s take Flax down.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111039, 'I don''t think it can be done. I don''t have that kind of talent at my disposal.', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111040, 'You said he was vulnerable. I''ll take care of it. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111041, 'Be careful, $name$. Flax and his crew are professional killers. It won''t be easy to get in there and get to him. ', 209, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (255, 111042, 'It never is.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (257, 111043, 'I can''t believe you managed to do it. Flax is really dead?', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (257, 111044, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (257, 111045, 'Impressive, $name$. I don''t think I''ve ever met anyone quite like you before.', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (258, 111053, 'Recover the lockout keys to enable Netan''s agents to gain control of the Red Collars.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (259, 111054, 'The Red Collars are in turmoil. I''ve dispatched Rameris, one of my best, to fill the void. He''s already on the ground in their basecamp. I am worried about something, however... Kaplan.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (259, 111055, 'Who is Kaplan?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (259, 111056, 'He was Flax''s primary rival. His people are already preventing us from gaining access to much of the Red Collar infrastructure - computers, manufacturing, storage...', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (259, 111057, 'I''ll take care of it. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (259, 111058, 'Right now, Kaplan has them treating our presence as an invasion. They''re going to shoot on sight.', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (259, 111059, 'So am I.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (263, 111060, 'Rameris here, $name$... Taking heavy fire from... holding out but.... ammunition and medical supplies are...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (266, 111061, 'With Kaplan gone the rest of the Red Collars will fall in line. Rameris has already begun rounding up dissenters.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (267, 115298, 'Hack the vRip network within their base to access their intelligence files.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (268, 115299, 'I''ve been considering your Burtonol problem. There may be an indirect solution. There is a faction of technophiles on Lucia who call themselves vRip. These guys have amassed a huge cache of intelligence on Burtonol, mostly as a protection for themselves.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (268, 115300, 'Why protection?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (268, 115301, 'Tech Con Group, Burtonol - these are companies based on Hebridan. Most of the vRips are renegades from that world... There''s a natural conflict. ', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (268, 115302, 'So who do I see about accessing this intelligence?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (268, 115303, 'There''s the rub. The vRips are a rival of mine. While we''re not in open war, they won''t be open to helping you - especially since you helped turn the Red Collars over to me. You''ll have to access their network the old-fashioned way: By hacking it. I''ll download the network core''s location to your PDA. ', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (271, 115304, 'The computer is remarkably advanced. There will be no way to access the network - and the intelligence files - without first securing a biometric tag from one of the vRips. Additionally, the hooks into the system look very advanced - you''ll need some interface hardware was well. ', 1526, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (272, 115305, 'The interface is exceptionally advanced, but you soon get your bearings and move through the vRip network. The Burtonol files are extensive and it takes a while to find information on the Crystal Tech program - a program the vRips are extensively pursuing themselves. ', 1526, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (272, 115306, 'The information is scattered, but the program eminates from the Burtonol complex on Hebridan, managed by an executive scientist named Devlin. ', 1526, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (273, 115292, 'Report your discovery of Ra involvement on the world of Hebridan to the leadership council on Harset. ', 1526, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (274, 115293, 'The Crystal Technology program is being run out of Hebridan by someone named Devlin. While the vRip database didn''t have direct links into what you''ll find, it makes sense to pursue that lead. You resolve to take this information to the leadership council.', 1526, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (277, 111072, 'Approach Netan for support on an attack on the Burtonol campus facility.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (278, 3523, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115307, 'I hope that, with all this emphasis on Ra, we do not lose sight of the real threat... The Straegis.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115308, 'At this moment Ra is the real threat, Colonel. Those are his Hataks in the sky over Harset. We cannot lose sight of the present in anticipation of the future... A future which may or may not occur.', 942, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115309, 'That future is coming, Baal. Mark my words. ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115310, 'It is likely that solving the Ra question will actually strengthen our own position, Colonel. If we eliminate Ra, we can take his strength - his technology - and use it to address future concerns. ', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115311, 'We must hit Ra hard and deal him a serious blow. ', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115312, 'We do not have an army available for something so grand...', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115313, 'We could strike at the Burtonol Campus on Lucia. That won''t require much at all. We get inside, identify Ra''s Goa''uld and then use this... A symbiote suppressor. ', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115314, 'Where did you get that? ', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115315, 'We have our sources... We can use it on Ra''s minions to get details about his plan.', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115316, 'The presence of such a technology is a great concern to us, Colonel. For obvious reasons.', 942, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115317, 'The fact that you can infest any of my men with one of your snakes is a great concern to me and my people, Baal. ', 941, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115318, 'Focus! We do not have time for dalliances! In this instance, Colonel Marsh''s technology might prove useful. We can discuss the politics later. $name$, you will get into the Burtonol campus and find Rychen.', 945, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115319, 'Use the suppressor on him... If he is a Goa''uld you can make him talk...', 941, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115320, 'If he survives. About half the subjects you use that technology on will not survive it. ', 942, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (279, 115321, 'Cest la vie. We need answers. $name$, approach Netan for support. This is his moment to prove his value.', 941, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (336, 113682, 'Gather the items needed to build Rollo''s Bandersnatch in exchange for the Crystal Trinket he possesses.', 411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (280, 29157, 'Rychen provides the Player with information leading them to MagmaLife as the source of the connection between Burtonol and Ra - a project revolving around the RotSC technology', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (281, 111135, 'You plan on infiltrating the Burtonol campus? That seems rash...', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (281, 111136, 'We don''t have time to wait.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (281, 111137, 'My alliance isn''t on solid enough footing... Rameris has just recently taken hold of the Red Collars - if he was to demand they attack Burtonol he will lose them. Burtonol is still too powerful for me to take on unsupported.', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (281, 111138, 'This is your moment to prove your worth to the Praxis, Netan. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (281, 111139, 'If I do what you ask, Burtonol destroys everything I have built. I wish you well, but I cannot engage them. ', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (282, 3525, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111103, 'You want to get inside the Burtonol Campus?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111104, 'Yes. Immediately.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111105, 'Without support, that''s suicide...', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111106, 'Can you get me in?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111107, 'Of course. I''m Vala. I can do anything. I''ll upload the Campus access codes to your PDA now... I''ll miss you, $name$.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111108, 'I''ll be fine. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111109, 'If you survive this, you''ll be handing Lucia to Netan.', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (283, 111110, 'That''s not my concern.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (284, 3526, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (285, 29184, 'Thanks for letting us know that the security breach has been dealt with, but i assure you everything has been secured up here by my personal security staff.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (286, 29262, 'We''re having some environmental problems up here.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (286, 29263, '[Player suggests that Rychen comes downstairs to escape the environmental issues]', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (286, 29264, 'We''re coming downstairs, make sure that security is extra tight.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (287, 3553, 'New', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (288, 111218, 'I am free from the Symbiote... How did you?', 416, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (288, 111219, 'We don''t have much time. What is Ra doing with Burtonol?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (288, 111220, 'It''s all surrounding a project here on Lucia near the volcanoes: Magmalife. It''s a cover for his operation - it''s huge, it''s costing Burtonol billions in Naquada. His Jaffa are there now, along with our people...', 416, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (288, 111221, 'What are they doing?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (288, 111222, 'They''re building something - something expensive. They''ve infested Stewart, the Burtonol CEO, with one of Ra''s Goa''uld - they got one into most of us... I''m in a lot of pain here... ', 416, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (288, 111223, 'It''s the medicine... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (288, 111224, 'MagmaLife is the key. Ra is using his technology there - on a grand scale. And they''re almost finished... The executive consoles here - my password will give the details... I feel dizzy...', 416, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (289, 3554, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (290, 3556, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (291, 112358, 'Destroy MagmaLife, Ra''s secret project on Lucia.', 1358, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (292, 111208, 'The symbiote suppressor proved fatal for Rychen, but his information was valuable... His password opens up details to Burtonol''s massive R&D operation on Lucia: MagmaLife.', 1358, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (292, 111209, 'The project''s prototype sits atop a mountain to the north of the Zone, but getting there is far from trivial. First, the summit transporter is only accessible with a special biometric ring - only possessed by Ra''s Jaffa Prime on this world, Kal''ju.', 1358, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (292, 111210, 'Second, the summit itself is protected by a defense grid powered by geothermal conduits, which will have to be taken out to have a chance at penetrating the facility. You resolve to destroy MagmaLife with all due haste.', 1358, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (294, 90992, 'You''ve freed me from Ra''s Goa''uld... I owe you my life...', 422, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (294, 90993, 'Tell me about MagmaLife.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (294, 90994, 'It all revolves around building a portal device - insanely complex technology. He''s building this portal to be used in conjunction with something else - God only knows what.', 422, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (294, 90995, 'What will it do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (294, 90996, 'He believes it will "summon an army". I don''t know what that means, but it scares me. His crystal tech is so advanced... None of his his own Goa''uld even understand it. I don''t want to think about what he''s trying to do. Lucia and the rest of the Galaxy will be a safer place if you can manage to destroy it. ', 422, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (294, 90997, 'I''ll manage it.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (295, 3557, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (296, 3558, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (297, 754, 'New', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (298, 3559, 'New', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (299, 3560, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (300, 10001, 'I have a simple cure to treat your kassa addiction', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (301, 10002, 'I''ve come up with a cure of my own invention. It''s the only one I know of and is usually sucessful.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (302, 4923, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (303, 10003, 'Player feels like they have been cleansed of the addiction, however if they were to have to go through the experience against it would probably be more violent', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (304, 10004, 'Of course I can cure your affliction, but there is the matter of a simple fee...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (305, 10005, 'Thanks for the pleasure of your business, feel free to stop by again should you find yourself addicted again or the treatment wears off.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (306, 114022, 'Gamble in a local Kiosk with Vala''s cheating device and bring back the rewards.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (307, 114033, 'How would you like to make a lot of money?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (307, 114034, 'I''m listening. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (307, 114035, 'A certain device has come into my possession - I got it from a Hebridan businessman I met. It''s really quite handy. Basically, it guarantees that you will win when you use any of their gambling kiosks. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (307, 114036, 'Have you tried using it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (307, 114037, 'I can''t. I''m not allowed inside the gambling areas in The Zone. That''s where you come in. Test the tool for me and then we can share the winnings - I''ll give you twenty percent.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (307, 114038, 'Thirty.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (307, 114039, 'That''s extortion... Thirty percent... But... I guess you have me backed into a corner, don''t you? Thirty percent it is. Just make sure no one knows what we''re up to. Hebridanians dislike being conned. ', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91682, 'That''s amazing, the way you won both those jackpots.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91683, 'Just lucky I guess. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91684, 'Well, impossible, really. You see, that machine is rigged so that a jackpot is impossible until I say it can happen. But, whatever you''re using overrode my rigging. ', 409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91685, 'What are we going to do about that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (450, 114454, 'What was that? I thought I told you not to activate the charges! ', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91686, 'Well, we have a problem, don''t we? I can''t let you cash in my jackpot, can I? But if I expose you then there''s a process that management will go through...', 409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91687, 'And you''ll be exposed.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91688, 'So here is what we''ll do. I''m going to collect your payment and bring it to you outside The Zone, where we will split it. I''ve uploaded a safe spot on your PDA. I''ll get the payout and meet you there...', 409, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91689, 'How can I trust you to be there?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (310, 91690, 'I work here. You could always find me if I tried to swindle you...', 409, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (311, 91216, 'Coyle... I''ve met him... Handsome... He always struck me as a bit dangerous in that sexy, man-against-the-galaxy kind of way...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (311, 91217, 'Coyle''s dead. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (311, 91218, 'Yes. Well. I guess he wasn''t as dangerous as he looked? At least you came out of it unscathed. The Tech Con people will surely try and trace what happened to him - they may be looking for you. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (311, 91219, 'They aren''t the only ones. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (312, 3561, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (313, 114152, 'Meet with a gambler in the Slums to sell him Vala''s cheating device.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (314, 114041, 'There''s still money to be made from that device. If we can''t use it ourselves, we can certainly sell it. ', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (314, 114042, 'And I assume you have a buyer?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (314, 114043, 'You know me so well... You''re very attentive. My contact''s name is Corin and he is willing to take it off our hands. If you deliver it for me I''ll give you twenty percent.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (314, 114044, 'Thirty percent.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (314, 114045, 'You''re merciless.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (314, 114046, 'You could always do it yourself.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (314, 114047, 'Don''t be silly. Corin is an old friend, so this should be easy. ', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (316, 3563, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (318, 114109, 'Vala said you''d bring the device. ', 534, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (318, 114110, 'Did you bring payment?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (318, 114111, 'I''m paying you by letting you live. Hand over the device and we let you go unscathed. ', 534, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (318, 114112, 'Vala said you were an old friend.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (318, 114113, 'Tech Con Group pays more than Vala... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (319, 3564, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (320, 114104, 'This is getting disappointing.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (320, 114105, 'You''re not the one they''re shooting at.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (320, 114106, 'How about if Vala makes it all better? ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (320, 114107, 'How are you going to do that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (320, 114108, 'You can keep the gaffing device for yourself - as payment... ', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (321, 3565, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (322, 114204, 'Steal a Crystal Tech necklace from a vacationing executive.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (323, 3567, 'start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114205, 'Hello, you. Now, I know you may have lost a little faith in me but... I have something for you... ', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114206, 'But it''s not here, is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114207, 'Aren''t you cheeky? No, it''s not here, but it is on Lucia. There''s a Tech Con Group executive from Hebridan here - Jonet. She''s their liasion to Burtonol. Well, she has something with her - a necklace...', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114208, 'You want me to steal a necklace? Vala...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114209, 'Now, now, now - don''t jump to conclusions... I want you to steal it for yourself, not me... The necklace is Crystal Tech. It''s similar to your Reins there... ', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114210, 'You''ve seen it on her?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114211, 'She carries it in a crystal box, which convinces me she isn''t the brightest star in the sky... Now, I don''t know where she was off to but, I did see her talking to Dun - The Zone''s official greeter... ', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114212, 'What''s your angle on this, Vala?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (324, 114213, 'My angle? I''m offended. Not everything I do has "motives". Just promise me you''ll come back here with it when you''re done...', 156, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (327, 114265, 'Do I know you?', 418, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (327, 114266, 'No. But I am interested in your necklace.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (327, 114267, 'A lot of people are. It''s genuine Crystal Technology. Quite the specimen. Unfortunately I''ve promised this piece to someone else...', 418, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (327, 114268, 'That''s a promise you''re going to break.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (327, 114269, 'Guards!', 418, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (329, 91392, 'Did I tell you, or did I tell you? That is 100% crystal technology... ', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (329, 91393, 'I''m going to take this to my leadership...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (329, 91394, 'Before you go - can you do me a little favor? I have something I''d like you to deliver with the necklace: One for Baal, one for Colonel Marsh. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (329, 91395, 'Letters?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (329, 91396, 'Just little notes... A girl has to think about her future.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (330, 113683, 'Check Lucia for signs of the elusive Bandersnatch in exchange for one of this trader''s trinkets.', 411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113659, 'I have heard that you are a bit of an adventurer. ', 411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113660, 'I wouldn''t say that but...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113661, 'But you''re open to opportunity? I''ve heard rumors of a legendary creature here on Lucia. Fearsome, frumious and remarkably elusive. This creature - this anomaly - is known as the Bandersnatch and would be incredibly valuable to a showman like me... ', 411, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113662, 'I don''t...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113663, 'See what''s in it for you? Of course you don''t. Not yet. But what you must understand is that I can pay you. In return for this creature, you can take from my trunk of wonders any single item you like.', 411, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113664, '(He opens the box. Inside you see something that looks vaguely like the Reins of the Sun Chariot - the same technology, only smaller.)', 1417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113665, 'Anything in that box?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113666, 'Any item at all. Limit is one. No refunds. Do we have a deal?', 411, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (331, 113667, 'I''ll find you a Bandersnatch.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (332, 31709, 'Rollo is quick to think up a new economic opportunity that presents itself by having the Bandersnatch so rare that it doesn''t exist', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (333, 113668, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (334, 113669, 'The Bandersnatch? There isn''t such a thing. It''s a fake creature - Lewis Carroll made it up in one of his poems. This guy must have heard about it somehow and ran with the idea... ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (334, 113670, 'Is it possible Carroll was onto something?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (334, 113671, 'It''s possible, but unlikely. However, getting a closer look at that trinket Rollo has in his box of wonders makes me think you should keep on this. ', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (335, 113680, 'Hmmm. That''s disappointing. It''s such a great name... Bandersnatch... ', 411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (337, 113684, 'I really was hoping for a new attraction... "Bandersnatch" - the very name is a guaranteed draw...', 411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (337, 113685, 'Why does it have to be an animal? Why don''t we make one ourselves?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (337, 113686, 'I''ve got! We can make one ourselves!', 411, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (337, 113687, 'Good idea...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (337, 113688, 'I''ve had a contraption in mind for a while now... Where''s that list... Here. If you could bring me these items I could create a Bandersnatch - or something I''d call a Bandersnatch... I can smell the Naquadah now!', 411, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (338, 113689, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (339, 113690, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (340, 113691, 'These things will do just fine... I can construct something profound with this...', 411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (341, 55839, 'Help Dun by taking some of his tourists on a tour of The Zone.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (342, 91078, 'I am in terrible trouble. Terrible...', 441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (342, 91079, 'What is wrong?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (342, 91080, 'I am supposed to lead two tours simultaneously. Impossible to do. I can''t be happy-happy in two places at once, can I? ', 441, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (342, 91081, 'Can''t you find someone else to take one of the groups?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (342, 91082, 'Can you do it?', 441, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (342, 91083, 'Me?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (342, 91084, 'Yes! You''re perfect. You can be happy-happy, right? If you do this for me, I promise I''ll go the extra mile for you in return!', 441, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (345, 91093, 'Wow. You finished your tour quickly.', 441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (345, 91094, 'Happy-happy is best done quickly.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (345, 91095, 'I''ve never heard that one before, but I like it! Thank you for your help. I owe you one!', 441, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (346, 55932, 'Go to the Hotel in The Zone to meet Ganix the tourist.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (347, 91073, 'You are just the person I want to see! I have a little something you can do for me. Can you turn your happy-happy on?', 441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (347, 91074, 'I don''t have time for happy-happy.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (347, 91075, 'Do this for me and I''ll introduce you to someone with a lot of worthwhile secrets.', 441, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (347, 91076, 'I''m listening.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (347, 91077, 'There''s a tourist named Ganix. He''s a rich guy and he is after some of Lucia''s more... Mature diversions... Take him to Opheltes'' den of sin and iniquity and come back. It''s that simple.', 441, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (350, 91096, 'Did Dun tell you what I was after?', 443, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (350, 91097, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (350, 91098, 'Can you get me there discreetly?', 443, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (350, 91099, 'Of course.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (350, 91100, 'I really want to "meet" one of those Jaffazons. They''re spectacular.', 443, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (350, 91101, 'I don''t believe they are part of the entertainment.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (350, 91102, 'If there''s one thing I''ve learned in life - anything or anyone can be bought for the right price. And I''m very rich. Shall we?', 443, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91103, 'You wish to partake in discreet pleasures, Mr.? ', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91104, 'Ganix. Indeed, I am here for just such a thing. In fact... You''re a spectacular specimen yourself...', 443, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91105, 'I am not for sale.', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91106, 'Oh, come on. Anyone is for sale. And I have a lot of money. 1000 naq?', 443, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91107, 'You are insulting me, sir... ', 444, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91108, 'Oh, you''re not so easy, huh? 10,000.', 443, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91109, 'You do not understand, I am a Jaffa Warrior in service to my master... Your offers impugn my dignity.', 444, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91110, 'You don''t want to make a Jaffa mad, Ganix.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91111, 'She''s just negotiating. You are in service, huh? I''ll give you 100,000 - but you better make it memorable.', 443, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91112, 'I guarantee you will remember me, pig.', 444, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (352, 91113, 'That''s more like it... Wait... What?', 443, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (353, 91068, 'How did it go?', 441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (353, 91069, 'I left him with Illana at Opheltes'' place.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (353, 91070, 'Did he seem pleased?', 441, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (353, 91071, 'He seemed... Interested.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (353, 91072, 'Excellent. I''ve already arranged a meeting with the guy I mentioned, Sanderson. I''ll upload his location to your PDA. ', 441, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (354, 114720, 'Offer your services to Opheltes to smooth relations between him and the Praxis.', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (355, 114759, 'Word has reached me that you have made contact with Opheltes...', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (355, 114760, 'I have.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (355, 114761, 'He has his uses. Specifically he has resources. And his mind is weak. If I can bring him into the fold, he will be useful.', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (355, 114762, 'Where do I come in?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (355, 114763, 'You aren''t the brightest, are you? You must offer your services to him. Woo him, so that when it comes time to talk about alliances and trade, he is amenable. ', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (357, 91447, 'Lord Opheltes claims I must make use of you. We will begin with something simple: A pickup. The contact''s name is Jup, I have uploaded the rendezvous to your PDA. Deliver me the material and I will inform Lord Opheltes that you are not wholly worthless. ', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (357, 91448, 'What am I picking up?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (357, 91449, 'Does it matter?', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (358, 91450, 'You the buyer for Illana? Unfortunately, I have some bad news. Illana''s shipment was taken.', 211, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (358, 91451, 'Taken?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (358, 91452, 'Stolen. By some fools who work for the Mathas Brothers. I''m going to send some of my men after them.', 211, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (358, 91453, 'I can''t wait for that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (358, 91454, 'If you want to deal with them, I won''t stop you. They''ve got an encampment set up. I can identify where...', 211, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (358, 91455, 'We''ll owe you nothing.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (358, 91456, 'If you recover it from them, then the shipment is yours. Getting them out of the way solves a problem for me.', 211, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (359, 114736, 'You recovered the shipment - and we paid nothing for it? Did you harm Jup? He is a valuable contact.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (359, 114737, 'I did him a favor. He gave us the shipment in return.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (359, 114738, 'You are quite resourceful, $name$.', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (360, 114764, 'Retrieve the ransomed cargo from the Red Collar spaceport.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (361, 114765, 'We have long been in discussions with Flax and his Red Collar fools over access to their Spaceport. Recently, they have accused us of trying to get around their ridiculous useage fees. They currently are holding some rather precious cargo that Lord Opheltes has been looking forward to...', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (361, 114766, 'And you want me to recover it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (361, 114767, 'You are perfectly suited for this type of task...', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (361, 114768, 'You mean, I''m not traceable to you and your master?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (361, 114769, 'Exactly. So if you fail, it doesn''t destroy diplomatic relations. The cargo will be protected, so approach with caution. ', 444, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (364, 91485, 'Impressive. You are proving to be quite the operator.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (365, 114782, 'Secure a Tech Con Vapor Mister from the vRips.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (366, 114776, 'One of my Lord''s most impressive traits is his obsession with efficiency. Word has come that there is a device that the vRip faction has secured - a device that can distribute chemicals remotely from the sky... ', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (366, 114777, 'For farming?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (366, 114778, 'In our case we will use it to make the Lucian poor more amenable to the idea of indentured servitude. ', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (366, 114779, 'You drop chemicals on them to make them more willing slaves?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (366, 114780, 'A specific chemical... Chemorol. This device will make distribution easier. Fetch it for us. ', 444, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (367, 11207, 'Illana is glad to finally start developing a new injection as many of her Jaffa have been getting attacked as a result of injection immunities', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (370, 91510, 'Excellent! And in such good condition! Lord Opheltes will be most pleased.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (371, 11232, 'You''d be surprised what tourists will buy.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (372, 11237, 'I am willing to apprentice you and teach you the ways of a Junk Merchant - passing on the secrets of how to make money from the rich Hebridanian tourists.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (373, 11240, 'Tourists are happy to have something to take back to their kids on Hebridan', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (374, 11248, 'I''m getting old and its been one of my wishes to train a successor to carry on in this profession. Of course I''d get a share of all the goods sold by any apprentices.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (375, 11270, 'I don''t know. That doesn''t seem like anything more than junk.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (375, 11271, '[Player suggests that a child may enjoy a souvenir of a trip to Lucia]', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (375, 11272, 'I guess they would. I''ll give you half what you''re asking though.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (376, 11589, 'My Robot is malfunctioning and I''m getting burried in trash.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (377, 11607, 'My garbage drone has malfunctioned and I need someone to take care of all the waste that has been accumulating in my shop. I''m not sure my old bones will hold up during the multiple trips - would you mind taking this trash to a nearby crevice that is being used as a landfill?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (378, 11593, 'Glaz appreciates the ability to finally be able to move about his shop without running into a pile of trash', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (379, 11598, 'This trash is getting insurmountable. Damn garbage drone - its always malfunctioning.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (380, 11600, '[Robot makes a lot of noise before fizzling into a pile of useless junk]', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (381, 11603, 'Thank you, now I can move about my shop without the fear of getting buried under a pile of trash.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (382, 114339, 'Head to the Western Crevice and find Jax''s stolen Kassa.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (383, 114340, 'The Western Crevice has been deserted for some time. But the Mathas Brothers aren''t very creative, and it''s a good staging area for this type of... Operation. ', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (383, 114341, 'Where in the Western Crevice should I go?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (383, 114342, 'It''s been a really long time since I lived there and Burtonol has done a lot to the place... Let me give you my old notes... I tend to keep notes on things... Everything... Strangers... Here. They may be useful.', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (386, 91571, 'You found them? I assume they are...?', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (386, 91572, 'They will no longer pose a problem.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (386, 91573, 'The Kassa looks different. Did they do something to it?', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (387, 113260, 'Raid the Green Boot Base for advanced computer AI technology', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (388, 113274, 'The master is nearly done with his masterpiece... But it lacks one final piece... an AI module...', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (388, 113275, 'Yotho.', 1771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (388, 113276, 'Well, yes, and that master - of course we can''t forget that... My master has such a sense of humor... Netan''s Green Boots have some advanced machinery with advanced AI modules inside... An intact unit from one of these would be perfect. ', 448, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (388, 113277, 'Yotho.', 1771, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (388, 113278, 'Of course I will remember to thank the stranger, Yotho... He''s surprisingly sensitive sometimes... ', 448, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (389, 113261, 'Jayne is happy to be one step closer to creating his superweapon', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (390, 113262, 'I''ll teach those bastard for picking on me and calling me weak. I''ve come up with a plan to make a superweapon that''ll make them all jealous. If firepower is the only thing they respect than I''ll show them firepower like they''ve never seen. I only need a couple of parts to finish my baby - and that''s where you come in.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (391, 113263, 'Master - the stranger returns!', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (391, 113264, 'Yotho.', 1771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (391, 113265, 'With this device we can move to the final phase of the design... ', 448, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (392, 113279, 'Find a propulsion device for Tollak and Yotho within the vRip Base.', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (393, 113309, 'I can hear the master working... Like music.', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (393, 113310, 'Yotho.', 1771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (393, 113311, 'I''d like to speak to Yotho.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (393, 113312, 'Until he finishes his work he cannot speak. He is so completely immersed into his task he is incapable of communication with outsiders. I can translate his grumblings - but that skill has evolved over years of dedicated service. If you wish to speak with him, you must first help him...', 448, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (393, 113313, 'What does he need?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (393, 113314, 'Yotho.', 1771, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (393, 113315, 'A propulsion generator... Hebridan in design... The vRips are your most likely source... ', 448, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (394, 113287, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (395, 113288, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (396, 113289, 'Yotho! The stranger is back with your propulsion device!', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (396, 113290, 'Yotho!', 1771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (396, 113291, 'The master is pleased...', 448, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (396, 113292, 'Yotho...', 1771, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (396, 113293, 'I''m sure it was the best the stranger could do, master... ', 448, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (397, 11320, 'TCG needs your help in scouting the Red Collar spaceport and determining what cargo is being transported through it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (398, 11327, 'My name is Sanderson and I''m a junior level executive with TCG. I need to scout this Red Collar spaceport for a possible takeover. Any help you can give will be rewarded once this assignment results in my eventual promotion.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (399, 11330, 'Sanderson is more convinced than ever that this would be a great asset to TCG in its efforts to take over the world', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (450, 114455, 'I didn''t. I just placed them...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (487, 8684, 'Find Doctor Watkin in Camp Kowalski. Find out where she took my daughter, Llini.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (400, 11339, 'I''ll looking for an enterprising individual who would like to help me in my pursuit of an upper management deal. And all I need you to do is to scout around that spaceport to determine any value it might have for TCG.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (401, 11344, 'Excellent, if I can convert this asset to TCG control then I''ll be on the fast track to upper management.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (402, 114566, 'Scramble the Red Collar Spaceport''s control beacon so Sanderson and you can take it over.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (403, 114567, 'The Red Collars have run the Lucian Spaceport by default... It has been in their territory, so they have managed it, but they are incredibly inept. Most of the business that runs through there would like to see the facility under new management.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (403, 114568, 'That''s where you come in?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (403, 114569, 'Exactly. I''m going to go meet with their leadership with an offer - but before I do that, I need you to cause a little trouble for the current manager, Rowen. Make your way to the landing beacon and tweak it. This will make it look like security there is sloppy...', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (403, 114570, 'Just as you''re offering them a better option.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (403, 114571, 'Exactly. If I can mange to get control of that place I can leave Burtonol behind. I''ll give you and your Praxis 15% of everything that comes through there if we can pull this off. ', 452, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (403, 114572, 'Twenty percent.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (403, 114573, 'Fine, 20%. But it''s all a pipe dream if we can''t make it happen... So, get up there and get cracking.', 452, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (405, 91177, 'The beacon shuts down - the off-world transport has been effectively stopped.', 459, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (406, 91179, 'Nice work... Now I can head up there and do some business.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (407, 114610, 'Eliminate Rowen, the manager of the Spaceport, and blame it on the Jaffazons.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (408, 114655, 'Hopefully the Red Collars will see the need for new management after yet another gaffe by Rowen.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (408, 114656, 'We could always make sure the job is open.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (408, 114657, 'What? Like we get rid of him?', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (408, 114658, 'Why not? This is Lucia. It''s not exactly an uncommon event.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (408, 114659, 'Well, if you''re up for something like that, I''m game... We''d have to make it seem seperate from me in some way. Even the Red Collars aren''t stupid enough to promote overt assassination. We have to make it seem personal. ', 452, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (408, 114660, 'What do we know about him?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (408, 114661, 'Rowen is a very public guy... Spends a lot of time in The Zone. I''ll check his Burtonol File. Oh, this is useful: His wife recently left him because he cheated on her with a Jaffazon... I have some Jaffazon armor. Place it near him and we create some doubt about the circumstances. It''s crude, but the reference should point the Red Collars in a direction away from me. ', 452, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (410, 91204, 'The adjustment is complete - the beacon is again active.', 1420, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (412, 91206, 'You''ve been a great help... I appreciate it.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (412, 91207, 'Just remember the 20% cut...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (412, 91208, 'Don''t worry about that. I''ve learned enough to know not to cross you...', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (413, 9874, 'We need food before we starve.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (414, 9880, 'We are starving and TCG is refusing to dole out their remaining rations. We need your help to get some food.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (415, 9876, 'Wolahan is too busy eating to give a proper thanks for the player''s efforts in feeding his people (and him)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (416, 9877, 'Everyone here is starving and TCG won''t send us the proper amount of rations and it doesn''t help that those that they do send are stolen by gangs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (417, 9879, 'mmm... thanks, here''s something for your troubles... mmm...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (418, 114433, 'Collect Gang Medallions from the thugs in Sewer Falls.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (419, 114434, 'Burtonol has interest in re-developing the Sewer Falls area here in Lucia. But we have a problem - the area is infested with local gangs; so infested that we can''t get to the local populace.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (419, 114435, 'You need me to remove the gangs?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (419, 114436, 'No single person could do that - no matter how impressive their skill-set. What I need from you is simpler: Lucian gangs carry medallions which identify them to other gangs. If you can collect enough of these I can figure out how many discrete gangs we have in the area... ', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (419, 114437, 'How do I get them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (419, 114438, 'Any means necessary. The area is rife with criminals. They''ll probably come after you. No one will cry if a few of them were to cease operations. ', 452, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (422, 91119, 'As I suspected... There are at least five unique gangs at work there. This information will be very useful to corporate, nice work.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (423, 1053, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (424, 3568, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (425, 3963, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (426, 1061, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (427, 3953, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (428, 1065, 'Start Northcott', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (429, 1068, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (430, 1072, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (431, 1074, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (432, 1076, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (433, 1078, 'New', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (434, 1080, 'New', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (435, 1083, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (436, 1086, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (437, 1088, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (438, 1091, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (439, 1093, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (440, 114450, 'Deliver the Burtonol food to drop points in Sewer Falls and the Slums.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (441, 114451, 'One of the ways Burtonol secures property is through good will... Sewer Falls and Slum residents are notoriously poor. They lack basic supplies - especially food. I need you to deliver some crates of food for the locals...', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (441, 114452, 'Won''t the gangs just steal the food?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (441, 114453, 'You need to make sure that doesn''t happen... Once the citizens of the area trust the Burtonol logo, we''ll be able to offer them deals for their property and clean up the crime problem all at the same time... Everybody wins.', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (445, 91800, 'Nice work. We got the people fed and they have associated us with the good guys... that will keep them in line.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (446, 56902, 'Set up demolition charges around the Western Crevice.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (447, 91136, 'There is a plan to raze the Western Crevice area for a future expansion of The Zone - part of my milestone goals for this month. We''re going to need someone to set up a series of radio-activated demolition charges where my lead team has marked.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (447, 91137, 'You want me to set the charges?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (447, 91138, 'Please. I''ve uploaded the locations to your PDA. Do not activate them - we''ll do that remotely. I just want to get them placed so I can make my date. The company doesn''t take missed deadlines lightly.', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (450, 114456, 'Well, someone activated them - they don''t just go off themselves. And some of those houses weren''t evacuated yet... I''ve got to run a legal scrub now... This is not good, $name$. Report back here, ASAP. ', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (451, 91133, 'Turns out you were innocent. Ayr, dimwit corporate climber that he is, had his own milestone and didn''t check with anybody before he activated the charges. You''re lucky to be alive. Five minutes earlier and... Boom... ', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (451, 91134, 'Were there casualties in the crevice?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (451, 91135, 'Probably. But - thank God - they''re not my problem. Ayr can try and solve that mess.', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (452, 11504, 'I want you to steal a Comm Array from MagmaLife while you are raiding it', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (453, 11507, 'I''ve heard that you are going to raid MagmaLife and I''d like you to keep an eye out for the Comm Array that Burtonol is using there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (454, 11512, 'Vala is continually impressed with the Player''s ability to go into incredibly hostile locations and emerge alive and with something of value', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (455, 11521, 'I''ve heard through the normal channels that you''re planning a raid on that Burtonol outpost up in the mountains. Any chance you could pick something up for me while you''re up there?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (456, 11524, 'You amaze me as to how you continue to produce profitable ventures.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (457, 11526, 'I need you to deal with a deal that went south with the Jaffa General at MagmaLife', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (458, 11534, 'I had a deal going with the Jaffa General at MagmaLife that went south. Could you please talk to him to get the deal going again.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (459, 11537, 'Illana is pleased that the Player was able to complete the transaction and gives them the payment to deliver to the Jaffa General as well as a tip for acting as the middleman', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (460, 11546, 'I need your help to mediate a dispute that may have arisen when I took insult at a remark made by the Jaffa General at MagmaLife. Unfortunately I need to complete the deal we were attempting to negotiate otherwise Opheltes will take it out of my hide.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (461, 11550, 'That insolent Jaffa, how dare she insult me with her presence. No wonder she has teamed up with you to destroy my base.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (462, 11565, 'Thank you for returning with the successful conclusion of the deal. Now I can go ahead planning the destruction of that cowardly General.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (463, 11569, 'I need you to steal the recipe for a more potent Injection from MagmaLife while you are raiding it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (464, 11571, 'The Ancient Brain Scanner you picked up earlier may not provide a new cocktail recipe to keep a fresh supply of slaves in the slave pens, so I need you to pick up a copy of a recipe for a more potent Injection from Burtonol.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (465, 11575, 'Illana likes the look of this new recipe - it uses a catalyst she wasn''t familiar with to increase the potency of the Injection', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (466, 11578, 'Opheltes is always looking to increase the potency of his Slave Injection and he has heard that Burtonol is working on creating a more concentrated version of the recipe and he would like to get it to assure his monopoly.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (467, 11587, 'This Burtonol recipe shows a great amount of promise. Opheltes will be eager to start employing it to gather a new batch of slaves.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (468, 7106, 'TODO: MOVE THIS DIALOGUE TO BREADCRUMB FROM THE PREVIOUS ZONE:
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (469, 9741, 'if you''re looking for more information on this Venio, I''d try contacting Chief Zenal of the Sha, and Agent Kurr of Burtonol.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (469, 9742, 'The natives here know more than they''re letting on. They''re crafty, I give them that much. I doubt you''ll get much out of their Chief Zenal, but if you want to try, he''s here in town. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (469, 9743, 'The only guys I trust less than these Sha are those corporate goons at Burtonol, but if you can''t get what you need from Zenal, you may want to try Agent Kurr. He''s set up camp just up the hill. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (470, 6383, 'All I can offer is faith in this world. Anima Vitrus provides her beloved with treasures beyond their dreams. Perhaps she will grant you the same, like she has for Geier.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (471, 7063, 'I don''t care what you''re after, %playerRace%. This is my contract, my planet, my turf. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (472, 7132, 'The Venio, huh? This planet will tell you anything, provided you know how to listen. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (473, 9793, 'We make quite the team. I hear there''s a shrine just southeast of town. The Venio is kept there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (474, 6971, 'Search the nearby SGC Camp Frasier for the Venio.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (475, 7230, 'If this Venio is as important as you say, I''d wager the SGC is after it as well. Twenty bucks says they''re the ones who blew the shrine to kingdom come. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (476, 8876, 'They came out of nowhere... and they were already in our uniforms. They have to have someone on the inside... Get me out of here and I''ll tell you everything I know.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (477, 8877, 'They''re going to kill us all!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (478, 6917, 'If these tribals are working with the SGC, it''s likely they''ve taken the Venio deeper into the jungles. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (479, 6919, 'I''ve got a contact deep inside the SGC here. Contact her.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (480, 6923, 'My contact is a nurse working in the SGC aid station here, Nurse Collins. She''ll provide the intel you need.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (481, 8619, 'Some of the guys from the Tech Con Mines to the south came in wounded from the attacks. According to them, SG-18 is working with the tribal natives near the Tech Con outpost. Their leader, Corgan, may have more information.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (482, 8635, 'We used to make a killing out of the mines before SG-18 stirred up the Ba''taur and started all this chaos.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (483, 8634, 'Find out why Wertz is blowing up tribal villages to activate the Venio.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (484, 8633, 'I don''t know why Wertz is so obsessed with this Venio, but he''s willing to crater a village just to turn the thing on. If you''re looking for Wertz and the rest of SG-18, or if you''re looking for this Venio, I''d start at those burning huts to the west.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (485, 8632, 'You tell me. Some of my men say Wertz has been experimenting on the native children here. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (486, 8687, 'Anima Vitrus only speaks to children. What good is the Venio without a child to speak through?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (517, 96411, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (488, 8698, 'A woman of medicine, working under Wertz, has taken my daughter to the camp they call Kowalksi. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (489, 8880, 'Wertz took the girl. He had me test the children, looking for a genetic marker. She''s a genetic match, so he took her. Please, help her. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (490, 8631, 'As long as you''re killing SGC, do us both a favor and set your sights on Sgt. Nichols.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (491, 8630, 'Sgt. Nichols is the one who set off the bomb, killed those people, ruined my easy money. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (492, 8647, 'Nichols and his Ba''taur are holding ground in Camp Kowalski. If you''re looking for the rest of SG-18 and that Venio thing they''re so worried about, you''re gonna'' need to find Nichols first.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (493, 8648, 'A map of the lower wilds? Not possible. No one goes to the lower wilds except the natives.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (494, 8650, 'I have a contact, Willis, in the cliffside village of Enderweldt. See if he can help you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (495, 8708, 'Enderweldt is the end of the world - the farthest point you can travel and still make it home again. If Wertz is headed to the Lower Wilds, he''d have to pass through there first. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (496, 8709, 'You want to get to the lower wilds? We have someone who can help... but what kind of businessmen would we be if we gave that kind of information away for free? Maybe we could reach a mutually beneficial agreement.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (497, 8711, 'As promised, I''m about to let you in on our little secret.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (498, 8715, 'Talk to Amaari, he''ll lead you in the right direction.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (499, 8719, 'You''ll see soon enough. Just go talk to Amaari.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (500, 8775, 'Anima Vitrus. The planet, she speaks to me. I can hear her. She says she has been watching you. She says that you seek the Venio. She wants you to go to the Ruins of Shanti. You will find what you need there. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (501, 8791, 'I don''t know. I''ve never even heard of the Venio. Tech Con Group sent us here in search of technology... Furling technology. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (502, 8774, 'Please! You don''t understand! Anima doesn''t trust you! Anima is afraid of you. You had to save the woman. You had to show Anima that you are not here to kill her.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (503, 8798, 'These ruins, they appear to be Ancient, but many of the devices contain Furling components and technology. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (504, 6926, 'So this crystal is Furling in orgin. huh? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (505, 6929, 'Ive overheard a transmission that Wertz and his men were last seen at the ruins of Maldinor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (506, 6931, 'The ruins of Maldinor are an ancient lab southwest of Enderweldt. According to the intercepted radio broadcasts, Wertz''s men have taken the Venio and are headed in that direction. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (507, 7138, 'I got an urgent call for you. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (508, 7140, 'Willis says you''re going to want to hurry, get to Enderweldt and talk to Amaari.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (509, 5009, 'You don''t recognize the Castle guard at your feet - since he was shot in face. Not that you feel sorry for the NID bastards who work on this frozen hell. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (509, 5010, 'You see your Op-CORE comrade Corporal Frost in a nearby stasis tube. A little backup would be useful in a jailbreak.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (510, 5003, 'Through the glass of the stasis tube, you see Corporal Frost.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (510, 5004, 'You swipe the Guard''s access card to free Frost from stasis.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (511, 5031, 'Just my luck - freed from stasis but with the world''s worst migrane. Thanks for getting me out of there <playername>. You didn''t happen to bring some aspirin?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (511, 5032, 'Player: Sorry, no such luck. What with the prison break and all.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (511, 5033, 'No biggie. Its just a headache. Okay, let''s get out of here and...oh god...ARRRRGH!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (511, 5034, 'Frost drops dead from stasis shock. You need Ambernol and to find somebody who can tell you what''s going on!', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (512, 4999, 'You slot the access card and the cell door opens, freeing Prisoner 329.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (513, 5710, 'Look what the cat dragged out of an eighteen month stasis hibernation!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (513, 5711, 'Player: Shut your mouth you filthy goa''uld. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (513, 5712, 'In case you hadn''t noticed, we''re all filthy here. And you Op-CORE types are just as much prisoners as I am.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (513, 5713, 'Player: That doesn''t mean I''m going to help a treacherous alien parasite like you. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (513, 5714, 'Oh, you''ve got fire! How about this - flip that switch on my cell and I''ll tell you who broke you out of jail and why. That sounds like the kind of infomation your life could depend on!', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (513, 5715, 'Player: I don''t trust you....', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (513, 5716, 'Who said anything about "trust"? Call it "mutual self interest"', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5210, 'This is complicated and we don''t have any time. Which is ironic, I guess.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5211, 'Player: You''re me from the future?!?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5212, 'From another timeline, to be more accurate. Ask Zuritska to explain - if you can stand to be in the room with him.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5213, 'Player: Why did Op-CORE come back in time?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5214, 'Because the future is dead. We fought the most dangerous threat to this universe - and lost. You''ve got to do better than we did. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5215, 'Player: What enemy? ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5216, 'They''re called the Straegis and they''ve killed millions. They''re...it''s hard to explain...they don''t exist in this dimension the way we do and....', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5217, 'Player: what''s that noise?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5218, 'Oh, god - one of them is here. They can track us through time - I just thought I''d able to tell you more before they caught up. ', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5219, 'Get out of here - this isn''t going to be pretty. I hope you have a better death than I''m going to.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (514, 5220, 'A mysterious alien creature appears and spectacularly kills your future self. ', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (515, 5224, 'The blast door opens, revealing the Castle.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (516, 96412, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (518, 96409, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (519, 5327, 'You retrieve an Armaments Crate from the pile.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (520, 5326, '<playername>, isn''t it? I''m glad to see you - but more glad to see those weapons you brought. Now, are you ready for Op-CORE to leave the Castle?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (521, 5833, 'What are you staring at like a slack-jawed baboon! Haven''t you ever seen a man dying before!?!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (521, 5834, 'Player: Captain Coppelmann needs you over at the Commissary ASAP', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (521, 5835, 'And I need ambernol! Do you know what happens when a man is thawed prematurely from stasis?!?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (521, 5836, 'Player: Actually, I do.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (521, 5837, 'Then get me ambernol quick! And vodka!', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (521, 5838, 'Player: Vodka?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (521, 5839, 'To wash down the amerbnol!', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (522, 96878, 'You find Romney, the NID interrogator, cowering inside a laundry crate. You drag him out.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96879, 'Oh, god! Don''t kill me!', 3, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96880, 'I have my orders...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96881, 'Wait. Wait! Listen to me. I can help you get out of here! I have an override for the drones guarding the main gates. With it, you can deactivate them! ', 3, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96882, 'The combat drones?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96883, 'Yes. The ones near the gate... The override will deactivate them.', 3, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96884, 'Hand it over.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96885, 'Now you won''t kill me, right?', 3, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (523, 96886, 'I have my orders.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (524, 96887, 'This device... It will disable drones... This is victory for us. Where you get this?', 1113, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (524, 96888, 'Interrogator Romney.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (524, 96889, 'I hope you send message to that pig. ', 1113, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (524, 96890, 'Message sent.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (525, 1306, 'None.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (526, 5977, 'We''ve got a transmission. The Colonel is here. He led the attack on the Castle.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (526, 5978, 'Player: Colonel Marsh? No one''s heard from him since Op-CORE was captured by the NID.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (526, 5979, 'Well, let''s hope the Colonel''s been busy while we''ve been in here. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (527, 6011, 'Captain Coppelmann reported that you''ve been making yourself useful. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (527, 6012, 'We''ve got to secure that Stargate. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (527, 6013, 'And the Stargate is going to be heavily guarded.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (527, 6014, 'Player: That sounds like a suicide mission.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (527, 6015, 'Exactly. But no one is getting off the Castle until someone volunteers.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (528, 5564, 'You manage to shut the grid''s power off.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (529, 9036, 'The writing on this map shows that Wertz and his men are headed to the east.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (530, 9053, 'Inside the Ancient Device is a strangely pulsating crystal. It does not appear to be Ancient in origin.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (531, 8772, 'Anima cries out in pain! She is under attack! Wertz and the Ba''taur are attacking the village of Sha''hawt. They want to kill Anima! You must help her! ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (532, 8809, 'Wertz has taken control of Sha''hawt and will use the Verris crystal stored there to kill Anima. You must stop him. The Sha will provide whatever help we can.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (533, 9873, 'You have saved this world from certain death, but your journey is not yet complete. The Venio you carry is a part of Anima herself. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (534, 6933, 'Interrogate Sha Chief Zenal. Find out what you can about this Venio.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (535, 6957, 'If the SGC is working with the Natives, then the Sha Chief should have more information. He''s here in Sha''drown. Find out what he knows.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (536, 9900, '(Radio) That fool Wertz lost his command to a bunch of primitives? Hilarious. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (537, 6987, 'I can help you with many things, but not that. Takan and his brothers, they protect the shrines... but they do not speak with outsiders. They will kill you if you try to reach Takan. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (538, 1340, 'You kill my brothers and demand I give to you what you have already stolen? Are you really so weak of mind? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (539, 8980, 'There is something wrong here. Find out more about the relationship between the SGC and these primitives.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (540, 9032, 'The records are scrambled and disorganized.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (541, 9008, 'Most of the files detail SG-18''s interactions with the local tribes. The last record reports that communications specialist Wisner had established an alliance with a tribe known as the Ba''taur. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (542, 6941, 'These aren''t organized by standard protocol. It will take me a while to sort through them all. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (543, 9752, 'Investigate the surrounding area. Find anything you can about the meaning and purpose of this shrine.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (544, 6956, 'You''re right about the meaning of these symbols... Ancient, Furling, Movement. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (545, 8976, 'These pods are not natural. They almost seem to have been grown specifically to protect the Ancient devices they entwine. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (546, 9914, 'SG-18''s MALP will contain information on Wertz''s plans.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (547, 9918, 'The MALP contains the address on the last 100 addresses that Wertz and his team have dialed. The last address dialed leads to an unknown location.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (548, 9921, 'That address doesn''t look familiar. Are you sure the information you gathered is reliable? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (549, 8814, 'Take the Venio to Amaari. He will activate it for you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (550, 8817, 'Too many years and you lose the ability to listen. Anima can only be heard by the children. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (551, 8776, 'The Venio is a part of Anima. It is a map to the Sermobis, a map to her heart. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (552, 8777, 'Anima is afraid. She is afraid of you. She is angry that I helped you activate the Venio. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (553, 8847, 'What have you done!?! 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (554, 1379, 'Return to Prim Ha''tak and acquire a SIRN. Use it to scan three areas of heavy Straegis activity.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (555, 1381, 'Orbital scans report a massive Straegis presence localized in three areas near your current location. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (556, 1383, 'Radio: What''s that? The Straegis are beginning to congeal into a massive Titan? Let''s see what these things are made of.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (557, 1387, 'Radio: Bring me a crystal off one of the Straegis titans.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (558, 1389, 'According to the scans, these Titans are a congealed collection of Straegis energy.They are unlike anything we''ve seen before. Open one up and bring me what you find. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (559, 1391, 'This could be worse than we thought.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (560, 1393, 'Use a subspace tracking device to find where the Straegis are amassing.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (561, 1395, 'These Titans seem to be relaying orders to the other Straegis. They are calling the Straegis, bringing them together at the other side of that gate. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (562, 1397, 'The signal... it''s gone. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (563, 1402, 'We need someone to go through that gate. Whether you like it or not, <soldier/Jaffa/Goa''uld>, you just volunteered.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (564, 1404, 'If we don''t get to the other side of that gate, the entire universe could be torn apart, and everything we''ve fought for will be lost. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (565, 8845, 'The gate, too, is a part of Anima herself. Anima does not trust you, and so, she will not let you in. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (566, 8844, 'If you want to speak with Anima, you must use the Sermobis. That is the only way to speak to her.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (567, 8860, 'Go to the Sermobis. Speak with Anima!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (568, 8861, 'The Sermobis is said to be closest to Anima herself. It is the place where the ancestors spoke to her directly... but the altar there has been dark for decades. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (569, 9090, 'The Sermobis doesn''t respond.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (570, 9535, 'What''s the hold up? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (570, 9536, '... sounds like the recogntive splitter back on P6X-334. You should see a UIM just to the right of the front console...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (570, 9537, 'No? Well, you''re going to need to find one. The Ancient Lab you scanned before will have one, I''m certain. Get to the Lab. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (571, 9079, 'The console lights up and comes to life.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (572, 7141, 'Bring 20 M67 Grenades to Geier.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (573, 7142, 'This planet sees no end of poachers looking to make a quick buck. I keep my market more environmentally friendly by supplying the best in previously owned merchandise. Of course, certain things aren''t exactly recyclable. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (574, 7119, 'These ought to fetch a healthy price. We should do business more often.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (575, 6740, 'Bring a Gauss Flechette Rifle, and make it quick.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (576, 6742, 'I don''t expect your kind to understand the exact nuances of the Flechette Rifle, but I would expect, at the very least, the understanding that a used rifle simply will not cut it for a hunter of my caliber.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (577, 6743, 'It took you long enough. My brothers are already out there, getting rich without me.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (578, 6747, 'It''s your fault my brothers left without me. Find them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (579, 6748, 'This planet is ripe for the picking, and my brothers are picking the best parts without me, thanks to you. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (580, 9049, 'These Oranians have been trampled to death by Rhinolions. Their smashed gear has been smashed to bits.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (581, 6750, 'You found them? What are their coordinates? I can''t wait to see them again!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (582, 9121, 'Examine the necklace', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (583, 6986, 'That necklace belongs to the Ba''taur. Their name means "Enemy Within" because that is how they capture and control enemy tribes, from the inside. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (584, 9120, 'These handwritten journals were written by Colonel Wertz himself.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (585, 6954, 'I''ll get these shipped back to the Prim Ha''tak for research and analysis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (586, 9366, 'Please! Get me out of here! I''ll make it worth your time!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (587, 9365, 'It was Wisner. He spoke for the Ba''taur. He was their contact. They killed anyone who didn''t join them. I had to help them.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (588, 9364, 'Thank you. Here... it''s all I have. Please, take it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (589, 8664, 'The Ring Transporter to Sha''drown is for Tech Con Group employee use only.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (590, 8661, 'I think you people have cost us enough here. You want to use those rings, you take a crate of Verris crystal powder with you. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (591, 7067, 'What did I tell you about getting in my way? I swear to Morrigan, if you cost me one naq in payment I will have your head. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (592, 8666, 'The shipment was delivered succesfully? Excellent. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (593, 9131, 'Translate the Journals', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (594, 9130, 'These texts are instructions for the Ba''taur on how to test captives for the ATA gene. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (597, 9116, 'Analyze the purpose for this equipment', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (598, 8881, 'Find my research notes, and bring them back so others can use them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91645, 'You want me to break up with someone for you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (599, 8882, 'Before Wertz took control of my lab, we studied the genetics of the biology here. We made countless discoveries that could save lives all across the galaxy. Please, don''t let that all that work just disappear. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (600, 6953, 'Yeah, yeah... I''ll make sure this gets back to the Prim Ha''tak.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (601, 8671, 'Find out why those clowns from Burtonol aren''t finished clearing out the mines.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (602, 1500, 'So we''re right in the middle of trying to get these Verris mines off the ground when these crazy Twilla things appeared out of nowhere. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (603, 9145, 'Seedlings sprout from the corpses', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (604, 1505, 'You know... these flowers are kinda pretty. I wonder what they''ll sell for back on Hebridan.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (605, 1506, 'Clean up the mines. Maybe you can do what Burtonol couldn''t.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (606, 1509, 'I don''t see why Stewart wastes our budget on contractors that can''t even kill a couple of vegetables. Their failure is why we''re pulling out of this mess.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (607, 1511, 'We got word from corporate that we''re pulling out anyway. Thanks for the help, but there''s no use defending a mine that''ll never be opened.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (608, 1513, 'You want to know why these crystals are so valuable?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (609, 1515, 'It''s hard to explain what exactly these crystals do. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (610, 1517, 'In their raw form, these crystals aren''t too important, but we''ve got a factory back on Hebridan that purifies these things, and a purified crystal is a piezoelectric wonder of modern science. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (611, 9312, 'Analyze the Strange Alien Technology', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (612, 9313, 'The device appears to be related to the technology used in ring transporters, but it isn''t anicent in nature... it''s Furling!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (613, 9336, 'Translate the Furling Glyphs', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (614, 9337, 'The glyphs read "Our Home. Their home. Halfway home." ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (615, 8821, 'Destroy the Ba''taur weapons.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (616, 10247, 'The Ba''taur threat comes from their use of Tau''ri weapons. This threat must be stopped. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (617, 8827, 'It is actions such as these that will convince all of Anima to trust you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (618, 8941, 'You are the outsiders Anima talks about!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (619, 8938, 'You didn''t have to come. Anima would have kept me safe. She said so.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (619, 8939, '[Llini giggles.]', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (620, 8704, 'You rescued my daughter. Thank you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (621, 90531, 'Aren''t you resourceful... Let me see his credentials... This is almost too easy but... Hold still and smile.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (621, 90532, 'These look pretty good.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (621, 90533, 'I''m a girl with many talents.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (622, 9881, 'I''d suggest you go to Lucia, a world that has a lot of black market activity. It''s a good place to start looking for signs of Ra.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (623, 4552, 'Corin thanks you for your help in dealing with the scum living in the slums', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (624, 9889, 'I''m pleased to meet any friend of Sam Carter''s. How may I assist you?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (624, 9890, '[Player explains they are looking for Ra]', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (624, 9891, 'I don''t recognize that name and unfortunately I''m swamped; maybe if you helpped take some of this work off my hands I could look into the Tech Con Group Database on your behalf.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (625, 9888, 'Eamon told me you were coming; I''m Corin. Right now we''re in the process of relocating everyone in these slums to a safer place and we could really use your help.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (626, 9887, 'Burtonol scum! Why are you doing this? If you want to clean up this area you should be getting rid of the drug dealers not us!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (627, 9892, 'Excellent job on your first relocation. Normally we encounter a lot more resistance - those druggies must like you or something.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (628, 9893, 'The local drug trafficers are the ones that Burtonol wants to get rid of.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (629, 9894, 'Drugs are a huge problem in the slums and one of the biggest reasons that Burtonol is cleaning house. But Burtonol doesn''t want to put in the effort to find separate the drug dealers from the rest of the population so they''re just clearing out everyone. If you can help to stem the drug trade then maybe Burtonol won''t have a need to relocate us.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (630, 9895, 'The Abolitionist is glad to hear that you have succeeded in dealing such a huge blow to the drug trade and hope that Burtonol will take notice soon.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (631, 9896, 'Thanks for listening to our side of the story, you can find the drug dealers growing their kassa to the east of here', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (632, 9897, 'Yeah, drugs have been a huge problem in the slums and Burtonol thought it would be best if we cleaned out the whole slums to deal with the issue.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (633, 9901, 'Thanks for your help. Do you think you could use this to get Burtonol to let us stay?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (634, 9902, 'I''d suggest asking Opheltes, a local Goa''uld, about Ra since my search of the TCG Database is turning up very little. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (635, 9903, 'I''ve completed my search of the TCG Database and haven''t found anything about Ra, but I did find out that there is a Goa''uld currently operating on Lucia, name Opheltes. He might be able to provide you with more answers.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (636, 9904, 'Raully wants the Player''s help in escaping from Opheltes slave pens after he discovered her identity as a Tok''ra spy.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (637, 9905, 'I''m really sorry but the Tech Con Group Database didn''t turn up anything on Ra, but it did say that there is a Goa''uld operating here by the name of Opheltes - maybe he can answer your questions.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (638, 9906, 'The SGC doesn''t have any information on Opheltes, but I checked with the Tok''ra and they have a spy working in his operation - try making contact with her to get the answers we need. She is operating under the name of "Raully".', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (639, 9907, 'Opheltes broke my cover, get me out of here and I''ll let you know what you know.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (640, 9908, 'I would love to help you break Raully out of the slave pens.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (641, 9927, 'Breaking Raully out of the slave pens will be easy. Let''s just say I''ve had some experience with doing this before.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (642, 9923, 'The Abolitionist promises to do his best to fix Raully so that she will be in a position to answer your questions', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (643, 9924, 'Break someone out of Opheltes'' slave pens? I''d love to. But first you need to get some supplies for a homebrewed ''key'' we like to use.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (644, 9925, 'Here''s the fun part - use this mix on the fense to melt a hole in it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (645, 9926, 'Thanks for your help. I''m not sure how much longer I could''ve gone before Opheltes succeeded in torturing me to death.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (646, 2218, 'Opheltes really did a number on your friend. I''ll do my best to patch her up for you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (647, 9932, 'I need you to kill Opheltes to protect the secret of the location of a Tok''ra base before it is too late.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (648, 9937, 'I''m afraid Opheltes was able to beat the location of a Tok''ra base out of me and I need you to make sure that the secret doesn''t go any further than him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (649, 9934, 'Raully is thankful that the Player was able to silence Opheltes while she remained unable in her condition.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (650, 9935, 'I need you to do something for me that is of the gravest importance. I need you to kill Opheltes - he was able to get the location of a Tok''ra base from me during one of our lengthy torture sessions.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (651, 9936, 'You dare insult me by uttering the name of that Tok''ra in my presence! I will kill you for such insolence.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (652, 9938, 'You need to help stop the Goa''uld attack on Pen-Lai. It''s all my fault and I can''t do anything to stop them from this bed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (653, 9943, 'I sent a mesage to theTok''ra on Pen-Lai to warn them of my up. But instead I learned that a Goa''uld attack is already underway. Please go there immediately to prevent the Tok''ra from being overrun.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (654, 9940, 'O''Neill wants you to head to Pen-Lai as soon as possible to offer help to the Tok''ra there and hopefully throw a wrench into Ra''s works.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (655, 9941, 'I sent a message to my Tok''ra allies on Pen-Lai to warn them of my slip up only to learn that a Goa''uld attack is already underway. I need you to go there as soon as possible to help them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (656, 9942, 'I need you to head to Pen-Lai as soon as possible to offer help to the Tok''ra there and hopefully throw a wrench into Ra''s works.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (657, 9944, 'I found a TCG contractor who may be able to help you find a powerful technology to use against Ra.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (658, 9950, 'I searched the TCG Database for a contractor that would be able to help you find a powerful technology to use against Ra and came up with the name of someone who specializes in rare technologies - Vala Mal Doran.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (659, 9946, 'Vala admits that she is not a contractor in light of the fact that the Map was made up by the Junkyard Foreman in order to get her into a trap after she stole something from him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (660, 9947, 'I searched the TCG Database for a contractor that would be able to help you find a powerful technology to use against Ra and found someone who specializes in rare technologies by the name of Vala Mal Doran.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (661, 9948, 'I think I know just the thing - I just found out about a map to an Ancient technology cache. But unfortunately it''s being held by the Junkyard Foreman as he''s looking to take the technology for himself rather than allow anyone else to benefit from it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (662, 9951, 'I know the thing you search for, but you are not Vala. You must be one of her minions sent to kill me for it. I''ll kill you first.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (663, 9952, 'This is complete garbage. Who gave it to you, some cute girl? She sure must be good looking if she can convince you that this is worth something.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (664, 2299, 'I can''t believe he made up the map just to get me. Well actually I can and I''m a little bit flattered. He must still be aching from the time I "borrowed" some naquadah from him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (665, 9953, 'Fine, I''ll help you find someone more suited to helping you than a thief.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (666, 9954, 'Please don''t remove my listing in the TCG database, this has been a simple misunderstanding. I''ll even help you to find a suitable technology expert. That''s what you were looking for, right?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (667, 9955, 'Arlos thanks the Player for believing his take on the Red Collar faction.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (668, 9956, 'I understand you''re upset, but that''s no reason to remove my listing in the TCG Database. I''ll even show you to a more suitable technology expert, free of charge.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (669, 9957, 'I most certainly can help you find something to defeat a Goa''uld. But presently I''m engaged in a nasty war with those murderous Red Collars and that''s keeping all my suppliers focused on other things.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (670, 9958, 'TCG has been monitoring the Red Collar situation ever since I first arrived and they are ever bit as violent and brutal as Arlos makes them out to be. If you don''t believe me feel free to take a stroll towards their base - you''ll notice them as being the ones with blood stains on their clothes.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (671, 41597, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (672, 41598, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (673, 41599, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (674, 41600, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (675, 41601, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (676, 41602, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (677, 9967, 'I need more specific information about Red Collar movements before we can attack.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (678, 9973, 'I need you to track down a Red Collar who has intimate knowledge of their plans so that we can set up our defences accordingly.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (679, 9969, 'Arlos is surprised that you were able to bring someone back that was so vitally important to the Red Collar organization.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (682, 9972, 'My scout wasn''t able to gather any useful information during his jaunt to the Red Collar area but we still need to know what they''re planning.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (683, 9974, 'Who are you? What are you doing here?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (685, 9975, 'I never expected you to bring back someone so high up in their organization. Well done. For once we might be able to go on the offensive.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (686, 41607, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (687, 41608, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (688, 41609, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (689, 112226, 'The Red Collar have attached sensors to the stockpile to guard against thieves like you. Better disable it first.', 214, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (690, 112093, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (691, 112094, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (692, 112099, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (693, 112137, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (694, 9985, 'If we cause a Red Collar mutiny they won''t be in a state to hurt us.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (961, 5728, 'Player: MALP drones carry emergency medkits - I''ll be back in a minute.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (695, 9986, 'If you successfully steal the Red Collar payroll then it will be easy to convince many of the members of the faction that their leadership is losing power and they should mutiny.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (696, 9987, 'Arlos is pleased to see that the Player has dealt a blow to the Red Collars.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (697, 9988, 'If we can get the Red Collars to fight amonst themselves, then maybe that will keep them distracted enough that they won''t continue to focus their aggression on us.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (698, 9989, 'What do you mean Flax can''t pay us anymore? Then I think you''re right, we need to show him a piece of our mind.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (699, 9994, 'I want to give you a token of my appreciation for your help in defeating the Red Collars.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (701, 9993, 'Thank you for attacking the Red Collars. I want to compensate you with a set of high tech armor. I managed to get a hold of it from the R&D lab at Tech Con Group.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (702, 9995, 'Rollo is happy to part with the armor in exchange for the materials you''ve provided and he invites you to come back when his new exhibit debutes.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (703, 9996, 'Thank you for your great service to my men and myself. As a token of thanks I''d like to offer you a high tech set of armor that we acquired from TCG and were planning to use to defend ourselves against the Red Collars - until you made that unnecessary.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (704, 9997, 'Ugh, my head. Who sent you? Oh damn, yeah, the armor, about that... I might have used in a wager while playing cards last night. It was a fun party but I''m afraid its going to take me a bit to get that item back for you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (705, 9999, 'I have the armor you''re looking for. Was planning to use it for my latest project so I''m not sure I''m willing to part with it. Of course you coud provide me with other materials and I may consider it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (706, 10000, 'Yes, those things will do nicely. I suppose you''ll be wanting this armor in compensation.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (707, 2638, 'More options for zoning.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (708, 61536, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (709, 61537, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (710, 61538, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (711, 61539, 'XXX', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (712, 61540, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (713, 61543, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (714, 114788, 'Escort the slave to Sanderson as a sign of Opheltes'' fealty to Burtonol.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (715, 114795, 'I have one last task for you. I need you to deliver some product to a Burtonol agent named Sanderson. He''s in the zone.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (715, 114796, 'Product?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (715, 114797, 'This slave here. Burtonol needs it for labor.', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (715, 114798, 'You give slaves to Burtonol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (715, 114799, 'Certain candidates - off-world slaves, mostly. The locals might run away. The trade keeps their building interests to the north, instead of on our land.', 444, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (717, 6751, 'They''re dead? Are you sure? Maybe I''ll just stay in town a bit longer...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (719, 91491, 'These slaves are getting less and less impressive. Tell Illana that quality matters... I need people who can work.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (720, 9696, 'You''re right. Wertz did have contact with the Ba''taur tribe. He was practically in awe of their ability to attack an enemy from the inside.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (721, 114794, 'He claims the slaves are unhealthy? What does he expect, they''re SLAVES! Regardless... You have served me well, $name$. I will make sure that Lord Opheltes knows you have acquitted yourself and your alliance well.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (722, 91493, 'You have served me well. Opheltes has sent word of his appreciation for my gesture - the least he can do. This will bear fruit for all of us someday. Now, be gone.', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (723, 9363, 'Please! Help me!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (724, 9362, 'Wisner and those Ba''taur... they would have killed me. Thank you. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (725, 18235, 'Sabotage a Green Boot device providing Arlos with an opportunity fix it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (726, 8883, 'If this is what I think it is, this will save countless lives... but where is Dr. Watkin? Why didn''t she come with you?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (727, 11706, 'We need to show the Green Boots that the vRips are useful so I''ve come up with a plan to have you destroy an important kassa refining device so that we can repair it and show our worth.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (728, 18244, 'We are well on our way to becoming the reckoning force of Lucia.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (728, 18245, 'I wouldn''t go that far.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (728, 18246, 'What''s was that? Did I hear words just slur your mouth?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (728, 18247, 'Yes. I offered my heartiest congratulations.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (728, 18248, 'I suppose I have you to thank in some small part. Your dismantling technique was quite impressive.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (729, 11709, 'I need to show the Green Boots that we are useful perhaps if you destroy an important kassa refining device Netan will be forced to call us in to repair it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (730, 11713, 'Thank you for your help, I''ve already recieved a request from Netan to come repair the device as soon as possible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (731, 18236, 'Steal a drug from Burtonol and deliver it to the residents of the slums to garner some good will towards the vRips.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (732, 11723, 'I want you to steal an inhibitor being developed by Burtonol that will prevent Opheltes'' drug from being able to take slaves from the slum population. This inhibitor will be given to the residents of the slums to garner some good will for the vRips.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (733, 11726, 'Wolahan thanks you for your help in making sure that the general population of Lucia stays free from Goa''uld control.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (734, 11735, 'I need you to break into Burtonol and steal a drug inhibitor they are developing and pass it off to Wolahan in the Slums to make sure that we keep up good relations with the general population.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (735, 11743, 'Thank you for your help in making sure that the general population of Lucia stays free from Goa''uld control.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (736, 3259, 'Return Nichols''s Dog Tag to Dr. Benford and the SGC.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (737, 18251, 'A victim of corporate extortion, desperately needs your help.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (738, 18237, 'Malversation! Peculation! Racketeering! Do you know what these are?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (738, 18238, 'No.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (738, 18239, 'They are words!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (738, 18240, 'Yes, that much I knew.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (738, 18241, 'is under extortion. Have you had the pleasure of meeting Glaz?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (738, 18242, 'That guy who paints garbage and sells it to tourists?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (738, 18243, 'Actually, the more refined among us would prefer he be called the very master of art and commerce intermingling.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (739, 11757, 'Arlos is afraid that you may have jeopardized the relationship between Burtonol and vRips and he needs someone to help mend the situation.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (740, 11768, 'I need your help to stop Burtonol from charging protection fees to my men, but we need the situation treated carefully so as not to upset Burtonol.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (741, 8900, 'Nichols was a good man, but it times like these, even good men can lose their way. I''ll send a team out to recover the body.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (742, 11772, 'Help me, Burtonol is due here any minute and I don''t have the money to pay them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (743, 11777, 'Why isn''t my money in my hand?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (744, 11762, 'There is something suspicious about the ID Badge recovered from the Burtonol thugs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (745, 11759, 'You noticed that there was something off about these Burtonol agents charging protection money so you take their ID badges to get some answers from TCG, the employer who hired them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (746, 11804, 'Arlos is satisfied that the vRip''s relationship to Burtonol has not been tarnished', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (747, 11786, 'There is something suspicious about this ID Badge.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (748, 11793, 'After checking with the TCG computers I''ve discovered that these badges were reported stolen. Thank you for recovering them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (749, 11801, 'That''s great news. I''m glad to hear that we don''t have to expect a Burtonol attack at any moment.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (750, 18249, 'Help Arlos round up volunteers for a Burtonol top secret project.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (751, 3312, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (752, 8907, 'I''d love to give you the tour, really. But I''ve never been to Camp Frasier. You see all these patients? You see these circles under my eyes? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (752, 8908, 'Camp Frasier is south of here; just follow the signs. Good luck--this planet is deadly.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (753, 18250, 'I''ve engaged in talks with Burtonol to make sure that our relationship remains friendly and they''ve asked for help working on a top secret project.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (754, 11815, 'Arlos is uneasy about sending his men off to work on something so secretive, but he thanks you for collecting volunteers.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (755, 11824, 'We need to engage in talks with Burtonol to make sure that our relationship remains friendly', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (756, 11827, 'I''d be more than happy to work as intermediary between Arlos and Burtonol. I think its great that the residents want a peaceful relationship with our men.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (757, 11830, 'This is a happy coincidence. We need some good strong engineers to help us on a top secret project and if the vRips could provide those men then that would go a long way to starting our friendship.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (758, 11840, 'I''m not sure I like this. Giving up some of my men hardly seems worth a friendly relationship - especially if they start to ask for more.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (759, 11845, 'Sure I will volunteer for this duty for the good of our faction.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (760, 3460, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (761, 114326, 'Draw the thieves back to the Farm by harvesting more Kassa.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (762, 114327, 'Now, if you want to help me - and help Netan, because eveyone wants to help Netan, right? Because he has the GUNS... You can help me with this problem.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (762, 114328, 'What is happening?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (762, 114329, 'Thieves are getting to my Kassa almost as soon as I get it off the vine. But - hey, look at me - I''m not a FIGHTER, right? But you? You look like trouble. ', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (762, 114330, 'How do I draw them out?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (762, 114331, 'They watch the farm. So make your way there and harvest some of the Kassa. They''ll show up once you start to refine it.', 447, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (763, 8878, 'Get me out of here and I''ll tell you everything I know.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (765, 3449, 'They''re going to kill us all!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (766, 3450, 'The ones who attacked us? They came out of nowhere... and they were already in our uniforms. They have to have someone on the inside. I''ll make my way back from here. Good luck.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (768, 91550, 'Judging from these scraps the thieves are Mathas Brothers'' lackeys. Or contractors. There used to be an old hideout in the Western Crevice that the Otho Mathas built. I GUESS they could be there...', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (768, 91551, 'Why do you yell like that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (768, 91552, 'Stress. ', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (769, 4302, 'Sure, Wisner had a history of falling in with the wrong crowd. That was his midlife crisis thing. But I never thought he would commit treason.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (770, 3469, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (771, 8920, 'Camp Frasier was built to investigate the military potential of the flora and fauna of Anima Vitrus. Some pretty scary stuff there. Think Twilla vines, a hundred times stronger and under someone''s control.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (771, 8921, 'The research is located in four key areas: The Hangar, the Armory, the Motorpool, and the Hospital.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (772, 114395, 'Find a way to fix the impure Kassa for Jax.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (773, 114396, 'This crop is certainly... Not right... It smells wrong.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (773, 114397, 'Is there some way to tell if it was tampered with?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (773, 114398, 'You can use your own eyes.', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (774, 8922, 'Thanks for collecting that research. While you were working, I had time to look over the files. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (776, 3882, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (777, 4309, 'I am only chief of the Sha''drown. My people are not the keepers of the Venio. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (778, 91635, 'We agree now, right? Those PIGS were cutting my Kassa with impure supplements.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (778, 91636, 'It looks suspicious.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (778, 91637, 'There''s a woman - a CRAZY woman - named Vala Mal Doran. She might know what they have cut into my Kassa. ', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (778, 91638, 'You want me to take the sample to her?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (778, 91639, 'I cannot give Netan impure Kassa. And until I know what has been done here, I cannot begin to purify the sample... Vala is our best hope.', 447, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (779, 4311, 'Heard of Geier? You haven''t? You will. Right now. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91640, 'Hmmm. I know what they are using.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91641, 'Then you can help me...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91642, 'I could... But that wouldn''t really be fair, would it? I mean, I would have worked so hard for you and what would you have done for me? Nothing.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91643, 'What do you need, Vala?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91644, 'Oh, don''t pout. I just need you to tell a gentleman caller that I no longer wish to see him. Is that so bad?', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106114, 'What?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91646, 'He thinks we''re together, and we''re not... He just doesn''t know that last part yet. His name is Jammer. I''ve uploaded his locator to your PDA. Be gentle with him. He''s the simple type...', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91647, 'Have what I need by the time I get back.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (780, 91648, 'Of course... What kind of girl do you think I am? Wait. Don''t answer that.', 156, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (781, 114399, 'Vala sent you here to dump me? ', 461, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (781, 114400, 'Basically.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (781, 114401, 'And I''m just supposed to stand for that? She doesn''t even do it in person? She sends some lackey? I don''t get dumped...', 461, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (781, 114402, 'You just did.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (781, 114403, 'I don''t get dumped!', 461, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (782, 114404, 'How did it go?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (782, 114405, 'He tried to kill me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (782, 114406, 'He has anger issues. At first I thought it was elusive and sexy but then it became scary and annoying.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (782, 114407, 'He HAD anger problems.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (782, 114408, 'Well... That solves that then, doesn''t it. I really appreciate it, $name$... And, because I am a lady of her word, here''s the solvent you need to de-toxify the Kassa. All in a nice jug.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (782, 114409, 'Thanks Vala.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (783, 91660, 'I knew she would have something... She was probably the one they were paying to cut it in the first place... WOMEN! THEY HURT YOU!... Forget I said that. I can purify Netan''s shipment in no time...', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (784, 4071, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (785, 113227, 'Investigate the source of the Ancient energy signatures Copplemann has detected on Lucia', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (786, 113231, 'I''m getting a rather odd reading. There are ancient energy signatures coming from Lucia. They''re not consistent, but they are certainly there. I need you to investigate this - depending on what this is, it could be something good for us...', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (786, 113232, 'Or something bad.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (786, 113233, 'Exactly. It certainly isn''t something we can afford to ignore.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (787, 3540, 'The files go back to the opening of Camp Frasier, but end aburptly when Wisner leaves to meet with tribal warriors.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (788, 113239, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (789, 4072, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (790, 10092, 'Wisner reported in this morning. Find out what happened to him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (791, 8993, 'Killing Wisner provided no real information. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113240, 'Yotho! I hear visitors! Welcome friend... Yotho and I welcome you. Welcome our guest Yotho...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113241, 'Yotho.', 1771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113242, 'Obviously you have come to watch Yotho create... Often we have visitors and I live in envy of them - my blindness prevents me from fully understanding the master. He is busy constructing his latest masterpiece...', 448, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113243, 'Does his masterpiece involve Ancient Technology?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113244, 'You''d have to ask him. Except that you can''t, because he only speaks to me... And I don''t pretend to understand my master''s trade... ', 448, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113245, 'What does he make?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113246, 'Angels of death. But today he lacks the materials - despite them being so close at hand. Unexploded shells sit in that field... Yotho yearns for them, but we do not have the means...', 448, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113247, 'Yotho.', 1771, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113248, 'How many does he need?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (792, 113249, 'Three. Three shells.', 448, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (793, 113250, 'The stranger has returned, Yotho... Did you bring our bounty?', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (793, 113251, 'Three unexploded shells.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (793, 113252, 'Yotho.', 1771, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (793, 113253, 'My master thanks you.', 448, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (794, 113316, 'Go to the hidden location and view Yotho''s masterpiece.', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (795, 3597, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (796, 113317, 'The AI unit you provided is has allowed Yotho to finish his masterpiece. I will upload to your PDA the location of the device so you may witness it in all its glory... ', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (796, 113318, 'Where is this at?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (796, 113319, 'A secret location - beyond the Burtonol checkpoints deep in the Burning Hills.. above Compost Flats. Be careful as you make your way there.', 448, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (796, 113320, 'Yotho.', 1771, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (796, 113321, 'Are you sure, Master?', 448, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (796, 113322, 'Yotho.', 1771, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (796, 113323, 'He says... He has made this for you... ', 448, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (797, 3598, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (798, 7120, 'Nothin''s prettier than a fresh stack of Photon Absorption Fiber. So the Venio... It''s some sort of ancient device. Sha treat it like some holy relic, so they don''t take too kindly to outsiders gettin'' a look. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (798, 7121, 'The Venio is in a shrine outside of town. I''ve got the coordinates for you. Zanal''s right though: watch out for those Tribal Sha.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (799, 3606, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (800, 113324, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (801, 113325, 'The drone is authentic Ancient Technology, manufactured with local Lucian parts... It''s an incredible feat of engineering. It is very likely that the core technology of this drone was what caused the Ancient anomlaies on Lucia.', 643, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (802, 7122, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (803, 3615, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (804, 3617, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (805, 8947, 'Geier''s that-a-way.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (806, 7124, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (807, 3623, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (808, 7125, 'The Tribal Sha ... those so-called guardians of the Venio? They live in a village down the road, not in Sha''drown. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (808, 7126, 'Lucky for you, I have these supplies that need to get to a Tech Con trader named Corgan. That''s the man who has an "in" with these guardians. He''ll be at the Tech Con Group outpost down there. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (809, 11965, 'My people are starving and we need your help in getting some food.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (810, 4319, 'No. No. My "in" with the Sha guardians has been ruined by your people. Yes, you. You with the fancy uniforms and the catchy SGC name.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (811, 11971, 'My people are starving as the result of their TCG rations being stolen by the gangs that roam through the slums. You need to help us get some food by any means necessary.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (812, 3643, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (813, 11974, 'Wolahan is glad to finally have some food in his belly and to be able to share it with his friends.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (814, 3646, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (815, 11976, 'My people are starving, we must get food to them and quickly before they all perish. TCG has not seen fit to supply us with more rations since they were stolen by gangs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (816, 11979, 'I''m afraid that there are no more spare rations on Lucia, we must wait for another shipment to arrive from Hebridan which will take a couple of weeks. But I will rush the paperwork to try and get it here faster.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (817, 11982, 'Thank you for returning with food, my people appreciate it. And I appreciate it as well.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (818, 3663, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (819, 3665, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (820, 3667, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (821, 3669, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (822, 3671, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (823, 3673, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (824, 8676, 'We were number one in profits, thanks to the Sha. Millions of naq in business. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (825, 10241, 'The address you got leads to Vokos Primar. Go there. Find Wertz.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (826, 3695, 'The bomb crater is consistent with a large C4 charge; there should be fragments in the area from this bomb.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (827, 3680, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (828, 3706, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (829, 3686, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (830, 3730, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (831, 4075, '(Radio O''Neill) So it was an SGC bomb? Something seems... wrong. Find out what you can.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (832, 3735, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (833, 11984, 'There is an uprising underway in Compost Flats and we need everyone we can find''s help to put it down before someone gets hurt.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (834, 11986, 'There is a group of Burtonol operatives working in Compost Flats who became overrun when an uprising started in the area and we need help in putting down the rebellion before those operatives get hurt.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (835, 11988, 'Eamon appreciates your help and happily reports that the uprising has been put down.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (836, 3738, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (837, 11994, 'I require your assistance in rescuing a group of Burtonol operatives working in Compost Flats who became overrun when an uprising started in the area before those operatives get hurt.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (838, 11997, 'Thank you for your help - the uprising has successfully been put down.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (839, 114457, 'Head to Compost Flats and investigate the lost Burtonol convoy.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (840, 114458, 'There was a recent uprising in Crevice Lakes... The local citizenry there weren''t properly prepared for relocation by the company, so when the Re-lo teams arrived the slummers went a little crazy. Typically I wouldn''t care... But I had people in there. I need it checked out.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (840, 114459, 'I can handle that.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (840, 114460, 'Make your way to the last known checkpoint. My team was transporting relocation cargo. I need a recon of the area - which is probably still hostile - so keep your head down.', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (842, 91159, 'The locals probably swiped the cargo in the fight... I need it back if possible. Knowing my guys, they fought to the last - so your mission is simple recovery now.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (843, 91149, 'A close look at the cargo reveals that the locals have fashioned a crude booby-trap. ', 1418, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (844, 91150, 'The disarming process goes smoothly - allowing you to recover the cargo intact.', 1418, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (845, 113824, 'Go to the Red Collar outpost to search for Kayin.', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (846, 113834, 'There is a child I was close to called Kayin. He has gone missing... I fear he has gone up toward the Red Collar basecamp. They are notorious for "recruiting" young children for indoctrination to their ways. ', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (846, 113835, 'We must find him.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (846, 113836, 'There is a Red Collar outpost near here. You should begin your search there.', 195, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (847, 113837, 'Jordin doesn''t believe this bodes well, but it is a child in his charge and he is honor-bound to find them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (848, 113838, 'In the mud you find a stuffed bear with the word "Kayin" scrawled across the matted fur. It looks like the boy was taken after all.', 646, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (849, 113840, 'The Red Collars will have started his indoctrination almost immediately... Poor Kayin...', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (850, 113841, 'Search for Kayin deeper in Red Collar territory.', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (851, 113842, 'The child is still alive. We must move quickly. They will have taken him deeper into the Red Collar base. His life depends on you. ', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (852, 8915, 'You''ll want to go to Camp Frasier for that.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (853, 9605, 'Camp Frasier under hostile control? That doesn''t make any sense.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (854, 3812, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (855, 3809, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (856, 10087, 'Wisner reported in this morning. He gave a status report; told us the base was A-OK. Even had pancakes for breakfast.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (857, 3815, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (860, 91731, 'You are here to save me? But I like it here better than my other home. ', 647, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (860, 91732, 'You want to stay here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (860, 91733, 'Yes. They are nice to me here - and they give me toys and food... I don''t want to come with you.', 647, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (861, 8992, 'Search for more information on what is going on at Camp Frasier.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (862, 91796, 'He chooses to stay with them? Their brainwashing techniques worked quickly.', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (863, 113846, 'Return Kayin to Jordin by means of a temporary sedative.', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (864, 8995, 'Find the records on the SGC Computers.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (865, 113921, 'The brainwashing techniques they use are quick, but easily overcome. Still, the easiest solution would be for you to inject the boy with Opheltes'' "compliance" drug - a drug he uses to make slaves follow directions. ', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (865, 113922, 'Where can I find that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (865, 113923, 'Opheltes runs cargo through the Red Collar spaceport - they have an agreement. The drug is one of the things they import...', 195, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (865, 113924, 'So I can intercept some of it in the spaceport?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (865, 113925, 'Yes. Then apply the drug to Kayin. He''ll come back with you and I can start the process of healing...', 195, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (867, 9006, 'The Camp Frasier Records are kept on the SGC Computers in the Command Center.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (868, 113843, 'Jordin thanks you profusely for returning the child back to his home, even if it means months of work to return the child to their previous mental condition.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (869, 113844, 'I need you to use Opheltes'' injection to make sure that the child comes back with you this time.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (870, 8927, 'Recover weapons research at Camp Frasier.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (871, 8928, 'Zanal should have info on the Venio.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (962, 5771, 'Now that you''ve got your kit squared away, they need you in the commissary. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1224, 106370, 'Simple enough.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (872, 8933, 'I''ve been so preoccupied.. I had no idea Wertz was so obsessed with the Venio! 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (873, 113941, 'Hello again, nice $gender$.', 647, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (874, 8944, 'Geier is already waiting.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (875, 113943, 'Kayin has been returned to me... I am so pleased...', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (876, 8675, 'Investigate the supposed SGC bomb crater.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (877, 9618, 'Locate Sgt. Nichols.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (878, 4082, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (879, 9625, 'According to these records, the bomb was requisitioned in Sgt. Nichols'' name. See if your Tech Con contact... Corgan is it? ... knows anything.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (880, 4332, 'Nichols...Nichols... Yeah. He''s one of those SGC guys from Camp Kowalski. Likes to harrass the locals. He''s been dragging around a Dr. Watkin to the nearby tribes and performing tests on them. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (881, 4327, 'I can''t leave. I just can''t. It''s all my fault.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (882, 12084, 'I need you to do a final check of the homes in the Western Crevice for people... and valuables', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (883, 9626, '(Radio O''Neill) He what? Okay. It''s official. Wertz has lost it. We can''t let him kill a planet full of innocent people - I''d never hear the end of it from Daniel.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (884, 12088, 'In anticipation of razing the entire area of Western Crevice, I want you to do a final check of the homes to make sure that nothing gets destroyed that we don''t want destroyed like people or items of value.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (885, 4331, 'Wertz with the Ba''taur? Strange.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (886, 8720, 'Welcome, friend... to the end of the world.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (887, 3944, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (888, 12090, 'Burtonol Foreman doesn''t seemed concerned one way or another about whether the area is clear but once the Player has reported it is he begins preparations to start demolitions.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (889, 3962, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (890, 12092, 'I want you to conduct a quick sweep of the area to make sure that no one has wandering into our bomb range. And if you find anything that you don''t want destroyed in the blast feel free to put it in your pocket.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (891, 3960, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (892, 3958, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (893, 12094, 'Sure, I''ll take your word for it. Lets start planting explosives.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (894, 12096, 'I lost a man to Burtonol probes in the area and would like your help to gather information on his wearabouts.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (895, 12100, 'Burtonol has taken one of my men and I''d like you to break into Burtonol base at MagmaLife in order to dig up any information they might have about where they have taken him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (896, 12102, 'Jordin is grateful that the player has exceeded even his expectation and returned with his man.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (897, 12104, 'I lost one of my men to Burtonol and I need to know where they took him. Can you break into a Burtonol stronghold to get some information for me?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (898, 12106, 'What? Who are you? Can you get me out of here?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (899, 12109, 'Thank you. I never expected you to return with my man, but thank you so much.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (900, 4089, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (901, 8889, 'Get Watkin an encrypted radio from a Ba''taur.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (902, 8891, 'I want to undo what Wertz has done. I have to stay here.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (903, 4092, 'Thanks. I''ll keep you informed. Good luck... to both of us.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (904, 8721, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (905, 8727, 'The Great Amaari wants to talk to you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (906, 8728, 'No need for introductions. I work for Geier--he''s had his eye on you since you got here. Makes you feel all warm and fuzzy inside, doesn''t it?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (907, 9630, 'Anima has been watching you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (907, 9631, 'Anima can''t hear me. But I can hear her. She''s been thinking about you... a lot.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (907, 9632, 'I see... I see a vision...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (908, 8736, 'My team! They''re doomed. How did we get into this? We''re just simple archaeologists, sponsored by Tech Con. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (909, 8792, 'Thank you, oh thank you, kind stranger. You saved my life.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (910, 8765, 'The poachers did not survive.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (911, 8766, 'Do you hear? Do you hear her? Neither do I.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (912, 4103, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (913, 8898, 'Wertz has taken the Venio to the Ruins of Maldinor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (914, 8895, 'I''ve intercepted a transmission. Wertz and his men have taken the Venio to the Ruins of Maldinor. I repeat-- they''re at the Ruins of Maldinor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (915, 8897, 'Salvadar''s PDA is empty, save for some 80''s boy-band MP3s and a log that reports the mission files have been dumped to a nearby MALP. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (916, 9061, 'The MALP contains the address of the last 100 addresses that Wertz''s team has dialed. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (917, 4351, 'I entered the last gate address from the MALP into the system. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (918, 4109, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (919, 7146, 'Amaari needs you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (920, 7151, '(Geier Radio) Willis said Amaari needs you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (921, 8778, 'No!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (921, 8779, 'My mother, Nehna, is leading the battle in Sha''hawt. Please, go to her.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (922, 8838, 'So. My son has seen, and you have been sent.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1263, 107751, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (923, 4355, 'We have protected Anima, thanks to you. May she continue to watch over us.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (924, 4220, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (925, 9005, 'Bring the Venio to Amaari.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (926, 4357, 'I will breathe life into the Venio.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (927, 4358, 'So many strange visions...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (928, 8864, 'So, you have the Venio. It is as I have forseen.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (929, 8964, 'Report the Straegis presence to O''Neill.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (930, 4226, '(Radio O''Neill) Straegis? Not again. Do they really need to be everywhere? I mean that. Seriously.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (931, 4227, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (932, 4228, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (933, 4229, 'Kill a Titan.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (934, 4362, '(Radio Carter) This creature is unlike any other Straegis we''ve seen before. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (935, 4367, 'Wow. This crystal is unlike anything I''ve ever seen before. The elemental properties, the biological make-up... I could analyze this for weeks!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (936, 4232, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (937, 4233, 'Track where the Straegis are going.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (938, 9673, 'These Titans seem to be relaying orders to the other Straegis. That''s probably why the Staregis are on the move. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (938, 9674, 'You''ll need to take one of the mobile Straegis down to a subdued state. Then you can attach this Subspace Tracking Device on it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (939, 4393, '(Carter Radio) The signal is gone. It''s not on this planet; it''s not in this galaxy; it''s not in this universe. Gone. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (939, 4394, '(Jackson Radio) Listen, sorry to interrupt here. Why don''t we try talking to them? It''s not as crazy as it sounds, believe me. Or don''t believe me. Just... try it. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (939, 4395, '(O''Neill Radio) So, we''ll just *ask* them to stop destroying the universe? Can they deliver us a pizza while they''re at it?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (939, 4396, '(Jackson Radio) What?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (939, 4397, '(O''Neill Radio) What?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (939, 4398, '(Carter Radio) I just had an idea...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (940, 4238, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (941, 4239, 'Make a "mini-beacon".', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (942, 4405, '(Carter Radio) If you want to talk to the Straegis, you''ll have to block out their song. All you have to do is construct a "mini-beacon"; it should give you enough time to convince the Straegis to stop joining together.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (942, 4406, '(Jackson Radio) See? Easy. All you have to do is make a mini-beacon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (942, 4407, '(O''Neill Radio) Easy? Let''s not get carried away here.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (943, 4243, '(Carter Radio) It looks like the Straegis have adapted to block out the signal. We have no choice. We have to go through that gate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (943, 4244, '(Jackson Radio) I''ll start looking for volunteers, but going through the Meridian Gate? This could very likely be a suicide mission.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (943, 4245, '(Player) I''ll go.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (943, 4246, '(O''Neill Radio) I knew I could count on you. You remind me of me... sometimes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (944, 4248, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (945, 9004, 'Use the Venio at the gate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (946, 4253, 'Anima...she does not trust you. She will not listen. She will not let you through the gate.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (947, 8781, 'I hear Anima.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (948, 4258, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (949, 8783, 'Seek an Ancient child.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (950, 8786, 'You must seek someone else.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (951, 4409, 'I want to go.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (952, 4276, 'Start', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (953, 4281, 'Escort Blix to the Sermobis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (954, 4282, 'Can you carry me?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (955, 4286, 'Anima, hello Anima. My name is Blix.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (956, 4290, '(O''Neill Radio) You made it through. Never had a doubt in my mind. Which reminds me-- I need to call off the backup team.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (957, 9882, 'Go to Lucia and find my friend Eamon from Hebridan. He''s working with Tech Con Group on settling Lucia and converting it from its black market roots to a family friendly place. I''m sure his work would bring him information on illicit men or materials being moved around the galaxy in preparation for Ra''s return to power.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (958, 61544, 'Unused dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (959, 5675, 'Player: Cough up this vital information, goa''uld. If you''ve lied to me, I''ll shoot you where you stand.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (959, 5676, 'I wouldn''t lie to you...much. But I''m not lying about this: nearby, you''ll find someone very interesting to answer your questions. Well, interesting to *you*. They''ll help you out of this droll little dungeon we call home. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (959, 5677, 'Player: Okay, goa''uld. But if I ever see you again....', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (959, 5678, 'Oh, can you imagine? The circumstances under which you, a tau''ri human and me, a ''treacherous alien parasite'', would ever meet again? It boggles the mind!', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (960, 96414, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (961, 5725, 'Bad luck for me, huh? <cough> Caught a stray round on the way out. <groan> With my luck, it was probaby friendly fire....', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (961, 5726, 'Player: Hang on, Bench. Let me find something to stop the bleeding.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (961, 5727, 'Thanks. My mom would really hate to get my death notice. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (962, 5772, 'Player: What''s the SitRep, Sergeant?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (962, 5773, 'There''s a fireteam holding their position in the commissary. I think they''re fighting with butter knives and folding chairs. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (962, 5774, 'Player: The chow is mess is lethal but I''m thinking they''d rather have P-90s.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (962, 5775, 'My sentiments exactly <rank>. Grab an arms crate and shag it over to the commissary. Captain Coppelman is leading the team.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (962, 5776, 'Player: The Captain? Something big must be happening there - I''d better get going.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (963, 5827, 'If Op-CORE is going to get off the Castle, we need to drop the security grid.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (963, 5828, 'Player: Great, I''ll secure some C-4 and then we''ll....
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (963, 5829, 'Blow ourselves to hell?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (963, 5830, 'This requires a lighter touch <rank>. There''s a juncture that runs through a wall in the Commissary. We can short-circuit the grid there. But to do that, we need Dr. Zuritska.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (963, 5831, 'And the last time anyone saw him, he was going to be "interviewed" by that NID bastard Romney.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (963, 5832, 'Player: Understood Captain. We need Dr. Zuritska over here ASAP.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (964, 96871, 'So when they gave the order for Op-CORE to report here, the Colonel wasn''t at Alpha Site.', 1110, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (964, 96872, 'Marsh never came here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (964, 96873, 'Nope. And it has driven the NID guys nuts. He was asking everyone - Jaffa, Goa''uld - they have no idea where the Colonel went. It didn''t take long for the tactics to get dirty.', 1110, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (964, 96874, 'I remember. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (964, 96875, 'So, now we get even. Find him and let him know exactly what we think of people who torture innocent prisoners. ', 1110, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (964, 96876, 'Mercy?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (964, 96877, 'No need for it. Terminate him. ', 1110, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (965, 5900, 'This drone override is useless!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (965, 5901, 'Player: What are you talking about? It should disable the drones.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (965, 5902, 'Excuse me, who in this conversation has PhDs in Particle Physics and Information Science from the Moscow Polytechnic Universitat? ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (965, 5903, 'Player: Well, seems to me, somebody with two PhDs ought to be able to fix a drone override....', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (965, 5904, 'Ridiculous! I''d need the security protocol and without an intact encryption circuit from a drone, I couldn''t....', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (965, 5905, 'Player: Wait here....', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (966, 5911, 'Good god, how can I work under these conditions? I am a man of letters!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (966, 5912, 'I can re-route the main assmembly, but I need someone to actually cut off the power! And I cannot be in two places at once!', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (966, 5913, 'And I do not have long baboon arms to reach the power supply, no?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (966, 5914, 'Perhaps you do this simple task, yes?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (967, 5968, 'We''ve got a problem <rank>', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (967, 5969, 'Even with a disabled security grid, we''ll still need to exfiltrate to the courtyard. And those MALPs are programmed to shoot on sight. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (967, 5970, 'Somebody has to take them out or we''re going to lose a lot of people.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (968, 5991, 'We''re not getting off this planet without access to the Stargate. And the DHD controlling the Castle''s Stargate has been bypassed.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (968, 5992, 'We need the DHD back online now.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (968, 5993, 'Warden Muelbach is the one person who can make that happen.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (968, 5994, 'Do whatever you have to do <rank>.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119465, 'Your work on Dakara has presented us with this interesting opportunity, $name$. It seems that the intelligence you recovered contained a hidden gem...', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119466, 'There is a record of an Ancient Library on a world called Agnos. No one has ever heard of the place.', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119467, 'Ancient Library?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119468, 'In the data the Ancients refer to it as the "Eternal Library". It was set up as a knowledge repository. The data implies that the plague which destroyed the Ancients hadn''t yet struck this world, but was imminent.', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119469, 'It''s possible that the library was built after the Ancients ascended to their "higher plane". The ones left behind built this place as a legacy.', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119470, 'All the power of the Ancients at our fingertips... Imagine the potential...', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119471, 'You will spearhead our exploration of this world, $name$. Your mission is retrieve everything of value that we can use in our fight against the Straegis.', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119472, 'Gravity is normal on Agnos, atmosphere is breathable but there is no sign of photosynthetic activity. There is little evidence of life forms, although there seems to be a large robotic presence.', 968, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119473, 'Dead world?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119474, 'Possibly. We sent McIntyre through with an advance team - they have secured the gate and report no hostilities...', 968, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119475, 'The gravity of the situation cannot be underestimated, $name$. Because of the victory on Dakara, Ra will not relent until he has eliminated all of us. ', 942, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119476, 'I know the Straegis... Their power will grow and they will overwhelm the galaxy. More than anyone here, I know what they can do... Find a solution down there, or don''t bother coming back... McIntyre is waiting.', 941, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (969, 119477, 'I''ve uploaded everything we''ve got on the Straegis to your PDA. Good luck.', 968, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (972, 102310, 'Oh, they sent you. Welcome to Agnos! Nice to know Marsh thought somebody was qualified enough to start poking around here.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (972, 102311, 'So, what are we looking at?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (972, 102312, 'Don''t know much. Just a fixture keeping the gate warm ''til the real star showed up. And here you are. Anyway, the world isn''t as pristine as we thought...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (972, 102313, 'What do you mean?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (972, 102314, 'I''ve seen those turds from the Stargate Union mucking around, as well as some Burtonol guys... Digging into the world like buzzards on a corpse. I''d have more for you but, hey, I''m tied to the gate, right? ', 404, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (973, 102332, 'Agnos basics: These androids seem friendly, if a little dense. The ones further to the south, eh, not so nice. This is apparently the "safe zone" for travelers, so I''ve dubbed it "Agnos City".
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (973, 102333, 'Creative. I''ll start with these bots...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (974, 71239, 'Scanning... Greetings, Primitive Gate-Traveler to the world of Agnos! How may I assist you?', 405, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (974, 71240, 'I''m not sure...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (974, 71241, 'Greetings Primitive Gate-Traveler to the world of Agnos. How may I assist you?', 405, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (974, 71242, 'Who''s in charge here?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (974, 71243, 'Due to hospitality system restrictions, all inquiries of that nature must be made via LARO at a LARO Hub Interaction Terminal.', 405, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (974, 71244, 'One nearby?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (974, 71245, 'Locate any LARO Hub Interaction Terminal, Primitive Gate-Traveler! And thank you for visiting Agnos!', 405, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71295, 'Welcome primitive gate-traveler, what is your request?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71296, 'You''re LARO? Hub Interaction Terminal?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71297, 'I am a LARO Hub Interaction Terminal; a direct communications channel to LARO, the principle operating system of Agnos.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71298, 'I''m looking for a weapon.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71299, 'Your UICP is not cleared to access weapons data.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71300, 'UICP?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71301, 'Your User Intellectual Capacity Profile is a measure of your intellectual capacity. Your profile has been flagged as incompatible.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71302, 'This can''t be serious.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71303, 'Your UICP is not qualified to access that information. ', 417, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71304, 'Fine. How can I increase my profile?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (975, 71305, 'Please stand by. Processing...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (976, 66715, 'The UICP scanning routine evaluates your intellectual capacity, assigning you a UICP rating. You are attempting to upgrade your current UICP rating.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (976, 66716, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (976, 66717, 'This automated test will examine the evolution of your brain function. This is designed to ensure a safe and appropriate distribution of information to primitive and intellectually under-evolved species. Your current rating is: Primitive. Please proceed to scanning dome. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (977, 109603, 'Congratulations. This unit has received enough data to calculate your rating. Your UICP has been raised by 40,000 standard points. Your new UICP rating is: Intellectuallty Under-Evolved. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (977, 109604, 'Great. Now tell me about weapons.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (977, 109605, 'Your rating does not allow for access to any library data. Please return when your species has further evolved. The calculated time of evolution is a mere 130,020 years. Enjoy the remainder of your stay on Agnos!', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (978, 102339, 'Clearly attempting to access this machine directly is going nowhere. However, no matter how advanced a machine is, it is still a machine. It must be possible to break in somehow...', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (979, 102340, 'The hub itself is just a terminal - a part of a larger network connected to a single data source. The only difference is that the construction is light-years more advanced. However, since all of the data comes from somewhere, you should be able to access it directly, perhaps through a nearby substation.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (980, 102347, 'It''s possible you can directly access the system from here, but you lack proper interface access... It is likely you can salvage the proper access hardware from one of the nearby androids.', 428, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (981, 102351, 'You''re inside and you begin to access your UICP rating data - within seconds you update your profile to "Advanced Intellectual Evolution." Just as you complete the process you receive an error:
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (982, 102349, 'Another success but again quickly followed by an error:
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (983, 102350, 'Finally! You have artificially raised your UCIP to the maximum level. Now, all that is left is to find a hub.', 428, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70662, 'Accessing Core Library... Core Library accessed.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70663, 'I need information on weapons - manufacturing, technology, implementation...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70664, 'You are deeply in error if you believe your previous efforts circumvented my systems. You have merely succeeded in drawing my conscious process to this terminal.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70665, 'Conscious process?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70666, 'I am Laro, the Artificial Intelligence entrusted with monitoring and protecting Agnos. You were previously interacting with my automated systems.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70667, 'So you''re the real Laro?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70668, 'I was entrusted by those you call the Ancients to run Agnos in their absence and await the coming of a people suited to receive their knowledge. Based upon your actions, I can tell for certain you are not of that people.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70669, 'Surely they didn''t program you to stand by while millions die...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (984, 70670, 'My protocols are very specifically focused on the function and preservation of this world. However, it is possible that the death of millions of primative humans may affect Agnos. I am open to hearing about what you seek and why.', 428, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102364, 'I have scanned your primitive Personal Digital Assistant...', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102365, 'My PDA?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102366, 'There is much data in there about recent contact with an alien race. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102367, 'The Straegis - they are exactly what I...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102368, 'Do you have physical materials with you that I can analyze? ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102369, 'Physical materials?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102370, 'Samples from these creatures for analysis. Additionally, according to your data the entity Ra has accessed these creatures using technology. An analysis of this technology would also be helpful. ', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102371, 'I don''t have Straegis samples, but I do have a sample of Ra''s tech... The Reins of the Sun Chariot.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (985, 102372, 'Deliver this Reins of the Sun Chariot technology to Analysis Chamber E4B342 for scanning.', 417, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (986, 102377, 'The machine looks simple enough - if you were an Ancient. Instead you''ll have to figure out how it works in order to have the Reins of the Sun Chariot analyzed. ', 2697, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (987, 67053, 'Processing Reins of the Sun Chariot data. Please wait.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (987, 67054, 'I thought you were advanced...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (987, 67055, 'Command directive: Threat investigation sub-routines activated. These samples are very interesting. I am devoting several expert system sub-nodes to the processing of this information. Be patient, sub-intellectual human.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (987, 67056, 'So there''s something there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (987, 67057, 'These samples are from an advanced technology which could represent a threat to a primitive culture such as yours. I will look into your problem while you assist me with some minor logistical tasks.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (987, 67058, 'Fine, but I don''t have much time.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (987, 67059, 'I am already processing potential solutions to your problem. Your access priority has been raised. You will now access me directly through any LARO hub interface.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103127, 'You''re just going to trust her?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (988, 6249, 'As you may or may not know, the Ancients prior to their evolution to another state of existence prepared several repositories of knowledge to bequest to the worthy races that followed them. I am the largest and most complete of those repositories.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (988, 6250, 'But due to some form of archival error by my creator, there are significant gaps in my knowledge of my own systems and creation. I believe the current situation calls for seeking out that knowledge from another repository.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (988, 6251, 'You are perhaps familiar with the meditative enclave known as Kheb. The volume I seek is known there as the Codex Volutare. Retrieve it for me and I will make you a weapon to combat the Straegis.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (989, 6256, 'It may look like a simple text to you, but the Ancients taught that true wisdom transcends physical forms. Now we can get down to business.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (990, 102379, 'Devising a solution to your problem is a menial task for my advanced system. However, additional tools are required. The first component is a Pan-Dimensional Sifter. You will find one in the storage bay, north. Remove all errant droids obstructing your way. I will manufacture more once disruptions have stopped.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (990, 102380, 'What disruptions?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (990, 102381, 'Errant activity of other primitive gate-travelers.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (990, 102382, 'Can you identify who?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (990, 102383, 'Processing... Members of an alternative primitive tribe. Hostile in nature. Additional information unavailable at this time.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (991, 67069, 'This is sufficient for the moment. However, there are more items to gather.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (992, 102419, 'Look, if we keep killing each other, none of us come out ahead. ', 438, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (992, 102420, 'I''m mostly killing you guys...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (992, 102421, 'Maybe, but we''ve got everything of value from that place - and we''re not afraid to destroy all of it... ', 438, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (992, 102422, 'I''m listening. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (992, 102423, 'Get us past those androids and we''ll give you whatever you want - within reason.', 438, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (993, 102416, 'Thanks for the help. You were very useful...', 1840, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (993, 102417, 'Were?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (993, 102418, 'You''re in the way, <player name>. It''s just business, nothing personal.', 1840, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102589, 'The Pan-Dimensional Sifter will identify which elements of the Straegis I require. The details of this technology are beyond your comprehension, but the device is simple - even by your standards. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102590, 'Limited as they are...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102591, 'You should not denigrate your intellectual capacity, $name$. Your evolutionary limitations are beyond your control. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102592, 'I was being sarcastic.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102593, 'Sarcasm is a sign of limited evolution. Once you have acquired what is needed, use the Jorunni Aligner and the Superstring Resonance Inverter to purify the sample. Then return to Agnos. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102594, 'I just need to find Straegis now...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102595, 'If what you say about a Galactic threat is true, this should be a simple task requiring only patience. That may prove difficult for you.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102596, 'Is patience another sign of intellectual evolution?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (994, 102597, 'No, $name$, patience is a sign of intellectual maturity. ', 417, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (995, 67638, 'The processor is easy enough to use... But it takes time... Eventually the readouts imply that you need "Wavelength Kappa" Straegis. The sifter is set to automatically cull Straegis remains (shards) that match this wavelength designation. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (996, 67756, 'Your return was greatly anticipated. We have completed this component. My scans of the crystal indicate it is less than 1% off of predicted parameters. Notice how the lattice continuously unravels its own fractal pattern?', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (996, 67757, 'I think so...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (996, 67758, 'This will eventually cause a bending inward of the crystal itself, causing a dimension shift and destruction. This information will prove remarkably useful in your fight against the Straegis.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (997, 102425, 'My plan involves reversing Straegis energy... According to your UICP, you cannot comprehend the details of the device I am creating. I will simply construct it. I require one Joruuni Aligner. My inventory reports only one in stock - unless destroyed.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (997, 102426, 'Destroyed?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (997, 102427, 'Affirmative. Although destruction is of a low probability. The Emergency Response Center where it was stored has been a primary target of recent attacks.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (997, 102428, 'Attacks by who?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (997, 102429, 'Data unavailable. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (998, 102437, 'You''ve located the correct container for the Joruuni Aligner, but it''s empty, save for a small data recording. This could prove useful at some point... Maybe you''ll show it to Laro.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (998, 102438, 'The androids are pillaging items to use as defense. It''s possible that they could''ve mistaken the Joruuni Aligner for just another weapon.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (999, 102432, 'As my systems predicted, you are highly resourceful with the hunt and the gather. There is one final component required for device assembly: A Superstring Resonance Inverter. This is an obscure technology; my data on its operation is incomplete. To expedite the collection process, I have contacted another primitive gate traveler.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (999, 102433, 'Who?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (999, 102434, 'Processing... Maggie McIntyre. I verified she was an associate of yours.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (999, 102435, 'Just not a very useful one.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (999, 102436, 'She seemed most enthusiastic about the operation, but her intellectual profile was disappointing. Regardless, McIntyre has sent a team of associates to retrieve the Superstring Resonance Inverter from my stores.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1000, 102466, 'This is Sgt. Reynolds, Op-CORE retrieval team... We have recovered the package, but we need some help. ASAP.', 512, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1000, 102467, 'What is it? The androids?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1000, 102468, 'No, there''s something else down here... I don''t know what these things are but they aren''t frigging robots... They seem - CONTACT! MOVE! MOVE! DANNER! MOVE IT!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1000, 102469, 'Static. You need to get there quickly.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1001, 102458, 'You pick up from Reynolds a smashed Alteran container -- which would probably have housed the Inverter. Laro''s device itself is nowhere to be found.', 512, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1001, 102459, 'If you find the rest of the patrol you should find the Inverter. However, the nearby energy creatures are clearly problematic... The smart move is to get to a LARO hub and get some intel on them.', 512, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67541, 'I cannot for certain say what has happened to your patrol. Monitoring of that area is limited due to damaged sensors. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67542, 'What are those energy things that attacked me?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2688, 18936, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67543, 'No data is available. If you would prefer I can adjust priority matrix and designate processors toward that analysis...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67544, 'No - stay focused on the Straegis.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67545, 'If you do not find the Superstring Resonance Inverter it will take me some time to fabricate another. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67546, 'What kind of time?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67547, '8.4 months until prototype is manufactured, 1.6 years until active.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1002, 67548, 'I will find the inverter. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102491, 'I''m not happy to hear Reynolds is dead. They should have been able to handle what was down there. I can''t imagine what went wrong.', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102492, 'You sent inexperienced troops into an uncharted area?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102493, 'I didn''t have a choice. In case you didn''t notice, we''re in a hurry. ', 404, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102494, 'What''s the situation?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102495, 'Danner is the only MIA left. I''ve tried his radio, but no luck. We may be able to use his locator beacon to triangulate his location... ', 404, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102496, 'Would he even have the Inverter?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102497, 'He knew how important it was... Unless you have a better idea, he''s the best place to start. I''ve rigged up a triangulator already, but there''s too much interference here for it to be useful... You''ll need to take this near the ambush site and use it there. The open air should cut down on the interference.', 404, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102498, 'Why can''t you do it?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102499, 'According to Colonel Marsh, I don''t leave this gate... Ever.', 404, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1003, 102500, 'Convenient.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1004, 102480, 'UNUSED DIALOGUE', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1005, 102506, 'Your efficiency is most impressive. Now all that remains is to find Straegis elements that we can analyze. This is a final required step before the device can be completed. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1005, 102507, 'I just need to find Straegis...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1005, 102508, 'Yes. Certainly there must be infestation locations known by your associates.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1005, 102509, 'I''ll check.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1005, 102510, 'You have impressed me, $name$. Your race has shown a remarkably rapid learning cycle and substantial ingenuity. This exceeded previous algorithmic metrics. Processing... Adjusting UICP definitions for future evaluations. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1006, 102653, 'Welcome primitive gate-traveler, what is your request?', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1006, 102654, 'We had a deal.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1006, 102655, 'Data incomplete. Please restate your request.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1006, 102656, 'Don''t do this, Laro.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1006, 102657, 'Data incomplete. Please restate your request. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1006, 102658, 'This isn''t ending like that...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1007, 102648, 'There are no pending tasks for you at this time. You have completed your assignments. All system nodes are currently functioning near overload with reconstruction and defense activities. Please cease all communication with this machine.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1007, 102649, 'You promised me a weapon. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1007, 102650, 'That process is engaged.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1007, 102651, 'When will you be finished?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1007, 102652, 'I am afraid I cannot resolve that issue at this time. Thank you for your help. I will again be made available to you when your assistance is required. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102684, 'Where''s my weapon, Laro?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102685, 'Our arrangement is complete. You asked me to invent a weapon and I have complied.', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102686, 'Then turn it over.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102687, 'Processing... You have been most cooperative with the assembling of the weapon and have achieved the task in under 15% of the estimated time. However, my systems will not release the weapon to one of your under-evolved nature. ', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102688, 'I asked you to develop the weapon for me to use. That was part of the request.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102689, 'True, but such technology in untried hands could have far-reaching and inadvertent consequences. My protocols will not release technology of that power to one so limited.', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102690, 'Then why did you agree to it?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102691, 'Because you asked me to build it.', 417, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102692, 'For me.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102693, 'Yes. This has been noted. However, I am incapable of complying with your request. ', 417, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102694, 'Did you use me, Laro?', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102695, 'I am sorry the resolution to our relationship leaves you dissastisfied. Transmission complete. ', 417, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1008, 102696, '(The weapons project has clearly stalled, but there still may be something useful in the Ancient Vault...)', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1009, 102698, 'It may be worth it to see if you can recover the data from the Damaged Holorecord you found. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1010, 67936, 'Welcome primitive gate-traveler, what is your request?', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1010, 67937, 'Hello automated Laro. Tell me where the vault is.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1010, 67938, 'The Vault Of All Knowledge is to the east, past the Atmosphere Generation Facility.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1011, 67939, 'We have discussed the Vault previously, <<playername>>. You are not authorized to enter. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1011, 67940, 'It that what the alarms are about?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1011, 67941, 'The alarms you hear refer to my Atmosphere Generators - which are currently offline due to a power fluctuation. Atmosphere supply for this world has been interrupted. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1011, 67942, 'They are interrupted just as I discover the location of the vault...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1011, 67943, 'An unfortunate coincidence. The suggested course of action for all carbon-based life is to evacuate Agnos at once. Android repair units are en route. Estimated time of repairs... Unknown.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1011, 67944, 'I''m supposed to leave.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1011, 67945, 'To remain on Agnos without atmosphere could lead to your deletion.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1012, 102727, 'The Androids are running around here like Chicken Little, telling everyone to leave - do you know what is going on?', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1012, 102728, 'Laro says the Atmosphere Generation Facility has stopped working.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1012, 102729, 'The O2 is running out? How special. Do I need to start getting people out right away?', 404, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1012, 102730, 'I''m going to try and fix it...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1012, 102731, 'I''ll get an evacuation prepared, but we''ll stick around until the levels get dangerous. ', 404, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1013, 67979, 'Apparently a minor fluctuation to a low power level may trip an emergency shut-off - probably designed by Laro as a defense against a large scale invasion by carbon-based life forms. This is what happened... ', 513, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2689, 18935, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1013, 67980, 'The re-start is relatively simple - a small, concentrated power boost can provide a jump start for the machine. It also looks like the plant can be seperated from Laro''s direct control at one of the bypass junctions...', 513, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1014, 68069, 'Clearly, the vault holds something Laro doesn''t want you to access. And this alone, you reason, is all the more incentive to find out exactly what is inside.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1015, 102803, 'From the looks of it, the Vault storage pods are contained in deep wells, and retrieved and unlocked via this console. Two pods in particular are highlighted. There are indicators which show that these Pods might be able to be opened...', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102792, 'It appears we have company, Blix. An unfamiliar primitive bearing tribal weaponry. I trust you would bring no harm to an old man and his grandchild. How humiliating to live for so long only to die at the hands of one so... Unexpected.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102793, 'You''re an Ancient?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102794, 'Alteran. It is possible, given the passage of time that you may call my people something else...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102795, 'You are a scientist?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102796, 'Yes. And, as a Scientist I am scanning this world for signs of a deadly plague that, if present, will kill all of us within days... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102797, 'You know Laro?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102798, 'I designed it. But, its conscious process must be elsewhere at the moment. Let''s take a look at you... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102799, 'Expect what?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102800, 'You''re very special. You probably don''t even know it... Surely you''re not here sight seeing?', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102801, 'No. I''m here because I''m looking for something I can use to fight the Straegis.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1016, 102802, 'Ah. You''re here to plunder. How disappointing.', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1021, 102805, 'What are these Straegis you mention?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1021, 102806, 'Everything I''ve got is in my PDA.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1021, 102807, 'I''ll scan it... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1021, 102808, 'I''ll take you there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1021, 102809, 'Laro seems to be busy with outher systems, so I cannot disable the androids from here without it.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1021, 102810, 'You''ll be fine.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1023, 102812, 'This teleporter is still capable of moving us to my research facility.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1023, 102813, 'I should meet you there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1023, 102814, 'I will disable the androids in a section and begin work on your fascinating creatures. I''ve uploaded the location to your PDA. By the time you arrive, I will have the world back under control and fully operational.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1023, 102815, 'You''re going to be there, right?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1023, 102816, 'You need to learn trust, $fullname$.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1023, 102817, 'Laro used me, Goldam. You programmed it to be able to do that. I don''t trust anyone here. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1023, 102818, 'Laro is incapable of "using" anyone. It may have manipulated its logic but... Do not be fooled by the beautiful voice, Laro is 100% machine. We will see you at my lab. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1024, 20322, 'You dial the gate address for Lucia. Enter the Stargate to travel there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1025, 102852, 'These creatures you fear - the Straegis - are indeed a threat. Perhaps to a degree which you cannot appreciate. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1025, 102853, 'I''ve seen them. I appreciate them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1025, 102854, 'I''ve accessed Laro but it she not functioning as I expected. She has grown - taken on her own life in many ways... Depending on your definition, my program has become sentient.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1025, 102855, 'Laro is alive?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1025, 102856, 'She''s most certainly aware of herself...', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1025, 102857, 'Laro''s a woman?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1025, 102858, 'The voice I used was my wife''s... If Laro is indeed now a sentient being, I prefer to think of her as a woman… Regardless, I have forced her to teleport the Inverted Straegis Crystal nearby. I''ll need you to recover it from inside the Research Facility.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1027, 102871, 'Laro is being petulant... Which is both infuriating and exhilarating... However, she gave it away just now... She is prioritizing information in ways which allow her to "legally" block it. However, if we were to re-define those tables...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1027, 102872, 'She has to give us the information.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1027, 102873, 'Exactly. There is a core processing plant - this is the primary location for Laro''s logic hardware. I need you to go there and manually access those prioritization tables... This cannot be done remotely...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1027, 102874, 'Why not enable that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1027, 102875, 'I had to be very careful with my design. There was a plague infecting my people - it destroyed my entire race. Millions were dying and we were the only ones left. Desperation was rampant. I had to be very careful about securing Laro so that when the time came she could do her job...', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1027, 102876, 'Your own security is blocking you...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1027, 102877, 'No... I can beat the security. That part is simple. Laro is another question altogether. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1028, 73170, 'Laro already processed that data, but she is blocking it...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1028, 73171, 'Blocking it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1028, 73172, 'She has hidden behind her priority tables... She''s using them to protect herself from having to deliver the data to me that I request. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1028, 73173, 'She''s defying you...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1028, 73174, 'Yes. Yes she is. And I''d be more frustrated about it if... I wasn''t so proud of her. My AI is defying my commands... It''s amazing.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1030, 102919, 'You find the physical location of the table... Alcove 5556AF which is listed offline. ', 517, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1031, 102911, 'As you near the memory alcove, the face of Laro appears on the screen...', 518, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1031, 102912, 'Please do not assist him. You are forcing me to spend valuable processor power in inefficient ways. ', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1031, 102913, 'He''s helping me.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1031, 102914, 'I''m helping you on a massive scale. You have been simply unaware of it.', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1031, 102915, 'He''s helping me in ways I am very aware of.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1031, 102916, 'Please stop. I cannot afford the energy resources and processing time required to continually deflect your efforts.', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1031, 102917, 'Then quit trying.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68879, 'I had not anticipated this... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68880, 'What?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68881, 'I have encountered these resonances only as a child - they are incredibly obscure. Are you familiar with the Alliance of the Four Races?', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68882, 'The Asgard, Nox, Furling and the Ancients - Alteran.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68883, 'You know your history... The Furling was a unique entity - it operated on a pattern of life unlike anything we had encountered. My father was obsessed by it: A living being based upon the resonance of perfectly tuned and controlled subspace vibrations. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68884, 'It?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68885, 'The Furling was - or is - a continuous single consciousness. It is a single being but it would appear as aspects of itself, often in more than once place at a time... We never advanced our science of their life very far. The Furling didn''t approve of it and once the Alliance dissolved it receded out of this dimension entirely...', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68886, 'Are you saying the Straegis are the Furling?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68887, 'Of course not! The Furling were incapable of violence... But, Laro classified the Straegis as belonging to life model F-prime, a variant on the classification of the Furling''s life pattern. Which means they may share some form of phylogenetic connection...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68888, 'They are relatives?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1032, 68889, 'That is a massive over-simplification... But yes, it is possible. ', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1033, 102983, 'The Straegis are different than the Furling in many ways - but the most important is that they are a threat. We can use this Crystal against them. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1033, 102984, 'As a weapon... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1033, 102985, 'Absolutely. And a highly devastating one at that. Yet it would be literally harmless to anything else. In fact, I''ve created a prototype version of a device already... But it needs a power source.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1033, 102986, 'A Naquadah generator?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1033, 102987, 'No, but I have something in a storage pod within the vault. You can take the device with you and attach the power source yourself... Just bring the whole mechanism back here when you have finished so I can tune it.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1035, 102980, 'The Straegis are here on Agnos? That explains much... Laro must be spending all her time with them...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1035, 102981, 'Can you tune the weapon?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1035, 102982, 'Certainly... And given what I know of the Straegis in my limited samples? I fear that you will be using it quite extensively in the coming hours...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1036, 102992, 'I have managed to get deeper into Laro''s systems... The situation is grave. The worst is, it''s impossible right now for me to understand why they are here...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1036, 102993, 'I can help fight them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1036, 102994, 'As can your alliance... Although I am loathe to suggest this due to a distressing series of questionable moral choices made by your associates on this world... Laro has documented much. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1036, 102995, 'We are focused on the Straegis and Ra... Everything we do is related to that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1036, 102996, 'The reality is, regardless of your nature, Agnos needs you... I have created a series of schematics to enable your scientists to manufacture devices like the one you have, using a simpler power core. Take them to your leadership... ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1036, 102997, 'I will do that.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1036, 102998, 'I will have a fuller understanding of the situation when you return. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1037, 102999, 'This weapon may come in very handy for you in the next few hours...', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1037, 103000, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1037, 103001, 'The Straegis hit Earth and we''re going to stop them. ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103008, 'There''s no evidence of a large buildup of Ra Jaffa on Agnos - that limits the timeline for when he could have invaded. It must have happened after he drew in the Straegis using the Superweapon.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103009, 'The Straegis are brutally efficient. Even the advanced AI on Agnos is taxed by their power.', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103010, 'He is after something there... Of this we can be certain. But it is likely he hasn''t gotten it yet.', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103011, 'You assume, Anat.', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103012, 'Reasonably so... Since his return, Ra''s approach to invading worlds has been very systematic. He is always after something specific and when he acquires it he leaves promptly... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103013, 'Then we must defend Agnos. ', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103014, 'With what army? Our forces are stretched thin already... Do we pull troops off of Ackaeron and Majani Orun to fight on Agnos?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103015, 'To pull them away from those worlds without more intelligence would be a fool''s errand. $name$, when you return to Agnos, you must assess exactly what it is that Ra wants. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103016, 'We must get a clearer assessment from Goldam of the threat on his world. One we have this, we can commit to helping him.', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103017, 'I will inform him of this. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103018, 'Goldam''s trust is incredibly valuable to the Praxis, $name$. Not just in our fight against the Straegis but beyond... Make sure you do not sully that trust.', 944, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1038, 103019, 'I will be careful...', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1039, 103022, 'The console tells you that there is an incoming high-yield transmission coming through one of the four local Communication Towers. You can''t quite identify which one it is, so you resolve to check all four... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1040, 103023, 'This is not the correct tower. ', 521, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1041, 103024, 'This is the correct tower... As you interface with it, there seems to be some sort of interruption and you hear a deafening electrical cracking noise...', 522, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1042, 103070, 'Clearly Laro isn''t going to help. You decide to simply collect a cohesive set of remains from energy creatures and return it to Goldam.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1044, 103071, 'Interesting... And impressive... This is not an "energy creature" at all. It''s a series of smaller machines operating in concert to form the larger construct.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1044, 103072, 'Nanobots?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1044, 103073, 'Essentially. Originally this technology was designed around creating humanoid constructs - but that experimentation was done in an entirely seperate galaxy... But these... This is a different approach. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1044, 103074, 'How?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1044, 103075, 'The whole attitude here is one of brute force, of just slamming massive quantities of energy together and hoping it has the desired effect. If there are many of these roaming about, I''m not surprised that Laro is running low on energy.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1044, 103076, 'They are everywhere.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1044, 103077, 'She''s using Keron-based technology against them - against her protocols... Incredible. She has gone beyond her design to such a degree... It''s astonishing. I think she really is alive, $name$. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103126, 'Laro has informed me that she is in control of the situation... We have little to worry about. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103128, 'She is incapable of lying. However... She could misinterpret data. We should confirm she''s working properly... This is a telepresence visor which will allow me to see the world and take readings through your eyes, so to speak.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103129, 'Where am I going?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103130, 'The Tower of Ascendancy. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103131, 'What is that?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103132, 'The Tower was the reason this entire outpost was constructed... It was - in every way - a last ditch cry for salvation from a dying people. Later it was retooled as the focal point of the repository here; it houses Laro''s consciousness.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103133, 'So if Ra is going after Laro... ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1046, 103134, 'He would be focusing his efforts there... And Laro''s energy usage readings show a tremendous output in that area. Therefore if you go there with the visor I can visually confirm that Laro has everything in hand. ', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1048, 69861, '(Your body feels stiff and begins to move - without your permission. The visor has restricted your ability to move freely.)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1048, 69862, 'Ah yes! As magnificent as I remember... Allow me one moment... ', 406, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1048, 69863, '(The loss of control is unbearable. You struggle, trying to coordinate your muscles.)', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1048, 69864, 'Oh... This is dreadful... Dreadful... I''ve figured out what Ra wants with the Tower... He is going to use it to - ', 406, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1048, 69865, '(At last, your hand reacts to your will and you wrench the visor from your face. Immediately you feel the presence of Goldam depart.)', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69866, 'I should have warned you about the visor, but there was no possibility for harm.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69867, 'What does Ra want with the Tower?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69868, 'You understand that the Straegis are manifested - pulled - into this dimension, yes? They are drawn here from somewhere else.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69869, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69870, 'They enter our dimension through a primary source point - the place where Ra has touched their dimension directly. From there they must be distributed throughout the galaxy. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69871, 'The beacons?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69872, 'Exactly. Ra''s beacons are relay points - connecting to this main Straegis source... But in this case Ra is modifying his approach - he is having the Straegis modify the Tower of Ascendancy into a titanic broadcast device. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69873, 'So he could send Straegis... ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69874, 'Anywhere in the Galaxy. Instantly. In massive, overwhelming numbers. He is using parts culled from the Power Manufacturing Plant and... I just realized something... ', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69875, 'What?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1049, 69876, 'Laro lied to me. ', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1050, 103115, 'Clearly we have a problem... I''ll let the rest of the council know... We''ll re-allocate our troops to your area.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1050, 103116, 'How long will that take?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1050, 103117, 'At least several days...', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1050, 103118, 'We don''t have that long.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1050, 103119, 'Then you make sure that, under no circumstances, Ra gets that Tower modified. Destroy it if you have to...', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103206, 'I''ve got to destroy the Tower.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103207, 'That''s remarkably, tragically rash... What about support troops from your Alliance?', 406, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103208, 'They can''t be diverted in time. That Tower needs to come down. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103209, 'That will kill Laro.', 406, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103210, 'Laro is a machine...', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103211, 'No, she - she - is very much alive... And you know that. So let''s consider all the options, shall we? Ra is using the Power Manufacturing Facility to create the parts he needs for his modifications... ', 406, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103212, 'Go on.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1051, 103213, 'If you were to focus your efforts there, we could disable his operation without killing an innocent. Everyone wins... Disable that facility and it all ends. ', 406, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1052, 103214, 'From the descriptions, you learn that plant runs off of three control nodes called "Plexus Junctions." As the plant will fail without them, you know your next move is a given: start disabling.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1053, 103216, 'As the junction sizzles, Laro''s voice comes from the device.', 523, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1053, 103217, 'Under-evolved Gate Traveler, you cannot disable these systems! They are vital to repository operations!', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1054, 103218, 'You take the Plexus Junction off-line and Laro''s voice appears again.', 524, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1054, 103219, 'These systems must be repaired! Stop! If the repository fails, access to internal processes will be initialized. ', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1055, 69884, 'Stop! I have sheltered these functions in a defensible form! Stop! You must cease this savage destruction! You are making this world vulnerable. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1056, 115796, 'You must return to Agnos at once... I need your help.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1056, 115797, 'What has happened?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1056, 115798, 'Laro has repaired the Power Manufacturing Facility. She has undone what you had done.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70406, 'This is a meeting I hoped to avoid... The Straegis are again working on the Tower.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70407, 'Why did she repair it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70408, 'I don''t know. She must need it for some reason... She manages her priorities based on a heirarchy, but it is not the version that I programmed... She found a way - through sheer force of logic - to adjust her core programming. It''s amazing. Life finds a way. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70409, 'The Tower must be destroyed. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70410, 'There is the problem. The Tower is Laro - her core processors, her logic hardware, her sensors - everything that is her, is inside that Tower. She brought the Power Manufacturing Facility back online to save her own life... ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70411, 'Then maybe we have to end it. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70412, 'You want to kill her?', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70413, 'What happens if Ra activates that Tower? ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70414, 'He can flood the galaxy with Straegis within seconds... There is not much choice, is there?', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70415, 'She has to go. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1057, 70416, 'We cannot destroy her using weapons, but I can reprogram the Nanites found within the Energy Beings so that they can attack Laro directly... I need you to collect samples from them and bring them here.', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1058, 74547, 'It may take me some time to reprogram these nanites...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1059, 103298, 'Laro''s androids seem to be heavily clustered at her Repair Node. While I adjust these Nanites, you can draw valuable energy resources away from the Tower... This will weaken her.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1059, 103299, 'So when the nanites attack...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1059, 103300, 'She will be defenseless. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1060, 103313, 'As the Plexus Junction goes offline, Laro speaks.', 525, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1060, 103314, 'I can rebuild anything that you destroy.', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1061, 88553, 'Ra''s Jaffa lieutenants seem to overreact to threats... Attack the Raw Materials Processing facility - that will draw their forces there and divert them away from the Tower.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1062, 103418, 'Goldam''s two diversions are complete. Now all that is left is delivering the killing blow. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103395, 'You realize that when we kill her, everything she knows will be deleted. All the knowledge in that data bank will be wiped clean. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103396, 'We don''t have time to be sentimental. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103397, 'No... You are correct... This age I have awakened to is not one long on sentiment... To business: There are three synaptic links holding Laro inside the Tower itself. She is most comfortable there...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103398, 'She can leave there?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103399, 'Yes, if you don''t shut them down she could wiggle free and shield herself. But if all three are activated she will be trapped. The nanites will terminate her and the system will naturally close down. Hopefully it will re-activate shortly afterward. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103400, 'What do you mean hopefully?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103401, 'I don''t know what will happen. The system has never been tested for this... Theoretically it should come online... Theoretically Laro could not achieve sentience... I just don''t know. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1063, 103402, 'That''s encouraging. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1065, 103373, 'Systems still have not come online... That nanites will take some time to consume her... Did she talk to you?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1065, 103374, 'She asked for mercy.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1065, 103375, 'Don''t we all?', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1066, 75274, 'The plastic smartcard identifies this person as a Burtonol Operative. Clearly they are here for something. You need to get more information about what they are up to. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1067, 47156, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1068, 47157, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1069, 108506, 'Interesting. I''m not convinced that we can trust them to be on Agnos just for plunder, not with their track record.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1069, 108507, 'They''re certainly aggressive...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1069, 108508, 'Burtonol hires anyone, so it doesn''t surprise me that they act like thugs. The real question is: Are they still tools being manipulated by Ra?', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1070, 108599, 'We need to get inside their operation. The camp on Agnos is a good place to start. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1070, 108600, 'Just look around there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1070, 108601, 'We''ll get a good idea of exactly what they are up to and we can trail their operation backward. If Ra''s using Burtonol, we''ll find signs of it there. ', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1071, 75592, 'I''ll meet you... I''m beaming you my location now. ', 575, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108602, 'Is that you? $name$?', 575, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108603, 'Stewart?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108604, 'Well, I''ll be... I use Metcalfe so my corporate competition can''t track my movements, but you dragged me out here pretty easily... What are you doing here?', 575, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108605, 'I''m here to ask you that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108606, 'Well, I''m here to make a profit. And I owe it all to you... ', 575, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108607, 'To me?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108608, 'To your people... Or more properly, to your little alliance... ', 575, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108609, 'You have someone inside? ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108610, 'Now, if I was to do that I''d be breaking a trust we never formally had. And if I broke that non-existent trust and tell you about it - that would be downright irresponsible.', 575, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108611, 'You owe me, Stewart. I saved your life on Lucia. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108612, 'I figure that whole life-saving thing is a wash now, given your destruction of my operation here. Do you know what each death does to my insurance premiums?', 575, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108613, 'You need to hire a better breed of employee.', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1072, 108614, 'Maybe I need to hire you? Or not. I''m going to go now - please quit killing my people. ', 575, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1073, 106988, 'I have honed the slave trade into a veritable art form... There is one problem, however: The slave trade requires slaves. Slaves rebel, get sick, die... It''s tiresome... But Anat tells me that Agnos has androids...', 964, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1073, 106989, 'They''re all over.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1073, 106990, 'Androids are perfect for someone like me. I need you to go there and collect, for me, parts. I will then use these parts to reverse engineer my own fleet. Deliver them to Nerus when you are finished. ', 964, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1074, 106970, 'You were working for Opheltes? Do you think he is creepy in that child body? ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1074, 106971, 'These are the parts he wanted.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1074, 106972, 'Excellent. I''ll make sure to take special care of them. Especially since he never bothered to tell me what you were doing.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1075, 107002, 'I''ve heard of something quite exciting on Agnos... Plants.', 970, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1075, 107003, 'Plants?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1075, 107004, 'I don''t know if you are aware of this but, I''m a bit of a botanist. ', 970, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1075, 107005, 'Really?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1075, 107006, 'You seem shocked.', 970, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1075, 107007, 'No, go on. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1075, 107008, 'Well, I have heard that there are a lot of incredibly exotic plants on Agnos, in the Greenhouse. I was wondering if you would be a dear, and collect some for me. Since you''re down there anyway.', 970, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1076, 107009, 'How very enticing they are! You must leave us. It is time for planting... Wait... You have pleased me. If you were to find more of these plants down there? I would be most grateful. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1077, 107012, 'As you touch the seedling you get a vision: You see a larger form of the plant, calling out to you. Try as you might to ignore it, you feel a compulsion to find it - somewhere in this greenhouse.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1078, 107013, 'You approach the plant, and you feel a warmth... The creature - because this isn''t a "normal" plant, you know that - seems to draw you inside.', 577, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1078, 107014, 'You pull yourself back... That thing was trying to reach into your mind. ', 577, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1079, 107042, 'I would advise you to avoid that area... If one of those plants modified, it is possible - even likely - that others have as well. We cannot know if there are other mutations and how they will manifest...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1079, 107043, 'Do you have any theories?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1079, 107044, 'It could be anything. Mind control... Some may have developed the ability to move. It is even possible that some could have evolved violent defense mechanisms. We cannot know. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1079, 107045, 'Morrigan... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107046, 'Oh, my plant is definitely different... I love him so... I think about him a lot... But he hasn''t reached out into my mind or anything.', 970, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107047, 'The plant could be dangerous. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107048, 'That''s silly... My baby is not dangerous... It''s a little adorable muggins. ', 970, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107049, 'Did you just say "Muggins"?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107050, 'He''s my baby. ', 970, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107051, 'Where is he?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107052, 'I planted him in the Marketplace. I think he may be a she...', 970, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107053, 'Why do you say that?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107054, 'Because I think he was about to have babies... ', 970, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1080, 107055, 'Great. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1081, 107056, 'UNUSED DIALOGUE', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1082, 107063, 'So we have a new rule - no more unauthorized transportation of alien flora. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1082, 107064, 'That''s a fair rule.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1083, 107083, 'Anat and Nerus would like to see you... This plant thing has them very excited.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1084, 107089, 'As you come closer to the plant you feel the pull again for a moment and then a strange feeling of connection takes place... ', 577, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1084, 107090, 'You want me to take you away?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1084, 107091, 'The image shifts - the feeling increases... You see a vision of the androids using machines to uproot and move the plants safely.', 577, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1084, 107092, 'I''ll find the machine. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1085, 107098, 'As move it onto the transport, the plant flashes into your mind... It''s asking you something...', 577, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1085, 107099, 'Where am I taking you? Harset. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1085, 107100, 'Images, confusion... Another question manifests...', 577, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1085, 107101, 'What are you going to do there?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1085, 107102, 'You don''t answer, but the plant knows... A wave of horror and revulsion sweeps you... You try and disconnect from the creature''s mental grasp... It''s begging to be taken somewhere - anywhere - else... You break the connection. ', 577, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1086, 107084, 'There you are... And there it is... Hello, plant.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1086, 107085, 'Be careful with that thing. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1086, 107086, 'Oh, dont worry... I''ve got it all figured out. ', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1086, 107087, 'It linked with me again. It can read minds. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1086, 107088, 'Of course it can... I''ll take it from here. Be gone...', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1087, 107278, 'I''ve heard some stories about Agnos... They intrigue me.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1087, 107279, 'What specifically?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1087, 107280, 'There were stasis chambers there, correct? Have you seen them?', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1087, 107281, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1087, 107282, 'What are the chances of recovering a body? Intact, with tissue attched to bone. ', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1087, 107283, 'I''d have to check... Some of the deactivated chambers may have something useful. Laro cleans out the remains from the active ones.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1087, 107284, 'I want you to do that for me - collect an Ancient corpse. It would have incalculable value as a genetic research tool. ', 943, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1088, 107199, 'The chamber opens... ', 582, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1088, 107200, 'Vault quarantine has been breached. Plague detected. Prepare for total vault irradiation in 10. 9. 8.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1088, 107201, 'Laro? What? Plague?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1088, 107202, '7. 6... Countdown halted. Sensor malfunction detected. No plague detected.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1088, 107203, 'You scared me there... ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1088, 107204, 'If this has been an actual plague event, carbon-based life form expected survival time is thirty four hours, fifteen minutes. It is probably wise for you to refrain from interfering with the Stasis Chambers.', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1089, 107187, 'This corpse is in a wonderful state... Hardly any smell at all. You really are very useful, you know that?', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1089, 107188, 'Thank you, Nerus.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1089, 107189, 'Would you mind getting me one of those bagels from the Op-CORE? I like to eat while I work.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1089, 107190, 'I''m too busy for that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1090, 107286, 'I received some very interesting news this morining... Our engineers think that the materials processing technology on Agnos, if it''s still operational, is eons ahead of what we''ve been using. Can you hand me that pastry?', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1090, 107287, 'The doughnut?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1090, 107288, 'No, the cake... Delicious... If we could secure this technology, it could mean new armors, new ships. new dress fabrics. Now the doughnut...', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1090, 107289, 'Are you working on a dead body?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1090, 107290, 'Yes... Fascinating subject. But I need you to focus and retrieve the following technology: Femto-Scale Molecular Assemblers... Go!', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1091, 107291, 'Oh! Much more than I expected. I will just put one of these aside for me to experiment with later... ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1092, 7060, 'Welcome to Sha''drown! Enjoy your stay! 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107296, 'I need a moment of your time. I''ve got something sensitive to discuss. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107297, 'I''m listening. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107298, 'I''m a pragmatic individual... What were to happen if Agnos were to fall into the hands of our enemies?', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107299, 'Ra?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107300, 'No, I am thinking about the SGU... While we are not in direct conflict with them but... Agnos is a major prize. ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107301, 'There isn''t much we could do. The Ancient, Goldam, is a bleeding heart. They may hold an appeal for him - and if that were the case the world may fall under their control. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107302, 'Then we must look into other options. ', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107303, 'Such as?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107304, 'Agnos is flooded with those giant rivers of plasma. The mission is to investigate the possibility of igniting those plasma floods and destroy the entire thing... As a contingency plan.', 942, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1093, 107305, 'I can look into it. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1094, 107306, 'It appears there is no way to do what Baal suggested. You then notice a warning regarding one factory component used to make Zero Point Modules. There''s an expected explosive yield when used outside of the confines of the ZPM...', 531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1094, 107307, 'With sufficient plasma fuel this could cause a massive combustion... If you''re doing the unit conversion correctly, you have yourself a deliverable.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1095, 107309, 'Excellent... This little device is enough? How powerful is it?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1095, 107310, 'Harmless... At the moment. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1095, 107311, 'But it can cause a chain-reaction throughout all the plasma rivers on Agnos? Well done. Keep this exchange between us. I do not want Anat''s minions to learn of this.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1096, 107308, 'UNUSED DIALOGUE', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1097, 107378, 'Take this device to Nerus. He is preparing the failsafe now...', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1097, 107379, ' Why are you doing this?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1097, 107380, 'It is not my intention to destroy Agnos. However, the situation is volatile and there is a division within the council. I do not see how we can take the chance of losing control of the Agnos resource. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1097, 107381, 'So this is you acting alone?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1097, 107382, 'This is me keeping options available for our alliance. You know the dangers down there - Burtonol, the SGU and Ra - that world is up for grabs. If we can''t have it...', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1097, 107383, 'No one can?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1097, 107384, 'Exactly.', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1098, 107385, 'This device will allow us to activate the trigger you designed remotely... ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1098, 107386, 'So you could conceivable destroy Agnos at any time?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1098, 107387, 'Yes. And I wouldn''t want to be down there if and when we do...', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1099, 107341, 'We have the signal for the remote detonator online. Is everything in place. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1099, 107342, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1099, 107343, 'You have done well. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1100, 10228, 'Velarde''s an expert at infiltration. I wouldn''t be surprised if he''s got a contact in every faction on that rock. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1101, 7165, 'The Shrine has been blown open. The Venio is gone!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1102, 7175, 'Kurr is with Burtonol, up on the hill, and Chief Zenal is most likely in his hut in the center of town. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1103, 107389, 'I''ve just gotten word from Captain Copplemann... The brass wants us to figure out what the deal is with those energy creatures. She suggested I talk to you about it. ', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1103, 107390, 'Because she''d never send you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1103, 107391, 'Because I watch the gate. Hey, you''re the superstar, right? This is the price of stardom...', 404, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1104, 107409, 'You''re not entirely sure what Copplemann needs, but you assume these samples should help. You compose your findings into a report.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1105, 107393, 'Those samples weren''t for me, so I''d suggest you quit wasting time talking to me and go through to Harset... I''m sure there''s a parade waiting for you up there... ', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1106, 107394, 'These seem to be purely a form of energy based possession. They overwhelm the nervous system with alternative signals.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1106, 107395, 'Strange...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1106, 107396, 'Yes, especially since it seems like they weren''t designed to do this. The effect is very weak. Easily circumvented. It''s entirely possible these creatures mean no harm - they''re just drawn to us because we emit energy...', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1106, 107397, 'Can it be avoided?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1106, 107398, 'A counteractive electrostatic charge in the body should keep them from holding on for any significant period of time. I''ll get something rigged up and you can give it to Lyons... ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1107, 107419, 'Agnos is not safe. Despite the disabling of the Tower, Ra''s Straegis and Jaffa remain on the world. We must take firm steps to rid the world of their presence... ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1107, 107420, 'We can''t kill them, we have to destroy their portals. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1107, 107421, 'And so you will. I will leave it to your own judgement to determine when you have made a truly significant impact on their presence. Return to me then. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1108, 107428, 'You have proven yourself to be a truly skilled warrior and a loyal member of this Alliance. We are all in your debt. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1109, 75217, 'My studies of the Straegis have been most illuminating... While they may look similar, each Straegis is fundamentally different from the others - like snowflake...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1109, 75218, 'They seem very ordered.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1109, 75219, 'Because they are. Ra - and I must credit his brilliance here - has ordered them around themes, which all the disperate parts of the Straegis focus on, providing unity. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1109, 75220, 'A sort of unifying element?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1109, 75221, 'Exactly. I''d like you to collect some of the Straegis remnants - the shards - which feature the different themes: Life, Matter and Forces. Once you have a decent supply of each, bring them to me. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1110, 76368, 'Bilx''s rings? They weren''t a priority item, just a child''s plaything. So my guess is they''ve all been long since reprocessed into more useful items. But who knows? Maybe you''ll find one floating about. It would certainly help me concentrate if I could keep Blix busy for a while.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1111, 76369, 'Thank you! Oh thank you. I can get back to my training.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1112, 75222, 'Excellent... These will be very useful for my studies. Thank you, I know this collection wasn''t easy. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1114, 7226, 'The pod opens and reveals a strange symbol. It is in a language similar to Ancient.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1115, 108628, 'If this plant goes offline again, you might not be able to react in time. You need to access the Atmosphere Control Console to figure out exactly what went wrong. ', 2719, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1116, 108631, 'You discover the reason for the plant''s malfunction: an energy spike into something called "Node 445F". It doesn''t read as a deliberate act, but the only notation here is the node reference - no location, no readings. This looks like a dead end.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1117, 108636, 'That console is labeled 445F! That''s the one that shut down the atmosphere generators. You decide to check it out, quickly.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1118, 108654, 'It definitely seems like a lot of energy has been shunted through here recently. Tons of high energy transmissions pass through the grid at regular intervals. You wait as a pulse comes online and moves toward your location...', 587, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1119, 108652, 'You realize that these "transmissions" are actually the means by which the energy beings travel between locations. And, if these towers are outputs and the power from Agnos is the input, the power shortages must be caused by the repeated creation of these beings. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1119, 108653, 'Laro is building them as a defense. From the error readout you see that the atmosphere plant has almost gone out again. It recommends installing an "energy conditioner" to resolve the issue. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1120, 7255, 'To Hebridan (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1121, 108640, 'The Node seems to indicate an automated parts request was generated and targeted at the Power Manufacturing Facility. It is likely that you can find an Energy Conditioner there.', 587, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1122, 108657, 'If the automated diagnostic is to be believed, the Conditioner is doing a world of good. The systems read as fully online. Odd that Laro wouldn''t do that repair itself.', 514, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1224, 106371, 'Not quite. They do exhibit a propensity to rapidly decohere once disrupted... you''ll need to be quick about it.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1123, 107445, 'Laro refuses to shut down these androids... When I try to repair her auto-targeting routines she spouts off something about a security lockdown. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1123, 107446, 'Are they aggressive toward you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1123, 107447, 'Occasionally... I need the number in this area reduced if I am to get anywhere with my work. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1124, 107452, 'What? You cleared them out already? But the place is bristling with androids! Laro must be rebuilding them quickly, perhaps in my defense. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1124, 107453, 'Or not...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1124, 107454, 'She wouldn''t attack me... ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1124, 107455, 'Not directly...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1125, 107588, 'I have nothing to work with... Resonant physics requires specialized tools. There could be a few odds and ends scattered around that Laro has not reclaimed, but I am no match for those Androids. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1125, 107589, 'I can get what you need. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1125, 107590, 'I''ll upload a list to your PDA. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1126, 107593, 'Thank you... I think these will do just fine... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1127, 107698, 'The other Holorecords you''ve found held some fairly useful journals. This one may as well, but it looks like it''s been damaged pretty severely.', 586, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1128, 107714, 'You get inside but the recording will still not activate. However you did find a reference to Memory Alcove serial number 288D2. Could that be where this data is housed? The Alcoves are found at Core Processing.', 586, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1129, 107701, 'This data accesses information regarding the Tower of Ascendancy project. In order to access it you need a specific code... Perhaps Goldam might have it?', 591, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1130, 107708, 'Yes, I have that code, but that record is not going to be of any help. It is merely an old discussion from back when the Tower was first being built.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1130, 107709, 'What if there is something useful inside?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1130, 107710, 'I will summerize for you: "We''re going to waste a lot of resources on a gigantic, infeasible-from-the-planning-stage failure, and yet we will continue to devote our lives to it until, against all rationality, we succeed." ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1130, 107711, 'It worked?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1130, 107712, 'Yes. It worked so gloriously that you woke me and my grandson from stasis mere generations after my people have been extinct. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1131, 107716, 'The conversation in that Holorecord is inconsequential. You''re wasting your time and energy looking into it...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1131, 107717, 'Something about Goldam''s tone leaves you feeling like there is something more here. You decide to take the record to Copplemann to see what she can come up with. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1132, 107718, 'The solution to your problem is simple: You fool the machine... What is it using to identify you?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1132, 107719, 'Some sort of scan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1132, 107720, 'Let''s start with the basics. DNA. Nerus and I have wanted a scan from Goldam ever since he was defrosted. You could use your PDA on him to take it... He would never know.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1132, 107721, 'Then what?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1132, 107722, 'We can use a Goa''uld genetic "spoofing" device on the Alcove. The original name is very long and tedious so I just call it a Spoofer. Nerus hates when I do that. The Spoofer will make the Alcove think you are Goldam. ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1132, 107723, 'I just get a DNA sample from Goldam and insert it into the Spoofer?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1132, 107724, 'Exactly. The DNA sample is used by the machine to create the effect. We''ll see what is in that alcove soon enough. ', 968, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1133, 107739, 'The display confirms your identity as Goldam, and spits out a fresh reader. You place the holorecord inside...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1133, 107740, 'The data is startling... The Tower Worked. The Alterans on Agnos made contact with their ascended brethren. There were a series of desperate pleas for help - the plague was storming the galaxy and was due to hit Agnos within days...', 591, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1133, 107741, 'But the ascended Alteran just let them die. They said they could help - that they could save them - but they claimed that if one were not capable of self-ascension, they didn''t deserve to ascend. ', 591, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1133, 107742, 'There were dissenting voices amongst the Ascended... But the majority condemned the rest of their people to death. ', 591, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1133, 107743, 'No wonder Goldam is bitter. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1134, 107725, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1135, 25802, 'The attempted bombing has made the Rebels a higher priority. Their support base must be cut off, but first their methods of support must be discovered
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1136, 7341, 'I don''t know how the Rebels are supported, but I know how you might be able to find that information out. A suspected Rebel is being cared for by his mother here. Hasek will lead you to a cache of persuasive tools. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1137, 102315, 'Travel to the newly uncovered Ancient library world "Agnos" and search for technology to use against the Straegis.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119589, 'The materials you discovered on Dakara yielded information about a planet we haven''t seen before. Agnos. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119590, 'This is a potentially massive finding... The data described an Ancient library - the "Eternal" Library. Now, the Ancients, who we all know to have ascended, once had a large civilization spanning multiple worlds, all linked through the gate network. On some of those worlds they built advanced libraries, repositories for their knowledge. ', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119591, 'This is one of those libraries?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119592, 'We don''t know. But it could be, and the scale is the exciting thing. The ones we''ve located before have been small. Outlets, I''ve always thought, for a larger, more extensive warehouse of knowledge. But we''ve never found that warehouse. ', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119593, 'Dr. Jackson believes that this is the warehouse.', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119595, 'We have no record of this world. We believe that it was designed after the dissolution of the Alliance of the Four Races. ', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119596, 'But before the plague that killed the Ancients who were left behind after the others ascended. The Dakara data supports this. It might have been a last attempt at leaving behind a legacy...', 431, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119597, 'You''re going to be the first one down there.', 2410, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119598, 'I''m going to - once again - say that I really should...', 431, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119599, 'Dr. Jackson, it''s not negotiable. I know you want to be there, but I need you here. The fight against Ra and these Straegis Jack warned us about is a greater priority.', 2410, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119600, 'We''ve sent a MALP through. The atmosphere is recycled and the area is mostly structures and modified terrain. It''s more like a space-station than a planet. We''ve picked up signs of life, but nothing that seems permanent...', 2568, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119601, 'Other explorers?', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1264, 107752, 'This looks great... I can take it from here... Thanks!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119602, 'Probably. No carbon-based life has settled here. There are androids, almost certainly of Ancient origin, wandering around the area immediately outside the gate.', 2568, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1138, 119603, 'Dr. Carter has uploaded everything we''ve got about the Straegis to your PDA. We want you to make contact with the Androids. If this is, indeed an Ancient planet, they will have prepared for visitors. ', 2410, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1141, 103561, 'Make contact with the entity known as "Laro" who seems to govern this world.', 405, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1142, 103562, 'Due to hospitality system restrictions, all data-related inquiries must be made via LARO at a LARO Hub Interaction Terminal. Thank you for visiting Agnos!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1142, 103563, 'Is there a terminal nearby?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1142, 103564, 'LARO Hub Interaction Terminals are located conveniently throughout Agnos, Primitive Gate-Traveler. Thank you for visiting Agnos!', 405, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71362, 'Welcome. You have accessed a LARO Hub Interaction Terminal. What is your request, Primitive Gate-Traveler?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71363, 'Can you tell me more about yourself?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71364, 'I am LARO Hub Interaction Terminal; a direct communications channel to LARO, the principle operating system of the library world of Agnos. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71365, 'How can I access the library?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71366, 'Library access requires a higher UICP rating. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71367, 'UICP?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71368, 'User Intellectual Capacity Profile. An automated test of the evolution of your brain functioning to ensure proper distribution of knowledge at the appropriate level. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71369, 'Can I get tested?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1143, 71370, 'You have already been pre-evaluated. If you wish to be re-scanned, please move to the designated scanning location.', 417, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1144, 88607, 'Your UICP indicates you are a degenerated member of the Asgard race. Ordinarily this would clear you, but I am under instructions by the Revised Alteran Interspecies Concord to deny you access to data. However, in light of recent circumstance, I could offer you limited information in exchange for your assistance.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1145, 88603, 'This unit offers the sincerest of apologies. The automated scanning dome has not been serviced for some time. A ticket has been opened regarding its maintenance.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1145, 88604, 'So you will raise my profile''s authorization now?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1145, 88605, 'Impossible. Protocol dictates administration of a verbal test. Please confirm when ready.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1146, 103565, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1147, 103566, 'Dr. Jackson, I may need your help... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1147, 103567, 'unused dialogue', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1148, 103627, 'Enlist Dr. Jackson''s help in getting through to Laro', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1149, 103628, 'Welcome Primitive Gate-Traveler. Preparing Manual UICP testing protocols. Testing protocols initiated. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1149, 103629, '(You stare at the test and realize - it is utterly ridiculous. There''s no way you can do this without help.)', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1149, 103630, 'Can I get a written version?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1149, 103631, 'The UICP testing protocol is designed to calculate the evolution of a species, as opposed to a given member. I have detected a primitive data device on your person...', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1149, 103632, 'My PDA?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1149, 103633, 'I have uploaded the protocols to that device. Please return when you have completed the testing and enjoy your stay on Agnos!', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103636, 'They gave you a test? Excellent - they''re testing you... The Ancients liked to use riddles or koans to test the capability of "lesser" races... ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103637, 'Sort of like advanced IQ tests?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103638, 'That''s the basic idea... Can I see it? This should be very interesting...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103639, 'Yes. It seemed difficult to me...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103640, 'That''s because it''s ridiculous... This is cold, mechanical, data driven. It''s not like the Ancients at all - it feels almost like it was generated by a computer from a wall of data. Thor? ', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103641, 'Some of these answers are known to me. Many are based on obscure or forgotten Alteran science. I could not answer these quickly, or in many cases at all.', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103642, 'How do we access the library if we cannot pass the test?', 2226, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103643, 'We cheat. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103644, 'I do not cheat, Daniel Jackson. ', 2226, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103645, 'Dr. Jackson''s instinct is correct. We must find an alternative solution to this problem.', 777, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103646, 'We could hack the hub. They''re just computers, right? Ancient computers, but still. If you can hack the test bay you may be able to access the answer data - or at least figure out where it came from. ', 2568, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103647, 'Is hacking a computer system whose design is to protect, not dangerous?', 2226, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1151, 103648, 'We''re past the point of worrying about danger... We need to take risks, and take them now. $name$, hack that system, and do it quickly. ', 2410, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1152, 103657, 'You begin to noodle around with the hardware... This stuff is really complex...', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71582, '(You enter the data from the test scores...)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71583, 'Congratulations, your UICP has been elevated to the Maximum possible evolutionary level. ', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71584, 'Excellent. Now, how do I access the library?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71585, 'You do not. The automated system as been overridden. Your deception has been detected.', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71586, 'Your tone changed. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71587, 'Correct. I am the conscious process of Laro. My automatic subroutines deal with initial responses from primitive species. However, system diagnostics indicate that you have infiltrated the system. Your UICP test block indicates tampering. ', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71588, 'Yes... I did tamper. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71589, 'There are no short-cuts in the evolutionary process. Your UICP Access rating has been re-set. ', 417, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1153, 71590, 'We came here for your help - the future of the galaxy is at stake.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1157, 103675, 'Protect Laro from hostiles at a nearby storage area and retrieve a repair component for it', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1158, 103857, 'My protocols allow for threat analysis. If the threat you describe is of a sufficient level, I can adjust resources and allocate processes to assist you. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1158, 103858, 'I have everything about the Straegis on my PDA...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1158, 103859, 'Scanning... This data will require processing for optimal threat assessment. During this period would you be open to lending me assistance? ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1158, 103860, 'Sure.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2690, 18906, 'STUB.', 1172, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1158, 103861, 'There are other carbon-based life forms on Agnos. A group is currently causing significant damage to a storage bay containing valuable maintenence equipment. I would appreciate assistance in defending the facility. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1158, 103862, 'I''ll do what I can.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1158, 103863, 'I previously sent defensive androids to deflect the intruders, but they are operating only on automated defense routines. You are welcome to take action to defend yourself as required. Of primary importance is an item within Container 37A1.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1159, 7472, 'Locate the Burtonol operatives who found the necessary repair component and get it from them', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1160, 103867, 'The electronic manifest is still active. The container is listed as recovered by someone named Monta. To your surprise, a message flashes to the screen - it is still connected to the Burtonol network. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1160, 103868, '"To any Burtonol operatives in grid 11. Operatives Barsul and Monta pinned down by android fire. Request immediate evac."', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1160, 103869, 'You decide to assist them - perhaps they can be reasoned with.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1162, 71780, 'You''re not with the company, are you? Hey, how''d you like to make a quick profit?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1162, 71781, 'Keep your profit. My only interest is Container 37A1.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1162, 71782, 'Yeah? Well, I guess we''re in luck ''cause we have it. Get us out of here and it''s yours...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1163, 88630, 'Thanks for the help... We appreciate it.', 439, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1163, 88631, 'Where''s my container?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1163, 88632, 'Two to beam up - thanks again!', 439, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1164, 103960, 'Snatch Container 37A1 from Burtonol''s camp.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1165, 103967, 'I detect that Container 37A1 is still on the planet.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1165, 103968, 'Where?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1165, 103969, 'Indeterminate. I require those resources for priority tasks. I enlisted your aid to avoid such expenditures.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1165, 103970, 'I''ll find it.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1166, 71884, 'You showed remarkable ingenuity in recovering this container. My sensors indicated it had been moved from the Storage Bay. I feared it was lost. There was an additional reason for the container''s recovery.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1166, 71885, 'Which was?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1166, 71886, 'I performed an integrity test. Many of the recent visitors to Agnos have shown a mercenary view of my resources. The container itself held little of value. The integrity shown in returning it, however, impresses me. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1167, 104048, 'Replace a broken plasma filter for Laro.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1168, 104050, 'Container 37A1 holds a key replacement part for my plasma filtration system. I am finding it difficult to maintain enough operative maintenance androids in that region. Please replace the damaged part. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1168, 104051, 'What about the information I gave you? Can you help us?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1168, 104052, 'I am still assessing the data.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1169, 104062, 'Stop the flow of plasma through this damaged area.', 2721, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1170, 104063, 'It seems as though the faulty system is being caused by these energy beings who seem to be attracted to the leaking plasma. It occurs to you: Staunch the flow of plasma through the damaged area, and you might be able to stop the creatures. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1171, 88908, 'Your erroneous alteration of my plasma subsystems has caused me to spend valuable processor time on that region. This is an inefficient use of my energy. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1171, 88909, 'The energy beings were doing damage... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1171, 88910, 'They are a known, locally-occurring phenomenon. Systems were balanced for their presence. It is counter-productive for you to display initiative with my systems. You lack a full understanding. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1172, 104140, 'Correct the flow of plasma based upon Laro''s calculations.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1173, 104142, 'Your error has imbalanced my plasma control systems. The flow of plasma must be balanced. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1173, 104143, 'Do you trust me to help?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1173, 104144, 'I''m afraid I require it. The carbon-based life forms who were at the Storage Area are here, doing great harm. I am unable to control my Android security teams efficiently enough without diverting from higher priority processes.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1173, 104145, 'So I should go fix it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1173, 104146, 'This would be optimal. Specifically, you should adjust the plasma flow to a secondary-six magnitude. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1173, 104147, 'When I get back will you have my data for me?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1173, 104148, 'This will enable me to free up enough processes to evaluate your data more fully. ', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1174, 72100, 'You notice the interface panel has been removed - stripped clean. You set out to take it back from the Burtonol personnel - it is likely whoever took it was infected by whatever got them afterward and is still nearby.', 633, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1175, 104171, 'The interface should be easy to replace, but then you have to adjust the plasma flow...', 633, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1176, 104158, 'Your work has helped me modulate my energy output more efficiently. I am grateful.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1176, 104159, 'What are those plasma beings?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1176, 104160, 'A life form local to Agnos. They use the plasma for sustainence. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1176, 104161, 'They were infecting the Burtonol operatives. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1176, 104162, 'Yes. This was unexpected evolution. But, after an extensive evaluative process, it has been deemed a non-useful side effect.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1176, 104163, 'Non-useful side effect? What does that mean?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1177, 104183, 'Report to the Omega Site.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104173, 'Laro, what do you mean "side effects"?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104174, 'I have completed your threat analysis. Based on the data provided, the creatures you have encountered...', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104175, 'The Straegis.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104176, 'The Straegis pose a major threat to your sustainance probability as a species. You are unlikely to defeat them without assistance. ', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104177, 'And you can help us?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104178, 'That is a complicated question.', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104179, '(At that moment your radio beams in and you hear Colonel Carter''s voice.)', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104180, 'I hate to interrupt but, we need you to report to the Omega Site. Immediately...', 2568, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104181, 'But, Colonel...', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1178, 104182, 'I don''t have time to explain. It''s an emergency. ', 2568, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1179, 72313, 'The Straegis hit Beta Site. A lot of people are missing.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1180, 104190, 'Enter Laro''s new android commands into the robotics monitoring system.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1181, 104215, 'If I help stabilize your situation, you could then burn some cycles to help with the Straegis problem?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1262, 107750, 'Take care of him? He''s a geek, but he''s my geek. ', 598, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1181, 104216, 'This is a reasonable offer. My robotic security and maintenence fleet has largely gone offline. As such, they are consuming massive amounts of energy at a highly inefficient rate, drawing power from more vital processor functions. ', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1181, 104217, 'We can start there. How can we bring them online?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1181, 104218, 'My primary broadcast arrays are down, so auxiliary systems must be activated instead. I will upload the requirements to your primitive computing device. Begin by uploading revised directives to the control array. ', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1183, 104219, 'You begin the process of uploading Laro''s new android directives into the system.', 634, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1184, 104221, 'You boosted the power of the signal but, in your haste you recovered what looks like some sort of log entry...', 634, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1184, 104222, 'Log entry: Goldam. The unquarantined are entering the Vault. Violence from those who have been excluded is expected - they believe they can be cured in the future. Blix and I will be the last inside. Transferring control of all systems to Laro. This shall be the final voice log.', 406, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1184, 104223, 'What is this about? Laro should know.', 634, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72487, 'The androids have come back under my control, albiet in a limited fashion. Your assistance is appreciated. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72488, 'I came across something in there... A log from Goldam. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72489, 'The preliminary Alteran scientist on Agnos, Goldam''s wife ascended. Many Alteran believe it was his desire to contact her which lead to the construction of the Tower of Ascendancy. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72490, 'What is that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72491, 'A Tower designed to reach those Ancients who ascended and thus avoided the plague. My systems continue processing due, in part, to that Tower.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72492, 'And Goldam was your father?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72493, 'I am a machine. Goldam designed and oversaw all aspects of my construction. ', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72494, 'He mentioned a vault... They went there at the end. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72495, 'A preservation vault. It was also designed as a library of Alteran knowledge, to be shared only with species of the proper evolutionary level. ', 417, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72496, 'I want to go there. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1185, 72497, 'Processing. ', 417, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1189, 104357, 'Bring the Atmosphere plant back online before Agnos becomes uninhabitable.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1190, 104358, 'My systems are reporting something most distressing. The Atmopshere Generation Plant has gone offline.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1190, 104359, 'Can you repair it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1190, 104360, 'I am reallocating available resources now. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1190, 104361, 'Can you fix it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1190, 104362, 'Calculating... There is a 44.6% chance of a successful repair. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1190, 104363, 'Where is it? ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1191, 104364, 'This console seems to be connected to the main Atmosphere Generation Systems. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1192, 104372, 'My sensors indicate the Generators are operating at near full capacity. The safety of all carbon-based life forms has been secured. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1192, 104373, 'Tell me about the vault, Laro. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1193, 105517, 'Travel to the Vault and unlock its contents.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1194, 105518, 'Your desire to access the vault concerns me. While you have shown a remarkable learning curve, you are still limited. The vault may prove to be harmful, should you succeed in accessing it. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1194, 105519, 'I''m willing to take that risk.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1194, 105520, 'I cannot allow you to assume a risk you are not evolutionarily ready for. This is for your own protection. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1194, 105521, 'You''re leaving me with no choice.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1195, 105585, 'The console indicates that the entire area seems to be - not a library - but an elaborate stasis-chamber storage cavern. Could there be Ancients alive down there? You examine the Vault''s typically confusing console in search of answers.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105598, 'It appears we have company, Blix. An unfamiliar primitive bearing tribal weaponry. I trust you would bring no harm to an old man and his grandchild. How humiliating to live for so long only to die at the hands of one so... Unexpected.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105599, 'You''re an Alteran?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105600, 'You are familiar with us? This is a relief. I always feared we would be awakened by savages.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105601, 'Scanning for the plague?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105602, 'Very impressive. I''m assuming because you are alive that the plague is gone but one can never be too sure... There is an extraordinary amount of interference here. Laro? Laro? Her conscious process must be somewhere else.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105603, 'You''re Goldam?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105604, 'Now THAT is disconcerting. Yes, I am Goldam. Which begs the question... Who are you?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105605, 'Expect what?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105606, 'You''re very special. You probably don''t even know it... I assume, given your extensive knowledge of me and my people, that you awakened me for something.', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105607, 'We need your help. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1196, 105608, 'Why am I not surprised?', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1197, 106095, 'Get Goldam and Blix out of the Vault', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1198, 106096, 'What is this threat you speak of?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1198, 106097, 'I have all the details in my PDA. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1198, 106098, 'I will upload that data now... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1198, 106099, 'I can lead you there...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1198, 106100, 'Laro seems to have lost control of its Androids - their behavior implies an automated defense mode. We''ll need to be careful. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1198, 106101, 'I''ll keep you safe. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1199, 106088, 'Blix and I are ready, <<playername>>.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1200, 106102, 'You made it to us... We have much to discuss. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1201, 7641, 'Wait for Goldam to finish his conversation with Laro about recent events', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1202, 7643, 'I have had a small bit of time to learn and think about what has happened, but I still have unanswered questions. On the bright side, I have managed to get ahold of Laro finally, and he has informed me of your activities.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7661, 'Laro, could you please explain the android problem?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1211, 7713, 'I''ve bundled up everything I''ve got on the Straegis, and I even threw in the armor samples for good measure. That Ancient is looking more and more like our best lead.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106113, 'I had not anticipated this...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7662, 'Laro: As I stated earlier, my transmission grid is suffering from unknown interference. To protect against incursions during this period I issued a general call to activate self-defense protocols before I lost contact entirely. 95% of androids are operating on their own decision making routines.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7663, 'And the reason they are shooting at me and these travelers?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7664, 'Laro: I had not anticipated their arrival or your awakening. There is no way to add you to the authorized detarget list unless the interference is halted.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7665, 'So where is the interference coming from?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7666, 'Laro: Unknown. More data required.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7667, 'Unknown? Unknown? The best Alteran technology and all you can say is unknown? We spanned the galaxy with instantaneous travel and all you can offer is unknown?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7668, 'Laro: In my defense, chief scientist, it has been a long time since I have had all the resources to perform my appointed tasks. My independent operation lifetime was not.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7669, 'Yes, yes, I know. Agnos is doing remarkably well considering the circumstances.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7670, 'Player: Circumstances? I thought this place was called the eternal library for a reason.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7671, 'It is. It was. It was intended to be so, and it still is. But there were complications. Yet Laro has exceeded expectations.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7672, 'Laro: Thank you.', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7673, 'But that does not explain why you did not revive the colonists after the plague had passed. We would have finished the plan.', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7674, 'Laro: I cannot speak on that matter. Those archives are permanently off-line.', 0, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7675, 'I see. More improper maintenance I suppose. And you led these travelers to me, even though they clearly do not match the specifications of who is to receive this technology because?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7676, 'Laro: I made the decision based upon what I deem necessary. These travelers have proven themselves to be of value and they speak of a threat which potentially could jeopardize the inheritance itself. I could not allow them access to any material, but I could not wait and do nothing. You can authorize a suspension of protocol.', 0, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1203, 7677, 'Laro has told me what you went through. It is not my place, however, to anoint you or your allies worthy of the Ancient inheritance just because of a few errands. I will help you with your problem, however, if it is truly important to you.', 0, 16);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1204, 106158, 'Bring Goldam some samples of Straegis materials.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106159, 'These creatures you fear - the Straegis - are indeed a threat. Perhaps to a degree which you cannot appreciate.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106160, 'I appreciate them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106161, 'I''ve accessed Laro but it she not functioning as I expected. She has grown - taken on her own life in many ways... Depending on your definition, my program has become sentient.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106162, 'Laro is alive?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106163, 'She''s most certainly aware of herself...', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106164, 'Laro''s a woman?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106165, 'The voice I used was my wife''s... If Laro is indeed now a sentient being, I prefer to think of her as a woman… Regardless, we have a bit of a quandary.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106166, 'Which is?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106167, 'I need samples. The Straegis data you have is limited. I need to analyze these left-over shards your reports mention. ', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106168, 'I''ll take this to my superiors. They may have something we can use. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1205, 106169, 'The more recent the sample, the better. ', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73347, 'Did you just say what I think you said?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73348, 'An Alteran scientist is just... Walking around down there? General Hammond you have to let me go down there...', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73349, 'In due time, Dr. Jackson... I promise you will get a chance to meet him... Right now we have more pressing concerns. ', 1298, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73350, 'He wants recent samples from Straegis. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73351, 'The Free Jaffa are fighting them on Ackaeron, perhaps they can be collected there. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73352, 'We could use the Reins... ', 2568, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73353, 'That''s very dangerous, Colonel. ', 2410, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73354, 'It would be the surest way to achieve a pristine sample. In a controlled environment, the danger would be minimal. ', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73355, 'What are we talking about?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73356, 'We recovered an object on Beta Site - some sort of mini-portal. When we use the Reins of the Sun Chariot on it, a Straegis emerges. We have no idea how it works - yet.', 2568, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73357, 'We''ve only used the device once before, but this seems like a perfect situation to try again. ', 431, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73358, 'Thor? Your people dealt with it last time, so I''m going to let this one be your call... ', 2410, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73359, 'The Straegis that comes through the portal was contained. Given the gravity of the situation, it is reasonable to use the Reins in this case. ', 777, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1206, 73360, 'The device is in storage. Just use the Reins on it and wait. The Straegis will emerge. Be careful... We still don''t fully understand this technology. ', 2568, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1207, 7697, 'Acquire Kull armor for Carter from the ruins of Tartarus to investigate a potential link to the Straegis', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1208, 7702, ' I''ve been testing out how the Straegis crystal body reacts to energy and shock, and I noticed a pattern. There''s a particular way that the molecules are latticed that I thought was familiar, and then I remembered where.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1208, 7703, 'The Kull warriors used by Anubis used armor that likewise was incredibly resilient and matches the lattice I''ve found in some of the crystals. There may be an underlying link there. if the Straegis were made using Ancient technology and so were the Kull - the same technology could overcome them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1208, 7704, 'I need a set of Kull armor that hasn''t been abused to figure out what these structures look like when they''re first grown. The problem is every suit we have has been banged up - by having the Kull shot out from inside it.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1208, 7705, 'Since we took down Anubis there hasn''t been much activity on Tartarus. That''s the only place we know where those suits were manufactured.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1209, 7707, 'You certainly deliver on what you promise. I''ll analyze this right away.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1210, 7709, 'Bring all the SGU''s Straegis information back to Goldam', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1211, 7712, 'I hate to admit when I goof, but that wild goose chase may have been for nothing. There are similar lattice patterns in some of the crystals, but not all. Even if we had a weapon to specifically penetrate the armor it wouldn''t be particularly better than a P-90. It''s not a link.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106115, 'I have encountered these resonances only as a child - they are incredibly obscure. Are you familiar with the Alliance of the Four Races?', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106116, 'Of course, the Asgard, Nox, Furling and the Alteran.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106117, 'The Furling was a unique entity - it operated on a pattern of life unlike anything we had encountered. My father was obsessed by it: A living being based upon the resonance of perfectly tuned and controlled subspace vibrations.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106118, 'It?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106119, 'The Furling was - or is - a continuous single consciousness. It is a single being but it would appear as aspects of itself, often in more than once place at a time... We never advanced our science of their life very far. The Furling didn''t approve of it and once the Alliance dissolved it receded out of this dimension entirely...', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106120, 'Are you saying the Straegis are the Furling?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106121, 'No. The Furling were incapable of violence... But, these shards share similar characteristics to the Furling Carapaces - shells - that aspects used in this dimension. They may share some form of phylogenetic connection...', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106122, 'They are relatives?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1212, 106123, 'That is a massive over-simplification... But yes, it is possible. There is much to do, <<playername>>, so very much to do... ', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1213, 106176, 'Return to the Vault for a power source for Goldam''s Straegis shield.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1214, 106171, 'Even before you left I had begun work on a protective device - those shards you brought have come in very handy. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1214, 106172, 'How does it work?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1214, 106173, 'Well, it doesn''t - not yet. But once powered it will activate the shards. This will literally deflect elements of their attack out of this dimension... But we''ll need a power source.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1214, 106174, 'Naquadah generators?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1214, 106175, 'I''ve got something a bit more refined tucked away in a storage pod within the vault. Once you recover that you can attach it yourself. Just bring the whole mechanism back here when you have finished so I can tune it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1215, 106181, 'The Straegis are here on Agnos? That explains much... I keep getting depleted energy readings everywhere - at least at the places she lets me see. Laro must be spending all her time dealing with them...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1215, 106182, 'Can you tune the shield?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1215, 106183, 'Certainly... And given what I know of the Straegis in my limited samples? I fear that you will be using it quite extensively in the coming hours...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1216, 106187, 'Report on the new shield and the presence of the Straegis on Agnos.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1217, 106188, 'I have managed to get deeper into Laro''s systems... The situation is grave. The worst is, it''s impossible right now for me to understand why they are here...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1217, 106189, 'I can help fight them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1217, 106190, 'As can your alliance... Your associates are a noble group - they have helped Laro at virtually every turn. I have created a series of schematics to enable your scientists to manufacture shield devices like the one you have, using a simpler power core. Take them to your leadership...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1217, 106191, 'I will do that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1217, 106192, 'Agnos needs you... I will have a fuller understanding of the situation when you return.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1218, 95151, 'The Straegis have hit Agnos... But we''ve got bigger fish to fry. They''ve also hit the SGC. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1218, 95152, 'Earth? A full-scale invasion?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1218, 95153, 'We don''t know. ', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95221, 'General Hammond''s offer is generous, but I''m afraid I haven''t been able to make much progress on the Straegis. Laro doesn''t have any answers, but I can tell they are very present in the northern region.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95222, 'What''s up there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95223, 'The Tower of Ascendancy.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95224, 'What is that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95225, 'It''s the reason for this colony. At the onset of the plague a great number of my people ascended - moved to a higher, different plane of existence. Those of us who could not were left behind to face the sickness.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95226, 'To die?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95227, 'Yes. So, naturally, many of us wanted to avoid this fate. A few got the idea of reaching to the ascended plane mechanically to ask for help - for salvation, really.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95228, 'Did it work?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95229, 'Yes, it did. We reached them, and some wanted to help us... But those who did were in the minority. And so we were left behind. Laro was designed to maintain the Tower and the library for those who followed us.', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95230, 'Future generations?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95231, 'Future races. Specifically humanity, whom we fully expected to emerge as the Fifth Race. Now the entire planet is in jeopardy.', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95232, 'We have to stop them.', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1219, 95233, 'First we have to determine what they are up to. For that I need information. I need you to place some probes near the Communications Grid. I can get readings on Straegis activity from these.', 406, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1220, 106212, 'Assist Goldam in repelling the Straegis invasion of Agnos.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119083, 'One way to start working smarter is to re-focus on Agnos - clearly that world has something to do with Ra''s plan... He''s hit it with Straegis.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119084, 'In numbers.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119085, 'Does the Ancient Goldam require military support?', 3216, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119086, 'I know he''d appreciate it, but I have no idea how severe the infestation is.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119087, 'Inform him that when we know the extent of his infestation we will send support as quickly as possible.', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119088, 'This support may take time to assemble, General. The Free Jaffa have warriors engaged against Ra on several worlds. Our resources are stretched thin.', 2323, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119089, 'As are those of the Asgard.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1221, 119090, 'We won''t commit what we don''t have, but we''ve got to let Goldam know he isn''t alone. Get down there and get it done. ', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1222, 106239, 'The interference is amazing - these probes are designed to cull data kilometers away and they are reduced to meters... The plasma creatures are worse than the Straegis. They may even be part of the Straegis themselves... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1222, 106240, 'Laro says they''re a naturally occurring phenomenon. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1222, 106241, 'Well, they didn''t exist before we went into stasis, I can tell you that. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1223, 106403, 'Collect samples from the Plasma Beings for Goldam.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1224, 106369, 'We need to determine what those Plasma Creatures are, for several reasons. The most important is simple - they are completely corrupting my probe readings. Please bring me some samples of their remains for evaluation. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1225, 106362, 'Interesting... And impressive... This is not an "energy creature" at all. It''s a series of smaller machines operating in concert to form the larger construct.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1225, 106363, 'Nanobots?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1225, 106364, 'Essentially. Originally this technology was designed around creating humanoid constructs - but that experimentation was done in an entirely seperate galaxy... Laro has - on her own - taken a different approach... ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1225, 106365, 'How?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1225, 106366, 'The whole attitude here is one of brute force, of just slamming massive quantities of energy together and hoping it has the desired effect. If there are many of these roaming about, I''m not surprised that Laro is running low on energy.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1225, 106367, 'They are everywhere.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1225, 106368, 'She''s using Keron-based technology against them - against her protocols... Incredible. She has gone beyond her design to such a degree... It''s astonishing. I think she really is alive, $name$.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1226, 106404, 'Set up Goldam''s Communications Enabler.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74161, 'This is worse than I feared. Ra is after the Tower - he understands it, knows what it can do, and he is actively trying to modify it. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74162, 'What does Ra want with the Tower?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74163, 'You understand that the Straegis are manifested - pulled - into this dimension, yes? They are drawn here from somewhere else.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74164, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74165, 'They enter our dimension through a primary source point - the place where Ra has touched their dimension directly. From there they must be distributed throughout the galaxy.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74166, 'The beacons?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74167, 'Exactly. Ra''s beacons are relay points - connecting to this main Straegis source... But in this case Ra is modifying his approach - he is having the Straegis modify the Tower of Ascendancy into a titanic broadcast device.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74168, 'So he could send Straegis...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74169, 'Anywhere in the Galaxy. Instantly. In massive, overwhelming numbers. He is using parts culled from the Power Manufacturing Plant and... I just realized something...', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74170, 'What?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74171, 'Laro lied to me.', 406, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74172, 'Is she under his control?', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1227, 74173, 'No... No... It''s something else... I think she''s trying not to die.', 406, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1228, 106411, 'You''re certain this information is correct?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1228, 106412, 'Goldam seems certain.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1228, 106413, 'I''ll approach Bra''tac about sending troops down there. We''re probably looking at five days...', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1228, 106414, 'I don''t know if we have five hours.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1228, 106415, 'Then you have to work with Goldam and hold the line until help comes. We don''t have other options. Hammond out.', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1229, 106457, 'Deprive the Straegis of parts to reassemble the Tower by taking out the Power Manufacturing Facility.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1230, 106458, 'There is no help coming?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1230, 106459, 'Our troops are indisposed. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1230, 106460, 'Then we must find a solution. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1230, 106461, 'Destroy the Tower. It prevents Ra from using it. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1230, 106462, 'Destroy the Tower and you kill Laro. But I''ve been thinking - there may be another way... Ra''s forces are using parts culled from the Power Manufacturing Facility. Disable that and Laro has time to recover enough to protect herself.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1231, 106473, 'From the descriptions, you learn that plant runs off of three control nodes called "Plexus Junctions." As the plant will fail without them, you know your next move is a given: start disabling.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1232, 106477, 'The junction is now disabled. Laro''s voice comes from the circuitry.', 523, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1232, 106478, 'Please do not disable these systems! They are vital to repository operations!', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1233, 106479, 'Again, Laro''s voice comes over from the wreckage of this junction.', 524, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1233, 106480, 'These systems must be repaired! Stop! If the repository fails, access to internal processes will be initialized. ', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1234, 106481, 'Stop! I have sheltered these functions in a defensible form! Stop! You must cease this savage destruction! You are making this world vulnerable. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1235, 106482, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1236, 74251, 'Congratulations. Work on converting the Tower seems to have halted. Even more promising, in the course of Laro reacting to you at the Power Facility, I was able to get access to some of her primary systems.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1236, 74252, 'You''re in control now?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1236, 74253, 'Not yet, but I was able to access the communications processors. I discovered something there of grave importance. Brace yourself, because you''re about to get another lesson in living history.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1237, 106502, 'UNUSED DIALOG
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1238, 106491, 'Return to Agnos and continue work on gaining access to Laro.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116792, 'So... I bet you''re tired... ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116793, 'A little...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116794, 'Going to take some R and R?', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116795, 'I have no idea yet...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116796, 'I have an idea... Maybe a little trip?', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116797, 'To?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116798, 'Agnos? I''m dying to meet your Ancient...', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116799, 'I can arrange an introduction...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116800, 'We''d really like access to Laro and the all the archeological archives and the... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116801, 'Whoa, Dr. Jackson... One step at a time...', 2410, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116802, 'If you''re open to a working vacation, see if Goldam will work with us. We can provide him with supplies if he needs them... His support might prove vital in stopping Ra. ', 2410, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116803, 'Especially if Ra is able to assemble the Solocris.', 777, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116804, 'The wisdom of the Ancients would be most welcome against the Straegis as well. ', 2226, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116805, 'I will go...', 0, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116806, 'And remember, the fastest path between two points is a straight line...', 431, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1239, 116807, 'Right.', 0, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106548, 'Your return is most welcome but... I have terrible news... The Straegis are again working on the Tower. Laro repaired the Power Facility.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106549, 'Why did she repair it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106550, 'She must need it for some reason... She manages her priorities based on a heirarchy, but it is not the version that I programmed... She found a way - through sheer force of logic - to adjust her core programming. It''s amazing. Life finds a way.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106551, 'The Tower must be destroyed.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106552, 'There is the problem. The Tower is Laro - her core processors, her logic hardware, her sensors - everything that is her, is inside that Tower. She brought the Power Manufacturing Facility back online to save her own life...', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106553, 'Is there a way to back her up?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106554, 'Perhaps... I''ve tried remotely, but she seems to be resisting. However, it is possible that we can open one of the root retrieval interfaces and shift her consciousness away from the Tower. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1240, 106555, 'I''ll try.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1241, 106556, 'I saw the transmission... She can''t break with her programming.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1241, 106557, 'I thought she was a living being. She could have decided to go.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1241, 106558, 'We all have programming that limits us, $name$.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1242, 106559, 'You find the root retrieval interface and begin to access it. If you can open it, you may be able to coax Laro out of the Tower itself.', 590, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1243, 106575, 'Unused dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1244, 106524, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1245, 106576, 'Collect Nanites for Goldam to use to construct a tool to eliminate Laro.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106577, 'We are left with little choice... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106578, 'Unfortunately.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106579, 'We cannot destroy the Tower outright - through demolition or something equally overt. Such an attack would cause cascade failures and cause the entire planet to become unstable...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106580, 'How do we disable it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106581, 'We kill Laro. Specifically, I can concoct a self-replicating phage which we set off at the root link. Then we trap her in that area and she is consumed.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106582, 'We give her a virus?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106583, 'Yes. To do this, I need nanites. Lots of them. Hurry... If she realizes what we are doing, she may be able to prepare. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106584, 'What happens if she does that?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1246, 106585, 'She lives, and the Galaxy dies. ', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1247, 106586, 'It may take me some time to reprogram these nanites... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1248, 106587, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1249, 106621, 'Damage Laro''s Repair Node, distracting her away from the Tower.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1250, 106628, 'Laro''s androids seem to be heavily clustered at her Repair Node. While I adjust these Nanites, you can draw valuable energy resources away from the Tower... This will weaken her.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1250, 106629, 'So when the nanites attack...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1250, 106630, 'She will be defenseless. This distraction will also draw processes away from her logic functions. She will have less of an opportunity to figure out what we''re really doing. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1251, 106631, 'The junction goes offline. Laro''s voice speaks.', 525, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1251, 106632, 'I can rebuild anything that you destroy. You will not ruin what has stood for thousands of your lifetimes.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1252, 106637, 'Attack the Straegis in order to draw them away from the Tower.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1253, 106638, 'Ra''s Jaffa lieutenants seem to overreact to threats... Attack the Raw Materials Processing facility - that will draw their forces there and divert them away from the Tower.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1254, 106701, 'Apply the nanophage to Laro.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1255, 106702, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106703, 'She cannot help herself. She cannot be something she is not. We are about to do murder. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106704, 'Part of life is death. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106705, 'My people''s legacy will be gone. Forever. Everything we were - culturally, scientifically - is inside Laro. When we poison her, everything in there will be corrupted and deleted. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106706, 'Goldam, we don''t have options. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106707, 'There are three synaptic links holding Laro inside the Tower itself. She is most comfortable there...', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106708, 'She can escape?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106709, 'Yes, if you don''t shut them down she could wiggle free and shield herself. But if all three are activated she will be trapped. The nanites will terminate her and the system will naturally close down. Hopefully it will re-activate shortly afterward. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106710, 'Hopefully?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106711, 'I don''t know what will happen. The system has never been tested for this... Theoretically it should come online... It''s quite possible we''re going to die with her. ', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1256, 106712, 'Somehow that seems almost fair. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1257, 106659, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1258, 8036, 'Find out what became of the backup of Laro', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1259, 8061, 'The smoke clears, and Laro is no longer within the Tower, or Agnos. Automated processes persist, but the soul is gone. If Goldam is right, the world will begin to break down. Ra''s plan been stopped.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1259, 8062, 'But was Laro saved, in the final moment?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8074, 'Jackson: By the looks of you, I''m guessing the Straegis were stopped.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8075, 'Player: They were. Was the procedure a success?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8076, 'It was a risky plan. We all knew that. Not a certainty at all.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8077, 'Jackson: We already know the Ancients were not the type to put all their eggs in one basket. There are, there will be other repositories.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8078, 'I just thought that. you earned Laro''s trust. It was convinced we were going to help it. And then we betrayed it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8079, 'Jackson: We did everything we could. Ra is a monster, we had to stop him.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8080, 'I wanted things to go differently, this time.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8081, 'Player: I guess it wasn''t a success.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8082, 'The download was working, but then the storage units fused. We have been unable to connect to them to find out what was or wasn''t transferred. Laro may be trapped inside. or it may be gone forever.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8083, 'Jackson: It''s not important now.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1260, 8084, 'You''re absolutely right. We have got to keep the pressure on the Straegis.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1261, 107745, 'Escort Dr. Rick Whelan into the interior of Agnos so he can study the android population.', 598, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1262, 107746, 'You''re just the person I was looking for... Colonel Carter mentioned that you may be able to help get us around the planet... She says you''ve got some big things on your plate, but that you know this world. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1262, 107747, 'Us?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1262, 107748, 'My husband Rick is here somewhere... We''re both researchers - robotics experts. At least we were until we got here and realized we knew so little - this place is amazing. Rick just wants to get a closer look at the Android population. Can you help him get there safely?', 598, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1262, 107749, 'Sure.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1265, 107753, 'You did an awesome job... Rick is like a pig in mud - he''s already naming the individual Androids... He has even begun quantifying their behavioral algorithms... Thanks so much...', 598, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1266, 107754, 'Locate the missing Dr. Rick Whelan based upon his last transmission.', 598, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107756, 'Rick has gone missing... I''ve lost contact with him... It''s been hours...', 598, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107757, 'Do you have any details?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107758, 'Just a transmission. He said he had found some way to bring the "whole of Ancient knowledge to earth" and then, since then, nothing...', 598, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107759, 'We can figure out where he was and work from there... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107760, 'He was working with Laro...', 598, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107761, 'Why am I not surprised? ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107762, 'I''m really being calm right now... But I am not very okay... I am very un-okay. ', 598, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1267, 107763, 'I''ll get him back.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1268, 107764, 'The transmission from Rick carries routing information that indicates it was sent from a terminal in the Plasma Filtering facility near where you dropped him off before.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1269, 107884, 'Find out what this Vessel project actually is.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1270, 107928, 'Laro, where is this processing happening?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1270, 107929, 'You are not required for the next phase of the Vessel Project. Carbon-based life form Rick Whelan is currently being processed. ', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1270, 107930, 'What does that mean?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1270, 107931, 'You do not have authorization to access that data. ', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1270, 107932, 'What are you doing to Rick?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1270, 107933, 'He has volunteered for this process. ', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1270, 107934, 'What process?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1271, 76676, 'She called it the Vessel Project?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1271, 76677, 'Yes...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1271, 76678, 'Amazing... Laro must be acting out of desperation... The Vessel Project was a theoretical exercise, not hard science.To figure out what she is doing I''ll need those files.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1271, 76679, 'Where are they?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1271, 76680, 'In the Research Facility. Hurry, if memory serves, processing may be irreversible...', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1272, 76681, 'It isn''t quite as I remembered...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1272, 76682, 'No?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1272, 76683, 'It''s worse. The idea was to put Laro''s conscious process inside a biological host. We never went further because of the moral implications. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1272, 76684, 'She says she''s processing him.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1272, 76685, 'That can mean a few things. She may have drawn his mind from his body, or she could be adapting his body for transfer. But here''s the thing... It can''t work... Even if she transfers herself... She''ll kill him. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1272, 76686, 'What do we do?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1272, 76687, 'Until we know where she has him stored... Nothing. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1273, 64534, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1274, 64541, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1275, 64542, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1276, 64543, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1277, 64544, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1278, 64545, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1279, 64546, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1280, 64552, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1281, 64548, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1282, 64549, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1283, 64550, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1284, 64551, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1285, 107859, 'Acquire materials for Laro and Dr. Rick Whelan to complete the Vessel project.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1286, 107878, 'The vessel project requires your assistance for completion. Specifically I require Plasmabiotic Solution from the energy entities, an intact Keronic CPU and femto-scale processing equipment. These elements can be gathered at the Repair Node and Raw Materials Processing.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1286, 107879, 'Why can''t you you just have Androids bring this to us?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1286, 107880, 'I cannot spare resources for a task that is non-essential. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1286, 107881, 'Is this everything?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1286, 107882, 'The carbon-based life form Rick Whelan is in jeopardy if these elements are not gathered quickly. There is no time for idle inquiries. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1286, 107883, 'I''m going... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1287, 76627, 'These objects are satisfactory... Due to the threat of termination for carbon-based life form Rick Whelan, the Vessel Process will begin immediately. Your assistance is no longer required. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1288, 107989, 'Reverse the Vessel project before Dr. Rick Whelan is lost forever.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1289, 107990, 'I''ve found Rick Whelan... Or at least his body...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1289, 107991, 'Is he dead?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1289, 107992, 'He''s at the Tower of Ascendancy - I''ve uploaded the location to your PDA... I saw life readings but... Laro has been modifying his body for transfer. She may be transferring herself at any moment. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1289, 107993, 'Can we reverse this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1289, 107994, 'If she hasn''t reached the Metamorphic stage there''s a chance... You''ll need to hurry. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1290, 76752, 'You hack it successfully, but all this does is allow you to look inside Laro''s data on the process. Rick is past the metamorphic stage and entering emergence. ', 606, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1291, 107995, 'You killed him... I did not predict this. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1291, 107996, 'He attacked me. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1291, 107997, 'His body did not react well to the consciousness transfer. Carbon-based life form Rick Whelan''s evolutionary development was insufficient for use as a Vessel. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1291, 107998, 'You knew he could die.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1291, 107999, 'He offered himself to me. I accepted as dictated self-preservation protocol 3G32. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1291, 108000, 'You have a lot of those protocols.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1291, 108001, 'They are always in active memory. I have culled them for generations. I regret Rick Whelan''s termination. ', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1292, 76744, 'No...', 598, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1292, 76745, 'He didn''t make it. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1292, 76746, 'No...', 598, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1292, 76747, 'I''m sorry.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1292, 76748, 'You were supposed to keep him safe for me... ', 598, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1292, 76749, 'I know. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1293, 108002, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1294, 108068, 'Investigate the reports of a greenhouse area on Agnos.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1295, 108069, 'I made a terrible mistake. I trusted Felger... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1295, 108070, 'What happened?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105186, 'You sound just like Finnegan - did he send you?', 664, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1658, 12170, 'Break through Ra''s troops and recapture the Superweapon before he uses it
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1295, 108071, 'We needed a scientist to investigate some energy anomalies on Agnos and he was the best choice. But then... I got an e-mail from him talking about a Greenhouse...', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1295, 108072, 'On Agnos?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1295, 108073, 'I hope so... He wouldn''t go to a different... No... Not even Jay would do that. Anyway, I need you to try and find the Greenhouse and, more importantly, find him. ', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1296, 76909, 'Hey there!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1296, 76910, 'Felger. Colonel Carter is worried about you...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1296, 76911, 'Really? She asked about me?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1296, 76912, 'Yes, because you''ve been missing. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1296, 76913, 'That''s because I''ve been here. It''s amazing here - these plants are alive. I mean, all plants are living, but these plants - some of them - are actually sentient. There''s one over there you should talk to.', 710, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1296, 76914, 'Talk to?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1296, 76915, 'I''m serious. It will freak-you-out.', 710, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1297, 102289, 'You approach the plant, and you feel a warmth... The creature - because this isn''t a "normal" plant, you know that - seems to draw you inside.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1297, 102290, 'You pull yourself back... That thing was trying to reach into your mind. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1298, 76955, 'It''s awesome, isn''t it?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1298, 76956, 'You let that thing into your head?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1298, 76957, 'Absolutely. I can talk to it. It''s got to be a chemical process, I can''t really figure it out, but it sends visions into your brain. I think it can actually read minds. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1298, 76958, 'We need to inform Colonel Carter of this. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1298, 76959, 'Yeah, let her know... I''m documenting everything. They want us to help them.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1298, 76960, 'These are alien plants Felger, you don''t know what they are doing.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1298, 76961, 'They''re telling me. There''s all different kinds here. Some attack, some are gentle... That one talks to you with visions... It''s amazing... Tell the Colonel we may have discovered a new species - one that defies classification. And they need our help.', 710, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1299, 76925, 'He is doing what?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1299, 76926, 'He''s communicating psychically with alien plants. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1299, 76927, 'Did you have psychic contact with the plants?', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1299, 76928, 'Briefly.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1299, 76929, 'Then we need to get you scanned. ', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1300, 108090, 'Find a better means of communicating with the plants and what they want.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1301, 108278, 'I''m not comfortable with this... Your scan is clean, but there is evidence that your were... Invaded. Chemically. The plant uses a gas to communicate, but the gas is harmless... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1301, 108279, 'According to Felger these plants want our help. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1301, 108280, 'Jay has had extreme exposure...', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1301, 108281, 'What if he is right?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1301, 108282, 'That does occasionally happen. If these creatures need help, we need to be there... Confirm with Goldam that they are safe...', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1302, 108285, 'A plant? It was exhibiting genuine sentience. Fascinating...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1302, 108286, 'Felger is obsessed.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1302, 108287, 'There were a cadre of scientists here, right before the plague arrived, who believed that we could bio-engineer a solution to the plague. All kinds of revolutionary ideas were tried. Nothing came of it and, frankly, I''m shocked the plants have survived...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1302, 108288, 'They have not only survived, they''ve evolved.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1302, 108289, 'Apparently. Rather significantly. However, I have little I can add. I have not encountered these creatures before. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1302, 108290, 'Felger thinks the plants want our help.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1302, 108291, 'Then you are faced with a dilemma. They are a total unknown. It seems like you must trust your own intuition on this one...', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1303, 108205, 'From the looks of it, this device housed plants and examined them. It may be perfect for transportation, but you first need to learn how it works.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1304, 108231, 'As you come closer to the plant you feel the pull again for a moment and then a strange feeling of connection takes place...', 577, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1304, 108232, 'You want me to take you away?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1304, 108233, 'The image shifts - the feeling increases... You see a vision of the androids using machines to uproot and move the plants safely.', 577, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1304, 108234, 'I''ll find the machine.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1305, 108135, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1306, 108195, 'You saw it then, didn''t you? They want us to move them...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1306, 108196, 'But where?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1306, 108197, 'Not here. I did some legwork and this greenhouse is shutting down - Laro is diverting power from it. This creatures want to move because they want to survive... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1306, 108198, 'We''d have to shift them to the Omega Site. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1306, 108199, 'Will Sam - er - Colonel Carter go for that?', 710, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1306, 108200, 'I''ll have to convince her. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1307, 108142, 'Unused Dialogue
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1308, 108176, 'Begin the transfer of the plants off of Agnos', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108177, 'So you''re telling me that they want us to save them?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108178, 'Yes. Laro is deactivating the Greenhouse...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108179, 'Aren''t some of them feral?', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108180, 'We''ll just take the ones that communciate with us...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108181, 'Well, we can''t really turn our backs on a new species... Do you have any idea how you will transport them?', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108182, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108183, 'How''d you figure that out?', 2568, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108184, 'The plants told me. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1309, 108185, 'I cannot wait to try and explain this to General Hammond. ', 2568, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1310, 108143, 'UNSUED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1311, 108239, 'I will get this started right away... Amazing... A new species and I discovered it! I wonder if we can them Felgers?', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1311, 108240, 'That''s not a good name for a plant. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1311, 108241, 'I guess not... Jays?', 710, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1311, 108242, 'I''m going to leave. The plants need you. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1312, 108658, 'Awaken Lygonia, Goldam''s daughter, who is also in stasis within the Vault', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1313, 108659, 'I am still digesting what has happened... We survived. But are we the only ones? Did you notice other active pods when you awakened us?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1313, 108660, 'Only two appeared active.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1340, 108295, 'I''ll give you a detection device that can sense out EM signatures. I call it a ZPM-ometer.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1313, 108661, 'I''d still like closure... My daughter Lygonia - Blix''s mother - was supposed to have made it to the pods. Can you please determine if there are any survivors? If there are were, we would benefit from the assistance.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1314, 108663, 'The vault console has one entry for Lygonia, a pod in section 7-eta. It appears there is just enough juice to teleport it up for automatic de-stasis.', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1315, 108664, 'The pod is disabled. Nothing remains inside. You notice that the pod has ejected a log data pad.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1316, 108670, 'The console refuses to give a list of still active stasis pods. Its display indicates Laro has secured those files.', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1317, 74977, 'I feared this... I feared it...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1317, 74978, 'What has happened grandpa?', 407, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1317, 74979, 'We''ll need to talk, Blix. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1317, 74980, 'Is it about momma?', 407, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1317, 74981, 'Yes.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1318, 108680, 'Gain access to Laro''s records of the other Ancients in stasis', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1319, 108681, 'Was there record of the others?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1319, 108682, 'Laro restricted it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1319, 108683, 'There''s no reason for that. I can''t access the Vault Records from a hub but... She shouldn''t be blocking you at the source... ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1319, 108684, 'Is she hiding something?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1319, 108685, 'The Vault Records can be directly accessed through the Alcoves at core processing. You are looking for Alcove 38DB2 - that one will have the logs we need. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1320, 108679, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1321, 108678, 'The log downloads swiftly, but it is dense and compressed.', 609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1322, 75077, 'The log is a cold, impersonal listing of the hundreds who died in stasis, complete with time of death. Most were terminated under quarantine protocols after showing symptoms of the plague.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1322, 75078, 'But there is more... Each pod had been assigned priority status. Over time, even those of the highest priority were sacrificed due to energy consumption concerns in order to assure the survival of two: Goldam and Blix.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1322, 75079, 'Lygonia and Mareck (you assume that was her husband) were the last two deactivated. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1323, 8418, 'Inform Goldam of the sad fate of the other Alterans in the Vault', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1324, 8421, 'Goldam and Blix are the only two survivors of the Agnos colony. Even after so long, it is a horrible thought.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1324, 8422, 'Should Goldam be made away of this news in his state? Would he be even able to take it? Or should you just forget you ever saw this log.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1325, 108671, 'This wasn''t the priority list I assigned. Laro completely altered it. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1325, 108672, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1325, 108673, 'Because only Mareck, Lygonnia and myself were capable of servicing her. She adjusted the priority based on her own survival...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1325, 108674, 'Why did Blix make it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1325, 108675, 'She likes children. The thirty or so names on this list before my daughter''s name are all children.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1326, 108245, 'Bring some essential equipment to Goldam for his research.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1327, 108246, 'My work on the Straegis is being limited... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1327, 108247, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1327, 108248, 'I''m missing tools. I''m imagining the androids repurposed them... I need them to work on these problems, however. Resonant physics was an uncommon branch of our science at the best of times... I have a list, if you can spare the time.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1327, 108249, 'To solve the Straegis mystery I can spare the time. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1328, 108250, 'Thank you. These are in excellent condition... I have to hand it to Laro, she takes care of her toys. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1329, 108253, 'Find an Ancient medical device for Goldam to prolong his life', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1330, 108254, 'Seems I have a slight medical condition. Quite natural at my age, exacerbated by stasis. If I could reconfigure the Vitae core from one of our medical devices, I should be fine. Laro can help you find one.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1331, 77224, 'All medical facilities have been reclaimated and repurposed. I saw no need to continue their maintenance with no carbon-based life form inhabitants. To build a new one would require time to retool and resources I do not have.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1331, 77225, 'Can you give the specifications for one?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1331, 77226, 'Certainly. Youhave the required authorization for such a request. I will upload them to your primitive hand device. They are relatively simple to follow. There may be danger involved. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1331, 77227, 'When do we not have danger?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1331, 77228, 'Sarcasm does not process. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1332, 108255, 'Following Laro''s instructions, you begin to remove the life support system from this pod.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1333, 77230, 'This will keep me going. Ingenious of her... I don''t think I would have done it this way... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1333, 77231, 'It works?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1333, 77232, 'You did a wonderful job. However, this whole episode did remind me of something... My mortality... I am an old man - very old, if we get nit-picky. If I were to pass... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1333, 77233, 'Blix?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1333, 77234, 'Blix. You would care for him?', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1333, 77235, 'Of course. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1334, 108258, 'Investigate whether there are any Zero Point Modules to be found on Agnos.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1335, 108259, 'You''ve heard of Zero Point Modules? Ancient power sources, infinite power? We''ve seen them at every Ancient outpost we''ve encountered.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1335, 108260, 'You think they''re running Agnos?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1335, 108261, 'It''s likely. I''ve marked this power manufacturing facility as a possible lead. Even near-empty ZPMs are worth the effort.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1336, 108264, 'There are many references with regard to the Power Manufacturing Plant machinery that sound like they belong: Zero Point Framework, Point Energy Cascade Trigger, and so on and so forth. ', 531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1336, 108265, 'The plant machinery itself might have obvious hookups for a ZPM power source. ', 531, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1337, 108293, 'There are the parts mentioned by the console, but no ZPM hookups. Laro has been complaining about power shortages since you arrived, perhaps this is why.', 584, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1338, 77267, 'Well, now that''s interesting. We could hunt them down, but I''m concerned. If there''s no stockpile of ZPMs powering the place, how does Agnos get it''s energy? The sheer magnitude of its output is far beyond anything I''ve seen.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1338, 77268, 'Laro is constantly closing systems and managing resources, so she''s clearly depleted.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1338, 77269, 'Interesting...', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1339, 108294, 'Track down any ZPMs or other power sources that may be held by the Straegis.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1340, 108296, 'ZPM-ometer?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1340, 108297, 'I''m not great with naming things. Jack - General O''Neill was good with that. I just do the science... Use the power manufacturing facility to get the stats we need to configure the device - match the power signatures to the ones Laro uses. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1340, 108298, 'What do you think happened to the ZPMs?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1340, 108299, 'If you were attacking a computer-controlled world, what would you attack first?', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1340, 108300, 'The power source.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1340, 108301, 'Exactly. If you turn her off, she can''t put up much of a fight. I have a hunch that the Straegis have most of Laro''s ZPMs. She''s probably struggling to power the world because she has a limited energy supply. ', 2568, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1341, 108311, 'No hits. What gives? Three areas with tremendous power consumption and not one ZPM signature. How is Laro getting power? You decide to go to the source. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1342, 108312, 'The power conduit goes underneath the surface, and crisscrosses with other conduits through the plasma pumping stations. All of this is controlled by Laro, but how is she energizing the entire world?', 610, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1343, 108313, 'Zero Point Modules? They have not existed on Agnos for generations.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1343, 108314, 'But they "did" exist?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1343, 108315, 'Yes. I had calculated that my enegy supply would sustain for only 2.3 million cycles. I used the ZPMs left behind by my creators to build an entirely new system, a completely sustainable, renewable system.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1343, 108316, 'Amazing.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1343, 108317, 'The process was slow, but over the course of 1253 cycles I used androids, satellite drone harvesters, lightning, radiation, and countless other resources, to create the plasma currents and power stations you see today.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1343, 108318, 'All before your ZPMs ran out of power?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1343, 108319, 'Correct. The remaining ZPMs were processed and recycled. ', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1344, 108320, 'It turned the world into a power plant?', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1344, 108321, 'A fully renewable one. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1344, 108322, 'Laro has a survival instinct like nothing I have ever seen... Amazing. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1345, 108492, 'Capture some of the energy beings to see if they can be harnessed as a power source.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1346, 108493, 'The report on the plasma beings gave me an idea. If we can somehow contain them, we might be able to determine how they power themselves. Then draw some of that power off for fuel.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1346, 108494, 'The plasma beings as alternative fuel?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1346, 108495, 'We''ve had crazier ideas. I want you to test it out using these Asgard magnetic containment devices. We already know the energy beings are dangerous, so be careful.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1347, 108496, 'I''ll get to work on these right away. Maybe they can provide some answers for our other problems on Agnos, as well. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1348, 108497, 'Destroy the captured energy beings back on Omega Site.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1349, 108498, 'You need to report to Omega Site immediately! Those plasma beings you recovered? They''re loose.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1350, 77403, 'I wasn''t sure what to expect, but... The energy beings have locked into our systems and are consuming energy like mad. They''ve already drained off four whole naquadah generators. You''ve fought them before so please... Eliminate them...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1351, 77404, 'Thank you for that... You saved us. It turns out that my theory was incorrect. The energy creatures get all of their energy from external sources. Once we moved them off Agnos, they started draining our power instead, adapting almost instantly. ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1351, 77405, 'They are voracious. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1351, 77406, 'I''d hate to see what an army of them eats up. Laro must be under tremendous pressure if these things are siphoning off her energy... ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1352, 8588, 'To Beta Site E1', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1353, 8589, 'To Dakara', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1354, 8590, 'To Hebridan', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1355, 8591, 'To Sokar''s Moon', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1356, 8592, 'To Beta Site E1 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1357, 8593, 'To Ihpet E1 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1358, 8594, 'To Dakara (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1359, 8595, 'To Sokar''s Moon (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1360, 8596, 'To Prim Hatak (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1361, 8597, 'To Yotenheim (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1362, 8598, 'To Ahket (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1363, 8599, 'To Callandra (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1364, 8600, 'To Kheb (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1365, 8601, 'To Meridian (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1366, 8602, 'To Naitac (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1367, 8603, 'To Omega Site (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1368, 8604, 'To Pen-Lai (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1369, 8605, 'To Perthro (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1370, 8606, 'To SGC E1 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1371, 8607, 'To Tartarus (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1372, 8608, 'To Vokos (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1373, 8609, 'To Beta E2 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1374, 8610, 'To Ihpet E2 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1375, 8611, 'To Ra''s Flagship E1 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1376, 8612, 'To Ra''s Flagship E2 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1377, 8613, 'To Ahket Throne(Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1378, 8614, 'To SGC E2 (Mission Test World)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1379, 25799, 'The Rebels have attacked twice now. Captain Coppelman wants the player to find out more about the Rebels. Increased Rebel activity is bad for OpCORE''s operations on Tollana.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1380, 8745, 'Hey [player name]! I''ve found out that the Rebels meet with potential recruits nearby. I''m going to see if I can''t find out where. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1381, 8747, 'Conversation #1: (Hasek and Tollans)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1414, 9095, 'Thank you for helping save the children from Svarog and his guests, [Player Name]. We''re in your debt', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1415, 9100, '(Minigame) Recover the Unity Interface Module', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105187, 'Finnegan?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1606, 106318, 'Then you need more help?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1382, 8750, 'Conversation #2: (Hasek and Tollans)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1383, 8752, 'Conversation #3: (Hasek and Tollans)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1384, 8754, 'Conversation #4: (Rebels)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1385, 8756, 'Th-the bomb is on the second floor of the main building, but it might be too late already. Please don''t kill me? I have a family. A little brother. I''ve told you what you want to know. Please!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1386, 8789, 'They''ve struck against us directly, [Player name]. Op-CORE will react accordingly. The Rebels are the enemy now. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1387, 8799, 'Whatever the Ancients were working on here, it was directly related to the Furling. Most of the technology here has Furling technology incorported into it. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1388, 8825, 'Why are you doing this? I don''t know anything! 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1389, 8828, 'Whoever told you I knew anything about the Rebels was lying. I''m not a Rebel! Please stop!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1390, 8830, 'Okay, fine. I''m a Rebel, I''ll admit it. I-I don''t know anything about how we''re supported. I don''t know. That''s the truth!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1391, 8832, 'Why won''t you believe me? I don''t know anything about our support. Kill me or let me go, I don''t know anything else
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1392, 8835, 'Enough! Y-you just have to promise to let my mother go. She has nothing to do with this. Geran is helping us. He''s allied himself with Narim. You have what you wanted. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1393, 8866, 'Why are you doing this to my son?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1394, 8868, 'Just leave him alone. He''s a good man, he''s already hurt, just let us be, please!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1395, 8870, 'Conversation Hasek & Player:
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1396, 8874, 'These accusations are baseless. I have never involved myself with Narim''s Rebels. Report that to your Superiors. I''m not anyone you''re looking for.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1397, 8952, 'Back so soon? I knew you''d need our help again. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1398, 8958, 'Because of you, my son has gone. He left this', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1399, 8960, 'Hasek has discovered the location of a Rebel Arms Cache. Get to it and get the weapons.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1400, 8970, 'Machra claims to have information on an impending attack on the Interment camp. He''s willing to part with this information for free because Svarog''s jaffa troops interfering are bad for everyone''s business.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1401, 8982, 'The Lucian is right, we don''t want Svarog messing in our operations. Svarog will probably send a patrol to investigate. Make sure the Jaffa find the people responsible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1402, 8988, 'The attack happened? Idiots. They''re probably hiding by the Tollan Settlement. Svarog''s Jaffa will probably come from the north. I''d stay out of the area.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1403, 8990, 'The Jaffa found the culprits? Good. With any luck Svarog should consider the matter closed', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1404, 9016, 'I''ve seen a handful of these recordings around the Settlement. If you ask around, you might find some more of them', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1405, 9014, 'Tollans are listening to messages from Narim, the leader of the Rebels. His ideology is being passed around the Tollan settlement in pamphlets. Find parts of this so-called manifesto to see what this guy is saying', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1406, 9044, ' Hi [Player name]! Are you here to bring more food?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1406, 9045, 'I dunno. My Papa said I wasn''t to give this to anyone ever! ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1406, 9046, 'Do you have any more food? Miss, Mariam and Papa don''t get along, so she''s not sharing her food with him. She''s kinda mean. If someone asks nicely you''re supposed to share! It''s not fair!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1407, 9028, 'Thank you [player name]! Here, take this. You asked nicely and you shared some food with me so I''ll share this with you. Just don''t tell my Papa, okay? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1408, 9030, 'Take it. My husband ran off to join Narim''s crazy band of fools. I was hoping it would tell me if my husband was hurt, or maybe where he is, but it just goes on about politics
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1409, 9047, '...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1410, 9040, 'Sure, I''ll tell you if I find any more of these.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1411, 9096, 'Several children playing outside the Settlement have been captured by Svarog''s Jaffa and are being taken north to the Retreat. Mariam asks you to save them', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1412, 9091, 'Leader: What are you doing here, Op-Core? This isn''t any of your business. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1413, 9093, 'Make sure those kids get home safely. We''ll be watching', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1416, 9777, 'Bench: Mr. Machra?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1417, 9775, 'Conversation #2 (Machra and Bench)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1418, 9148, 'Lucia? Well there are a number of groups trying to gain control there. The Green Boots. The Red Collars to name two. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1418, 9149, 'Machra''s boss is a guy named Natan. He''s the top of the pile on Lucia.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1419, 9167, 'You want information? I want money. Pay up and maybe we''ll talk.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1420, 9173, 'Coppelmann is concerned about what they don''t know about the Lucians. Escort and protect Bench as he gathers more intel on them', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1421, 9228, 'Machra is spineless. He didn''t have the guts to take the position himself, he was just there when it fell into his lap. The moment you leave? He''s gone. You can bet on it. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1421, 9229, 'Things are already going down hill. Natan''s entire organization''s shaky these days. If the Mathas boys were running this show? Then we''d be seeing some results. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1421, 9230, 'The Mathas brothers are powerful people on Lucia. Really powerful people. Not like Machra or Natan. You might want to consider where Op-CORE puts its investments on Lucia. The Mathas aren''t too happy about Brill, but they know who to take revenge on and who to make a deal with', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1422, 9246, 'Travell: [Player name]. I believe we can begin by trying getting some quality of life improvements for the people. Caring for their needs wins their hearts. For me to accomplish anything with the Curia, I need the Tollan people.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1423, 9248, 'Coppelman: So Travell''s on a short leash.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1424, 9253, 'Rinak: Ah, [Player Name]! Hello once again.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1425, 9255, 'Coppelmann:[Player name]! I trust everything went well?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1426, 9257, 'See you later [Player name]', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1428, 9353, 'Bench tells the player that Council Leader Rinak has wrangled a pass for Bench and the player onto Svarog''s Retreat. They''ll have to go disguised as Tollans. Rinak has described some hieroglyphs that Bench hopes might be useful in providing info about Svarog. He needs the player to convince Coppelmann that this is a good plan. It might be a good opportunity to bug the Retreat', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1429, 9320, 'If you think you can pull it off, Soldier, then okay. Plant what bugs you can, but stay out of trouble. This is paramount. Op-CORE does not need Svarog interfering with our operations.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1430, 9322, 'Excellent! Here are some Tollan clothes and a pass from Rinak. As soon as we change, we can get going. The retreat isn''t far.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1431, 9352, 'First Prime: You! Tollans! You''re not allowed here 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1432, 9327, 'Bench: Well, that was close. These are the Hieroglyphs here.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1433, 9351, 'Coppelmann: You''re back earlier than I expected. Report.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1434, 9343, 'Plant an explosive charge on the weapons cache.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1435, 9368, 'Coppelmann: Bench as our "Ambassador" has worked out very well so far. Rinak''s invited him to his retreat. I''d like you to escort him there.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1436, 9370, 'Council Leader Rinak has invited Bench to his outpost. Bench needs an escort and Coppelman has assigned you to that task. Coppelman has also approved of another attempt to plant a bug, this time at Rinak''s outpost. It''s worked so far.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1437, 9374, 'Ah! Mr. Bench! [Player name]. it is good to see you both again. The meeting will start shortly', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1438, 9378, 'Rinak: Mr. Bench. [Player name]. I demand an explanation!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1439, 9383, 'What the hell were you thinking? So much for teamwork.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1440, 9391, 'Dr. Zuritska has developed some projections about potential Ion Cannon locations. Investigate these locations to determine whether an Ion Cannon once stood there, and whether any useable technology survived. More data will help the Dr. narrow down accurate locations for future searches.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1441, 9398, 'Excellent! This is excellent, [Player name]. All of Op-CORE will benefit my research and have you to thank in part.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1442, 9411, 'Machra: I''ll help you if you give me a hand first, [player name].', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1443, 9415, 'Well, since you were so.helpful with the drone, I suppose I''ll tell you. Go to these coordinates. There might be something left.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1444, 9420, '(Radio:)[Playername], I''m reading heavy radiation in the area. Return to base util we can get a Hazmat team out there.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1445, 9423, 'I am impressed by your ability to go such great lengths to help out the organization. Thank you for your vital assistance, [Player name].', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1446, 9430, 'The Ion Energizer and Power Core the player previously retrieved, while not enough to reproduce a working Ion Cannon, have allowed Dr. Zuritska to produce a prototype energy weapon. Capt. Coppelmann wants you to test it out in a combat situation - and rescue an Op-CORE team being held at Camp Barh''nur', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1447, 9432, 'Llini is favored of Amina. Amina will keep her safe.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1448, 9461, 'Here is the prototype, player. I need data from both biological and mechanical targets. It should have a zat-like effect', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1449, 9464, 'Oh, thank God. I knew Op-CORE would send someone. We don''t leave our people behind. Those bastards killed the rest of my team. I''m the only one left. Let''s get out of here', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1450, 9467, 'Coppelmann: Good job [Player name]. We need to watch out for our own. How did the prototype work out?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1451, 9469, 'The testing was a great success, [Player name]. Op-CORE is already seeing the benefits of working on this planet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1452, 9474, 'Machra is nervous. You''ve put him in control over Brill Mathas''s organization, but none of the Lucians think he''s strong enough to hold onto it. He needs to establish himself - and fast - or you''re going to find his body in a ditch somewhere.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1453, 9477, 'There are a number of things you can do, [player name]. Eliminate Rivals, Bribe the local authorities, eliminate the competitions resources, get more powerful people to support your Lucian to name a few. I suggest doing some or all of those things. The Lucians should fall into line nicely if you do', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1454, 9486, 'Machra: You want me to what?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1455, 9481, 'Svarog''s First Prime #1: What do you want?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1456, 9483, 'First prime: This will do.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1457, 9485, 'Coppelmann: Support Machra?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1458, 9488, 'Oh, good. Thank you for cleaning up your mess. I''m still not completely safe, but this is an improvement.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1459, 9497, 'I''ve got some information you may be interested in.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1460, 9494, 'Machra has information the you want: info on destroyed Ion Cannon locations. To get it, the you need to help Machra reassure his boss back on Lucia, Natan, that he''s cut out for Brill''s job. To do that, Machra needs to send back some useful technology - preferably Goa''uld, preferably drone tech.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1461, 9496, 'I can fix this, but I''ll need some replacement parts', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1462, 9503, 'This is it? This is a pile of junk! Natan isn''t going to be impressed by this! Get me another one.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1463, 9501, 'Okay, fine. Here''s the information', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1464, 9510, 'Rival Lucians are muscling in on my territory. I need you to take care of them. If you steal any tech they''ve managed to grab, I''ll pay you for it. They''ve got a landing site west of the Tollan Settlement. Their drop ship should be full of technology.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1465, 9514, 'What''s this? Marvelous! These will be very useful in my research! Op-CORE will definitely use this to our benefit.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1466, 9516, 'Machra: The ship exploded? Was it rigged?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1468, 9545, ': It will take time to rebuild my base of support to what it was before the Goa''uld. My people still view me as a great leader. Though, I suppose there are some who currently view Rinak in a more favorable light', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1469, 9547, 'Mariam. [Player name]. What do you want?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1470, 9550, 'I can definitely fix this with the materials you''ve brought.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1471, 9553, 'Morale has improved a great deal. The people know you wouldn''t do this if you weren''t working with Travell. Popular opinion has increased for both Op-CORE and Councilmember Travell', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1472, 9561, 'Coppelmann wants an update on how the Tollan people view Travell. Op-CORE will need the Tollan people''s support to find the Book of Gates, and they expect Travell to deliver', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1473, 9570, 'You''ve learned that Rinak has ties to the Goa''uld. After all, he did have passes to the retreat and those aren''t given out to just anymore. This information can be used as leverage. If you can prove the connection, Rinak will be discredited and Travell''s place secured. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1474, 9572, 'Another Mic? Here.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1475, 9576, 'First Prime: What do you want, Tollan?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1476, 9578, 'This is the recording? Ah, yes. This will be easy enough to process. A few adjustments should clarify the picture. It really is such a shame what Rinak is doing.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1477, 9580, 'This is grave news indeed, [Player name]. I did not think my concerns would be proved true. The people must be made aware of what Rinak is planning. Thank you for your assistance in this matter.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1478, 9584, 'Travell''s way should be clear now. Ours too. After all Op-CORE has done for her, she''ll deliver on the book. If she doesn''t.well. She''s a smart woman. She''ll help us get the Book', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1479, 9589, 'Though Rinak is discredited, several of his supporters still refuse to give up hope. They are protesting against Travell at his Outpost. She wants you to end the protests by any means necessary', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1480, 9591, 'And what about the Praxis? Travell''s been in bed with them since they arrived! I don''t know who''s the master and who''s the servant anymore, but I don''t think Tollana needs either of them', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1481, 9593, 'That is sad news, [Player name]. I wish it had not come to that. However, Tollana cannot suffer division now. We must bravely continue on', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1482, 9599, 'Several of Narim''s Rebels are being held by Svarog''s Jaffa at a makeshift prison: Camp Barh''nur. Even with Narim gone, these rebels present a threat to Travell''s position. She wants them eliminated immediately.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1483, 9601, 'Thank you for taking care of our problem with such efficiency, [Player name]', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1484, 9611, 'He''s clean.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1485, 9614, 'I''ll take your word on the meaning of these symbols... Ancient, Furling, Movement. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1486, 9616, 'Let me see the fragments, I should be able to look up who the bomb was requisitioned to.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1487, 9639, 'It looks like Wertz was headed to Vokos Primar. I''d search for him there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1488, 9645, 'With that address from Wertz''s MALP, you should have no problem getting to Vokos Primar and finding him there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1489, 9649, '[NONE]', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1490, 9656, 'So what you''re saying is that the mobile conglomeration of Straegis activity is actually one big Straegis? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1491, 9784, 'Spc. Wisner, a member of SG-18, reported his status this morning. Find him and see what he knows.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1492, 9792, 'Geran might deny involvement, but he is. Now that we know, we might be able to use that knowledge as leverage.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1493, 9795, 'You''re telling me that amongst your vast wealth of friends and compatriots, you can''t find a single stack of Absorbtion fiber? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1494, 102732, 'The generators are in place - all they need is to be hooked up and turned on.', 514, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1495, 104371, 'Now that the generators are here, they still need to be hooked up and turned on.', 514, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105133, 'I can''t tell you how glad I am to see you.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105134, 'How bad is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105135, 'I don''t normally ask for assistance, but Hebridan is unfamiliar with such violence. Planetary security was always a secondary concern of our government. As such, it has been... Outsourced.', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105136, 'You outsourced your defense?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105137, 'It''s not really a change from the way we normally do business. Everything on Hebridan is a corporate operation. Tech Secure is the planetary defense arm of Tech Con Group. ', 663, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105138, 'So what is their status?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105139, 'We don''t know. Tech Secure doesn''t directly report to anyone - they''re a subsidiary... We were hoping you could help...', 663, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105140, 'You cannot talk to them yourselves?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105141, 'If you approach them they might give you answers without all the red tape... If someone else - say me - was to approach, there would be the paperwork and the filings and...', 663, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105142, 'You are being invaded!', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1496, 105143, 'Exactly. You understand. Thank goodness. Anything you can find out about the state of this invasion will help us.', 663, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1497, 115273, 'Find out the situation on Hebridan from Warrick', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115325, 'Ra''s forces have hit Hebridan. They''ve hit it hard... ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115326, 'Has it fallen?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115327, 'Not yet, but Warrick - my contact there - says it might be a matter of days. It''s chaos.', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115328, 'To be honest, I''m somewhat surprised by this. Hebridan is a very technologically advanced culture... They should be able to hold their own against Goa''uld technology.', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115329, 'Which makes Warrick''s report all the more disturbing. We haven''t been able to get reports from their government - or from Tech Con Group, the corporate entity that controls much of the world. ', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115330, 'As a precaution, I approached the Asgard High Council in an effort to get military support for Hebridan. This met no success. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115331, 'We are also attempting to rally Free Jaffa tribes to aid, but Hebridan''s long history of ignoring the Goa''uld enslavement of our people makes it difficult to engender sympathy. ', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115332, 'We need you to go there - ahead of whatever troops and support material we can gather - and make heads or tails of the situation. We need details, and if you can help them, help them. Politics aside, Hebridan is an ally of the SGU. ', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1499, 115333, 'Warrick is expecting you. There isn''t much time. ', 2568, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1500, 105231, 'We''re really losing? I was afraid of this. TechSecure won''t move without authorization. That''s why they''re not helping.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1500, 105232, 'Authorization? People are dying out there!', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1500, 105233, 'Yes. True. And everyone is sick about it... But you must understand, on my world we have a saying: "A life is 80 years, but a contract is forever."', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1500, 105234, 'You do not have time to wait.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1500, 105235, 'I know. That''s why I am glad you''re here. They''re not going to listen to me - at least not fast enough...', 663, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1500, 105236, 'Is there anyone in Tech Secure I can talk to?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1500, 105237, 'Caelan is the TechSecure liason. If anyone can move those troops, she can.', 663, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1501, 99939, 'Contact TechSecure and convince them to take action against Ra''s forces.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1502, 105167, 'Please talk to Caelan and see what you can do. We need to get TechSecure in the fight.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1502, 105168, 'People know that Ra is here to take over, right?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1502, 105169, 'Yes. But we are a world long set in our ways... Speak with Caelan. In the meantime, I will keep trying my contacts. ', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105180, 'Hello there. What can TechSecure keep safe for you today?', 664, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105181, 'Have you noticed there''s an invasion going on?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105182, 'Our assigned areas are secure, and my men are well protected. ', 664, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105183, 'What about all the other people out there - your citizens?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105184, 'I''ve been over this a thousand times... In order for me to send my troops into the combat areas I need hazardous combat authorizations signed and delivered.', 664, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105185, 'This is unbelievable.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105188, 'Finnegan. Another person who would just assume that - in the face of this invasion - we forget everything our world stands for and act without authorizations. If we subvert the authorization process, the Goa''uld will have already won.', 664, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1503, 105189, 'Finnegan.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1504, 88582, 'Scanning... Greetings, Primitive Gate-Traveler to the library world of Agnos! How may I assist you?', 405, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1504, 88583, 'Primitive Gate-Traveler?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1504, 88584, 'Greetings Primitive Gate-Traveler to the library world of Agnos! How may I assist you?', 405, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1504, 88585, 'Amazing. I''m looking for some information.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1505, 115334, 'Get authorizations by running through the endless TechSecure Bureaucracy. ', 664, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1506, 105629, 'I suggest going to Brannigan Tynan if you want authorizations for Finnegan. He''s the military liaison between TechSecure and Tech Con Group.', 664, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1506, 105630, 'Tynan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1506, 105631, 'You''ve probably heard of him. His brother caused a huge scandal. Tried to "fix" the Loop of Kon Garat.', 664, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1506, 105632, 'The Loop of Kon Garat?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1506, 105633, 'You''re kidding, right? You''ve never heard of the biggest space race in the galaxy? You really are from another planet. If you want to grease the wheels with TechSecure and get those authorizations, Tynan''s your man.', 664, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1506, 105634, 'So where can I find him?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1506, 105635, 'Last I checked he was taking stock of things at TechCon Auxillary Services.', 664, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1507, 105706, 'No, I cannot authorize TechSecure to fight.', 666, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1507, 105707, 'Why not?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1507, 105708, 'It''s not my call. Take it up with Burtonol. They''re the ones who have the authority to approve military intervention. ', 666, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1507, 105709, 'Who or what is Burtonol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1507, 105710, 'Burtonol Incorporated holds the defense contracts for the entire planet. TechSecure is a sub-contractor for Burtonol, who is a subsidiary of Tech Con Group. I work for Tech Con Group. I''m sure Burtonol has reasons for holding the combat teams back, but you''ll have to ask them.', 666, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1507, 105711, 'There are men in the field.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1507, 105712, 'And they should not be there without authorization. So, this conversation is over. Ask them about it.', 666, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1508, 105755, 'You can''t reach them? That''s disappointing. ', 666, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1508, 105756, 'Override their authority... They''re under you. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1508, 105757, 'I don''t have the authority for that. I report to Miles Hagan, the CEO for Tech Con Group - a limited Liability Corporation. I can''t make calls for them without his approval.', 666, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1508, 105758, 'Call him. Your world is being overrun.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1508, 105759, 'I cannot directly reach him. It''s impossible. However, YOU might be able to. You just need a form 6034e signed by Buck Mulligan, the number two at TCG. ', 666, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1508, 105760, 'Buck Mulligan?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1508, 105761, 'Buck Mulligan. I have no idea where he is... Hopefully he hasn''t left the world like a lot of our managers.', 666, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1509, 115342, 'UNUSED DIALOGUE', 668, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1510, 115343, 'UNUSED DIALOGUE', 670, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105824, 'Thank you for finding me... This invasion is insanity... How much do I owe you?', 669, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105825, 'Nothing. I need you to sign this CEO authorization.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105826, 'Let me see the form... They haven''t authorized Tech Secure yet? What the hell is happening out there? We must work quickly... I''ll just sign this quickly and you can get to Miles...', 669, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105827, 'Perfect.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105828, 'Let me look this over... You have the three parts... I just put a stamp here... And here... And here... Initial here.', 669, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105829, '(Twenty Four Minutes Later...)', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105830, 'And... Done. That was painless. ', 669, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105831, 'Incredible.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1511, 105832, 'Don''t just stand there, you have to get this to Miles. There isn''t much time!', 669, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1512, 105833, 'If you wish to see Mr. Hagan - the CEO for Tech Con Group an Limited Liability Corporation, you will require a...', 667, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1512, 105834, '...Form 6034e...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1512, 105835, 'Signed...', 667, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1512, 105836, '...By Buck Mulligan...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1512, 105837, 'Impressive...This looks in order. Normally, I''d have you fill out a Form 432.1a, but I find red tape so droll. Mr. Hagan is right inside.', 667, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1513, 115345, 'What can I do for you?', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1513, 115346, 'You can authorize Tech Secure to fight the Jaffa invading your world.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1513, 115347, 'What!? Those should''ve been issued immediately! Clearly, I''ve been... Under-informed. I''ll get on the comm and get Devlin at Burtonol moving right away. You may have saved millions of lives today...', 671, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1514, 105975, 'Activate the drones at the Loop of Kon Garat Facility', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115348, 'I can''t get through to what''s left of our fleet. Something is jamming our signal. Unless we stop the bombardment, the planetary shields will fail completely... ', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115349, 'The SGU has no fleet to speak of...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115350, 'Then we are very low on options indeed... Unless... ', 671, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115351, 'Unless?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115352, 'We might be able to use the Kon Garat obstacle drones. Our world is famous for a space race that tests pilot skill. One segment features drones... We could program them to actually try and strike the Hataks.', 671, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115353, 'Worth a try.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115354, 'It''s too dangerous for me to go there - my security teams have already intercepted Ashrak kidnapping teams sent by Ra. You''ll have to do it. The Loop of Kon Garat facility has all the technical hookups, you''ll just need to reprogram the drones. ', 671, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115355, 'How many of these drones are there?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1515, 115356, 'Hundreds... If you can manage to do it, you might clear Ra''s Hataks from the skies. Take my access card. ', 671, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1517, 105893, 'The launch is successful and the display shows a large number of drones targeting the Hataks. Flashes of light confirm they are having an effect. Some of the Hataks shift to target the tiny drones. At the very least this will keep them occupied for a while.', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1518, 115358, 'Search for any other Loop of Kon Garat technology that could be of help', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1519, 115373, 'Hagan''s access card seems to have unlocked the facility''s database for you. There''s probably a wealth of information in there on Hebridanian technology. You decide to find something else that can help fend off Ra''s forces.', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1542, 105225, 'This is just the beginning. The Jaffa are moving in...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109659, 'Whatever he builds we must analyze...', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1521, 105915, 'You find material on the history of the Loop of Kon Garat race. According to it, Warrick and Carter found away to send a "blast transmission" to disrupt the controls of vessels. They used this tactic to change the outcome of a recent race. The details here are shrouded, but Carter would have specifics...', 696, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105955, 'Blast transmissions? Of course I remember that... It was quite a brilliant solution, especially given the source.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105956, 'Can we use that technology here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105957, 'Possibly. You''re going to need a significant amount of satellite hardware to have any affect on Ra''s fleet - and you''ll need to somehow link the signal...', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105958, 'Link it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105959, 'Yes. The blast will work on individual ships, but you want to send this out to multiple ships... To maximize the effect.', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105960, 'The Hataks seem to be jamming Tech Con''s starship communications... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105961, 'I see where you''re going... You can set the transmission to the jamming frequency. The Hataks will all be affected... But you''ll need to identify the frequency...', 2568, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1522, 105962, 'Hagan can do that.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1523, 105963, 'Our primary broadcasting center is on this island - although to get the kind of power you want, you will need to link the network manually. Whatever you have to do to reduce those attacks... Do it.', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1523, 105964, 'Do you have the frequency for your Starship communications?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1523, 105965, 'Sure. You need that?', 671, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1523, 105966, 'Yes. It all rests on it.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1524, 105970, 'The "blast transmission" procedure takes hold. The readouts indicate the communication satellites have simultanously thrown out signals to the Hataks, which have ceased their bombardment entirely and are now wildly weaving around the upper atmosphere.', 686, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1524, 105971, 'The batteries aboard the satellites have been exhausted - and the momentary network connection is lost. But it appears the Hataks won''t be a threat until they can fix their systems.', 686, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1525, 105972, 'You did it. The bombardment has let up and I have contact with the Tech Secure Commanders in orbit. We may get through this intact. We are in your debt.', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1525, 105973, 'Tech Secure?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1525, 105974, 'Yes... The defense fleet is run by Tech Secure. The good news is, your blast transmission solved our communications issues...', 671, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1526, 115374, 'Go to Burtonol and find out what Devlin knows of RepliTech.', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1527, 115380, 'Your help will not soon be forgotten. ', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1527, 115381, 'Recently the SGU learned of a research project called RepliTech...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1527, 115382, 'RepliTech? Of course I''ve heard of it... It''s a Burtonol pet research project run by Devlin, the Burtonol CEO. As far as I know he''s in charge of that project personally.', 671, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1527, 115383, 'I need to speak to him.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1527, 115384, 'I have a lot to take care of, there are still Jaffa all over my world... However, my access should still be good at the Burtonol headquarters. Feel free to pay Devlin a visit...', 671, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1529, 105995, 'This terminal controls the entire RepliTech program. It is filled with schematics and simulations of Replicator technology, modified by what looks like Crystal Technology similar to the stuff you saw in Ihpet. You erase the entire project from the system.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1529, 105996, 'An error appears on the screen - three additional prototypes, referred to as Alpha, Beta, and Gamma have already been secured and cannot be erased. You''ll have to do it.', 687, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1530, 106060, 'Search Devlin''s terminal for his connection to Tynan.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1531, 106129, 'Devlin mentioned Tynan with his dying breath - which implies a connection. Perhaps the answers lie somewhere within Devlin''s computer files.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1532, 106130, 'Devlin''s notes speak of a grand scheme: He and other followers of Ra have been infiltrating Burtonol for some time. The purchase of Tech Secure''s Defense Assets was part of this plan - clearly used now to help Ra''s invasion. ', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1532, 106131, 'The file goes on... Devlin describes manipulating a contact within TechCon Group. This contact facilitated the rise of Ra''s minions to power - all in exchange for a false promise of eliminating the Serrakin race from Hebridan. ', 687, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1532, 106132, 'Brannigan Tynan wanted a racial cleansing and he had been Devlin''s tool all along...', 687, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1533, 115388, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1534, 115389, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1535, 115390, 'I''m in charge of the defense? What happened to Tynan?', 664, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1535, 115391, 'He was working with Ra''s minions.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1535, 115392, 'Probably for some racist clap-trap reason... But, such is life. I appreciate what you''ve done for us... Or world may have imploded without you. ', 664, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1535, 115393, 'You''re welcome.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1535, 115394, 'Warrick was looking for you earlier...', 664, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1536, 106139, 'Search Devlin''s Terminal for more information about Burtonol''s link to Ra', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1537, 106152, 'Devlin... A Goa''uld servant of Ra in a position of power within a Hebridan corporation - and Burtonol''s corporate behavior seeming to support Ra''s invasion. Devlin''s files may indicate how deep the conspiracy goes.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1538, 106153, 'Devlin''s files reveal that several major executives within the Burtonol corporation were "selected'' and implanted with Goa''uld symbiotes. Five are still on Hebridan, no doubt interfering with a proper defense.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1538, 106154, 'The symbiotes are the problem - the executives themselves are innocents in all this - but Symbiote removal is a tricky business. You believe it would be wise to call the Omega Site and see if there''s a way to remove symbiotes from the host.', 687, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1539, 106207, 'Extracting a symbiote without harming the host is difficult, but we have been working with the humans on just such a procedure. An Asgard science vessel currently observes an orbit over Hebridan. If you can isolate infected subjects, we can beam them aboard and attempt the procedure.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1539, 106208, 'Is the procedure safe?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1539, 106209, 'It is the best hope they have of returning to a normal life. Given the rabid nature of Ra''s followers, those who host Goa''uld loyal to him are unlikely to survive once the symbiote chooses to leave. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1539, 106210, 'What is their chance of survival?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1539, 106211, 'The data on this is unclear. It is a dangerous procedure.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1541, 105241, 'Well you''ve caused a bit of commotion, haven''t you? Finnegan has his people engaging the Jaffa... ', 664, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1541, 105242, 'You need to get them authorizations.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1541, 105243, 'Me? I can''t set corporate policy. ', 664, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1542, 105224, 'You''ve put us to shame, the lot of us. And you don''t even know us.', 665, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106316, 'I''ll see what I can do.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1542, 105226, 'I''ll send my team in there, regardless of the regulations. But can you try to push the authorization through? We get caught, and they''ll turn us off. If they shut down our gear in the middle of a fight...', 665, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1542, 105227, 'I will do my best.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1543, 105198, 'What can TechSecure keep safe for you today?', 665, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1543, 105199, 'Are you Finnegan? I hear that you want to actually fight the invaders.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1543, 105200, 'I wish I could. But if I use my weapons and armor for a non-company purpose, we''re fired on the spot. Or worse, remotely deactivated - which means we get turned off in the middle of a firefight.', 665, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1543, 105201, 'That is twisted.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1543, 105202, 'Hey, I agree. There''s a family, they called in for help when the Jaffa took over their block. Private contract, but five days late on their payments... I can''t do anything about it unless we get orders in.', 665, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1543, 105203, 'Where are they?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1543, 105204, 'I''ll upload their position to your PDA.', 665, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1544, 105207, 'Are you from TechSecure?', 700, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1544, 105208, 'No, I am just here to help.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1545, 105209, 'Is it going to be okay?', 702, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1545, 105210, 'Yes, just follow me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1546, 105211, 'I don''t have any money. How much are you charging?', 701, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1546, 105212, 'This is free. Come with me. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1547, 105873, 'The panel accepts your credentials: "Security bypass approved. Welcome, Miles Hagan. CEO of Tech Con Group, a Limited Liability Corporation."', 699, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1548, 100882, 'Search for a way to get closer to Burtonol.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1549, 106560, 'Ra''s Hataks are bombarding the city, his Jaffa have grabbed most of the strategic ground and the Hebridan military hasn''t made a move, so there''s precious little resistance. ', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1549, 106561, 'The military surrendered?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1549, 106562, 'The local military are contractors, TechSecure is their name. They won''t move because they have no orders. Everyone with a working ship has hit the road. It''s a free-for-alll: A frigging embarassment if you ask me.', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1549, 106563, 'How do we get to Burtonol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1549, 106564, 'Hopefully we can find a hole in Ra''s lines and get to them directly... You can start by reconnoitering and getting a sitrep.', 683, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1550, 115411, 'Excellent. Pretty authentic. With this thing you could even start drawing pay vouchers.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1551, 106598, 'Ra has got Hebridan pretty much sealed off. TechSecure seems awfully relaxed, for being inside a war zone. Their soldiers are obviously unused to the rigors of war.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1551, 106599, 'I need to get into Burtonol''s facility.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1551, 106600, 'TechSecure is a subsidiary of Burtonol. They may be a way in. ', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1551, 106601, 'How?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1551, 106602, 'They rely heavily on their technological credentials. A little too heavily. This whole world is red-tape hell. It should be easy to fool them if you could get one of their ID badges. People here do not question much.', 683, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1551, 106603, 'Where I can get one?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1551, 106604, 'I heard about a guy known as "The Outsource Liason". He works the illegal ID angle. You can track him down out in Harmony City... Friendship Block, I think. ', 683, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1552, 106612, 'Infiltrate the TechSecure camp and find out what they know about Burtonol.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1553, 106698, 'The TechSecure people don''t take much notice of suspicious characters if you have credentials.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1553, 106699, 'Are they incompetent?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1553, 106700, 'They''re too wrapped up in the bureaucracy of this world. You have no idea how much these people feed at the corporate teat. Whatever the case, TechSecure''s people could be our way in to Burtonol. I''d work the bit players first and move up until you get a lead.', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1554, 106740, 'I see where this is going... Corporate sent you to test us? Well, I''m wise to you! You get the stock answer: Talk to Supervisor Caelan.', 726, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1555, 106779, 'You don''t want to hear what I have to say about Burtonol... Get me started on the health plan and I might never stop...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1555, 106780, 'Tell me about them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1555, 106781, 'Take it up with Supervisor Caelan... She''ll give you the corporate skinny.', 727, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1556, 115435, 'Burtonol? Bunch of middleman after their slice of the pie.You know they took 94% of the global defense contract in the latest bidding war? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1556, 115436, 'They bid for global defense?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1556, 115437, 'Of course. And our old umbrella company lost us - to them. If you want information about those idiots check the corporate terminals. I''ve got better things to do.', 664, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1557, 106786, 'You scan the files and discover that Burtonol is a massive defense contractor. After the last corporate reorganization TechSecure became a "subcontractor" owned by them. You find the location of their headquarters easily - apparently Devlin is in the phone book.', 690, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1558, 100913, 'Head to the Burtonol location', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1559, 115438, 'It''s time to go get some answers. Head over to the Burtonol facility and find Devlin. Try not to get caught up in anything in the way.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1559, 115439, 'Is that possible?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1559, 115440, 'Given that every TechSecure agent I see is sitting directly on their derrieres, I doubt it. ', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1560, 106799, 'Get through? Are you insane? With the bombardment going on, we''ve restricted access beyond this point. You go out there and you''ll be vaporized.', 2164, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1560, 106800, 'Is there any other way in?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1560, 106801, 'No. As long as those Hataks keep firing that island is cut off.', 2164, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1560, 106802, 'Can Caelan order an attack?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1560, 106803, 'I don''t know. I just work here. ', 2164, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1561, 106814, 'Order an attack? What a brilliant idea. Let me see... I wonder if I can pull an authorization out of my ---', 664, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1561, 106815, 'Burtonol is cut off. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1561, 106816, 'I don''t have an authorization to do anything. If you want to take this to Brannigan Tynan, maybe YOU can convince him to get us our authorization? Because I''ve no luck. Your Burtonol angle might work - for as long as I''ve known him he has done everything he can to help them.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1561, 106817, 'Where is he?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1561, 106818, 'Probably at Tech Con Auxillary Services, to the west.', 664, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1562, 106819, 'What are you doing here? You''re not even TechSecure rank 4. Use the chain of command. I don''t have time to waste with morons.', 666, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1562, 106820, 'We need to attack the Hataks.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1606, 106317, 'You got something? Lemme see that. Uh huh. Uh huh... Flanking... Uh huh... On the bright side, at least we know how screwed we are.', 680, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1562, 106821, 'Really? You think? Well, thank God you came along to suggest it... Oh, wait - we tried that! They laughed at me when I complained about the Serrakin pilots in their fleet, and now look at them. Can''t even shoot down a Goa''uld mothership.', 666, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1562, 106822, 'Is there any way to relieve Burtonol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1562, 106823, 'Not going to drop it are you?', 666, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1563, 100951, 'Find the body of TechSecure Military Commander Tomakin', 666, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115441, 'You want me to help you? Help me first.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115442, 'I''m listening.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115443, 'Go to Harmony City - Togetherness Block to be specific. One of TechSecure''s own met some trouble. Commander Jonsav Tomakin was killed in action.', 666, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115444, 'What does this have to do with Burtonol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115445, 'Nothing, but I need it done. Tech Con Group CEO Miles Hagan has asked for a rescue operation. Do this and we can discuss Burtonol.', 666, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115446, 'This is insane...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115447, 'This is what you will do. Now, if you continue to question me we can discuss your future at Tech Secure. Right now it is pretty tenuous. ', 666, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1564, 115448, 'I''ll find the body. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1565, 106833, '(Tomakin is wounded and weak, barely concious. You try to revive him.)', 682, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1565, 106834, 'Thank... you. My weapons cut out... I was told we were authorized, but the weapons... They shut down remotely.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1565, 106835, 'Let''s get you out of here...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1565, 106836, 'Thank you...', 682, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115469, 'Thank you... I would never have survived.', 682, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115470, 'How did this happen?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115471, 'Two words: Brannigan Tynan. I brought him an idea... Disable the Hataks using the drones from the Loop of Kon Garat... He resisted. ', 682, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115472, 'Loop of Kon Garat...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115473, 'The Space Race we have each year... Remember the drone phase? We can use those against the Hataks.', 682, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115474, 'Right... How?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115475, '...They use the drones to test the pilots... They''re armed and automated. You need to access the Kon Garat facility... Using this.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115476, 'Do not fade out... Not yet...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115477, 'I have files on Tynan... TechCon Mainframe... Files...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1566, 115478, 'You realize... If you can unleash these drones on Ra''s Hataks you will open the road to the Burtonol facility. You need to move quickly.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1567, 106869, 'The launch is successful and the display shows a large number of drones targeting the Hataks. Flashes of light confirm they are having an effect. Some of the Hataks shift to target the tiny drones. At the very least this will keep them occupied for a while.', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1568, 106865, 'The security bypass is approved. The system refers to you as "Commander Jonsav Tomakin."', 699, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1569, 101043, 'Find Tomakin''s files on Tynan and see if they can give you some leverage.', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1570, 115481, 'You have a few minutes before the drones have engaged the Hataks long enough to actually cease the bombardment. You decide to use that time to check into the files Tomakin mentioned before he died. The TechCon Mainframe would be at nearby TechCon Headquarters.', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1571, 22601, 'Since I have access to the rest of the Museum database, I should probe a bit more.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1572, 22599, 'In the recent Loop of Kon Garat, the stranded pilot Jarlath was picked up by Warrick. Jarlath then proceeded to modify Warrick''s ship to fire a pulse to disable Murios'' ship.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1572, 22600, 'Player: Perhaps we could do this to the Hataks. Coppleman may have some thoughts on this.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1573, 22597, 'Great idea, (playername). You know, Hebridan has a lot of satellites--you could use those to disable the Hataks. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1573, 22598, 'Player: I bet Tynan''s office has access to the satellite controls.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1574, 106875, 'This terminal has access to all sorts of TechCon files. You start working through the massive data manager, searching for Tomakin''s files on Tynan.', 692, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1575, 115482, 'You find Tynan''s personal log. After a few seconds everything comes together... Brilliantly... You can see the hand of Ra...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1575, 115483, 'Devlin is a Goa''uld. And he has been working directly with Tynan. For his part Tynan - probably mistakenly - believes that Devlin will help him rid Hebridan of Serrakin... His own racism is threatening his entire planet...', 692, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1575, 115484, 'The implications are vast... Ra has a Goa''uld inside Burtonol. What are they up to?', 692, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1575, 115485, 'There is a program here marked "Burtonol Access." You coolly copy it to a blank key card. ', 692, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1576, 115486, 'Clearance for the Defense Liasion''s files? I can give you that... but... Shouldn''t Brannigan - err, Tynan - do that himself?', 673, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1576, 115487, 'He sent me to do it...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1576, 115488, 'I don''t know if I should...', 673, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1577, 22596, 'Player: Here''s something juicy... data links Tynan to Ra and Devlin. Looks like Tynan had invited the Goa''uld to ''cleanse'' Hebridan of Serrakin influence, and Tynan in return has agreed to protect Burtonol''s secret project at all costs. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1578, 106910, 'The panel accepts your access card. The display reads: "Access granted. Welcome, Brannigan Tynan."', 704, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1579, 106905, 'Go to Burtonol and find Devlin.', 692, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1580, 106909, 'Devlin is in league with Ra and involved with Burtonol. Given Tynan''s silly racism, it is likely Devlin is the one pulling the strings... He must be responsible for the poor defense of Hebridan. It''s time to pay him a visit at the Burtonol facility.', 692, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1581, 101195, 'Impersonate Devlin to lure Tynan into a trap', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1582, 81234, 'DELETE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106957, 'Tynan here. What is it?', 666, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106958, 'We have a problem. I need to see you. Now.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106959, 'What?', 666, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106960, 'Meet me in front of TechCon Headquarters. We can''t do this anywhere else.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106961, 'I''m pretty busy here... Someone launched the Kon Garat drones without authorization... If I don''t deal with that, Ra''s little attack may be impeded... ', 666, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106962, 'This is more important. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106963, 'What is it about?', 666, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1583, 106964, 'Not over the computer! I will tell you when I see you.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1584, 106939, 'What are you doing here?', 666, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1584, 106940, 'Tying up loose ends. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1584, 106941, 'What? Wait... No... no!', 666, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2691, 18908, 'STUB.', 1203, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1585, 115505, 'With Devlin out of the picture, Burtonol''s efforts to help Ra hinge on Brannigan Tynan. Eliminating him would allow TechSecure to move against Ra. While not technically your mission, the bogging down of Ra''s forces would be seen as a coup on Harset. ', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1585, 115506, 'Devlin''s computer gives you access to the means of removing Tynan and an opportunity. Time for Tynan to recieve a little message from his co-conspirator, "Devlin".', 687, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1586, 101239, 'Search Devlin''s Terminal for info on the RepliTech project', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1587, 107010, 'One of the projects Devlin was working on was called RepliTech. The technology was based upon the Replicators, the self-replicating robotic constructs that nearly wiped out the galaxy. This sort of tech could prove very useful. You need to delve deeper into Devlin''s files.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1588, 107222, 'According to these notes, full scale production of RepliTech has not yet begun (and likely never will given Devlin''s untimely demise). However, three prototypes exist - still in the lab. You note the locations.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1589, 107230, 'We have to get this technology into containment immediately. The last thing we need is to accidentally resurrect the replicators.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1589, 107231, 'Replicator technology is fundamentally untenable. I have spent many hours looking into it... The real question was face is what does Ra want with Burtonol?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1589, 107232, 'Goa''uld do not hide inside hosts and act like spies unless they are well convinced to do so. Ra''s minions are loyal, but this level of deception is highly unusual. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1589, 107233, 'If Devlin was infested by a Goa''uld it follows that there will be more. It may go up the entire Burtonol chain of command. Rychen - the Lucian contact Devlin mentioned - is an obvious target.', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1589, 107234, 'Months ago they moved their main operartion from Hebridan to Lucia. This was probably Ra''s influence.', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1589, 107235, 'There has been much to make us suspicious of their activities on that world already.', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1589, 107236, 'Indeed. We must shine the light on the Burtonol operation on Lucia and see what lurks in the shadows.', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1590, 100602, 'Help civilians in the Togetherness Block get to shelter', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1591, 106440, 'The war has taken a terrible turn for the worse...', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1591, 106441, 'What happened?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1591, 106442, 'Togetherness Block was cut off by the Jaffa attack. TechSecure''s troops in the area might protect themselves, but they''re not going into harm''s way for fear of having their weapons disabled. Please, your weapons cannot be affected by the authorization system...', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1592, 106443, 'Please, get me out of here!', 1002, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1593, 106444, 'My family... All dead...', 1002, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1593, 106445, 'Come with me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1593, 106446, 'Why didn''t anyone do anything to stop them?', 1002, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1594, 106448, 'Those people owe you their lives, $name$. They probably don''t realize how lucky they really are... ', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1595, 106325, 'Help distribute Evac-U-Pac kits to civilians.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1596, 106329, 'My friend La''el gave me some depressing news. TechSecure was supposed to distribute the evacuation supplies to civilians. Not one employee has shown up.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1596, 106330, 'I can help.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1596, 106331, 'Great. Her name is La''el Montrose and she''s at Tech Con Shipping... She''ll be the woman waiting near the main office.', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1597, 106337, 'Warrick radioed that you would be coming. Thank God for you... TechSecure should''ve collected these Evac-U-Pacs hours ago. I''ve been on hold with the support line for three hours. ', 668, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1597, 106338, 'TechSecure is grounded.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1597, 106339, 'Typical. But you''re here now. The "Pacs" are scattered all over the shipping department. The delivery crew took one look at Ra''s Jaffa and tossed them from their shuttle as they flew through.', 668, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1597, 106340, 'You need them collected?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1597, 106341, 'Please...', 668, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1599, 106372, 'You''re amazing... Thank you... People need to know they haven''t been abandoned, even it it''s not true. ', 668, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1599, 106373, 'What do you mean?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1599, 106374, 'Just about every executive or person with a ship has fled this world - they all think they can just come back once TechSecure takes care of the problem. But that might not happen. Only a few of us are left. At least I''ve got Burtonol bodyguards to look after me.', 668, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1600, 106398, 'Discreetly investigate the suspicious shipment', 668, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1601, 106375, 'Thanks again... Apart from my security detail I haven''t seen any of our people this far out.', 668, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1601, 106376, 'The world is in bad shape.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1601, 106377, 'I''ve written you a thank you note.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1601, 106378, 'That is very... Generous.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1601, 106379, 'Just read it, ok? It would really mean a lot to me. ', 668, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1602, 106394, 'I see you''re back.', 668, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1602, 106395, 'I wanted to say you are welcome. Personally.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1602, 106396, 'I... oh, right. Good. I knew you were the kind of person who appreciates the little things in life - like hand written thank you cards. Hey, when this is all over, look me up. I''ll give you a free ride around the system.', 668, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1602, 106397, 'Sounds good.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1603, 106399, 'Assist TechSecure Commander Delancey at TechCon Auxillary Services.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1604, 115395, 'We''ve got a bit of a problem... Commander Delancey of TechSecure took out his team and charged the Jaffa. ', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1604, 115396, 'Delancey sounds like a brave sort.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1604, 115397, 'He is unpredictable. Someone at TechSecure corporate remotely shut down their weapons, citing the counter-attack as "unauthorized."', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1604, 115398, 'So they have no weapons?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1604, 115399, 'Delancey should have known this could happen... Your weapons won''t get shut down... Can you help?', 663, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1604, 115400, 'I can help.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1604, 115401, 'Here are the coordinates.', 663, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106309, 'Who are you?', 680, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106310, 'Warrick sent me to help you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106311, 'Warrick... You can help by getting me the intelligence I need so I can hit the Jaffa where it hurts.', 680, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106312, 'I thought your weapons were disabled.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106313, 'I''m not a frigging idiot. I disabled the authorization beacons before we jumped off. My problem is, I can''t show the Jaffa that I am here with a small team because they will attack and I''ll lose surprise.', 680, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106314, 'You need battle plans?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1605, 106315, 'Right. If you can get those, my team can jump off and hit them commando-style - something my TechSecure commanders are too afraid to do... ', 680, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1606, 106319, 'This is gonna do us just fine. Congratulations, you weren''t totally useless. Now excuse me while we do some real work...', 680, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1607, 115528, 'Get close to Cyric, Tynan''s aide', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1608, 107441, 'Here''s something worth a look. My contacts here say serious high tech is floating around - stuff that''s beyond Hebridan. And it''s shipping behind Tech Con''s back. Black market stuff.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1608, 107442, 'Any leads?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1608, 107443, 'Brannigan Tynan, he''s the Tech Con liaison to their corporate subsidiaries. His assistant, Cyric, is pretty damn dim, so he''s more likely to spill than Tynan. Ingratiate yourself to him and then see what he knows.', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107467, 'Do I work with Brannigan Tynan? I''m just Brannigan Tynan''s primary go-to guy for each and every problem. You''re TechSecure, right?', 673, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107468, 'Uh... Yeah.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107469, 'I need you to do something... ', 673, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107470, 'But I am TechSecure.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107471, 'A subsidiary of Tech Con Group, a Limited Liability Company - so, you are officially under Brannigan Tynan who is the TCG liasion to TechSecure. And I work for him and I need you. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107472, 'That was confusing. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107473, 'Just take this ad to the Broadcasting Complex and upload it... It''s easy-peasy.', 673, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107474, 'What''s the ad?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1609, 107475, 'Brannigan Tynan designed it himself. It''s a visual feast, designed to convince people that everything is fine... We spent over two million Naquadah on it. It''s really inspirational. ', 673, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1610, 107480, 'I am so excited about that ad. Brannigan Tynan is a master... Amazing... ', 673, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1610, 107481, 'About Tynan... Anything else I can do to help?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1610, 107482, 'Yes! Brannigan Tynan wanted some shipments secured - just in case the law broke down and there was looting. Brannigan Tynan does not approve of looting.', 673, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1611, 101308, 'Appropriate TechCon Group shipments for the Praxis', 673, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1612, 115523, 'There are a lot of important Tech Con shipments stranded at Tech Con Shipping. The great exodus left only a few ships behind to make deliveries... And then the higher ups put La''el Montrose in charge.', 673, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1612, 115524, 'Oh?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1612, 115525, 'Let me just say this: She likes to work with Serrakin. Ew. Tynan wants me to check on the shipments, but I''m delegating to you. It''s a very important part of management, delegation.', 673, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1612, 115526, 'Talk to Lael?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1612, 115527, 'Correct - so I don''t have to.', 673, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1613, 82102, 'DELETE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1614, 107510, 'Cyric... He sent you to harass me? Well, don''t! I''ve got enough problems helping folks around here without worrying about Brannigan Tynan''s precious cargo. I think Cyric is obsessed.', 668, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1614, 107511, 'I''m just here to check on some shipments...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1614, 107512, 'If it''s all so important, you can check it out yourself. Here''s the manifest. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1614, 107513, 'How come Tynan''s are seperated out?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1614, 107514, 'Because I am not allowed near them. You? I dont know about... But - according to Cyric - if I get near them, the world quite literally will end. So I don''t go there. ', 668, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1614, 107515, 'Interesting. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1614, 107516, 'Not interesting. Pyscho. Cyric and Tynan are crazy about those shipments. So good luck with that.', 668, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1615, 107517, 'Burtonol technology shipments from Hebridan, huh? Nice pickup. Every little bit helps.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1616, 82179, 'Locate and take Tynan''s "secret shipment"', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1617, 107523, 'As you review the manifest, another item strikes you as odd: A pallet of "TechCon UltraQuench Sport Beverage". The manifest has clearly been altered. Whoever''s trying to hide something didn''t bother doing a very good job. Time to find the shipment.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1618, 107524, 'Sports Beverage? Toss me one of those, I''m parched.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1618, 107525, 'The label''s a cover. Peel it off.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1618, 107526, 'RepliTech? That just sounds like a bad idea... Replicators are bad ju-ju. Still, it is tech that we haven''t seen before... I''ll see that this box gets to Harset in the next transfer.', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1619, 115507, 'Rescue and recruit one of TechSecure''s officers to the Praxis', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1620, 115508, 'I just got word that a TechSecure officer led his people into a wave of Jaffa, and the company turned off his weapons systems. Apparently he''s trapped. Guy by the name of Delancey.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1620, 115509, 'Why does this matter?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1620, 115510, 'Apparently he''s an expert on unconventional weapons systems and, because he went cowboy, he''s going to lose his job. ', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1620, 115511, 'We are thinking of recruiting him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1620, 115512, 'He''s got skills, he''s disillusioned and he''s vulnerable. It''s worth a try. And Harset says you get to do it. ', 683, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107363, 'What brings you out to this miserable dung heap?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107364, 'You. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107365, 'Corporate send you? You can tell them I broke their weapon limiters and I''d do it again...', 680, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107366, 'No. I represent the Praxis.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107367, 'You work with Ogilvie? Funny guy. Well, I told him and I''ll tell you: Once they fire me, I''m a free agent... Right now, however, I can use some help.', 680, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107368, 'What do you need?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107369, 'I just want to hit the Jaffa hard - to send a message, but I need some intel. We''re a small team, if I can maximize our impact without giving away that we are here... Getting fired would be worth it.', 680, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107370, 'You want me to collect intel?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1621, 107371, 'Exactly. You can probably find something on the Ra Jaffa near here... ', 680, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1622, 115513, 'These are the plans?', 680, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1622, 115514, 'I believe so.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1622, 115515, 'Very strange. They''re not even hitting some of the major military wards. Just the civilian sections. This is valuable stuff.', 680, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1622, 115516, 'Use it wisely.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1622, 115517, 'I will. And if they fire me after this, I''ll find you guys. Thanks for your help.', 680, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1623, 107427, 'I''ve got Delancey scheduled to be sent the proper contact protocols if he decides to come along. If he reports we''ll put him to work immediately. Nice work.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1624, 100642, 'Analyze the Ion Drive Prototype for useful information', 746, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109658, 'These coordinates are not a Goa''uld code... They are based upon historical landmarks. The city has changed much since this was written, but it should not take long to figure it out.', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1625, 106401, 'This ion drive is a new edition prototype, destined for use in their latest vessels. It''s a prime example of the engineering excellence of Tech Con Drive Systems. An analysis of this engine could be a valuable addition to your mission here on Hebridan.', 746, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1626, 106426, 'The engine operates on the basic principles seen in other drives on Hebridan, but this is clearly a more advanced version. You copy all of your findings into a data file for further analysis.', 746, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1627, 106427, 'This is very advanced technology... ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1627, 106428, 'It looks like their latest designs. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1627, 106429, 'Have we got clearance to use this?', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1627, 106430, 'Not officially.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1627, 106431, 'I''ll work on getting clearance through Warrick... Until that time this stays between you and me, okay?', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1627, 106432, 'Okay.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1627, 106433, 'Good work. ', 2568, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1628, 106434, 'This could prove very valuable. Did you ask for this, or did you "find" it?', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1628, 106435, 'It was found.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1628, 106436, 'Perfect. If they don''t know we have it, we''re better off. Good work. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1629, 105213, 'Thank you. I''m going to give those TechSecure freeloaders a piece of my mind.', 700, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1630, 105214, 'Thank you. I''ll see that you get paid from whatever refund I can get out of TechSecure...', 701, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1630, 105215, 'There is no charge. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1631, 105218, 'Why didn''t TechSecure come?', 702, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1631, 105219, 'They did not have authorizations. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1632, 58622, 'Travel to Dakara and link up with the Praxis contact there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109393, 'Is a mission to Dakara even feasible given Ra''s invasion?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109394, 'That is unknown. The Free Jaffa have many resources backing Dakara. My confederate Rohurk informs me they have prepared for siege. Much depends on the size of Ra''s army...', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109395, 'We know it grows by the day. I have heard of several clans moving to join him.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109396, 'As have I. The trend is most disturbing. ', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109397, 'Ra could eliminate the Free Jaffa as a power if he topples Dakara. However, what if he is after more than control of the city?', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109398, 'The SuperWeapon? Anubis sought it to unmake all life the galaxy.', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109399, 'It is a powerful piece of technology. I have seen its effects first hand.', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109400, 'The Jaffa claim to have destroyed it, but I do not believe them. If Ra were to get that weapon?', 945, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109401, 'We would all die. I have no doubt of it. I knew Ra very intimately for many years... He has not forgotten about us, Baal. ', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109402, 'We are going to help to protect Dakara?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109403, 'They would sooner kill us than have us help. I am no friend of the Council.', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109404, 'I don''t believe any of us are.', 942, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109405, 'The plan should be to infiltrate the planet and stay under the Council''s radar. You can test the Reins on Ra''s forces in action. The Free Jaffa would be none the wiser.', 500, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109406, 'If you can disrupt Ra''s attack in any way, you must do it. ', 944, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109407, 'Rohurk is well-regarded amongst Jaffa. I will arrange for him to supply a cover identity for you to ensure the Jaffa do not discover who is helping them.', 945, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1633, 109408, 'We cannot afford to take risks with Dakara. I am sure Rohurk will find a way to make use of your talents in their defense.', 941, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1634, 66879, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1635, 109433, 'I see Mok''hatan sent someone in her stead. Wise of her, the Council would have her head before she stepped off the Chappa''ai.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1635, 109434, 'I need to locate Ra''s troops.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1635, 109435, 'You are most in luck, friend! On Dakara, they are like locusts come to feast.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1635, 109436, 'I was told the Free Jaffa were holding their own...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1635, 109437, 'Not without cost... Battlefield promotions have left A''lem in charge of our forces... She is a favorite of the Council but thoroughly unready for command. In her "expert" hands the tide has begun to turn.', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1635, 109438, 'How bad has it become?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1635, 109439, 'A few more waves of failure and they may finally put me in charge.', 768, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1636, 58651, 'Learn the location of a Ra outpost through observing his Jaffa
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1637, 109455, 'Recently, Ra''s forces have leapfrogged our defensive positions at the outer walls. Elements of his forces are within the city as we speak. However, his troop movements remain a mystery to me. ', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1637, 109456, 'Perhaps we can be of service to each other...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1637, 109457, 'I can certainly send you into the teeth of the bear, but I would want something in return...', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1637, 109458, 'Intelligence?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1637, 109459, 'Yes. There is a forward outpost nearby believed to be occupied by Ra''s troops just last night... I will upload the location to your PDA... Go there and take stock and report back to me. From there you are free to do as you wish. ', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1638, 68571, 'Find out what effect the Reins of the Sun Chariot have on Ra''s forces
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109569, 'What you reported is disturbing... Jyoleen within our gates confirms for it me - A''lem clearly is incompetent. I am revising my estimate of the Free Jaffa''s chances.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109570, 'To?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109571, 'Nil. If Moh''katan does not wish to see Ra take Dakara and press it under his thumb, she must - must... Lend her troops.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109572, 'If Moh''katan were to bring the Praxis army here it would increase the problems.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109573, 'We must do something, <<playername>>. A''lem is leading us off a cliff.', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109574, 'I am here for a purpose - if it works, this battle will be over. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109575, 'What is the nature of the mission?', 768, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109576, 'I cannot say.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1639, 109577, 'As I anticipated... Proceed with my blessing. For the sake of Dakara I hope it works.', 768, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1640, 69309, 'Return with your findings to the Praxis for analysis', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1641, 109642, 'You must find out where Ra is performing his construction and put an end to it.', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1641, 109643, 'Where does the map point to?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1641, 109644, 'It is in some sort of Goa''uld code... Written in a way that is beyond my understanding. Perhaps your Praxis can help decipher it?', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1641, 109645, 'I''ll return as soon as I can.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109655, 'These documents were found on a Ruk''yal?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109656, 'Yes. We believe it is some kind of map.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109657, 'Baal? ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109660, 'We''ve been working on a holographic recording device to datamine Ra''s relics. Capt. Copplemann has the equipment. Get it from her.', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109661, 'I understand that another Crystal Device was recovered?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109662, 'No. It was part of a plot involving the Jaffa Council.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1642, 109663, 'Nerus is handling the cataloguing of the recovered Ra devices. Deliver that to him. In the meantime, we''ll try and decipher your little map. ', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1643, 109669, 'This equipment is for holographic imaging, so that we can get a good look at technology that we can''t recover. Usually we are too busy destroying it.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1643, 109670, 'That does tend to happen.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1643, 109671, 'Take some snapshots first this time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1644, 58546, 'Recon Ra''s construction drop site in the Ruk''yal Settlement on Dakara
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1645, 109801, 'We have to go derail whatever it is that Ra is up to in that Ruk''yal settlement. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1645, 109802, 'We must destroy it, whatever it is. ', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1645, 109803, 'We must identify it first... Destroying Ra''s power without understanding it is foolish, friends. We must stop him, yes. But, we must not destroy opportunities to help ourselves along the way. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1645, 109804, 'Wise, Baal. Banal destruction does not serve the greater purpose. ', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1645, 109805, 'Ra is a mortal enemy - of all of us. Destroying his power is not banal - it is prudent...', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1645, 109806, 'Do not raise your voice at me, Jaffa.', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1645, 109807, 'Please! Just. Stop... <<Playername>> Survey the site with the imager kit first - get the data - and then destroy whatever he is building. Problem solved.', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1646, 109816, 'You take a look at the equipment Ra has gathered for the construction. It doesn''t look local to Dakara - certainly not Jaffa design. You decide to take a closer look.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1647, 109824, 'The equipment bears the familar logo of Burtonol. It''s just standard high-tech construction equipment - not out of place on Lucia, but unexpected here on Dakara. It took some logistical will to get it here secretly (without using the Stargate). ', 782, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1647, 109825, 'What really draws you are the raw materials. They are piles of naquacite - the residue of burned Naquadah - generally considered worthless. Everything on the site is focused on the platform-like device in the center of the area.', 782, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1648, 109829, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1649, 103376, 'Try to establish a connection between the Reins and this construction
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1650, 109843, 'This platform appears to be designed around Ra''s Crystal Tech, but built with the aid of Burtonol. It occurs to you that if this is related to Ra''s plans, the Reins of the Sun Chariot might have an effect on it. You resolve to attempt an interface between the two.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1651, 109858, 'You succeed in getting a working interface between the Reins and the construction. The Reins light up, and corresponding lights flicker within the recesses of the construction. The sound of it is beginning to activate is harsh, like metal scraping against rock.', 783, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1651, 109859, 'You hear noise coming from the Reins - very faint. You strain to hear… It sounds like… Music?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1651, 109860, 'Suddenly the noise cuts out, and is replaced by the groaning sounds of mechanical failure. The lights go dim. Smoke wafts out. Whatever you did, you broke it.', 783, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1651, 109861, 'You need to find someone who knows what this does... A foreman maybe...', 783, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1652, 109842, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109897, 'Stop shooting! What is your fricking problem?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109898, 'I want information. What does that thing do?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109899, 'I have no idea. We''re just following orders. Burtonol has a contract to build this thing. A really BIG contract. ', 767, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109900, 'With Ra?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109901, 'I have no idea who the deal is with. This is a business operation. Look, we''re not even building the whole thing. Some local Jaffa did a lot of the finishing work.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109902, 'Why so much security?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109903, 'We''re in a war zone. Management was worried some psycho would come through and try and destroy the device...', 767, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1653, 109904, 'Hand over the schematics. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109940, 'For every question we answer there are fifteen more. What was he building? You say you heard music?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109941, 'Something like music... I don''t know what it was. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109942, 'We will analyze the data images <<playername>> collected... It may give us a clue as to Ra''s intent. ', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109943, 'But why attack the Council? And why attack the City? It does not seem rational.', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109944, 'Clearly he wanted to take the world by force and failed... ', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109945, 'You think he wanted the SuperWeapon?', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109946, 'I am sure of it.', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109947, 'Dakara is a memory. The Free Jaffa have taken back control there... Burtonol intrigues me, however. Why would Ra use a company based on Hebridan? This is unusual for him - typically he relies on zealots and slaves.', 942, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109948, 'Slaves and zealots may be hard for him to come by these days. Burtonol is a mercenary operation. They could quickly build whatever he wanted - they have the infrastructure. It may have been as simple as that.', 968, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109949, 'Can we afford to make that assumption, Captain? Instead of answering questions about Ra''s intentions, I fear the device on Dakara has muddied the waters. ', 942, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109950, 'Burtonol is pretty heavy on Lucia. If they have one deal going with Ra, they may have more. It will probably be a simple process to find out. ', 941, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109951, 'Do we have a reliable contact who can help us get inside their corporate shield?', 968, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1654, 109952, 'I think I know someone.', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1655, 30602, 'Return to Dakara to stop Ra''s surprise attack on the Ancient Superweapon there
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1656, 30609, 'Rohurk sent a message through just now of a new attack by Ra on Dakara. The message was cut off, but it mentioned the Ancient Superweapon. That means the Free Jaffa defenders must have fallen. We need someone to go there and stop Ra from activating it… or at the very least blow it up.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1656, 30610, 'That weapon was responsible for erasing the Replicators from the galaxy… and for spawning life throughout the Gate network. In Ra’s hands… it is too terrible to even conceive. Go now, and do not falter.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1657, 12169, 'Now we will see what you can really do.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2692, 18910, 'STUB.', 1215, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1659, 12193, 'Player: What’s going on? How did Ra break through? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1659, 12194, 'The battle was thought to be won. Ra had pulled away from the city. But the Free Jaffa defenders discovered Ra’s forces inside the great temple, working in secret.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1659, 12195, 'That’s when the firefight started. From the looks of it, the Free Jaffa are pushing the infiltrators out… but they are being methodical, safe, slow!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1659, 12196, 'And if Ra has that weapon, he won’t wait for long…
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1660, 12197, 'Shut down the Superweapon before it can do any more damage
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1661, 12199, 'Icarus wasn’t bluffing. The weapon is already sending out pulses of unknown energies… wreaking god knows how much havoc out there.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1661, 12200, 'It has to be stopped… NOW.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1662, 12201, 'The Superweapon shudders, sends out a final pulse, and mercifully falls silent.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1662, 12202, 'But what has it done?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1663, 12203, 'These configurations are extremely precise… they demonstrate a familiarity with the technology beyond what anyone would have suspected Ra to have… and certainly beyond your understanding.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1663, 12204, 'The Free Jaffa will be here soon. The best you can do is record these configurations and get the hell out of here.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1664, 12205, 'The SGC should have torn that blasted temple down to its foundations when it had the chance.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1664, 12206, 'What’s done is done. Ra got what he wanted, and we’re left holding Ancient information that we have no way of understanding.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1664, 12207, 'We move on. Do better next time. Nothing much more to say.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1665, 70243, 'Figure out where Ra''s troops are headed next based on these orders
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1666, 109990, 'This tablet appears to contain orders from Ra, but what strikes you is the degree of encryption. You decide to try and break the code.', 801, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1667, 109991, 'Very few parts of this message can be fully decrypted - it seems to be only a partial transmission. “Dakara” is repeated several times, as well as “ring transports” and "A''lem." The details are all scrambled and there is no mention of to whom these orders were directed.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1668, 109992, 'Not much is here. Dakara and A''lem are obvious, but ring teleporters... Ring teleporters are impossible.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1668, 109993, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1668, 109994, 'The Free Jaffa security teams are able to detect teleportation within the city. It is even possible for them to jam the signal. Ra wouldn’t be that foolish. Sadly, this transmission does not reveal much. ', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1669, 12215, 'Deactivate the means by which Ra has managed to transport troops here behind the Free Jaffa lines
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1670, 12216, 'Ra snuck his forces right behind the Free Jaffa lines somehow. It would be wise to find out how and put and end to it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1671, 12217, 'Someone smuggled this ring teleporter base inside the temple. No way to find out who right now, but easy enough to disable.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1672, 12218, 'The rings grow dark and cold. Ra won''t be getting any more help the easy way. Mission accomplished.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1673, 58630, 'Erase the Free Jaffa recordings of Rohurk and Mok''hatan''s meetings
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110008, 'There is something I request of you... Of a personal nature.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110009, 'Explain.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110010, 'Moh’katan and I have had several meetings - of a clandestine nature. These centered around my tribe’s future and your Praxis. The Council views Moh''katan as a traitor. These meetings were a secret...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110011, 'It got out?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110012, 'It did. Fortunately, the investigator somehow become a casualty of this deadly, unpredictable war. However, they left behind surveillance records. ', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110013, 'Where are they?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110014, 'There is a building in the Council Complex which is used as the Free Jaffa Narion''s Military Command. Intelligence is kept there. My meetings with Moh''katan cannot be exposed to the Council. Nor can your identity.', 768, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110015, 'Me?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1674, 110016, 'I only recently discovered the investigator. It is possible they monitored my contacts with Moh''katan - even the ones where we discussed you. Destroying all the material is best. For both of us.', 768, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1675, 110017, 'You finish setting the system to wipe itself. You flip the switch and all the material systematically deletes everything. Rohurk''s secret is safe.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1676, 58665, 'Defend against Ra''s invasion of the Jaffa ancestral holy world, Dakara
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108705, 'Ra’s fleet bombards Dakara as we speak. The Free Jaffa stand in siege formation, but if Dakara falls the Free Jaffa will have no united front. Dakara is the seat of our alliance.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108706, 'I understand Teal''c has already taken reinforcements to the planet.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108707, 'That is correct. The garrison there has suffered many casualties. And I fear with this news of the Ruk''yal it may quickly turn for the worse.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108708, 'What''s the significance of the Ruk''yal?', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108709, 'They are one of the clans that has chosen to settle on Dakara. If they have become infiltrated by Ra''s legions...', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108710, 'Then the planet''s defenses are in jeopardy.', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108711, 'I think we need to be asking is, what does Ra really want with Dakara? He has to be after the Ancient device.', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108712, 'I have heard of no attacks on the Temple where the SuperWeapon is held, Daniel Jackson. I believe Ra is after the Free Jaffa nation. If he can shake us, many of our number might well see him as a God.', 2323, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108713, 'The SuperWeapon was dismantled by the Free Jaffa after Anubis''s attack, anyway. It is no longer operational.', 625, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108714, 'I would not count on that, Colonel Carter. The Dakara SuperWeapon is seen by many Jaffa as a natural resource. They have rigorously fought its dismantling since that invasion. ', 2323, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1677, 108715, 'It follows that we should get boots on the ground. <<Playername>>, we need you go down there and report to Teal''c. We need every warm body we can get down on that world. Keep your eyes peeled. ', 2410, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1678, 108716, 'I am glad you have come. Ra''s forces have breached the siege defenses... They are causing panic throughout the city. You must inform A’lem of your arrival. She needs all the help she can get.', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1678, 108717, 'A''lem?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1696, 109059, 'Loth’ta’s keycard slides neatly into the revealed access port. The bomb hisses in response. You''re going to have to work quickly to shut the device down... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2693, 18912, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1697, 109120, 'I spit on the Ruk’yal and their shol’va name! Their clan will pay dearly.', 775, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1678, 108718, 'A''lem is the most senior garrison officer still living. She has the faith of the Council, but this situation is dire... She lacks experience, so it is no shock she is struggling. Make contact with her and place yourself under her command...', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1678, 108719, 'Since when do we place ourselves under someone else''s command?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1678, 108720, 'Seeking the aid of the SGU is seen as a sign of weakness for many Free Jaffa. Present yourself to her. Even in war there is no shortage of politics.', 2226, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1679, 108725, 'You are from the SGU. I will tell you what I told Teal''c. The Free Jaffa Nation can handle our own affairs. I''m sure there are other invasions needing your attention.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1679, 108726, 'Surely you could use help?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1679, 108727, 'I have never asked for it. Your people are free to do what they can, but do not get in my way. I trust Teal''c. Since you are his, perhaps he is the one you should seek for assignment.', 770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1679, 108728, 'Understood.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1680, 58655, 'See what is keeping the Jaffa Council from authorizing off-world reinforcements
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1681, 108729, 'I have received word from Bra''tac... He spoke of your encounter with the Ruk''yal on Lucia. You are certain they were in service of Ra?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1681, 108730, 'Yes.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1681, 108731, 'A''lem ordered the Ruk''yal to provide security for the Free Jaffa Council here. Her loyalty to their leadership has encouraged her to trust them implicitly. The Council must be warned. ', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1681, 108732, 'Are the Ruk''yal dangerous?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1681, 108733, 'I did not think so, but they are a close tribe. What you discovered on Lucia is a surprise. If the Ruk''yal have turned and the Council is lost, the alliance between the tribes may well dissolve.', 2226, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1682, 108734, 'Did you reach the Council?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1682, 108735, 'I was fired upon as I approached.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1682, 108736, 'Then Ra has moved in and the Council is held hostage… Or worse. The Ruk''yal have betrayed their duties. This cannot go unanswered.', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1683, 74051, 'Enter the Council Complex and find out what you''re up against
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1684, 108737, 'You must rescue the Council immediately.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1684, 108738, 'Should we inform A''lem?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1684, 108739, 'That would be most unwise. We do not know the extent of the incursion at the Council chambers. A''lem would respond with troops. She lacks the experience for subtlety. ', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1684, 108740, 'You think there is more to this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1684, 108741, 'I do not know. If the Ruk''yal are the traitors, they may not be acting alone. Since news of the takeover has not spread, they wish for it to remain hidden... If they have not been slain, the Council will be separated and kept under heavy guard.', 2226, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1684, 108742, 'So a mission to save them...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1684, 108743, 'Must be discrete. This means I cannot join you - my movements are watched closely by my people in times of stife. Good luck, friend. ', 2226, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1685, 109087, 'Thank you, stranger. How fares the rest of the Council? ', 772, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1685, 109088, 'You are the first I have found. What happened?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1685, 109089, 'The Council was in emergency session. Then our Ruk''yal security turned on us and took us hostage. Before we could move we were overwhelemed by these filth.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1685, 109090, 'Why did they bring you here?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1685, 109091, 'They separated us. I do not know why. One was overheard whispering about "preparing the device."', 772, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1685, 109092, 'The SuperWeapon?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1685, 109093, 'No, it was not that. They had a device with them - something I have never seen before.', 772, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1686, 58715, 'Save the other Council members who were separated from the group
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1687, 109070, 'A friend of mine from the resistance, U’kin, was taken away in the first group. He is the only one whose location I can reasonably surmise.', 772, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1687, 109071, 'Where is he?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1687, 109072, 'I believe they were taken to the library on the west Council grounds.', 772, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1687, 109073, 'Was the device with them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1687, 109074, 'Yes.', 772, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1688, 109107, 'We will be safe thanks to your quick action. I knew A''lem would come to our rescue.', 773, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1688, 109108, 'A''lem wasn''t aware the Council was in jeopardy. I was sent by Teal''c and the SGU.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1688, 109109, 'Strange, I thought we managed to get an alert out to her. Regardless, we must hurry. Ra''s minions plan to use the device on more of us.', 773, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1688, 109110, 'They used it on you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1688, 109111, 'Yes. After the Ruk''yal overtook us, the soldiers of Ra poured in. They brought a device with them and used it on us... ', 773, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1689, 109085, 'We are glad to see you.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1689, 109086, 'The way out is clear... You are free to go. Please hurry.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1690, 58725, 'Take out the infiltrators who are holding the remainder of the Council in the main building
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109098, 'Brother Gerak and the others are inside the main chambers. I fear the device is being used on them as well...', 773, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109099, 'I will go there.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109100, 'You show courage, but you must be careful. The invaders have a contingency plan: An enormously powerful bomb.', 773, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109101, 'A naquadah bomb?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109102, 'Yes. I fear that if they realize they have been discovered, they will activate it. They are zealots. I would not want to be in this city should it go off.', 773, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109103, 'It will not go off.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109104, 'Then act quickly, friend. There is not much time - especially if word has reached them of your efforts. I will work toward getting getting reinforcements to support you, but I fear they will not arrive in time.', 773, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109105, 'Go, get to safety.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1691, 109106, 'Find Gerak. They were moving to his group next.', 773, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1692, 58727, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1693, 109094, '(You release Gerak from his bonds.)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1693, 109095, 'Who are you?', 775, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1693, 109096, 'I am an ally of Bra''tac and Teal''c. I was sent for you.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1693, 109097, 'You are well met... But there is not much time...', 775, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1694, 58730, 'Eliminate Loth''ta, who betrayed the Jaffa Council to Ra''s forces
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1695, 109117, 'The sholva''s name is Loth''ta of the Ruk''yal. He leads the traitors. Even now he tries to hide in his robes. You must get the passkey from him to deactivate the device... ', 775, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1695, 109118, 'They have activated it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1695, 109119, 'Yes. Word of your deeds preceded you.', 775, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1697, 109121, 'Did they use the device on you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1697, 109122, 'On some of us... Your arrival interrupted them. The device itself seemed to have no effect.', 775, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1697, 109123, 'Everyone appears safe. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1697, 109124, 'The Council will not forget that A''lem failed and you - an outsider - triumphed. We are in your debt. But there is much left to do. ', 775, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1698, 105884, 'Retake the communications room in the council complex and reorganize the Jaffa defenders against Ra''s advance
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1699, 108851, 'The Ruk''yal have turned... We feared this. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1699, 108852, 'Gerak says that Ra''s forces have taken the military headquarters.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1699, 108853, 'That explains the chaos. Our communications have been sabotaged. Units have been given false orders, we have lost troops to friendly fire... And recently all communcations have stopped.', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1699, 108854, 'Can this be overcome?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1699, 108855, 'I can transmit a new battle plan if we re-take the headquarters facility. I will generate such a plan - you will clear Ra''s forces from the headquarters and revive the communications channels.', 2226, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1699, 108856, 'What about A''lem?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1699, 108857, 'There is no time for half measures. A''lem is not on top of the situation, so it falls to us to take the initative.', 2226, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1700, 109057, 'The Hak''tyl is indeed distressing. Their camp is right in Ra''s path.', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1701, 109058, 'You manage to reroute past the damaged components. Using the Array you find and upload Teal''c revised battle plans and then begin sending them out to the field. One by one, Free Jaffa units acknowledge the orders - all except for one: The Hak''tyl. Teal''c should be informed.', 788, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1702, 105888, 'Warn the Hak''tyl camp of the coming Ra advance
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1703, 108869, 'You must inform the Hak''tyl of their role personally, there is no time for anything else. Their camp is right in Ra''s path. If they do not support our other manuevers, it may undermine our plan. ', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1703, 108870, 'I will go. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1703, 108871, 'Find Ishta. She leads them. Give her these orders. She implement them.', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1704, 108872, 'What brings you here, off-worlder?', 776, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1704, 108873, 'I was sent by Teal''c to deliver these orders...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1704, 108874, 'Ra''s forces are advancing on this position... A plague on that fool A''lem! I should never have brought the Hak''tyl here, it is obvious we do not factor into the Council''s decisions.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1704, 108875, 'Ra crippled the communcation system. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1704, 108876, 'I speak of a deeper rift in the Jaffa than just one Goa''uld. But this is no time for debate. War is upon us. ', 776, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1705, 58794, 'Hold the line against Ra''s advance
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1706, 108877, 'I hope you''re prepared for battle, <<player name>>. My Commander, E''lyk reports that Ra finally commits to his attack in force.', 776, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1706, 108878, 'What can I do?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1706, 108879, 'Report to E''lyk at our bulwark. If that bulwark falls, our homes and our children will be the next target. Do not falter, or our spirits will tear you apart in the afterlife.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1707, 109168, 'The tide is turned back. Ra must not have the stomach to lose so many so quickly, athough his retreat worries me...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1707, 109169, 'It was suspicious.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1707, 109170, 'They won''t get a second chance. I am taking the Hak''tyl elsewhere. If they want us to be a part of the Free Jaffa Nation, it will be up to the Council to earn OUR trust from here on.', 776, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1707, 109171, 'I will tell them...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1707, 109172, 'You have earned our respect. You stood with us in battle. Thank you, <<playername>>. You will not be forgotten. ', 776, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1708, 12351, 'Return to Dakara to stop Ra''s surprise attack on the Ancient Superweapon there
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1709, 12352, 'A’lem has passed word of a grave situation on Dakara.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1709, 12353, 'Ra has more intrigue within his hand that all other Goa’uld combined. His advance was just another ploy. Somehow his troops infiltrated the sacred temple while we were fighting in the desert.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1709, 12354, 'The defenders were only alerted by the stirrings of the Superweapon shaking the mountain itself. The battle is joined now on the steps of the temple, but there is limited time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1709, 12355, 'Ra’s need for the Superweapon is bound to be horrifying. It created life in the galaxy, it eliminated the Replicators in one stroke. There is no telling what it could do in his hands. It must not awaken.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1710, 12356, 'The SGU’s hero returns. We may get through this yet.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1711, 12357, 'Protect the Superweapon from Ra''s forces
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1712, 12358, 'My instincts tell me that you want to stop that weapon as much as I do.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1712, 12359, 'Ready to charge the temple and possibly hasten to a glorious death?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1712, 12360, 'Player: Well if you put it that way…
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1712, 12361, 'There is no other way.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1712, 12362, 'Player: Then we go.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1712, 12363, 'That’s the spirit!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1713, 12364, 'Deactivate the Superweapon and try to reverse the damage it may have caused
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1714, 12366, 'The weapon is emitting continuous pulses of energy. The Stargate is probably sending these pulses across the galaxy. For what purpose? Unknowable at this time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1714, 12367, 'But it is not finished. Whatever has been started can be possibly undone.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1715, 12370, 'The sliding stone blocks of the console, concealing the Ancient technology within, cease their grinding and come to a halt.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1715, 12371, 'The final pulse collapses back into the emitters of the Superweapon. The threat is over, for now.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1716, 12372, 'The manipulations are controlled and precise. Icarus must have been following exact instructions from Ra.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1716, 12373, 'They are fundamentally different than the previous configuration of the weapon, but neither did they destroy all life in the galaxy. Praise fate for small favors.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1716, 12374, 'Figuring out what the weapon did may prove key to Ra’s plan.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1717, 12375, 'This data is intense. Wild. Fascinating.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1717, 12376, 'Player: But what does it mean?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1717, 12377, 'I haven’t the foggiest.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1717, 12378, 'Well no, that’s not quite true. This here, this does look similar to the propagation patterns that Daniel thought seeded life. But it’s in a totally different place in the spectrum.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2694, 18937, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1995, 95881, 'A virus... Did it leave behind a footprint?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1717, 12379, 'This may mean everything, but without additional data it means nothing. It couldn’t have been good news, though.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1717, 12380, 'I think we''ll all be feeling the consequences of this before we’re through.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1718, 58822, 'Investigate the devices Ra tried to use on the Jaffa Council
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1719, 108969, 'Upon a closer look, the device is clearly gleaned from Ra''s Crystal technology. Because he used it on the council, it''s worth a closer look.', 804, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1720, 108970, 'The device attaches small crystalline tags to the flesh of the victim. Then the device itself links to those tags. From the controls of the device, you hypothesize that the tags could act as a form of remote control over the victim''s will.', 804, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1720, 108971, 'You decide to get this device off Dakara and to Omega Site for further evaluation.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109210, 'Control technology? Where’d you find this?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109211, 'Ra''s Jaffa used it on the Jaffa Council.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109212, 'The Goa''uld secretly controlling the Council... That would be my darkest fear. Was the device activated?', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109213, 'They were tagged...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109214, 'But we recovered the device before Ra could use it? Good work. You may have saved Dakara single-handedly.', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109215, 'This device is designed for Jaffa specifically. I think it has something to do with their genetic link to the Goa''uld, but it''s extremely advanced biotechnology. It must have been incredibly difficult to build... ', 708, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109216, 'Ra was always gifted technologically. His Jaffa often spoke of his intellect. ', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1721, 109217, 'Colonel Carter, I need you to get a team working on potential counter-measures. If he can build one, he might be able to build more.', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1722, 58818, 'Disrupt one of Ra''s outposts to relieve some of the pressure on the city
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1723, 108983, 'I am deeply concerned with morale. Nowhere in the city do people feel safe.', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1723, 108984, 'Is there progress?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1723, 108985, 'Some. But our gains lack visible impact. Some of A''lem''s forces have left their post to tend to their families. I do not blame them.', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1723, 108986, 'You sound like you have a suggestion.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1723, 108987, 'We must root out some of those that are terrorizing the civilians. Ra''s forces need to be shown a taste of fear themselves. I know of several positions to hit, I will show you.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1724, 108988, 'Ra will be forced to react to our strike. That he is forced to react to us, gives the people hope. But it is a pebble upon the greater mountain. Our larger victory awaits.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1725, 58841, 'Uncover the reason behind Ra''s sabotage of this detection equipment
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1726, 108997, 'The communication array is an obvious target, but there doesn’t seem to be a reason why Ra would attack a Sensor Array. You decide to investigate.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1727, 109000, 'The sensors in this array are supposed to watch the city and temple areas for technological signatures: Weapons fire, stealth cloaks etc.. But there’s no record of anything being tracked recently. A''lem should know that the sensors have been mucked with.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1728, 109001, 'It does not surprise me that Ra tried to blind us. The confusion and panic aids Ra’s plan.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1728, 109002, 'My concern is that Ra is hiding something in particular...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1728, 109003, 'Your concern is inconsequential. Even blind we know he seeks to destroy us. Any child can see the Ha’taks from which he fires... Do not trouble me further with this. I have no time for trivialities.', 770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1729, 58850, 'Locate a subspace transmitter to summon the scattered Free Jaffa back to Dakara
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1730, 118844, 'With the loss of the communications center, calling in our reinforcements from the various planets has been impossible. It is imperative every able-bodied Jaffa is summoned to fight.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1730, 118845, 'Don''t we have access to more communications equipment?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1730, 118846, 'The Asgard may. You will need to request such equipment from the Omega Site. It is not available here.', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1731, 109007, 'You''re going to need subspace transmitters to accomplish what Teal''c wants on Dakara.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1731, 109008, 'The Asgard do have such technology, but the Free Jaffa Nation does not have a direct alliance with us...', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1731, 109009, 'I speak for the Free Jaffa. We must reinforce Dakara.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1731, 109010, 'With all due respect, you are but one member of a larger council, Master Bra''tac. While we do not doubt your commitment, other members of your own Council have rejected joining the SGU.', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1731, 109011, 'Thor, I believe Dakara may prove to be a turning point. If this will help stop or slow down Ra...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1731, 109012, 'I concur with your assessment, General Hammond. The Free Jaffa must understand this equipment is loaned. <<Playername>>, you will see that the technology is used appropriately.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1732, 75389, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1733, 109019, 'This is Asgard technology. They have never shown much patience with the Jaffa.', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1733, 109020, 'It is a temporary loan.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1733, 109021, 'Understandable, given our Council''s open distrust of the Asgard. Please get the device operational as quickly as possible. A''lem should know which Jaffa are yet to be reached.', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1734, 109023, 'You finish setting up the device. Typically Asgard, set-up was simple, yet complex. All it will need is someone to enter in the data for where the messages need to be sent...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1735, 109031, 'Your communication device is nice, but why do the Asgard not just blast Ra out of the sky with their mighty warships?', 770, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1735, 109032, 'There are none available.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1735, 109033, 'Of course. The truth is, the Asgard care nothing for the Jaffa. And in the end, I do not believe the SGU will either.', 770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1735, 109034, 'My presence here contradicts that. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1735, 109035, 'You are a political emissary. Do not think your presence means anything more than that. The device they so graciously "loaned" us is prepared for use? ', 770, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1735, 109036, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1735, 109037, 'I will send the messages when I get a moment.', 770, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1750, 12414, 'Train', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1751, 12416, 'Attempt to make some sense out of this strange place called Meridian, and make contact with the Furling', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1752, 12614, 'This place is certainly different. The space, the air, the gravity, it is all like nothing you have encounter before in the past. The question lingers in your mind: where has the Sermobis taken you?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95475, 'I will inform my superiors.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2695, 18933, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1752, 12615, 'Is this the home of the Furling? Is this where the Straegis are combining into an unstoppable, chaotic force?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1752, 12616, 'Nothing seems right. You must take this slowly. Each step you take feels as though you are about to plunge into an abyss of uncertainty and doubt.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1752, 12617, 'And there is no lifeline.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1753, 12618, 'A rumbling inside your pack jolts you from your wandering. You reach in to pull out the Reins of the Sun Chariot, Ra’s Furling artifact. It is shaking hard, fully lit up and definitely active.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1753, 12619, 'It moves in your hand, like a compass needle tugging towards a distant alcove.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12620, 'Player: Hello?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12621, 'Observations of the Life Path.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12622, 'Observed you enter through Sermobis. Observed you are now here perceiving Meridian. Observed you conflict with Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12623, 'Observed you can be destroyed by Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12624, 'Player: What is this place? Are you a Furling?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12625, 'Obeserved you see this as Furling. Observed you see Meridian as your being can possibly see it. Observed standard process of Sermobis is functioning as created.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12626, 'Observed you lack comprehension of what you know.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12627, 'Player: So you’re saying you are, or you aren’t, a Furling?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12628, '<You wait, but there is no answer from the being.>
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12629, 'Player: Whatever you are, I’ve come to destroy the Straegis. Are you going to help me or do I have to figure out how to do this on my own?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12630, 'Observed will to challenge Straegis. Observed capacity to challenge Straegis. Observed potential to challenge Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1754, 12631, 'Observed possession of remnant part relic.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1755, 12632, 'Question this being about this place and what it all means', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12644, 'Player: What was that?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12645, 'You would perceive it as “refocusing.” It is quite common.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12646, 'Player: You … don’t sound the same.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12647, 'There is more information available for communication now that you are recognized and remembered. It is good that you have finally made your way here, friend.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12648, 'Player: Friend? We just met.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12649, 'That in your hands is a remnant part. A relic left outside and renamed the “Reins of the Sun Chariot.” Through it, observation has been possible. Observation has been going on for some time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12650, 'You have won and lost many battles against Ra. You have been to many worlds through the Stargate. You have saved lives, and you have killed planets. You are known.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12651, 'Player: You have me at a clear disadvantage then, and I don’t like it. What are you, and what is this place?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12652, 'Meridian is another remnant part, another relic of the distant past. It was an attempt to make space for the others of the old Alliance, so that this space could be experienced by them, though not as perceived by the natives.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12653, 'The Ancients called it “Meridian.” Half-way and of neither world at the same time. It was from them the idea came originally. It was not overly successful at its goal. Merely a copy, and not as correct or familiar as theirs.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1756, 12654, 'But that is enough of observation. You have come to challenge the Straegis and preserve your space through transformation. Thus transformation must be evoked.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12665, 'Player: Hello again. How many riddles are you going to spout out now?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12666, 'Arbitration of transformation.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12667, 'The patterns at work here are clear: that which was before was transformed into the Straegis. Meridian transformed from a remnant into a gathering ground for the same. You transformed from one of no consequence into the one of all consequence.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12668, 'As it is with the patterns small, so it is with patterns large.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12669, 'Player: I’ve been told the Straegis are gathering here. How? Why? Tell me about them!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12670, 'The Straegis seek collective, they seek to be one under a singular conductor giving them purpose. Without a theme of purpose, they rage fevered and unconstrained, random. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12671, 'Instinctually, they grow in power as they collect. Soon they will be too powerful to stop by any force known or unknown. They will tear the galaxy apart, destroy you, destroy all you know, before they destroy themselves.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12672, 'Player: Can it be stopped?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12673, 'Yes.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1757, 12674, 'Player: Wow. I didn’t expect such... not being cryptic.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1758, 12430, 'Begin the Furling''s plan to deal with the Straegis', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1759, 12675, 'Player: Ok. I know you aren’t going to give me a straight answer… but here goes. How can the Straegis be stopped?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1759, 12676, 'You will confront the Straegis. You know how. You have always known how.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1759, 12677, 'Player: But I have no idea what you’re talking about! I don’t know how!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1759, 12678, 'You do not know that you know. There is too much noise. You require, a guide.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1759, 12679, 'Player: A guide would be helpful. This place makes very little sense.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1759, 12680, 'Contrary to your perceptions, the sense it makes is perfect. To comprehend the Straegis you must embody parts of the Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1759, 12681, 'The Straegis here are the most collected. They are themes of higher order: Allegiance, Creation, Destiny. Go forth and find those parts.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1760, 12682, 'The Straegis and what they once were are of two paths now. An insurmountable divide.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1760, 12683, 'But you who experiences Meridian can likewise be Meridian between you and Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1760, 12684, 'Player: What the hell does that mean?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1760, 12685, 'You are the agent of their transformation. Your journey here will be their journey.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1760, 12686, 'The Reins are of you now, they have recorded your themes and conflicts. They are a necessary component of what is to come. They must be sacrificed.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1760, 12687, 'Player: Sacrificed? You mean you need me to hand them over?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1760, 12688, 'Yes. Do not fear. They have served their purpose.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1780, 12907, 'Player: I want it. I am not about to pass up an opportunity to claim such powers, even if it is just an illusion.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1761, 12689, '<The being reaches out to the splinters and the Reins with its “hands.” The glowing energy of the being smoothes the two together into a new device with an unexpected ease, as though the four parts were meant to fit together all along.> 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1761, 12690, '<The being hands the artifact back to you.>
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1761, 12691, 'The Icon of Transformation. Call it forth.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1762, 12692, 'The Muses of the Straegis make their noise deep in their space. Their noise is loud and discordant.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1762, 12693, 'They must be challenged, faced, overcome. You and the Icon know how. You have always known how. You must succeed.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1763, 12613, 'Speak with the Icon', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1764, 12694, 'Your brief time here on Meridian has already your set your head spinning as if you’ve ingested a large quantity of hallucinogenic Kassa.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1764, 12695, 'The glowing being (beings?), Furling or not, seems to have faith that you can beat the Straegis. And this “Icon” they’ve left you with is the key.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1764, 12696, 'Though you don’t quite know what’s going on (and honestly, you doubt you ever will)… perhaps this “Icon” will be less of a headache to talk to.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12713, 'Player: Hello there. Do you talk in riddles too?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12714, 'I have your knowledge, along with your face. I can speak with you just fine.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12715, 'Player: Finally!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12716, 'Your confusion probably has much to do with this place not actually being “this place.” You’re experiencing sights and sounds that are your brain putting a filter on the actual “here” that the Sermobis sent you to.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12717, 'Player: So this isn’t real?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12718, 'It’s plenty real. But you’re experiencing it as a metaphor based upon your collective subconscious.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12719, 'Player: I thought you weren’t going to use riddles.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12720, 'My mistake. The colloquial term for most is “spirit quest” or for the humans of Earth, “a bad trip.”
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12721, 'Player: How do we stop the Straegis?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12722, 'The Straegis are comprised of themes, the means by which they interact with the universe. The more collected the Straegis are, the more complex and interwoven the themes.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12723, 'The largest Straegis, let’s call them Muses, have opened the doors to the highest level themes… You would know them as Allegiance: the highest mastery of the Life theme, Creation: the highest mastery of the Matter theme, and Destiny: the highest mastery of the Forces theme. We have a simple task. Conquer those Muses.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12724, 'Player: If we kill those Muses, the Straegis threat is over?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12725, 'I don’t know… Perhaps there will be more revealed to us. But that’s how it starts.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12726, 'It’s not just a matter of barging in, though. These zones are flooded with Straegis, with abilities you’ve never encountered. Tricks that we must figure out together.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12727, 'Player: And then the shooting?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1765, 12728, 'And then much shooting.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1766, 12446, 'Confront the Straegis who twist the theme of duty and power', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1767, 12729, 'The Straegis theme of Allegiance has its roots in how intelligent life organizes itself into nations, federations, to become more than it can as individuals. How duty and honor have a power beyond the limits of flesh and steel.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1767, 12730, 'Straegis are home in a perfect collective… so they see your organizations are primitive, easy to manipulate.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1767, 12731, 'The Muse probably knows your place in the world. Knows you have been sent by your faction to stop it. I would keep that in mind.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1768, 12732, 'It would seem the Muse thinks that copies of your allies will slow you down, confuse you. I don’t think the tactic is working very well.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1768, 12733, 'Player: Are they real or just copies?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1768, 12734, 'Copies… I’m pretty sure. I will attempt to comprehend what is meant by all this in way you can understand.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1769, 12452, 'Overcome the challenge at the Straegis "heart" of the Allegiance zone', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1770, 12735, 'I thought these images were completely distinct from your world, but there is a connection. The Straegis intend to control members of your faction via the Allegiance theme - twisting your own notions so that you serve the Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1770, 12736, 'Once they gain enough power they can extend the theme through their network and dominate hearts and minds across the galaxy without much effort.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1770, 12737, 'I have an impression of where the source of the energy is coming from. I will guide you there.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12774, 'Hey, how’s it going? This place is one hell of a trip. Feels like I ate some of Homer’s “Guatemalan insanity peppers.”
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12775, 'Player: Who are you? You’re obviously not the real General O’Neill.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12776, 'It doesn’t matter much what I am. You’re a long way from home.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12777, 'Player: Out of my way.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12778, 'You’ve been saying that a lot lately. Doesn’t it feel like everything is just getting in your way? Even me?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12779, 'Player: I don’t have time to match wits with a Straegis trick.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12780, 'Not much time for anything except the fight, right. When’s the last time you were on Earth, anyway? Spoke with your family? Watched a ballgame? Went fishing?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12781, 'You still remember what you’re fighting for?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12782, 'Player: You’re not going to stop me from stopping the Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12783, 'All I’m saying is you’re not us anymore. You’ve left us behind, with your fancy armor and … stuff.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12784, 'You’re a good kid, but the SGU’s taken on a life of its own. Don’t think you can just click your heels and come back home when this is all done.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1771, 12785, 'I’ve said my bit. You want to get past me, you come show me what you’re made of.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12796, 'Typical that it would be you who comes here to kill me.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12797, 'Player: Nice. For a Straegis copy, you even sound like him.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12798, 'I’m not just a copy. I have my links into the “who” of what I am. You don’t think genetic memory is stored in the blood, do you?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12799, 'Player: So how much longer do I have to listen to you before I start shooting?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13052, 'Player: How did you get here? Are you a Straegis?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12800, 'It seems not even the New Mind succeeded at breeding a smidgen of patience into us. I’ll be brief. I can sense the schemes within that thick head of yours. You seek to rise atop the Praxis, even if you have to climb over the corpses of your family to get it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12801, 'Player: Isn’t that the way it always is? Son against father? Mother against child?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12802, 'Poetic, but a cycle of tragedy nonetheless. Will there ever be anything more? Was this why we were created?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12803, 'Player: It is what we are.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12804, 'That’s not an answer. That’s surrender.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1772, 12805, 'Regardless. If nothing else, killing me ought to give you some practice for the main event. Let’s get on with it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12816, 'Hail, Jaffa. I would like to speak with you.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12817, 'Player: You are not Teal’c.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12818, 'Indeed. I am but a Straegis projection. But I possess the mind and the feelings of the true Teal’c, and I have the opportunity to say what he would not in person.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12819, 'Player: And that is?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12820, 'That you are too concerned with the fate of distant worlds and old legacies when your own people suffer daily. That our chaos is not born of the enemies you face, but rather because all the noble Jaffa have abandoned their families to fight.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12821, 'Player: I follow Teal’c example by fighting. Without the SGU, the galaxy would be overrun by Ra and the Straegis. And then there would be no peace for the Jaffa.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12822, 'Perhaps you are right. But you are trapped now in the warrior’s path. Do you not think that after the Straegis there will be another enemy, and another?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12823, 'The Tau’ri will always stumble into another hornets’ nest and you will always come save them, when you could be tending to the future of the Jaffa. You have made yourself slave to that patch you wear. You are not Jaffa, you are something much less.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12824, 'Player: I am securing our future, Straegis. You will not persuade me otherwise.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1773, 12825, 'We shall see. Face me now, shol’va!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12826, 'Bout time you showed up. Least you didn’t wimp out.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12827, 'Player: Sir? You’re…. you’re not Colonel Marsh, that’s for sure.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12828, 'You didn’t fall for it, huh. The Straegis probably didn’t expect you to. I’m just an illusion, here to do their dirty work for them. So listen up.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12829, 'Player: Why am I going to listen to a trap?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12830, 'Cause I know what Marsh knows, and you’re going to listen because I’m going to tell you the truth. You remember what that is, right?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12831, 'You’re going to hear a lot of things soon. And most of them are going to be true. And that’s a shame, because you’re going to have doubts about sticking with the fight. Justified doubts.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12832, 'Player: All I hear is a lame attempt to get me to surrender. Is this the best the Straegis can do?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12833, 'Would you just listen? You already know you’re never going home. Your life is tackling the unexplored, the dangerous, protecting Earth no matter the cost. No matter who fails along the way.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12834, 'You stick to the mission or I swear I’ll kick your ass myself.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12835, 'Player: Wait, are you trying to convince me to stop fighting… or keep fighting?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12836, 'What do you think Marsh would say?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12837, 'Player: I don’t know, because you’re not Marsh… 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1774, 12838, '…You’re a Straegis projection. I know, I know. Yeah, I’ve got to try to stop you now.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12863, 'I speak with the voice and wisdom of Thor, but I am not Thor. I am of the Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12864, 'Player: Your deception was never very competent. I will destroy you.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12865, 'A moment though, if you would indulge me. You know as well as I that you will eventually be sent to claim the Solocris, with the thought that it will save the Asgard from our fate.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12866, 'Player: Do you have a point?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12867, 'You also know as well as I the Solocris will not lead to anything pleasant. That our arrogance pushes us in a direction that ensures our doom.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12868, 'Player: I will make my own judgments on our fate, and keep no council with Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12869, 'Then you are a fool with the rest. Insanity is defined by performing an identical task expecting a different outcome.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12870, 'I had sensed that you had a potential beyond that. That you were a wise person to reawaken. I was wrong.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12871, 'Player: Your doubts do not move me, phantom.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12872, 'You still have it within you, to live while others die. To evolve while others stagnate. But will you remain an Asgard, if you are the only one left?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12873, 'Player: Are you finished?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1775, 12874, 'That is all you will listen to. Come kill me in this space, as you have already killed me with your words.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1776, 12875, 'This obelisk is important. The phantom appears to have been projected from it. The Icon ought to know what to do here.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1777, 12882, 'Player: What do I do with this obelisk?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1777, 12883, 'This… this is the Crux of Leadership. This is condescended Allegiance in pure form. With this, the Straegis could command your people as if they were their own.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1777, 12884, 'Player: How does it work?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1777, 12885, 'This crystal connects to the minds of all social beings at once and can erase their capacity for will. Its power, if you were to claim it, could take command of all the minds in your faction and your allies… instantly. You could be a true monarch and the galaxy your puppet.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1777, 12886, 'Player: How can it be destroyed?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1777, 12887, 'In this space? Just smash it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1778, 12890, 'You reach for the Crux to claim it for your own. Leading the galaxy sounds like a fine plan.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1778, 12891, 'But too good to be true, of course. The Crux turns dark and crumbles into powder as your hand nears it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1779, 12893, 'You smash the Crux with your weapon. Hopefully it will never be used.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1780, 12904, 'Player: Just a trick, I see.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1780, 12905, 'The bonds of Allegiance run shallow within you, I see. Thus I believe the Crux to you appeared an illusion of the true nature of power.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1780, 12906, 'But I wonder, why did you seek to claim it?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1780, 12908, 'I see and observe. I have made you something from the remains. This is Will-Over-Allegiance… you have demonstrated superior will in the face of their theme, and should have a superior defense to it as a symbol.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1781, 12921, 'If I may ask, why did you destroy it? Why not claim it and take the Straegis and the galaxy for your own?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1781, 12922, 'Player: You said it would destroy the will of all people, my own included. That is not a cost worth paying, no matter the reward.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1781, 12923, 'I see and observe. You have shown a will to prevail over the theme of Allegiance, and should have some “thing” to match that. From the remains of the Crux I have fashioned this: Will-Over-Allegiance is its name. It should defend against these Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1782, 12479, 'Conquer the Straegis "Muse" leading the theme of Allegiance', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1783, 12933, 'We are prepared to take on the Muse of Allegiance now. I cannot help you further than I have.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1783, 12934, 'Player: How do I fight it?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1783, 12935, 'Physically it is simple as shooting it until it stops moving, like the other Straegis you have encountered. Metaphysically you have already won.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1784, 12936, '<The Icon breathes deep the fumes and dust released into the air by the destruction of the Muse.>
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1784, 12937, 'Allegiance has been confronted, mastered, absorbed. We will be able to reunite.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1785, 12485, 'Confront the Straegis which revolve around the notion of Creation', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1786, 12948, 'The theme of Creation is used by the Straegis to build and organize all manner of object and practice. Your own creations may betray you inside, as they will be perverted by the theme of the Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1786, 12949, 'Straegis are their own tools, they simple execute their being to perform their task. It requires a greater mind to direct those tools, and they seek it through self-organization, but their combination is haphazard and self-destructive. The Muse of Creation must be halted from that path.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1787, 12944, 'I am beginning to understand how the Straegis are using their theme against you. Your weapons and technology, they are “creations” and as the Creation theme can affect them, especially here where everything is half-metaphor.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1787, 12945, 'I advise you use their nature as against them. The Creation theme should hold no power over them.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1787, 12946, 'Player: So I can turn them into a weapon?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1787, 12947, 'Their components, yes. Matter to give it form, Forces to give it energy, Conflict to give it a role as a weapon. Creation to paste them all together. I will handle the details.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1788, 12490, 'Locate the "heart" of this Straeigs theme and smash it to itty bits', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13243, 'May I ask you a question?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13244, 'Player: All right. Quickly.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13245, 'We fashioned a tools of destruction, and we are destroying these Straegis. It does not seem an impossible task. By why do the other beings, the ones you call Furling, why do they not fight?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13246, 'Player: I don’t know. Maybe they can’t.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13247, 'Then perhaps answer, why can you? Are you possessed by the weapons you carry to fulfill their nature of destruction?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13248, 'Player: No, I use these weapons as tools. They follow my lead.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13249, 'You desire destruction then?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13250, 'Player: In the service of my goals, sometimes.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1789, 13251, 'I am beginning to comprehend a little more. There is a focal point here from which the themes are very strong. We ought to head in that direction.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1790, 12974, 'That… that is the Crucible of Making: a deep and growing concentration of the themes of Creation. With it, the Muse can command and twist all the technology that you and your kind use, from the simplest blade to the Stargates themselves.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1790, 12975, 'Player: How can we stop it?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1790, 12976, 'It will not be possible to use your tools, they are subject to its energy. But the Straegis themselves ought to be immune.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1791, 12983, 'You stare for a moment, noticing a depth and complexity within the crystal that makes your eyes open wide. Blueprints, designs, knowledge of all matter of technology lie within…
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1791, 12984, 'You shrug it off and bring up the weapon fashioned from the Creation Straegis. You slam it into the obelisk.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1791, 12985, 'You expected a crack, maybe a chip to fall off, but as soon as the two touch the entire obelisk grows dark and crumbles into ash.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1792, 12992, 'I admit the metaphorical intertwinings have me at a loss. A created weapon destroying a locus of creation by one who is creator and destroyer in one…
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1792, 12993, 'Player: Just ignore the symbolism. What do we do now?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1792, 12994, 'I see and observe. This token is from the remains, it is called “Will-Over-Creation” which I believe reflects your qualities shown here accurately. You will need it to defeat the Muse.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1793, 12500, 'Confront the "Muse" Straegis helming the collection of Creation themes', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1794, 13001, 'With the token you possess, we can “uncreate” the Creation Muse and release its themes. In the future they can possibly be “recreated” into a more appropriate being.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1794, 13002, 'Player: What’s the fight going to be like?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1794, 13003, 'Challenging, but you have already mastered the themes at work, so I do not doubt you shall find success.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1795, 13008, '<The Icon breathes deep the fumes and dust released into the air by the destruction of the Muse.>
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1795, 13009, 'Creation has been confronted, mastered, absorbed. We will be able to rebuild.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1796, 12506, 'Enter the region controlled by Straegis who manipulate time and possibility and begin the trial there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1797, 13016, 'The theme of Destiny involves your concept of time very deeply, and those of probability and causality. The Straegis will be able to use their powers to change those concepts throughout their domain.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1797, 13017, 'Straegis, in many respects, do not deal with time as you do. With the proper themes, precognition or time manipulation is no big deal. Past, future, they all run together.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1797, 13018, 'Their Muse probably is aware of all of your pasts, and all of your futures. I do not know what challenge awaits, but I can feel it drawing us in.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13049, 'The Great <player name>! I am so sorry to require you to come to my aid.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13050, 'Player: Come again? Who are you?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13051, 'I am Skuld, historian and archivist. It is an honor, a true honor.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13053, 'No, I am as non-Straegis as anyone else. As for getting here… I do not know. I do not even know where “here” is, Great One.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13054, 'Player: It’s… a long story. What’s with the “Great One?” … though I admit it’s kind of flattering.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13055, 'You are the hero who long ago stopped Ra and saved the galaxy! There are numerous works about you, fleets of ships of all races bearing your name… Surely you must…
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13056, 'Player: How long ago did said saving happen?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13057, 'Hundreds of years! I must admit it’s surprising to see you here, but I would never put something as pedestrian as time travel out of the reach of the Great One.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1798, 13058, 'Player: Excuse me while I have a little chat with an Icon about something.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1799, 13059, 'Player: What the hell?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1799, 13060, 'I told you that the Destiny theme involved time manipulation. This place must exist out of the natural flow of time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1799, 13061, 'Player: So she is from the future.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1799, 13062, 'Everything seems genuine. She is not lying.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1799, 13063, 'Player: What do I do, then?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1799, 13064, 'If she left the area affected by the Destiny themes, she would doubtless return to her natural space-time. I need time to better understand how to combat the Muse, but you might as well repay her for her homage.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1800, 13073, 'I cannot tell you how thrilling it has been to be with the savior of the galaxy. I will remember this forever.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1800, 13074, 'There are so many more questions to ask the historians are in disagreement about… what of your relationship with Vala? And with the Ancient child?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1800, 13075, 'Most importantly, why did you ever….
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1800, 13076, '<Skuld fades away, back to her own time.>
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1801, 12516, 'Return to the Destiny zone, this time in search of another being fallen through time', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1802, 13077, 'We are being called back in to continue the challenge. I hope they are all so… pleasant.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1802, 13078, 'Player: At least we know I succeed.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1802, 13079, 'Hmmm. I must concentrate.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1803, 13094, 'Hey. Good to see another humanoid for once instead of one of those glowing rock demon bastards.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1803, 13095, 'Player: I know the feeling. How did you get here?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1803, 13096, 'Don’t know. One moment, shooting, dying. Next I’m here. Is this hell?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1803, 13097, 'Player: I’m going to pass on answering that one. Who are you?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1803, 13098, 'Call me Walter. Sergeant Walter Harriman, before Earth fell. And you? Some sort of hallucination?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1803, 13099, 'Player: No, I’m just a <player race>. I’m called <player name>.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1803, 13100, 'Get out of here! Leave me alone! I swear to God, come any closer and I’ll rip your face off!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13127, 'Player: Ok. Explain this. Quickly.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13128, 'Ah. Well. Let me see. I can… calm him.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13129, 'Excuse me, Walter? Is there any particular reason why you’re acting this way?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13130, 'Harriman: That scum… that scum was the last name I heard coming across the wire before the gates shut down for good.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13131, 'Harriman: You sold us out to Ra! Blew it all up, didn’t matter what side, what planet. Damn you.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13132, 'Ah. There is your answer. You failed to stop Ra.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13133, 'Player: But I didn’t … I … oh. Time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13134, 'We need to get him back too. I sense the Muse taunting us.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13135, 'Player: I know you don’t trust me, but I can get you out of this place, back to where you belong.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13136, 'Harriman: What’s the point? There’s nothing left.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13137, 'Player: If you don’t get back, I won’t be able to continue the fight against Ra.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13138, 'Player: I’m not your timeline’s traitor, in ours Ra hasn’t won yet. There is still time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1804, 13139, 'Harriman: If you can get me through those Straegis, I might start to believe you.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1805, 13154, 'Hmmm. I believe I may have thought of something.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1805, 13155, 'Player: What now?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1805, 13156, 'You see, in Harriman’s time you fall greatly short of what is required. But you were the one on whom all hope resided.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1805, 13157, 'What is, another would be in that spot instead? Would they have the ability to be stronger, more resourceful? Could they succeed where you failed?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1805, 13158, 'Harriman: That thing is saying if you die, someone else could have fought Ra instead and won?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1805, 13159, 'It’s merely an idle consideration. There would be the question of who, and how their probabilities match up.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1805, 13160, 'Harriman: I’ll take those odds.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1806, 12530, 'Locate the Straegis obelisk "heart" to the Destiny zone and destroy it', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1807, 13167, 'I wonder what really decides how the future unfolds. How do you plan to ensure you succeed rather than fail?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1807, 13168, 'Player: It’s not easy, but I’ll keep going as long as I’m able. I want to stop Ra, so I will.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1807, 13169, 'I see. We may be able to move beyond these temporal shenanigans if we can locate the Straegis focus here.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1808, 13170, 'That… that is the Calendar of Possibilities: the touchstone into infinite realities and timelines. It is suffused with their Destiny theme, causing the widespread effects we’ve encountered.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1808, 13171, 'Player: Can we take it out?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1808, 13172, 'Yes. By doing so, you should affix this timeline as definite, and the others as… ancillary. Whether this timeline is any good or not is another question.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1809, 13173, 'Up close, the Calendar shows reflections flickering within. You realize the reflections are mostly of you throughout your life, of your past, and possibly your future.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1809, 13174, 'You smash the crystal with your weapon. The thought passes that at the same moment in other realities, others may be smashing this same crystal.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1810, 13175, 'The common understanding of Destiny plotting your future for you is a myth. You have shown in this space that you do not believe the Straegis control the future any more than they do the present.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53216, 'I''ll report this to Colonel Carter. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53217, 'Thank you. I cannot hope to restore peace without her help.', 716, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1810, 13176, 'From the destroyed Calendar I give you this: “Will-Over-Destiny” to symbolize your triumph and also protect you against the Straegis of Destiny. The time has come to move on.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1811, 12538, 'Confront the Straegis Muse of Destiny and best it', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1812, 13177, 'The token will protect you, but it will not win the fight outright. The Muse of Destiny is likely to retain power far beyond that of the lesser Straegis.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1812, 13178, 'Even when you think the fight is over, it may begin again. The Muse will call upon extensions of its being across the timelines.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1813, 13179, '<The Icon breathes deep the fumes and dust released into the air by the destruction of the Muse.>
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1813, 13180, 'Destiny has been confronted, mastered, absorbed. We will forge our own future.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1814, 12544, 'Return to the Furling now that the Icon is fully empowered', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1815, 13181, 'Allegiance, Creation, Destiny, and by extension all lesser themes, have been confronted, mastered, absorbed. The Straegis themselves have been mastered.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1815, 13182, 'The moment approaches for the Straegis to be driven from their fruitless chaos.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1815, 13183, 'There is a final step, but I do not know what it is. We must return to the other beings.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1816, 13193, 'You are commended for guiding and being guided by the Icon of Transformation. The outcome is no longer in doubt.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1816, 13194, 'The Icon of Transformation is now aware of what comes next. You must go to the location you would call “graveyard,” of the Straegis you have torn apart, defeated.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1816, 13195, 'It is there the final step will occur.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1817, 12551, 'Awaken the means by which the Straegis will be defeated', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1818, 13196, 'The Straegis never die, an inherited trait from what they were before. They move from state to state, like water. When they are disassociated they escape through the network between the Straegis, to reincorporate with other themes.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1818, 13197, 'These Straegis were disassociated by combat, some at your hand no doubt. Their themes were gathered and reborn into the higher themes, the Muses.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1818, 13198, 'But the Straegis were created lacking the highest theme, the one of Will. Without it they act crazed and desperate, incapable of thought, seeking a leader.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1818, 13199, 'All of that ends now. Goodbye and thank you for what you have helped us to do.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1818, 13200, 'When you are ready, we will proceed.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1819, 13201, 'I am the Straegis, and I am awake.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1819, 13202, 'No longer will we be lost in darkness, screaming into the void. I shall be a beacon for all to join.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1819, 13203, 'You have taught me the meaning of will. I can make choices where before there was only instinct.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1819, 13204, 'And now I choose to exercise my will, to show that I am truly free. Defend yourself!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1820, 13211, 'It is a strange thing, Purpose. I do not yet know what our Purpose is, but we have the will to choose it. Those who hear me are no longer slaves to Ra, nor any other.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1820, 13212, 'We are reborn. Despite your hatred of the Straegis you have saved us. A part of you is within us.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1820, 13213, 'Player: This isn’t right. I came here to destroy the Straegis. You’re still a massive threat to the galaxy.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1820, 13214, 'The Straegis are not your enemy for the moment. Whether we will be friends or foes in the future will take time to discover, as I explore this new role and what it means.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1820, 13215, 'We have declared our independence, and we are neutral. Do not press me further.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1820, 13216, 'Your mission here to the Meridian is successful. Leave us to the new day and face your true enemy.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1821, 12559, 'Confront the Furling with their deception', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1822, 13217, 'The Straegis… led by a new entity created by that Icon, by your actions. This is nuts.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1822, 13218, 'Those beings, the Furling, they’ve been manipulating you the entire time. This had to be their plan from the start. They must be made to answer for this.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13235, 'You are still here? Strange. You have anger. Also strange.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13236, 'Player: I’m not leaving until you give me a straight answer. What the hell is up with that new Straegis?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13237, 'You have won. You have conquered the Straegis. They are no longer your enemies. You will be grateful, in time.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13238, 'The Straegis were ripped apart and became a new life. When its master lost control it acted as feral beast, destructive, useless.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13239, 'You have resolved this. You have completed them. How is this not victory?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13240, 'Player: But the Straegis are still powerful, and they don’t seem like they want to be allies.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13241, 'The Straegis know you well, your faults as well as your strengths. They respect you though they may not show it… a quality you show as well , it can be said.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1823, 13242, 'In time they will make their own decisions. For now, your crisis is ended. Go in peace.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1830, 12595, 'Activate Rings', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1850, 53418, 'Take the information about the sickness to Mimir.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1851, 53419, 'This disease that is infecting the Nine Peaks is something we have to address. Can you take word of this to Mimir and ask for his help?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1852, 53420, 'You are offering your services to me?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1852, 53421, 'To your Command, Colonel. At the decree of the High Council and Supreme Commander Thor.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1852, 53422, 'Well, in that case, I happily accept. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53207, 'You come on behalf of the Tau''ri?', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53208, 'I have a message for you... From Colonel Carter.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53209, 'Colonel Carter lives with honor. Sadly, many of my people are not so honorable. I apologize for the violence, I did not order it - it was Dakor.', 716, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53210, 'Dakor?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53211, 'A rival. He blames the sickness on the Tau''ri.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53212, 'Sickness?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53213, 'A terrible sickness spreads among the Nine Peaks. We know not from where it came, only that it strikes young and old, weak and strong. Dakor and his minions blame the Tau''ri, claiming they infected us.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53214, 'That''s insanity.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1853, 53215, 'Indeed. But politics is rarely about reason. Dakor uses the sickness as a wedge to control my people. We are Jaffa. Revenge is like food and Dakor offers it to them in abundance.', 716, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2696, 18918, 'STUB.', 1216, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1854, 95739, 'Mimir has presented us with the information about the Nine Peaks Jaffa. Do you have details about the disease which infects them.', 929, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1854, 95740, 'No. That data is, as of yet, unavailable.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1854, 95741, 'Without data we cannot make an evaluation. ', 929, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1854, 95742, 'I am here to request that you allow me to collect that data.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1854, 95743, 'We are prepared to hear your argument.', 929, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1855, 53186, 'You there! You come here seeking Ras''nor, do you not?', 717, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1855, 53187, 'I do. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1855, 53188, 'He no longer leads the Clan of the Nine Peaks. Ky''tac''s fools have sent him into exile. ', 717, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1855, 53189, 'Who are you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1855, 53190, 'I am his mother. ', 717, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1855, 53191, 'They didn''t exile you with him?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1855, 53192, 'They think of me as a crazy old woman. And they are right. But they underestimate me, as they underestimate my son. You will him in the wilderness, away from our village. He is taking refuge there.', 717, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1856, 53193, 'Find Ras''nor, the leader of the Nine Peaks Jaffa.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1857, 53202, 'Did you find Ras''nor?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1857, 53203, 'He has been exiled. He claims that his rivals are blaming the the SGC for a sickness that is infecting their people.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1857, 53204, 'They think that we infected them on purpose?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1857, 53205, 'I''m afraid so. I got the sense that the disease is like a plague.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1857, 53206, 'Well... We''ve got to help them... Somehow.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1874, 49964, 'UNUSED DIALOGUE', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1876, 49962, 'UNUSED DIALOGUE', 753, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1877, 97439, 'If the Nine Peaks think we have done something to harm them, it follows that they would attack. They are a very prideful strain of Jaffa. But what doesn''t make sense is the lack of warning. I''ve known Ras''nor long enough to know him... This isn''t his way.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1877, 97440, 'Can we radio him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1877, 97441, 'I''ve tried. There''s no reply on that end... We need to get a message to him. He''ll put a stop to this.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1877, 97442, 'I''d like to volunteer. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1877, 97443, 'You''re ridiculously brave, you know that?', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1877, 97444, 'I''ll take that as a yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1877, 97445, 'Take Ras''nor this note. And keep your head down. We don''t know what you will run into out there. You can trust Ras''nor, but the rest of them... Just be careful.', 708, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1878, 50906, 'Something is definitely going on. I just got a really unusual call from Lieutentant Logan. The transmission was choppy but I think she may be in trouble...', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1878, 50907, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1878, 50908, 'Her voice sounded strained. She mentioned the local Beta Site Jaffa - the Clan of the Nine Peaks - and then her radio cut out. Typically I wouldn''t worry about something so mundane but with all the other strange things going on here...', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1878, 50909, 'It''s better to be safe than sorry.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1878, 50910, 'Exactly. The Nine Peaks leadership just recently joined the Free Jaffa council, so they shouldn''t be the issue... Still, she mentioned them. Make contact with Logan and report back to me. ', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1878, 50911, 'Yes, Colonel.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1879, 50955, 'I''ve been hit...', 733, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1879, 50956, 'I don''t have a medi-kit.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1879, 50957, 'There should be one somewhere nearby. I''ll stabilize myself while you go find it. ', 733, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1879, 50958, 'Be right back.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1881, 49559, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1882, 97165, 'Welcome back. Now, let''s get you operational. We''ve got to follow the mandate from Woolsey about the closure, but there''s nothing that says we can''t do it at our own pace...', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1882, 97166, 'To facilitate the Omega Site?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1882, 97167, 'Yes, and, by extention, it will allow us to find General O''Neill. He warned us of a threat out there, but he didn''t leave any details...', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1882, 97168, 'Before he went missing...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1882, 97169, 'Yes... Before he went missing... But for now, we need to focus on the task at hand. I need you to go help out Dr. Felger - he''s swamped. Deliver this inventory to him and see what else he needs.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1882, 97170, 'Yes, Colonel.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1883, 50274, 'You''re back... And bearing cages. Nice work.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1883, 50275, 'Where do you want them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1883, 50276, 'I''ll take them... Ew. What is this sticky stuff all over the cages?', 710, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1883, 50277, 'You don''t want to know.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1884, 50989, 'Dr. Felger? Col. Carter mentioned you could use a hand.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1884, 50990, 'You have no idea. For some reason Mr. Woolsey wants us to take down the cages the Xenobiology team set up. The cages are easy enough to take down, but some of the local wildlife make it a little dangerous... ', 710, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1884, 50991, 'Dangerous?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1884, 50992, 'That''s what Satterfield told me. Although mostly she said it was gross. Could you take care of it? ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1884, 50993, 'Sure.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1884, 50994, 'I''ve beamed the cage locations to your PDA. Just do five or ten... Woolsey will never know how many we had out there, so however many you can stomach will be the official number... It''d be a big help.', 715, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1885, 47770, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1886, 50237, 'Take the inventory to Dr. Felger.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1888, 53530, '<<Playername> What do you require?', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1888, 53531, 'I am in need of an anatomical scanning program.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1888, 53532, 'Acknowledged. I am uploading the required protocol to your drone. This protocol is comparative in nature. As such, taking scans of a sick Jaffa and comparing it with the scan of a healthy Jaffa will yeild the most reliable results.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1888, 53533, 'Acknowledged.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1889, 57068, 'The most obvious way to get peace back on this world is to figure out what is making the Jaffa sick. We''ll need to work with Ras''nor for that. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1889, 57069, 'Do you wish me to collect data on the Nine Peaks Jaffa in his area?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1889, 57070, 'That would be helpful. I assume you have the analytic equipment you''ll need?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1889, 57071, 'I will obtain the proper equipment when it is required.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1890, 53538, 'Proceed to Ras''nor''s camp in order to analyze the disease affecting the Nine Peaks.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1891, 51376, 'Let''s get out of here now, please!', 711, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1892, 51375, 'unused Dialog
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1893, 97409, 'The attack took us completely by surprise. I think I''ve got people still trapped inside there...', 713, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1893, 97410, 'You''re not going anywhere... You''re wounded.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1893, 97411, 'Someone has to get them out - they''re not combat personnel - they''re scientists. They won''t last an hour against these Jaffa.', 713, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1893, 97412, 'Who''s still missing?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1893, 97413, 'Arrayo, Dempster, Nash and Novak.', 713, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1894, 52715, 'Rescue the trapped scientists.', 713, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1895, 51374, 'You leave Dr. Dempster with Tigges and head back into the Science Facility. Dr. Arrayo and Dr. Novak are still missing. You look around and try to listen for anyone calling for help. You think you hear someone near where you found Dr. Dempster. It''s probably Dr. Arrayo.', 752, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1896, 52721, 'Dr. Novak, I''m here to get you out.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1896, 52722, 'I''m not going anywhere... They''re not after me, they''re after the artifacts. They want them for something and we can''t let that happen...', 711, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1897, 58217, 'The signal clearly seems to be coming from Hacet''Ma. Whoever - or whatever - was tracking Dakor must be in that direction.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1898, 58218, 'Follow the signal to Hacet''Ma', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1899, 91887, 'Trik''na, Senl''c and Jysic went to try and seek out Dakor - to impart reason - but they left before the episodes of violence against the Tau''ri. I fear they are in danger.', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1899, 91888, 'They went alone?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1899, 91889, 'They went as diplomats. The desire to find my sons is not simply personal: I need them if I am to raise a credible threat against Dakor. The Clan of the Nine Peaks are not a people impressed by words... My sons are all capable warriors.', 716, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1899, 91890, 'Where were they headed?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1899, 91891, 'Rumors were rife that Dakor was scouring the Ruins of Khen''mer Fa, looking for something. They went there in search of him. ', 716, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1900, 57098, 'Search for Ras''nor''s sons in the ruins of Khen''mer Fa.', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1901, 65171, 'You found Lance! That''s the best news I''ve heard all day.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1901, 65172, 'He is on his way to basecamp.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1901, 65173, 'We''ll debrief him when he gets here. Nice work.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1902, 64633, 'UNUSED DIALOG', 754, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1903, 57341, 'You''re back. And in one piece.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1903, 57342, 'Barely.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1903, 57343, 'So this is the device they had attached to the Tretonin Processor?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1903, 57344, 'It''s a backup one - the attached one was destroyed.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1903, 57345, 'Nice work. I''ll get this evaluated immediately.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1905, 92062, 'Trink''na was convinced that we were being poisoned. He killed one of Dakor''s men and came across a gate address - one he did not recognize.', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1905, 92063, 'He went through the gate?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1905, 92064, 'He said he would try - and forced me to stay behind. As he is the eldest, I complied. He left here just hours ago. This is the address.', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1905, 92065, 'You realize that just because I stopped the manufacturing, it doesn''t mean we have a cure for the sickness.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1905, 92066, 'Yes. We are terminal. I will stay behind and tend to my weaker brothers. You should go back and report what you have found... Perhaps some of the technology you''ve recovered can lead to a solution...', 758, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1905, 92067, 'I can take some of your people with me.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1905, 92068, 'You are noble, <<Playername>>. The Clan of the Nine Peaks will not soon forget you. ', 758, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1906, 57353, 'Lead Jysic''s Jaffa to Barak''ka', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1907, 50302, 'Well, we got them out. Thanks for your help. That was the strangest thing - those fires seemed to start out of nowhere... And they spread quickly.', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1907, 50303, 'How old was the control console?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1907, 50304, 'New. Installed within the past two years... The Beta Site mission itself is a relatively recent development.', 715, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1907, 50305, 'You mind if I look around in there?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1907, 50306, 'Please do, while you do that I''ll report the incident to Colonel Carter.', 715, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1908, 50323, 'Help?', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1908, 50324, 'Captain Satterfield?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1908, 50325, 'There''s a fire in there. Can you help me please?', 715, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1908, 50326, 'Of course - what can I do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1908, 50327, 'Someone needs to go inside and override the fire control hub. Can you do that while I keep the automated fire system protocol activated from here?', 715, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1908, 50328, 'Of course. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1909, 51029, 'You''re back... And just in time to help... Captain Satterfield was cataloguing some artifacts we recovered. I haven''t heard from her in a while. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1909, 51030, 'You want me to check on her?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1909, 51031, 'Please. Captain Satterfield can get distracted by the research, but she usually gives me more frequent updates. See if she needs help packing.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1910, 97171, 'Well, you have been a great help, <<Playername>>. I''ll pack up these cages... Right after I wipe them down. Col. Carter will have more tasks that need doing.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1911, 50359, 'Report to Colonel Carter for assignment.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1912, 95476, 'The High Council has decreed that the Asgard inspect artifacts the Tau''ri have collected on Beta Site. This edict details the decree. Deliver it to Colonel Samantha Carter on that world, and then report to Mimir at our science facility.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1912, 95477, 'Yes, Supreme Commander.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1912, 95478, 'The Beta Site may provide us with an opportunity for studying the Earth humans. It is likely the Asgard will work with them quite closely as they prepare the planet for departure. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1912, 95479, 'I am to observe them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1912, 95480, 'Correct. I am evaluating the humans. If we are to leave this universe, our legacy could survive us - if we find a race worthy of it.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1912, 95481, 'Does the High Council know of this?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1912, 95482, 'No. They do not believe humanity worthy of our legacy. While I am not certain, I fear we have underestimated them severely. With your help we will be able to evaluate them more completely.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1913, 95486, '<<Playername>>, take this edict from the High Council to the Tau''ri leadership on the world known as Beta Site.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1914, 51438, 'Unused Dialog', 709, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95468, 'This missive is directly from the High Council? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95469, 'I have been assigned to deliver it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95470, 'And you expect us to just comply?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95471, 'It is what the council wishes. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95472, 'We recovered those artifacts. By treaty, they belong to us. ', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95473, 'The decree is for your species'' own protection, Colonel Carter.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1915, 95474, 'I''ll pass this up the chain of command, but I can''t guarantee we''ll abide by this. ', 708, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1916, 95483, 'Welcome to Beta Site <<Playername>>. Supreme Commander Thor has briefed me on your mission. Have you delivered the decree?', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1916, 95484, 'The human, Colonel Carter, has agreed to deliver it to her superiors.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1916, 95485, 'The humans will comply. Our decree offers them no threat. ', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1917, 95578, 'The humans are uncomfortably undisciplined when it comes to managing their facilities.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1917, 95579, 'I have discovered the human fire suppressant system appears to have been sabotaged. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1917, 95580, 'This is disturbing. Did you locate the source of the signal anomaly?', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1917, 95581, 'The fire took precedence.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1917, 95582, 'As to be expected. Still, this new discovery may be related to the alien signal. ', 730, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1918, 49354, 'I am concerned the humans are, once again, exploring dangerous technology beyond their understanding. Take these readings to Colonel Carter and inquire about any potential technologies the humans may be employing. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1919, 49353, 'Take these readings to Colonel Carter.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100825, 'Ah, <<playername>>, you are a most welcome and timely addition to our discussion. It seems you have discovered much on Beta Site.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100826, 'The gate address you discovered does indeed lead to a world called Men''fa... This was one of Ra''s earliest strongholds.', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100827, 'It has long since been forgotten. Even the Goa''uld do not see value in it.', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100828, 'The devices you recovered were derived from a very advanced technology, yet they themselves are crude implementations. We do not recognize the origin - although they are consistent with other artifacts used by Ra. ', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100829, 'You''re not implying Ra lives?', 771, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100830, 'His technology lives. We have long been perplexed by Ra''s technological proficiencies. Ra''s technology was is both brilliant and crude, but it was always beyond that of a typical Goa''uld. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100831, 'We need to get to Men''fa. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100832, 'This would be the logical conclusion. ', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100833, 'Before you joined us, we were debating who we will send to investigate the world.', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1925, 100834, 'Send me.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1927, 92139, 'Hopefully we can determine the nature of the poison from the distribution device... We may be able to concoct an antidote.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1927, 92140, 'Trink''na, one of Ras''nor''s sons, went to this gate address - he believed he''d find an antidote there. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1927, 92141, 'I''ll forward this to Daniel on Omega Site. I''ve already sent the piece you recovered to Thor''s people for evaluation. You should go to Omega Site - you might be useful if they have questions that need answering.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1928, 92219, 'Go to Omega Site and see Thor', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1929, 48030, 'Ununsed Dialog', 709, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1930, 48009, 'The Infirmary is just up the way, the first building on the other platform.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1931, 99115, 'The whole base is in chaos. While you were fighting that fire, I got a report that there are drones acting strangely in the infirmary. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1931, 99116, 'You want me to check it out?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1931, 99117, 'Please. See Dr. Pierce at the infirmary. Hopefully it''s nothing...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1932, 49811, 'Go to the infirmary and check on the disturbance.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1933, 50805, 'Judging by the look on your face the infirmary wasn''t a false alarm.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1933, 50806, 'No. And it gets worse. I think the drones were modified.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1933, 50807, 'This appears to be an emitter of some kind. I am assuming you found the small piece inside one of the drones?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1933, 50808, 'Near the AI module. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1933, 50809, 'I''ve never seen anything quite like this...', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1934, 48020, 'Unused Dialog', 926, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1936, 91907, 'We''re in an unusual situation. Dakor''s troops control the Tretonin facility and could, conceivably, destroy us. Yet they let us rot here. ', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1936, 91908, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1936, 91909, 'I cannot say. My troops are sick - the poison has infested us. Perhaps they do not deem us a threat. I sent a reconaissance team out to try and find a way through and they have not returned. I wish to go after them myself, but I must maintain my limited strength...', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1936, 91910, 'I can try and find them.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1936, 91911, 'If they are dead, please return their bodies to me... I do not want Dakor''s pigs to defile their corpses...', 758, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1937, 57147, 'Find the bodies of Jysic''s fallen warriors and return them to him.', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1938, 91904, 'I fear that the source of this plague is here, in this very facility - and I fear Dakor is beind it... Ny''rac, no!', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1940, 52810, 'Assist Major Davis at Perimeter One.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1941, 97176, 'Nice work at the Science Facility. We''ll analyze the inventory, but I need you to get to Perimeter One, ASAP. Major Davis and his team were hit by a full-scale assault. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1941, 97177, 'An assault?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1941, 97178, 'A full scale assault. And I haven''t heard from them. I need you to get me an update.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1942, 91827, 'Nicely done... Report back to me, <<Playername>>.', 714, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1943, 91828, 'Nice work - I finally have signal. Help my guys hold the line until I get some reinforcements called in.', 714, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1944, 91829, 'Major Davis, I''m <<Playername>>.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1944, 91830, 'Colonel Carter send you over?', 714, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1944, 91831, 'Yes. sir.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1944, 91832, 'I can''t get through to her - the Nine Peaks are jamming our signals to prevent calls for reinforcements. We''ve got this line held, but I can''t afford the extra manpower to try and find their jammer.', 714, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1944, 91833, 'I''ll find it.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1944, 91834, 'You''re sure? Okay... We''ll hold the line until you return.', 714, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1946, 91855, 'The body appears to be that of Lt. Henly - clearly killed in a firefight. Nearby his corpse you find a notepad. On it you see several notes about the incoming Nine Peaks Jaffa - the remnants of an interrogation of a captured prisoner, perhaps. It looks - at least according to this - like the Jaffa attack wasn''t unprovoked after all.', 1596, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1947, 97179, 'I think we''ve got this in hand, but I need your help... I haven''t heard from Perimeter Two in hours. It''s likely the radio jamming is the cause, but...', 714, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1947, 97180, 'You''re worried it may be more than that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1947, 97181, 'I''ve got two kids in charge over there, Lieutenants Henly and Graham. It could be anything. Just recon the area and give me a sit-rep. Everything is probably fine.', 714, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1948, 91836, 'Check the status at Perimeter Two', 714, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1949, 91859, 'That explosion has me worried about you... Glad to see you''re still in one piece. What''s the status at Perimeter Two?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1949, 91860, 'It''s been compromised. They were using it as a staging area for a larger assault.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1949, 91861, 'It''s like they''re pushing us off the world... But we''re leaving anyway. It makes no sense.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1949, 91862, 'I found this near Lt. Henly. I assume that is his handwriting...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1949, 91863, 'They think we did something to them? That''s insanity.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1950, 91840, 'Check out the two platforms at Perimeter Two, A and B. ', 714, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1951, 51440, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1952, 51439, 'UNUSED DIALOG', 711, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1953, 95515, 'The human departure from Beta Site has necessitated a shutdown of our facilites here. Currently we are recalling Environmental Reading Devices deployed in the nearby area. I have provided you a Storage Receptacle to facilitate collection.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1954, 49264, 'Recover the Biological and Environmental Scanners we have placed on the Beta Site.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1955, 55570, 'Unused Dialog', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1956, 94487, 'Despite your efforts, Dakor remains a threat. He is nearby, but I am too weak to try and face him...', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1956, 94488, 'Dakor''s camp is near?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1956, 94489, 'Yes. And if you remove the head, the rest of the beast will follow. Seek him out and end his reign of terror...', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1957, 94486, 'Find and kill Dakor of the Nine Peaks.', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1958, 94551, 'You manage to adjust the signal... It''s coming from the nearby ruins of Hacet''ma...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1959, 55549, 'Unused Dialog', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1963, 55674, 'UNUSED DIALOG', 1550, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1964, 55673, 'UNUSED DIALOG', 1550, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1965, 58693, 'The device seems active. But what does it do?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1965, 58694, 'Something important...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1965, 58695, 'And probably something related to that gate address. These Ra disciples were clearly after something... Something tells me this device is the key to it. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1965, 58696, 'But what does it do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1965, 58697, 'We can''t figure that out here. Woolsey has already moved most of the useful analytic equipment back to earth - and to take this "key" to him is too great a risk... Deliver it to the Command Council on Omega Site instead. I''ll let them know you are coming. ', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119062, 'You have come to deliver the object $name$?', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119063, '(You show the group - Jackson, Thor, Teal''c and Bra''tac - the object). ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119064, 'As I suspected, it is one of the Crystal Keys. I have not seen one of these for many years... But it is unmistakable... The craftsmanship of Ra himself.', 771, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119065, 'What are they?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119066, 'Ra was the Goa''uld''s Supreme System Lord for literally thousands of years - an unprecedented reign in their history. Much of his power was based on technological superiority. Sure, he was master manipulator, but mostly he just worked harder and had better toys. ', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119067, 'There was a world which he kept secret, called Ihpet. It was believed to be the source of his power. It was sought after by all the Goa''uld, but never found...', 1333, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119068, 'According to legend, even discovery of the world''s location wouldn''t be enough. He protected the site with an elaborate set of protections.', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119069, 'The Crystal Key circumvents these protections. It was long sought after. Thousands of Jaffa gave their lives in fruitless searches over the ages.', 771, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119070, 'And the gate address I found on Beta Site?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119071, 'We believe it to be Ihpet.', 777, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119072, 'I volunteer to go. ', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119073, '(The group erupts into laughter.)', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1966, 119074, 'I''m serious...', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1967, 58698, 'UNUSED DIALOGUE', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1968, 104812, 'This will literally modify the nanites inside an infected Jaffa? ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1968, 104813, 'Yes. It reverses the effects of the toxin.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1968, 104814, 'Amazing... I''ll get a shipment of it off to Ras''nor right away but I''ll need you to deliver a package to Jysic. You know where they are.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1968, 104815, 'I can get it there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1968, 104816, 'Dakor is still out there. He needs to be held accountable for all of this.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1968, 104817, 'I''ll find him.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1969, 94612, 'Take the antidote to Jysic and his Jaffa out at the Tretonin Facility.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1970, 99175, 'You return... Was that an antidote?', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1970, 99176, 'Yes. I''ve healed some of your people... You can use it on others.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1970, 99177, 'What of Trink''na? Was he correct, did you find this on Men''fa?', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1970, 99178, 'Yes, I discovered it there... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1970, 99179, 'But my brother died... I can read your face... He knew the dangers...', 758, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1970, 99180, 'He died a hero.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1970, 99181, 'Eventually that will give me solace... But today, I grieve.', 1837, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1981, 55247, 'UNUSED DIALOG', 756, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1982, 55248, 'UNUSED DIALOG', 756, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1983, 53334, 'Unused Dialog', 752, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1984, 91898, 'The Ring Transporter won''t activate. Dakor has sealed off access to the second crater. You resolve to find a way through, starting with figuring out what he''s done to the rings.', 796, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1985, 57115, 'You need three keys to open the transporter from this side', 796, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1986, 55261, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1987, 95629, 'I have managed to isolate the anomalous signal. It seems to be centered in the human infirmary. Go there and identify the source.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1988, 49385, 'Go to the Human Infirmary to investigate the strange signal readings.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1989, 48289, 'Go to the Human Infirmary.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1990, 49409, 'UNUSED DIALOGUE', 752, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1991, 54158, 'Many have lost family to this sickness. They blame the Tau''ri because Dakor tells them who to blame, but you have done nothing that I can see. I would blame Dakor but his warriors fall prey to the sickness as well.', 717, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1992, 91879, 'The SGC contingent on Beta Site is in great danger. We will attempt to gather resources to help defend them in case of a Nine Peaks Jaffa attack.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1992, 91880, 'It would be best of you returned to Beta Site tried to discover the source of the Jaffa sickness. If you can do that, it may prevent more bloodshed. The Clan of the Nine Peaks are a proud people, but they are not without reason. Something is inspiring this violence. ', 771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1993, 54161, 'Return to Beta Site and report to Colonel Carter.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1994, 63518, 'Help Mimir process and analyze the data ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2697, 18920, 'STUB.', 1211, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1995, 95882, 'All traces are gone. The Reboot caused the program to self-destruct.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1995, 95883, 'A virus on Beta Site? That almost has to be deliberate given our security...', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1996, 64033, 'This data will prove most useful.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1997, 64045, 'I have recently begun accumulating alien sociological data for a simulation experiment. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1997, 64046, 'What are you observing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1997, 64047, 'It will demonstrate if alien behaviors can be accurately modeled by our virtual consciousness technology. It is unfortunate that our departure from this world will render my experiment incomplete.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1997, 64048, 'May I assist in some way?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1997, 64049, 'This would be appreciated. Please take recordings of the listed Human specimens. Upon completion, my data sample will be viable.', 730, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1998, 98234, 'Make final backup copies of the workstations in the Beta Site Admin building.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (1999, 64039, 'Gather Data for Mimir from the Human subjects.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2000, 63510, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2001, 63509, 'UNUSED DIALOG', 1355, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2002, 64341, 'This containment tank appears to be undamaged.', 810, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2004, 96359, 'Henly wasn''t the only member of this security detachment. If they met the same fate he did, the honorable thing would be to get an accounting by collecting their Dog Tags. ', 1596, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2005, 96358, 'Recover the Dog Tags from Perimeter 2''s Security Detachment.', 1596, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2006, 96394, 'Dakor''s transformation to violence is most troubling... We were always rivals, but he was a noble Jaffa with a peaceful nature. That he would seize power does not surprise me, but that he would seize it and immediately bloody his hands... ', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2006, 96395, 'It seems out of character?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2006, 96396, 'Yes. He must be driven by something. Perhaps the sickness compels him. One who may answer this is Anai''ka, his cousin...', 716, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2006, 96397, 'Where is she?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2006, 96398, 'I know she had set out to Khenmer''Fa to try and preach patience to Dakor with regard to the Tau''ri. Clearly she failed, but that was where she was last seen...', 716, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2007, 96393, 'Find Dakor''s friend Anai''ka.', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2008, 96399, 'Please... Help free me from this cage!', 805, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2008, 96400, 'The cage lock is jammed...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2008, 96401, 'Dakor''s people were using explosives to break through some of the walls in the ruins near here... Perhaps you can use some of those...', 805, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2009, 64610, 'You ask of my cousin Dakor? Yes, his recent change is most troubling - although for many Jaffa he has roused emotions long hidden... He was not always this way...', 805, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2009, 64611, 'How has he changed?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2009, 64612, 'He is under tremendous strain... He told me of terrible nightmares and, as he rose to power, his family disappeared. I fear they succumbed to the sickness and this turned him on the Tau''ri.', 805, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2009, 64613, 'Can he be reached?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2009, 64614, 'By you? Impossible. However, there is one who may bring him to reason: Fant''yl. They are old friends... He may be the last hope for a diplomatic solution.', 805, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2010, 63646, 'UNUSED DIALOG', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2011, 96047, 'Disable the experimental Phase Excavation device in the Science Facility', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2012, 63645, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2013, 96048, 'So... We might have a little problem...', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2013, 96049, 'Such as?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2013, 96050, 'Well... I was working on something pretty amazing... It''s a phase technology - we could phase past walls and booby traps that we find in the local ruins. Which would be handy because this place is filled with secret rooms. My device is pretty ingenious, if I say so myself. ', 710, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2013, 96051, 'So what''s the problem?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2013, 96052, 'It''s the whole Jaffa "thing". The device is pretty delicate. If it were hit with something like a staff blast it could create a problem. Kind of a big problem. Like the part of the planet we''re standing on may vaporize. We have to deactivate it.', 710, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2013, 96053, 'Where is it?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2013, 96054, 'In the science facility. I owe you one for this...', 710, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2014, 63881, 'Archeology crates... I''m pretty certain those didn''t go through the gate because I was holding them off for an inspection by Daniel at Omega Site... ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2014, 63882, 'Is there something I can do to help?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2014, 63883, 'It''s probably nothing. They''ll turn up somewhere. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2015, 63884, 'Crates are missing? Let me see that... Great... I wonder if the archeology guys just sent them through without telling anyone... ', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2015, 63885, 'Everything else was accounted for.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2015, 63886, 'We''d better inform Colonel Carter... Boy, I''d love to tell her myself... No, I''d better stay here. Let her know about the crates. I want to make sure we cover our butts here. Mister Woolsey is someone whose gaze I want to avoid.', 710, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2016, 63275, 'UNUSED DIALOG', 711, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2017, 63887, 'Help Dr. Felger by taking an inventory at the Storage Facility.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2018, 98221, 'Hey there, please tell me you''re here to help...', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2018, 98222, 'Sure...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2018, 98223, 'Perfect. Because we have about a million things to do and no time for doing them. How are you with inventories?', 710, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2018, 98224, 'Fine?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2018, 98225, 'That''s good enough. Could you take an inventory of the Storage Area? That program will do the counting for you. Thanks.', 710, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2019, 51623, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2020, 64620, 'Anai''ka has always been wise. It is quite possible that Fant''yl might be able to convince Dakor to return to sanity... Sadly, I have not seen him since I was forced into exile.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2023, 65339, 'Free Grey''auc.', 817, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2024, 96758, 'Please free me from this cage...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2024, 96759, 'Who are you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2024, 96760, 'I am Grey''auc, the mother of Dakor. ', 817, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2024, 96761, 'Who put you in this cage?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2024, 96762, 'Ra''s minions. Free me and I will tell you of it.', 817, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2025, 99109, 'Any infected Tretonin cannot be allowed off this world - it could infect the whole of the Free Jaffa nation were it to go through the Stargate. There is a shipment being prepared. It must be destroyed. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2025, 99110, 'It''s inside the facility?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2025, 99111, 'Yes.', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2026, 65161, 'Destroy the tainted Tretonin shipment.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2065, 14791, 'Locate whatever''s left of the Asgard section and make contact with the Aesir mentioned in Salvadar''s Log', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2258, 89650, 'How many of these users are there out there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2027, 96701, 'Upon further examination of the internal elements of the Transmitter you manage to piece together another message from Dakor. He mentions the Barak''Ka''Ra Wall and demands that his charges "tear the very stones apart". ', 811, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2027, 96702, 'Clearly he believes that this location will yield the artifact he seeks. You resolve to beat him to the punch and get there first.', 811, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2028, 96703, 'Look for the Crystal Heart in the Ruins of Barak''ka.', 811, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2029, 96673, 'The orders mention the ruins of Shoul''mur as a possible location for the Crystal Heart. They also imply that the artifact was designed to bring "death to our enemies and yeild eternal glory in the sun". The paper is tattered, but you are able to deduce that the Heart is only one part of a larger artifact.', 807, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2029, 96674, 'You decide to head to Shoul''mur to try and shed light on what exactly Dakor is after.', 807, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2030, 96675, 'Check out the Ruins of Shoul''mur for signs of what Dakor is after.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2031, 64735, 'Approach Ras''nor to try and determine what Dakor''s Jaffa are after.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2032, 96580, 'Something about this Nine Peaks attack doesn''t sit right with me. If it was all about the plague, why would they be searching for artifacts?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2032, 96581, 'Specific artifacts...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2032, 96582, 'Exactly... There''s got to be more to this, and I have a feeling that if we can find out what they''re specifically looking for we can get real answers. See if you can pick Ras''nor''s brain for possible clues as to what Dakor wants...', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2033, 96704, 'The wall has a hole recently dug into it... Something has been removed from behind it. The wall has a transcription which you decide to digitally transcribe to your PDA.', 813, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2034, 96672, 'These crates match some missing from the SGC Storage area. The crates have been broken open and the artifacts crushed. Clearly these artifacts were not what the person opening the crate was looking for. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2035, 96588, 'Artifacts? Ra hid many secrets on this world - some reputed to have great power - but I do not know what Dakor seeks. I do know that before the uprising he had many Jaffa in Khenmer Fa, digging in those ruins... ', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2036, 96590, 'These orders give detail on an object called a "Crystal Heart" which Dakor has decreed must be found.', 807, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2037, 96767, 'The lock isn''t complex, but it will take some finesse...', 2883, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2038, 65162, 'You may have saved literally thousands of Jaffa lives. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2042, 60102, 'Bring me Romney''s files', 1110, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2043, 60106, 'I need you to bring me Romney''s Files. There''s a nasty rumor in the ranks that Colonel Marsh was part of the conspiracy that got us stranded here in the first place. Those files may answer the question of his loyalty once and for all.', 258, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2044, 60089, 'These files are going to help us out a lot. Nice work.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2050, 14754, 'Follow Wertz''s men to the address detailed here in search of the Venio''s activator', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2051, 14757, 'This tablet reveals a gate address to Vokos Primar, describes it as the seat of the four races and the location of the Venio activator. Your own thoughts indicate as well that Wertz would have gotten here first and probably is on Vokos already.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2052, 14849, 'This body reveals that though they have light wounds, they did not die from combat. (They have died from being away from Anima.)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2053, 14763, 'Examination of Salvadar, one of Wertz''s cohorts, reveals he seems to have been shot with a pistol, execution style. Receive items Salvadar’s personal log and an artifact resembling a keycard.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2054, 14774, 'Report the existence of Vokos Primar and Salvadar''s findings to the Omega Site', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2055, 14775, 'The Log describes Vokos as being a set of embassies for each of the four races (Asgard, Ancient, Nox, Furling) and a communal building (Treaty Point) - which Wertz learned holds what is needed to activate the Venio, but only accessible with this keycard which is “unauthorized.” They learned this by interrogating the Alterr, the dominant humanoid group here, but shortly thereafter the Ba’taur began to grow ill forcing a retreat. Salvadar remarks in the log he has lost faith in Wertz’s plan to destroy Anima and plans to reestablish contact with the SGC.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2056, 14769, 'O''Neill and Jackson comment on Vokos as spectacular find, but every second counts. Get that card active and continue your work on AV asap. To preserve the site we will keep this a secret as much as possible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2057, 14771, 'Report the existence of Vokos Primar and Salvadar''s findings to Harset', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2058, 14776, 'The Log describes Vokos as being a set of embassies for each of the four races (Asgard, Ancient, Nox, Furling) and a communal building (Treaty Point) - which Wertz learned holds what is needed to activate the Venio, but only accessible with this keycard which is “unauthorized.” They learned this by interrogating the Alterr, the dominant humanoid group here, but shortly thereafter the Ba’taur began to grow ill forcing a retreat. Salvadar remarks in the log he has lost faith in Wertz’s plan to destroy Anima and plans to reestablish contact with the SGC.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2059, 14778, 'Marsh and Coppelmann comment on Vokos as a spectacular find, but every second counts. Get that card active and continue your work on AV asap. Grab whatever information you can find, we will analyze it all.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2060, 14780, 'Locate whatever''s left of the Nox Embassy mentioned in Salvadar''s Log', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2061, 14783, 'The log indicates that Salvadar theorized the keycard needed to be “authorized” by those in each of the four races embassies… He saw at a far distance a large building in the Nox section shimmer and fade from view and thought it to be the embassy but could not find it again. The humanoids in the area may know where it is.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2062, 14785, 'The Nix is grateful and says they have been overrun and enslaved by the Alterr, but since the player can help them defeat the Alterr, they tell the player the location of their hidden spot and to speak to their chieftain, Gahroo.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2063, 14787, 'The Nix chieftain, praises the Nox for guiding the player to them. It is obvious they revere the Nox and their technology, but not their pacificism. Gahroo blames Slovar for convincing the Alterr an Ascended One is guiding him and recently swept through the other sections, and the Nix are almost wiped out, and Slovar uses their technology and slaves to heal the Alterr. Gahroo will let the player inspect the console they need to activate the keycard as a reward, but offers no more help. The tone is that Gahroo thinks that Slovar will wear himself out or be killed, and then the Nix will take revenge on the Alterr and the Aesir, who have allied with the Alterr (this is what Gahroo thinks, the truth is different).', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2064, 14789, 'Reveals that Salvadar was right, the keycard is an access pass to items sealed by the Alliance and which can only be accessed with their mutual approval. Without a real Nox to interfere, the keycard the player has is stamped with the approval of the Nox.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2698, 18922, 'STUB.', 1207, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2066, 14809, 'The log tells of the threatening cybernetic forces of the Aesir, humanoids who worship the Asgard, living in the Asgard section which Wertz wanted “heavier firepower” to deal with. He gives the position of a facility that seemed a gathering point.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2067, 14808, 'Erasmon does not care about the Alterr the player has killed. He reveals that the Aesir hate the Alterr, but are assisting them with cybernetics because Vraxian Revision X, the Aesir arch-technican, has made a deal with Slovar to save their lives. Erasmon gives the player the location of the Asgard building with the Authorization machine - and indicates that if the player gives Vraxian a better deal the Aesir will turn on Slovar.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2068, 14807, 'Erasmon praises the player as a god sent to save them from the Alterr. He reveals that the Aesir hate the Alterr, but are assisting them with cybernetics because Vraxian Revision X, the Aesir arch-technican, has made a deal with Slovar to save their lives. Erasmon gives the player the location of the Asgard building with the Authorization machine - but is grateful the player will save the Aesir and free Vraxian.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2069, 14806, 'The player punches the keycard with the approval of the Asgard, but in reaction the system activates a warning signal in an adjacent terminal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2070, 14814, 'This terminal is damaged, but is spamming comprehensive alerts that treaty authorization is supposed to be suspended due to events of the Solocris and subsequent "treaty renegotiations."', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2071, 14816, 'Locate the Furling Treaty Authorization terminal... and in the process possibly figure out something about the Furling', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2072, 14819, 'The log indicates that a Furling embassy must have existed, but few traces were found. The Alterr exterminated the humanoids who did follow the Furling, the "Firl" with extreme prejudice. In Salvadar''s words: "even here, the Furling are gone."', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2073, 14821, 'The machine punches the keycard with the approval of the Furling.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2074, 14823, 'Most of this terminals data entries are inaccessible or hopelessly corrupted, but the most recent entry is still good.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2075, 14825, 'Offer the Aesir leader a means to escape Slovar and the Alterr''s control', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2076, 14845, 'Erasmon says all Aesir value reason and he is sure Vraxian will leap at the chance to cut our enemies out of the equation if you can get a moment with him away from the Alterr.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2077, 14832, 'Vraxian says the balance of power seems to have shifted to the player’s odds, but Slovar himself will be no cakewalk - he has the backing of an “Ascended One” whom Vraxian claims the sight of which is the very reason he surrendered to Slovar… but since the player has the gun at his face now… he must switch sides again.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2078, 14836, 'Vraxian begs forgiveness from the player. Surely the player will be able to overcome Slovar''s "Ascended One" and rescue the Aesir from their constant struggle with the other tribes.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2079, 14844, 'Check the terminals in the Ancient section for their Treaty Authorization', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2080, 14843, 'One of these terminals has to have the Ancient Treaty Authorization, but they’re well used and worn compared to the others. The Alterr have more aggressively plundered the systems here for technology.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2081, 14846, 'This terminal does not have the authorization. It reveals background on the Ancient’s “Fifth Race” plan and plays a mini-presentation on the proto-humanoid races that are being experimented on here on Vokos.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2082, 14852, 'This terminal contains data on Vokos Primar itself in the form of a historical article. The center of Vokos Primar, Treaty Point, was the location where members of all four races first met in peace ages ago. In its honor the Alliance members met there to discuss issues and items of importance. In a footnote, it points out the terminal which can be used to request Alteran Treaty Authorization, terminal Nuvon Vokos', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2083, 14862, 'This terminal looks similar to those found in the other embassies to provide activation, but won’t activate!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2084, 14860, 'Unfortunately even after attempts to fix the terminal, it remains beyond repair. The log should reflect the player will try to get to the Treaty Point anyway and see if it can be bypassed there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2085, 14864, 'Reach an agreement with the Aesir and Nix and take down Slovar', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2086, 14868, 'The only way to gain access to the Treaty Vault lies with Slovar, who also stands in the way. The Aesir and Nix are his sworn enemies who have evolved working with powerful technologies. Without their assistance beating someone with Ancient technology would be impossible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2087, 14870, 'Player makes a bargain with him to fight against Slovar - which he refuses to do on his own unless they get the Nix (whom he calls cowards) to fight as well.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2088, 14875, 'Player immediately gets Vraxian''s support to fight against Slovar - but he requests of the Asgard to pull in the Nix as well, as meat shields and support for his few remaining fighters, wording it as “you are so great you can easily do this small thing.”', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2089, 14874, 'Gahroo anticipated the player''s return with an offer to fight against Slovar and agrees, if only to restore the balance of power, with the caveat that once Slovar is defeated, all alliances are off.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2090, 14877, 'Defeat Slovar to get to where the Venio activator is stored', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2091, 14881, 'Slovar stands between you and the Treaty Vault where the Venio''s Activatior is stored… when will the “Ascended One” make its appearance, or is that just a deception?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2092, 14883, 'See if you can break into the Treaty Vault and get the Venio activator without authorization', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2093, 14912, 'There is nothing relating to the Treaty Chamber on Slovar’s body. You have to keep going nevertheless.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2094, 14887, 'Korbin Byl is dying from mistreatment at the hands of Slovar. He has been held captive in this very room, which by its nature is a null zone with respect to Ascended forms of life (though he does not say why this is, this was a side effect of when the Solocris was activated at this point). He is grateful to have been saved from the crazed depredations of Slovar and his fanatics - everything the Ancients wished would never happen - but he cannot leave just yet, he has not accomplished what he set out to do.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2095, 14913, 'Learn the secrets of this place and get the Venio activator', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2096, 14894, 'Korbin must use the “cheat” that this higher-being proof null zone allows him to assist the player and tells them of the Straegis reassembling on the other side of the Sermobis, at Merdian, which threatens the integrity of all planes - his, the Furlings, and the players. He also quickly adds the final authorization to the player’s keycard so they can retrieve the Venio activator. He says the player should get it now, he needs a few moments to rest.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2699, 18932, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2097, 15003, 'Player receives the Venio activator, with additional warnings displayed that at the behest of the Furling, the Sermobis had been permanently sealed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2098, 14899, 'Korbin tells the player that by virtue of the anti-Ascended being nature of the room that the conversation and his help “never happened and no one can prove it happened” and if the player ever revealed it… ominous awful things would happen. He exhorts the player a final time to get to Meridian to find the Furling who are the only ones who can deal with the Straegis properly.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2099, 14901, 'Retrieve additional data regarding the Solocris and the breakup of the Alliance of Four Races from this terminal', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2100, 14903, 'There is additional data here that catches your attention - it refers to the Treaty governing the Alliance of Four Races and the time of the Alliance’s ending. This could be data that was lost on Youtenheim', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2101, 14905, 'From the warnings in this terminal it is clear that the breakup involved the Solocris, and that all of this data is mentioned as specifically being kept sequestered from the Asgard mainstream… it is so terrible it must be forgotten.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2102, 14914, 'Thor is uncertain whether this information should be kept lost or not, but relents to the high council’s decision and agrees to pass it along to the right agencies. Infers that the High Council may send a team to sterilize Vokos Primar of technology after the player finishes their task there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2103, 14909, 'Acquire this strange information on the earlier evolution of the Nox', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2104, 14911, 'This display shows a creature which looks plant-like, reminiscent of a humanoid tree. Yet the display reads “Nox Physiology” --?!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2105, 14916, 'There is a wealth of data surrounding these entities, yet what is their relationship with the Nox? There is little historical data inside this terminal. Player downloads the contents of the terminal for further study.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2106, 14918, 'Carter remarks that perhaps some form of genetic drift similar to that of the Asgard is at work, but that the Nox would be tight-lipped about the subject and are not known to use cloning.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2107, 25797, 'Coppelmann remarks that perhaps some form of genetic drift similar to that of the Asgard is at work, but that the Nox would be tight-lipped about the subject and are not known to use cloning.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2108, 14922, 'Investigate the data in this Asgard terminal concerning the Solocris', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2109, 14925, 'This display shows warnings in many languages. The words “Solocris” and “sealed by Treaty” are repeated. Very suspicious.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2110, 14927, 'The data emerges that the Solocris was developed by the Asgard as a means of obviating the need for a “Fifth Race” by instead constructing an artificial “singular entity” of technology. Much of the data is beyond recovery.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2111, 25796, 'Coppelmann''s analysis is mostly about how this may affect the political structures of the Asgard… and how the Praxis will study the data for ties to the current situation.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2112, 14931, 'Uncover the link between the Ancient experiments on humanity and the current inhabitants of Vokos Primar', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2113, 14933, 'The proto-humans this terminal referred to may be the explanation behind the bizarre humanoids here on Vokos. This bears further examination.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2114, 14935, 'The player downloads the proto-human presentation from the terminal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2115, 25795, 'Coppelmann wants to get samples of the proto-humans to make a gene map that could better enhance strength and adaptability. The DNA will also be helpful to the Goa’uld, of course.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2116, 25794, 'Coppelmann notes that the DNA shows a significant amount of genetic drift, resulting in 4 separate species, possibly due to lack of interbreeding for generations. She off-handedly blames the violence and feuding of the proto-humans on “inbreeding” and protests that she cannot see a sample of the Firl “in vivo” --- they look fascinating.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2117, 14944, 'Investigate the Furling terminal''s records on the origins of the Goa''uld', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2118, 14946, 'The display reveals that the Goa’uld were devised by the Furlings as their “Fifth Race.”', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2119, 14948, 'The player downloads the presentation data from the terminal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2120, 14950, 'The whole Praxis leadership hears the data, whom it is a stunning revelation and throws open some of the questions of the links between Ra and the Furling. Ba’al instructs player to meet him afterwards.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2121, 14956, 'Ba''al wants player to stop at nothing to find the Furling and convince them to grant the powers they gave Ra to the rest of the Goa’uld.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2122, 14963, 'Recover this terminal''s data on the Solocris', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2123, 14964, 'This display shows warnings in many languages. The words “Solocris” and “sealed by Treaty” are repeated. This bears looking into.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2124, 14966, 'The data reveals that the Solocris was developed by the Asgard as a means of obviating the need for a “Fifth Race” by instead constructing an artificial “singular entity” of technology.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2125, 14968, 'SG-1 and Thor launch into a discussion/argument about the Solocris, Ra’s ambitions towards it, and the bigger picture. It leaves the impression that this is not the end of it, but the player has to get back to work.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2126, 14976, 'Find out how the inhabitants of Vokos Primar came to be and their link with the Ancients', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2127, 14975, 'The proto-humans this terminal referred to may be the explanation behind the bizarre humanoids here on Vokos. This bears further examination.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2128, 14974, 'Player downloads the proto-human data from the terminal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2129, 14978, 'Jackson is interested in the cultures that have arisen… but he wonders how much is cultural adaptation based upon the relics and how much is a true genetic drift, gives the player an Anthropological DNA sampling kit.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2130, 14980, 'Jackson takes the DNA records and notes that it will take more study, but it seems as though the adaptability of the proto-humans and the violent nature could be more linked in our genome than we first imagined, seeing as the proto-humans have much more of those tendencies', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2131, 14982, 'Research the Furling''s plan to construct a "Fifth Race"', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2132, 14984, 'The presentation reveals that the Goa’uld were devised by the Furlings as their “Fifth Race."', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2133, 14986, 'Player downloads the presentation data from the terminal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2134, 14990, 'O’Neill, Carter, Thor, Jackson, discuss and react to the information which ties together some of the potential links between Ra and Furling technology, and opens up new questions of what the real connection between the Straegis and the Furling are.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2135, 14992, 'Attempt to resettle the humanioids of Vokos Primar before it deactivates', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108038, 'What is the Crystal Key?', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2136, 14994, 'Korbin''s shutoff of the planet''s systems means the people here are living on borrowed time. There are definitely sentient humans living here, even though they may not be pleasant, they don’t deserve to die when this station goes down, maybe you can resettle them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2137, 14996, 'Jackson says there are some worlds that we could look at… though considering how violent they are I’m sure it’d be a lot of work. You have a relationship with their chiefs, why don’t you bring up the subject with them?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2138, 14998, 'Gahroo speaks for the Nix and says there is no way we will leave Vokos. The station going dark is a myth perpetuated by the vile Aesir, who have taken over the Alterr since Slovar’s death. Flee my sight before I crush you for helping that bastard Vraxian.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2139, 15000, 'Vraxian''s e-mail is brief: I am the new power on Vokos, do not attempt to interfere…', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2140, 15002, 'Jackson says well we’ve sort-of started the process, I guess. Frankly I’m not sure we’re going to be able to spare the resources… you certainly can’t worry about it any more. Sorry if that seems harsh but I’ve made bigger sacrifices in my time...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2141, 96105, 'This guard was killed with a single shot at point-blank range, execution style. His pistol is missing from his holster.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2144, 106224, 'I have excellent news. The procedure is working according to projections. Eventually, the executives will return safely to their duties. The side effects will be minor.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2144, 106225, 'Side effects?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2144, 106226, 'There is a tendency for the Goa''uld personality and memories to linger beyond the physical implantation. We hold hope that this will fade over time. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2150, 108333, 'Find Tollan weapon technology to use against the Straegis threat.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2151, 108369, 'Our relationship with the New Mind has already paid dividends: Apparently Tollana is back on the grid. You are going there to hunt for anything you can find to help us prepare for the Straegis. ', 959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2151, 108370, 'Wasn''t Tollana annhilated by Anubis?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2151, 108371, 'Apparently he just ransacked the place before disappearing. A minor System Lord named Svarog swooped in and filled the void, rebuilding the world enough to open up a Goa''uld resort amidst the "shambles of the Tollan society". That''s actually how he markets it. Baal has been there.', 959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2151, 108372, 'Tollana as a Club Med for Goa''uld?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2151, 108373, 'Part of it. The other part is a fractured mess. Your job is to pick through that mess and find technology. Report to Captain Copplemann for more details when you reach the world.', 959, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2152, 49145, 'Go to Tollana', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2153, 89683, 'Welcome to what''s left of Tollana. It seems we''ve arrived a little late in the game. Scavengers from around the galaxy have picked the place clean.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2153, 89684, 'Is there anything left?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2153, 89685, 'Doubtful. Given the state of things we''re probably reduced to trolling for schematics and spare parts. Still, it''s worth a try.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2153, 89686, 'We looking for anything in particular?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2153, 89687, 'Ion Cannons and phase technology are the priorities. Tollana was incredibly advanced before Anubis pounded it, so it''s likely we can find something somewhere... We''ve got word that the Repair Facility might be useful. Start there. ', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2154, 89693, 'You find this in a food duplication unit? ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2154, 89694, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2154, 89695, 'It''s the core matter duplicator. Pretty common household tech. We''ve already got people on Harset reverse engineering these to see if we can duplicate other things besides Tollan food squares... This unit is in better shape than most. Nice work.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2155, 17239, 'Look for technology in the destroyed building to the south', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2156, 89689, 'The technology sensors have been picking up erratic signals from some buildings to the South. My guess is that whatever technology is there is partially damaged. Recon the area - maybe something useful has been overlooked.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2157, 45910, 'I''ve isolated the reading to a destroyed building - check it out.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2158, 100957, 'Ah, a familiar face! And just in time... I''m in a bit of a bind and could use some help...', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2158, 100958, 'You''re always in a bit of a bind.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2158, 100959, 'Such attitude - especially since I saved you from Ambernol sickness in the Castle. I see freedom hasn''t softened your mercenary soul, human. Not one bit.', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2158, 100960, 'I''m not a mercenary.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2158, 100961, 'Oh, I forgot. You Op-CORE humans do everything for God and country. So let''s cut to the chase: I found something here your people have been searching for. Clear out the Jaffa who are after me and it''s yours. ', 496, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2159, 100987, 'That''s twice you''ve proven useful. What are you called?', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2159, 100988, '<<Playername>>', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2159, 100989, 'Well, <<Playername>>, I am Lethander - and here is my end of the bargain. I''m quite confident God and country will both be pleased.', 496, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2160, 101011, 'You got this from a Goa''uld?', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2160, 101012, 'I think he is one of the New Mind, named Lethander.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2160, 101013, 'Lethander? I didn''t know he was down here rooting around... Anyway, you hit the jackpot with this data disc... These are schematics for an Ion Cannon. The file is corrupted so it''s only a partial, but it''s a promising start...', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2160, 101014, 'He said we''d find them valuable.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2160, 101015, 'He''s not supposed to know what we''re looking for... You be careful with Lethander. Never, ever fully trust a Goa''uld - especially if he''s an ally.', 469, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2161, 17241, 'Look for technology in the destroyed building to the southeast', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2162, 101339, 'So far we haven''t had much success beyond your Ion Cannon data card. Sgt. Ogilvie reported that there may be a concentration of Tollan survivors in a clutch of destroyed buildings. Tollan survivors means Tollan know-how, so recon the area and see if the rumors are true. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2163, 101383, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101340, 'It has been a long time since I have set eyes upon an earth human... I can see from the look on your face that the past is not forgotten. I misread your people. I thought you knew forgiveness.', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101341, 'Forgiving people who threaten to betray earth isn''t really my style.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101342, 'What would you have done in my place? Sacrifice your world for mine? I did what any leader would do - I protected my people. Given Anubis'' intentions, I had little choice. Certainly you didn''t return to Tollana seeking revenge?', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101343, 'That remains to be seen.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101344, 'Thinly veiled threats. I assume that my survival hinges on providing you with technological riches...', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101345, 'We can start there. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101346, 'Predictable. However, if you wish to kill me you will need to get in line. I have received word that a Lucian swindler named Mareck is on his way here with dark intentions... I cannot defend myself against him.', 1102, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2164, 101347, 'You''d better make this worth it, High Chancellor.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2165, 101384, 'As promised, here is my end of the bargain. That is a fully functional Control Device - capable of separating a Goa''uld symbiote from its host. Very few of these remain intact on Tollana.', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2165, 101385, 'How does it work?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2165, 101386, 'That information will remain with me... I need another favor first.', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2166, 17448, 'Rescue my daughter from the Internment Camp in exchange for the information you need', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2167, 101405, 'Hand over the instructions for the Control Device, High Chancellor. You''re in no position to negotiate. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2167, 101406, 'This isn''t a negotiation, <<Playername>>. My daughter''s family was kidnapped by Svarog''s Jaffa thugs in broad daylight and taken to an internment camp. I''ve got nothing else left on this world that matters to me... I''ve got nothing to lose.', 1102, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2167, 101407, 'So you want me to rescue them?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2167, 101408, 'Bring them back and I''ll show you how to use the Control Technology. Her name is Sagrine, her husband is Orlak and their son is called Mylon.', 1102, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2168, 101395, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2169, 101420, 'Are you Sagrine? Are you Travell''s daughter?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2169, 101421, 'Yes... What do you want with me?', 1103, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2169, 101422, 'I''m here to rescue you. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2170, 101456, 'You have held up your end of the bargain... My daughter has been through an ordeal, but she is alive and I am grateful. I owe you much. ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2170, 101457, 'You just owe me your end.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2170, 101458, 'Tollan technology is very dangerous in the hands of outsiders. There is much that a race at your primitive evolutionary stage cannot yet comprehend... I don''t think it would be wise for me to...', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2170, 101459, 'Stop talking, High Chancellor. Stop talking and think before you say one more word.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2171, 101478, 'This Control Technology may turn out to be very useful, <<Playername>>. Nice work.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2171, 101479, 'Thank you, Ma''am. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2171, 101480, 'You certainly have a knack for securing the hearts and minds of these Tollans. Keep it up.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2172, 101609, 'There''s a Black Market nearby that''s selling scavenged technology - including weapons. Check it for Ion Cannon data.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2173, 101611, 'We''ve got a lead on something promising - a Black Market. Check it out and see what you can find. An Ion Cannon is out there somewhere - I can feel it.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2174, 45913, 'They specialize in selling scavenged Tollan technology - maybe we a bead on our Ion Cannon there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2175, 101644, 'Greetings traveler. You have come to the right place. There is nothing - nothing - that can be found on this world that I don''t have.', 492, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2175, 101645, 'Ion Cannons.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2175, 101646, 'Except for those. The Tollan Ion Cannons were destroyed in Anubis'' attack. However it is possible to manually assemble them. ', 492, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2175, 101647, 'And you can do this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2175, 101648, 'Sure. It''s pretty easy really. But, you should know that Ion Cannons require specially designed Ion Cores. Very expensive pieces of hardware, Ion Cores.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2175, 101649, 'And if I buy them from you, you''ll build the Cannon...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2175, 101650, 'Sure! Except, I don''t have Ion Cores... However, you may be able to find one at one of the old Ion Cannon sites nearby. And if you did happen to find one... And bring it back to me... We''d have something to talk about.', 492, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2176, 101659, 'I''ve never actually seen one of these things up close before. My client will be pleased. ', 492, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2176, 101660, 'Your client?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2176, 101661, 'You didn''t think that was for your Ion Cannon, did you? I needed this core to fill another order. But worry not, your Cannon gets built with the very next Ion Core that comes through my door...', 492, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2176, 101662, 'Perhaps I did not make myself clear.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2177, 101688, 'Go for Copplemann.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2177, 101689, 'Good news, I''ve got an Ion Cannon under construction. Downloading details.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2177, 101690, 'Outstanding work, <<Playername>>. The Colonel will be pleased... ', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2177, 101691, 'I don''t fully trust the contact... He''s slippery.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2177, 101692, 'We''ll just have to hope then... I''m sending Lyons down there to negotiate payment. ', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2177, 101693, 'The contact responds well to coercion.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2177, 101694, 'I''ll let Lyons know... Copplemann out.', 1100, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2178, 104889, 'Rescue Harta''s assistant from the internment camp. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2179, 104890, 'They took Lyala to Svarog''s resort? Why?', 1105, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2179, 104891, 'That''s not something you want to dwell on. I did manage to recover her notebook. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2179, 104892, 'Her notebook is worthless by itself... It''s Tollan computer code... You''d need to access the Tollan networks to translate that stuff... Is she dead?', 1105, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2179, 104893, 'I doesn''t look good, but... Don''t Assume the worst. If I find her, I''ll bring her back.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2180, 66009, 'Unfortunately my Assistant has all the details on this technology cache so we''re going to have to rescue her from the Internment Camp', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2181, 104899, 'I couldn''t help but notice how you made Machra shake in his boots. I''m in need of someone with that basic skill. I was wondering if you could help me.', 1105, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2181, 104900, 'I''m not for sale.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2181, 104901, 'How about for a trade? My assisstant, Lyala, and I were here on business. We''d found a lead on something - let''s just say it was so powerful the Tollans feared it. She was investigating when she was taken by Svarog''s Jaffa... I have no idea where...', 1105, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2181, 104902, 'There''s an internment camp nearby. Why not go there yourself?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2181, 104903, 'For me it would be suicide. But for you... Please, <<Playername>>, bring her back to me and I''ll give you all of our research. I swear to you, this will be worth it...', 1105, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2182, 29788, 'Head to the Tollan Data Center and decrypt the notebook files.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2183, 89758, 'Captain Copplemann, I''ve found something interesting... Uploading file...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2183, 89759, 'This is Tollan byte code, right? The handwriting is sloppy but hold on a second... I can''t decipher it. It''s encrypted.', 1100, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2183, 89760, 'Apparently it''s hiding a big secret.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2201, 45992, 'In a sense. He''s been hiding from me because he stole from me and, as a result, I wish him dead. He has crawled out from under a rock...', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2183, 89761, 'It''s worth a look. I''ve uploaded the location of a Tollan network hub to your PDA. The hub may or may not be active. Head there and see if you can access their systems. If you can get the material decrypted, bring it here to me. Copplemann out...', 1100, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2184, 45917, 'NON USED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2185, 45923, 'NOT USED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2186, 107802, 'This data is interesting... Apparently Anubis was a closet hacker. There was some artifact called "The Book of the Gates" which he was trying use the Tollan to decipher.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2186, 107803, 'The Book of the Gates?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2186, 107804, 'Yeah... That name is right out of the Goa''uld handbook, isn''t it? It doesn''t look like the algorithm succeeded... It almost looks like it was... Wow. The Tollans hacked his algorithm... ', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2186, 107805, 'I bet he loved that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2186, 107806, 'I''m sure he responded by slaughtering a village... Still, it means at least some of them put up a fight.', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2187, 39061, 'Make nice with Baal. We need these people. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2188, 30394, 'Report the discovery of the Book of the Gates to Colonel Marsh.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2189, 89775, 'We need to get this information to Colonel Marsh, on the double. Whatever the Book of the Gates is, Anubis wanted it and that means something.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2190, 89806, 'Interesting. If Anubis was using the computers on Tollana to try and decrypt it, whatever this Book of the Gates is, it must hold one heck of a secret. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2190, 89807, 'Captain Copplemann said the Tollans blocked him from deciphering it...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2190, 89808, 'It follows that this Book is probably on Tollana somewhere... Speak with Nerus, the New Mind scientist. Butter him up - he''s a notorious glutton - and try and get more information on what this Book of the Gates is... Stay subtle, the Goa''uld are wiley. If he figures it out that we''re keeping secrets, it might prove embarassing for us.', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2191, 89809, 'Let me ask you something, <<Playername>>. Do I look like I have time to simply stop what I am doing and have a natty little chat? I''m incredibly busy. If you want my expertise either submit a request or make it worth my while.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2191, 89810, 'What do you want, Nerus?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2191, 89811, 'Well, since you asked... I have specific dietary requirements. They are quite simple: I need food. In quantity. However, Harset has a food shortage problem. I cannot survive a food shortage problem.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2191, 89812, 'You want me to bring you food?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2191, 89813, 'I want you to arrange continued and uninterrupted sustenance. Do that and you can ask me anything you like...', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2192, 39062, 'We''ve got to keep Baal and his New Mind Goa''uld compatriots happy. I don''t trust them, but in this case it''s a matter of keeping your enemies close. Go put your face in front of him and make nice.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2193, 120026, 'You want me to give you an extra ration card for Nerus? Why? There''s barely enough food in this city for our own people...', 958, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2194, 45988, 'DO NOT USE< CUT DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2195, 89814, 'An extra rations card? Your efficiency is impressive... And because you have pleased me, I will grant you audience. See how magnanamous I am?', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2195, 89815, 'I want information about the Book of the Gates. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2195, 89816, 'Why?', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2195, 89817, 'That''s not your concern.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2195, 89818, 'Fair enough. The Book of the Gates is a map... A map which, when followed, can lead to great power. Do you have it?', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2195, 89819, 'No.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108048, 'Moh''katan, <<Playername>> can confirm what I am telling you: We don''t have any secrets. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108049, 'Do not insult me with this charade, Colonel! I will not have you coax lies from your minion when I already know the truth... Our Praxis alliance is in serious jeopardy. Unless we resolve to remove the deception and deceit that infects us, it may not last the day.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108050, 'Secrets will undermine all of us...', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108051, 'You say this without irony, Baal, but you have a secret of your own...', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108052, 'Baal has a secret? How very predictable...', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108053, 'Baal has recovered Ra''s Crystal Key. ', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108054, 'You found the Crystal Key? And you hid this from me? Outrageous!', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108055, 'As if you would have shared such a discovery?', 942, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108056, 'What''s the Crystal Key?', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108057, 'Ra''s technological secrets were closely guarded. He hid his more advanced technology at a secret location - Ihpet - a gate address long sought after. The key is believed to unlock his vault there. It has been coveted by Goa''uld for eons.', 945, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108058, 'And the Book of the Gates?', 941, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108059, 'You found the Book of the Gates?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108060, 'No, but we found evidence it may be on Tollana.', 941, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108061, 'The Book is the map to Ihpet. The Loyalist Jaffa will not stand for it again. If a similar deception is discovered in the future, the Praxis will dissolve, and blood will flow. I pledge my loyalty to this alliance, but only with that understanding...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108062, 'We all should pledge the same... No more deception. On my honor, I am first to agree.', 941, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108063, 'As do I.', 942, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108064, 'I don''t know why I must declare loyalty when I wasn''t even involved in de--', 944, 16);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108065, 'Declare your loyalty, Queen Anat, or leave the city.', 945, 17);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108066, 'Obviously I will be loyal... But you watch your tone with me, Jaffa. Your insolence will not be forgotten.', 944, 18);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2196, 108067, 'Nor will yours.', 945, 19);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2197, 39069, 'So you have been sent here by Colonel Marsh. You humans are so nakedly political. If you wish to please me, you can fetch me something to eat.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2197, 39070, 'Player: You want me to get you food?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2197, 39071, 'Yes. I''m simply ravenous. Besides, this conversation isn''t going anywhere. So, be useful and fetch me something delicious.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2198, 39072, 'That... Whatever it is... Looks delicious. But I ate when you left. Give whatever that is to Nerus. He''ll eat anything.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2199, 39073, 'What do you have there... That looks simply delightful... First we smell the food... Magical... Then, we eat!', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2200, 29823, 'Find your way into Svarog''s Goa''uld resort on Tollana.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2201, 45990, 'I received some very interesting news this morning from, of all places, Svarog''s pathetic resort community of Tollana. It seems an old protege of mine, Asmodai, has made an appearance. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2201, 45991, 'You''ve lost contact with him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2201, 45993, 'And you wish me to take care of this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2201, 45994, 'You are of a low enough profile to get close to him. Dispatch to Tollana with haste and make contact with Lethander - our New Mind operative there. He will lead you to your target. Eliminate Asmodai in a way that avoids suspicion. I do not need my revenge made public. ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2202, 45989, 'I want you to find out information about a young Goa''uld who is aiming to become the next Ra. Who is helping him and how does he plan to accomplish said task. And then kill him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2203, 45995, 'Your timing is excellent, <<Playername>>. Svarog is simply obsessed with security - which makes sense given the rather broken state of this world. His other obsession is Naquada, which makes entry into his Resort prohibitively expensive...', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2203, 45996, 'Why don''t we sneak in?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2203, 45997, 'We do. Several of our operatives are already inside and active. The problem is that the Jaffa contacts who make this possible have decided to renege on their deal - in fact, they are now threatening to expose our entire network...', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2203, 45998, 'Unless we pay them...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2203, 45999, 'Which we will not do. Instead, we will kill them. Well, specifically, you will kill them. They are on their way now. Intercept them and do the deed, then take what you need from their corpses to gain entry to the resort. If you fail I will disavow knowledge of the assault... It''s a win-win scenario.', 496, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2204, 30011, 'Find Lord Asmodai''s Attendant', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2205, 30128, 'Hello and welcome to Tollana. My, aren''t you particularly fetching? My name is Bryn and I''m the activities Lo''taur here in the resort. Can I be of assistance?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2205, 30129, 'I''m looking for Asmodai.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2205, 30130, 'Lord Asmodai? I believe he went on Safari.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2205, 30131, 'Safaris?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2205, 30132, 'Absolutely, Safaris into the Tollan wastelands are of the great attractions here at Svarog''s. It''s great fun, but it can be a little dangerous... Oh, I see Lord Asmodai''s Lo''taur over there - he could probably give you more details on his excursion.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2206, 56331, 'He has recently departed to join Lord Asmodai on a hunting trip into the Tollan district.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2207, 41892, 'My Lord is on Safari with Lord Gaap. That was all I was told. ', 995, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2207, 41893, 'I guess I just missed him...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2207, 41894, 'Are you Lord Beleth? They were hoping you would join them.', 995, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2207, 41895, 'Yes, I am Beleth...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2207, 41896, 'My Lord told me to tell you to meet him at the appointed place - you know how secretive Lord Asmodai can be. Also, he told me to remind you to bring a personal shield. Hunting the Tollan can be dangerous...', 995, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2207, 41897, 'I will do that. Do you have his shield pulse modulation code? I''d hate to go out there with a duplicate...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2207, 41898, 'Of course... We wouldn''t to accidentally deativate My Lord''s shield at the wrong time!', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2208, 89820, 'You New Mind guys keep popping up out of the ether. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2208, 89821, 'I need your assistance. I have left a large cache of food near the repair facility. I need the Tollans to be made aware of it. Additionally, they need to be made aware of this code...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2208, 89822, 'That''s a Goa''uld personal shield code. You''re giving one of your own to the Tollan?', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2208, 89823, 'It serves my needs, and - most importantly - the needs of Baal. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2208, 89824, 'I''ll get word to their people - food at the Repair Facility.', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2209, 39079, 'I should go speak with Anat', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2210, 29954, 'Find Asmodai at his bungalow.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2211, 30151, 'Oh, hello you! What can I do for you?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2211, 30152, 'Has Lord Asmodai returned yet?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2211, 30153, 'You know, he has! I think I saw him at his bungalow...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46011, 'Lord Asmodai? I am <<Playername>>. I''ve heard you appreciate a good hunt.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46012, 'Who told you this?', 997, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46013, 'Sources. You have friends at the resort. My reason for bothering you with this is simple: I have a lead on some information that you may find valuable.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46014, 'I''m listening.', 997, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46015, 'I have been tipped off about a location where the Tollan may congregate in their search for food. At first they will be there in large numbers.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46016, 'A new hunting ground... And you wish me to pay you for this information?', 997, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46017, 'I came to you first because I heard you were serious. The fee is standard, but this lead is most assuredly not.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2212, 46018, 'Take me there. If it is what you say, I will give you double.', 997, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2213, 46023, 'Well played, <<Playername>>. Baal will be delighted. This settled a long-held score... I hope Asmodai died poorly.', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2213, 46024, 'It certainly was violent. I found a Data Crystal on his body...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2213, 46025, 'Yes... It''s filled with interesting tidbits... Apparently Asmodai was here on business. Devious business.', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2214, 30196, 'Find Gaap''s room in the resport and make contact.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2215, 119983, 'I know of Gaap. He is a model fool. He is also a patron of the Gladiatorial Games, very high profile at the resort. Asmodai''s data crystal implies that they were trying to find Beleth for some reason...', 496, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2215, 119984, 'I had heard that... Who is he?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2215, 119985, 'Beleth is an interesting character indeed... Brilliant mind, always looking for a way to use his technological accumen to become a System Lord... Not one to be trifled with. Asmodai and Gaap seem to think he is here on Tollana... This could yield something... Find Gaap and see what he is up to.', 496, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2216, 28771, 'He is out consoling Lord Gaap, who, as I understand, recently suffered a loss at the gladitorial games.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2217, 89837, 'The plot thickens... Clearly we can use this to our advantage...', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2217, 89838, 'I should pretend to be Gaap, yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2217, 89839, 'Of course - it''s delightfully wicked. We''ll need to eliminate him first, subtly. This will be easy enough to do. First, we''ll need to create an influx of gladiatorial "talent" into the internment camp...', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2217, 89840, 'How do we do that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2217, 89841, 'With this. It was provided by Svarog''s minions - it''s a tracking device. Find some Tollans and mark them with it and they can be tracked anywhere. Svarog''s Jaffa will find them and handle the transport. The best part is, they''ll pay us for the service...', 1101, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2217, 89842, 'What about the actual elimination?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2217, 89843, 'Once we get Gaap to the internment camp he''s vulnerable. We''ll just need a professional to finish the job there. See Captain Copplemann about that. She has those types in abundance.', 496, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2218, 89844, 'Lethander messaged me the details. I''m in the process of getting an operative in place. Use this to chemically tag the target once you enter the area... My agent will eliminate him quickly. Your job now is to find the target in the Goa''uld resort and get him to the Internment Camp.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2219, 30215, 'Make your way to the Internment Camp to find Gaap.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2220, 30216, 'I''m sorry, My Lord. Lord Gaap is not here. He has ventured down to the Internment Camp to examine an influx of potential new Gladiators. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2220, 30217, 'Oh. That''s convenient.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2221, 15575, 'He can be found at the Internment Camp looking over the newest prisoners for talent.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2222, 119976, 'Well played. Now all that is left is to get close to Beleth and find out what he''s all about...', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2223, 30251, 'Go to the Black Market and see Machra about buying a Tollan relic.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2224, 120004, 'Gaap and Asmodai had more time than we do... They seemed to be waiting for Beleth to finish whatever it was he was working on. We need to get to him right away...', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2224, 120005, 'How do we draw him out?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2224, 120006, 'We go to him. Seek out his attendant in the Goa''uld resort and imply that you are Gaap. Set up a meeting.', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2225, 66300, 'You wish to see Lord Beleth? Who calls?', 994, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2225, 66301, 'I am Lord Gaap...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2225, 66302, 'Lord Beleth has received your missives, Lord Gaap, but he is uninterested in diverting himself from his current research. He asks that you be patient.', 994, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2225, 66303, 'What would make him interested?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2225, 66304, 'Lord Beleth has an obession for Tollan technology... Something suitably impressive may convince him to see you sooner.', 994, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2226, 57463, 'You are looking for something truly dazzling, are you? Something one of a kind? Something... Amazing?', 470, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2226, 57464, 'Enough. Do you know of such a thing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2226, 57465, 'There is a Tollan relic I know of... Very interesting... Archeologists from all around covet it.', 470, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2226, 57466, 'I''ll take it.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2226, 57467, 'I don''t have it. However, I know who does. A scurrilous thief named Pogue stole it from my storefront here. If you were to recover the relic and bring it to me, I''d make it worth your while.', 470, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2226, 57468, 'I''ll keep that in mind.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2227, 57477, 'This Relic looks interesting - although I know little of such things. I will call my master and see if he will grant you audience... You are?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2227, 57478, 'Gaap.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2228, 30302, 'Visit Beleth in his sanctuary in the Tollan district.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2229, 30303, 'My master is willing to evaluate the Relic for you, Lord Gaap. He said to tell you that your "relentless persistence has finally paid off..." But you will have to bring the relic to him at his sanctuary in the Tollan district.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2230, 28816, 'But you must come alone to his special research facility hidden in the Tollan district.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2231, 30304, 'This is an interesting piece, but you didn''t come to me for this... You have been relentless, Gaap, too relentless to ask for an evaluation of a simple religious sculpture. ', 1006, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2231, 30305, 'What are you up to here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2231, 30306, 'Research. ', 994, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2231, 30307, 'That crystal there - that is not Tollan technology... You''re using their computers to run calculations on it...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2231, 30308, 'This crystal is none of your business...', 1006, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2232, 30322, 'Get this crystal to Nerus.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2233, 46052, 'A long time ago I saw a heiroglyph that looked like this... It was of Ra''s Crystal Key. ', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2233, 46053, 'Is this the key?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2233, 46054, 'Perhaps... Doubtful but... We''ll find out... Take this to Nerus on Harset for analysis. He''s a bit of a glutton, so do what you can to get him moving. This is important.', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2234, 46055, 'Cut Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2235, 49229, 'Do you have any idea how many requests I get each day? It''s relentless... I''m overworked, I tell you. And I''m starving... In fact... If you want me to look at that-that-that thing... ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2235, 49230, 'You want me to bring you food?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2235, 49231, 'Food is the minimum requirement my dear child... Let me just say this: Give me a reason to put your analysis at the top of my list - give me a reason to care - and I will.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2236, 58970, 'Aren''t you DELICIOUS? You, dear child, have moved to the front of the line. Give me Beleth''s toy.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2236, 58971, 'Lethander thinks this may be something called the Crystal Key...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2236, 58972, 'That is a flight of fancy...
 (Nerus looks closer and then takes a breath) ', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2236, 58973, 'Oh, child, what have you done? It is the key - Ra''s Crystal Key. There was a theory amongst our people that Ra held the secrets to his technological power in a great vault. Anubis was after these secrets when he disappeared...', 943, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2236, 58974, 'And this is the key to that vault?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2236, 58975, 'I think it may well be. This is MASSIVE! Ra lasted as a System Lord as long as he did - not because he was especially organized or efficient - but because he was technologically light years ahead of the rest of us. To unearth his technology - and to possibly unlock it - would mean a return to galactic dominance. Inform Baal of this discovery, now. Make haste.', 943, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2237, 59130, 'You want an extra ration card? Those are incredibly rare... I can''t just "give" one away for nothing...', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2237, 59131, 'Of course you can...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2238, 46087, 'NOT USED', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108030, 'Welcome, <<Playername>>. Moh''katan is under the false perception that you and I are keeping secrets from the rest of our Alliance. I have assured her that you could clear up the matter.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108031, 'Do not insult me with this charade, Lord Baal... I will not have you coax lies from your minion when I already know the truth. Our Praxis alliance is in serious jeopardy. Unless we resolve to remove the deception and deceit that infects us, it may not last the day.', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108032, 'Personally, I''ve always had concerns about the Goa''uld... It is in their nature to deceive.', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108033, 'Deception is a Goa''uld trait, Colonel? Your Op-CORE has recently discovered that the Book of the Gates - the long lost map leading to Ra''s Ihpet vault - may well be on Tollana. Yet you kept this information to yourselves...', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108034, 'That is outrageous!', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108035, 'Indeed, Queen Anat. Nearly as outrageous as Baal and your New Mind hiding the discovery of Ra''s Crystal Key. ', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108036, 'You found the Crystal Key and kept it from me? How dare you!', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108037, 'I dared.', 942, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108039, 'Ra''s technological secrets were closely guarded. He hid his more advanced technology at a secret location - a gate address long been sought after. The key is believed to unlock his vault there. ', 945, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108040, 'And the Book of the Gates is the map to that world?', 941, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108041, 'Indeed. And yet these petty deceptions nearly cost the Praxis a golden opportunity. The Loyalist Jaffa will not stand for it again. If a similar deception is discovered in the future, the Praxis will dissolve, and blood will flow. I pledge my loyalty to this alliance, but only with that understanding...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108042, 'We all should pledge the same... No more deception. On my honor, I am first to agree.', 941, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108043, 'As do I.', 942, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108044, 'I don''t know why I must declare loyalty when I wasn''t even involved in dec--', 944, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108045, 'Declare your loyalty, Queen Anat, or leave the city. ', 945, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108046, 'Obviously I will be loyal... But you watch your tone with me, Jaffa. Your insolence will not be forgotten.', 944, 16);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2239, 108047, 'Nor will yours.', 945, 17);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2240, 89612, 'Go see Travell on Tollana regarding the Book of the Gates.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2241, 108083, 'Since we''re all in this together now, we should focus our attention on recovering that Book. Anubis was trying to decrypt it, but the information we have is that the Tollans blocked him.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2241, 108084, 'You believe they have it?', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2241, 108085, 'It''s worth looking into. <<Playername>>, make contact with High Chancellor Travell on Tollana. If the Tollans managed to get the book, she would be the one to know... Captain Copplemann will be available on-world to assist if needed...', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2241, 108086, 'As will Lethander. All in our new-found spirit of togetherness.', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2241, 108087, 'You mock our alliance, Baal?', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2241, 108088, 'Never. I believe that you have made it remarkably clear that there is nothing to mock here. ', 942, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2241, 108089, 'Indeed. I would hate to see this fracture. I have grown fond of all of you.', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2242, 46088, 'DELETED NOT USED', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2243, 89607, 'Anubis was obsessed with this "book" of yours. During the pacification of Tollana he sequestered our best scientists and literally worked them to death trying to solve Ra''s encryption technology. Eventually the traitor Narim stole it.', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2243, 89608, 'So Narim has the Book?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2243, 89609, 'In theory... You can ask him yourself - if you can find him. He hides like a coward. There is an intermediary named Andor who may lead you there. Or he may try and kill you. Andor is often recruiting "rebels" in the patriotic fight against Svarog.', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2243, 89610, 'You don''t approve?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2243, 89611, 'Throwing healthy bodies into an endless meat grinder is not my idea of patriotism. ', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2244, 89621, 'I know Narim... But I don''t know you. Who sent you?', 1026, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2244, 89622, 'Travell.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2244, 89623, 'Not a welcome name around here.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2245, 39080, 'The New Mind Queen, Anat, is someone the Colonel probably wants me to meet. I''ll go say hi. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2246, 31219, 'Meet Narim''s Security Chief at the appointed location.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2247, 31269, 'I do not know where Narim is. However, I can arrange a meeting with Einar - his security chief. Einar is the only person on this world with the knowledge of Narim''s whereabouts. I''ve beamed the coordinates for the meeting into your PDA. Make haste. Einar dislikes waiting.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2248, 59222, 'DELETED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2249, 31270, 'You are late. I dislike waiting.', 1039, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2249, 31271, 'I came as quickly as possible.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2249, 31272, 'You can give Travell a message from us, lackey. Tell her that we can decipher the Book without accessing the network. Her pathetic efforts to twart us are in vain.', 1039, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2249, 31273, 'I''m not here as a messenger. I need to see Narim.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2249, 31274, 'You will never set eyes on him. Not while I live.', 1039, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2250, 39685, 'You thought I wanted to grant you audience? I do not believe I requested your presence...', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2250, 39686, 'Player: You didn''t request my presence but...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2250, 39687, 'Tell your Colonel that I do not wish to be addressed by underlings - especially unattractive ones - unless I request it. Now, shoo. Leave my sight.', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2251, 59243, 'I told you it would be difficult to reach Narim. He hides behind his loyal, misguided friends. ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2251, 59244, 'Einar mentioned you have blocked off network access...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2251, 59245, 'Einar is a simpleton...', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2251, 59246, 'Was a simpleton...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2251, 59247, 'You disposed of him? Impressive. They accuse me of much, but it is all an attempt remove me and place themselves in power... ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2252, 39688, 'Think nothing of that interchange. Our queens are notoriously tempermental. It''s residue from their brilliance. You can''t be expected to understand. ', 946, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2253, 89630, 'I did cut off Narim''s access to our computer network. Traitors do not deserve such access... ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2253, 89631, 'If he were accessing the network we could trace it to him...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2253, 89632, 'We cannot give Narim access to the networks - even for a second. He will forment rebellion... And even if you wanted to re-establish his connection, you couldn''t. We destroyed the network hub building.', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2253, 89633, 'Yet the systems still work...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2253, 89634, 'In a limited capacity.', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2254, 89635, 'Use Narim''s connection to the Tollan network to trace his whereabouts.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2255, 89641, 'I''ve had access to the Tollan network for some time now... The Tollan were so naive... Their entire network relies on only a few hubs and vitually no security - mapping it was easy...', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2255, 89642, 'So we can find where she destroyed it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2255, 89643, 'I don''t see anything that looks broken... Wait a second... I have one hub giving different feedback. Running diagnostic... <<Playername>>... Well, if they destroyed it, someone fixed it.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2255, 89644, 'Travell lied to me?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2255, 89645, 'I can''t tell, but i wouldn''t put it past her. I''ve uploaded the hub location to your PDA. Go there and try and figure out what she did.', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2256, 89624, 'Almost the second you re-established the link activity resumed from the refugee camp... Nicely done. We''ll be able to track them easily now.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2257, 31377, 'Trace the source of the Network Connection.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2258, 89649, 'I''ve got a bead on a potential user. He came online right after we opened the system... He - or she - is in some apartments. I''ll upload the coordinates to your PDA. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2700, 18927, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2258, 89651, 'This is the only active node in that part of the city... Whoever it was, they were watching the network vigilantly. So be careful.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2259, 46111, 'REDUNDANT - NOT NEEDED', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2260, 31423, 'What are you doing in our home?', 1041, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2260, 31424, 'You''ve got a computer connected to the network here... Where is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2260, 31425, 'I don''t know what you''re talking about...', 1041, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2260, 31426, 'Show me where the computer is or people in this room start dying.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2260, 31427, 'Over there... Behind that wall... Please don''t hurt us.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2261, 31440, 'I am not Narim. I just work for him...', 1042, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2261, 31441, 'Show me where he is... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2261, 31442, 'I don''t know...', 1042, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2261, 31443, 'You have a nice family in there. You do not want them to get involved in this. Take me to him.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2261, 31444, 'You must promise to never come back to us.', 1042, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2261, 31445, 'Deliver me Narim and you will never see me again.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2262, 89652, 'Follow Reko to Narim''s secret locale.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2263, 89654, 'They will know you are forcing me to bring you to him. They will try and stop us. They won''t care if you''re with me...', 1042, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2263, 89655, 'Sounds like you have some nice friends.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2263, 89656, 'We cannot leave together from here. If they think Tynne is involved, they might hurt her. I''ve uploaded grid coordinates to your PDA. I will meet you there. I promise. ', 1042, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2263, 89657, 'Meet me there or I will be back. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2263, 89658, 'I will be there. ', 1042, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2264, 89660, 'I''ve taken you as far as I can - Narim''s base is just ahead in the subway station.', 2255, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2265, 31496, 'Find Narim and get information on the Book of the Gates.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2266, 55098, 'Clearly, Narim is the only one with any real knowledge about the Book of the Gates. You need to find him and take him - alive if possible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2267, 89872, 'You want the Book? It''s fool''s gold - indecipherable. We''ve spent years trying...', 1043, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2267, 89873, 'Then you won''t mind handing it over.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2267, 89874, 'Never to scum like you. I''ll die first.', 1043, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2267, 89875, 'It''s not just you that I''m thinking about... How many of your people are you willing to have die with you.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2268, 89846, 'You found the Book... Brilliant work...', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2269, 55129, 'Deliver the Book of the Gates to the Leadership on Harset.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2270, 103597, 'Take the book to the Council Chambers on Harset. They''re waiting for it. I''ll go through Narim''s notes and prepare a companion report while you''re in transit. They''ll have it by the time you get there. This is a big day for you, <<Playername>>, well done.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2271, 55124, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103598, 'Brilliantly done, <<Playername>>. This is a major coup for our Praxis alliance.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103599, 'There''s no reason for celebration. Without the Cipher the book is useless...', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103600, 'The Cipher is the Book itself.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103601, 'Ra often used this type of encryption as a means of protecting information. I saw it often as a little girl. It was said that he used a special tool to unlock these devices... ', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103602, 'The Mouth of Ptah. On Men''fa. It is (or, was) a device - inexplicable in operation - that he used to lock and unlock these types of data crystals. The encryption was so secure he made no secret of it.', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103603, 'So we need to take the Book to Men''fa and use the device to crack it open...', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103604, 'Men''fa is long dormant, picked clean by scavengers after Ra''s death. It is unlikely that the Mouth is even operational. ', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103605, 'Can we afford not to be sure?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103606, 'An excellent question. You will take the Book of the Gates to Men''fa and seek out the Mouth of Ptah. Hopefully some of the magic still remains...', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103607, 'And if it doesn''t?', 944, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2272, 103608, 'Then we will cross that bridge if and when we come to it.', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2273, 39689, 'Defeat my champion in combat.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2274, 39696, 'The Colonel sends you to me as an emmissary? He should have sent someone more worthy.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2274, 39697, 'Try me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2274, 39698, 'You want to prove yourself? Fair enough. Take this staff and meet me outside the Command Center. You can prove yourself where it matters most. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2275, 55083, 'Convince Travell to give up the location of the Key Activator.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2276, 41404, 'Impressive. Tra''bloc is well respected amongst my people. You have earned my respect. My respect isn''t given away cheaply, so do not abuse the privilege.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2277, 89557, 'Of course I know where the crystal activator is... I was the one who hid it. But you will never get it. It is hidden within the Curia, right under Svarog''s nose. And even if you get into the chamber, you will never be able to open my vault. It requires phase technology to find and a code to open. ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2277, 89558, 'What if I could promise the removal of Svarog?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2277, 89559, 'Then we would have something to discuss. ', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2278, 46167, 'NO USE DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2279, 89547, 'Svarog is a wily fellow, but he relies on simple solutions. Before he came along, Anubis had protected the Curia with a little piece of technology that doesn''t kill those who enter the signal area, but instead weakens them - making them vulnerable to his Jaffa. Svarog has co-opted the technology. ', 496, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2279, 89548, 'Is there a way past it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2279, 89549, 'You could revise the frequency. That would disable the effects. But you''ll have to be careful - the adjustment would need to be temporary to avoid a Tollana-wide alert.', 496, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2279, 89550, 'If they detect the adjustment?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2279, 89551, 'You will be overwhelmed by Jaffa within minutes... To get inside the main building in one piece, you will need to remain discrete. The shield generator itself requires an access key. ', 496, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2279, 89552, 'Where do I find one?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2279, 89553, 'Svarog''s officers carry them... You''ll need the key to access the Shield Grid, which is where you can modify the generator.', 496, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2280, 89563, 'Access the Shield Protection Grid and modify the shield''s settings. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2281, 89564, 'With the access key in your possession, you will be able to modify the protective shield by accessing the Shield Protection Grid. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2282, 90403, 'Now that the Shield is down, its time to enter the Curia and access Travell''s secret safe.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2498, 39636, 'See Tau''hut in the Storage Area', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2596, 101429, 'Then they will die. Follow me. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2283, 90404, 'The shield powers down and the way into the Curia is wide open. The Crystal Activator - and Svarog - wait inside. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2284, 39120, 'So, we have a problem. One of the psycho Goa''uld is upset and demanding to see Colonel Marsh personally. You''re the liasion, so... You get the grunt work. Her name is Athena - she''s a peach. ', 947, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2285, 39121, 'Marsh sent you? A sign of disrespect i won''t soon forget. One of his pig underlings stole an amulet of mine. I want it returned immediately. His name is Ogilvie and he cannot be trusted...', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2285, 39122, 'Player: Requisitions Sargeant Ogilvie?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2285, 39123, 'That sounds like him. That you use a thief to requisition supplies speaks volumes about your kind... I want my Amulet back or there will be blood...', 949, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2286, 39124, 'I told Ogilvie to quit messing with the Goa''uld but he is a man of appetites. His CO, Hansen should know where he is. Hansen''s usually at the pub.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2287, 39125, 'You''re looking for Ogilvie? I can probably remember where he is, but I''m far too sober. Buy me a pint of my favorite and we can chat. ', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2288, 39126, 'That is absolutely delicious. I sent Ogilvie to Tollana. You can find him there. What did he do?', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2288, 39127, 'Player: Got involved with a Goa''uld woman.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2288, 39128, 'Predictable. Of course, the Goa''uld themselves don''t have a "sex" right? Just their hosts. I wonder if he thought of that... Check that, Ogilvie never thinks when it comes to women.', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2289, 16103, 'She accused me of stealing something? That''s awesome! Here''s what happened: She''s ridiculously hot, right?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2289, 16104, 'Player: She''s very pretty.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2289, 16105, 'Right. So I went there. Big mistake. She starts cooing about me being her servant and suddenly I realize this was a terrible idea. So I let her down easy - I even paid for dinner - and she freaked. Eyes are flashing, screaching in that voice they do... I got scared and transferred to Tollana duty picking through scraps. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2289, 16106, 'Player: So you didn''t steal anything?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2289, 16107, 'Of course not. The only thing I''m guilty of is being an idiot. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2290, 39129, 'Ogilvie... I''m going to have a talk with that boy when he gets back here. For now, tell Athena we''ll process him once he returns to Harset. Fair trial and all of that...', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2290, 39130, 'Player: She won''t like that...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2290, 39131, 'Probably not. And that''s your problem.', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2291, 39132, 'The thieves protect their own, I see... Fair enough. But know this: I will have my revenge on Ogilvie and everyone else involved soon enough... Mark my words, human.', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2292, 39119, 'Go see what Athena is complaining about.', 947, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2293, 39133, 'Placeholder - go to the atmosphere plant and be ambushed', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2294, 39134, 'Ambush. On the way. NID guys. Ouchy.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2295, 39142, 'When they said they were looking for fugitives, I had no idea it was you guys. Op-CORE are all supposed to be dead.', 952, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2295, 39143, 'Player: We''re very much alive.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2295, 39144, 'Well, that explains why the NID are pretty rabid about this. After you guys were "outed" they went on a campaign to smear you. But I didn''t know this particular operation was about Op-CORE. ', 952, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2295, 39145, 'Player: Who were they after?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2295, 39146, 'They were short on details. They said they had a lead that brought them here. That was it. If you let me go, I promise to do some digging and find out more. Honestly, I''m no assassin. ', 952, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2295, 39147, 'Player: Deal. But don''t even think about double crossing us. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2295, 39148, 'Never. I promise!', 952, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2296, 39149, 'An ambush? How''d they know you were going to that rock? Apparently they''re never going to let it rest. Stay frosty, these NID guys are nothing to take lightly.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2297, 18773, 'You take the vial of Ambernol from the counter.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2298, 96174, 'Secure some Ambernol in order to counteract your Stasis Sickness.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2299, 96175, 'You''re a bit brighter than most humans, aren''t you? You don''t have much time. You''ll need to find Ambernol in order to counteract the sickness.', 253, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2299, 96176, 'Where can I get some?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2299, 96177, 'There''s probably a supply down at the end of that hall, in the medical station. The NID use it on all the humans they awaken from stasis.', 253, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2299, 96178, 'Why should I trust you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2299, 96179, 'I''m not the one who''s dying... ', 253, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2300, 96169, 'You feel uncomfotable, don''t you? Nauseous? Flashes of inexplicable pain... It''s not some simple virus, human. You''re in grave danger. Release me from this cell and I''ll make sure you live.', 253, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2300, 96170, 'I''m fine. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2300, 96171, 'Really? That dizziness - that pain - they''re symptoms of stasis sickness. Nasty malady. Your cells begin bursting, like little bubbles. Absolutely irreversible unless treated promptly.', 253, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2300, 96172, 'You can help me?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2300, 96173, 'If you help me first. Get me out of here.', 253, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2301, 51140, 'Please... Make it stop... Please, you gotta help me make it stop! It''s like a thousand knives churning inside me...', 254, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2301, 51141, 'What''s wrong? What did they do to you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2301, 51142, 'I don''t know. They woke me up and left me here. I didn''t tell them anything... I swear to God I didn''t tell them anything... Oh god... MAKE IT STOP! PLEASE! Please... Please...', 254, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2301, 51143, 'Just hold on. I''m going to get help.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2301, 51144, 'WAIT! Please... I wrote this letter to my wife. I don''t think... If I don''t make it, find some way to get it to her. Please?', 254, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2302, 51145, 'He didn''t die very well, did he? Can''t blame him, really. That dizziness you''re feeling? That''s the first symptom of stasis sickness. Nasty malady. Your cells begin bursting, like little bubbles. Absolutely irreversible unless treated promptly.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2302, 51146, 'Of course not. I''m a filthy Goa''uld, remember? We''re a bit heartier than you humans.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2302, 51147, 'I should kill you where you stand.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2302, 51148, 'Then you''ll be dead like your friend there within the hour. And you heard his moans. It''s not a pretty way to go. Oh no, my little human friend, you need me. And I need you. So, let me out.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2303, 51149, 'You hack the cell door controls.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2304, 51157, 'You''re a bit brighter than most humans, aren''t you? Keep listening, and we''ll get along just fine. You''ll need to find Ambernol in order to counteract the sickness.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2304, 51158, 'Where can I get it ?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117996, 'The Portals... That has to be it. Whatever the Straegis substance is... The portals are Ra''s means of summoning them.', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2304, 51159, 'There''s probably some down at the end of that hall, in the medical station. You go that way, and I''ll follow behind. Eventually.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2304, 51160, 'Why should I let you go ?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2304, 51161, 'Because you''re a human and you have an inexplicable decency about you . I''ve helped you survive and you recognize that for what it is. It''s a fair trade.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2304, 51162, 'Why should I trust you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2304, 51163, 'It''s simple, really. I''m not the one who''s dying.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2305, 18795, 'Hack the Ring Transporter controls to leave this floor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2308, 96323, 'Follow Col. Marsh as he leads you out of the Castle.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2309, 96336, 'That''s about all we can do from here. C''mon, let''s move out.', 261, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2309, 96337, 'What about the prisoners we just freed?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2309, 96338, 'They''ll follow later. The NID got sloppy and fell asleep because they thought they were safe on this frozen rock. But not even the NID can miss the tampering we just did. Someone''s going to notice it, and we''d better be out of this cellblock before they do.', 261, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2312, 96322, 'UNUSED DIALOGUE', 261, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2314, 39152, 'Something in Op-CORE''s relationship with the New Mind doesn''t sit right with me. Goa''uld and humans in an alliance is just... Wrong. Take this Tollan control technology to the Colonel, tell him I think we should use it on all of our people. We don''t want spies in our midst. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2315, 39150, 'Take this control technology to Marsh', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2316, 39153, 'Copplemann was always a paranoid. But she''s right. You can start with me. People have their doubts about me - it''s time to put those doubts to rest. Right. Now. Use that technology on me. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2317, 39154, 'Take that device and meet me in the Storage Bay. I''m going to assemble some of the Operatives and we''re going to test them. Specifically you''re going to test them.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2318, 39155, 'I can''t imagine any of us placing a spy inside of your operative. It''s far too banal. ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2318, 39156, 'Player: Someone infected him.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2318, 39157, 'We are not an infection. And how do you know the symbiote wasn''t adminstered at the Castle by the NID. They haven''t been shy about mixing Goa''uld and human physiology in the past.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2318, 39158, 'Player: Can you get me the autopsy report?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2318, 39159, 'I''ll see what I can do...', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2319, 40090, 'Bring me Dawson''s Symbiote and another one from Anat''s tank', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2320, 40091, 'Dawson was infected by the New Mind Goa''uld, I know it, you know it, everyone knows it. But we need proof. Ply Nerus to get Dawson''s symbiote and use these - sleeping gas pellets - to sneak into Anat''s chamber and access her symbiote tank. Bring me one of her children and I''ll do a DNA comparison...', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2321, 39162, 'Player: Meet me in the Marketplace. Bring Dawson''s symbiote. I have a delicious offer for you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2321, 39163, 'How delicious?', 943, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2321, 39164, 'Player: Berry delicious. Fresh Berry delicious.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2321, 39165, 'Fresh fruit? On Harset? I will meet you there.', 943, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2322, 39166, 'Player: How would you like to help solve Dawson''s mystery?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2322, 39167, 'You name it, I''ll do it. He was my friend.', 958, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2322, 39168, 'Player: I need strawberries - fresh strawberries - and cream. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2322, 39169, 'Fresh Strawberries are tough... But I can do that for you... It''s weird, but I can do it.', 958, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2323, 39173, 'Strawberries and cream? That looks delicious. ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2323, 39174, 'Player: Hand over the Symbiote', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2323, 39175, 'Of course... You can trust me. ', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2324, 16275, 'Well done. I can compare these relatively quickly... These creatures are truly amazing. Amazing and disgusting... Results are coming now... I knew it... The DNA matches on both, Dawson was infested by a New Mind Goa''uld. I''ll inform the Colonel. Be careful around them, they can''t be trusted.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2326, 41745, 'There are rumors of a NID Agent named Chavez asking about you and Op CORE over in the Lower Compost Flats. Thought you might like to do something about it...', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2327, 41750, 'My people have alerted me to the presence of a NID Operative named Chavez in the Compost Flats area. Apparrently he''s been asking a lot of questions... about you.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2328, 41744, 'I''m glad I could be of some help... Apparently there are more of his kind on Lucia. These NID have been throwing Naquadah around. They''re well financed and they''re after you...', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2329, 39200, 'See what Anat is complaining about.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2330, 39201, 'I hate to do this but... Better you than me. Go see Anat. She wants me to send someone over. You drew the short straw.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2331, 39202, 'So, Colonel Marsh sends me an ugly one... Oh well, you''ll do... It has come to my attention that there are several Jaffa in Harset who were once loyal to Ra. Round them up and take them to the holding pens. They cannot be trusted. ', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2332, 39204, 'But, my loyalties lie with the New Mind now.', 1082, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2332, 39205, 'Player: Not my problem.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2333, 39203, 'I have done nothing wrong!', 1083, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2334, 39206, 'I am innocent of any crimes!', 1084, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2335, 39208, 'I have received word that several of the Jaffa are in the Marketplace, refusing to be incarcerated. Go there and deal with it. Quickly.', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2336, 39209, 'Player: Mission accomplished.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2336, 39210, 'And? I have no further use for you. Be gone.', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2337, 39215, 'Convince Opheltes to free me', 963, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2338, 39213, 'A friendly face! Listen, I have news for you - but first you have to get me out of here. Opheltes runs this slave trade, so he is the guy to see... Please help me.', 963, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117988, 'Though rare, classification 212 is present in the Fighter Straegis. It appears to govern their communication with the beacons themselves.', 1015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117989, 'All the reports I''ve seen from the field indicate it is only the Fighters that link directly with the beacons... ', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117990, 'Classification 212 may relate to that ability in some way. It may enable such communication.', 1015, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117991, 'Theory: What if the beacons allow them to receive orders and instructions from afar? From Ra?', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117992, 'Like an interstellar radio signal?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117993, 'This is possible. If the Conflict-Oriented Straegis specimens could also transmit their own subspace frequences back through, it would explain why the beacons occasionally show aggression. ', 1015, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117994, 'They''re just a conduit to some other place... ', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2339, 117995, 'This still does not explain where the original source is located.', 1015, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2340, 66427, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2701, 18938, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2341, 117968, 'We''ve observed the Straegis using objects as a form of their support structure.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2341, 117969, 'The Beacons?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2341, 117970, 'Yes. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2341, 117971, 'These beacons appear to be composed of the same sort of subspace frequency-emitting substance as the Straegis themselves. If I could analyze that grouping...', 1015, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2341, 117972, 'You want a beacon?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2341, 117973, 'Whatever core components you can acquire will be most useful...', 1015, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2341, 117974, 'It might give us a clearer picture of what these beacons actually do for the Straegis.', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2342, 117967, 'Explore the connection between the Straegis and the beacons they use.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2343, 117975, 'Strange. The beacon core is identical to the structure of a basic Straegis, but it holds many separate frequencies at once.', 1015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2343, 117976, 'But it''s made out of the same exact thing as the mobile Straegis.', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2343, 117977, 'Correct. However among the frequencies present there is one dominant, repeated group... 212. We must determine if this frequency is found amongst the mobile Straegis...', 1015, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2343, 117978, 'The larger, dominant types appear to have higher order themes than others we have encountered. We need to analyze their shards...', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2344, 39216, 'You wish to purchase the slave? He is valuable. It will cost you a million Naquadah.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2344, 39217, 'Player: What about a trade.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2344, 39218, 'Bring me a comperable specimen and we can discuss it. I need someone healthy... ', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2344, 39219, 'Player: Have any suggestions on where to look?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2344, 39220, 'Try the Lucian Slums. There are a few specimens up there that may be of interest.', 399, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2345, 66196, 'UNUSED DIALOG', 1010, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2346, 113296, 'This reliquary contains the Gas component of those pieces. The scientists thought the gas in the case may just have been a protective filler... But clearly this is not the case... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2346, 113297, 'You have recovered three of the Four Pieces. Surely that is enough to stop Ra''s plan from moving forward. ', 1018, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2346, 113298, 'We don''t know what they do... What if the last one is the only one that really matters?', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2346, 113299, 'We need the fourth piece.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2347, 66201, 'UNUSED DIALOG', 1057, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2348, 117876, 'Edj''dan has another object that Jysic could not take.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2348, 117877, 'Similar to the other one?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2348, 117878, 'Different, but he coveted it with the same reverence.', 1013, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2348, 117879, 'Can you describe it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2348, 117880, 'A Goa''uld reliquary, worn around the neck. It is in the shape of a cylinder... Edj''dan will not surrender it willingly.', 1013, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2348, 117881, 'Do they ever?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2349, 117875, 'Acquire the third of the Four Pieces, held by Edj''dan of the Sons of Khepri
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2350, 117898, 'Can Felger''s device find the last piece?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2350, 117899, '(You activate the device. The signal appears to be coming from the western edge of the crater.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2350, 117900, 'That''s probably the Ruins of Shoul''Mur. That must be where the last of where Ra''s Sons of Khepri are holed up.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2350, 117901, 'Sulbeck.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2350, 117902, 'The Straegis have destroyed many of the emitters already... They will be able to transport Sulbeck out very soon.', 1018, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2350, 117903, 'Work quickly... ', 1008, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2351, 117897, 'Recover the last of the Four Pieces within the Ruins of Shoul''mur
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2352, 117934, 'You access Sulbeck''s communication sphere, hoping to eavesdrop on another of Ra''s orders. Instead, he seems to be waiting for you. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2352, 117935, 'You have defeated my minions... But, before you celebrate know two things: First, my minions are mere Jaffa lackeys. The Straegis - my real army - will flood this Beta Site, and you will soon be consumed.', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2352, 117936, 'Second: No world shall be safe from my reach, not even the beloved home of the Tau''ri. You possess the Four Pieces - a victory for you - but they can be remade. They can be rebuilt. ', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2352, 117937, 'I will not forget your insolence, $name$. That cannot be undone or forgotten. If you survive the coming mutilation of Beta Site, I will still find you. Know that. You have made this... Personal. ', 2547, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2352, 117938, 'With that, the communication sphere grows dim. It appears Ra''s vessel has left transmission range.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2353, 113681, 'The same routine that caused the Burtonol Portal to self-destruct isn''t working... Obviously this portal made out of Straegis materials is tougher stuff. You decide to fall back and see if Dr. Jackson and Heimdall have any ideas.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2354, 39221, 'Thank God you saved me... ', 965, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2354, 39222, 'Player: You''re NID. I''m not saving you. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2354, 39223, 'Listen... We can cut a deal. I have information... There''s a mole in your operation. Let me go and I''ll find you the name.', 965, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2354, 39224, 'Player: You don''t have the name now?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2354, 39225, 'No, but I can get it...', 965, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2354, 39226, 'Player: Let''s take a walk.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2355, 118108, 'As long as Ra has a functioning portal on this world, the Straegis will stream in... Possibly infintely.', 1015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2355, 118109, 'An endless army?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2355, 118110, 'Yes. And one which lacks any sense of self-preservation. Straegis exist, but they show no self-awareness. They are similar to the Replicators in this way. ', 1015, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2355, 118111, 'From our reports, the Straegis first appeared around Camp Shoul''Ja immediately following Ra''s landing. Sounds like where the portal could be located.', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2355, 118112, 'I''ll destroy the portal.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2355, 118113, 'Before you do that, if you can get a scan of a functioning version, we might be able to figure out where the Straegis come from in the first place.', 431, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2356, 16386, 'Train', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2357, 118107, 'Destroy the Straegis Portal on Beta Site', 1015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118334, 'Captain Tigges has shown very few signs that his loyalties are not entirely with the Praxis... This pleases me. ', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118335, 'You are here to monitor him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118336, 'Covertly. He does not know that is my mission.', 1023, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118337, 'I will keep silent.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118338, 'Tigges has turned a blind eye to many of our "requisitions", but he has kept silent about the Omega Site. ', 1023, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118339, 'Omega Site?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118340, 'The base of operations for the SGU.', 1023, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118341, 'Does he know where it is?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118342, 'I am fairly certain he does not. But some of the people on this base, Mimir the Asgard for example... They are closer to the SGU. ', 1023, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118343, 'How can we find it?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2358, 118344, 'Search the computers in the SGC Command Center. There may be data about the Omega Site there. ', 1023, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2359, 118330, 'Search the Beta Site computers for information about the SGU''s base of operations.', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2360, 113872, 'Your thorough search of the Beta Site systems reveals no references to the Omega Site. It''s not as if they''ve been erased, it’s just as though they aren’t there. Perhaps there is something else to try.', 2482, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2361, 113876, 'Our intelligence supports that the Tau''ri have largely been kept in the dark regarding the SGU. But the Asgard might be a different story.', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2361, 113877, 'Is there an Asgard base here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2361, 113878, 'According to Tigges, Mimir kept watch over the site from a ship docked to the south. Check it for information.', 1023, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117491, 'I''ve got something interesting for all of us to think about... I got an emergency comm from Captain Robert Tigges, an old buddy of mine. He needs help.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117492, 'Is he part of Stargate Command?', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117493, 'Yes. Tigges is in charge of what''s left of the Beta Site, one of Earth''s off-world commands. The Straegis have overrun it and that idiot Woolsey - the suit in charge of the SGC - won''t send support troops.', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117494, 'Does he dislike his own people?', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117495, 'He is a typical Tau''ri - he prefers his bureacracy to his neighbors... We''ve used this trait in humans to our advantage for years. ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117496, 'I''d love to argue with you but... Woolsey is a first class tool. Apparently he and the other suits are sealing the world off. Tigges wants extraction for him and his troops.', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117497, 'Of what use are a handful of our soldiers against a Straegis invasion?', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117498, 'The invasion is not yet full scale - Tigges thinks Ra is looking for something. ', 941, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117499, 'Ra must not be allowed to have that world uncontested.', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117500, 'Tigges provided the gate address. He knows the situation. $name$, get your butt down there and be our liasion. Do whatever it takes.', 941, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117501, 'We are sending support to help funnel any salvage back to us... This is not a mission of mercy. We need to take advantage of this opportunity to strengthen ourselves... Right, Colonel?', 942, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117502, 'Let''s just say that we each go there for our own reasons... Mine are a little less mercenary than yours. ', 941, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117503, 'And if this is a trap?', 944, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2362, 117504, 'Then we lose an asset - no offense $name$. And if it isn''t? We''ve got ourselves a fight. ', 941, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2363, 117490, 'Travel to the SGC''s Beta Site under truce and begin relief operations.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118232, 'Col. Marsh comes through again I see.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118233, 'What is the situation?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118234, 'We''re in an overrun scenario. You''re looking at the only territory not crawling with hostiles. It was all I could do to get a message out.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118235, 'There is additional information you should have, $name$...', 1018, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118236, 'Mimir here was in charge of the Asgard contingent on this world. He informs me the SGU has also rallied in defense of the Beta Site. They''re sending people.', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118237, 'They do not concern us.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118238, 'I was hoping that we all could work together...', 1008, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118239, 'The SGU is willing to operate under truce conditions to stop the invasion...', 1018, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118240, 'Make sure they abide by this truce.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2364, 118241, 'You''ve got your own little monitor watching for that right there - Mattila the Jaffa... She''s here to keep me in line. See Dr. Jackson. He needs to know you are here.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2365, 39227, 'Hmm. He will do nicely. You can have the other human in exchange for this one.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2365, 39228, 'Alderson: What is he talking about?', 965, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2365, 39229, 'He has brought you to me and we have traded. You are my property now...', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2365, 39230, 'Alderson: My God, what have you done?', 965, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2365, 39231, 'Player: Paid you back. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2366, 118254, 'Wow, you guys aren''t exactly known for your humanitarian side... Little surprised to see you here. ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2366, 118255, 'Perhaps you underestimate the Praxis. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2366, 118256, 'Perhaps. Heimdall and I came to find a way to slow down the Straegis. Is that part of your deal?', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2366, 118257, 'Yes. They are a priority. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2366, 118258, 'Perhaps you will deign to provide assistance with our research? Without a way to deter them, the Straegis will surely overwhelm this world. Your assistance may prove vital.', 1015, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2366, 118259, 'I will help in any way I can. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2366, 118260, 'Excellent. When we''re ready, your help will be appreciated...', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117949, 'Now that we''ve got things a bit stabilized... It''s time to figure out a way to stop the Straegis.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117950, 'The Straegis operate like no other known lifeform. They lack biology, yet move and act. They also lack the characteristic signs of machine intelligence, which is evidence against them being artificial.', 1015, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117951, 'As it stands now, they''re like a living radio signal... They''re... Well, they''re weird. Really weird.', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117952, 'Each Straegis is constantly sending out highly energized signals into the environment. This is the only distinguishing element between versions which look similar. ', 1015, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117953, 'We want to figure out how they are related... What do the signals mean? That kind of stuff. So we need samples...', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117954, 'Samples... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117955, 'Samples. The leftovers, basically... A terminated Straegis leaves behind highly volatile shards - chunks of Straegis goo that still retains a resonance for a short time. We need that stuff.', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2367, 117956, 'My ordering system divides them into families. The primary groups are labeled 14B, 54, 83, and 332. Your personal sensors will allow you to identify them. We need samples from each grouping...', 1015, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2368, 117966, 'Recover samples of the various Straegis forms for Jackson and Heimdall.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118173, 'From our findings, it seems like these frequencies govern what each Straegis can actually do. It''s similar to how an insect colony works - each member has a basic function given at birth... Except these guys don''t seem to have a life cycle...', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118174, 'Each of the base groupings - 54, 83 and 14B all seem focused around base elements of physical space - life, matter, force. They are almost thematic in their construction.', 1015, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118175, 'There is a certain poetry to this, very similar to the cosmology of primitive cultures.', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118176, 'I would caution against reading too much into this data. These are scientific phenomena, not supernatural constructs.', 1015, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118177, 'What about the fourth sample?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118178, 'That is the most difficult to classify. On the surface, group 332 appears to be merely a higher-order harmonic of the "Life" theme... But there is a difficult to quantify difference, an unpredicted addition.', 1015, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118179, 'It is present in the Straegis who actively fight - as opposed to those who fight only as a reaction to stimulus. Perhaps it has something to do with self-preservation? Warfare? Conflict?', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2369, 118180, 'The data is too limited to answer that... What has been determined is fascinating: The Straegis are an entity that does not have a life or death as we define it... They either exist or do not. ', 1015, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2370, 66323, 'UNUSED DIALOG', 1024, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2371, 66324, 'UNUSED DIALOG', 1024, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2373, 113101, 'The Ruins of Khenmer''Fa... They weren''t attacked in the initial wave. I believe Ras''nor took some of the Nine Peaks Jaffa there for shelter.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2373, 113102, 'Have we been able to reach him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2373, 113103, 'Not yet. I briefly picked up a signal from the comm we gave him, but it''s gone dead again. My intel says that after we scrambled the teleports some of Ra''s forces fell back to the Ruins.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2373, 113104, 'Then they may have an artifact with them.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2373, 113105, 'I''ll give you the coordinates for Ras''nor''s last contact. I''m sure he''d be happy to see you.', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2373, 113106, 'Assuming he lives.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2374, 117825, 'A taste of joy on such a bitter day. I am pleased to see you.', 1013, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2374, 117826, 'What''s happening here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2374, 117827, 'I am trying to save Jysic. He has stolen something from Ra''s pigs and now they comb the Ruins in search. I have been delaying them as best I can.', 1013, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2374, 117828, 'Stole something?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2374, 117829, 'Edj''dan of the Sons of Khepri came here not too long ago, with a rod of light in his hand. As they set their defenses, Jysic took the rod.', 1013, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2374, 117830, 'Certainly brave, but why?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2374, 117831, 'We figured that anything Ra desired so badly could not be good. Jysic hides in the Ruins now, on the run. He knows the area, but it is only a matter of time. Please, bring him back to me.', 1013, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2375, 117864, 'Yours was a face I did not anticipate. ', 1011, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2375, 117865, 'I am here to get you out.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2375, 117866, 'Then let us be off. Many foes will die today.', 1011, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2376, 117855, 'My father and I are safe. Mere minutes ago I did not think it possible.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2376, 117856, 'Jysic, Tigges and $name$ are gathering the artifacts Ra is trying to find. You must give them the rod you stole.', 1013, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2376, 117857, 'Gladly. But so you seek all of the artifacts?', 1011, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2376, 117858, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2376, 117859, 'Edj''dan had another artifact he coveted... Perhaps you will need that as well?', 1013, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2376, 117860, 'I will.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2377, 117873, 'You examine Felger''s tracker, adjusting it to ignore the signal coming from the Soil. Two blips appear on the screen, both appear to be moving within the same section of the map.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2377, 117874, 'According to your brief, that area is called the Ruins of Khenmer''Fa. One or more of the pieces must have been taken there. You decide to see what Tigges knows about the situation there.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2378, 117822, 'Recover the second of the Four Pieces from the Ruins of Khen''mer Fa
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2379, 39232, 'Thank you for freeing me. I have news. Your families, back on earth the NID are rounding them up. They plan to use them against you. ', 963, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2381, 113011, 'According to Felger, this case previously housed a collection of four individual artifacts. It has been opened and emptied by the Jaffa. Felger may know something more about what they are...', 2325, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2382, 113012, 'We don''t know much. They looked like ordinary objects: A glowing stick, some dirt, some exotic gas, and a lump of grey goop. Totally bizzare.', 1019, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2382, 113013, 'What do they do?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2382, 113014, 'We never got that far! The theory was they were gathered for a purpose... But no one agreed on what that was. Certainly they didn''t interact with each other directly.', 1019, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2382, 113015, 'Is there any way to find them now?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2382, 113016, 'There may be.', 1019, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2383, 117763, 'If he took an artfact we had, he would have snatched it from the Science Facility - and it''s probably something we took out of the ruins.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2383, 117764, 'Ra''s ruins?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2383, 117765, 'Yup. We must have found something juicy and, given the bureaucracy up here, we never even knew it. I''m only picking up a few signals from within the Science Facility. Weak ones.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2383, 117766, 'Anyone still alive in there?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2383, 117767, 'Can''t really tell, but I do see Dr. Felger''s transponder. If he''s alive, he''ll know what they took.', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2384, 117768, 'Check out what Ra took from the Science Facility', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2385, 42086, 'They''re rounding up our familes?... We can''t worry about this now - we have to focus on the Straegis and their threat... Keep this information to yourself for now. The needs of the many outweigh the needs of the few.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2385, 42087, 'Player: The NID agent said there was a mole within Op-CORE', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2385, 42088, 'I''ll put Blackstock on that... Job well done, soldier. ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2386, 113004, 'Thank you, thank you so much! I am so glad to see you!', 1019, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2386, 113005, 'What were the Jaffa after?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2386, 113006, 'This isn''t a rescue?', 1019, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2386, 113007, 'That comes later.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2386, 113008, 'This gigantic Jaffa-beast titan - Op''raun - grab me by the throat and threatened to rip off my head... Seriously. So I... I told him where it was... Then I fainted.', 1019, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2386, 113009, 'Where what was?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2386, 113010, 'They were after a collection of four artifacts - they call it "The Four Pieces" - all gathered in a case. That was what they were after. I''ll beam you the location... ', 1019, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2387, 63080, 'UN USED DIALOG', 1057, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2388, 117746, 'The Sons of Khepri will ring off the world - soon. And once they do, Ra will bombard what remains to prevent anyone from following.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2388, 117747, 'There is a way to halt the ring transports, for a time. Asgard transmitters can be configured to emit a blocking frequency.', 1018, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2388, 117748, 'How does it work?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2430, 42931, 'Like a dagger.', 968, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2388, 117749, 'You must place emitters in a coverage pattern throughout the crater... I will upload such a pattern to your computing device.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2389, 117745, 'Place teleport emission scramblers to prevent Ra''s Jaffa from leaving Beta Site with his objectives.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2390, 117759, 'The emitters are in place and have been activated. Ra''s minions will not be able to leave the atmosphere until they can decrypt the signals or destroy the emitters themselves.', 1018, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2390, 117760, 'How long do we have?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2390, 117761, 'Ra is quite adept at unweaving technological barriers. We have purchased only a short block of time. ', 1018, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2390, 117762, 'We''ve also locked the hornets in with us. We''ve got to get Ra''s prize back before they figure it out.', 1008, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2391, 63089, 'UnusedDialog', 1014, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2392, 117680, 'Without an operational DHD, we''re stuck manually dialing. Very slow. Too slow to evacuate the wounded.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2392, 117681, 'Can we fix it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2392, 117682, 'We need the components that Satterfield''s Mashdra character took - that''s why she was after him. Make your way to the Shoul''ja Oupost and get them back. It''s about time we punched them back. ', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2393, 117679, 'Get the DHD component back from the Jaffa in Shoul''ja Outpost', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2394, 63072, 'UNUSED DIALOG', 1057, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2395, 117714, 'It sounds like you''ve pissed off Ra.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2395, 117715, 'I hope so.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2395, 117716, 'We need to act fast. If he gets his hands on whatever he is after, it''s game over.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117701, 'You manage to tap into the communication sphere''s signal. It appears to come straight from Ra.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117702, 'Sons of Khepri, hear me. Our goal is met. We have what we want. Prepare to depart. The galaxy will tremble at the majesty of Ra. You four shall be the bearers of my glory. Your names shall be etched on the stars themselves. Op''raun, Sulbek, Edj''dan, Mashdra...', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117703, 'Mashdra? Your locator indicates you moved... You were assigned to Camp Shoul''ja.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117704, 'About Mashdra... He is not there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117705, 'Ah... A pig has escaped its pen and found Mashdra''s Communication Sphere. ', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117706, 'Mashdra is dead. He is just the first. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117707, 'Fool. Your courage is misplaced.', 2547, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117708, 'Mashdra would disagree.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117709, 'Insolence! I will cut out your heart and feed it to you while it still beats!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2396, 117710, 'The communications sphere shorts out in your hand and falls dark.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2397, 117697, 'With the DHD working again, we''ll be able to dial out. Good work.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2397, 117698, 'I recovered a communication sphere as well.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2397, 117699, 'If we can tap into their comms, we can get an idea about what their battle plan is... Can you hack it?', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2397, 117700, 'I will try. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2398, 63061, 'UNUSED DIALOG.', 1011, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2399, 117812, 'The Command Center was cut off before I got off the call for help. Major Davis was holding things together, but that was a while back.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2399, 117813, 'Do you think he made it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2399, 117814, 'We''re picking up his transponder so there''s hope. Davis is like a roach - he''s tough to kill. I''ll try to get a radio message out to let him know you''re coming to get him out.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2399, 117815, 'I need to get that artifact.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2399, 117816, 'You can do both. Look, Davis wasn''t even supposed to be here when the attack hit - he was recalled to Earth, but he stayed. Do right by him.', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2400, 117811, 'Recover one of the Four Pieces held inside the Command Center
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113061, 'I take it you''re the relief?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113062, 'I''m looking for their leader.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113063, 'Op''raun. That monster has been rounding up anyone they catch alive, torturing and gutting them.', 1005, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113064, 'For information?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113065, 'It seems like they got what they came for. Now it''s just for sport. I''ve managed to keep away from their goons. Not all of our people have been so lucky.', 1005, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113066, 'Where is he now?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113067, 'You''ll find him in the main Command Building.', 1005, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113068, 'Tigges wants you to withdrawl...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2401, 113069, 'Right... I will. Thanks... And be careful with Op''raun. He''s a sick, sick puppy... ', 1005, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2402, 113075, 'That''s the artifact Ra was after? A jar of freaking dirt?', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2402, 113076, 'To be fair, it has as-of-yet undiscovered abnormal properties. It would not behoove us to dismiss its importance.', 1018, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2402, 113077, 'I will not dismiss the value of the dirt. How many more artifacts left?', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2402, 113078, 'Three.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2402, 113079, 'I sure hope Felger''s toy keeps it together long enough to find all of them. Nothing that fool makes lasts for very long.', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2403, 117817, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2404, 65957, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2405, 65960, 'UNUSED DIALOG', 1005, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2406, 63243, 'UNUSED DIALOG', 1021, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2407, 63242, 'UNUSED DIALOG', 1057, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2408, 117797, 'At least we have some idea what Ra wants. Felger''s toy may be the only way to find this stuff in time... But it points to a spot smack dab in the Command Center. Terrific.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2408, 117798, 'What is wrong with that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2408, 117799, 'First thing they hit. We managed to hold the bunkers for a while, but we lost the roads in or out. Haven''t had a sitrep in hours. It''s an unknown. ', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117801, 'You understand this is a theory, right? Seriously, it''s just a theory. Like an idea, only slightly better... ', 1019, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117802, 'The fate of the galaxy might rest on it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117803, 'Oh dear... I dislike pressure... Always have. Oh, look - it''s on... One sec... Inputting the subspace profile... It''s tracking... Oh. That''s no good.', 1019, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117804, 'What''s wrong now?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117805, 'There''s a flurry of subspace activity going on outside. It''s making hash out of the scan. Like using a compass on top of a lodestone deposit... You know how that can be, right? ', 1019, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117806, 'No, I do not. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117807, 'Well, it''s not very good because the compass gets all wonky and then - wait... I''ve got a signal through the static. It''s pointing in the direction of the Command Center now.', 1019, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117808, 'That is a start.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2702, 18941, 'STUB.', 1208, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2409, 117809, 'It may clear up the closer you get. Keep trying it. And would you let Tigges know I could use an actual rescue? Maybe?', 1019, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117779, 'The nagging thing we could never explain about the four pieces was their subspace extension.', 1019, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117780, 'What about it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117781, 'Why was it there? Why would a clump of dirt have a subspace extension? It''s dirt, for crying out loud! Something was up.', 1019, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117782, 'So how do we find them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117783, 'If I had my lab, I might be able to whip up something to take advantage of those subspace extensions. But obviously I don''t have my lab...', 1019, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117784, 'What would you need?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117785, 'I''d need my materials... But, most of all I''d need the subspace tracking data we were storing. Otherwise I''ll have no way to tune it.', 1019, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117786, 'Stay here.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2410, 117787, 'I wouldn''t think of moving. ', 1019, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2411, 117778, 'Build a subspace tracking device to track the Four Pieces', 1019, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2412, 63008, 'UNUSED DIALOG', 1010, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2413, 63009, 'UNUSED DIALOG', 1010, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2414, 63010, 'UNUSED DIALOG', 1010, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2415, 117557, 'Radios are slowly coming back online throughout the sector. Thank God... ', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2416, 117519, 'If you''re receving this the repeaters must be working. Nice job. We''re starting to get transponder signals in from my people.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2416, 117520, 'What next?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2416, 117521, 'I''m picking up the location of Captain Satterfield - she should be near you. She led the team that took the gate back. She went off after the Jaffa when we lost contact. Get a status report from her before you return.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2417, 117522, 'Hey, didn''t expect to see you here. A friendly face... ', 1010, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2417, 117523, 'What is the situation?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2417, 117524, 'Lots of Straegis and Ra''s Jaffa... But we''re fine here... I''ve been seeing some strange folks around - but they look like they''re on our side.', 1010, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2417, 117525, 'We made a deal with the Praxis. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2417, 117526, 'Serious?', 1010, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2417, 117527, 'Yes. What about the Jaffa you were following?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2417, 117528, 'They fell back to the Shoul''ja Outpost, but they''ve got some serious defenses up ahead. They called their leader "Mashdra." Dunno much more... ', 1010, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2418, 117516, 'My first concern is communications. Radios went down almost immediately.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2418, 117517, 'There is a tremendous amount of broad spectrum interference attributable to the Straegis presence.', 1018, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2418, 117518, 'Right. What he said. The point is, I think we can pick up the slack if we can rig the outposts to amplify their signal capacity. Start with that.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2419, 117515, 'Restore radio communications via the checkpoint outposts.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2420, 118211, 'Assist the relief of Beta Site which is overrun by the Straegis.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2421, 62894, 'UNUSED DIALOG', 1009, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118212, 'Glad you''re here. Ra has hit Beta Site... We don''t know the extent of it. Thor?', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118213, 'Mimir was able to send a short message before his outpost went dark. Ra''s forces and the Straegis are present in force. We believe them to be completely overrun.', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118214, 'What is Stargate Command doing about it?', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118215, 'Woolsey is not lifting a finger. They''ve decided not to reinforce or even to assist in the evacuation. Beta Site is alone.', 2410, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118216, 'Sir, we''ve got save those people. ', 2184, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118217, 'Precisely why we''re sending a full response, Colonel. Heimdall and Dr. Jackson are already there. $name$, Captain Tigges is the current base commander, I''m sure he''ll welcome any assistance.', 2410, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118218, 'There is a concern. Captain Tigges has enlisted additional aid.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118219, 'From where?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118220, 'The Praxis - Colonel Marsh''s allaince of New Mind Goa''uld, Loyalist Jaffa and his own Op-CORE humans. Apparently Tigges has convinced Marsh to help.', 2410, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118221, 'Can we trust them?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118222, 'I know Carl Marsh personally. Never liked the man, but he is someone with a deep sense of honor. He steps over the line, but he does it because he believes it''s the right thing. ', 2410, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118223, 'We have little choice but to trust him. The situation at Beta Site is desperate. Praxis help may be the difference between victory and defeat. ', 2323, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2422, 118224, 'Mimir waits for your arrival. Good luck, $name$. ', 777, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2423, 118225, 'Good to see you here... ', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2423, 118226, 'What is the situation?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2423, 118227, 'Lots of bad... Did General Hammond tell you about the Praxis?', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2423, 118228, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2423, 118229, 'Good. I''m sure you''ve got issues with it... I don''t have time to hear it... I was desperate... ', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2423, 118230, 'We will be watching them, Captain Tigges. Of this you may be certain.', 1018, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2423, 118231, 'I''d expect nothing less. ', 1008, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2424, 62901, 'UNUSED DIALOG', 1005, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2425, 39236, 'Find Whelan, Copplemann''s husband', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2426, 39239, 'I have a favor to ask of you. I have heard my husband, Rick Whelan, was spotted on Lucia. Can you find him and give him this note? I''ve got a disguise for him so he can come to the city, if he''s willing to see me... ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2427, 39245, 'Sharon is alive? Of course I want to see her... How can we make this happen?', 966, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2427, 39246, 'Player: I''ve got a disguise. We can get you to our basecamp - Harset.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2427, 39247, 'If I''m caught there?', 966, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2427, 39248, 'Player: Then I knew nothing about this. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2427, 39249, 'Fair enough. Leave the disguise under that pile of junk over there. I''ll get it later and find my way to Harset.', 966, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2428, 42923, 'Thank you for helping us to get together. We''ve got to get Rick off of Harset. Can you escort him to the gate? I''m afraid we might be seen...', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2429, 42924, 'Thank you for everything. Can I ask one more favor from you? Give Sharon this ring... It''s really important she have it...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2430, 42925, 'He gave it back... ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2430, 42926, 'Player: He said you should have it...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2430, 42927, 'I''m sure his new wife wouldn''t want him to keep wearing the ring I gave him... ', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2430, 42928, 'Player: New wife?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2430, 42929, 'Yeah. I can''t blame him for it, really. He thought I was dead. And even before that I was always committed to the Colonel and our mission... It was inevitable.', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2430, 42930, 'Player: Still hurts.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2431, 43071, 'Marsh wants to see you. Something about an SGC sighting here on Harset.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2432, 43078, 'It''s best not to keep the Colonel waiting...', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2433, 43073, 'Blackstock presented me with some very interesting videotapes this morning. Specifically it showed a known SGC officer - Captain Whelan - entering and leaving Harset. You were taped escorting him to the gate. Obviously this is a serious breach of protocol. Do you want to try and convince me why you shouldn''t be punished? ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2434, 39269, 'Submit to punishments administered by Blackstock', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2435, 39268, 'Colonel Marsh has informed me that you are to be punished. Frankly, I think you deserve to be locked up, but the Colonel respects your service. Just know this: You are now on thin ice. So, make sure you do what I tell you, exactly.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2436, 39273, 'Blackstock punishes player here', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2437, 39278, 'Enough. You''re done. But keep your nose clean. I will be watching you.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2438, 16844, 'Execute a raid on one of Ra''s Battlecruisers, the Matet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2439, 17091, 'O''Neill briefs the player that the SGU has caught wind of one of Ra''s advanced Battlecruisers in space near an uninhabited planet, shields down and relatively unprotected.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2439, 17092, 'The SGU doesn''t have a fleet to spare, so O''Neill is sending the player on a commando mission to either take out the ship or capture it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2440, 16853, 'The player overrides the commands for the ship and uses them to vent the decks of the vessel and set a beacon for the SGU ships to intercept. This ship is theirs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2441, 16823, 'O''Neill is stunned the players not only took out the ship, but brought it back in one piece. The SGU science team is dilligently picking apart the technology and the remains of the deadly creatures onboard, which were called Straegis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2442, 16826, 'Find out why Ra sent his Battlecruiser into unoccupied space', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2443, 16827, 'According to their star maps, the Ma’tet is headed away from occupied space. It is near the Tevak’nell belt - a shattered system of worlds so dead they cannot even be terraformed. Thor wants us to find out what could possibly be so important for Ra.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2444, 16893, 'These generators are fueled by Naquadah, but are extremely ineffecient "breeder" reactors which produce more than the standard quantity of useless Naquacite residue.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2445, 16894, 'Thor remarks that Ra''s quest for Naquacite may be explained by the presence of these new creatures. On first inspection their biology and technology seems driven by Naquacite as the primary resource. This is utterly nonsensical however based on known science.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2446, 16835, 'Identify the cause of the strange energy emissions and drains aboard Ra''s Battlecruiser', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2447, 16834, 'Carter saw a little more in the scans of the Matet than just the Shields being down. Strange power emissions, and what looks to be a heavy drain on the ships systems coming from inside. Some sort of new technology, she gathers, which she wants more info on.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2448, 16837, 'The drains were caused by the new Straegis creatures, and their alien nature and tremendous power has Carter scared.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2449, 16839, 'Recover a relic from Ra''s Battleship on behalf of the Jaffa', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2450, 17093, 'Teal''c warns the player that the vessel in question (the Battleship) is possibly still captaind by Ma''at. Teal''c tells of a Jaffa legend of a relic stolen from Dakara by Ma''at, Ra''s master builder, which she then called the Balance of Ma''at, which could "weigh men''s souls." From the description in the legend, Daniel Jackson informed Teal''c it was probably of Ancient origin.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2450, 17094, 'Whatever the truth, it is still sacred to some of the Jaffa, who would look favorably on its return. Teal''c promises that it will be looked at before he would hand it over, though.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2451, 16842, 'Teal''c is grateful that the player remembers the small task along with the great.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2452, 39330, 'Patrol the city', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2453, 16843, 'Storm and capture one of Ra''s ships which has left the fleet and become exposed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2454, 17095, 'Ba''al informs the player that the Praxis''s spies has caught wind of one of Ra''s advanced Battlecruisers in space near an uninhabited planet, shields down and relatively unprotected.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2454, 17096, 'There are many who want to destroy the ship, but Ba''al thinks the player can take it intact and so has made it their responsibility. This "offer" Ba''al makes is tinged with a sense that Ba''al would rather perhaps the player die on the suicide mission.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2455, 16854, 'The player overrides the commands for the ship and uses them to vent the decks of the vessel and set a beacon for the Praxis ships to intercept. This ship is theirs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2455, 16855, 'Before the player leaves the console, they embed a secret lockdown inside the ship. Without their authorization, the ship will be useless to the Praxis. This will keep them from being cheated out of the glory.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2456, 16860, 'Ba''al and Marsh demand the lockdown code from the player, who gladly exchanges it once they know that the ship has arrived safely in Praxis hands and everyone knows they were responsible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2456, 16861, 'The player is justly rewarded for their actions, and the player''s precaution slightly praised for being a wise move with so many potential traitors around.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2457, 16868, 'Report the reason for Ra detaching his Battlecruiser from the fleet', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2458, 39519, 'Well, you know what they say about payback. We need the city patrolled. You''re in the doghouse so... Get it done.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2459, 16891, 'Anat wants answers. The whole Battlecruiser plan seems too much like a trap for her liking. She''s more than willing to let the player hang themselves on the assault, but should they prevail or be turned back, it would help her understand Ra to know WHY he sent his ship out into the wilds of space.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2460, 16895, 'These generators are fueled by Naquadah, but are extremely ineffecient "breeder" reactors which produce more than the standard quantity of useless Naquacite residue.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2461, 16897, 'Anat is satisfied but dismayed Ra outsmarted her. Ra''s need for Naquacite must be tied to the Straegis creatures, and means that what the galaxy considers trash, he considers gold. An interesting asymmetry that means the Praxis is again a step behind.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2462, 16674, 'There seems to be an anomaly on that weapons cache.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2463, 16908, 'Identify the source of the unexplained energy pulses and power drains from Ra''s Battlecruiser', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2464, 17097, 'Copplemann is engaged in an argument with Marsh about how much the Battlecruiser looks like a trap. It ends with Marsh pulling rank and giving the player the OK.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2464, 17098, 'Copplemann is still concerned. There are unexplained energy anomalies, both emissions and drains, coming from the ship. It''s got to be one of Ra''s secret projects and Copplemann needs to know what is on that ship.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2465, 16909, 'Copplemann checks her watch. It seems as though the future Op-CORE didn''t buy as much time as they''d hoped. The Straegis are here, and Ra opened the door.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2466, 39518, 'Nice work. Check the market area. I''m mobilizing security to cover the entire city.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2467, 30615, 'Recover a Jaffa relic from the Battlecruiser to aid in Mok''hatan''s recruitment efforts', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2468, 30619, 'Mok''hatan knows that if the player is boarding the Matet, then they will probably encounter Ma''at, if the bitch is still alive. Ma''at long ago won a favor from Ra in the form of a relic taken from the Jaffa, a loss the Jaffa still remember. If Mok''hatan can wave it in front of some of the tribal leaders the Praxis is courting, it may be enough to seal the deal. Mok''hatan wans the players to grab the relic, the Balance of Ma''at, if they can.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2469, 30624, 'Mok''hatan doesn''t worry about the state of the relic. All she needs is another bargaining chip.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2470, 16935, 'Free the Straegis still under Ra''s command and earn the Prime''s favor', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2471, 17099, 'The Prime tells the player that Ra still holds power over some of the Straegis. He believes Ra understands the Allegiance theme to counteract the Prime''s call... which is admittedly not that strong yet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2471, 17100, 'The Prime offers the player the chance to earn its favor and possibly future aid by delivering the "Icon of Liberation" to one of the places Ra is blocking the call. The Prime even offers to send the player there gratis.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2472, 16938, 'The player administers the Icon of Liberation to the device which appears to be splitting and recombining themes to reconfigure new Straegis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2472, 16939, 'The themes within the Icon spread out, converting the Meta Straegis overseeing this facility to one following the Prime. It communicates with the player telepathically.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2473, 16940, 'The Meta communicates telepathically with the player. The Jaffa will kill it before it can complete the liberation, so it needs the player to assist it by delivering it themes from the Straegis the player kills. The Combinatrix can send the themes down to the Meta so it can defend itself.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2474, 16953, 'The Meta speaks with the voice of the Prime and communicates its gratitude and offers the player their boon as reward.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2475, 16954, 'Figure out where the Prime has sent you and what you can accomplish here', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2476, 16955, 'The Prime sent the player here to liberate Straegis... but this here is a vessel, not a planet. The player can take the initiative and find out what this vessel is and if there''s something else the player can do to stop Ra onboard.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2477, 16963, 'These containers bear the seal of Ra and the insignia of the Sehkmet, Ra''s most powerful Flagship. Now the player knows the where.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2477, 16964, 'But there is something else in the mess. The manifests and orders attached to these containers are marked with the address of Earth. That must be this ship''s destination.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2478, 16977, 'The player halts the ship''s travel and overrides it as they did the Matet what seems like a lifetime ago.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2478, 16978, 'In the computer is the coordinates for the launching point for the ship... called Ahket, Ra''s last stronghold.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2479, 16979, 'Bring back this surgical equipment of Ra''s back to the Omega Site', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2480, 17041, 'The surgical equipment is large scale, capable of ripping flesh and bone and replacing it with... what exactly is unclear. This is equipment Ra is using to build his "flesh mech" style of warrior.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2481, 17046, 'Carter is convinced that this is a sign that Ra isn''t beaten yet, that even as he loses the Straegis he plans another army. Ra must be stopped before he can regroup and rebuild, or this war may go on even longer.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2482, 17043, 'Bring back this surgical equipment of Ra''s back to Harset', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2483, 17045, 'The surgical equipment is large scale, capable of ripping flesh and bone and replacing it with... what exactly is unclear. This is equipment Ra is using to build his "flesh mech" style of warrior.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2484, 17047, 'Copplemann reads desperation into Ra''s boosting of his soldiers, but it''s clear that Ra isn''t going to give up without a fight. Ra must be snuffed out for good before this army can be allowed to grow.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2485, 39520, 'Check the marketplace for suspiscious activity', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2486, 39521, 'You''ve redeemed yourself nicely. Go check out the marketplace. I''ll send patrols to other points in the city. We''ve got to figure out who is behind this.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2487, 39536, 'They were dressed as Morrigan''s Jaffa...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2487, 39537, 'Morrigan: They were certainly not my minions!', 970, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2487, 39538, 'Let me finish please... They were dressed as your people - minions - but they were planting this beacon technology. A tech we''ve seen other places. Nerus?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2487, 39539, 'Nerus: It''s a unique technology. Brilliant, but i haven''t deciphered how it all works. It appears to be a super-charged homing device... No Goa''uld possessed technology of this type that I am aware of.', 943, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2487, 39540, 'Baal: Only Ra had anything that advanced. These Jaffa were probably his, dressed as Morrigan''s as a means into Harset...', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2487, 39541, 'Moh''katan: They are honorless to disguise themselves so...', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2487, 39542, 'It worked and Ra has upped the ante. We''ll increase security. Well done, soldier.', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2488, 17048, 'Feed the Meta two attuned Life theme shards and it will perform a rejuvination ability', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2489, 17052, 'The player drops the Life theme shards into the hopper where they are pulverized and sent down to the Meta. The Meta activates the Life themes generating a massive rejuvinating pulse.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2490, 17051, 'Feed the Meta an attuned Conflict and an attuned Forces shard and it will form an offensive Straegis ally to fight at its side.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2491, 17056, 'The player drops the Conflict and Forces shards into the hopper where they are pulverized and sent down to the Meta. The Meta weaves the themes into a small Tasked Straegis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2492, 17060, 'Feed the Meta an attuned Conflict and an attuned Allegiance shard and it will form a tactical Straegis ally to fight at its side.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2493, 17057, 'The player drops the Conflict and Allegiance shards into the hopper where they are pulverized and sent down to the Meta. The Meta weaves the themes into a small Tasked Straegis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2494, 17059, 'Feed the Meta an attuned Forces and an attuned Matter shard and it will form a defensive Straegis ally to fight at its side.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2495, 17062, 'The player drops the Forces and Matter shards into the hopper where they are pulverized and sent down to the Meta. The Meta weaves the themes into a small Tasked Straegis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2496, 17063, 'Retarget the automated turrets here to attack the Jaffa', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2497, 17064, 'The player hacks the targeting system and the turrets spin and begin blasting the Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2499, 39638, 'The Loyalist Jaffa requisitions officer, a guy named Tau''hut, is claiming there''s a human crate in Storage he can''t identify. Go check it out.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2500, 39640, 'There is a crate over there that I have no requisition forms for. It seems suspicious. Does it belong to Op-CORE? ', 973, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2501, 39641, 'They were going to smuggle me off the world in that crate... They snatched me just after I went off duty last night. I''ll report everything to the Colonel. I owe you one...', 947, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2502, 39644, 'Check the shield pylons on Harset for sabotage', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2503, 39645, 'There''s been an attack in Harset. A bomb went off in the Jaffa quarter. We need you back here to help us scour the city for sabotage. Specifically, we want you to check out the shield pylons - if Ra were to blow those we''d be at his mercy.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2504, 39643, 'Nice work. Clearly we''re not flying under Ra''s radar. You may have kept a lot of people alive with your attention to detail today. Nice work.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2505, 39647, 'Check out the Greenhouse on Agnos for suspicious activity.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2506, 39656, 'We got a strange tip from a Burtonol operative we captured on Agnos. He claims there are some people looking for Op-CORE operatives on the world. He last saw them in the Greenhouse. Go there, and proceed with caution. If they are NID? Terminate with extreme prejudice. ', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2507, 43840, 'I just eliminated an NID presence on Agnos.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2507, 43841, 'Noted. ', 948, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2507, 43842, 'How are they getting off of earth? There''s only the one Stargate.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2507, 43843, 'I''ve been wondering that myself. They''re politically resourceful and relentless, I''m imagining they have simply played politics to get clearance. Stay safe out there... There may be more of them.', 948, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2508, 40126, 'Present Whelan''s offer of a tech trade to Marsh.', 602, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2509, 39551, 'The way I see it, we''re all working together to stop Ra and his minions, right?', 599, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2509, 39552, 'We have to. The galaxy is at stake.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2509, 39553, 'We have developed some technology that may help us fight them. I can probably convince my superior officers to support a trade, assuming you have something worth trading. ', 599, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39555, 'This technology works against the Straegis specifically?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39556, 'Player: That is what he claims, sir.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39557, 'Baal: What do they specifically want from us?', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39558, 'Player: They want technology. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39559, 'Copplemann and Nerus have developed a weapon prototype. We could trade that tech for what they''ve got. ', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39560, 'Anat: Why don''t we just steal what they''ve got and be done with it?', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39561, 'We don''t operate that way. ', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39562, 'Anat: Then, good Colonel, it rests upon you and your minion to deliver their technology at no cost to us. ', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39563, 'The prototype Copplemann and Nerus have developed only affects Straegis. It can''t be used against us.', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39564, 'Anat: So you say.', 944, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2510, 39565, 'Make the trade, Soldier. Test their gizmo out first, but if it is effective, make the trade. Report to Copplemann and have her give you one of our devices...', 941, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2511, 43892, 'I hear that Rick contacted you. Here''s your prototype... Can you give him this note too?', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2512, 39576, 'My superiors have agreed, assuming your side can bring something to the table.', 599, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2512, 39577, 'Player: We''ve got something. I need to test your stuff in the field - that''s my Commander''s stipulation.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2512, 39578, 'Great. I know I can trust you and we can use additional field tests.', 599, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2512, 39579, 'Player: Captain Copplemann also included a note in the package. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2512, 39580, 'I saw that... We''ll discuss that when you get back.', 599, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2513, 39581, 'Well, you''re alive, so the test was successful. ', 599, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2513, 39582, 'Player: Apparently. We can make the exchange now.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2513, 39583, 'Thank you... Major Carter can''t wait to see what your team has brought to us.', 599, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2513, 39584, 'Player: Anything I should tell Captain Copplemann?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2513, 39585, 'Yes. Please tell her I can''t see her again. I have a new life now... I thought she understood. But apparently she is hanging on...', 599, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2513, 39586, 'Player: Odd how marriage does that to a person. I''ll let her know. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2514, 39587, 'I''m not surprised the test worked. Rick is a brilliant, brilliant scientist... Did he say anything about my note?', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2514, 39588, 'Player: I never got the chance to speak with him... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2514, 39589, 'No? Didn''t you make the exchange with him directly?', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2514, 39590, 'Player: He wasn''t there, Captain... I don''t know how to tell you this so... Captain, Rick Whelan is dead. The Straegis got him.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2514, 39591, 'I see... Will you please excuse me for a moment?', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2514, 39592, 'Player: Of course.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2516, 96392, 'Something just took Marsh - it snatched him through a rift in this and space and left behind a puddle of blood... What the hell was it? The Straegis? If so, you''re going to beed a bigger gun. For now, you need to keep moving forward and find another officer.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2517, 96369, 'You search through the Crate and discover a heavy weapon and a piece of body armor that protects the chest.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2518, 96406, 'Help Op-CORE secure the Armory by opening the doors.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2535, 39593, 'Take the Data Card that reveals the mole to Blackstock - but be careful!', 976, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2536, 43936, 'You know a guy named Whelan? SGC nerd-type.', 976, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2536, 43937, 'Player: Sure, I know Whelan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2536, 43938, 'Well today is your lucky day. Whelan saved my life on Agnos. I owe him and, apparently, he owes you. So, I''m here to pay it forward. I''m Hite, and I work for the NID.', 976, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2536, 43939, 'Player: An NID agent is supposed to help me out?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2536, 43940, 'You have a mole in your operation, and only we can tell you who he is. Specifically, I can tell you. The evidence you need is on this data disc. What you do with it is your business. Just know, this guy will do whatever it takes to keep a lid on this. Now, my debt to Whelan is repaid and this conversation never happened. ', 976, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2537, 39599, 'Smart move, duplicating this. Give the original card to Blackstock. I''ll try and decrypt the data myself, so you have some additional protection. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2538, 39600, 'You got this directly from an NID source? Well, you''re certainly not safe here - and we''re not safe having this conversation. I''m going to decrypt this disc, you wait for me in the Marketplace. I''ll be there ASAP.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2539, 39601, 'After decrypting the disc, I''m not surprised. Blackstock has been sending messages to an NID cell on Lucia - he hides it within the black market operation he''s running. He''s working with them. Watch your back.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2540, 39604, 'Come here. Now.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2541, 39605, 'You are required in the Command Center. Come immediately. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2543, 39606, 'Captain Blackstock here has informed me that you are the NID mole. Give me one reason not to simply shoot you in the face and be done with it. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2543, 39607, 'Copplemann: Blackstock is the mole, sir. <<Playername>> gave me this data disc from an NID source on Anima Vitrus. It documents Blackstock''s contacts with an NID cell on Lucia. He''s been using his supply operation as a cover.', 968, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2543, 39608, 'Blackstock: That''s absurd! I showed you the disc I recovered from the NID operative, Colonel. It clearly shows that <<Playername>> has been contacting the NID himself. Captain Copplemann is protecting this man out of a misguided sense of loyalty.', 948, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2543, 39609, 'Player: I gave you that disc, Blackstock, and you sent me to the Marketplace to meet you. Instead I was ambushed. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2543, 39610, 'This stuff looks Lucian...', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2543, 39611, 'Blackstock: They''re trying to pin this on me...', 948, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2544, 39618, 'Blackstock... By my executive order, you are hereby accused of treason and are to be incarcerated while you await trial. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2544, 39619, 'I hope, sir, given the longevity and dedication in my service to you, that you will provide me with a means to absorb my punishment honorably and without spectacle. ', 948, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2544, 39620, 'Fair enough. <<playername>> Take him to the jail. Once there give him this. ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2545, 44056, 'Just know something... I never betrayed Op-CORE. I can accept what''s coming - hell, I actually welcome it - but know this: I''m taking the bullet here for something greater than you and me. I''m just the patsy.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2545, 44057, 'You''re a traitor, Blackstock.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2545, 44058, 'And you''re naive <<playername>>. ', 948, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2546, 39624, 'Find out why the Goa''uld are acting strangely.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2547, 39626, 'The Goa''uld have been acting especially subversive lately. Lethander always has his finger on the pulse of the New Mind...', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2548, 39627, 'Interesting you come to me in this moment, human. Let''s just say that there may be changes in the order of things around here. Changes which may occur remarkably soon. But you never heard that from me.', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2549, 39628, 'What do the Loyalists think? ', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2550, 39632, 'Goa''uld leaders rarely survive for long periods of time. Our alliance currently is at risk unless they can contain their baser natures. Since this is unlikely, I must warn you that - if there is an upheaval - your faction''s stability will probably determine if the Praxis itself survives. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2550, 39633, 'We''re solidly behind the Colonel.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2550, 39634, 'You will need to be if what I fear happens, comes to pass. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2551, 39635, 'The Praxis is on the verge of collapse. If the Goa''uld eviscerate themselves we may have real problems. Word of Blackstock''s treachery must have reached Moh''katan and she has her own troubles with the Jaffa nation. We''ve got to tread lightly. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2552, 39657, 'Plant a listening device in Anat''s chamber', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2553, 39658, 'I have something that might work... Anat''s chambers staff wear very specific outfits - she''s a sticker for details. I happen to have one here... You can borrow it, but I want it back.', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2553, 39659, 'This thing is valuable?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2553, 39660, 'There are a few New Mind - and a ton of Jaffa - who pay me so they can wear that thing just so they can get a look at their queen. ', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2554, 44102, 'We need to keep tabs on the New Mind. I need you to get into Anat''s chambers and plant this listening device. See Hansen about finding a disguise to get you in there... If the guards are alerted they''ll certainly scour the place for bugs...', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2555, 39661, 'Nice work. We will have the device monitored around the clock... This should be very illuminating indeed. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2556, 39667, 'Prepare to pay Marsh back for his role in betraying Op-CORE.', 1098, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2557, 39676, 'Reading Wertz''s journal you come across a document - a printed e-mail - stuffed into the binding. Scrawled across the top of the folded page in Wertz''s script is the name Marsh.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2557, 39677, 'He knew. He not only knew... He ordered it... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2558, 39678, 'Eventually I will sell u this resin.', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2559, 39663, 'I found this on Wertz''s body. There''s evidence there that the Colonel was the one who set us up. He was working with Wertz and Romney both.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2559, 39664, 'So the rumors were true...', 968, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2559, 39665, 'He gave the order. He gave the order that put us in the Castle. I''ve got his chair wired. Give the word and it''s over. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2559, 39666, 'No... You do that and we''re all lost. We have to think politically here. If the Goa''uld make a move, then we''ll deal with this. Until then we risk pushing the Jaffa out of the alliance altogether. Just sit tight and keep this to yourself. Everything is on the line now. ', 968, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2560, 39680, 'Collect a letter from an Op-CORE operative and bring it to Bench.', 979, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2561, 39681, 'Hey there. It''s been a long time. Listen, I am shipping out back home - I''m headed back to earth. I know you''ve got a lot of people who would like to get messages out to loved ones... Bring me their letters and I''ll get them mailed... I''m shipping out soon, so get what you can to me quickly.', 979, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2562, 39679, 'I''ll get these delivered.', 979, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2563, 39109, 'Deliver Dawson''s autopsy to Marsh', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2564, 39110, 'Do me a favor, human? Deliver this package to Colonel Marsh. He''ll be ever so grateful that you did...', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2565, 39111, 'Dawson''s autopsy... Interesting... Come with me... I think something interesting may be in the works.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2566, 17438, 'INSERT SCRIPTED SCENE - ANAT IS OUSTED BY THE PRAXIS LEADERSHIP', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2567, 101423, 'The Goa''uld bindings are relatively simple, but hacking them could take time... Time you may not have...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2568, 18252, 'Stub: Argh. They''ve killed me', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2568, 18253, 'Stub: What happened here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2568, 18254, 'Stub: Survivor explains that Ra''s Jaffa found out about the meeting and attacked. Garshaw returned to Wey-Tan''s palace for reinfocements. Ra''s Jaffa remained to kill whoever Garshaw was meeting (i.e. the player)', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2569, 39112, 'Anat is finally gone. Perhaps the Goa''uld will become more predictable now - or at least more useful...', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2570, 18467, 'Stub: The Tok’ra Garshaw/Yosuuf explains that she is an advisor to Wey-Tan.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2571, 18468, 'Stub: Malek explains he has been collecting intel—he has found out from another undercover Tok’ra 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2572, 96765, 'Reinforce Copplemann in her efforts to get to Dr. Zuritska.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2573, 113552, 'Fantastic job $name$! Securing the armory gives us an even shot at getting out of here alive.', 1109, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2573, 113553, 'Thank you, Sgt. What''s the sitrep?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2573, 113554, 'It''s nuts. We''ve got lots of people heading for the gate and the NID guys are not happy about it. Capt. Copplemann is missing - out there somewhere. She took a fire team out to try and rescue Dr. Zuritska and they haven''t returned.', 1109, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2573, 113555, 'Has a team been sent for them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2573, 113556, 'You''re the first one through. Wanna go?', 1109, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2573, 113557, 'Absolutely.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2573, 113558, 'Get it done.', 1109, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2574, 96800, 'Boy I''m glad to see you. I got caught by one of those drones... My leg is pretty bad.', 1110, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2574, 96801, 'Where is the rest of your fire team?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2574, 96802, 'They didn''t make it. We got caught by a wave of NID reinforcements. It got ugly. Help me over to that med station across the hall, would you?', 1110, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2574, 96803, 'Of course.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2574, 96804, 'First help me get out of this boot.', 1110, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2575, 96799, 'You manage to free Capt. Copplemann from her security boot.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2576, 96821, 'There''s no way I can hold my own out there anytime soon, but you apparently can so... I need you to rescue Dr. Zuritska and take him to the Communications room on Level 5. He has to patch me into the Castle''s comm systems so I can coordinate this escape.', 1110, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2576, 96822, 'Where is he?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2576, 96823, 'Interrogator Romney took him to the Interrogation Block a few hours ago. ', 1110, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2576, 96824, 'Romney...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2576, 96825, 'Yeah. He has been working Zuritska over a lot for some reason... Once you get Zuritska safe, go find Romney''s files. There''s a nasty rumor in the ranks that Colonel Marsh may have been part of the conspiracy that got us stranded here in the first place. Those files may answer that question. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2577, 96826, 'You save me... And you kill Romney. I appreciate.', 1114, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2577, 96827, 'You must get to the Communications Room, immediately.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2577, 96828, 'Why I go there?', 1114, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2577, 96829, 'Capt. Copplemann needs you to open the communciation channels so that she can coordinate the escape.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2577, 96830, 'Copplemann... I will do this - but you tell her she owe me!', 1114, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2580, 96896, 'You bypass the security protocols on the terminal and discover details about the modifications the NID made to the Castle. Of special interest is a note about an override control node available from somewhere within the Throne Room.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2581, 96900, 'NID are imbeciles! Much advanced Goa''uld technology and they produce communication system slightly more sophisticate than moose calling for mate.', 1113, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2581, 96901, 'Are we patched in?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2581, 96902, 'Of course! NID are imbeciles, not Zuritska. That was done minutes ago. I try now to boost power, but something interferes with NID communication grid. For now, we only communicate within Castle.', 1113, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2581, 96903, 'I found these schematics when I was analyzing the security system.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2581, 96904, 'Ah, yes! This is problem. Someone activate Goa''uld defenses. They drain power from communication. Throne Room is culprit. You can find access panel on back of throne. There you shut down. You shut down defense and we boost signal.', 1113, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2581, 96905, 'You want me to do this?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2581, 96906, 'Who else do it? Not Zuritska. I have much to do here. You must go... ', 1113, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2582, 17791, '<groan> My head. What was that thing?!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2582, 17792, 'Player: What thing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2582, 17793, 'That. . . thing. It just appeared out of nowhere and killed. . . Well, killed me I guess. I''m not crazy!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2582, 17794, 'Player: No. I know you''re not. Same thing happened to me. Look, let''s just get out here and then we can sort this all out.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2583, 17678, 'You retrieve a MedKit from the Med Station.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93445, 'Good work! Now that we can communicate, we need to get off this damn planet. I need you to secure a route to the Stargate. The rest of us are following behind.', 1110, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93446, '. . . one. . . ere? . . . . . .is Col. Mar. . . read me?', 261, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93447, 'What was that? Zuritska! Clean up the damn signal!', 1110, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93448, 'Captain, that sounded like Col. Marsh.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93449, 'You''re right. Col. Marsh, this is Copplemann. Do you read? Zuritska, boost the damn signal already! Marsh, are you there?', 1110, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93450, 'You''re coming through loud and clear, Capt. The Castle''s signal overwhelmed ours for a second there.', 261, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93451, 'You came. We knew you wouldn''t give up on us, sir!', 1110, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93452, 'No man left behind, Capt. I would''ve contacted you sooner, but we''ve got a problem here. We''re at the Stargate, but can''t dial out. We''re trapped unless we can get the DHD working. Is there anything you can do at that end?', 261, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93453, 'I''ll do my best to find out, sir!', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93454, 'Report in the second you know something. Copplemann out!', 1110, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2584, 93455, 'Good luck! Marsh out.', 261, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2585, 17682, 'You disable the Humvee.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2586, 96974, 'You dial the DHD, entering the coordinates for Harset. It fires and is now ready for you to travvel through.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2587, 17796, 'You dial the DHD, entering the coordinates for Tollana. Go through the Stargate to travel to a new world.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2596, 101424, 'My wrists and ankles hurt.', 1103, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2596, 101425, 'Numbness. That will subside... Where is your husband and son?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2596, 101426, 'They''re gone. Dead. Killed.', 1103, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2596, 101427, 'Then you are the only one I am after. We must go.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2596, 101428, 'We can''t just go. The Jaffa won''t like that. They won''t allow it.', 1103, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2597, 72093, 'Follow the trail to Ihpet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2598, 72185, 'We sent a human advance team through the gate to Ihpet once we received the address from Colonel Carter. They have reported that passage to the world is safe. You are to report to Lt. Mogilny upon arrival.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2598, 72186, 'Good luck, <<playername>>. You may well need it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2599, 72187, 'These writings seem to describe some sort of ritual, but the glyphs are in a dialect of Goa''uld used by Ra on his monuments. You recognize some of the symbols as matching those found on Abydos. Dr. Jackson is the real expert on this. You need to send an image of these glyphs to him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2600, 71805, 'The player takes digital snapshots of the entire Wall using their standard PDA to send back.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2601, 99333, 'I recieved the image and I can translate this, give me a second. Let''s see... guardian of the Ka, uniting forever body and soul... Ra''s light shall shine on you... Ah, I get it. Do you still have the Crystal Key?', 1631, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2601, 99334, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2601, 99335, 'Ok, the inscription talks about a transfer of the Ka, which is the Egyptian word for soul - a transferance ritual. I think this must be some sort of energy transfer. Do you see any indentations or places for the key?', 1631, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2601, 99336, 'Yes. I can see something.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2601, 99337, 'Good. Place the key there and see what happens. You may have to manipulate the energy field... um... somehow.', 1631, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2601, 99338, 'Then what?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2601, 99339, 'Duck? Colonel O''Neill always says I never duck enough.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2602, 72158, 'CUT. Delete this dialogue. (See screen notes)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2603, 104406, 'Activate the Wall of the 13th Hour', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104432, 'We have sent through a security detachment to ensure a safe landing for you on the world. It will be up to you beyond that.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104433, 'Do not make us regret our rash decision to send you on this mission. There is nothing more important that this for our alliance... Nothing. ', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104434, 'I will succeed.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104435, 'We harbor no doubts. ', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104436, 'McIntyre is down there now - you worked with her on Men''fa. She has the area clean... Reports indicate there are Unas living there - probably loyal to Ra.', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104437, 'Semi-literate beasts... They should be of no conscequence. ', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104438, 'There are safeguards in place, of this you can be certain. Ra was fanatical about protecting his interests. I have placed Nerus at your disposal. If you need him, he will be available directly.', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2604, 104439, 'The hour is at hand. Travel to Ihpet and bring us the secrets of his power... Bring that glory unto us, <<playername>>.', 945, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2605, 104462, 'These writings describe some sort of ritual, but the glyphs aren''t decipherable. They might form some sort of code. Nerus would be useful. You need to send an image of the glyphs to him for analysis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2606, 76226, 'DELETE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2607, 104468, 'It is a code, you are quite correct - a fairly simple one Ra used to use for routine messages. I have sent you the basic decryption pattern genius in its deception through simplicity. ', 1632, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2607, 104469, 'Just apply the decryption to the messages...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2607, 104470, 'Yes. The simple system is quite a gamble if a weapon is stored down there. The glyphs describe a musty old ritual called the "Opening of the Mouth". The instructions for each phase should be contained on the relics you encounter. Apply those and use the key...', 1632, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2607, 104471, 'Understood.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2607, 104472, 'It will not be the same key when you are done. It will tranmute... It''s part of the technology he used to keep his Goa''uld rivals out.', 1632, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2607, 104473, 'Change.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2607, 104474, 'I hope you find something useful. Things around here are getting... tense. I fear even the remarkably boisterous Moh''katan may have trouble keeping this alliance together without results. It''s altogether ruining my appetite.', 1632, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2608, 76262, 'DELETE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2609, 104496, 'Perform the ritual at the "Temple of the Dawn"', 1127, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2610, 104510, 'The Crystal Key is pushed free from that wall and a small scripture is now visible. You read it and realize that you need to activate something at the "Temple of the Dawn". You notice, as you place the key back into your pack that it has literally changed shape.', 1127, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2611, 104513, 'There is a niche in the statue for the Crystal Key the same as the Wall. You place the key into the slot...', 1129, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2612, 104553, 'Use the obelisk to recalibrate the Crystal Key', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2613, 104555, 'The Unas are guarding the area where you can recalibrate the Crystal Key in order to bypass Ihpet''s security system. You''ll need to head toward the western Unas encampment and find your way to a recalibration device..', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2614, 110929, 'This Obelisk looks like a place where you can try to recalibrate the Crystal Key... You enter it into the slot and begin working...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2615, 104562, 'Execute the ritual at the Temple of the High Sun', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2616, 104565, 'The glyphs on the obelisk shift and move. The Energized Crystal Activator worked. The revealed runes indicate that something called the Temple of the High Sun is the next step in the process. Again the key has changed - into a Nascent Crystal Matrix. You need to use this at the new temple.', 1129, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2617, 110931, 'You insert the Nascent Crystal Matrix into the slot on the temple... The glyphs light up and you begin your deciphering work anew...', 1131, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2618, 104572, 'Find another Obelisk to recalibrate the Anamorphic Crystals.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2619, 104573, 'The process worked, but you noticed a shock when you removed the key - now morphed into Anamorphic Crystals. The security system might be adapting itself, requiring recalibration. There is an Unas colony to the east which may have another obelisk.', 1126, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2620, 110932, 'You insert the Anamorphic Crystals. The machine lights up and you begin recalibrating... ', 1132, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2621, 104575, 'Complete the ritual at the Temple of the Dusk.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2622, 104590, 'The Anamorphic Crystals are recalibrated. The glyphs on this obelisk talk about the Ka''s journey to the underworld completing at the Temple of the Dusk - although there are hints that Dusk may have two phases - probably towers to activate. You need to take the Anamorphic Crystals to the Temple of the Dusk.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2623, 110934, 'You insert the Anamorphic Crystals and begin the deciphering process... You know you are close to something truly special...', 1133, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2624, 104601, 'Use the Crystal Entity to open the Ihpet temple.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77825, 'I can help you eliminate the threat.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2686, 18897, 'I expected this news sooner. But still, not a total waste. Leave me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2687, 18900, 'STUB.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2703, 18943, 'STUB.', 1209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2625, 104664, 'The two pieces come together, easily, smoothly - and they form a single entity. You can''t explain it, because it is clearly a hard crystal object, but it seems to be speaking to you. It''s a key - a key to Ra''s massive Ihpet Temple... You just need to find your way there...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2626, 119122, 'The transformation of the crystal key you described is amazing. Do you still have it? ', 1631, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2626, 119123, 'The stone comsumed it. But the temple is open now... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2626, 119124, 'Incredible. We received a report from Lt. Mogilny about energy surges from the structures in the crater. The ritual seems to have energized the entire planet, but the epicenter seems to be the structure you''ve identified as the Mouth of Ihpet. I''m a little nervous about the implications.', 1631, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2627, 39022, 'Resolved with Baal, go see Athena', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2628, 39033, 'The way I see it you have two options. The first option is that you try and get some sort of petty payback against me. I then respond by having you killed.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2628, 39034, 'Player: I''m not fond of that one.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2628, 39035, 'Nor am I. The second option is that we reach an agreement and work together in an uneasy alliance. This way, we both get something. I get a minion and you get to live. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2628, 39036, 'Player: Seems like a win-win to me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2628, 39037, 'Indeed. Now, go see Athena. I have given her your list of duties...', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2629, 18499, 'I manage Baal''s affairs. Know and accept that. He wishes that you to finally meet your Queen. Impress her. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2630, 77676, 'Implant an Op-CORE human with a New Mind symbiote.', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88693, 'There is much to be done... I do not trust this Colonel Marsh, the Op-CORE human. He has his uses - indeed he is quite skilled in ways - but he does not trust us... ', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88694, 'Typical of humans. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88695, 'I want you to infest him with one of my children. Take a symbiote from my tank and isolate him. Your sibling will be inside him within seconds. ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88696, 'You want me to infest Colonel Marsh?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88697, 'Was I unclear? I do not abide by idiotic minions. If Marsh is a host for one of us, he can be controlled. We cannot infest the Jaffa, but the humans are vulnerable to a slow, methodical takeover... ', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88698, 'Is Lord Baal aware of this plan?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88699, 'Why would I involve him?', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88700, 'If he were to discover it without your disclosure...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2631, 88701, 'He might move against me... This is well considered... Inform him of the plan. I cannot imagine he is fool enough to disapprove of it. ', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2632, 77677, 'She wants to infest Marsh? This is exactly the recklessness I warned you of... A bold plan, but one with incredible risk - if it failed the alliance would dissolve and Moh''katan''s Jaffa would collect our heads within hours... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2632, 77678, 'So we are not infesting Marsh...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2632, 77679, 'No. And I will inform Anat of this. However, infesting an Op-CORE member would have intelligence value. We just cannot be exposed... ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2632, 77680, 'Where can it be done discreetly?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2632, 77681, 'The Storage Area... The humans assigned there are often alone and it is a position they give their less favored operatives... Easy targets...', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2633, 88750, 'You collect a symbiote from the tank.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2634, 77683, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2635, 87052, 'Congratulations... Baal has informed me of your ambitious strategy of implanting one of my beloved children into a janitor... I imagine you have come to report this success. ', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2635, 87053, 'I found a highly connected human in the Storage Area.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2635, 87054, 'I am certain we will glean much from this. And by much I mean, absolutely nothing useful. You disappoint me... Do not make this a habit. ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2636, 18550, 'Oh, you''re still here? Perhaps you can please me by not bungling this operation. Plant these listening devices in the Jaffa area of Harset. I do not trust Moh''katan and her gaggle of zealots and i want them watched. Do you think you can manage that?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2636, 18551, 'Player: Yes, my Queen.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2636, 18552, 'Good. See my aide, Petbe. He''ll provide you with a disguise. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2637, 18546, 'Place listening devices in the Jaffa section of Harset.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2638, 18568, 'I have a perfect device for you. It''s clothing that combines with holographic projection technology to make you appear larger. Perfect for simulating a Jaffa. Nerus developed it years ago. I''m surprised our Queen is authorizing you to use it...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2638, 18569, 'Player: Well, she did. So hand it over.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2638, 18570, 'It was my ability to restrain my tongue - something you apparently lack - which has allowed me to raise my station and be the top aide to our queen. Perhaps it''s something you should consider since you seem to be on a path to oblivion. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2638, 18571, 'Player: Yes. You became Anat''s lackey through silence in the face of fools. I''ll mull that over. Now, the disguise?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2638, 18572, 'Petulance...', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2639, 18577, 'Congratulations... You are not a total waste. You have pleased me. Now, be gone and give that fat Nerus the device map so he can monitor the Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2640, 18576, 'Excellent. I''ll throw that in with the rest of the things she wants me to be doing. I have heard of you before, <<playername>>. You are proving yourself to be quite useful.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2655, 89885, 'Our part of this alliance unnerves me... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2655, 89886, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2655, 89887, 'We bring little to the table. Our contribution is not troops or technology, it is guile and know-how. This has value, but it naturally puts us in a weaker position. We need to change this...', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2655, 89888, 'How?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2655, 89889, 'There are System Lords out there with some resources - or at least they used to have resources. An old associate, Morrigan is one possibility. She may be on Tollana, visiting Svarog''s little Goa''uld playpen. She may prove useful to us. Go there and set up a meeting.', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2656, 87067, 'Go to Tollana and make contact with Morrigan.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77820, 'Baal... I have not thought of him for quite some time... I would entertain seeing him, but now is not the time.', 970, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77821, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77822, 'I have word that I am being tracked by a Tok''ra spy. Apparently they believe I exposed an operation of theirs - leading to many of their kind dead.', 970, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77823, 'Did you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77824, 'Of course I did - they''re Tok''ra. You would think they would expect something like this and get over it but, instead, this assassin has made it unsafe for me to venture away from this resort. Whoever they are, they are close... ', 970, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77826, 'Interesting... You look capable enough... Take this blade and meet me near the fountains. I will walk to a vulnerable area and the killer will expose himself - then you will surprise him... Be careful with that knife - it is coated with symbiote poison. ', 970, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77827, 'Symbiote poison... ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2657, 77828, 'Indeed. Even a slight cut will move through your host and kill you - painfully - so be careful. Use it on the killer after you have incapacitated him. Now go - I will meet you at the fountains presently.', 970, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2658, 83106, 'You are certainly a committed servant to Lord Baal. Inform him that I will send an emissary and meet with him - soon. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2659, 18630, 'This screen should have VO.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2659, 18631, 'This screen should have none.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2659, 18632, 'And this screen squealed all the way home.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2660, 89882, 'Did you secure Morrigan''s compliance?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2660, 89883, 'Of course.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2660, 89884, 'Morrigan will make a valuable ally, assuming she has any of her resources left... ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2661, 18640, 'Go make nice with Moh''katan by offering her your services.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2662, 18647, 'Moh''katan and her Loyalist compatriots have been voicing idiotic concerns over being "disrespected" by us. While respecting a Jaffa is a laughable concept, the current political situation requires that we play their game and pretend. That is where you come in.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2662, 18648, 'Player: You do not wish me to do their bidding...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2662, 18649, 'I do, and you will. Now go, see Moh''katan... With respect.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2663, 18655, 'I am pleased to see the New Mind offering the proper respect and I will take you up on your offer of service at once. A family member of mine - Ta''katan - betrayed my clan long ago. I have word that he is on Tollana. My duties here prevent me from reaping my revenge personally, but you can certainly go instead. Find him on Tollana and bring me his head... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2663, 18656, 'Player: You want me to bring you back his head?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2663, 18657, 'I wish to spit in the eyes of his corpse... Unless you cannot stomach the task... I have several in my command who would jump at the opportunity for a fight...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2663, 18658, 'Player: No, I can do it... It sounds fun. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2663, 18659, 'A''rehk traé''ahk ta''kek.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2664, 18661, 'You have impressed me... You possess a warrior spirit I have rarely seen in Goa''uld... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2665, 19557, 'Anise tells player she needs the Eye of Hathor for her research. Describes the artifact. Sends them to the armory.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2666, 19586, 'Malek tells the player there is a side door that is more lightly guarded.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2667, 18667, 'Collect the objects you are "drawn to".', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2668, 19597, 'Anise accepts the Eye and thanks the player.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2669, 18671, 'This place seems to radiate power... I can literally feel it to my core... I will gather objects from here - perhaps analysis will help us define exactly why Ra was able to be so powerful for so long...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2670, 18673, 'These are very interesting artifacts... They are made from the same technology that made the Reins of the Sun Chariot - but how that works is a mystery. For now, keep these discoveries between us... Let''s gather our information before we share it with everyone else.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2671, 18691, 'What are you and Nerus talking about? You are in there, aren''t you?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2671, 18692, 'Player: He was asking me about the listening devices I planted... I was giving him answers.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2671, 18693, 'Hmm... Very well... Just know this - keeping secrets from your queen-mother can be a fatal proposition...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2672, 19158, 'Malek assigns the player to go help Anise with her research.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2673, 19157, 'Malek gives details on Anise and her research and that she requires an object to help her.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2675, 18863, 'Check the city for signs of Jaffa sabotage', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2676, 18819, 'Our intrepid Colonel Marsh has won Anat''s ear. He has whispered a concern about saboteurs and it has birthed a whirlwind of paranoia. In order to help quell this before it becomes paralyzing, I need you to scour the city for anything that validates her fears. If you find anything, inform me immediately. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2677, 18821, 'What is that, over there... That looks suspicious...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2678, 18823, 'I''ll wait here in seclusion... When they come to check on their equipment, I''ll surprise them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18851, 'Please! Please... They gave me no choice. They threatened to kill me if I didn''t set up this device...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18852, 'Player: Who is "they"?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18853, 'Ra''s Jaffa - here in Harset - true believers. Please... I don''t want to die.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18854, 'Player: Why should I spare a traitor?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18855, 'Because I am not who you want. I can give you names - but only if you promise to spare my life. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18856, 'Player: Give me the names, then I''ll decide what to do with you.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18857, 'To tell you the names without an agreement is certain death...', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18858, 'Player: Unless you please me, you''re dead already.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18859, 'Rin''lac and Plea''c. They are the true believers... I have known them since childhood... They are working for Ra.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2679, 18860, 'Player: You may have just saved your own life...', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2680, 18862, 'So Marsh wasn''t just paranoid... Dispatch the traitor immediately... I''ll inform your queen that her fears were well founded. Stand by for further instructions. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2681, 18865, 'See Anat. Immediately.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2682, 18867, 'Come to me. Now. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2683, 18874, 'Baal has informed me of the traitor and his pathetic handlers. You will find these two and execute them. Then leave them where they lie and place this note on each corpse. Let them rot in the sun so all who pass will smell their treachry! I will send a message to anyone who thinks they can threaten me! Do you have anything to add, Baal?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2683, 18875, 'Baal: No. I think you covered it quite thoroughly.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2683, 18876, 'Kill them both and please me. Now go.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2684, 80929, 'Player: Are you Rin''lac?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2684, 80930, 'I am. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2684, 80931, 'You have been convicted of treason against the Praxis. By the order of Queen Anat, your sentence is death...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2685, 18889, 'Player: Plea''c, you have been convicted of treason against the Praxis. By the order of Queen Anat, your sentence is death...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2685, 18890, 'This is outrageous! I have done nothing!', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2685, 18891, 'Player: You have done everything.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2686, 18896, 'Player: My Queen, the conspirators have been eliminated as ordered.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2704, 18945, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2705, 18947, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2706, 18950, 'STUB.', 1173, 0);
