INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2708, 18955, 'STUB.', 1185, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2709, 18957, 'STUB.', 1171, 0);
