INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2716, 18975, 'STUB.', 1179, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2717, 18977, 'STUB.', 1179, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2718, 18979, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2719, 18981, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2720, 18983, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2721, 18985, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2722, 18987, 'STUB.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2723, 18989, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2724, 18992, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2725, 18994, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2726, 18996, 'STUB.', 1175, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2727, 18999, 'STUB.', 1175, 0);
