INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2729, 19003, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2730, 19005, 'STUB.', 1172, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2731, 19007, 'STUB.', 1194, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2732, 19010, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2733, 19014, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2734, 19017, 'STUB.', 1219, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2735, 19019, 'STUB.', 1176, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2736, 19021, 'STUB.', 1176, 0);
