INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2741, 19034, 'STUB.', 1193, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2742, 19036, 'STUB.', 1192, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2743, 19038, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2744, 19040, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2745, 19042, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2746, 19044, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2747, 19046, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2748, 19048, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2749, 19050, 'STUB.', 1171, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2750, 19052, 'STUB.', 1175, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2751, 19055, 'STUB.', 1175, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2752, 19057, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2753, 19059, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2754, 19061, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2755, 19066, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2756, 19077, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2757, 19078, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2758, 19080, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2759, 19085, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2760, 19086, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2761, 19090, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2762, 19093, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2763, 19095, 'STUB.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2764, 19162, 'Malek tells player to help Anise gather more data.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2765, 19163, 'Malek is dissatisfied with Anise''s progress and wants the player to show him the data first.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2766, 19595, 'Anise gives the player a data crystal programmed to search for her data in the Library Computer in the Haven of Glorious Achievement.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2767, 19165, 'Malek notes that the lockdown codes could prove useful and instructs the player to take the other crystal to Anise.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2768, 19596, 'Anise thanks the player.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2769, 19110, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2770, 19116, 'STUB.', 1173, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2772, 19122, 'STUB.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2773, 19145, 'STUB.', 1180, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2774, 19135, 'Meet Lethander in the Market', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2775, 19137, 'Come to the Marketplace... I need you at once. Tell no one.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2776, 19562, 'I found her here. Apparently she is dead, which is problematic.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2776, 19563, 'Player: Did you do this?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2776, 19564, 'Do not underestimate me, <<playername>>. If this was my idea, your head would spin at the elegance of the execution... This was... Thuggery. Probably Ra''s Jaffa in Harset fermenting terror. She may have an idea of who it was who killed her, so we will need to revive her using the Sarcophagus. Take her corpse to Baal and have him ask Anat.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19573, 'Athena''s dead. Oh, the tragedy. And why do I care about this?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19574, 'Baal: You care because she is a valuable advisor to me and the Praxis...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19575, 'But she means nothing to me.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19576, 'Baal: She means something to me, and I wish her to be revived. I am not requesting. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19577, ' Do you forget who I am?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19578, 'Baal: No, I know very well who you are. And you should not forget who I am... Athena is a valuable part of our alliance and I wish her to be revived. Choose your next words wisely, Anat. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19579, 'I have never seen this side of you, Baal. It amuses me... Still, I will grant your request... But know this - I am simply granting a request, not taking an order.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2777, 19580, 'Baal: Use the Sarcophagus to revive Athena, <<playername>>. Go.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2778, 19552, 'I did not see who attacked me, although I am fairly certain it wasn''t Ra''s Jaffa. They were Jaffa, to be certain, but they belonged to that beast, Moh''katan...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2778, 19553, 'Player: Moh''katan? Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2778, 19554, 'Because she dared speak to me without consent and was promptly put in her place. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2778, 19555, 'Player: And for this she had you killed and put the alliance at stake?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2778, 19556, 'She is a Jaffa, <<playername>>. They are no more than animals. She is the worst of their kind - for she is an animal with a brain. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2779, 44180, 'Kill Flax, the leader of the Red Collar, for Opheltes', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2780, 19720, 'Malek assigns the player to help Anise feild test her research', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2781, 19878, 'Grazlak, a friendly Unas from the local tribe, asks the Player for help rescuing his family from Ra''s forces.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2782, 19879, 'Grazlak introduces himself cautiously to the player, he is more intelligent and articulate than the average Unas (being genetically modified) and is scared -- his mate has been culled by the Jaffa and dragged off with other Unas into the Ihpet complex -- this has happened before, but now it is stepped up. As the player seems to be killing Jaffa, Grazlak asks if they would free his wife, and promises the player no trouble.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2783, 19880, 'The player opens the cage and Grazlak''s Mate emerges, but something is wrong. She has no sign of any intelligence inside her, just a brutal violence. She attacks the player.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2784, 19881, 'Grazlak asks what has happened. The player tells Grazlak that his wife died at the hands of Ra''s forces (fudging the fact that the player did the killing). The player leaves Grazlak to mourn.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2785, 19882, 'Breach the Ihpet complex and bring the Ra Jaffa''s plan to a halt', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3002, 110812, 'What?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3501, 115131, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3926, 103817, 'Investigate the safe within the Crypt of Hor-Aha.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2786, 19884, 'The Ihpet stronghold is a major worry. There are signs the Ra Jaffa are focusing their efforts on that location, which has been discovered to be a secret laboratory world of Ra''s. They are planning to somehow resurrect Ra using the technology they have gathered. The player must head into the fortress and stop it. Gathering any other technology in use will give us an advantage in the fight.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2787, 20189, 'Breach the Ihpet complex and bring the Ra Jaffa''s plan to a halt', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2788, 20192, 'Ra''s Jaffa are seeking the return of Ra using technology he kept in secret, especially that on Ihpet. There is not much known about the world except it was a private fortress of Ra''s whose location was lost following his demise. The player is tasked with breaking into Ihpet and applying the Praxis''s symbiote control technology to the process.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2789, 19888, 'The player picks up a Goa''uld tablet reader of notes on the recent experiments performed here.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2790, 19889, 'The player pulls out a handful of components from the crate. These are not standard Goa''uld supplies.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2791, 19890, 'The player acquires what appears to be a drug used in vast quantities in the research.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2792, 19891, 'The journal describes how the believers here have been performing genetic experimentation of all sorts, seeking to improve their utility as soldiers of Ra.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2793, 19892, 'These weapon components look as though they have been broken down and coated with a protein goop, as if destined for implantation in some poor soul by the scientists.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2794, 19893, 'This serum is designed to ease the genetic manipulation process and prevent the rejection of experimental grafts.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2795, 20193, 'Determine the nature of the experiments being conducted here', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2796, 20194, 'The stuff the player has found indicates powerful genetic experiments are being performed here, but on who, and to what end?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2797, 19896, 'The Jaffa show no signs of manipulation. They appear to be normal Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2798, 19897, 'This Unas has been severely modified to increase their speed, metabolism, muscle and neural density.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2799, 20195, 'After discovering the Unas are modified, the possibility for stealing this technology for personal use becomes clear', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2800, 20198, 'It appears as though many different mutations are being experimented with here. As the player heads deeper into the compound, it would be helpful to get ahold of all the different mutations so they can be reverse engineered later.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2801, 20199, 'Look for a connection between this technology and Ra''s resurrection plans', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2802, 20210, 'So far it seems as though this place is a breeding ground for new soldiers, based upon the Unas. This does not answer the question of how they plan to resurrect Ra. The player must continue until they find the answers to those questions.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2803, 19902, 'This equipment is dedicated to the genetic manipulation of the Unas project. According to this, some of the Unas, Mael in particular, have been amplified using "the technology" which Ra kept most secret.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2804, 19904, 'The communications system shows a recent flurry of activity from the Jaffa coming to Ihpet and the worlds the player has visited. The player''s name appears a few times in these communications. The most recent outgoing trasmissions are from Amun, apparently head of this facility, and quote directly from the Amduat.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2805, 19905, 'The sensors show a large amount of Unas and Jaffa within the exterior regions of the complex. The interior beyond the lab, however, is blacked out by some form of interference.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2806, 19921, 'The entire facility is built on top of a Naquadah reserve, which is being tapped into conduits directly in the ground. The power readout shows that almost all of the complex''s energy is being directed into a device deep within the complex, labeld the "Temple of Origins."', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2806, 19922, 'The device receiving the power has to be the technology they intend to revive Ra with... and the fact that it''s operational means it must be active. The player needs to get to it ASAP.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2807, 19912, 'The player bypasses the security on the checkpoint, enabling further access into the complex.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2808, 20212, 'Follow the active power conduit deeper into the tombs to the resurrection device', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2809, 20214, 'The player must trail the power flow to the resurrection device, which appears to be in full swing. These modulators are part of the power system, and disrupting them will damage the device and slow the process.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2810, 19918, 'The player shorts out the modulator. Power surges ahead, but appears to be contained by the next modulator in the series.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2811, 19919, 'The player shorts out this modulator. That worked! Power streams ahead through the system, no doubt overloading the devices further down the line.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2812, 20215, 'Destroy the resurrection machine', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2813, 20216, 'There is no time for anything fancy. The resurrection of Ra appears to be going on right now. The player needs to stop it, at any cost.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2814, 20219, 'Survive', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2815, 20220, 'Unfortunately, Ra is returning.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2816, 20221, 'Give your report on the Ihpet mission', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2817, 20224, 'Ra is back, and his men have been building armies in secret during his absence. The player must bring back this news to the SGU immediately. The SGU will be tested by war.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2818, 19928, 'The player''s report convinces O''Neill, at first incredulous, of the reality and new danger. O''Neill and the other SGU leaders decide to mobilize the SGU''s allied forces immediately to potential targets of Ra. The player is congratulated for surviving the mission, any criticism of the player is left unsaid. The player is told that vey soon there will be new missions, and they are unlikely to cease any time soon.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2819, 19931, 'Carter is only mildly interested in the Unas genetic samples. Genetic modification is a dangerous process, especially given the propensity of those modifications to have unforseen side effects. Still, if a common technological thread can be found it may give some answer as to why we''re only seeing these now.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2819, 19932, 'The shattered Reins of the Sun Chariot are much more intriguing. They are obviously not Goa''uld in origin, and they also do not appear to be Ancient. They are much more, and simultaneously much less. Carter remarks that the device appears to be naturally designed for transmission, but from what, and to what, and to what purpose? Her team is unlikely to restore it, but she can make some obvious fixes, given enough time.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2820, 20225, 'Give your report on the Ihpet mission', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2821, 20227, 'Ra has returned, without any restraints holding him back. This is not good. The Praxis needs to be warned, and every attempt made to cut off his attempts to regain galactic dominance.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3055, 91882, 'The disease really seems to be crippling those infected.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2822, 19937, 'Ba''al and Marsh have already learned of Ra''s return when the player arrives. Armies and ships have begun moving, open galactic war is at hand. There is nothing that can be done except stay alive and look for an opening. Ra was defeated once by luck, he is unlikely to underestimate humanity again.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2823, 19939, 'Nerus has seen something like this, but only once, while working for Ma''at, one of Ra''s most trusted scientists. It was not something he was supposed to have seen. It''s badly damaged, which he blames the player heavily for after learning how it came into their posession, but he thinks he can do something with it. The player is right in guessing that it is neither Goa''uld nor Ancient. Still, Nerus feels a certain amount of... affinity for the device.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2824, 19940, 'Copplemann appreciates the genetic samples the player has brought back. The most likely result is a bioweapon, but Copplemann also believes that the New Mind might figure out ways to beef up our genetic engineering programs. Of course, such mods would be entirely voluntary, of course.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2825, 20229, 'Return to the ruins of Ihpet and shut down the Straegis signals coming from there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2826, 19719, 'Malek tells player about Anise''s progress on her research and that he wants to attempt a field test using the lockdown codes from the previous mission.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2827, 20231, 'We have been working with the Asgard and Goldam on Agnos to track the signals by which the Straegis communicate in the hopes of finding the source of Ra’s control over them. You’re not going to like what they found. It seems the signals are coming from the direction of Ihpet. We’re sending you back to check it out and deal with it as you see fit. We could use the opportunity to land a killing blow to the Straegis. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2827, 20232, 'O''Neill explains how the player is going get into Ihpet the second time.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2828, 19960, 'The area further ahead shows signs of intense radiation. Additional protective measures will be required. Player automatically attempts to contact the SGU for delivery, but the signal is overwhelmed by chaotic interference.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2829, 19959, 'This Jaffa has succumed to severe naquadah radiation posioning which overwhelmed its symbiote as well. However, he carries a communications sphere.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2830, 19953, 'The player uses the communications sphere as a means to cut through the interference and radios back for additional anti-radiation supplies.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2831, 19971, 'The player picks up some radiation gear and an injector of Androstenediol, a potent anti-rad drug.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2832, 20233, 'Return to the ruins of Ihpet and shut down the Straegis signals coming from there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2833, 19885, 'Anise informs player she is ready for field test but is cryptic about it''s nature. She insists Palab go along to supervise the test.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2834, 20234, 'Nerus and Copplemann have been hard at work tracking the signals by which the Straegis communicate in the hopes of finding the source of Ra’s control over them. You’re not going to like what they found. It seems the signals are coming from the direction of Ihpet. We’re sending you back to check it out and deal with it as you see fit. We could use the opportunity to land a killing blow to the Straegis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2834, 20235, 'Marsh explains how the player is getting back to Ihpet a second time.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2835, 19968, 'The area further ahead shows signs of intense radiation. Additional protective measures will be required. Player automatically attempts to contact the Praxis for delivery, but the signal is overwhelmed by chaotic interference.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2836, 19967, 'This Jaffa has succumed to severe naquadah radiation posioning which overwhelmed its symbiote as well. However, he carries a communications sphere.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2837, 19969, 'The player uses the communications sphere as a means to cut through the interference and radios back for additional anti-radiation supplies.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2838, 19972, 'The player picks up some radiation gear and an injector of Androstenediol, a potent anti-rad drug.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2839, 20236, 'Begin your expedition at the remnants of the Unas Compound', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2840, 20237, 'Much has changed here, but the buildings of the compound can still be made out. No better place to start than there. If the Jaffa are dead, then what of the Unas?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2841, 19977, 'Grazlak is suprised to see the player alive. The player demands to know what Grazlak knows of the Straegis. What Grazlak says is after the explosions, many Unas were taken deep by the Goa’uld and the Straegis. The player asks about the Straegis and Grazlak reveals he has been to where there are many Straegis, and offers to lead the player there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2842, 20238, 'Stifle the radioactive exhaust hindering your movement', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2843, 20239, 'These thick radiation clouds are too much except for an Unas to cross. It needs to be cleared or redirected temporarily.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2844, 19981, 'The player diverts the exhaust into another tunnel, hopefully it will not overflow or backup while the player is exploring.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2845, 20240, 'Dispatch these genetically modified Unas Goa''uld and proceed further', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2846, 20241, 'It appears as though conditions have forced the Goa''uld who survived your last visit to abandon their human hosts and take those of the modified Unas. They are blocking the path Grazlak took.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2847, 20242, 'Get through the Straegis Fighter perimeter and into the former Genetics Lab', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2848, 20243, 'Ahead are Straegis guards. Ra’s device must be within this section of the complex. But the only way through could be… painful.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2849, 19986, 'Grazlak apologizes for running ahead, but Ra''s men know nothing of his dealings with the player. The Player asks about the Straegis and Grazlak does not know much but the ones at the front will fight, but not all of the ones inside. And they see Grazlak as friend, not foe. The Player asks Grazlak to leave a satchel charge by the Straegis so they can make forward progress. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2850, 19989, 'Grazlak brings the explosives to the Straegis, then runs off again.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2851, 20244, 'Check out the new reactor that has been placed in this lab', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2852, 20245, 'The old genetics lab seems to have been pushed aside in favor of a new, toxic looking reactor. This thing looks like it would go off if you looked at it funny, let alone set off some high explosives.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2853, 19992, 'This reactor is redlined on every scale. It is running full tilt to power something that makes the resurrection chamber look like a toaster oven. It seems extremely vunlerable.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2854, 20013, 'The player plants a demolition charge at this end of the reactor and rigs it for remote radio detonation.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2855, 20012, 'The player plants a demolition charge right up against the containment shield generator. They won''t fail at taking out this facility a second time.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2856, 20246, 'Shut down the gigantic Straegis signal generator and all the other Straegis tech present', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3844, 107727, 'I have a lot to do...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2857, 20247, 'In the middle of the former lake now stands this monstrosity. This has to be the device Ra has been using to control and command the Straegis, possibly across the entire galaxy. It seems as though more are being "born" by the second and being sent via their portals to other worlds. Destroying it could mean the end of the war.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2858, 19999, 'Grazlak knows little except the Straegis go through the portal and don’t come back.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2859, 20000, 'This portal is like those initially used by Ra to send the Straegis across the galaxy, but it is very powerful. The best the player can accomplish is retargeting the Portal to not leave the planet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2860, 20001, 'The machine gives way to the player''s efforts, and hangs still in the air for an endless moment before crashing down to the ground. The crater erupts in the cacophonous sound of the Straegis, to put it bluntly, "freaking the heck out."', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2861, 20248, 'Ensure Ra will be unable to rebuild these devices again by preparing to blow Ihpet sky high', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2862, 20249, 'Ra picked this world because of the Naquacite that feeds the Straegis technology, and has been doing nothing but making tons of it non-stop. Even with the machine damaged, the odds of him rebuilding are too high to risk keeping this planet open for business. But what of the poor Unas who are still trapped here? What wrong have they done?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2863, 20005, 'The player calls the SGU on the radio and explains that the Song machine seems to be halted, but the area has too many resources for Ra to come back to. O’Neill asks if that can be dealt with, the player responds in the affirmative, but that there are still Unas on the planet. O’Neill accepts responsibility and orders the players to blow the store.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2864, 20021, 'The player alters their charge to a timed detonation. Radio is unlikely to keep a strong enough signal after the player leaves.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2865, 20024, 'The player alters their charge to a timed detonation. The Straegis will be too disoriented to deal with the explosives, and if the player climbs back up the way they came they ought to stop any of the Goa''uld from discovering the bombs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2866, 20250, 'Ensure Ra will be unable to rebuild these devices again by preparing to blow Ihpet sky high', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2867, 20251, 'Ra picked this world because of the Naquacite that feeds the Straegis technology, and has been doing nothing but making tons of it non-stop. Even with the machine damaged, the odds of him rebuilding are too high to risk keeping this planet open for business. It will, however, mean that any other secrets here will be lost. But that is a feeling the player already knows well.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2868, 20019, 'The player informs Marsh that the Song generator has been taken out, but to keep it from being rebuilt they intend to take out the whole fortress. Marsh salutes the player''s courage, but double-checks with them that they will keep the explosives from being disarmed and to not prioritize their own safety over the completion of their mission.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2869, 20022, 'The player alters their charge to a timed detonation. Radio is unlikely to keep a strong enough signal after the player leaves.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2870, 20023, 'The player alters their charge to a timed detonation. The Straegis will be too disoriented to deal with the explosives, and if the player climbs back up the way they came they ought to stop any of the Goa''uld from discovering the bombs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2871, 20252, 'Return to the surface exit, being careful to not leave any chance of the explosives being defused', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2872, 20253, 'The player must return the way they came, and make it to the extraction point just as the bombs go off. It is the only way to stop Ra.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2873, 20030, 'The player tries to tell Grazlak to flee if they value their lives. In response Grazlak says the player tried to kill his son before, and killed his wife. In their memory he will enjoy killing the player as their world collapses.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2874, 20254, 'Report the destruction of Ihpet and the Straegis technology there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2875, 20255, 'Ihpet is no more. The Straegis Song pushed by Ra has been silenced, at least assuming that was the only one in existence, and his main source of Naquacite has been destroyed. All in all, a good day''s work.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2876, 20036, 'O''Neill congratulates the player and provides them with the next mission. There is, unfortunately, no time to celebrate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2877, 20256, 'Report the destruction of Ihpet and the Straegis technology there', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2878, 20257, 'Ihpet is no more. The Straegis Song pushed by Ra has been silenced, at least assuming that was the only one in existence, and his main source of Naquacite has been destroyed. All in all, a good day''s work.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2879, 20037, 'The Player reports success to Ba’al and Marsh, who debate over where to send the player next, then give them their next mission.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2880, 20258, 'Check out the technology in the explosives used by the Unas', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2881, 20263, 'The Unas were chucking some pretty heavy explosives your way. It might help to find out what they''re made out of.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2882, 20040, 'Your analysis reveals the device is using Naquadria. Naquadria wasn’t detected here on the last visit. It’s a rare, highly unstable, radioactive and powerful Naquadah isotope. This must mean a significant change in the minerals on Ihpet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2883, 20262, 'Investigate the armor used by the Unas Goa''uld for connections to the Straegis technology', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2884, 20264, 'This armor was worn by the Unas Goa''uld, and it looks similar to the Straegis. What’s it made out of?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2885, 20043, 'Your anaylsis reveals the armor to be some sort of altered Naquacite. The Straegis vibrations appear to be affecting the Naquacite in a similar fashion as their own bodies and beacons, but to a lesser degree. The Straegis energy gives the Naquacite material properties not normally found in nature.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2886, 20266, 'Take a closer look at this reactor for clues as to its operation and purpose', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2887, 20265, 'Perhaps we can glean more about the retooling of this facility from checking out this reactor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2888, 20047, 'This is a highly toxic reactor that’s working off of Naquadria, an unstable isotope of Naquadah only previously seen on Kelowna, caused by a chain reaction within vast underground Naquadah deposits. Working backwards, it seems possible that the disaster caused during your last visit turned some of the remaining Naquadah into Naquadria. Such a reaction would have created large quantities of Naquacite as well.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2889, 19887, 'Palab tells the player to go to the security terminal and that he will signal them when the Jaffa arrive.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2890, 20099, 'STUB.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2891, 20848, 'Stub.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2892, 21073, 'Player. Thanks.', 1302, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2892, 21074, 'We need to get the hell out of here.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2892, 21075, 'We can''t just leave.', 1302, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2892, 21076, 'Why the hell not?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2892, 21077, 'Because the planet is at stake.', 1302, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2892, 21078, 'You know as well as I do that the SGC is going to be setting off the Nuclear failsafe. That''s S. O. P.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2892, 21079, 'If they could have, they would have done it already.', 1302, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2893, 21038, 'Thanks for the save player.', 1301, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2893, 21039, 'We need to get out of here.', 1300, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2893, 21040, 'Player: Where''s General O''Neill?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2893, 21041, 'Dead most likely.', 1300, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2893, 21042, 'All due respect, we don''t know that. If he''s alive, he''s headed for the Failsafe.', 1301, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2894, 21045, 'They''re going to kill those hostages if I don''t do something fast.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2895, 21047, 'Those are our guys, but it doesn''t look like they can hold off for much longer.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2896, 21049, 'Our guys are dead if I don''t act quickly.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2897, 21051, 'Those are our guys pinned down there!', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2898, 22146, 'I have no desire to return to a tank. We shall go and come back with greater force.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2899, 22141, 'Looks like we''ve got to get going.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2900, 21461, 'Victory here won''t mean anything if the Pentagon and the IOA nuke the mountain from above.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2901, 21459, 'The Beacon''s down. We should tell get word to Hammond so he can call off the strike.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2902, 21436, 'The Beacon is down. The Straegis are defeated. There''s time to stop the O''Neill from setting off the failsafe.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2903, 21432, 'Get back to O''Neill.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2904, 20740, 'I need to look for survivors and get rid of any Straegis I find.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2904, 20741, 'If the SGC doesn''t resolve this foothold situation, the IOA and the Pentagon will resort to nuclear measures.', 1299, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2905, 20737, 'We need to get rid of all the Straegis in the SGC', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2906, 20757, 'The Pentagon and the IOA are going to flatten the mountain if the Straegis aren''t taken care of.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2906, 20758, 'But first things first. I need to get what I need and get out quickly.', 1299, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2907, 20733, 'The Straegis need to be eliminated.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2908, 20376, 'There is a power-grid relay panel here. With some careful wiring, if someone threw the main circuit breaker on this level, everything in between should get electrocuted.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2908, 20377, 'The crystals should pass the power along, hopefully frying everything. This could work.', 1299, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2909, 20367, 'The Straegis seem to be using crystals to tap into the power grid. This gives you an idea...', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2910, 20380, 'There is a power-grid relay panel here. With some careful wiring, if someone threw the main circuit breaker on this level, everything in between should get electrocuted.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2910, 20381, 'The crystals should pass the power along, hopefully frying everything. This could work.', 1299, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2911, 20369, 'The Straegis seem to be using crystals to tap into the power grid. This gives you an idea...', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2912, 21266, 'The Failsafe room is secure?', 1304, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2912, 21267, 'It is now. What''s our next move?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2912, 21268, 'Give me a second to evaluate our situation.', 1304, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2913, 21260, 'We need to control the Failsafe room. I don''t want to have to blow this place up if I don''t have to, but we might not have a choice.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2913, 21261, 'I can''t let them blow up the SGC either.', 1304, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2913, 21262, 'I''ll check it out and secure the room.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2914, 21124, 'The Armory''s close by. They don''t seem to be too interested in our guns. We should be able to hide out there for a bit.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2915, 21106, 'I don''t know if General O''Neill is alive or not. If he is, he''ll try and set off the Failsafe if he thinks we can''t control the situation.', 1301, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2915, 21107, 'I''ll try to find him. What about you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2915, 21108, 'I''ll get Mr. Woolsey and everyone else out. Hammond''s in command on the surface?', 1301, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2915, 21109, 'He is.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2915, 21110, 'I''ll try to get him to buy you some time. I can''t guarantee anything.', 1301, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2915, 21111, 'Understood. Good Luck.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2916, 21113, 'This isn''t an easy situation, Playername. It isn''t hopeless yet though.', 1301, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2917, 21426, 'And how can Earth be a resource?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2917, 21427, 'This world is an asset to your OpCore allies and the humans of this world can provide hosts.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2917, 21428, 'I have decided that we will claim this world as our own. The straegis must be dealt with.', 1310, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2917, 21429, 'I agree', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2917, 21430, 'Take care of them.', 1310, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2918, 44409, 'Earth can be a great resource you say? Do go on.', 1310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2919, 21411, 'I''m going to activate the nuclear failsafe. I don''t like it. I don''t think you do either, but it needs to be done.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2919, 21412, 'Sir, I think I can stop the Straegis.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2919, 21413, 'That''s what I''m counting on. Once you leave here, You''ll have about 20 minutes to stop the Straegis and get back to me.', 1304, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2919, 21414, 'Right, Sir.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2919, 21415, 'Well? Get going. Walter and I will see you in the Failsafe room.', 1304, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2920, 21405, 'The Straegis can''t take the SGC and the Pentagon can''t blow up the mountain. I have a plan', 1304, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2921, 21651, 'We''ve been able to hold off the aliens so far, but we haven''t been able to push into the tunnel.', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2921, 21652, 'I''ll take care of it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2922, 21705, 'There are two ways in. The hard way and the harder way. Do you think you can get past the aliens here?', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2923, 20359, 'We''ve been able to hold the aliens off so far, but we cannot do it forever.', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2923, 20360, 'Player: I''ll take care of it, Sir.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2923, 20361, 'I appreciate your valor, but I don''t want to send someone in on a suicide mission. The entrance tunnel''s become a gauntlet.', 1298, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2923, 20362, 'Player: I''ve had some experience with these aliens, General. I''m confident I can get into the SGC.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2923, 20363, 'If you''re sure then, Playername. I''ll try and buy you some time with the Pentagon and the IOA. They might reconsider using nuclear force.', 1298, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2924, 20348, 'Do you feel like you''re up to the task, Playername?', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21812, 'We are facing a critical situation here.', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21813, 'I know. We''re going in.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21814, 'The will not be happy you decided to interfere.', 1298, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21815, 'You car what the NID thinks?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21816, 'Look. It''s suicide to go in, but if you''re determined, I can''t stop you. I have bigger issues to worry about.', 1298, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21817, 'Thank you general.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3844, 107728, 'As do I... So... ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21818, 'If we resolve the situation and we find you in there, we''ll be forced to turn you over to the NID.', 1298, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2925, 21819, 'Understood.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2926, 21584, 'What are the Praxis, doing here?', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2926, 21585, 'We''re here for our people.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2927, 20333, 'These Aliens have taken over most of the SGC. Now, we''ve still got people down there, but we have no way of knowing what shape they''re in.', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2927, 20334, 'Player: Is there a way in, Sir?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2927, 20335, 'I''m not sure I feel comfortable sending more people in. The Pentagon and the IOA are considering dropping the mountain on the Stargate.', 1298, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2927, 20336, 'Player: I''m confident I can save the SGC, Sir.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2927, 20337, 'You''d be saving Earth too. Well, you''ll need some pretty fancy hacking skills, but you could try the emergency access hatches.', 1298, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2928, 20343, 'Good to see you Playername. We''re facing a difficult situation.', 1298, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2929, 21369, 'Have you been successful?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2929, 21370, 'I was. However we have an opportunity.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2930, 21350, 'They will pay for their transgressions!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2930, 21351, 'Of course they will.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2930, 21352, 'We will destroy them.', 1310, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2930, 21353, 'Actually, I know just how. The Nuclear Failsafe. If I secure that, we will be able to control the SGC. Or blow it up if we want.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2930, 21354, 'That is acceptable. Go. Secure the means of their destruction.', 1310, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2931, 21313, 'Once we secure the failsafe we can leave.', 1302, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2931, 21314, 'We need to get out of here.', 1303, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2931, 21315, 'I''ll secure the failsafe.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2931, 21316, 'You''re sure?', 1302, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2931, 21317, 'I can do it. Besides I have another task here for OpCORE.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2931, 21318, 'I''ll lead us out of here.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2931, 21319, '... Good luck.', 1302, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2932, 21277, 'We need to secure the Failsafe.', 1302, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2933, 41955, 'You were not deceiving me, <<Playername>>. This area is rife with challenging targets... Make sure you stay alert - the Tollan is a dangerous animal...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2934, 106483, 'Take the news of Ra''s invasion of Yotunheim to the Council.', 1327, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2935, 106484, 'You activate the transmission - immediately you notice a data stream. Is that a gate address?', 1327, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2935, 106485, 'Minions. I have made a discovery of great importance. The Asgard have, in their possession, a weapon of great power - a weapon that only a God could possible wield. Called the Solocris, this dormant power is my destiny.', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2935, 106486, 'He who recovers the Solocris for me from the wasteful Asgard at Yotunheim will live in my graces throughout eternity at my side. Proceed there in great haste, this order is of the highest priority.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2935, 106487, 'What follows is a series of replies by Ra''s Goa''uld - proceeding there in great numbers. The date places this transmission just three days before.', 1327, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2936, 106488, 'Unused dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79280, 'He has quite an inflated opinion of himself...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79281, 'That is an understatement.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79282, 'The Solocris is not a weapon, but rather a misguided solution to a problem forseen by the Alliance of the Four Races many, many years ago. It was designed by the Asgard as a potential Fifth Race.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79283, 'Fifth Race?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79284, 'The eventual replacement for the Alliance of the Four Races... Humanity was our "Fifth Race", and the Furling had their own answer. The Nox believed that entropy would provide a replacement.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79285, 'What happened?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79286, 'The Solocris wasn''t designed to evolve, so it came online first. It was brilliant, but unstable, causing tremendous harm. The Asgard genome was mutated by it. That some survive today is a testament to their fortitude. Ultimately the decision to terminate it broke the Alliance apart. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79287, 'And if Ra gets it?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2937, 79288, 'If he can activate it and - help us all - control it, he would have a weapon beyond anything you can imagine... He must not get his hands on it.', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2938, 115799, 'Yotunheim? We have received no distress transmissions from the garrison there. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2938, 115800, 'Is that the correct Gate Address?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2938, 115801, 'This is most disturbing. Yotunheim is more than a mere world. It is a secret.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2938, 115802, 'Have you heard of this Solocris, Thor?', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2938, 115803, 'No, but this does not mean that Goldam is incorrect. Because we do not "die" the Asgard have limited memory capacity. Certain memories are recorded and then moved to storage for later access. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2938, 115804, 'Yotunheim is a memory bank?', 2568, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2938, 115805, 'No. In the case of great secrets, we would restrict those memories. Yotunheim is the location for all of our greatest secrets. Only those assigned have access to those high-security memories. It is possible this "Solocris" is there.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2939, 106499, 'UNUSED DIALOG', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2940, 106496, 'UNUSED DIALOG', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2941, 106497, 'UNUSED DIALOG
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2942, 103220, 'Congratulations. Work on converting the Tower seems to have halted. In the course of her reacting to you at the Power Facility, I was able to get access to some of her primary systems. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2942, 103221, 'You''re in control now?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2942, 103222, 'Not yet, but I was able to access the communications processors. I discovered something there of grave importance. Brace yourself, because you''re about to get another lesson in living history. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2943, 103253, 'Take the news of Ra''s invasion of Yotunheim to the Council.', 1327, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2944, 103255, 'You activate the transmission - immediately you notice a data stream. Is that a gate address?', 1327, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2944, 103256, 'Minions. I have made a discovery of great importance. The Asgard have, in their possession, a weapon of great power - a weapon that only a God could possible wield. Called the Solocris, this dormant power is my destiny. ', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2944, 103257, 'He who recovers the Solocris for me from the wasteful Asgard at Yotunheim will live in my graces throughout eternity at my side. Proceed there in great haste, this order is of the highest priority. ', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2944, 103258, 'What follows is a series of replies by Ra''s Goa''uld - proceeding there in great numbers. The date places this transmission just three days before. ', 1327, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114686, 'He has quite an inflated opinion of himself...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114687, 'That is an understatement.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3054, 54165, 'Even if you find a cure for the sickness you will need to find an antidote to Dakor, whose words poison my people faster than any disease could. ', 716, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114688, 'The Solocris is not a weapon, but rather a misguided solution to a problem forseen by the Alliance of the Four Races many, many years ago. It was designed by the Asgard as a potential Fifth Race.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114689, 'Fifth Race?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114690, 'The eventual replacement for the Alliance of the Four Races... Humanity was our "Fifth Race", and the Furling had their own answer. The Nox believed that entropy would provide a replacement.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114691, 'What happened?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114692, 'The Solocris wasn''t designed to evolve - it was a machine, afterall - so it came online first. It was brilliant - exceeding expectations... However, it was also remarkably unstable, causing tremendous harm. The decision to terminate it broke the Alliance apart.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114693, 'And if Ra gets it?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2946, 114694, 'If he can activate it and - help us all - control it, he would have a weapon beyond anything you can imagine... He must not get his hands on it.', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114695, 'Your work on Agnos was outstanding... We dealt Ra a blow there. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114696, 'This Solocris intrigues me. What more do you know of it?', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114697, 'Nothing more than what Goldam told me.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114698, 'Yotunheim is something previously unknown to the Goa''uld. It is not part of the old Protected Planets Treaty. Instead it is a place the Asgard have tried to keep secret. This feels like a tremendous opportunity. If Ra can use the Solocris, so can we.', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114699, 'It is a risk to send anyone into an Asgard facility. We cannot muster the forces for a full-scale attack in a short time. It will take weeks to marshal our forces. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114700, 'Ra has already attacked so we are already short on time... However, we can break the mission down into a classic smash-and-grab. We go in, identify where the Solocris is, recover it and leave. ', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114701, 'This is a plan I like. We let Ra''s own forces engage the Asgard and we pull it from under their noses... The Solocris will be the turning point in our fight against Ra... ', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114702, 'Who do we send in there? ', 968, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114703, 'This opportunity is an honor, and I can think of only one who has earned it... ', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2947, 114704, 'It will be a pleasure. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2948, 21575, 'General Hammond? The threat has been contained.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2948, 21576, 'I''m going to need you to stand down. My people should be there in another few minutes. You''ll do us all a favor if you just stand down and wait there.', 1299, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2948, 21577, 'Thank you for the gracious offer, general. However I do not believe we will take you up on it.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2948, 21578, 'I believe this is our opportunity to exit. Unless you want to be put into a tank again.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2948, 21579, 'This world will be of use to us, but for now I believe you are correct. We will return with greater forces.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21550, 'This is Hammond.', 1299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21551, 'Sir? We''ve shut down the Alien incursion. I''ve found General O''Neill.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21552, 'Good work. May I speak with General O''Neill?', 1299, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21553, 'I''m here sir.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21554, 'What''s the situation?', 1299, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21555, 'Under control sir. I wont be using the failsafe.', 1304, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21556, 'General O''Neill! I insist that you answer to the IOA immediately!', 1300, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2949, 21557, 'General? Keep in touch. O''Neill out.', 1304, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2950, 115385, 'Tynan... The fool... Should have stopped you... But you will never stop Ra...', 675, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2950, 115386, 'Ra?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2950, 115387, 'Ra.', 675, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2951, 106081, 'Tynan sold us out to the Goa''uld... I should have seen it, but i trust people too much... His brother was a xenophobe, but Brannigan swore he didn''t share those sympathies. I didn''t believe him, but... I had hoped he could be professional.', 671, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2951, 106082, 'What will happen to him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2951, 106083, 'He''ll be arrested for treason, just as soon as I fill out the proper forms...', 671, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2951, 106084, 'And Tech Secure?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2951, 106085, 'They are under the Tech Con umbrella until we can get Burtonol sorted out... We have to dig into the conspiracy and see how far it goes... That will take time.', 671, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2951, 106086, 'More forms?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2951, 106087, 'This is Hebridan, that is who we are. In the meantime, would you please inform Commander Caelan that she is in charge of the defense operation? I know I can trust you, and that''s more than I can say for my own organization right now...', 671, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2952, 106383, 'The encryption is easy enough to break and indeed it reveals a hidden note: ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2952, 106384, '"I can''t speak openly with Burtonol around. I don''t trust them. They''re certainly not looking out for Hebridan, or they''d have mobilized all their forces."', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2952, 106385, '"Just before the attack, they threw a shipment of sports drinks into the TechTrash Collection bins and replaced it with another shipment. Definitely not bottles of flavored water. I don''t think they wanted anyone to notice."', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2952, 106386, 'You take note of the location of the shipment.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2953, 106390, 'The crate suffers from a shoddy job of concealment: Labels for "TechCon UltraQuench" have been sloppily plastered over the top of a "RepliTech" logo. Inside you see some of the Replicator-based technology. ', 689, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2953, 106391, 'You decide to disable the replicator tech within the crates... These can''t be allowed to get off-world. ', 689, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2954, 106393, 'You short out a naquadah cell inside the crate - within a few minutes all the little replicator blocks will fuse together into a massive pile of useless alloy. ', 689, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2955, 22386, 'Not Visible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2956, 106911, 'Tynan... Should have stopped you... You will never stop Ra...', 675, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2956, 106912, 'I beg to differ.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2956, 106913, 'You will be begging soon enough... I die in his glory. ', 675, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2956, 106914, '(Devlin dies... Pathetically.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2957, 107219, 'You manage to hack into the system. There is no mention of the Reins of the Sun Chariot... In fact, there isn''t much here at all. You find references to the Lucian Burtonol Campus which mention massive budget increases.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2957, 107220, 'Everything seems to flow through an executive called Rychen. If he is not a Goa''uld, he is actively working with them in support of Ra. ', 687, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2957, 107221, 'Devlin was also in charge of a division called "RepliTech", a secret project designed to harness Replicator technology for use by Ra. ', 687, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2969, 107476, 'This is the system Cyric referred to. You insert his ad''s data card and prepare the uplink.', 695, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2970, 107478, 'The upload finishes. Now an ad extolling the benefits of a world defense strategy based on mercenary security companies will be broadcast... As you watch you notice that you get caught up in the rampant, empty jingoism. ', 695, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2970, 107479, 'It strikes you... This ad is a lie. TechSecure has done the opposite of what this video implies. They aren''t fighting, they''re sitting. Do believe this stuff?', 695, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2971, 107527, 'The crate suffers from a shoddy job of concealment: Labels for "TechCon UltraQuench" have been sloppily plastered over the top of a "RepliTech" logo. Clearly this is a black market technology shipment... Best get this to Harset.', 689, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2972, 102588, 'Fold this operation for Laro into your Beta Site assignment, $name$. There''s no shortage of Straegis there... But keep in mind, the Beta Site mission itself takes priority.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2973, 95511, 'As the Storage Receptacle reaches maximum capacity, you notice unusual sonic transmissions eminating from a non-standard source. You reasonably decide to report this anomaly to Mimir.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2974, 49363, 'Unused dialogue', 752, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2975, 49821, 'You manage to get inside the drone and notice a small crystalline device attached to the drone''s AI unit - certainly not standard equipment for a medical drone. You pocket the device and resolve yourself to searching the rest of the infirmary for signs of sabotage. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2976, 90477, 'You discover a surprisingly complex piece of hardware buzzing happily. Given the guards that were surrounding it, this is no doubt the jammer, but it seems remarkably advanced for the Nine Peaks clan. You begin to disable it.', 724, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2978, 96700, 'The fire will destroy this tretonin before it could harm any Jaffa and will not spread.', 2426, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2979, 96720, 'Lo and behold, fair servants of the Sun God. Find, behind this wall, great power which unlocks the chariot of the mighty and omnipotent Ra. His might is therein contained and shall be removed only by those worthy. ', 813, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2980, 65347, 'My son is a victim. That device - that obelisk - affected his mind. It infected him with visions. Visions of Ra and demon beasts coming to destroy him, coming to destroy me... I tried to help him, but he was infected...', 817, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2980, 65348, 'How''d you end up here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2980, 65349, 'The Ra cultists arrived - or revealed themselves - they may have always been here. They told my son that if he did not submit, the visions would come to pass. When he resisted they took me. I do not know what they told him, but I know this broke him...', 817, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2980, 65350, 'How?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2980, 65351, 'They showed me. They took great delight in showing me my son''s manipulation... And they killed him. You may have done the deed, but they took him from me before you even arrived here.', 817, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2980, 65352, 'I''m sorry for your loss.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2980, 65353, 'You will want to disable that machine... It is evil...', 817, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2981, 96766, 'The technology is similar to the other crystal tech you have seen - incredibly advanced and hard to understand. You begin to try and shut it down for transport back to the Administration Building.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2982, 96106, 'The last thing you remember is going into stasis after another session with that sadist, Romney. Always the same question: "Where is Colonel Marsh?" - the same question you''ve been asking yourself for four years...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2982, 96107, 'But now you are free - and awake. But where are the guards? If this is an escape - and you hope it is - you need to find a weapon. Quickly. Perhaps there''s something on those corpses nearby...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2996, 110243, 'You scan through the files, gathering information. Podhertz is apparently some sort of genius - he invented the process for making corn into Kassa and it has inflated his ego. You download as much of the scientific data about Podhertz''s process as you can: Information like this could prove to be very useful to the Praxis. ', 394, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2996, 110244, 'You hack into the network and identify Podhertz''s personal machine. You isolate the location and download it to your PDA. The rest should be easy...', 394, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2997, 90618, 'The cages appear to have been broken into by means of a very primitive - almost home-made - explosive. There is a significant amount of a strange brown residue - probably the explosive - surrounding the cage. Assuming the materials in the residue are unique enough, it may possible to track the culprits back to their hideout.', 395, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2998, 110755, 'Timely work, $name$. Ra''s fleet is over Dakara as we speak. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2998, 110756, 'Can we use the Reins of the Sun Chariot to control his fleet?', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2998, 110757, 'That idea crossed my mind as well. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2998, 110758, 'And mine. If the device is as powerful as we suspect, this could make Ra''s power ours. ', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2998, 110759, 'Then we are all in agreement? We test the Reins on Dakara.', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (2999, 110785, 'You notice that Jordin''s tent includes a Goa''uld Sarcophagus, as well as other trinkets. Jordin is either a Goa''uld herself or has close ties to one. ', 1358, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3000, 110786, 'Hello, $name$. And what brings me this unmitigated pleasure?', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3000, 110787, 'I may have located one of our own hiding here on Lucia. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3000, 110788, 'A Goa''uld in hiding? How dramatic! I suppose you want some help in solving this mystery, yes?', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3000, 110789, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3000, 110790, 'I''m uploading to your PDA a scanning algorithm Nerus built to detect Tok''ra. We''ve modified it to scan a human for any symbiote type. It will do a full-body scan of the host and symbiote and beam me the data directly. However, to use it you will need to get close to him...', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3000, 110791, 'It''s a female.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3000, 110792, 'Scandalous! I''ve often thought of taking over a human female myself... Regardless, you''ll have to get close to her and have a short conversation. The PDA will buzz when you have acquired enough data.', 978, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110802, 'Ah, a stranger! And what brings you to see me, dear one?', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110803, '(You activate the PDA scan)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110804, 'Of course you have heard about me. Do you know why? Because I - and my followers, of course - are bringing change to Lucia. We''re going to remove the toxic corporate influence of Burtonol and put the land back into the hands of the people.', 195, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110805, 'It sounds like a religious movement.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110806, 'You flatter me. But it is, in a way. Because, when we have removed the corporate elements will be left to shape Lucia in my image. ', 195, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110807, 'Our image. You said my.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110808, 'You misheard. This is a group effort, a grass-roots movement of like-minded citizens hoping to wipe Lucia clean of Burtonol''s corporate corruption.', 195, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110809, '(The PDA buzzes.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3001, 110810, 'Of course we do... Take some...', 195, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3002, 110811, 'Guess what? ', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3002, 110813, 'The scan came back positive for a symbiote. This woman - whoever she is - is a bona-fide Goa''uld. I''ve downloaded the scan results to your PDA. Unless Baal or Anat give approval, you should avoid more contact if possible. If she is in hiding and you expose her, it could be very dangerous. ', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3003, 110814, 'Jordin is a Goa''uld? I wonder how her human followers will respond to that...', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3003, 110815, 'She''s deceiving them...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3003, 110816, 'They''re not going to like that one bit... And we need to make sure they are well aware of it. I''ll put a call into marketing... ', 157, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3004, 96560, 'You begin to rig the charge on the cage door. This could go horribly wrong if you''re not careful...', 2800, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3006, 115294, 'If Burtonol has an entire program dedicated to Ra''s Crystal Technology, we need to know what they''ve got. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3006, 115295, 'Hebridan has recently come under assault. Ra''s Hataks are in the sky and his troops are on the ground. He''s after something.', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3006, 115296, 'He has limited resources, so to commit to an attack has meaning.', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3006, 115297, 'I''ve got one of our operatives, Ogilvie, on Hebridan now - making inroads with the locals. We sent him down on an intel mission when we first learned of Ra''s attack. $name$, make your way to Hebridan and link up with him. He may already have a lead on Devlin. ', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3007, 63511, 'UNUSED DIALOG', 1379, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3008, 111140, 'The scanner codes Vala gave you seem to work, but almost instantly warnings appear across the screen. Someone called "Security Chief Harris" has personally ordered a lockdown alert. The top executives will be out of reach unless the lockdown is halted.', 412, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3009, 111141, 'Entering the security chief''s access code only confirms that this area is under full lockdown. The system requires an override code which you don''t have. Thinking quickly, you access a list of "qualified personel". One of these people may have the code. ', 414, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3009, 111142, 'Most of the people are listed as already inside the bunker. Only one name stands out, someone caught outside: Wo Efrem, a marketing executive. He might be your last hope of getting inside.', 414, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111119, 'Please! Please don''t hurt me - I have a family!', 593, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111120, 'I need to get inside that bunker. You need to help me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111121, 'You can''t get inside. Even with my code pass the system will do a bio-scan and identify you as an intruder. ', 593, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111122, 'Then help me get them out.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111123, 'There''s no way... They can stay down there for weeks...', 593, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111124, 'Then I have no use for you... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111125, 'God, no! Don''t! The ventilation system... You can use that...', 593, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111126, 'Go on.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3010, 111127, 'It''s always been a secret amongst the design team - the bunker is vulnerable through the ventilation system. You could simply pollute the air they have. Then they''d have to come out. You could even use Chlorafate - there''s a surplus of it in the West Building. ', 593, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3011, 91006, 'These conduits are providing power to the site. If you were to blow them, the power would be cut and the project security would be crippled. You believe you saw excavation explosives coming up the path... that might do the trick.', 440, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3012, 90999, 'Congratulations... The mission is complete.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3012, 91000, 'This is a great victory for the Praxis.', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3012, 91001, 'Let''s not lose our minds here... It''s just a single portal - it would be insane to believe he built only one. ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3012, 91002, 'You speak truth, Queen Anat. But we must embrace victories when they happen. Our feelers are out in search of other portal projects... Hopefully next time we will be able to analyze his technology more thoroughly before we destroy it.', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3012, 91003, 'Analysis of that technology would have been quite useful...', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3012, 91004, 'There wasn''t time. The site was active.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3012, 91005, 'So you say, <<playername>>. So you say.', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3015, 89825, 'You have secured his shield modulation code? Brilliant.', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3015, 89826, 'Imagine the tragedy, were he to have an accident hunting.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3015, 89827, 'Baal will be pleased indeed. Well considered, <<Playername>>. In the proper numbers the Tollan can be difficult to overcome - even with a working shield. ', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3015, 89828, 'How do we draw them out in numbers?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3015, 89829, 'Food. The Tollan will show themselves for food. ', 496, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3016, 89831, 'As you parse through the files you discover Asmodai and Gaap''s plan: They would make contact with Beleth, isolate him and steal whatever technology he has. They were using Gaap as the lure because Beleth has never met him but Beleth was proving elusive... You quickly close the files - careful to make sure no trace of your presence is found...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3017, 107987, 'This is an interesting recovery indeed, <<Playername>>. Beleth never concerned himself with things that lacked value...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3018, 30699, 'Go talk to Moh''katan before she pulls the Jaffa out of the Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3019, 30705, 'Go talk to Moh''katan before she pulls the Jaffa out of the Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3020, 45127, 'Moh''katan is really ticked off. Turns out her Brother was Beleth''s First Prime.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3021, 44923, 'Moh''katan is really ticked off. Turns out her Brother was Beleth''s First Prime.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3022, 30645, 'I''ve heard from the Goa''uld that my brother has been slain.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3022, 30646, 'He died as a true warrior - protecting his leader. It was Beleth who was foolish enough to try and hide from us that there is a secret cache of Ra technology on Tollana.', 942, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3022, 30647, 'That''s not all Beleth was holding back on - We recovered information that he was trying to decypher the Book of the Gates, an artifact brought to Tollana by Anubis.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3022, 30648, 'We can''t have this anymore. Both of you have launched your own attacks on my Brothers master - causing the maximum amount of death and destruction in order to come away with two small pieces of information. We must strike as a unified force in order to make these attacks much more precise.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3023, 30685, 'I''ve heard from the Goa''uld that my brother has been slain.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3023, 30686, 'He died as a true warrior - protecting his leader. It was Beleth who was foolish enough to try and hide from us that Book of the Gates is on Tollana.', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3023, 30687, 'That''s not all Beleth was holding back on - We recovered information that this Book of the Gates leads to a powerful cache of Ra''s technology.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3054, 54166, 'What can we do to stop him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3054, 54167, 'You can help me find my sons.', 716, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3055, 91881, 'Uploading data now. Nice work.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4227, 116383, 'Why not?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3023, 30688, 'We can''t have this anymore. Both of you have launched your own attacks on my Brothers master - causing the maximum amount of death and destruction in order to come away with two small pieces of information. We must strike as a unified force in order to make these attacks much more precise.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3032, 31530, 'You dial the gate address for Harset. Enter the Stargate to travel there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3034, 60274, 'Narim''s locker opens, revealing the Book of the Gates as well as a a passel of notes. A quick scan reveals their value: Narim seems to believe that Travell has access to the crystal activator. You resolve to get this information to Copplemann as quickly as possible.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3035, 49722, 'You notice this stack of fuel cans are in a strange place - near what were some highly flammable curtains... ', 723, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3036, 64089, 'Help Dr. McKinney escape the fire.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3037, 91229, 'You play the game and within seconds you win a large jackpot and shortly after another. It seems to have drawn the attention of an official-looking security person...', 408, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3038, 114214, 'Well, hello there! What can I do for you?', 441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3038, 114215, 'I had an appointment with Jonet and I was supposed to meet her here but...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3038, 114216, 'Were you late, tardy pants?', 441, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3038, 114217, 'Yes...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3038, 114218, 'Well, she''s gone... Jonet is a big fan of local-world culture and she decided to see a real-live Lucian show in Opheltes'' basecamp...', 441, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3038, 114219, 'So she''s there now?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3038, 114220, 'It''s very likely... ', 441, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3039, 114286, 'Vala gave you a letter for me? This should be good...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3040, 114271, 'Vala gave you a letter for me? This should be delicious... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3041, 114272, 'This necklace looks promising... It is Ra''s technology to be sure... ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3041, 114273, 'It looks slightly modified...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3041, 114274, 'It is. It looks like someone... Carved into this... Like they were carving into a precious gem. The technology is compromised. It was a good try, $name$ but... I''m afraid this necklace is worthless.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3042, 113679, 'Clearly the Bandersnatch is not common to Lucia. You resolve to call into base and see if there is anything about the creature in the archives there...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3043, 113675, 'The Bandersnatch? Lewis Carroll. He wrote these brilliant, insane poems and the Bandersnatch is mentioned. There''s no other reference in anything I''ve ever seen.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3043, 113676, 'Is it possible that Carroll knew something?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3043, 113677, 'It''s possible. But I wouldn''t count on it. Most of the discoveries we''ve made in the Stargate program revolve around cultural legends - multiple source legends. Myths at a massive scale that turned out to be true. Carroll''s work isn''t repeated anywhere... He was one in a million. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3045, 31996, 'Access Svarog''s computer systems in search of material to use against Travell.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46180, 'If Ihpet is, indeed, Ra''s vault then we are incredibly close to unlocking great power, friends. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46181, 'Without the activation crystal, Ra''s Crystal Key is worthless. We need that crystal.', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46182, 'Copplemann''s report indicates that Narim''s agents stole the activation crystal, but were unable to smuggle it out of the Curia. Instead they hid it. Anubis tried to beat the information out of the population, but Narim seemed to think the activation crystal was there for the taking once they deciphered the Book.', 500, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46183, 'The Tollan are masters of phase technology - perhaps they used this to deceive Anubis. ', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46184, 'If it is in the Curia Travell would know where it is.', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46185, 'Then she must help us, one way or another. ', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46186, 'That is easily accomplished. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46187, 'Not through violence. The Tollan are fractured, but murdering Travell would eliminate virtually everything we''re accomplished on the world. The Black Market on Tollana is a large part of Harset''s supply network. ', 941, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46188, 'Then we blackmail her into it.', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3046, 46189, 'That shouldn''t be difficult.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3047, 113692, 'You dig through the trunk and recover the Crystal Gem... It''s small, but it''s clearly a technology related what was discovered on Ihpet... ', 1417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3048, 32035, 'The system is wide open - Svarog apprently isn''t overly concerned with secrecy in his slave dealings. Within minutes you uncover the truth: Travell has been working with Svarog, exchanging information with him about potential slaves in return for favor. In some cases there are electronic messages showing she set up specific Tollan for capture.', 1415, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3048, 32036, 'Myla''s name is on one of these lists. If this information got out, the Tollans would kill Travellthemselves. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3049, 113693, 'Interesting crystal... It is certainly Ra''s technology. Looks almost like a data storage device of some kind... I''ll see if I can crack it apart and get to what is inside.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3050, 32076, 'You accuse me of working directly with Svarog? This is absurd. My people would never believe the likes of you.', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3050, 32077, 'I got access to Svarog''s computers. There''s a written record.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3050, 32078, 'I didn''t have a choice... Dealing with that animal was a means to survival.', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3050, 32079, 'So now you deal with me. I need information about the Curia. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3050, 32080, 'You seek the activation crystal, no doubt. ', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3050, 32081, 'How do you know about that?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3050, 32082, 'I was the one who hid it.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3051, 46193, 'Access to the Curia area can be difficult to obtain. However, sources have provided the Ring Transporter passcode for the Curia. I''ve uploaded it to your PDA. You should see it now when you access the Tollana Ring Network.', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91085, 'Are you our guide?', 419, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91086, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91087, 'It says in the brochure that you will be Happy-Happy. You don''t seem Happy-Happy.', 419, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91088, 'I''m happy-happy.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91089, 'You''re not smiling or anything.', 419, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91090, 'I''m happy-happy on the inside. Shall we get started?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91091, 'Can I get a fizzy-pop first?', 419, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3052, 91092, 'No.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3053, 54162, 'UNUSED DIALOGUE', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3054, 54163, 'You have returned. ', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3054, 54164, 'We''ve gathered some samples and are having them evaluated. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4284, 118506, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3055, 91883, 'I''ll get this information to Omega Site for evaluation. Find Ras''nor and let him know help is on the way.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3056, 91151, 'Nice recovery... We got the cargo, we got what the company wants...', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3056, 91152, 'You don''t seem happy about it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3056, 91153, 'Of course I''m not. I lost men in there - good men. Burtonol is like everything else on this world - a bunch of freaking mercenaries who only worry about themselves: No different than the gangs we got rid of, just more organized. ', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3056, 91154, 'So quit.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3056, 91155, 'That''s one option, but it''s a sucker''s game because I''ll always be on the bottom looking up... I should just game the system like Ayr and the rest of them... That way I keep my job and make a little on the side... ', 452, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3056, 91156, 'That''s another option. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3056, 91157, 'An option that could benefit us both, <<playername>>. How''d you like to split some cargo that never got recovered from Crevice Lakes?', 452, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3057, 95512, 'Curious. These are not Asgard readings. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3057, 95513, 'They are quite complex.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3057, 95514, 'Yes. This requires investigation.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3058, 114322, 'Collect a Kassa shipment from Jax, one of Netan''s farmers.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3059, 114323, 'I have something for you - if you can spare the time.', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3059, 114324, 'Sure.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3059, 114325, 'One of my Kassa growers has been delinquent with his shipments. I need you to pay him a visit. Since he doesn''t know you, he is more likely to be compliant than if I send my usual people. He''s an unusual sort... He fears strangers.', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3060, 91525, 'I don''t know you... I don''t know your face. Identify yourself!', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3060, 91526, 'Netan sent me. He wants to be pick up his shipment.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3060, 91527, 'He wants... That''s just great... How does he expect? So he sends a stranger... Which makes me CRAZY... There are thieves in the area - thieves who are robbing me blind.', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3061, 91634, 'Clearly the Kassa has been tampered with. To what degree would require an actual lab, but there is no doubt this sample is not pure.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3062, 114410, 'Take Jax''s Kassa and evidence of corruption to Netan.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3063, 114414, 'I''ve cleaned the Kassa. You can deliver Netan the shipment he asked for. This business - the drug business - is stressful for a guy like me... I''m just a farmer.', 447, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3063, 114415, 'A Kassa farmer.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3063, 114416, 'I can''t help it if I am best with Kassa. I was made me this way. Please tell Netan that I am sorry for the delay.', 447, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3064, 114422, 'Thanks for the recovery. The shipment looks in order.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3064, 114423, 'It took some work, but we got it sorted out.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3064, 114424, 'The reality is that I need to stop relying on small-timers like Jax and corporatize my entire operation. Look at Tech Con Group and Burtonol - they make their money hand over fist. ', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3064, 114425, 'They don''t sell Kassa.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3064, 114426, 'The product is irrelevant, $name$. What matters how you do business. Mark my words, this Green Boot operation? It''s just the beginning. ', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3065, 36218, 'Take Travell''s Holographic Image Devices to Copplemann.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3066, 54198, 'We both know that my success on Tollana is directly tied to your "Praxis" success here. I can bring stability to parts of this world that no other leader can... Stability will mean a restoration of commerce. ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3066, 54199, 'And you will be able to trade with us.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3066, 54200, 'Exactly. But Narim''s rebels continue to infuriate Zvarog - hampering my ability to forge peace... I need to bring them back under my wing.', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3066, 54201, 'How can I help?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3066, 54202, 'You can go to the refugee camp and set up these - Holographic Image Projectors. These will get my message out to the people... I have ten of them for you to place.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3067, 119924, 'Interesting device... A propaganda machine. But remarkably durable. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3067, 119925, 'What if we change the message?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3067, 119926, 'Hmmm. Devious idea, $name$. I''ll upload a recruitment message for the Tollan - but instead of Travell''s message, they''ll see an offer to come work directly with us. Go ahead and set those up now... Travell will never be the wiser. ', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3068, 39076, 'Excellent work. Eventually, when my people come back and peace is at hand, your Praxis will reap the benefits of your labor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3068, 39077, 'We already are.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3069, 54543, 'Find the supply distribution site Narim''s rebels use.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3070, 54544, 'Your interest in technology can serve both of us. If you are willing to bring me one of Narim''s lackeys - a charlatan named Rasmus - I am willing to trade the specifications on a device you will find... Useful. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3070, 54545, 'Where is he?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3070, 54546, 'He helps Narim secure supplies for the rebels in the refugee camp.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3071, 54547, 'Excellent. Rasmus always was a bit simple. My people will prepare him for the next phase.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3072, 36204, 'Use Travell''s device on Rasmus.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3073, 36205, 'The device I am giving you was used by my people to teach our children efficiently. For example, we were able to infuse into them a complete understanding of particle physics within seconds...', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3073, 36206, 'A learning device is of little...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3073, 36207, 'I have modified it. Now, it can be used to implant within a target subliminal suggestion - remotely. ', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3073, 36208, 'A brainwashing device. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3073, 36209, 'A mind-control device. I will able to have Rasmus slowly sabotage Narim''s supply network - from the inside. And he will think it was his idea... Use the device on him. Once it has worked, he will forget everything and you can return him to whence he came.', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3073, 36210, 'And the device?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3073, 36211, 'It is yours. I have others.', 1102, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3074, 36212, 'Where am I? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3074, 36213, 'You''re about to go home.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3075, 113326, 'More analysis leads to an even greater appreciation of the design... Yotho is a true genius. This is a technological masterpiece - and immensely powerful on a battlefield. You upload the scan to your PDA.', 643, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3076, 113328, 'So, what do you think?', 448, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3076, 113329, 'Your voice changed...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3076, 113330, 'Of course it did. You didn''t buy the blind routine did you? Yotho is a genius, but his mind is mashed hash - he''s an idiot with a talent. I recognized that talent and deliver product to potential buyers. I use the cover story to keep the factions on this God-forsaken planet in the dark. ', 448, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3076, 113331, 'This drone is for sale?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3076, 113332, 'Yes. And there''s more where that came from. I just set the Yotho train in motion and stuff like this pops out. You''re not from Lucia, but you look smart enough to see when an opportunity is presented to you. ', 448, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3076, 113333, 'Let me speak to my leadership.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3077, 113353, 'This sounds like something worth pursuing. Yotho probably found an Ancient face-hugger somewhere and it broke him... Whatever the reason, if this tech matches the scans you''ve uploaded... This could be profitable indeed. Nice work.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3078, 39108, 'Head to the Refugee camp to meet with Travell''s Jaffa contacts.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3079, 39105, 'I have an urgent favor to ask of you... As part of the accord we signed, Zvarog occasionally recruits Tollan civilians for work in his Resort complex. I am often tasked with finding people that would be right "fit". He has sent an emissary into our territory for a pickup... Could you meet with him?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3079, 39106, 'And...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3079, 39107, 'There''s a volunteer I''ll need you to make sure he gets: Berit. Simply make sure she fulfills her commitment and goes with him. It''s important that we always please Zvarog - for now... ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3080, 39185, 'You are Travell''s liasion? You are new. We are to be delivered a human female. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3080, 39186, 'What is she used for?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3080, 39187, 'That is best left to the imagination. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3081, 36282, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3082, 36301, 'What do you mean, there were complications?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3082, 36302, 'The Jaffa were ambushed. I did what I could. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3082, 36303, 'Zvarog won''t like this. What about Berit - was she hurt?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3082, 36304, 'I never saw her.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3083, 91444, 'You have come to offer your services to me on behalf of Anat? Isn''t she gracious? But it does bring up the question: Are you Praxis useful? ', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3083, 91445, 'There is only one way to find out.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3083, 91446, 'Indeed. See my first prime, Illana. She is my eyes and ears. She will decide if you are useful.', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3084, 36314, 'Find Morrigan a Tollan "companion". ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3085, 36328, 'I''m unhappy, <<Playername>>. My human plaything, Vilgan, has outlived his usefulness and had to be put down. I''ll need another.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3085, 36329, 'Another human, I presume?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3085, 36330, 'The Jaffa make terrible playthings - you know that. Yes, I''d like you to find me a human plaything. It will please me. And pleasing me pleases your Queen, Anat. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62590, 'This is the best you can do? I want a plaything - attractive, fit... Not some slovenly, underfed, filthy slave. Would you want this-this-this creature as your plaything?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62591, 'I agree it is not a particularly pleasing specimen but...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62592, 'Does this mean I can go?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62593, 'Not yet.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62594, 'Yes, leave. Your very face displeases me. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62595, 'Lord Morrigan, the Tollans are all basically like that one.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62596, 'Then do not bring me a Tollan. I have heard about a human who does intrigue me... He is purported to be handsome, virile, fit... He is called Ogilvie and is part of the Op-CORE. If he were to visit me...', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62597, 'You''d be pleased?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3086, 62598, 'Quite.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3087, 89930, 'Why would Lady Morrigan want to see me? I have no idea who that even is.', 951, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3087, 89931, 'She has heard you are remarkably talented.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3087, 89932, 'Oh, it''s like that. I''m not sure how I feel about fraternizing with a Goa''uld - no offense.', 951, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3087, 89933, 'None taken. Simply let me help you weigh the pros and cons...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3088, 36562, 'Go see Machra about smuggling a bomb into Zvarog''s Resort.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3089, 36520, 'My minion has informed me... Olokun is here. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3089, 36521, 'And?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3089, 36522, 'I want him gone. Olokun will stop at nothing to destroy me in my current, depleted state. He is unaware that I am here, but when he finds out I will be in danger. I want him killed.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3089, 36523, 'I can''t do that, it would be suicide.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3089, 36524, 'What if we used a bomb? There is a merchant, Machra. He could provide the materials. I will give you a pendant he covets to barter with. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3090, 36525, 'I want that pendant, but there''s no way to do what you want. Svarog is constantly scanning the entire resort for explosives - it is a retreat for Goa''uld afterall. Any device that is assembled completely would probably be exposed within minutes...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3090, 36526, 'Can you smuggle the pieces in?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3090, 36527, 'Of course... But they would need assembly...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3090, 36528, 'Perhaps not. They might be useful as is. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3090, 36529, 'And you will still give me the pendant as payment?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3090, 36530, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3091, 63360, 'There''s a bomb here in the resort? That''s not possible - we have a scanner!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3091, 63361, 'I believe he smuggled it in. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3091, 63362, 'Olokun? I will alert security immediately!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3091, 63363, 'Hurry - you may not have much time. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3092, 63394, 'He''s not going to be blown up?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3092, 63395, 'It was impossible to arrange. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3092, 63396, 'Expulsion from the resort does not totally displease me... ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3092, 63397, 'It''s likely there will also be torture involved.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3092, 63398, 'Oh, well in that case. You please me...', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3093, 54292, 'Retrieve the device which can open the Tel''Tak from Asmodai''s corpse.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3094, 63484, 'I know that you have used false papers to get in here. I have evidence of it...', 995, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3094, 63485, 'You are a fool, slave, to threaten me...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3094, 63486, 'I am not threatening you, but instead offering you a deal. My master has hidden a ship - a Tel''Tak - on this world. But, to protect it, he had a special device made which makes accessing it impossible. I need that device.', 995, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3094, 63487, 'You wish for me to kill your master?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3094, 63488, 'He is already missing. I simply wish for you to retrieve the device. If he lives, I will serve him. But I fear he is dead. If that is the case, I will use the ship to reach freedom - and your secret leaves with me.', 995, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3095, 54298, 'Impressive. You are certainly resourceful, <<Playername>>. I will recover the ship and deal with transporting it to Harset. You need to make sure Asmodai''s lackey is taken care of. He must be discredited and, if possible, eliminated. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3095, 54299, 'This is already in motion.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3095, 54300, 'I must remind myself to keep an eye on you. We are of a similar mind. Finish off the attendant. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3096, 110266, 'Kefflin radioed me. Your handling of the Mathas brothers problem was impressive. Kefflin said you were asking about Opheltes...', 209, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3096, 110267, 'Podhertz said he''s a collector of crystal technology.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3096, 110268, 'He wouldn''t be the first Goa''uld obsessed with it. Opheltes is tough to get to. ', 209, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3096, 110269, 'Who are his associates?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3096, 110270, 'Well, Vala is one. For some reason she seems to be able to see him whenever she wants. She could make it happen. ', 209, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3096, 110271, 'I''ll need the Rimal. She won''t get me in there for nothing...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3096, 110272, 'The Rimal is very valuable, $name$. But, given the way you handled my Mathas brothers problem, it seems a fair trade. And you''re right, she won''t do anything out of the kindness of her heart. Take the Rimal. And, once you reach Opheltes, please tell him I wish to see him as well...', 209, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3097, 54333, 'Go see Machra about Ogilvie.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3098, 89951, 'Machra is a very valuable contact for us here. Some how, some way, Ogilvie has managed to piss him off. We can''t have this. Go see Machra, figure out what has happened and solve that problem. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3099, 54341, 'Ogilvie... What has he done? He has sullied my daughter! I do not have much, <<playername>>, but child is the jewel in my eye. And this pig, Ogilvie, is whispering sweets in her ear... She claims they are to be married. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3099, 54342, 'When?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3099, 54343, 'She will not say. It is a secret, but I suspect it may happen soon - perhaps it is happening as we speak. But know this: If it does happen, I will never deal with you and your Op-CORE again.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3100, 89967, 'Copplemann is ordering me to dump my future wife? Just because her dad doesn''t want her to marry me?', 951, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3100, 89968, 'We need Machra. He''s a key supplier for the Praxis. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3100, 89969, 'But I love her... I mean, look at her... She''s gorgeous.', 951, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3101, 54839, 'Find the Tollan Mainframe and access it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3103, 54840, 'Unexpectedly, this computer terminal seems to have access to the larger Tollan network. After a few minutes of digging you discover the location of a mainframe - with what appears to be connections to a data library. Within seconds you have isolated the location and uploaded it to your PDA.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3107, 54841, 'This is a spectacular recovery, <<Playername>>. I''ll get this up to the science team immediately.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3108, 54362, 'Confirm that Svarog''s Jaffa have not caught wind of Op-CORE''s sizeable presence on Tollana.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3109, 54363, 'I''ve heard some worrying rumors lately. It''s possible that Svarog, the Goa''uld who runs this world, has been made aware of our presence here. I need you to take down some of his reconaissance teams and access their reports. We need to know if we''ve been exposed. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3109, 54364, 'What if he knows we''re here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3109, 54365, 'Then the game may change. But, for now, let''s just find out what kind of information he''s got.', 469, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3110, 54366, 'I assume this went off without a hitch?', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3110, 54367, 'There is no chance of survivors identifying us. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3110, 54368, 'Good... After a quick scan it looks like they still haven''t figured out we''re here. I''ll need to go through more thoroughly, but for now it looks like we''re still under the radar. Nice work.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3111, 54406, 'Find and rescue agent Moseley.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3113, 89991, 'The Tollans aren''t pleased with our support of Travell. They''ve decided to retaliate by snatching one of our people - Corporal Matt Moseley. His GPS is still operational. Go find it and, if he''s not there, try and find him. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3114, 89974, 'Nice work, although this whole episode leaves a bad taste in my mouth. We may have to send a very firm message to these Tollans if they ever try a stunt like this again. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3115, 62221, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3116, 62228, 'UNUSUED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3117, 62236, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3118, 62244, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3120, 54504, 'Free Vesna, Goran''s lover, from Narim''s rebels.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3121, 54505, 'Machra has told me much about you - that you are very capable. I need your help.', 1518, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3121, 54506, 'I''m very busy.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3121, 54507, 'I''ll pay you. ', 1518, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3121, 54508, 'I''m listening.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3121, 54509, 'I have fallen in love with a girl, Vesna. We were to be married, but Narim''s vile rebels broke into her house in the night and snatched her away. They are holding her, forcing her to try and solve their computer network problems...', 1518, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3121, 54510, 'Why don''t you rescue her yourself?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3121, 54511, 'I tried, but I''m not capable of taking them on... If you do this for me - if you bring her to me - I''ll give you everything I have. ', 1518, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3122, 64373, 'Goran sent you to rescue me?', 1519, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3122, 64374, 'You sound surprised.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3122, 64375, 'It''s a long story. Please, just get me out of here and you can hear the whole thing...', 1519, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64409, 'You brought her to me... Thank you... Are you well, my love?', 1518, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64410, 'I''m not sure what you thought you were going to achieve with this stunt, Goran. ', 1519, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64411, 'Stunt?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64412, 'Goran and I aren''t lovers. That''s a fantasy of his... I was abducted, in part because I was trying to avoid him by hiding in the computer lab. Narim''s people found me and forced me to come with them. Were it not for Goran, I never would have been abducted in the first place.', 1519, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64413, 'But, I saved you.', 1518, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64414, 'No, <<Playername>> saved me. You just paid for it. ', 1519, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64415, 'You haven''t paid yet. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64416, 'You can''t buy me Goran. You never could. ', 1519, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64417, '(Vesna stalks off, leaving a crestfallen Goran alone with you.)', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64418, 'I don''t suppose you''d consider a discount?', 1518, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3123, 64419, 'No.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3124, 35166, 'There is no hope for Tollana, can you help me get to a new world?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3125, 35170, 'I''m tired of watching my people fight each other rather than the Goa''uld who oppress us. I need to get off this world before we tear each other apart. Help me and i''ll make it worth your while.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3126, 48281, 'I''ll see what I can do about getting you papers for a Tollan to head off world. But I wouldn''t get my hopes up, these guys are not what you''d call trustworthy.', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3127, 36038, 'You''re picking up Lethander''s travel papers? Damn, I was hoping to get a chance at Lethander in person.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3128, 65065, 'If you want to get a Tollan off Tollana your best bet is to get them hired to work for a Lucian Trader and have them make a business trip to Lucia. Just so happens I have a parcel that needs to get taken back to Lucia as part of a transaction. Have your Tollan take it through the gate for me and I''ll say I hired him to my staff.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3129, 65070, 'Congrats, you now work for Machra. Now take this package through the Stargate to Lucia.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3130, 35175, 'I need someone like you to help me complete a transaction with one of the slimiest traders around here.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3131, 35180, 'My name is Jory Daveth, you might have heard of me - third best scavenger on Tollana. Anyway, I need someone with your... physicallity to help me complete a transaction with a real swindler. I''ll pay you in the technology, I''ve heard your after the best Tollana has to offer.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3132, 33916, 'Pleasure to meet you, I''m Margh Pasco. I assume Jory hired you to keep this transaction clean; unfortunately I have no plans to make this easy on you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3133, 33939, 'Impressive work. I might have to hire you for myself next time. I''ll complete the agreed upon transaction now that I''ve been bested.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3133, 33940, 'After all that work, you''ll be giving Jory a 20% discount.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3133, 33941, 'Wow, now I really like your style. If you insist about the discount then it''s done.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3134, 33951, 'Excellent work. I''ll give you the full 20% discount you arranged for me, but only if you agree to a non-compete clause - you can''t work for any of my competitors.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3136, 104905, 'Help Lyala escape the Curia by taking her to Harta.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3137, 104914, 'Please, help me. I''m a slave, held here against my will.', 1531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3137, 104915, 'You wouldn''t happen to be Lyala, would you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3137, 104916, 'I am Lyala... Did Harta send you?', 1531, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3137, 104917, 'He has been looking for you... I''ll take you to him.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3138, 104927, 'Lyala? I thought I''d never see her again... But she is here and safe... I owe you everything.', 1105, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3138, 104928, 'How about we get more specific?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3138, 104929, 'You will be paid, <<Playername>>. And gladly. Lyala lives!', 1105, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3139, 35195, 'We need weapons to free our friends and family from the Internment Camp.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3140, 35200, 'We''ve all got friends and family trapped in the Internment Camp and they''ll rot there unless we do something about it. Machra has a store of guns just collecting dust at his shop. Help us get some of them to use in our assault and we''ll compensate you fairly for them.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3141, 34069, 'Great work. With any luck our friends and family will be free in time to join us for dinner.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3142, 35204, 'I''ve gotten word some rebels want to attack the Internment Camp with weapons the stole from me. They must be stopped.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3143, 35210, 'If an attack goes off against the Internment Camp then Svarog will increase his patrols in this area to make sure no more attacks are getting planned. Which will drastically cut down on my business opportunities.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3144, 39705, 'Excellent work, I''ll let the Jaffa know where they can break up an attack. I may even be able to get some positive standing with the Jaffa after this.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3145, 54679, 'See Machra about creating a formal relationship with the Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3146, 54720, 'There''s a trader on Tollana named Machra. We''ve got a decent relationship with him, but I need to get supplies consistent and prices stable. Take this manifest - it''s a listing of the goods we''ll need - and see if he can supply us exclusively.', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3146, 54721, 'Will do.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3146, 54722, 'This is an important mission, <<playername>>. Harset is running low on almost everything. We need to get this deal done, no matter what.', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3146, 54723, 'Understood.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3147, 54683, 'This offer is very tempting... However I cannot meet these demands - not at that price.', 470, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3147, 54684, 'Why not?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3147, 54685, 'There is too much competition... Piran and Jowan would make my life miserable. It simply will not be profitable...', 470, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3147, 54686, 'What if there was less competition?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3147, 54687, 'Then this is a different discussion.', 470, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3148, 54689, 'You want me to simply stop doing business on Tollana? ', 1614, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3148, 54690, 'You will be compensated for it. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3148, 54691, 'And if I don''t? ', 1614, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3148, 54692, 'This isn''t a negotiation. You can either agree to this deal, or we will have a problem.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3148, 54693, 'You are Praxis, aren''t you? I''ve heard of you people... I''ll take the compensation. ', 1614, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3148, 54694, 'That is the smart choice. Wait for me at Machra''s and I''ll make sure you''re properly compensated. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3149, 54695, 'I heard what you did for Piran, but what you''re doing isn''t right...', 1615, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3149, 54696, 'Piran was smart. He did what everyone on Tollana does - what is right for them. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3149, 54697, 'Piran was a coward. ', 1615, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3149, 54698, 'Piran is going to live to see tomorrow. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3149, 54699, 'As is Jowan.', 1615, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110793, 'Hello, $name$. And what may I do for you? I live to serve.', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110794, 'I need some help, Lethander. I may have located a Goa''uld in hiding...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110795, 'On Lucia? How dramatic! And I suppose you''d like some help in solving this mystery, yes?', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110796, 'I''d appreciate it.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110797, 'We Goa''uld have a rather advanced physiology. Nerus, our resident genius, has concocted a scanning algorithm that we used to identify Tok''ra. We can adjust it for regular Goa''uld and download it to your PDA. It will do a full-body scan of the host and symbiote and then beams me the results directly. You''ll need to get close to him...', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110798, 'The target is female.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110799, 'Scandalous! Be careful $name$, female Goa''uld are the worst.', 978, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110800, 'You''re all parasites. Gender doesn''t matter.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3150, 110801, 'We are not parasites - we inhabit our hosts, we do not feed on them. Engage this Goa''uld in conversation, $name$. The PDA will buzz when it has sent me enough data.', 978, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3151, 54983, 'Piran seems to think that I am supposed to pay him something... ', 470, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3151, 54984, 'You are. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3151, 54985, 'That wasn''t part of our deal... I simply mentioned that we could negotiate if my competition on this world was reduced... ', 470, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3151, 54986, 'I imagine it wouldn''t matter whose competition was reduced... Perhaps Piran would be interested in my offer. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101968, 'We must try everything we can. The future of the Free Jaffa nation may be at stake.', 1333, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3151, 54987, 'I think this is all a misunderstanding... My misunderstanding. I didn''t realize how "committed" you were to this deal. I will compensate Piran for his graciousness and you can report to your Quartermaster that the supply lines are officially open. ', 470, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3151, 54988, 'Good choice, Machra.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3151, 54989, 'Thank you for not killing me. ', 470, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3152, 54715, 'Nicely done, <<playername>>. Machra is a useful contact. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3153, 96578, 'The lock itself isn''t very complex, but the rust makes it a bit tricky...', 2823, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3154, 54548, 'Please don''t kill me...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3154, 54549, 'Follow me?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3154, 54550, 'Anything you say...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36289, 'Why are you doing this? ', 1456, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36290, 'You volunteered.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36291, 'I did no such thing! Why do you think my family was fighting you? Travell has targeted me for slavery because my father has spoken out against her! How do you think she stays free of slavery herself? ', 1456, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36292, 'So this is political...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36293, 'The Jaffa are too afraid to come in here, so she is forced to use people like you - bounty hunters.', 1456, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36294, 'I''m not a bounty hunter. In fact, I could be convinced to let you go... But I will need something in return.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36295, 'I can give you technology - powerful technology. My father developed the terraforming technique used to create this world. I can give you access to this technology, if you spare me. ', 1456, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3155, 36296, 'I''m listening. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3157, 62552, 'Please don''t hurt me...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3157, 62553, 'Just come with me and you''ll be fine.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3158, 90796, 'You are adorable! Here is your manifest... But you may need a little more than that to convince Netan of Flax''s intentions.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3159, 90843, 'Thank god you came when you did... I think the perimeter is finally secure. We can take it from here.', 212, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3160, 63874, 'The successful hack leads to a data library. Inside the library you find the locations of various Tollan Health Monitor stations. The Tollan Health Monitors were a seminal Tollan technology - recovery of a Monitor Node would be a major technological coup.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3161, 95583, 'Oh, good, a friendly face. I need your help.', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3161, 95584, 'How can I be of assistance?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3161, 95585, 'There''s a fire inside there - and it wasn''t my fault. ', 715, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3161, 95586, 'We should extinguish it.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3161, 95587, 'That''s the problem. These exterior fire controls are jammed and system hasn''t kicked in. I''ve called a fire supression team to come help, but their gear was sent through the gate to Earth. By the time it gets back here, I think we''ll lose the building and everything in it. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3161, 95588, 'I will assist you.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3162, 89997, 'I don''t know what you''re talking about... I''ve never heard of anyone named Moseley. ', 1513, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3162, 89998, 'You''re wearing his watch. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3162, 89999, 'Oh.', 1513, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3162, 90000, 'You can keep lying if you want - and I''ll start killing people until I find someone you care about...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3162, 90001, 'You think intimidation will work on me?', 1513, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3176, 92144, 'Help Mimir analyze the Poison Introduction Device', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3177, 92131, 'This technology you keep recovering looks very advanced for Jaffa, yet similar to technology used by the Goa''uld, Ra. He was clever for a Goa''uld and used very advanced technology, albiet in a crude, brutish way. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3177, 92132, 'Is there a way of creating an antidote for the poison which ails the Jaffa?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3177, 92133, 'We must analyze the artifact', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54185, 'Your interaction with the High Council was successful. They have freed you to work directly with the humans in solving the Jaffa sickness on Beta Site. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54186, 'I am pleased.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54187, 'This affords us an opportunity, <<playername>>. While working with the humans, you can assess their potential as the fifth race more easily.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54188, 'This project is to remain secret from the Council?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54189, 'Yes. The politics of the Council dictate that we remain silent about the question of the Fifth Race. However, if the humans are indeed worthy, the Council may be swayed to reconsider the humans as a potential option. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54190, 'It is possible that the Nine Peaks Jaffa will overwhelm the Beta Site withan invasion.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54191, 'I will speak to Bra''tac in an effort to have him commit Jaffa to its defense. We have no Asgard resources for such an endeavor. Report to Colonel Carter on Beta Site and offer your services. You will work under her command until you receive contrary orders from me.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3178, 54192, 'Yes, Supreme Commander.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3179, 50402, 'Unused Dialog', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3180, 57072, 'You have returned.', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3180, 57073, 'We have gathered data and are in the process of analysis.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3180, 57074, 'Even if you find a cure for the sickness you will need to find an antidote to Dakor, whose words poison my people faster than any disease could. Surely the Asgard could intervene and render Dakor powerless?', 716, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3180, 57075, 'I am not here on behalf of the Asgard, but am instead serving under the command of Colonel Carter.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3180, 57076, 'Your people are not committed to saving the Clan of the Nine Peaks from destruction?', 716, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3180, 57077, 'I can only speak for myself, Ras''nor. I am here to help.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3180, 57078, 'You can help by finding my sons.', 716, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3181, 36214, 'I have done nothing to you... Please let me go.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3182, 36215, 'Interesting device. Clearly the Tollan were far more capable of deception and deceit than their own people knew... We can reverse engineer this pretty easily. Nice work.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3195, 54234, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101963, 'This gate address used by Trink''na is known to us... It was a world controlled by Ra, long ago.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101964, 'According to everything we''ve got, it was fought over following his death and then quickly forgotten.', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101965, 'I remember those wars. I lost many friends there. We must assume Trink''na was led there by something. You will follow to Men''fa and make contact with him. ', 771, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101966, 'We will focus on finding a medical solution through research here on Omega Site. General Hammond is arriving shortly with new research from earth. Hopefully, this will provide hope given that your mission to Men''fa has little probability of providing a solution.', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101967, 'Then why pursue it?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119014, 'She cannot be trusted. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101969, 'Tretonin from Beta Site is shipped to several Free Jaffa worlds... If those shipments are infected...', 771, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101970, 'You are facing an epidemic.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3197, 101971, 'There is an SGC operative on the world already, sent as a gate liasion... Lt. Mogilny. Meet him on Men''fa.', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3199, 100728, 'The device reveals that the poison is, in fact, a series of tightly programmed nanites. The disease is literally a series of machines working in concert to destroy the Jaffa from the inside.', 1334, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3199, 100729, 'Curious and worrisome. Supreme Commander Thor on Omega Site should be informed of this new development immediately. I will search deeper records.', 730, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3202, 97766, 'You recovered the activator?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3202, 97767, 'Yes, it''s here. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3202, 97768, 'According to the plans you uploaded, the activator works with the device Dr. Novak recovered...', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3202, 97769, '(Colonel Carter reveals the "thing" Dr. Novak recovered and inserts the glowing activator. The two objects fuse together into one whole - almost as if it were a living system integrating with itself.)', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3202, 97770, 'That was... Interesting.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3204, 90571, 'Podhertz is nowhere in sight. This computer could have information on him.', 394, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3206, 111062, 'You successfully crack the electronic lock for the Red Collar item.', 1523, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3209, 114462, 'You begin to disarm the booby-trap attached to the cargo.', 1418, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3210, 114574, 'The beacon''s electronics are tricky, but nothing you haven''t seen before... ', 459, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3211, 91190, 'You begin to set the Spaceport''s controls so they can unscramble the landing beacon.', 1420, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3212, 113295, 'You begin to disassemble the machine so you can remove the AI processing board safely.', 538, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3213, 113344, 'You begin to analyze the drone weapon Tollak appears to have constructed.', 643, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3216, 95863, 'The device registers that some crates are missing - marked for the Archeology section at the SGC. A quick double check confirms it - the crates are not here.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3217, 63847, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3218, 63848, 'UNUSED DIALOG', 1379, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3219, 64473, 'The whole detachment? My God... This is worse than P3X-666... I don''t see Airman Lance''s tags here...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3219, 64474, 'I checked the area pretty thoroughly. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3219, 64475, 'Hopefully he found his way clear... Keep your eyes peeled when you go back out there. I want to bring all my people home in one piece.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3220, 63849, 'UNUSED DIALOG', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3221, 63850, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3222, 63644, 'UNUSED DIALOG', 805, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3223, 98235, 'How are you with computers?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3223, 98236, 'Pretty good.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3223, 98237, 'Great. My IT guys are going crazy trying to get everything wrapped up. They asked me to send them some help... I just need you to back up the hard drives in the Administration Building. Use the master backup device on any open terminal.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3224, 95923, 'You plug in the master backup device into the machine and notice something odd. Another program is running. More checks reveal what looks like a viral worm currently in the process of culling through the base''s archeological and gate address database. The worm could spread - you''ll have to act quickly.', 2330, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3224, 95924, 'The only solution is to try an Network Reboot - a tricky procedure which may damage the hardware if done wrong. You begin, knowing that you don''t have much time to stop this worm from infecting everything.', 2330, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3225, 98256, 'Check the tanks of volatile gas for damage.', 713, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3226, 96063, 'There''s something I need you to secure... Felger has a supply of volatile gasses stored in one of the rooms here. We were going to transport them off-world, but he convinced me to wait and now we''re basically left with a ticking time bomb...', 713, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3226, 96064, 'I''ll investigate.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3226, 96065, 'Hurry. We could be talking about a major catastrophe if we don''t get those tanks squared away. If there has been damage, there''s a quick-release valve that will evacuate the gas safely. ', 713, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3227, 95947, 'This technology parallels that which is being used on Orilla. It is possible this technology may provide a solution to our genome malfunction.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3227, 95948, 'Was the experiment a success?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3227, 95949, 'The results are inconclusive. Our simulation breaks down almost immediately, but it does demonstrate currently unquantifiable sociological qualities which I find intriguing. More work must be done but, unfortunately, it must wait until we have relocated off of Beta Site.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3228, 64066, 'You help has enabled us to complete my simulation. There are several steps in the process. Would you like to assist in this procedure?', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3228, 64067, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3228, 64068, 'The data must first be processed into Consciousness Matricies. Once processed, we will run a parallel simulation and then finally compare the processed results with the observational data. Begin processing now.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3229, 95926, 'When you re-start the machine after the network reboot there are no traces of the virus. It must have been designed to disappear if detected. You decide to bring the backup and word of the virus to Carter.', 2330, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3230, 113694, 'Ra''s technology seems to be all over Lucia... I''ve seen these before - Data Storage Crystals. Until we get something that can read them, they''re impenetrable. Still, it''s a worthy find, $name$.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3231, 50157, 'Unused Dialog', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3233, 91913, 'The disease is insidious... It weakens the body and then takes the mind... I have had to put several of my brothers down. We haven''t much time...', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3234, 38938, 'Well, I''ll tell you one thing I won''t miss about this place: the food. The last time I had this much indegestion, I was on a dig in Honduras.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3235, 38940, 'Half my team''s been transferred back through the gate! How am I going to pack up everything myself?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3236, 38980, 'I am not looking forward to going back to academia. Alien parasites are a hell of a lot easier to face than the buerecracy and red tape around my last grant proposal. The aliens are probably a lot less vicious too.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3237, 38944, 'Visit strange new words they said. Meet interesting people they said. They never said we''d be going just to move everything back home.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3238, 38975, 'I guess I can see the IOA''s point. We have opened some pretty nasty cans of worms out here. Not sure sticking our heads in the sand is going to help much, though.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3239, 38972, 'I''ve been here a month, which was about twenty-fice days too long. I''m out with the next group and it can''t come nearly soon enough.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3320, 111266, 'I still need more census work done. Can you make your way to Slums neighborhood for more readings?', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3240, 38971, 'This place is cool, but it''s in the middle of nowhere. Don''t look at me like that, it is! 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3241, 38969, 'I''m not sureI would have ever gotten used to being off-world at night. I keep expecting the same constellations, you know? That one over there is supposed to be the North star, but see how small it is?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3242, 49953, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3243, 49954, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3244, 49955, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3245, 49956, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3246, 49957, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3247, 49958, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3248, 49959, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3249, 38987, 'So, now that we''re leaving, do you think I could get away with asking the Asgard about Roswell?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3250, 40094, 'These symbiotes are genetically linked. Do not trust Anat and her kind.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3251, 64741, 'Approach Ras''nor to try and determine what Dakor''s Jaffa are after.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3252, 96583, 'The recent Nine Peaks Jaffa uprising is most disturbing. The humans believe the discontent is related to Jaffa discord over their recent sickness.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3252, 96584, 'You debate this conclusion?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3252, 96585, 'Evidence shows that the Jaffa are searching for something amid the various ruins here. The humans have themselves recovered artifacts which the Jaffa have since reclaimed. ', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3252, 96586, 'To discover what they seek would enhance our understanding.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3252, 96587, 'Yes. Ras''nor, the exiled Nine Peaks leader, may have those answers. Visit him and enquire. ', 730, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3253, 64207, 'UNUSED DIALOG
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3254, 64208, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3255, 96676, 'Perhaps if you can hack this transmitter you can get into the computer memory and reconstruct messages sent through it. ', 811, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3256, 64258, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3257, 64282, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3258, 65268, 'You''re pretty certain Dakor has secured the Crystal Heart... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3258, 65269, 'I think so.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3258, 65270, 'But that''s not the only thing he''s after. Hopefully we can keep him away from everything else...', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3259, 64785, 'I find I have come to develop a grudging respect for their science teams. However, I have orders. The communication we intercepted indicates that they are conducting research in the Ruins of Barak''Ka. ', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3259, 64786, 'The area has been split by their sciensts into two areas. They begin with the location designated the "Upper Ruins"', 872, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3260, 64787, 'Fascinating. This is a depleated Zero Point Module. Our allies, the Ancients, used these as power sources when we were barely ahead of the Tau''ri in terms of scientific progress. We have since learned our own ways of generating power. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3260, 64788, 'If the Tau''ri had come across this item it likely would not have caused much trouble, but it is up to the High Council to decide if we will let them find it or not.', 872, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3261, 64585, 'UNUSED DIALOG
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3262, 64584, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3263, 64586, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3263, 64587, 'I was. I dismantled a Goa''uld bomb.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3263, 64588, 'That is fortunate. Such a device could have caused untold destruction on the Tau''ri homeworld.', 872, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3264, 64942, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3265, 64943, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3266, 65355, 'We''ll certainly get to work on this right away. I have all of the Ra cult''s crystal technology on the way to Omega Site as we speak... It''s very advanced, but with enough evaluation we''ll figure it out. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3266, 65356, 'You always do.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3266, 65357, 'We do, don''t we? We''re pretty neat that way.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3275, 40070, 'Harset needs supplies - try convincing Machra to enter into an arrangment with the Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3276, 40073, 'I''m getting word that Harset is running low on supplies. Luck for us, that''s one thing that Tollana and more specifically the Lucian Scavengers seem to have a surplus of. Machra seems like the most trustworthy of those in a position to help. See if you can start up a relationship with him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3277, 40076, 'I''d love to have a guarentied customer for all of my wares. Problem is that if I send half of my supplies, a more than generous amount that should give you what you need, I''ll be left with severly depleted stocks here on Tollana and become easy prey for my competitors - some of the other larger suppliers in the area. Maybe if you could convince Piran and Jowan to close up shop it''d be easier for me to join up with you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3278, 40079, 'You''ll give me all that currency for all of my supplies on the condition that I close up shop here on Tollana and head to a new world? I''ll take it! My wife has been nagging me to leave here anyway.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3279, 40082, 'All that money for my full stock of supplies? Something doesn''t smell right here. I guess you''re also the one who convinced Piran to close up shop. Thanks for you doing so - it''s put me in a much more advantageous position to take on your friend Machra.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3280, 40085, 'Wow, I never thought anyone could get Piran and Jowan to leave this game. Thanks for your help and I''ll send the first batch of supplies to Harset by the end of the day.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3281, 40089, 'We got in some of your shipments from Piran and Jowan. How much did you pay for that stuff? It''s mostly useless junk. Thankfully the stuff coming in from Machra is proving to be very useful.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3282, 104515, 'The statue surprised you?', 1631, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3282, 104516, 'No it SHOCKED me. Electrocution.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3282, 104517, 'Oh. That''s... Interesting... It must be some sort of defense system. You said yourself the relics seemed aware of you in a strange sort of way. The whole area is like a big machine. It probably has a defense mechanism to guard against unwanted intruders.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3282, 104518, 'So can I deactivate the defenses?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3282, 104519, 'There must be a way. If the Crystal key is actually changing maybe you can calibrate it to recognize you as a valid user. There might be Some object or building there with a means of calibrating the key. Is there any area that''s more heavily guarded than the rest?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3282, 104520, 'The Unas... I think I know where to go.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3320, 111267, 'Sure.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3320, 111268, 'Be careful, the Slums aren''t exactly friendly.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3844, 107729, 'I was wondering about Laro... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3283, 104547, 'You were electrocuted? That is so Ra. He loved electricity... No doubt that must be part of his security system - in place to prevent access from unauthorized people - like you. Undoubtedly there is a way to recalibrate that crystal do-dad and bypass security. ', 1632, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3283, 104548, 'You''re sure?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3283, 104549, 'I knew Ra. He was a paranoid - so he would defend everything he could vigilantly. But, he also was impatient, so he would make bypassing security easy for himself and his minions - who were often intellectually challenged. The solution to this is around you somewhere.', 1632, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3283, 104550, 'There are large groups of Unas here guarding certain artifacts.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3283, 104551, 'Well there''s your answer. Unas tend to fervently defend objects that hold religious significance to them. Ra used their gullability to his advantage. Go to whatever location they''re slobbering over and see if you can''t recalibrate the Crystal Activator.', 1632, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3296, 73648, 'DELETE', 1126, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3297, 76947, 'The Unas are agitated and upset. They clearly want to do harm to outsiders, but why?. You’ve noticed a non-hostile Unas outcast.', 1126, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3298, 76962, 'Perhaps you can learn something about why the Unas are so hostile from this one.', 1126, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3299, 104687, 'Vey''Ka not fight. You kill me. They kill me. Hopeless.', 1654, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3299, 104688, 'Why are the others fighting?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3299, 104689, 'You enter temple we die. None stranger can enter temple. So we fight. We fight forever. Hopeless.', 1654, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3299, 104690, 'Why would you die if someone entered the temple?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3299, 104691, 'Ra has cursed us. We fight forever - keep you out - or you enter and we die.', 1654, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3299, 104692, 'Is there a leader I can talk to? Maybe the curse can be lifted.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3299, 104693, 'Zhaakaa leader. He will kill you. Must prove you are Unas friend. Take him Kalas, holy relic of Ihpet Unas. He then may listen. It can be found in ruins.', 1654, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3300, 76806, 'DELETE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3301, 99696, 'Investigate the Goa''uld Lab', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3302, 120280, 'Clearly we need to see if this story is true. Check out that lab... If it is true then we may have a problem when it comes to getting inside that temple.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3302, 120281, 'There is no way the Leadership Council would jeopardize an entire colony of Unas.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3302, 120282, 'Bingo. If you think about it, it''s brilliant. It''s another layer of Ra''s defense.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3303, 104742, 'The machine implants capsules into the Unas that release toxins on via some kind of remote command. There must be some kind of kill switch inside the main temple that is triggered by intruders. Entry in there would kill the whole Unas colony.', 1656, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3303, 104743, 'If you can find a way to reprogram the capsule frequency, you may be able to deactivate the capsules - rendering the capsules implanted into the Unas inert.', 1656, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3304, 76833, 'You begin to hack the Goa''uld machine', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3305, 104804, 'Reprogram the capsule tester at The Wall of the 13th Hour and free the Unas.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3306, 104779, 'There are glyphs on the Wall of the 13th Hour that might give us clues to the frequency. If you can reprogram this... You can save these people.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3306, 104780, 'Even as they try to kill me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3306, 104781, 'No one ever accused the Unas of being excessively bright. Hurry, the sooner you do this, the better. ', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3307, 104796, 'I felt change... This was you removing curse? ', 1655, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3307, 104797, 'Yes. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3307, 104798, 'I cannot trust...', 1655, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3307, 104799, 'You feel different because I deactivated the capsule inside you. All of your people feel different.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3307, 104800, 'This is truth. I heard many say it.', 1655, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3307, 104801, 'You are healed.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3307, 104802, 'You are great friend. Unas are suspiscious, but Zhaakaa try to tell them you friend. Zhaakaa give you totem of friendship. You show this and maybe they not attack.', 1655, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3308, 111067, 'If these glyphs are correct, you can hack the network Ra uses to poison the Goa''uld right here... It will tough, but if you do this right, the entire colony will be saved.', 1127, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3309, 104803, 'Reprogram the capsule frequency at The Wall of the 13th Hour.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3310, 104752, 'So these creatures live in fear... Let''s use it for our advantage, shall we? The Wall of the 13th Hour has data on it about the frequencies that were used. Figure out how to reprogram the Capsule Tester so that we can use it to throw the kill switch any time we want...', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3310, 104753, 'Sort of a Hand of God over the Unas?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3310, 104754, 'Exactly a Hand of God. If they think we can kill them, they might keep away from us...', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3311, 104759, 'While not perfect, the Capsule Tester does look like it will throw the signal directionally. Now it''s time to send a message to the Unas colony by setting Zhaakaa "free" - in front of witnesses. ', 1127, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3315, 111253, 'Head to Lower Compost Flats and use the census taking device at the specified locations.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3316, 111254, 'Personally I haven''t heard about Ra or his Jaffa here on Lucia. The Jaffazons are the only tribe I know of here - but they work for a Goa''uld slave runner called Opheltes. ', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3316, 111255, 'Is he connected to Ra?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3316, 111256, 'No, he''s an independent... I could do some research with the Burtonol people - our sister company here... They would know if there were Ra Jaffa around.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3316, 111257, 'Could do some research?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3316, 111258, 'Unfortunately. I''ve been under the gun lately - these Burtonol people are relentless and I''ve been asked to assist them on some relocation projects. I simply haven''t the time to spend on side tasks... ', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3316, 111259, 'Can I help?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3316, 111260, 'Absolutely. To start with, you could go into the Lower Compost Flats and take some census readings. It''s really easy to do, and it would give me time to look into your situation immediately. Be careful though - the locals in the area are a tough bunch. ', 611, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3317, 111261, 'The body - conspicuously left in the street - has been maliciously treated, abused even after death. You notice the uniform has a Burtonol symbol on it. ', 494, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3318, 59275, 'You finished! Thank you...', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3318, 59276, 'I found a body out there...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3318, 59277, 'Mowbry? ', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3318, 59278, 'Yes...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3318, 59279, 'I was afraid of that... Sanderson - one of the Burtonol employees - told me he had been missing... Tech Con Group''s attempts at civilizing this world have inspired some of the locals to mindless terrorism... I never leave The Zone for that reason...', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3319, 111262, 'Head to the Slums and continue the census survey.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3452, 115040, 'A cure?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3321, 90490, 'I was analyzing some of the data you sent and found something interesting - or scary... There was another Burtonol operative, Alpin, missing...', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3321, 90491, 'In the Slums?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3321, 90492, 'Yes... I think the device may have accidently found him, or something that was his... I''ll upload the location of the anomaly to you...', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3321, 90493, 'I''ll investigate.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3322, 111312, 'Another Burtonol corpse - similar in state to Mowbry''s... You hear a faint sound - a beeping - you pull back the shirt to reveal a crude radio device... Almost immediately you hear a voice coming through the transmitter.', 460, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3323, 111317, 'Do not fear... But I can see you right now. You have been working for them - Burtonol and its parent company, Tech Con Group - but you are not an employee... You seek something...', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3323, 111318, 'Who are you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3323, 111319, 'I am called Evron. Know they will lie about me, but you can find the truth. Speak to Vala Mal Doran and ask her about me... I can find what you search for, and you can help me in return.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3323, 111320, '(The radio abruptly dies. )', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3324, 111321, 'Evron spoke to you? He''s a terrorist - he killed Mowbry and Alpin to name just two... You want to stay clear of him. Burtonol has a price on his head.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3324, 111322, 'And Vala Mal Doran?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3324, 111323, 'Hangs around the Zone''s nightclubs. She is a chameleon. She knows everyone but cannot be trusted... These are people to be avoided, $name$.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3324, 111324, 'Could she know something about Ra''s presence on Lucia?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3324, 111325, 'Perhaps... But know that you are courting disaster each and every time you speak with her. ', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3325, 90458, 'Well, hello you... Have we met?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3325, 90459, 'We have mutual friends... Eamon and Evron.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3325, 90460, 'Eamon and Evron? You run in interesting circles indeed... But you have come to me. Why? What can I do for you? Or to you?', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3325, 90461, 'Tell me about the terrorist, Evron. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3325, 90462, 'You took the serious option. Well, to begin with, Evron is not a terrorist, he''s a freedom fighter.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3325, 90463, 'Burtonol and Tech Con Group say differently.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3325, 90464, 'Burtonol and Tech Con Group want land...', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3326, 111352, 'Go into the Slums and recover information from the Kassa Dealers there', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3327, 111353, 'I can prove to you that Evron is not simply a terrorist, but you would need to do be willing to dig.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3327, 111354, 'Why should I even care?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3327, 111355, 'Because you''re on Lucia looking for information and, despite how much I adore him, Eamon is naive. He and his Burtonol freinds are not sources worth anything. Burtonol are the real terrorists.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3327, 111356, 'I''m supposed to believe that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3327, 111357, 'No. Look for yourself. They have their fingers in many pies. To be honest, I admire their approach, but they are far too cutthroat for my tastes. ', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3327, 111358, 'What kinds of things are they doing?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3327, 111359, 'Make your way into the Slums - the evidence of their business is out there. Bring whatever you find back to me. We''ll go from there.', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3328, 90519, 'I knew they had stooped low but... Burtonol are using the Mathas Brothers to fill the Slums with Kassa.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3328, 90520, 'Burtonol is financing a drug ring?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3328, 90521, 'Not directly. They don''t do things directly. But they know that supporting the Kassa trade will increase violence and, therefore, convince decent people to move off world... Burtonol want the land to expand The Zone. They make no secret of it.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3329, 111360, 'Go to Sewer Falls and find the Mathas Brothers'' hangout. ', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3330, 111361, 'The Mathas Brothers are the second largest gang of Kassa runners on Lucia. They are murderers - I know this firsthand. And I have heard, from good sources, that they work with Burtonol. ', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3330, 111362, 'Who are the sources?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3330, 111363, 'Would it matter? If you''re looking for the truth, you will find it in Sewer Falls. That is the Mathas'' base of operations. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3331, 59473, 'There is a connection between these thugs and Burtonol. If you look harder, you can find it...', 834, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3331, 59474, 'I''ve killed almost the entire gang... You want to be more specific?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3332, 111364, 'Check the Mathas Brothers computers for evidence of a connection to Burtonol.', 834, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3333, 111365, 'Check the Mathas Brothers'' computers... The evidence will be in there.', 834, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3333, 111366, 'The drug lords have computers in the Sewers?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3333, 111367, 'The evidence is in there...', 834, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3334, 111368, 'The computer is old, but unexpectedly clean for a machine stored deep inside a Sewer. You realize that you cannot simply get in without hacking...', 394, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3335, 111369, 'Once inside the system you find a surprising amount of information about the Mathas Brothers'' business, but nothing which connects them to Burtonol until - finally - a series of old documents... Burtonol supplied the Mathas Brothers with weapons. Apparently the Mathas gang simply took them, but the evidence is clear: Shipping manifests. ', 394, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3335, 111370, 'You download all the material you can. It''s not the best evidence, but it certainly shows that the Mathas Brothers have a Burtonol connection... However, you realize that they weren''t actually financing the Kassa trade... Vala.', 394, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3336, 59500, 'This is... I''m not sure what I can do with this... I don''t work for Burtonol.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3336, 59501, 'They sold the Mathas Brothers guns.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3336, 59502, 'Months ago. I don''t deny that there is something uncomfortable about these documents... I will certainly run these through the proper channels. They will find the corruption and terminate it - if that hasn''t already happened. We''re a very efficient corporate entity, <<playername>>. ', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3336, 59503, 'That''s it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3336, 59504, 'I don''t know what more I can do. ', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3336, 59505, 'Did you find anything on Ra?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3336, 59506, 'No, I''m afraid... I really can''t find anything of substance... He doesn''t seem to be on Lucia. I''m sorry.', 611, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90559, 'You''re back...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90560, 'You lied to me Vala. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90561, 'Lie is such a strong word. I prefer misled.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90562, 'You said Burtonol was financing drug dealers...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90563, 'And were they connected or not? They were. So I wasn''t really lying so much as goading... And you got rid of those nasty, bad drug dealers and did Lucia a world of good in the process.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90564, 'I don''t have time for diversions.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90565, 'Evron wants to meet you. What you did in the sewers gained his trust and he can be a very useful source of information. Now that I think about it, I think you owe me an apology...', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3337, 90566, 'We''ll see, Vala.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3338, 90572, 'I''m taking a great risk in revealing myself to you. I am the most wanted man on Lucia... ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3338, 90573, 'And the most enigmatic.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3338, 90574, 'If you are willing to help me, I can be of service to you as well.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3339, 111415, 'Disrupt the Kassa Operations at one of the Green Boot Farms.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3340, 111399, 'You seek information, correct?', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3340, 111400, 'Yes, it would be nice.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3340, 111401, 'I seek help. My people - the Lucian people - are bound by the scourge of Kassa. I will offer you a bargain: I will use my contacts to discover what I can about Ra...', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3340, 111402, 'You know I am looking for leads on him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3340, 111403, 'I know most of what happens on this world. I will give you information - reliable information - but I need from you in return. ', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3340, 111404, 'This is sounding familiar...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3340, 111405, 'There is a gang on this world known as the Green Boots lead by the overly-ambitious Netan. They are mercenary and simple, but their Kassa infects my people. I want you to go to one of their farms - I will upload the location - and disrupt the operation. ', 398, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3341, 111413, 'The drone is a simple design... Rendering it irreparable should not be too difficult...', 612, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3342, 111414, 'The refiner''s control console isn''t well maintained and comes off easily. You begin to re-wire the insides.', 638, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3343, 59559, 'You are remarkably efficient. My people owe you much. ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3343, 59560, 'You owe me information. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3343, 59561, 'Indeed.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3344, 111426, 'Stop Nais "The Ox" from delivering slaves to Burtonol', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111446, 'I have reason to believe that Ra may be working with Burtonol.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111447, 'That is absurd.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111448, 'My sources claim it is true.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111449, 'Who are these sources?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111450, 'I cannot say... But you already know Burtonol is corrupt. If you were to deliver to Eamon irrefuteable evidence, he might look deeper into their operation... ', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111451, 'And discover they are working with Ra? That''s unlikely.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111452, 'There is a slave runner Opheltes uses, Nais the Ox. She is dangerous, but I know that she provides Burtonol with labor. If you were to disrupt her and deliver that kind of proof to Eamon... ', 398, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111453, 'That would inspire him to dig...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3345, 111454, 'And you will discover things which genuinely surprise you, $name$. ', 398, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111436, 'This is... Most disturbing... SLAVES... I certainly will have to report this...', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111437, 'I think there''s more...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111438, 'You have additional evidence?', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111439, 'No, but I''ve heard rumors that Burtonol may be working with Ra in some way...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111440, 'Ra? That is impossible... The Goa''uld and the Serrakin have long had a non-aggression treaty, but for Burtonol to take on contracts from Ra would destroy the company... You heard this from Evron, I suppose?', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111441, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111442, 'He is using you. He is a crusader and he is using you to fight his fight against Burtonol...', 611, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111443, 'He keeps exposing them...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111444, 'Burtonol is a corporation. ANY corporation has employees who cross the line... Even Tech Con Group has has transgressions - which are always dealt with... Nothing he has shown us implies a massive conspiracy to the degree you describe. You cannot trust him, $name$. ', 611, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3346, 111445, 'I don''t know who to trust.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3347, 111455, 'Take the crystal artifact to Jackson on Omega Site.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3348, 111456, 'On Nais you discover something unusual - a Crystal Charm of Tok''ra design. Given the animosity inherent between the Goa''uld and Tok''ra, this is ertainly not something you''d expect to find on one of Opheltes'' Jaffazons... Assuming it is authentic, it might be worth having it analyzed on Omega Site.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3349, 90619, 'Interesting... Beautiful design... Definitely Tok''ra. This is a very, very personal object - the Tok''ra version of an heirloom. It wouldn''t be given up easily. You say you found this on a "Jaffazon"?', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3349, 90620, 'One of Opheltes'' slave runners...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3349, 90621, 'Well, given the Tok''ra''s resistance to all things traditionally Goa''uld - the slavery, the power mongering and the violence - you can be certain this wasn''t a gift. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3349, 90622, 'Opheltes may have a Tok''ra captive?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3349, 90623, 'Possibly.', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3350, 111519, 'Ask Evron about a possible Tok''ra in Opheltes'' slave pens.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3351, 111514, 'If there has been a Tok''ra captured by a Goa''uld, we can''t simply ignore it. ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3351, 111515, 'I can investigate.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3351, 111516, 'It''s possible that Opheltes might not even know. Despite the fact that the Tok''ra have symbiote, they are very adept at hiding that fact from the Goa''uld when captured. If, however, that Tok''ra has been exposed...', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3351, 111517, 'Torture?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3351, 111518, 'The Goa''uld would be merciless.', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3352, 111494, 'UNUSED DIALOGUE', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3353, 90651, 'I have heard stories of a rather exotic off-world capture made by the Jaffazon recently... A woman. I did not hear the word, "Tok''ra" whoever...', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3353, 90652, 'That might be a good thing.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3353, 90653, 'If this is your target, breaking into that area is very dangerous. They would be holding her in the special pens... High security... I''ve lost many friends there to Jaffazon Staff Weapons. ', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3354, 59957, '(You hold up the pendant you recovered off of Nais the Ox.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3354, 59958, 'Who are you?', 615, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3354, 59959, 'We don''t have a lot of time - is this yours?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3354, 59960, 'Yes. It is mine.', 615, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3354, 59961, 'Stand back.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3355, 111543, 'The pen Raully is in has a very complex locking mechanism. You feverishly begin disassembling it... You work quickly...', 623, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3356, 111679, 'Thank you for freeing me...', 615, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3356, 111680, 'We''re not out yet...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3356, 111681, 'I can get myself out now, I believe. Your fighting has caused ample distraction, and I get the sense you intend to cause more.', 615, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3356, 111682, 'We need to talk.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3356, 111683, 'I will meet you in the Zone Hotel. I shall be using the alias "Jane Doe." Do not forget it.', 615, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3357, 111691, 'My people had heard that Ra returned... Naturally, my people were motivated to do all we could to stop and destroy him... ', 615, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3357, 111692, 'And you came to Lucia in search of leads?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3357, 111693, 'Yes. The Tok''ra had heard that he had connections here and I was assigned to investigate. I was captured, but I managed to hide my data crystal from the Jaffazons. I eventually dropped it into some wreckage when I was clearing the Western Crevice in a slave detail.', 615, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3357, 111694, 'What''s on the Crystal?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3357, 111695, 'Everything I know. Opheltes is not aligned with Ra, but there are groups here who are... Jaffa. Human... ', 615, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3357, 111696, 'We have to get that Crystal...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3358, 111697, 'Recover Raully''s Data Crystal from the Western Crevice.', 615, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3359, 111718, 'There is something you should know... I was never sure, but it seemed that I was being followed... Even when I was in the custody of the Jaffazons I saw them...', 615, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3359, 111719, 'By?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3359, 111720, 'Jaffa. I do not know the tribe. I got the sense that if I were vulnerable they would have come after me, but they desired to remain covert... ', 615, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3359, 111721, 'Do they know about the Data Crystal?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3359, 111722, 'That may be what they are after... If that is the case, you will need to recover the Crystal quickly for they will be searching for it...', 615, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3360, 111586, 'I''ll have the Crystal decoded immediately but, you are telling me it was the Ruk''yal who were after it?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3360, 111587, 'Yes. They fought me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3360, 111588, 'We will investigate this. It''s most confusing... Especially given the invasion.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3360, 111589, 'Invasion?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3360, 111590, 'Dakara has been invaded by Ra. His Jaffa hit the world three days ago... The situation is chaos.', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3361, 111723, 'Return to Lucia to look for signs of Ra''s presence there.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111724, 'Interrogations of Jaffa in service to Ra on Dakara indicate that there may be something of great importance happening on Lucia. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111725, 'Lucia?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111726, 'Yes. The prisoners have yielded little information, but intercepted communications between Ra and his forces confirm that there is something of substance. We need you to return and continue your investigation... ', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111727, 'We got word of possible Ra Jaffa sightings, but there has been nothing about troop movements... It may be another one of his deceptions... ', 2410, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111728, 'Like the Council on Dakara...', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111729, 'Exactly. We need to look into every nook and cranny on that world and root out what he is up to. ', 2410, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111730, 'Do you have contacts there who may be useful in this regard?', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111731, 'You''re the only one of us with experience down there... ', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3362, 111732, 'I think I have someone in mind. ', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3363, 94839, 'You''re back. How delicious... How was Dakara?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3363, 94840, 'Bad. Have you heard anything about Ra and Lucia?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3363, 94841, 'Nothing specifically about Ra, but I may have something for you.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3364, 111807, 'Search the uppermost Compost Flats for a suspected meeting involving Ra''s Jaffa.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3365, 111808, 'There are some Jaffa in Lucia who have been seen having meetings with locals in Compost Flats... They''re not Opheltes'' Jaffazon... And there''s not a Goa''uld presence on Lucia. These may well be Ra''s minions...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3365, 111809, 'What are they doing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3365, 111810, 'I haven''t the foggiest. But I do know where it all happens... I''ll upload it to your PDA. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3365, 111811, 'You''re the best...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3365, 111812, 'I know. I''m adorable...', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3366, 111813, 'This Jaffa is certainly one of Ra''s - the outfit is standard issue. It''s the first confirmation of a Ra presence on Lucia. ', 215, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3367, 111814, 'The Burtonol Operative''s corpse has signs of Staff Weapon damage. Was he killed by Ra''s Jaffa? ', 535, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3368, 111815, 'You don''t recognize this victim''s outfit, so you cut an identifier patch off and pocket it. Clearly whatever happened here was a total shock for this guy - he doesn''t look like he was even armed. ', 835, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3369, 90754, 'The patch you recovered is from a vRip - one of the factions on Lucia... ', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3369, 90755, 'vRip?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3369, 90756, 'They''re traders. They collect all sorts of technologies and, well, junk... They do a lot of work on the world. I know them well.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3369, 90757, 'What about the Red Collar?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3369, 90758, 'They must have had the same information I did. They probably broke up the first meeting and figured they''d double their pleasure... But then they met you... You''re very good aren''t you?', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3369, 90759, 'I can take care of myself.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3369, 90760, 'You certainly can.', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3370, 111816, 'See the Junkyard Foreperson, Bedwyr to get closer to the vRips and find out what happened in Compost Flats', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3371, 112037, 'That fact that a vRip was involved with whatever happened in Compost Flats doesn''t surprise me. Like everyone on Lucia, Arlos has his hands in many pies.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3371, 112038, 'Arlos?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3371, 112039, 'He''s the head of the vRips. Handsome in an intellectual, trollish way...', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3371, 112040, 'Would he work directly with Ra?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3371, 112041, 'I honestly don''t know. Arlos is a bit of an enigma, really. I know a woman there, called Bedwyr. She adores me. Talk to her and she''ll get you an introduction to Arlos. ', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3371, 112042, 'Can''t you get me to him?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3371, 112043, 'There was a time when I could... But now it would be very, very complicated... Stick with Bedwyr.', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3372, 111843, 'Vala Mal Doran sent you... And you expect me to just lead you to Arlos? After what she did?', 617, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3372, 111844, 'What did she do?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3372, 111845, 'What didn''t she do? She left him a tattered husk of a man. Vala Mal Doran is no friend of mine... ', 617, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3372, 111846, 'Well, is there something I can do to see him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3372, 111847, 'For starters, you can duck.', 617, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3372, 111848, 'Duck?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3372, 111849, 'Get down - we''re being raided!', 617, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3373, 111824, 'Thank you... That was the second attack today. The Red Collar have been getting more and desperate...', 617, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3373, 111825, 'This happens often?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3477, 62475, 'So is she.', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3373, 111826, 'This is Lucia, so there''s always trouble... But lately it has gotten much worse... I''ll radio Arlos, it''s the least I can do after you helped me in a fight. He''ll be waiting in the vRip basecamp. Do not mention Vala.', 617, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111827, 'Aren''t you the one I''ve seen speaking with Vala Mal Doran in The Zone?', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111828, 'Maybe?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111829, 'How is she? ', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111830, 'She''s good.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111831, 'Remarkable woman, Vala. She made me see God. Literally. Any friend of hers is a friend of mine.', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111832, 'I came across a meeting site in Compost Flats and found one of your people dead... Along with a Burtonol Agent and a Jaffa...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111833, 'Ah yes... That... ', 480, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111834, 'I''d like to know more about that meeting.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3374, 111835, 'Wouldn''t we all? ', 480, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3375, 112140, 'Find and help Arlos''s scout Glaz in Crevice Lakes.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112027, 'I''m a businessman, $name$. A trader, by trade. I probably could have said that better, but you get my meaning. You want information from me... But what will you do to get it?', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112028, 'I don''t know. What will I do?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112029, 'I don''t know. What will you do?', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112030, 'I''m asking you that: What will I do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112031, 'You tell me.', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112032, 'You have to tell me. So I can do it.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112033, 'Exactly my point. First I need to see what you are willing to do. One of my agents, Glaz, was supposed to meet with a potential business associate... He activated his emergency call button. ', 480, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112034, 'You want me to bring him back?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112035, 'Impressive. It''s like you knew I''d ask you something like that. You''ve done this kind of thing before?', 480, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3376, 112036, 'A few times.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3377, 60598, 'Who are you?', 446, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3377, 60599, 'I''m here to help... Arlos sent me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3377, 60600, 'Thank God. The Red Collars ambushed me... The defector was just a setup... They''re starting an all-out war.', 446, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3377, 60601, 'We need to get you out of here.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3377, 60602, 'If you can get me to my brother, Watz, he can help me... He''s in a safe house. I know the way...', 446, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3378, 90844, 'Thank you for saving my brother... You need to let Arlos know that the Red Collars have escalated... They''re mobilizing for a real fight. ', 539, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3378, 90845, 'A war?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3378, 90846, 'Yes. They want war.', 539, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3379, 90829, 'The Red Collar are mobilizing for war... This is most disturbing... Flax must be desperate beyond what I had imagined... He has never done this before.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3379, 90830, 'Why are they attacking you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3379, 90831, 'Because I won''t extend them any more credit. Since they can''t buy guns from us anymore, they''ll try and take them. It''s all very Lucian... And exhausting.', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3380, 112139, 'Force the former vRip, Maco, to rejoin the vRips.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112063, 'The game has changed, $name$. I''m going to put my cards on the table, no more games, no more show... ', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112064, 'I''m listening. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112065, 'Help me fight Flax and his Red Collar mercenaries and I will give you my most valuable technology... A technology so experimental I''ve never even tested it. ', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112066, 'If you haven''t tested it, how do you know it''s worth anything?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112067, 'There''s a former associate of mine, Maco, who started working for the Red Collar because they paid him more... I think he could be a source of valuable intelligence. ', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112068, 'You didn''t answer my question...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112069, 'If you threaten Maco, he''ll squeal like a pig. ', 480, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112070, 'What''s the technology Arlos?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112071, 'A body armor that stops almost everything... I''ve never seen anything like it. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3381, 112072, 'Where can I find Maco?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3382, 112082, 'Please... Stop... I don''t want any trouble.', 619, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3382, 112083, 'Arlos sent me...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3382, 112084, 'Of course he did. Who else would attack the bookkeeper... What does he want?', 619, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3382, 112085, 'Information. Intelligence about the Red Collar...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3382, 112086, 'Fine. I''ll go back to Arlos...', 619, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3383, 112080, 'Your defector has been delivered. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3383, 112081, 'I know. We''ve already debriefed him.', 480, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3384, 112101, 'Cripple the Red Collar''s artillery pieces for Arlos.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3385, 112105, 'Maco''s intelligence indicates that somehow Flax has gotten his grubby little hands on some STAM Warheads. ', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3385, 112106, 'STAM warheads?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3385, 112107, 'Self-Tracking Anti-Matter Warheads - Artillery. If the Red Collar were creative, they could fire them right now... Fortunately their collective IQ is somewhere below an advanced roach, so we have some time. I need you to sabotage them with these Thermist Charges. Just place and step back.', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3386, 60705, 'Well done. Without those STAMs the Red Collar threat is much reduced.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3387, 112227, 'Swap the Red Collar munitions with Arlos'' booby-trapped versions. ', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3388, 112228, 'Maco has proven to be very useful... He hacked the Red Collar computer system and downloaded all the shipping information for their Space Port.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3388, 112229, 'Anything good?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3388, 112230, 'Apparently they just received a supply of munitions - for their mounted auto-cannon - but Flax is having delivery problems.', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3388, 112231, 'Should we acquire the shipment?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3388, 112232, 'Oh, that''s so straightforward, $name$. I have something more delicious... We''ve been developing this for some time - dummy versions of the auto-cannon shells. If they used them it would totally disable the cannon. ', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3388, 112233, 'So if we replace their munitions with your dummy shells...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3388, 112234, 'Exactly. Boom.', 480, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3389, 60706, 'We''ve got the Red Collars on the run, and they don''t even know it yet...', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3390, 112235, 'Steal the Red Collar payroll to effectively end their organization.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3391, 112236, 'My master plan is almost realized! Maco has revealed that Flax is struggling to meet his payroll. In the mercenary world, missing payroll is an especially bad plan because mercenaries are, well, mercenary. ', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3391, 112237, 'Go on.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3478, 115103, 'Get one of Evron''s followers off-world via the Stargate.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3391, 112238, 'He is reduced to paying in naquadah chips directly - no credits... If we could get to those chips, there just might be a rebellion...', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3391, 112239, 'This is the last task, Arlos. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3391, 112240, 'Agreed. Bring me their payroll crate and I will give you the body armor I promised... ', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3392, 112252, 'The crate''s lock is encrypted, but the mechanism looks relatively primitive to some others you have seen. You begin to pick the lock, carefully... ', 621, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3393, 112241, 'Ah... You have truly delivered, $name$. And, so will I. That armor is a prototype I "acquired" from some Burtonol agents. It''s called Repli-tech armor... It''s the most effective body armor i have ever seen. Conforms to the user, one size fits all...', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3393, 112242, 'Repli-tech?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3393, 112243, 'That is what they call it... It''s yours... Also... I want you to take half of this Naquadah and give it to the poor in Lucia. Knowing Flax the majority of it belongs to them anyway...', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3393, 112244, 'I didn''t expect this out of you, Arlos. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3393, 112245, 'I''m a man of many dimension... Say hello to Vala for me when you see her.', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3394, 60787, 'What is this?', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3394, 60788, 'A gift from a very unlikely source.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3394, 60789, 'I will make sure this gets to those who need it most...', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3395, 112246, 'The design of this armor is fascinating... The material is incredibly flexible. What is it called?', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3395, 112247, 'Repli-tech.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3395, 112248, 'That''s disconcerting... You don''t think it''s Replicator Technology?', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3395, 112249, 'It wouldn''t shock me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3395, 112250, 'We''ll get to work on it right away. Nice work.', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3396, 112253, 'Assist Evron is preventing Netan from taking control of Lucia.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112254, 'I need your help... There has been a disaster here - and you are partly to blame. ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112255, 'What''s wrong?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112256, 'While Arlos was weakening the Red Collar through you, Netan and his Green Boots were cutting off the faction''s head: Flax is dead. ', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112257, 'This was unexpected.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112258, 'Yes, and it means that Netan - a drug dealing crime lord - is poised to take control of the Red Collar. He may try and put all of Lucia under his control. With the Red Collar collapse, the balance of power has been disrupted.', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112259, 'Could he take on Burtonol and Tech Con?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112260, 'If he were to proceed unchecked it is possible. I am mobilizing the scattered forces I have to move against him. I need your help. Specifically, I need your expertise to disable Netan''s communications grid.', 398, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112261, 'Consider it done.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112262, 'I''ll keep you informed about our progress. I don''t think we can engage Netan without your support.', 398, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3397, 112263, 'You will have it.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3398, 112272, 'The communications grid is like most things Lucian: Jury-rigged and in decay. You snap the cover off and begin disabling it.', 213, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3399, 112264, 'I need you up to the Omega Site immediately. That armor you found? It is replicator technology. ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3399, 112265, 'Replicator technology? How?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3399, 112266, 'Apparently the geniuses at Burtonol are playing with Replicator technology. Report here for a full briefing. Carter out. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3400, 112273, 'Evron... This is $name$. The communications grid has been disabled, but I''ve been ordered off-world.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3400, 112274, 'You cannot support us in our attack?', 398, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3400, 112275, 'Not immediately... ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3400, 112276, 'Please come back if you are able, friend. We will proceed in our assault on Netan because we must strike while the iron is hot but... It is much to ask of simple people. ', 398, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3400, 112277, 'I''ll try and come back.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3401, 119078, 'Fundamentally that body armor is constructed of Replicators. Literally. Given their nature, it is only a matter of time until they gain sentience. If these types of products are mass produced...', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3401, 119079, 'We''d have a full scale Replicator invasion?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3401, 119080, 'It''s very possible. The source of the technology is Hebridan. Which is disconcerting because a good friend of mine just told me that it is being invaded. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3401, 119081, 'You think Ra might be after this technology?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3401, 119082, 'It''s possible. Whatever the reason, you''re going to find out. See General Hammond for a briefing.', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3402, 112351, 'See Eamon about getting into the Burtonol Campus.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113216, 'Given what we now know about Burtonol, it is important that we investigate their entire Lucian operation', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113217, 'With the exposure of the conspiracy on Hebridan, security in the Campus facility will be increased. In case there are Goa''uld infections, I will provide you with a Symbiote Teleporter...', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113218, 'Symbiote Teleporter?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113219, 'An Asgard technology designed to extract a symbiote from a host. It is experimental and survival of the victim is not guaranteed. However, in this case its use is warranted. ', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113220, 'Stopping Ra calls for extreme measures. ', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113221, 'Sending someone to the Burtonol Campus is reasonable, but dangerous. They are not likely to simply let us inside. ', 771, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113222, 'Eamon might be able to help with that...', 2568, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3403, 113223, 'Colonel Carter, you open communications with him. You, $name$, are going back to Lucia and you''re going to find your way into that campus - no matter what. We need to find out exactly what Ra is up to.', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61048, 'Colonel Carter has told me everything... I am... I am shocked... When I went to look into it I discovered that the Campus has gone on a full lockdown. ', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61049, 'You have to help me get into that campus, Eamon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61050, 'I cannot. The codes that Tech Con Group uses are biometric. They cannot be transferred... ', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61051, 'Can they be hacked?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61052, 'I once heard a rumor that the vRips managed to steal codes and gain access... ', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61053, 'Give me your code chip.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61054, 'Here... But... Please try and have him not break the chip... If possible... ', 611, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3404, 61055, 'No promises.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3405, 112307, 'Certainly I can modify the code chip - it''s child''s play. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3405, 112308, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3844, 107730, 'Yes?', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3405, 112309, 'Netan will eventually overpower Burtonol like he is overpowering everything else. I''m leaving this world - I even convinced Vala to come with me. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3406, 112289, 'uNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3407, 112310, 'The device to get into the Campus is simple enough. You slide the modified code chip through the slider. ', 412, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3408, 112350, 'Penetrate Burtonol''s Campus and interrogate their head researcher, Rychen.', 412, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3409, 112346, 'The Pass Scanner has accepted Eamon''s altered code chip, but displays a series of lockdown protocols - obviously you did not beat the news from Hebridan.', 412, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3409, 112347, 'You need security codes in order to access the Main Building... Arlos mentioned that the Burtonol Security Chief would be the most likely candidate to have the proper chip.', 412, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3410, 112314, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3411, 112348, 'The interlock uncouples and deactivates. ', 832, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3412, 112315, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3413, 112349, 'The interlock uncouples and deactivates. The lockdown has been deactivated.', 456, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112334, 'Thank you for removing that thing from me... ', 416, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112335, 'You''re hurt.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112336, 'There isn''t much time. Ra infected several of us... Stewart our CEO is one of them... They are running a program here on Lucia called Magmalife... It''s all for Ra...', 416, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112337, 'Do you need water?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112338, 'There iis no time for that! If MagmaLife comes online then Ra will get stronger, do you understand? He is more than a standard Goa''uld... His Goa''uld see him as their God... They fear him. MagmaLife must be destroyed...', 416, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112339, 'I''ll take care of it.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112340, 'It''s heavily guarded. His Jaffa, they have a camp inside the facility.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3414, 112341, '(He says no more and, as you move toward him, he fades into death.)', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3415, 112359, 'Destroy MagmaLife, Ra''s secret project on Lucia.', 1358, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3416, 112367, 'The symbiote seperation process proved fatal to Rychen... But he made it very clear that the MagmaLife project was a threat of massive importance. His password opens up detailed blueprints and security plants.', 1358, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3416, 112368, 'The project''s prototype sits atop a mountain to the north of Compost Flats, but getting there is far from trivial. First, the summit transporter is only accessible with a special biometric ring - only possessed by Ra''s Jaffa Prime on this world, Kal''ju.', 1358, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3416, 112369, 'Second, the summit itself is protected by a defense grid powered by geothermal conduits, which will have to be taken out to have a chance at penetrating the facility. You resolve to destroy MagmaLife with all due haste.', 1358, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3417, 112406, 'These conduits power the security grid for the MagmaLife facility. Traveling up there without shutting them down would be suicide. You set to work sabotaging...', 440, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3418, 112402, 'The conduit is going to require a powerful explosive to crack... Burtonol camps leading here seemed to have excavation-grade material that might do the trick.', 440, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3419, 112396, 'I''m free... Thank you... Your timing is impeccable... This entire site went active this morning...', 422, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3419, 112397, 'Are you okay?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3419, 112398, 'I''m hurt but... I''ll survive... This facility needs to be destroyed. The entire project is centered on building a portal device for Ra - insanely complex technology. He''s building this portal to be used in conjunction with something else - God only knows what.', 422, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3419, 112399, 'What does it do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3419, 112400, 'He believes it will "summon an army". I don''t know what that means, but it scares me. His crystal tech is so advanced... None of his his own Goa''uld even understand it. I don''t want to think about what he''s trying to do. Lucia and the rest of the Galaxy will be a safer place if you can manage to destroy it. ', 422, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3419, 112401, 'I''ll get it done.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3420, 112405, 'This device appears to be some form of transit portal augmented by Ra''s Crystal Technology... The focus of all Ra''s labors on this world. It appears dormant, and you set to work destroying it.', 467, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112374, 'You''ve done good work, $name$. We''ve ended a credible threat on Lucia.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112375, 'Your efficiency in solving this problem was notable.', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112376, 'This begs the question: What does this portal do?', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112377, 'Ra claims it will summon an army... There are various things that could mean...', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112378, 'Some sort of Quantum Mirror?', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112379, 'Possible...', 431, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112380, 'With all due respect, I fear my human colleagues miss the larger point in today''s victory... ', 771, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112381, 'Which is?', 431, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112382, 'It''s not what this portal does - whatever it is, we know it will be bad. The larger question is: Was this the only one? ', 771, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3421, 112383, 'That is a good point, Master Bra''tac... And something we will need to look into... Deeply.', 2410, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3422, 41396, 'I just received a message to examine the [INSERT POI HERE], but I''m busy here. I need someone to check it out for me... care to help me out?', 951, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3423, 114917, 'Help Eamon get a delayed Medical Aid shipment moving.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3424, 61427, 'There''s another thing that I could really use some help with... I had set up a program where we would help the local poor with medical supplies - got it approved and everything - but there''s been a delay in their delivery. Can you check with Sanderson and see what the holdup is?', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3425, 61428, 'Medical supplies? Yeah, I''ve got them... Who are you, some contractor?', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3425, 61429, 'In a way. I''ll take them to Eamon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3425, 61430, 'He wants to give them to the poor. Sorry. Not going to happen. They are my backup supplies in case my stock runs low. We''re a corporation, not a charity... ', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3425, 61431, 'But they were earmarked for the poor.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3425, 61432, 'Not anymore.', 452, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3426, 61433, 'He wont give them to us... That''s not... Right. They''re mine. ', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3426, 61434, 'How can we get them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3426, 61435, 'We could break the rules... A little. Supplies around here often "go missing". The company thinks it''s a sign of Black Market activity. ', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3426, 61436, 'How do we do that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3479, 115104, '$name$, I have a request of grave importance... One of my people - a man called Citan - is being pursued by Burtonol. ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3479, 115105, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3426, 61437, 'We just adjust the manifests. We can say they were damaged in transit and then you can simply take the supplies and deliver them yourself. It just means I can''t be seen delivering them. ', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3426, 61438, 'Let''s do it.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3427, 114919, 'You find the stores and access the computerized manifest. You begin to hack the system so you can change the status field...', 648, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3428, 114920, 'The field now reads: ''damaged in transit.'' You take the supplies.', 648, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3429, 61441, 'I don''t like bending rules like that but... It was for a good cause. Thank you.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3430, 114916, 'Distribute the brochures about Burtonol''s Colonization plan.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3431, 114912, 'I can''t believe I''m going to ask you this but... ', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3431, 114913, 'Go on.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3431, 114914, 'I''m in a bit of trouble... There was a delivery of some Burtonol Colonization Brochures that I completely forgot about... Could you - possibly - deliver them for me? It''s only two stops - I''ll upload the delivery contacts to your PDA. ', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3432, 61470, 'Colonization Brochures! Let''s see how marketing is going to sell under-bidding on shanty town condominiums today...', 157, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3432, 61471, 'You don''t want them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3432, 61472, 'Of course I do. These make it easier to convice squatters to sell their land at cut rate prices... Thanks for the drop off.', 157, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3433, 61474, 'Brochures! I''ve been waiting for these for weeks!', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3433, 61475, 'You don''t even work for Burtonol.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3433, 61476, 'They are handy covers for my own brochures... We''re creating a new Lucia here in the Plains - a better Lucia... I wrap the Burtonol brochures around offers of relocation to the Plains and my neighborhood grows...', 195, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3433, 61477, 'That''s... Ingenious...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3433, 61478, 'I know. Can you get me some more?', 195, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3433, 61479, 'I''ll look into it.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3434, 61480, 'You finished?', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3434, 61481, 'Yes. Jordin was especially enthusiastic. She wants more.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3434, 61482, 'I don''t even know how she got on the list...', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3435, 41313, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3436, 41361, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3437, 40968, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3438, 41319, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3439, 41366, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3440, 40976, 'NEW', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3441, 114921, 'Deal with the rogue Burtonol Agent Sorpen.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3442, 114922, 'How would you like to do something for the greater good?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3442, 114923, 'Such as?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3442, 114924, 'There''s this man called Sorpen... He works for Burtonol but I have it on good authority that he is running slaves and Kassa. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3442, 114925, 'How do you know that?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3442, 114926, 'I have my ways... You have an in with Eamon, the Tech Con liasion, right? Tell him what Sorpen is up to and he''ll be certain to get him transferred off-world. ', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3442, 114927, 'What is your stake in this Vala?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3442, 114928, 'It''s personal.', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3443, 62107, 'You think Sorpen has been running slaves and Kassa? These are very serious charges.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3443, 62108, 'I''m not sure how legitimate they are... My source is weak. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3443, 62109, 'Well, I certainly can''t run this up the ladder without some kind of evidence. Sorpen does work in the Corporate Responsibility Branch - and they work directly with all the undesirables on the world - but they work to try and refine them.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3443, 62110, 'Could he have gone rogue?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3443, 62111, 'Ask him yourself. I''ll upload his locator to your PDA.', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3444, 114930, 'Let me guess, Vala Mal Doran told you all sorts of bad things about me and convinced you to come down here...', 1630, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3444, 114931, 'How''d you guess?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3444, 114932, 'Because I dumped her and she can''t handle it... She''s been spouting all kinds of lies. I suppose she claimed I beat her and cheated...', 1630, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3444, 114933, 'She didn''t say that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3444, 114934, 'Really? What else has she come up with?', 1630, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3444, 114935, 'She said you''re running slaves and Kassa.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3444, 114936, 'Hmmm... I didn''t know she knew about that. She''s a remarkable snoop, that girl. But it just means bad luck for you, because that is a rumor I really can''t afford floating around.', 1630, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3445, 114929, 'Remarkable... Although this evidence is too circumstantial to take to my supervisors, I do believe your story, $name$. I am glad you survived his attack.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3446, 114937, 'Secure some of Sorpen''s things from his locker in the Tech Con Office.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114958, 'Oh, $name$... I fear there has been a disaster... I have been called into the office of Moldavour - my supervisor... He wants to ask me about Sorpen. They found him dead... What do I do? What do I do?', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114959, 'Calm down, Eamon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114960, 'I NEVER see my supervisor. I''m an ex-ex-exmplary employee... But they think he w-w-was m-m-murdered... Moldavour is a by-the-book type. This may be my career.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114961, 'What if we can prove Sorpen was working with one of the local factions?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114962, 'You mean... We plant evidence?', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114963, 'Exactly. We know he was bad, so it''s not like we''re doing the wrong thing... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114964, 'That''s... That''s... A g-g-g-ood idea... He had a desk in the Tech Con Office. You could get his things and deposit them somewhere... Then I could tell Moldavour where and it will look like Sorpen was killed by gangsters...', 611, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114965, 'Where should I plant his things?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114966, 'There is a Green Boot Kassa farm nearby. I''m shaking...', 611, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3447, 114967, 'Calm down... Go to your meeting. I''ll set get his things to the farm right away.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3448, 115002, 'The drawers are locked. You begin to pick the security panel...', 1626, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3449, 62185, 'I think I did well... There was only a little sweating and I coughed once... Did you get his things to the farm?', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3449, 62186, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3449, 62187, 'I am relieved... Drained really... This is not something I am accustomed to... I think we''re fine... Are we fine?', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3449, 62188, 'You''re fine Eamon... Just breathe.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3449, 62189, 'Breathing... Breathing is good.', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3450, 114971, 'UNUSED DIALOGUE', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3451, 115032, 'Find the scientist with the antidote to Kassa addiction in Sewer Falls.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3452, 115039, 'I went through some of the Mathas Brothers'' computer files and found something interesting... They mention - vaguely - that there may be a cure for Kassa addiction.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3452, 115041, 'They believed that a scientist they were using - Podhertz - is some kind of Kassa growing genius... He also may know of a cure. Seek him out and, if he has no cure, his death will be beneficial anyway...', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3452, 115042, 'I''m not an assassin, Evron.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3452, 115043, 'Nor am I... But my world''s future is at stake and this man refines Kassa to be more addictive... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3452, 115044, 'I will do that.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3453, 91471, 'A cure for Kassa? That''s impossible - it''s the most addictive drug I''ve ever encountered... I had concocted a vaccine that showed promise but...', 706, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3453, 91472, 'But?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3453, 91473, 'It was taken by Netan''s men - they came in here after the Mathas Brothers were killed. I hid. They took everything... ', 706, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3453, 91474, 'The vaccine?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3453, 91475, 'They took my papers... The vaccine was described there.', 706, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3454, 62325, 'A possible cure exists...', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3454, 62326, 'Not quite a cure...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3454, 62327, 'Something... You must understand how valuable anything that can curb Kassa''s addictive power can be.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3455, 62355, 'Acquire Podhertz''s vaccine from Netan''s Green Boot Farm.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3456, 62349, 'I know Netan - he is ambitious, but simple. If there is a vaccine that works he will have tried to exploit it. He would sell both the drug and the cure if he could.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3456, 62350, 'So the vaccine could be intact?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3456, 62351, 'Most certainly. He uses a farm for research projects. The vaccine will be there. Do you think you can get in and get out with it?', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3456, 62352, 'I can try.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3457, 62353, 'We have to distribute this as soon as possible. I will handle one of the other neighborhoods... Put his dosage in the water supply near here... ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3458, 91205, 'Now we wait and see... If this does have an effect it may save thousands.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3459, 115045, 'Investigate the chemical used by the slaver Opheltes'' to dope his victims.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3460, 115046, 'There''s been a sharp upturn in the slave trade in recent months. Certainly Burtonol''s rapid expansion is part of it, but I''ve also heard that Opheltes is using a new drug to great effect...', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3460, 115047, 'A drug that makes people slaves?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3460, 115048, 'No, it just makes them susceptible to suggestion - making them easier to capture and transport without conflict. I''ve got word that he has stores of the drug in his base of operations.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3460, 115049, 'I''d like to analyze it...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3460, 115050, 'If we could find a counter-agent we could reduce the slave trade by 50%.', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3461, 115057, 'You open the stores and notice that the packaging looks like standard Tech Con pharmaceutical wrapping... You begin to analyze the drug using your kit...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3462, 62380, 'The compound is very complex - made by a professional pharmaceutical house as opposed to something concocted in the field... Given Tech Con Group''s connections with this world, it''s very possible this drug was manufactured on Hebridan.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3463, 115052, 'Chemorol is a pretty common drug on Hebridan... Tech Con Medical prescribes it as a relaxant and anesthetic all the time...', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3463, 115053, 'What about high doses?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3463, 115054, 'I''ve heard it has side effects but... We don''t give it in high doses.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3463, 115055, 'Is there a counter-agent? ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3463, 115056, 'I''ll have to look...', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3464, 115058, 'Locate the stolen Anti-Chemorol at the Red Collar Outpost.', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3465, 115059, 'There is an Anti-Chemorol product - recently introduced to the market. It seems to be designed to counteract the effects of high doses of Chemorol. ', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3465, 115060, 'Can you get me a sample of that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3465, 115061, 'There was a whole shipment sent to Lucia - earmarked for the Corporate Responsibility Division - but it has been listed as "lost in transit." That means it was probably stolen by the Red Collar. ', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3465, 115062, 'This happens often?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3465, 115063, 'Usually it is Black Market activity, the products get re-routed. It''s disgusting. If the Red Collar have it, it is likely at their outpost - they tend to re-sell our products from there.', 611, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3465, 115064, 'Openly?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3465, 115065, 'This is Lucia. Much happens here that shouldn''t.', 611, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3466, 115067, 'This could save many lives, $name$. Thank you. I will spread it amongst the at-risk population...', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3467, 115068, 'Meet Vala''s contact Fionne in Crevice Lakes.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3468, 115069, 'I''ve got a friend in Crevice Lakes called Fionne... She has a package for me which you may be interested in. If you''ll go get it, I promise to share in the spoils...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3469, 115073, 'I''m too injured to move... You have to let Evron know that she is alive...', 1620, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3469, 115074, 'Vala sent me to see you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3469, 115075, 'Then tell Vala... Tell them Torb has her... She''s alive... ', 1620, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3470, 91143, 'She said "she"? Impossible...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3470, 91144, 'Who is this mystery woman?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3470, 91145, 'Kai. Evron''s wife. Everyone thought she was dead... But Fionne must have seen her. Torb must have her...', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3470, 91146, 'Who is Torb?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3470, 91147, 'He''s tall, dark and dim. Torb. Former Red Collar who has turned Crevice Lakes into his own fiefdom... He must have snatched her months ago...', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3471, 115088, 'Keep Kai safe by taking down Torb in Crevice Lakes.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3472, 115089, 'If Torb saw you with Fionne, it is likely he might move to do something to Kai. He''s a pig - handsome - but he''s basically an animal. If he thinks Evron found out that Kai''s alive he may do something terrible...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3472, 115090, 'I''ll hurry.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3472, 115091, 'You''ll have to deal with Torb. Be careful...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3473, 115095, 'As Vala feared, Kai was killed recently. You find something on her body... A ring...', 453, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3474, 91178, 'I was afraid of that... Sometimes I think I need to get off this world for good.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3475, 115093, 'Take the ring to Evron.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3476, 115092, 'The ring you find looks like a Wedding Ring... If it is her wedding ring Evron may want it back as a memento.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3477, 62471, 'Her ring... I gave her this a lifetime ago. She was in Crevice Lakes all this time?', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3477, 62472, 'Held by Torb.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3477, 62473, 'A pig... Did you?', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3477, 62474, 'He''s gone.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3479, 115106, 'They tried to seize his house and he fought back... They have branded him a fugitive. I fear they may kill him.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3479, 115107, 'Kill him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3479, 115108, 'You do not understand Lucia yet, friend. Citan''s life is in danger - can you please help him?', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3480, 115112, 'Are you the one sent by Evron?', 1628, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3480, 115113, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3480, 115114, 'Burtonol has put a price on my head. My family is already through the Stargate... Can you help get me there? I would be eternally grateful...', 1628, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3481, 115115, 'Thank you, $name$. You have given my family a chance at a new life.', 1629, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3482, 115147, 'Take Arlos'' romantic message to Vala.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3483, 104558, 'Continue the ritual at the Temple of the Dawn', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115176, 'I have something to ask of you, but it''s... It''s more personal in nature.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115177, 'You''re sweating.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115178, 'I do that. Ignore it. How well do you know Vala Mal Doran?', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115179, 'I know her...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115180, 'Well, here''s the thing: She and I shared a - moment - a few weeks ago... I''m almost certain of it. I mean, it seemed like a moment to me - we locked eyes - and I''d like to extend it a bit. Perhaps into a lifetime. ', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115181, 'Aw...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115182, 'I want you to set up a date with her for me... Tell her it would be extravagant - amazing! I''d ask her myself but...', 480, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115183, 'You''re afraid?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3484, 115184, 'Yes.', 480, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3485, 41407, 'The Goa''uld are up to something here. See if you can get any info out of Nerus.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91009, 'Arlos sent you to ask me on a date? He must have forgiven me.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91010, 'For what?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91011, 'Long story. Short version: It involved a stabbing, three Jaffazons and a Kor Mac bracelet... I still don''t have feeling in the tip of this finger. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91012, 'He said you shared a moment.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91013, 'Arlos is not exactly my type...', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91014, 'He''s got a big heart.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91015, 'Yes, but the rest of him is positively dwarven. You know what they say about small shoes...', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91016, 'Surely there''s something about him you can find attractive?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91017, 'He''s rich. ', 156, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91018, 'He said he''d make the date special...', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3486, 91019, 'Special... This would be special: We have a meal at Euphorion, enjoying a snifter of Lesic ''43 while I dab on the Grinnell Number 6 that he brought me as a gift. Something like that might make me interested. ', 156, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3487, 61851, 'Euphorion? It takes six months to get a reservation there and they don''t even serve food - they give you flavor cubes at 1000 Naquadah-a-pop so you can sit and stare at people as you starve... The Lesic ''43 is impossible to find and Grinnell Number 6 is 15,000 Naquadah an ounce...', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3487, 61852, 'So you''re not going to go?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3487, 61853, 'Are you insane? Vala is worth double that. I''m just upset because I am cheap. However, I am also resourceful... Bedwyr just happens to have the brandy in her personal stock, there is an impounded shipment of Grinnell at the Spaceport, and the Tech Con Reservation System is incredibly easy to hack. You could clear the whole restaurant out for us if you wanted.', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3487, 61854, 'Me?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3487, 61855, 'Of course you, you''re the one that got me into this.', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3488, 115185, 'He wants me to give you what?', 617, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3488, 115186, 'Your Lesic ''43.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3488, 115187, 'For a date with Vala? The nerve of that man... There is no way I will ever give him that bottle to use with her...', 617, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3488, 115188, '(You realize this will be a difficult negotiation.)', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3489, 115172, 'You know, you''re right... He isn''t worth it... If he wants to chase vapid, money grubbing... No man is worth it... No man...', 617, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3489, 115173, 'He probably won''t even enjoy the date.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3489, 115174, 'Of course he won''t! She just wants his money. This will be a good lesson for him... Thank you, $name$, for helping me see the light.', 617, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3489, 115175, 'Thank you for the Lesic ''43.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3490, 104564, 'It looks like the Crystal Key has been recalibrated into an Energized Crystal Activator. Hopefully this modified technology makes it safe to re-attempt the ritual back at the Temple of the Dawn.', 1130, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3491, 115189, 'The reservation system is easily accessed. A hack should take only a few minutes.', 462, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3492, 115190, 'The restaurant has been cleared for a date next week.', 462, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3493, 91020, 'Outstanding... You''ve made sure this date will be smashing success. ', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3494, 115125, 'Meet with the Burtonol Representative in the Junkyard.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3495, 115126, 'There''s a liasion from Burtonol that wants to meet with me... Perhaps you''d like to meet with them first and ask questions...', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3495, 115127, 'What do they want with you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3495, 115128, 'Typical Lucian graft... You can meet them, ask them your questions and then bring them to me.', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3496, 110930, 'You re-insert the key... It seems to take again, but you won''t know until you interact with the runes if it worked or not. ', 1129, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3497, 115120, 'We''re here for the gear...', 640, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3497, 115121, 'What gear?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3497, 115122, 'Arlos stole some technology from us - very powerful technology - and we want it back.', 640, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3497, 115123, 'I have nothing to do with that. I wanted to ask you about Compost Flats.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3497, 115124, 'It''s one of Arlos'' diversions, fellas... Let''s send him a little message.', 640, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3498, 61930, 'They attacked you? Inconceiveable. You got this ID Tag from them?', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3498, 61931, 'They seemed to think you have something of theirs.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3498, 61932, 'Possession is nine tenths of the law... I think I can use this tag... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3498, 61933, 'Why do I think you want me to do this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3498, 61934, 'Because it will benefit you too, my friend. You want to know what they are up to just as much as I do... There is an exposed network node in The Zone. Use this to tap it.', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3499, 61935, 'The tap is working perfectly... We can monitor most of their radio communications and even some computer networks...', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3500, 115129, 'Bring Evron''s request for arms to Arlos.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3501, 115130, 'Vala told me you''ve made contact with Arlos, the leader of the vRip faction...', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3501, 115132, 'She seems to have the impression that he isn''t completely a lost cause... I have my doubts, but I am a cynic. Is it possible he would be amenable to working with me and my followers?', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3501, 115133, 'I don''t know. I''ll ask. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3502, 62029, 'Evron... The crusader... He actually thinks that he can change Lucia? He should start with Netan and his Kassa-running Green Boots.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3502, 62030, 'He wants your help.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3502, 62031, 'Interesting. Even if he is naive and insane, he could be a useful contact... There is an old stock of weapons in the junkyard - you can take those to him... ', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3502, 62032, 'You want nothing in return?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3502, 62033, 'Sometimes you have to spend money to make money.', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3503, 62034, 'The weapons surplus? It was taken by the Red Collar during their last raid. I have a tracking device on it - so I know where it is, but I don''t have the manpower to get it back...', 617, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3504, 62035, 'He delivered... And he wanted no payment?', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3504, 62036, 'No. He offered it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3504, 62037, 'Hmmmm. Perhaps there is hope for Lucia yet.', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3505, 115136, 'Disable the Kassa enhancing devices at the Green Boot Base.', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3506, 115137, 'What''s your opinion of Kassa, $name$? ', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3506, 115138, 'It''s a terrible, addictive drug.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3506, 115139, 'It''s destroying Lucia. Literally. The largest supplier - Netan and his Green Boots - are infecting the world with it. But I just got some information that we could use to hurt his operation. Interested?', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3506, 115140, 'I''m listening.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3506, 115141, 'I acquired a map which outlines where he is housing some Kassa refiners and even a hydroponic breeder. Destroying those would certainly slow down his operation...', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3506, 115142, 'What''s your angle?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3506, 115143, 'In this case, nothing. I hate Kassa and everything about it - the drug is a scourge. There is no benefit for me on this one.', 480, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3507, 115145, 'You begin to disable the Kassa Refiner.', 1625, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3508, 115144, 'The Breeder is a complex device. You open the computer cover and being to access the internal wiring...', 538, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3509, 115146, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3510, 91316, 'Thank you... Perhaps we''ve given Lucia''s poor a little extra time to breathe...', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3511, 41572, 'There''s some suspicious activity going on around here. Can you give me a hand with this?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3512, 41463, 'Someday, you will whomp me with that Staff. But for now, let''s just talk it out. Why can''t we be friends?', 957, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3515, 113234, 'Investigate the source of the Ancient energy signatures Carter has detected on Lucia', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3535, 76769, 'The Unas are acting crazy and suicidal, more so than usual, but you’ve noticed a non Hostile Unas outcast.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3555, 104696, 'Though you bring the Kalas, Zhaakaa cannot help you. We are cursed by Ra. You enter, we die. You cannot enter.', 1655, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3555, 104697, 'How do you know the curse still works?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3555, 104698, 'Unas taken by Goa''uld. They cut us. We are altered - cursed. Then brought back here. To fight. To die.', 1655, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3555, 104699, 'Interesting... Are you taken to some sort of laboratory here?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3555, 104700, 'I do not know that word. They take us inside temple to curse us.', 1655, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3555, 104701, 'If I set you free from the curse, will you help me?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3555, 104702, 'If you can do this, Zhaakaa will be in your debt. The place inside temple to North. Much danger there.', 1655, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3556, 99695, 'Investigate the Goa''uld Lab', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3557, 104733, 'We need to see what is going on inside that Goa''uld lab... ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3557, 104734, 'I figured as much.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3557, 104735, 'Be careful. Ra was a nutter to the ninth degree... If they were doing experiments in there - it might be very disturbing in there. ', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3558, 104750, 'The machine implants capsules into the Unas that release toxins on via some kind of remote command. There must be some kind of kill switch inside the main temple that is triggered by intruders. Entry in there would indeed kill the entire Unas colony. ', 1656, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3558, 104751, 'If the trigger was under your control, it could be very useful. Perhaps you can reprogram the capsule frequency to manually activate the kill switch when you choose... You pick up a Capsule Tester which could be used for just such a purpose. ', 1656, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3563, 64090, 'Help me get out of here! Please!', 731, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3564, 95961, 'Thank you so much, you saved my life... I went in there when I saw smoke and when I got inside something hit me in the head, really hard... Knocked me for a loop.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3564, 95962, 'Falling debris?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3564, 95963, 'Maybe. But the fire wasn''t that serious yet. It felt like it came from the side... ', 731, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3564, 95964, 'Someone hit you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3564, 95965, 'I don''t know... But whatever it was gave me a major headache. I''m going to get to the infirmary. Thanks again for your help...', 731, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3575, 41984, 'Okay! Enough already! You got me, I''ll come with you.', 965, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3576, 64283, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3595, 51441, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3596, 91944, 'Locate and remove the foreign hardware in the Tretnonin Facility', 765, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3597, 91943, 'The data you culled from the system revealed a modification to the system, but it wil take leg work to actually find the offending hardware and remove it. ', 765, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3601, 91942, 'You search around the normalizing injectors and find a crystalline attachment. It looks to be of the same family of technology that the emitter and the Ring Transporter modifcations came from. Clearly, this attachment is alien to the Tretonin production process - but how to remove it?', 1755, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3602, 91941, 'The device comes free... Jysic was right - the Jaffa were being poisoned by their Tretonin. While disabling the device is a victory, it means most of the Nine Peaks Jaffa have already been infected. ', 1755, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3615, 57295, 'Search the area to make sure no other poison implementation devices exist.', 1755, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3616, 57296, 'Upon examination you realize that the poison isn''t traditional - there is no fluid or gas. Instead, the device is a machine of some kind. In order to remove it you broke it, but it is possible that there are backups in the area. You decide to report the news of the poisoning to Colonel Carter before you search for possible replacements.', 1755, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3617, 91983, 'You find a series of the units neatly stored. The crystal components are strangely durable, but they eventually they shatter under enough force. You decide to keep one of them intact, for future evaluation.', 1766, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3844, 107731, 'It is a brilliant design... How did you do it?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4838, 110961, 'The Reins?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3618, 91984, 'Another supply of the devices. Given the way they were laid out, you get the sense these aren''t easily manufactured. You destroy them without remorse.', 1767, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3619, 73784, 'They were poisoning us through the Tretonin... We are vindicated...', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3619, 73785, 'We?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3619, 73786, 'My brother Trink''na and myself each believed this to be true.', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3626, 96622, 'Help Fant''yl''s ill family members.', 1770, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3627, 96661, 'You seek information about Dakor? I know much but do not have time for stories now...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3627, 96662, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3627, 96663, 'The sickness has hit my family... My brother and sister have gone missing, Turlen and Ish''lei. The sickness can affect the mind of a Jaffa as well as the body. I fear the worst.', 1770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3627, 96664, 'I can help you find them.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3627, 96665, 'I would be in your debt.', 1770, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3628, 96654, 'You have helped me and now I can help you, <<Playername>>. You wish to know of Dakor? ', 1770, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3628, 96655, 'What happened to him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3628, 96656, 'I cannot say. He spoke to me of nightmares - visions - which grew in intensity until they took all his strength to resist. ', 1770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3628, 96657, 'What were the nightmares about?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3628, 96658, 'He would not say. I lost touch with him as he rose against Ras''nor. Indeed, I tried to warn the council of Dakor''s nightmares, but few listened. Then I heard his family had given in to the sickness and I knew it was too late...', 1770, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3628, 96659, 'Why?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3628, 96660, 'All Jaffa are tied to their families, but Dakor was more devoted than most... He would do anything to serve his mother who doted on him, often to his own detriment. If she were gone I knew his mind would soon follow.', 1770, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3629, 96620, 'Can you help me? I am lost... This looks familiar but... My mind is cloudy...', 2434, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3629, 96621, 'Follow me, I''ll get you home. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3630, 96605, 'I cannot come with you, I must find my brother...', 2433, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3630, 96606, 'I found him already, he is with Fant''yl.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3630, 96607, 'I am relieved... Thank you... I will follow you back now. I must confess, I fear I cannot remember the way myself. ', 2433, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3630, 96608, 'You will be fine.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3631, 96755, 'Find Seshan''s father Ry''adic.', 1772, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3632, 96750, 'Please... My family is sick and I see that you are helping others... My father, Ry''adic, follows Dakor but this is because I believe Dakor has done something to his mind. He speaks of nightmares and has, at time, become almost as if in a trance. He is no longer himself.', 1772, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3632, 96751, 'I''ll try to find him.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3632, 96752, 'Be careful. He can be dangerous... I fear for him.', 1772, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3633, 96754, 'You... Must die for Ra.', 1774, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3634, 64837, 'UNUSED DIALOG', 1775, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3635, 64839, 'UNUSED DIALOG', 1775, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3636, 97211, 'My father is dead?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3636, 97212, 'I''m sorry.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3636, 97213, 'He and Dakor both began acting strangely when they recovered a crystal obelisk. My father thought it valuable and he and Dakor hid it. They visited it often... I believe the obelisk was a device of some kind... It has destroyed our people...', 1772, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3637, 64831, 'UNUSED DIALOG', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3638, 64832, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3645, 44062, 'Placeholder for escort.... TAKE ME TO JAIL! LOCK ME UP!', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3655, 112138, 'You pull out a Thermist charge and attempt to sabotage the artillery piece.', 620, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3656, 103880, 'I am injured. Too much damage... My host will perish if you do not get me to a sarcophagus.', 1777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3656, 103881, 'Then you better tell me where the Mouth of P''tah is.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3656, 103882, 'Please, I don''t know.', 1777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3656, 103883, 'You''re in no position to play games. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3656, 103884, 'Just get me to a sarcophagus... Once there I will tell you everything I know... ', 1777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3657, 44181, 'Flax, the leader of the Red Collar Faction here on Lucia, has long been a thorn in my side. Dispatch of him and we shall talk more.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3658, 101993, 'The monument stone is filled with heiroglphys...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3659, 44187, 'You are serious people. I shall come to Harset shortly to meet with your leaders.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3675, 103662, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3676, 103664, 'The Jaffa''s orders bring to light two things of note: First, the planet is a military staging area. The Jaffa are setting up camps, readying weapons and activating Goa''uld drones. This is a big operation.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3676, 103665, 'Second, the forces here don''t trust a Goa''uld named Saarthon. Given that none of them seem amenable to talk, you need to question the outsider. You decide to update McIntyre about this development.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3678, 44347, 'Go away. You say the Jaffa are free, but you hover. Leave us be. Let us live our own lives for once.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3679, 44348, 'I do not feel well.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3680, 44350, 'After a lifetime under false gods, I am wary of prophets.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3681, 44352, 'Leave. If the others were to see you, they would kill you on sight.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3682, 44354, 'Freedom is not easy for us. I believe the leaders are trying their best.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3683, 44356, 'I am not sure I believe Dakor, but there are those who do. Take care around our villages.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3684, 44360, 'I have nothing to say to you Tau''ri dog.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3685, 44367, 'Tau''ri dog!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3686, 44374, 'Liar. You have no place here!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3687, 44391, 'Honorless mongrel! Die by my hand!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3688, 50996, 'The cages are mostly on the hill outside and you only have to pick up as many as you can stomach.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3689, 47749, 'UNUSED DIALOGUE', 709, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3690, 48593, 'Unused Dialog', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3691, 52723, 'We don''t have a lot of time... The Jaffa are everywhere.', 713, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3692, 52724, 'They were on us so quickly... I just ran...', 1933, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3692, 52725, 'I''m here to get you out.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3692, 52726, 'Why did they do this?', 1933, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3692, 52727, 'We don''t know.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3693, 51042, 'Thank God you''re here, our medical drones have gone haywire.', 1330, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3693, 51043, 'Haywire?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3844, 107732, '(Goldam delves into Laro - hopefully this can last long enough to get a decent DNA scan...)', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3693, 51044, 'They''re attacking people. They''re acting against their standard protocol and I can''t shut them down remotely. I''ve tried to evacuate the building, but until we figure out how to contain these drones it''s too dangerous inside for my staff. ', 1330, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3693, 51045, 'I''ll go see what I can do...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3693, 51046, 'Thank you, <<Playername>>.', 1330, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3695, 91819, 'The radio jammer is probably somewhere behind their main lines.', 714, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3697, 90326, 'I can''t believe you''ve managed to make it in here...', 713, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3697, 90327, 'What''s the sit-rep?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3697, 90328, 'The Nine Peaks are pissed off about something. I have no idea what...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3698, 50889, 'Lieutenant Logan is in the Science Facility.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3699, 91864, 'Ras''nor''s home is in Camp Shoul''ja. It''s up on one of the plateaus overlooking the crater.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3700, 53218, 'Colonel Carter awaits your report.', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3701, 91884, 'Bra''tac is probably right. If we can figure out why they are sick and cure it, the Nine Peaks won''t blame us for the disease...', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3701, 91885, 'And the violence will stop.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3701, 91886, 'Hopefully. Take this medical scanner into the field and gather some samples from the Nine Peaks. We need data before we can help anyone. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3702, 54174, 'UNUSED DIALOGUE', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3703, 54175, 'UNUSED DIALOGUE', 717, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3704, 54176, 'UNUSED DIALOG', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3715, 48115, 'Go through the Stargate to Beta Site.', 927, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3716, 51443, 'UNUSED DIALOG', 1581, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3717, 48109, 'You''re looking for Mimir. He''s in the Asgard Base', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3718, 51444, 'UNUSED DIALOG', 709, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3719, 48148, 'You will find many of our devices between our base and the Human base.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3720, 51445, 'Your scanners are set up all around this part of the base and then in the area around it. I think a few are between here and the Admin complex.', 711, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3721, 51446, 'UNUSED DIALOG', 711, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3722, 49408, 'Hidden behind some medical supplies you find a small crystalline object. Readings indicate the object is emitting the unusual pulse you isolated before. Perhaps this pulse is causing the support drones in this facility to get aggressive? You decide to investigate the strange drone behavior. ', 763, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3725, 95695, 'The sickness you describe concerns me. However, the High Council has determined that this facility is to be shut down. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3725, 95696, 'I wish to visit the council.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3725, 95697, 'This is reasonable. I will make arrangements. Proceed to the Stargate. They will be waiting.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3726, 53436, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3729, 53272, 'UNUSED DIALOG', 927, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3731, 95790, 'Did you get field data from the Jaffa?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3731, 95791, 'Yes, Colonel. I am uploading the data now.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3731, 95792, 'I will forward it to the Omega Site science team for evaluation. Nice work.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3731, 95793, 'You will not submit it to the SGC?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3731, 95794, 'The SGC is officially not working on this problem. ', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3731, 95795, 'But you are?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3731, 95796, 'Yes. As is anyone with a heart... Find Ras''nor and see if there is anything else we can do to help him.', 708, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3732, 53860, 'Head to the Ruins of Khen''mer Fa', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3733, 53969, 'UNUSED DIALOGUE', 754, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3734, 64250, 'UNUSED DIALOG', 1770, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3735, 55264, 'UNUSED DIALOG', 756, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3737, 92069, 'You have returned. I am most pleased.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3737, 92070, 'I have recovered a device Dakor''s Jaffa have been using to poison the other Nine Peaks Jaffa. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3737, 92071, 'These races... Always assaulting each other; it is most inexplicable. We will begin evaluation presently.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3743, 55548, 'Find and kill Dakor', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3745, 58702, 'UNUSED DIALOGUE', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3746, 102344, 'You take a closer look at the inner-workings of this computer system.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3747, 102343, 'You use the interface you recovered and begin to access the system. Access to the data should be a matter of seconds...', 428, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3748, 102345, 'You need to load the library functions which will enable you to adjust your UICP.', 428, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3749, 102346, 'You start to load the algorithms... This machine is rapidly getting on your nerves.', 428, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3750, 63276, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3751, 63277, 'The storage area you''re looking for is back behind some of the huts here in the Admin Complex.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3752, 63279, 'I really hope Col. Carter had those crates shipped through already. I don''t need another angry email from Woolsey. Or worse, a personal visit.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3753, 96055, 'The phase excavator has already been hit by a staff blast. Smoke is rising from the device and a high-pitched whine rings in your ears. You need to start the shut down procedure right away.', 2384, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3754, 96056, 'You finish the shutdown procedure but the device doesn''t respond. Instead it sparks violently, vibrates then suddenly dissappears. You wave your hand through the area where the device used to be. Nothing. Felger''s device has phased itself out, permanently.', 2384, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3755, 63647, 'UNUSED DIALOG', 805, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3756, 63851, 'UNUSED DIALOG', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3757, 52099, 'Unused Dialog', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3758, 52883, 'Unused Dialog', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3759, 63852, 'UNUSED DIALOG', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3760, 64051, 'Acquisition of this data will allow me to complete my research. Please take recordings of the individuals listed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3762, 63423, 'UNUSED DIALOG', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3763, 63425, 'UNUSED DIALOG', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3764, 63513, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3765, 63512, 'UNUSED DIALOG', 1355, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3766, 48116, 'I am busy. Speak with Mimir. He is coordinating our departure.', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3767, 64209, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3768, 64213, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3769, 64284, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3770, 64301, 'UNUSED DIALOG
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3771, 64789, 'Barak''Ka is over in the second crater. The note I have says the upper area is "the part immediately around the transporter".', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3772, 64793, 'Proceed to the ruins. They are located in the second crater inhabited by Jaffa.', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3773, 64589, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3774, 64591, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3775, 64945, 'UNUSED DIALOG', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3776, 102673, 'The sentient AI has left this terminal. You attempt to get it back by hacking into the system using the tricks you learned earlier...', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3777, 64950, 'UNUSED DIALOG', 872, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3778, 104103, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5234, 98551, 'The New Mind Goa''uld.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3779, 104170, 'Skimming the journal you find reference to the Hall of Secrets. If what Safkhet says is true, the artifact can do just about anything, including decoding the Book of the Gates. You need to get to the Hall of Secrets.', 1842, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3780, 104102, 'UNUSED DIALOGUE', 1632, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3781, 64833, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3782, 67947, 'The Holorecord is garbled, but you learn about a Vault somewhere on Agnos - apparently this is where the Ancients retreated with their most important secrets. As you play the section back again, Laro interrupts you...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3782, 67948, 'I notice you are playing a Holorecord. ', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3782, 67949, 'What''s the vault?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3782, 67950, 'The vault is inaccessible. It has been sealed and is not available for entry. ', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3782, 67951, 'I''d like to get in there.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3782, 67952, 'Given the current state of our progress, there are other - higher - priorities. ', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3783, 102699, 'The unit looks sound enough now... The Laro Hubs probably have built in holorecord playback slots.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3784, 64836, 'UNUSED DIALOG', 1772, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3785, 102737, 'A typically ancient console - remarkably easy to use if you understand it already... It will take a few moments to figure out how it works...', 513, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3786, 102736, 'You are going to bypass Laro''s direct connections and insert the Naquadah generator at this bypass junction... This should enable the system to run without interference for months. ', 514, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3795, 102777, 'The console indicates that the entire area seems to be - not a library - but an elaborate stasis-chamber storage cavern. Could there be Ancients alive down there? You examine the Vault''s typically confusing console in search of answers.', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3796, 102778, 'You prepare to engage the revival process on the two stasis pods - if you can just figure it out...', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3801, 102881, 'The index is relatively complex - a massive labyrinth of hardware and data storage. You begin the search for the prioritization tables...', 517, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3802, 102918, 'You attempt to manually access the prioritization lists inside this alcove. One you set their switches the hierarchy can be controlled by Goldam...', 518, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3803, 102979, 'Goldam''s storage pod is one of several hundred... You begin the process of figuring out which one is his...', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3804, 103021, 'For an area under heavy attack, this communications grid is still exhibiting a lot of activity. You investigate the equipment for a meaning behind it.', 520, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3806, 103215, 'This console should give you a decent look at the innder workings of the plant... Hacking past the security should be easy enough. ', 531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3807, 103435, 'You need to disable this synaptic link so that Laro cannot escape.', 526, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103436, '(You begin to carefully administer the nanobots into Laro''s system...)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103437, 'Please do not do this...', 529, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103438, 'I don''t have a choice...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103439, 'I do not wish to be terminated. ', 529, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103440, 'I don''t have a choice. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103441, 'I promise I will allow Goldam to help me... I will allow it. I will comply to all directives. I wish to be a good girl now. Please do not terminate me. ', 529, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103442, 'Can we stop the Straegis from converting this Tower without terminating you?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103443, 'I cannot answer that, self-preservation protocol 32342 invoked.', 529, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103444, 'Answer me or I let these things loose on you right now.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103445, 'We cannot stop them. Overrun is inevitable. ', 529, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103446, 'Then I have no choice.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103447, 'What will happen to me?', 529, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3808, 103448, 'I don''t know.', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3810, 47937, 'Unused Dialog', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3811, 49848, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3813, 49969, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3815, 55262, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3816, 45594, 'You noticed that not all of the Jaffa in Camp Shoul''Ja desired to attack you. You surmise that one might be willing to tell you where Ras''nor is.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3817, 53271, 'UNUSUED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3822, 54828, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3825, 91843, 'Graham has suffered a similar fate to Henly. The state of his body is particularly disturbing - the attack was almost personal. Clearly this Perimeter was hit first. You decide to try and determine what the Nine Peaks want with this little outpost.', 1878, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3829, 102640, 'UNUSED DIALOGUE', 1877, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3831, 64632, 'UNUSED DIALOG', 754, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3832, 107206, 'You attempt to convince this stasis pod to surrender its contents: Long dead Ancient remains.', 582, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3833, 63854, 'UNUSED DIALOG.', 805, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3834, 96068, 'This tank is damaged... You hear a hissing sound. You move to activate the emergency release.', 2799, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3835, 96059, 'Nice work... You probably saved a lot of lives there. I should never have let Felger store them in there...', 713, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3835, 96060, 'What were they for?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3835, 96061, 'Novak and Felger told me they were using them to evaluate one of the artifacts - the one with the case... I told them storing that gas like that was crazy...', 713, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3836, 107314, 'You start searching through the system''s commands for a means to execute the Praxis''s backup plan.', 531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3837, 107376, 'You start to enable the detonator to recieve the subspace signal from Harset should the need arise.', 585, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3838, 107592, 'UNUSED DIALOGUE', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3839, 104847, 'You''re not getting into that sarcophagus until I get what I want.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3839, 104848, 'You want Safkeht, not me. She was Ra''s scribe... Devoted to him. She knows all about the Mouth of Ptah. That technology was different and strange, but Ra ceased his research here long before he died. He left her in charge of it.', 1778, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3839, 104849, 'That was almost useful. Where can I find her?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3839, 104850, 'I do not know... Please... Let me inside the sarcophagus... ', 1778, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3839, 104851, 'I need more than a name, Saarthon.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3839, 104852, 'You may find her at her lab... She is often there - her First Prime always carries a key with him... Now... Please. I am in a great deal of pain.', 1778, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3839, 104853, 'Go ahead. Get in.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3840, 107707, 'You attempt to bypass the standard playback mechanisms in order to get at the data inside - hopefully it will still be intact.', 586, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3841, 51385, 'You think you heard someone else as you were escorting Dr. Arrayo out. Maybe that''s Dr. Novak. You rush back into the Science Facility and hope you''re not too late.', 752, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3843, 107713, 'You prepare to download the holorecord''s source data from the memory bank.', 591, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3844, 107726, 'You''re back... You come and go a lot. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3846, 104483, 'Stasis... I guess that''s a good thing. It just means they''re all misguided and not actually organized. Hopefully your little trick will reduce their numbers... God, I hate this place!', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3847, 108503, 'This is disconcerting... How did they get the Agnos gate address? ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3847, 108504, 'Ra?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3847, 108505, 'That''s one idea - the worst idea. It may be something else entirely. We have to find out. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3848, 108615, 'Find out how Burtonol discovered the Agnos gate address. ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3849, 108616, 'There''s a camp on Agnos. If you can get inside you can probably find out if Ra''s there. ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3849, 108617, 'You just want intelligence?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3849, 108618, 'Anything you can find would be helpful. If Ra''s on Agnos our problems just got a lot bigger. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3850, 108620, 'This is Metcalfe. ', 575, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3850, 108621, 'You should come to Agnos. Your operation is in Jeopardy. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3850, 108622, 'Who is this?', 575, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3850, 108623, 'Someone you need to speak to.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3850, 108624, 'You just call me and threaten me and I am supposed to just travel to Agnos? ', 575, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3850, 108625, 'I can promise it will be worth your while.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3850, 108626, 'You''re going to have to do some serious convincing...', 575, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3851, 108619, 'This looks like a reasonable way to reach Metcalfe - you just have to find the right key codes...', 579, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3852, 65118, 'You found Lance! That''s the best news I''ve heard all day.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3852, 65119, 'He is on the way to your location.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3852, 65120, 'We''ll debrief him when he arrives. Thank you for your help.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3853, 108633, 'You attempt to get a positive fix on what caused the plant''s operation to cease in the first place.', 513, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3854, 108651, 'You examine the node for any reason why it would have drawn so much power to knock the atmosphere generators out.', 587, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3855, 108656, 'You begin to apply to the Energy Conditioner to the Junction... This solution seemed easier in theory...', 514, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3856, 108655, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3857, 108668, 'The pod has not automatically opened. You attempt to disengage the stasis manually.', 608, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3858, 108669, 'You decide to search the vault records for other active pods.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3859, 108676, 'UNUSED DIALOGUE', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3860, 108688, 'You attempt to download the vault log file into your PDA.', 609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3861, 103837, 'Hmm... Looks like these forces are awakening because someone somewhere belives their god, Ra, is returning. I wouldn''t hold my breath if I was them.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3861, 103838, 'They seem pretty convinced.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3861, 103839, 'It does explain why they are all so frigging fanatical. I''ll get this intel into hands more powerful than mine and let them decide what to do. Good work.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3875, 47830, 'The Quartermaster on Omega Site just sent through a list of items we need there. I need you to descreetly get some of those items.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3876, 47880, 'Obviously we can''t have one person get everything we need for Omega Site. I''ve assigned you some of the things we need to get. Collect them from around the Admin complex, then t', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3877, 104356, 'The energy readings from that soil... I hope the eggheads on Harset can make heads or tails of this because I can''t. I''ll make sure this makes it''s way to them. Good work.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3878, 104298, 'This is really weird. She''s talking about the Mouth of Ptah like it is religion... And from these notes it looks like it relates to... Consciousness? I''m not even sure I know what I''m looking at here.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3878, 104299, 'Maybe she is just protecting it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3878, 104300, 'Without any understanding. Given her girlish devotion, you may be right. Hopefully she doesn''t figure out whatever it is Ra knew. I''ll pass this on to the eggheads and see what they come up with, or maybe Ba''al can decipher this mumbo jumbo. Good work getting this.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3879, 104374, 'This research is strange. Though the Goa''uld are adept at genetic manipulation, this work seems haphazard. Yet at the same time they have made sudden leaps in knowledge, seemingly out of nowhere. I do not know if this research will be of any help to us, but you have done well in securing it.', 2050, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3880, 103310, 'Well I don''t see what''s so special about this stuff - aside from this glowy bit here - but I''ll send it back to the lab boys. I trust you destroyed the rest.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3880, 103311, 'it is gone.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3880, 103312, 'Good work.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3881, 104282, 'Hopefully we''ve done enough to convince Harset to let us off this God-forsaken planet... Your little mercy killing should be the last gasp for Ra''s little fan club.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3881, 104283, 'You think so?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3881, 104284, 'It''s what I am going to report to our leadership. Do you disagree with that assessment?', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3881, 104285, 'No...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3881, 104286, 'Good. I wouldn''t want us to give conflicting assessments to leadership. It looks bad. It''s always better when we all agree. Then we all get to leave.', 1885, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3882, 103122, 'Thank you for freeing me.', 1777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3882, 103123, 'You are not free. You are coming with me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3882, 103124, 'But...', 1777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3882, 103125, 'You are coming with me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3883, 104256, 'I found this in a cell.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3883, 104257, 'Saarthon... ', 1885, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3883, 104258, 'I assume you are going to let me go? It would be the honorable thing...', 1778, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3883, 104259, 'You assume wrong. We''re going to send you through to Harset where you will be debriefed by our people. It''s either that or I can send you back to Ra''s Jaffa... They seemed to like you...', 1885, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3883, 104260, 'You people are barbarians. I agree to see your leaders... But on the condition that I will be freed after that.', 1778, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3883, 104261, 'Negotiate with them when you get there. For now, no more talking.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3884, 50361, 'I think Col. Carter had more tasks for you.', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3885, 50363, 'You better get inside and find that manual control system.', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3886, 51025, 'Weren''t you going to take a look around?', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3887, 49781, 'You think the fire was deliberate?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3887, 49782, 'I''m not an expert, but I think it''s possible. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3887, 49783, 'I''ll call the SGC and have Woolsey send up a forensics team to confirm... If it was arson it leaves us with a big question...', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3887, 49784, 'Why?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3887, 49785, 'Exactly. We''re leaving anyway... ', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3925, 103812, 'Investigate the source of the Jaffa on Men''fa.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3888, 97173, 'The fire suppression systems are now back online. Strange that they didn''t kick in on their own.', 1411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3889, 51051, 'Take the crystalline devices to Mimir, the Asgard liasion on Beta Site. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3890, 99121, 'This technology is fascinating... But, unfortunately I don''t have time or the tools to analyze it properly. Take it over to Mimir at the Asagrd outpost...', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3890, 99122, 'The Asgard are here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3890, 99123, 'Yes, they have set up a research outpost - although they are also packing up and leaving... Still, Mimir may be able to answer our questions about the nature of that emitter pretty quickly. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3891, 49913, 'This technology is unusual. I do not recognize it. If you wish for an initial analysis against all common technologies, you may access the Analytic Assistance Module.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3891, 49914, 'I can use your equipment?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3891, 49915, 'Certainly. The Analytic Assistance Module is capable of being used by the most primitive of intellects.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3891, 49916, 'I see.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3891, 49917, 'Simply place the object inside the module.', 730, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3892, 48061, 'The Asgard Base is on one side of the crater. Look for Mimir there.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3893, 96891, 'The machine''s analytic processes take only a few seconds. Soon a readout appears, but you are unable to decipher the Asgard script. Mimir can probably help. ', 1334, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49930, 'Is the analysis complete?', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49931, 'I think so.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49932, 'I will access the results from here... Interesting...', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49933, 'You find something?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49934, 'No. The analysis found nothing, which is interesting. This technology is highly unusual. There are similarities to several types of known technologies, but nothing which supports a direct match. ', 730, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49935, 'Could it be a derivative of a known technology?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49936, 'Possibly. Further analysis is required. If it is acceptable to you, I would like to take this technology to our Science Council for further investigation. ', 730, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3894, 49937, 'Knock yourself out.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3895, 95594, 'That signal pattern doesn''t seem familiar at all. Captain Satterfield was cataloguing some artifacts earlier... Perhaps she came across something? ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3896, 95589, 'You remove cover of the melted sprinkler control for examination. A quick re-build pass with a matter converter gives you a detailed display of the state of the sprinkler control prior to the fire. It appears that two wires have been cleanly clipped. You upload a digital scan of the control.', 1411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3897, 49371, 'How may I be of assistance, <<Playername>>?', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3897, 49372, 'There is a fire at the human basecamp. Can you beam me a Fire Suppression Manager?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3897, 49373, 'Yes... Initializing... Fire Suppression Manager upload... Upload complete.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3898, 49377, 'Please speak with Colonel Carter.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3899, 51099, 'Captain Satterfield was over by the Quartermaster last I saw her.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3900, 51100, 'I really need someone to, well, go in there? If we can get both sides of the system working we should be able to stop this fire from destroying everything.', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3901, 95631, 'This quite interesting. These devices are a very advanced technology I have never encountered. They will require analysis. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3902, 95630, 'The interior electronics appear to be of standard human design: Bulky, wasteful, unweildy. However, attached to the drone''s AI control unit is a small crystalline receptor. The technology - alien to you - seems like remarkably advanced Goa''uld technology. You secure the drone in preparation for your report to Mimir.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3903, 49434, 'Examine the recovered Emitter and Receiver more closely.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3904, 49435, 'I suggest you use the Analytic Assistance Module to determine if the Emitter and Receiver technology has a known origin. I upgraded the specification library on that unit just yesterday. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3905, 49938, 'Interesting. The listing of potential sources are almost all exceptionally unlikely: Early Ancient, Furling, Goa''uld during the time of Ra''s protracted rule... But none are an exact match.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3905, 49939, 'Perhaps this technology is a deriviative form of these?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3905, 49940, 'This is possible. I will forward this material to the Council of the Sciences for an archive search. Perhaps we have memory records somewhere which will identify this directly.', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3906, 49439, 'Analyze the device using the Analytical Assistance Module.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3907, 97202, 'The machine''s analytic processes take only a few seconds. The results are surprising: There is no exact match for this technology in the known database. You resolve to deliver these results to Mimir.', 1334, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3908, 49984, 'Report to Colonel Carter that the devices seem to indicate sabotage.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3909, 52415, 'The devices you recovered indicate tampering with the medical drones. This information - and these modules - should be passed on to Colonel Carter at once. ', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3910, 50916, 'Sabotage... Why would anybody sabotage our camp as we''re packing up to go?', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3910, 50917, 'Can I be of additional assistance?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3910, 50918, 'Actually, you could. I just got a strange call from one of my people - Lieutenant Logan. I couldn''t understand most of it, but she mentioned the Clan of the Nine Peaks Jaffa.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3910, 50919, 'I am unfamiliar with this group. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3910, 50920, 'They''re the local Jaffa tribe. They recently joined the Free Jaffa Council. I''m not sure how they fit into this.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3910, 50921, 'But you wish for me to make contact with Lieutenant Logan?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3910, 50922, 'Please. And then just let me know that she is ok.', 708, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3911, 50095, 'Report the confirmation of sabotage to Colonel Carter', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3914, 83797, 'Gate to Men''fa and report to Maggie McIntyre.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3915, 103655, 'Find a nearby Jaffa and interrogate him for information about the Mouth of Ptah.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3916, 52728, 'Thank god... Can you help me, please?', 1929, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3917, 103772, 'Reprogram the drones to throw the Jaffa into disarray.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3918, 103938, 'Find the Goa''uld Saarthon. See what he knows and how he could be of use.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3919, 103962, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3920, 103977, 'Search Safkhet''s Lab for any information regarding the Mouth of P''tah.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3921, 104126, 'Break into the Hall of Secrets.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3922, 104208, 'Use the Mouth of Ptah to Decipher the Book of Gates.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3923, 104196, 'Get the key to the Mouth of Ptah from Safkhet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3924, 104231, 'Take the Deciphered Book of the Gates to the Leadership Council.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3927, 104479, 'Investigate the Goa''uld excavation site.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3928, 104288, 'Investigate Safkhet''s Research.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3929, 104382, 'Extract Saarthon and bring him back to McIntyre.', 1926, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3930, 103223, 'Bring back a sample of Ra''s Jaffa''s weapons. Destroy the rest.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3931, 104267, 'Assassinate the garrison commander for Men''fa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3932, 52789, 'Secure the artifacts in the main building.', 711, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90374, 'I managed to secure this...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90375, 'What is that thing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90376, 'We don''t know exactly, but I think they are after it - among other things. They are being pretty methodical in what they are doing. The chaos is a cover. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90377, 'Where are the artifacts?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90378, 'In the main building, but we''re probably too late. The artifacts have a secruity system. Hopefully it will hold out.', 711, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90379, 'You have an inventory?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90380, '(hiccup)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90381, 'It''s important.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3933, 90382, 'Here''s a listing... While you do that, I''m going to get this "thing" to the Command Center and get them to send over reinforcements. Be careful.', 711, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3934, 52799, 'The central building is the huge one with the dome. ', 711, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3935, 90356, 'You are immediately struck by this case - ornate and extravagant, this is clearly no standard artifact. The case is hermetically sealed and judging from the damage to the exterior, extremely strong. The objects inside seem mundane - soil, a glow rod and a strange silvery metallic goo.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3935, 90357, 'While everything seems to be accounted for, the case has clearly been assaulted. You decide to make sure the security system is still operational.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3936, 90383, 'The system is down - the Jaffa have done a decent job on the mechanism with their staff blasts but, upon closer inspection, you may be able to fix it.', 720, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3937, 90473, 'I have an inventory from the Science Facility.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3937, 90474, 'Is the situation secure?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3937, 90475, 'Temporarily. The security system has be re-activated.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3937, 90476, 'Nice work. Let me see that inventory for analysis.', 753, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3939, 90384, 'This artifact is highly unusual - obviously recovered here, it is clearly Ra''s technology. The object was a tool he used for mass mind-control and seems to be still functional. This is certainly not something humans should have without supervision. You begin to deactivate the object.', 721, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3940, 90385, 'The humans have lovingly placed a massive, high-explosive Goa''uld artifact in the middle of their artifact collection. Clearly they are oblivious to the potential danger of the object. It won''t take long to modify it enough to remove the danger...', 735, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3941, 50816, 'Hidden behind some equipment you find a strange crystalline emitter - resembling the piece you found inside the drone... Clearly something strange is going on here. You decide to report this directly to Colonel Carter. ', 763, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3942, 96370, 'You search through the Crate and discover a stealth suit and a nasty-looking serrated knife.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3943, 96372, 'You search through the Crate and discover a staff weapon and a piece of plate armor for the chest.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3955, 102096, 'Travel through the gate to Men''fa and make contact with Lt. Mogilny.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3975, 102047, 'Reprogram the drones to throw the Jaffa into disarray.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3976, 54428, 'Go to the SGC and inform Mr. Woolsey and General Hammond of the situation on Beta Site', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3977, 97484, 'I need you to go to the SGC and report what is happening here to General Hammond. We''ve got to keep this facility open long enough to help the Nine Peaks Jaffa fight whatever plague they are facing.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3977, 97485, 'Isn''t Mr. Woolsey in charge now?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3977, 97486, 'He''s overseeing the closure of the off-world program, but General Hammond still has some power. Deliver the report to both of them - just make sure General Hammond gets the information.', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3978, 91869, 'How serious is the situation?', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3978, 91870, 'The Jaffa have attacked a science facility already. I think a larger assault is coming soon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3978, 91871, 'We certainly need to do something... The problem is, Woolsey won''t allocate more resources to Beta Site. Especially now. ', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3978, 91872, 'What about Thor?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3978, 91873, 'My thinking exactly. Take this information to him at Omega Site right away. Make sure that Thor and Bra''tac both know what you just told me.', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3978, 91874, 'If I go directly to Omega Site from here, I''ll leave behind a travel log...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3978, 91875, 'I''ll take care of that. Just go. We don''t have a lot of time.', 2410, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3979, 91878, 'Go speak with Hammond on Earth.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3981, 91877, 'Go to the Omega Site and speak with Thor and Bra''tac.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3982, 102000, 'Trik''na''s notes indicate he was on his way to question a Goa''uld named Saarthon. You realize Saarthon might be the key. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3983, 102526, 'Dead planet they told me. It''s crawling with Jaffa who still think Ra is alive. I''m worried we''ve only seen the tip of the iceberg. I don''t see Trink''na.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3983, 102527, 'He is dead. I have a lead, However: Saarthon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3983, 102528, 'Whatever that is. Before you do anything else, let me check in with the Command Team at Omega Site and get the go-ahead to continue.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3984, 101999, 'Find the Jaffa, Trik''na.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3995, 96108, 'There are no obvious wounds on Cpl. Frost, though it appears he died soon after killing that NID Guard. On his body you find a pistol and a letter addressed to "Jess" - Frost''s wife.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3998, 96246, 'You succesfully bypass the security systems - the Stasis Pods for the East Wing slowly begin to open.', 934, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96252, 'Nice to hold a combat weapon in your hands again, isn''t it? You''re going to need it.', 256, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96253, 'There''s a war coming?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96254, 'Yeah. In a very short time from now - I''m not sure of the exact timeline - an alien enemy called the Straegis will appear in the galaxy. I don''t know where they came from or who controlled them, but I do know that they effectively eliminated humanity in a matter of months. ', 256, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96255, 'Months?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96256, 'Months. I saw it with my own eyes. The first time around I couldn''t get to Op-CORE quick enough to get us into the fight. This time we''re going to be on the front lines. ', 256, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96257, 'Sir, Op-CORE is just one unit... Did you tell the Pentagon?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96258, 'I left that up to Jack O''Neill. They sure as hell weren''t going to listen me, but they love Jack so much they think he craps gold bars. They might listen to him.', 256, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96259, 'They still think we''re criminals?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (3999, 96260, 'You don''t have time to worry about that. There''s a terminal over there that controls all the Stasis Pods in the East Wing. Use it to free the troopers still held in stasis there. We''ve got to work fast and get as many people off this rock as we can. ', 256, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4000, 96219, 'Get outfitted for your escape from the Cellblock.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4001, 96247, 'Well, you woke up faster than I thought you would. That''s good. I don''t have much time.', 256, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4001, 96248, 'Col. Marsh? Is that you? You look. . . different.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4001, 96249, 'It''s a long story. The short version is - I''m your Colonel Marsh, but from the future. There''s a war coming - a war we lost the first time. I''m here to make sure that when we fight it again, we win. And you''re going to help me.', 256, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4001, 96250, 'Colonel? ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4001, 96251, 'I understand it''s a lot to take in, but I don''t have time to play therapist. I''m your superior officer and we have a job to do... There''s a weapon over in that locker. Arm yourself.', 256, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4002, 50959, 'What happened here?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4002, 50960, 'You tell me. The Nine Peaks have gone haywire. They''re shooting people... Its insanity.', 733, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4002, 50961, 'Do you know what upset them?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4002, 50962, 'No idea. I was looking for Captain Tigges to try and find out. Those Jaffa have gone off the grid. ', 733, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4002, 50963, 'Can you make it out of here?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4002, 50964, 'Give me a minute and I''ll be fine. Find Tigges - if anyone will know what is happening, he will. ', 733, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4003, 96339, 'Damn!', 261, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4003, 96340, 'What''s wrong, sir?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4003, 96341, 'That sparkly energy field is what''s wrong. It''s blocking our way out. ', 261, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4003, 96342, 'Maybe we can break through. . .', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4003, 96343, 'Waste of time. And at this point the NID are getting their people armed and ready. It''s going to be a slog from here on out.', 261, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4004, 102616, 'I am injured. Too much damage... My host will perish if you do not get me to a sarcophagus.', 1777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4004, 102617, 'I need the cure for the Jaffa plague.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4004, 102618, 'Get me to a sarcophagus and I will help you...', 1777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4004, 102619, 'How can I trust you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4004, 102620, 'I am going to die! Please!', 1777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4004, 102621, 'Let''s get going.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4005, 103963, 'UNUSED DIALOGUE.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4006, 103964, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4007, 102375, 'Find Saarthon and see what he knows about the Tretonin Virus.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4015, 102583, 'This looks like the virus affecting the Jaffa, but there''s no bio tech equipment here. Something is still missing. Maybe there are lab notes around somehwere...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4016, 104189, 'The research notes are unusually personal. Safkhet thinks she and Ra are destined to be lovers. The details in between the rants indicate that the virus was made with something called the "Mouth of P''tah." But there''s nothing more about it here... Perhaps Dr. Jackson could help.', 2015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104130, 'You found a sample and a reference to what?', 1631, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104131, 'The reference in the notes is to something called the "Mouth of Ptah."', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104132, 'The Shabaka Stone!', 1631, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104133, 'Shabaka Stone?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104134, 'The Shabaka Stone was an artifact of Memphis, dated around the time Ra was on earth. In Ancient Egypt, Memphis was the seat of the Cult of Ptah. The Shabaka Stone described Ptah, not Ra, as the center of creation. ', 1631, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104135, 'Ra must not have appreciated that.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104136, 'Ptah was likely a rival. The stone described the ritual "opening of the mouth", intended to release the Ka, thus allowing the soul to leave the body and reunite with the life force. The Mouth of Ptah is a technology.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104137, 'Do you understand it?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104138, 'No more than you do... But the story fits our problem: The Mouth of Ptah was used to make the virus. You need to find the Mouth of Ptah. There''s probably reference to it in that lab somewhere. ', 1631, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4017, 104139, 'I will go through her notes.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4018, 102575, 'Search the lab for the source of the virus.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4019, 78311, 'Get an audience with Queen Anat.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4020, 77588, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4021, 104129, 'Break into The Hall Of Secrets.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101982, 'You must know that finding a solution to the Beta Site poisoning on Men''fa is very unlikely.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101983, 'Why is that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101984, 'The poison technology isn''t exactly standard. From what we were able to determine, the "poison" is actually a tightly controlled group of nanites - little machines. These nanites are released into the victim''s system and wreak havoc.', 1332, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101985, 'Attempts at reprogramming the nanites are proving disappointing. We cannot access their processors.', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101986, 'The infected Jaffa on the Beta Site are likely to die. ', 1333, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101987, 'Which creates a massive political issue for the Free Jaffa. Beta Site Tretonin has been delivered to various worlds around the galaxy. Other nations are likely to have been infected. ', 771, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101988, 'So finding a cure is imperative. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101989, 'Correct. You will proceed with a search of Men''fa to make contact with the Jaffa Trink''na. Hopefully he will provide useful information. ', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101990, 'Congratulations - the future of the galaxy just might depend on you... Around the SGC we call days like this "Wednesday".', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4022, 101991, 'The SGU has sent another through before you to secure the area around the Stargate. He is called Mogilny. Seek him out when you arrive.', 1333, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88684, 'Are you who I think you are? It was you who saved me from Ra on Egypt, was it not?', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88685, 'Yes, my queen.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88686, 'And shortly afterward I lay, trapped inside a Canopic Jar for 5000 years... Give me one good reason I shouldn''t plunge this knife into your flesh and rip you from that host with my bare hands?', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88687, 'I too was placed in a Canopic Jar.... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88688, 'After me?', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88689, 'Moments after. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88690, 'For your own safety, no doubt. He imprisoned you for generations for your own safety... ', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88691, 'This is Lord Baal''s claim, yes. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4265, 118332, 'Have you lost many others?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4023, 88692, 'Lord Baal is not to be trusted - never to be trusted. Mark this for yourself. He is useful, but he will outlive that usefulness... Do not find yourself close to him when this day comes. ', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4024, 104811, 'Get the cure to the Nine Peaks in the Tretonin Facility', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4025, 102683, 'Get the key to the Mouth of Ptah from Safkhet.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4026, 58710, 'UNUSED DIALOGUE', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4027, 119075, 'Your desire may yet exceed your ability... But you have impressed us thus far, $name$.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4027, 119076, 'It is imperative that you deliver frequent reports. The Free Jaffa will have support troops at the ready. ', 771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4027, 119077, 'We are sending an advance team to secure the gate area on Ihpet. When they report in you will be cleared to go. Be ready.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4028, 102707, 'Activate the Mouth of Ptah.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4029, 102714, 'Thank you <Player Name>. This antidote is easy to mass produce - as if it were designed just for us. I will see to it that the cure is disseminated quickly.The source of this virus is worrisome. ', 1961, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4029, 102715, 'Worrisome?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4029, 102716, 'Any technology which is capable of such devastation is worrisome. That we do not understand all of its properties makes it exponentially so. You should report your success to the leadership council in the Command Center. I will deliver them supplies within the hour. ', 1961, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4030, 102711, 'Retun to Heimdall at the Omega Site with the Tretonin Virus Cure.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4031, 104482, 'Jaffa in stasis... Leave it to some psycho Goa''uld to get his followers to fall for that stuff... Nice work, <<playername>>. Hopefully that cuts down on their numbers...', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4032, 105077, 'Investigate the source of the Jaffa on Men''fa.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4033, 103831, 'Hilarious. Someone thinks Ra is returning. No wonder they are all so excited... ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4033, 103832, 'They are very serious about it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4033, 103833, 'True. And they may be nut cases, but they''re heavilly armed nutcases. This intel is valuable. We may have to intervene here if they start causing trouble.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4034, 102862, 'Investigate the safe within the Crypt of Hor-Aha.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4035, 102945, 'The readings from these soil samples are like nothing I''ve ever seen. If that''s some form of radiation, it''s from an energy source like nothing else. I''ll get them to Heimdall ASAP. Nice work.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4036, 104478, 'Investigate the Goa''uld excavation site.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4037, 94470, 'Consciousness... what? Safkhet clearly was onto something but I can''t tell if even she knows what it is. I mean is this a form of energy or something else they were investigating?', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4037, 94471, 'I don''t think even she knows.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4037, 94472, 'Well if Ra learned here he took the secret to his grave. Let''s hope Safkhet never figures out what he was doing. I''ll file this. Good work.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4038, 103037, 'Investigate Safkhet''s research and try to learn more about the nature of Ra''s technology.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4040, 103318, 'Looks pretty standard to me. Except for this glowy bit. I''ll forward it to the Omega Site. The rest were destroyed?', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4040, 103319, 'Yes. This is the only one left.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4040, 103320, 'Nice work. ', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4041, 103247, 'Recover the weapon sample and destroy the weapon cache.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4042, 102511, 'According to the triangulator, Cpl. Danner''s tracking device is located near something Laro calls the "Plasma Pumping Station" -- perhaps Danner has fallen back to that position.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4043, 104375, 'Secure the Genetic Research on Men''fa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4044, 104381, 'Extract Saarthon and bring him back to Mogilny.', 1926, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4064, 104706, 'Find out why the Unas fight so valiantly in the Ihpet Crater.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4065, 76789, 'DELETE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4066, 68067, 'You made it to us... We have much to discuss. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4067, 103624, 'Look who finally decided to grace us with their presence. This place isn''t quite abandoned is it?', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4067, 103625, 'No?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4067, 103626, 'No. We''ve got all kinds of company... Jaffa, Goa''uld... Ra loyalists I think... Idiots.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4068, 103780, 'Excellent work. I''m already getting reports that the drones are attacking Jaffa. Hopefully, by the time they figure it all out and uncross the wires we''ll be off this rock.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104233, 'You''ve done well unlocking the book - beyond what we could have hoped. All that remains is finding the activator crystal for the key we found on Tollana. ', 1880, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104234, 'This creature you''ve described... It seemed to pass through some sort of dimensional portal? ', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104235, 'You fear that this creature was a Straegis?', 1880, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104236, 'The description concerns me.', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104237, 'It spoke to me, directly. But without words... It was not a threat. It was strangely comforting.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104238, 'Did your Straegis speak, Colonel?', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104239, 'No. They never spoke...', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104240, 'Then we have nothing to worry about.', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104241, 'I will dispatch a team to examine the Mouth of Ptah. The key was absorbed by the device?', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104242, 'Yes, unfortunately.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4069, 104243, 'Regardless. We will send a team out to make certain it is no threat.', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4070, 101994, 'Finally... I was getting lonely... My first few trips out into the world show signs of Jaffa activity here. ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4070, 101995, 'Jaffa? Ra''s Jaffa?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4070, 101996, 'It seems that Men''fa might not be as dormant as we thought. Hopefully Trik''na''s trail hasn''t gone cold. You don''t want to be out there alone for too long. ', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4071, 102082, 'I just got a radio call from a forward team at one of the crypts. The Jaffa are going crazy trying to deal with the drones. Good work.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4072, 63517, 'UNUSED DIALOG', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4073, 119873, 'You hurry to administer CPR, but she is showing no vital signs. Dr. Rebekah Nash is dead.', 712, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4074, 77598, 'Our alliance is tenuous, filled with distrust and deceit. In some ways our own Goa''uld are the most dangerous - many hang onto the old ways of our race, unable to break with the past. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4074, 77599, 'What about the others in our alliance?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4074, 77600, 'Colonel Marsh''s Op-CORE are typical of humans - nonsensical in their allegiance to intangible ideals, but resourceful and useful. Moh''katan''s Loyalist Jaffa are powerful, utterly dedicated to her and their cause... ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4074, 77601, 'We are in league with Jaffa? As equals?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4074, 77602, 'Times change, friend. Begin by asserting yourself on the council. Pay a visit to Queen Anat - she is your mother afterall, it only makes sense that you finally meet her... ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5253, 111348, 'Simulated symbiote?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4075, 114443, 'This scanner can track the radiotactive isotope we implanted in our forces. Ha''kur and his Jaffa will be disguised as Ra''s Jaffa. Use the scanner to locate Ha''kur and make contact. He has been informed of your arrival.', 798, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4075, 114444, '***Note***
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4076, 114679, 'Tak mal tiak, <<Player Name>>. Moh''katan sent a communique detailing your arrival.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4076, 114680, 'What happened to you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4076, 114681, 'Ra. He has modified all of his Jaffa with his technology... We are made more powerful but... It is an abomination. So far my assignment has been kept secret. I intend to keep it that way. ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4076, 114682, 'As do I. Where is the Solocris?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4076, 114683, 'No one can find it. Ra is furious. He has already had several Jaffa commanders executed for their failures.', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4076, 114684, 'What about the Asgard?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4076, 114685, 'Decimated in the initial onslaught, but they have proven surprisingly resilient. They guard what areas remain to them fiercely. Ra is certain the Solocris is in their possession, but interrogation of captives has proven fruitless.', 2059, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4077, 111425, 'Go to Yotunheim, rendezvous with Ha''kur and begin the search for the Solocris.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78727, 'I have control of the human... He feels very... Utilitarian. ', 1139, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78728, 'He was the only choice we had. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78729, 'Is he pleasing to look at?', 1139, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78730, 'He was our only choice... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78731, 'There is a surveillance camera - we will need to disable it. I will dispose of Johnson... I will claim he never reported for duty and I will make sure his body will not be found. ', 1139, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78732, 'I will inform Anat. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78733, 'Also inform her that I will not remain in this body for long. I will serve my Queen, but there are limits to my ability to survive torture... ', 1139, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78734, 'Torture?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4078, 78735, 'I am not in a pleasing form... This is torture... ', 1139, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4079, 77719, 'Plant listening devices in the OpCORE and Jaffa areas of Harset.', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4080, 118471, 'Your chance at redemption is at hand... Unlike Baal, whose trust in the Op-CORE humans and Moh''katan''s great unwashed horde knows no bounds, I am more pragmatic... ', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4080, 118472, 'Yes...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4080, 118473, 'Was that sarcasm?', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4080, 118474, 'No, my Queen. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4080, 118475, 'Good. Sarcasm does not please me... To business: I have some scarab monitoring devices - six of them - plant them in the Op-CORE and Jaffa sections of the city. Do not be caught. ', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4081, 77725, 'The Scarabs are placed, then? ', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4081, 77726, 'Yes, my queen.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4081, 77727, 'Excellent... You are proving useful, if a little weak minded... ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4081, 77728, 'Thank you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4081, 77729, 'You''re welcome, minion. Leave me. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4093, 114715, 'There is no information about the Solocris here... It is as though the Asgard themselves do not know what they hold. The information about Loki may prove useful...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4093, 114716, 'Loki?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4093, 114717, 'He is one of their greatest scientists - assigned here for an undisclosed reason - and yet the Asgard cannot locate him. He may prove to be important. ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4094, 84873, 'Hack into a security terminal to learn the location of the Solocris.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4095, 77945, 'Go to Men''fa and examine Ra''s research.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4096, 88820, 'Men''fa was once the seat of Ra''s scientific empire... The world''s location was a long held secret that became common knowledge long after it held any real strategic value. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4096, 88821, 'He had other facilities in place...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4096, 88822, 'Exactly. Still he used the world extensively for purely military purposes and, since we are going there to seek the Mouth of Ptah anyway, there may be opportunities to secure hidden treasures...', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4096, 88823, 'Ra hid his treasures well?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4096, 88824, 'He hid them... But he wasn''t especially creative about it. Usually he would hide things near key landmarks. Search for something obvious - a Sphinx or a pyramid. If there are riches to be found, it will be near there. ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4097, 80303, 'Interesting... His technology has always been a mystery to us. Perhaps some day we can grow to understand exactly what these words mean... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4098, 78057, 'Recruit Opheltes to the Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4099, 78075, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4100, 78071, 'Opheltes... Does he still have...', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4100, 78072, 'The Jaffazons? Yes. In numbers.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4100, 78073, 'They are fierce warriors. He could be useful. Well done.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4101, 78068, 'Please don''t hurt me.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4101, 78069, 'Come with me... Now.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4101, 78070, 'I will. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4102, 78074, 'Yes, yes, this is the girl of which I spoke. Such a beauty... Here is my offer to Ba''al. Make sure that he recieves it.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4103, 118483, 'Baal is enlisting Goa''uld for alliances now? Interesting... He sent you to reach out to me. ', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4103, 118484, 'I saw the value in your friendship without his prodding. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4103, 118485, 'I am always willing to listen to new business opportunities when I have time... However, I am very busy and my time is given only to those who earn it.', 964, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4103, 118486, 'I''m listening.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4103, 118487, 'There is a very beautiful young woman living in Crevice Lakes with a very difficult brother. She is called Prue and she is no mere slave...', 964, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4103, 118488, 'You want me to deliver her to you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4103, 118489, 'Do this and Baal will have his meeting...', 964, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4104, 114746, 'Well done. And I have news... There has been some unusual activity in one of the Asgard vaults. Ra has sent troops to investigate. ', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4104, 114747, 'A lead?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4104, 114748, 'Perhaps.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4105, 114732, 'If the Asgard reactivate Thor''s Hammer, we''re in trouble. Make sure it''s broken... permanently.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4106, 114836, 'What are these Asgard playing at? They must have it hidden somewhere... If we are not killed by them, we will surely die at the hands of Ra. My head aches...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4106, 114837, 'Oh?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4106, 114838, 'This technology Ra has filled us with... It jabs into our flesh. It links into our brains... All his Jaffa speak of the pain...', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4106, 114839, 'But they follow him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4106, 114840, 'They think he is a God. They see the pain as divine suffering... They are insane...', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4107, 85080, 'Search for the Solocris in the Asgard vault. Recover any other tech you find.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4108, 115233, 'Thank you for your assistance.', 2066, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4108, 115234, 'You were wounded.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4108, 115235, 'Still, you are Praxis - you owe me nothing... What are you doing on Yotunheim?', 2066, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4108, 115236, 'Fighting Ra. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4108, 115237, 'Are there many of you?', 2066, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4108, 115238, 'No. But we are committed. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4108, 115239, 'It would seem our goals are, once again, in alignment. If you will help me back to our command center, I will introduce you to Ullr. He is our commander.', 2066, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4109, 114882, 'You have saved one of us from certain death, however you are here - on a facility that is one of our most closely held secrets. ', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4109, 114883, 'We followed Ra here.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4109, 114884, 'Why should we work with you?', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4110, 115243, 'The fact that they are willing to work with us is crucial. They may grow careless and let slip the location of the Solocris.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4110, 115244, 'They gave me a communicator.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4110, 115245, 'Give me the frequency and I will monitor their communications. If I hear anything regarding the Solocris I will send you after it.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4111, 111544, 'Attempt to make contact with the Asgard and enlist their help.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4112, 91852, 'The Jaffa were defending a supply cache - storing a massive amount of weaponry for what looks for a potential assault on the main Beta Site facility. This needs to be destroyed. It should be simple enough to prime a grenade and let the resulting chain reaction take care of it.', 722, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4113, 115211, 'How can an Asgard be assigned to work at a facility that they know nothing about? ', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4113, 115212, 'Perhaps they use this to keep things classified...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4113, 115213, 'That would be very... Asgard... You are probably correct. But it does not help... This discovery probably means only a select few Asgard even know of the Solocris.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4113, 115214, 'Loki?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4113, 115215, 'Yes, or someone else at his level of clearance. ', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4114, 85141, 'Find the Solocris by stealing an Asgard consciousness chip.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4133, 85355, 'Track Loki via the Asgard teleportation network.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4134, 115258, 'The logs indicate that Loki last used this teleporter to reach the Vault Level of Yotunheim. There is no record indicating he has since returned. Unless there is another way out, he has to still be on Yotunheim.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4135, 115259, 'The logs show lots of travel by Loki between this Level and the bottom level. The last record he appears in has him returning to the bottom Level.', 2078, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4136, 116895, 'You quickly download the basic information to your PDA... A quick scan of the data reveals that this device - whatever it is - is incredibly powerful.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4137, 115266, 'You found the singularity...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4137, 115267, 'Singularity?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4137, 115268, 'Yes. Black Hole research... Ra discovered it recently and he is already trying to cull everything he can from the Asgard ledgers...', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4138, 119874, 'Prevent Ra''s research team of scientists from containing the black hole in the Singularity', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4139, 115489, 'I am reluctant to discuss our research with a Praxis member... But Ra cannot be allowed access to our technology. Loki''s technology is often troublesome, but has proven useful in our fight against Ra.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4139, 115490, 'Loki. Is he here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4139, 115491, 'I believe he still lives, but I don''t know where he is. The research you discuss is something he called "pocket black hole" technology. Very unstable...', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4139, 115492, 'Pocket black hole?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4139, 115493, 'It was Loki''s attempt at a weapon for use against the Replicators. He had managed to create miniature black holes that could be manipulated, but he could not achieve complete control.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4139, 115494, 'If Ra gets the technology?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4139, 115495, 'He cannot be allowed to possess it. If you can gather intelligence on his research team''s behavior, I can instruct you further.', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4140, 115549, 'I assume you have achieved success?', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4140, 115550, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4140, 115551, 'It would be best if you were to leave that area now... There is nothing for you there.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4141, 116919, 'Secure the Pocket Black Hole for return to Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4142, 115569, 'That is a black hole? Do not get it so close to me!', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4142, 115570, 'Relax. It is contained.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4142, 115571, 'To think of so much power in such a tiny device... Can we use it as a weapon? Is it ready for combat? ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4142, 115572, 'I do not know...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4142, 115573, 'I will have it delivered to Nerus for evaluation. Good work.', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4143, 115574, 'I have encouraging news... The data you delivered earlier has borne fruit. I have uncovered a passkey Loki may have used...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4143, 115575, 'How is this useful?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4143, 115576, 'Much of the data you downloaded from the computer before was encrypted. This passcode may unlock that encryption. Hack that machine and apply the passcode... It may lead us to the location of Loki''s lab.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4144, 115630, 'Asgard maps can be complex... However, Ra trained many of us in their arcane ways... He was brutal about it... I will upload the translated location to your PDA. ', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4144, 115631, 'Hopefully we find him before Ra.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4144, 115632, 'I have heard nothing of Loki on the internal channels... If Ra seeks him, he does it secretly.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4145, 119919, 'Disable Mayet''s stealthing abilities to protect Ha''kur.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4146, 114076, 'UNUSED DIALOG.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4146, 114077, 'This is excellent information. We will crush these Asgard.', 2092, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4146, 114078, 'Be careful, they can be tricky.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4146, 114079, 'I will see to it we have sufficient forces. Ra will reward you for your service.', 2092, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4147, 114082, 'UNUSED DIALOG', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4147, 114083, 'We cannot allow Ra to acquire the Solocris. But how can I trust you? We cannot afford to be lured into a trap.', 2093, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4147, 114084, 'Ra IS setting up a trap, but I can show you where. Follow me.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4148, 115627, 'Ra will keep sending Ashrak after us... He will be relentless. His rage knows no bounds...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4148, 115628, 'What will we do?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4148, 115629, 'You are safer than I am. He knows my appearance. I must find a way to disguise myself. ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4149, 86525, 'Find and interrogate Loki.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4174, 116957, 'Decrypt the captured Asgard technical data.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5337, 75623, 'I think so...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4150, 115639, 'Please do not struggle. I have contained you in a force field. Unfortunately I cannot allow you access to me or my work. There is too much at stake. I assure you that my drones will make this quick and painless.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4151, 115643, 'You know of the Solocris? You are here to protect it?', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4151, 115644, 'Of course.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4151, 115645, 'I assure you the Solocris is safe.', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4151, 115646, 'And I assure you it is not...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4152, 86687, 'Recover the Solocris from the Nox Vault.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4153, 117478, 'This is not the Solocris, but only some sort if storage case... It is gone... Ra must have it...', 2097, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4154, 116534, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4155, 116544, 'They have the Solocris? This cannot be allowed to happen.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4155, 116545, 'Then address it... Can we track it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4155, 116546, 'No. I have spent months trying to do that. ', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4155, 116547, 'Then what do we do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4155, 116548, 'We track Ra''s minions... Give me a moment...', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4156, 86911, 'Steal what technology you can before the Asgard destroy Yotunheim.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4157, 118490, 'Your return is timely. We have mere minutes... I have something to tell you...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4157, 118491, 'What?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4157, 118492, 'You did not destroy the Solocris. ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4158, 86915, 'Leave Yotunheim before the Asgard destroy it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117579, 'You let Ra recover the Solocris! You fool - the Solocris was to be ours!', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117580, 'This is highly disappointing... ', 798, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117581, 'In a different time, this type of failure would mean...', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117582, 'Death? We are not animals, Anat... $name$ did what was possible... You cannot punish good soldiers for bad results. ', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117583, 'Regardless of who is at fault, Ra now has a dangerous new weapon to use against us. We must react to this development...', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117584, 'He cannot activate it...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117585, 'He lacks the Four Pieces... Ha''kur informed us. This gives me solace.', 798, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117586, 'He will find replacements. ', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117587, 'Perhaps, but for now he is delayed... That will need to suffice. We cannot change what has happened, only what will be.', 942, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117588, 'I apologize for this failure.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117589, 'It will not soon be forgotten... Fool...', 944, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117590, 'It was beyond controllable, Anat. There is no reason to continue this tirade. ', 941, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117591, 'Understand this - all of you - I will TIRADE when and where I please. That, you will NEVER change. ', 944, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4159, 117592, 'You are delightful, aren''t you?', 942, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4160, 86765, 'Intercept Ra''s Ashrak and recover the Solocris.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4161, 115698, 'There is no way to get onto the Tel''tak alive... However... The black hole could be transported on board... And then activated...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4162, 111910, 'The window was damaged in the explosion. It won''t last much longer. You need to get out of here!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115737, 'Is that you, Ha''kur?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115738, 'Yes. I am using Asgard holographic disguise technology... Ingenious, yes?', 2059, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115739, 'You look... Different.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115740, 'This cloak is best suited for this world... It has certainly kept me safe since Ra discovered our ruse - his Jaffa run past me with little interest. What has happened with the Solocris?', 2059, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115741, 'It was destroyed.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115742, 'Harset will be disappointed, but this is certainly not the worst that could happen. ', 2059, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115743, 'No. However, you must tell Nerus NOT to open that Pocket Black Hole. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115744, 'Yes?', 2059, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115745, 'It would be very bad. ', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4163, 115746, 'I will inform Harset immediately. ', 2059, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120007, 'Did my father send you?', 2124, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120008, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120009, 'He must know... Dakor has horrible intentions. I was attempting to preach patience to him when his troops overwhelmed me. ', 2124, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120010, 'Dakor has already attacked. Your father is in exile, but safe. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120011, 'My brothers may not be so lucky. They set out for Shol''mur. Word had come that something unusual was happening with the Ring Transporter which leads to the other crater, so they went to look into it. I was left here to try and talk sense into Dakor... ', 2124, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120012, 'It does not seem to have worked.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120013, 'I fear my brothers are in danger... I am too weak to follow them, but you must if you can. My friend Seshan lives in the other crater, he will know where they went. I will make my way home and prepare for the countermeasures against Dakor.', 2124, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4164, 120014, 'I''ll find your brothers. Make your way back to your father.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4165, 55239, 'UNUSED DIALOG', 2104, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4166, 54082, 'This information concerns me. However, we are limited in our resources. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4166, 54083, 'Warriors can be culled from the Free Jaffa, but it may take time to mobilize them. ', 771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4166, 54084, 'Do we have time, <<playername>>?', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4166, 54085, 'I don''t know.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4166, 54086, 'That is most disconcerting.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4167, 54301, 'A quick glance at the body reveals that it has been picked over by Lucian Scavengers. However, the work looks recent. Perhaps the culprits are still around. For good measure you take a quick photograph of the body... Perhaps this could be useful later.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4168, 54302, 'He murdered his master? And sent you after his valuables?', 1491, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4168, 54303, 'You see the evidence in the photograph. I was appalled at this type of behavior in a slave.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4168, 54304, 'I will immediately take this to Svarog. This is very, very disturbing behavior in a slave.', 1491, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4168, 54305, 'What will happen to him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4168, 54306, 'He will die, of course. Slowly and publicly. ', 1491, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4169, 64122, 'Boy, am I glad to see you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4169, 64123, 'Let''s get you out of here. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4171, 116899, 'Eliminate Jaffa targets of opportunity to help the Asgard.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4172, 116922, 'I have already heard reports about the weapons you made into booby traps. Ingenious.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4172, 116923, 'And Lor''ka?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4172, 116924, 'Ra is enraged... He has demanded retibution... He has not yet found a replacement.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4173, 116925, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4175, 116952, 'Those were consciousnesses... Asgard minds... You uploaded thousands of them... ', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4175, 116953, 'I was afraid of that. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4175, 116954, 'According to these logs they were prisoners... Interesting. Yotunheim, along with the other functions it serves, is a prison colony. ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4176, 116943, 'Interesting... You received this from someone within Ra''s ranks?', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4176, 116944, 'Correct. A spy.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4176, 116945, 'This object is most valuable to us... ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4176, 116946, 'Can you tell me what it is?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4176, 116947, 'I can tell you where to decrypt it. I will upload a location to your PDA. Go there and use the console to upload the data on that device. At that time you will understand its contents. ', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4177, 116926, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4178, 104935, 'Please... I am a slave, held here against my will...', 1531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4178, 104936, 'I have no time for this...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4178, 104937, 'I can get you money. There is a man, he is wealthy and I was his assistant. We fell in love and he will pay for my return - I am sure of it. ', 1531, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4178, 104938, 'Where is he?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4178, 104939, 'Here, on Tollana. Free me and I will take you to him.', 1531, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4179, 105001, 'Lyala... You brought her to me.', 1105, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4179, 105002, 'She claims there is a reward.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4179, 105003, 'Yes, anything... You brought her back to me... She lives! ', 1105, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4180, 116973, 'Investigate the Asgard''s Furling research area for useful technology.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4181, 118270, 'Intersting... These will be useful for research. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4181, 118271, 'You will send them to Nerus?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4181, 118272, 'I will get them to him presently... ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4183, 117082, 'Neutralize Ti''moth, Zaren and Urlk in order to keep Ha''kur''s secret intact.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4184, 117048, 'They are vanquished?', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4184, 117049, 'They are done... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4184, 117050, 'Good, good. Forgive me. Combat and fighting I understand, but this is unlike any task I have ever had to overcome.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4184, 117051, 'We need you here.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4184, 117052, 'I am safer now... Thank you.', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4185, 87168, 'Go to the Asgard base, Yotunheim and find the base commander, Ullr.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4186, 113186, 'Find Ullr by questioning an Asgard', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115841, 'We were taken by surprise. After the initial shock, those of us who survived began to mount a defense.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115842, 'How did Ra find this station?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115843, 'That is unknown. We had received word that his Straegis army had assaulted one of our supply outposts. It is possible he discovered the gate address there.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115844, 'How many troops do you have?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115845, 'Few. In an effort to increase numbers I was forced to place dormant consciousnesses into our reserve bodies. This has temporarily increased our numbers, but makes combat terminations costly. ', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115846, 'Ra may be after something called the Solocris.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115847, 'This is a technology?', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115848, 'We believe it is a weapon.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115849, 'For security reasons Asgard who are stationed here possess memory information only to those projects they were assigned. There are some projects which have no on-site caretaker. ', 2069, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115850, 'So there are projects that no one here may even know about?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4187, 115851, 'Correct. This helps restrain the dissemination of classified information. The Solocris is not retained within my memory.', 2069, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4188, 117674, 'Ullr? He is in the Command Hub... Are you SGU?', 2120, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4188, 117675, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4188, 117676, 'Are you sending reinforcements?', 2120, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4188, 117677, 'We were unaware you were even under attack...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4188, 117678, 'That indicates the distress signals were jammed. Ullr must be informed of this. ', 2120, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4189, 87409, 'Reactivate Thor''s Hammer to stop Ra''s forces', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4190, 115858, 'This is not surprising. Ra''s assault has been remarkably methodical. ', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4191, 115857, 'The Hammer''s circuitry is damaged beyond all repair. By the damage pattern you suspect that someone sabotaged it. Ullr should be told of this.', 2062, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4192, 55194, 'Find your way to Paglen''s residence and take his phase shifting technology.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55195, 'As you know, my daughter Magra is remarkably beautiful. Her high cheekbones, pouty lips and doe eyes are the envy of the galaxy...', 470, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55196, 'Ok.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55197, 'She''s a goddess, truly. And therein lies the problem: Some unsavory types are willing to do anything to get to her. And, because of her innocence, she is easily influenced. ', 470, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55198, 'What are you getting at?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55199, 'There is a Tollan called Paglan who has been using Phase Shifting technology to steal trinkets from the Goa''uld resort, which he proceeds to give to my daughter with alarming frequency. At first I didn''t mind - they had considerable retail value...', 492, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55200, 'But?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55201, 'Now she believes she loves him. It''s unconscionable. So I want you to send him a message.', 470, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55202, 'How?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4193, 55203, 'Destroy his home. You can keep his phase technology for yourself in the bargain - it''s just the sort of thing your Praxis have been searching for on this God-forsaken world. We both win. And he loses. ', 470, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4194, 55204, 'Tollan technology like this is very rare... We have been looking for something like this for weeks... What happened to it?', 469, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4194, 55205, 'It was damaged in an explosion.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4194, 55206, 'Well... Hopefully we can save it. Regardless, the piece has value - nice work.', 469, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4195, 55207, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55089, 'The Tollan Narim''s notes imply that Travell has knowledge of the key activator. Without that, the key we recovered is useless.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55090, 'She cannot understand the value of the key, not without the Book. ', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55091, 'She''s not to be underestimated. Clearly Narim knew she would be an obstacle. It is likely that she has it hidden or has maintained it under her control in some way. She has a very calculating mind. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55092, 'She wishes to reunite her people under her rule. If we are smart we can use her ambition against her. ', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55093, 'Offer her power in exchange for the activator?', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4227, 116381, 'I will take Igyn there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4227, 116382, 'Do not inform Loki of the Portable Singularity Apperatus you created unless neccessary.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55094, 'Even if she were to rise again, we could easily force her into a position of subordination once we have secured the technology at Ihpet. Ra''s power was vast. Beyond anything she could muster on that broken world...', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55095, 'Negotiation seems a prudent path. <<Playername>>, you will approach her about the activator. She trusts you. Negotiate accordingly, but know this: You must return to Harset with that activator. ', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4196, 55096, 'It will be done.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4197, 115860, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4198, 115859, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4199, 115862, 'UNUSED DIALOGUE', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4200, 115861, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4201, 87590, 'Destroy Asgard technology before Ra can steal it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4202, 119934, 'My sensor readings indicate that all movement in the vault has ceased. The vault contents were destoyed.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4202, 119935, 'You have no idea what was destroyed, do you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4202, 119936, 'It is inconsequential. Our choice was simple - deny technology to Ra, or give it to him. We chose the prudent path.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4203, 91899, 'The three crystals glow and pulse. The Ring Transporter activates. ', 796, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4204, 88363, 'Find out what happened to Tyr', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4207, 115928, 'You have revived me... How long was I unavailable?', 2130, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4207, 115929, 'I do not know...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4207, 115930, 'Then you must hurry... I am still recovering, but you must hurry... Ra cannot get to Loki''s toy...', 2130, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4207, 115931, 'Loki''s toy?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4207, 115932, 'The Singularity...', 2130, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4208, 91924, 'Hack one of the Tretonin Facility Consoles.', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91925, 'One thing I am sure about - Dakor and his followers are behind the poisoning. ', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91926, 'Why do you say that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91927, 'They are far too organized for this to be an accident. They knew there would be crisis and they were prepared for it. I believe they have poisoned the Tretonin itself...', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91928, 'They do control the facility.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91929, 'I cannot prove my words, however... Wild ideas will not return my people to my father''s side.', 758, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91930, 'The Tretonin facility is automated, correct?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91931, 'There is a main control computer - I tried to get into it, but I am a warrior with little patience for machines that disobey...', 758, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4209, 91932, 'What if I looked into it?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4210, 91933, 'Hacking into the system was surprisingly harder than expected - the original protocols have been tampered with, making the process a delicate one. Despite this you are able to dig into the logs and discover: Jysic''s theory may indeed be correct - the production pipeline has been modified... ', 765, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4211, 89697, 'This food duplication unit looks like it still has some functioning parts. Specifically the core... You pull the core ou and decide to take it back to Copplemann for further analysis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4212, 91935, 'Find one of the computers monitoring the production system.', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4213, 89691, 'The guts have been knawed out of this device - a rodent of some variety used it as a nest for some time. You discard it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4214, 89690, 'There''s green fungus growing on the circuitry of this device - the only thing it may be capable of diabling is your immune system. You put it back.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4215, 115893, 'Find Igyn and prevent Ra from stealing black hole technology.', 2130, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4216, 115935, 'The process is arduous, but eventually you are able to tie Igyn''s last transporter use to the bottom level. It makes sense to look there for him...', 2077, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4217, 117777, 'It appears as though Igyn is logged in to this computer from a remote location. You may be able to hack your way in and communicate with him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4218, 88624, 'DELETE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4219, 115984, 'Download the Asgard consciousnesses.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4220, 117819, 'Your work is most appreciated. I will upload these survivors presently. I will send a team out to try and retrieve those you couldn''t bring back.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4220, 117820, 'What about Igyn?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4220, 117821, 'I cannot reach him. He remains trapped behind the Singularity firewall. ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4221, 88977, 'Rescue Igyn', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4222, 117862, 'The corpse on the ground indicates that this is where Igyn uploaded himself. You''ll need to carefully upload his consciousness into the device Ullr gave you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116326, 'I appreciate your efforts to save me, but there is a great threat which must be immediately addressed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116327, 'What is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116328, 'In the singularity room there are Goa''uld scientists who are trying to access the Singularity. While inside the system I was defending against their encroachment. By removing me, you have left the Singularity vulnerable. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116329, 'What do I need to do to stop them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116330, 'When I intercepted their communications, I saw indications that they were using highly powered personal shields to prevent direct attack. Is this true?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116331, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116332, 'The Goa''uld energy shield produces a very strong energy signature. If you were to adjust the intensity of the Singularity it should naturally be attracted to the Goa''uld energy shields. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116333, 'It might draw them in?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116334, 'Perhaps. Or it may disrupt their matter, breaking them into ever-smaller pieces until they cease existence. Regardless of the means, it will destroy them. But this is a highly dangerous task...', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116335, 'If I over-adjust the Singularity''s intensity...', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4223, 116336, 'You could destroy yourself - or even the entire station. Be careful, but hurry.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4224, 116363, 'Use the Singularity to generate a Pocket Black Hole.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4225, 117883, 'This console is damaged. You''ll have to fix it to get the process started.', 2086, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4226, 112095, 'The field is stable. Move the black hole to the center of the field and I can permenantly contain it.', 2143, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4226, 112096, 'How do you move a black hole?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4226, 112097, 'Approach the pocket black hole. It''s gravity will move it toward you. You will have to activate a singularity grid at three stations to contain it. Just don''t let it touch you...', 2143, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4226, 112098, '***Note***
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4227, 116378, 'We must have Igyn transferred to a new body immediately...', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4227, 116379, 'You need me for this?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4227, 116380, 'During the initial assault we used all our reserve bodies to help fend off Ra. Loki has the only remaining source of bodies on Yotunheim. ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4227, 116384, 'Loki is... Morally more creative than other Asgard. You must be careful when interacting with him.', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4228, 116432, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4229, 116158, 'Yes, the computer activity you discovered was also monitered by us. We have use it to locate Loki''s lab.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4229, 116159, 'Are you sure he is there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4229, 116160, 'There is quite a large power drain from that area. Either Loki is there or the Jaffa are.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4229, 116161, 'Either way I have to go there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4229, 116162, 'Agreed. Be careful, Loki is... Morally more creative than other Asgard. He may not trust you, in which case he will treat you as any intruder.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4232, 116416, 'Igyn requires a body? Interesting... I can provide him one, but he will experience some pain. He sacrificed much to save prisoners most of our society has forgotten. ', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4232, 116417, 'Weren''t you a prisoner?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4232, 116418, 'I was a political inconvenience. I assume you have come to protect Yotunheim?', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4232, 116419, 'I came to prevent Ra from recovering the Solocris. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4232, 116420, 'You know of the Solocris?', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4232, 116421, 'Yes. Do you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4232, 116422, 'We have much to discuss.', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4233, 116185, 'UNUSED DIALOGUE', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4234, 112135, 'Find Loki and get him to tell you where the Solocris is. Secure it at all costs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4253, 97764, 'After a moment the Access Codes work, revealing something wholly unexpected: A clear and concise plan, replete with a gate address and images of artifacts which you recognize were in the SGC Science Facility. These Goa''uld - followers of Ra - were here on a mission to recover these objects. But why?', 1550, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4253, 97765, 'You upload the plan to Colonel Carter and resolve to try and recover the "Crystal Activator" - something the readout implies they aready recovered in the ruins. It''s likely to be found with the leader of the group, a zealot named Dijtra.', 1550, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4254, 89330, 'Set explosives to destroy Yotunheim.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4255, 116738, 'He rigged the Singularity?', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4255, 116739, 'Correct.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4255, 116740, 'That will be a very efficient way to prevent any scavenging of debris.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4255, 116741, 'Should we detonate?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4255, 116742, 'I am waiting for a recovery team to return... They have seven minutes before I stop waiting and simply give the order.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4255, 116743, 'They are late?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4255, 116744, 'Correct. ', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4256, 58699, 'Take the artifact to Thor on Omega Site.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4257, 88656, 'Rescue the Asgard recovery team and escape Yotunheim.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4258, 116745, 'We had managed to transfer them through the Singularity firewall when Ra''s forces attacked us. We managed to fight them off, but... Something is wrong with the storage mechanism... I could not fix it during the attack...', 2162, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4258, 116746, 'Can it be fixed?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4258, 116747, 'I believe so... At the terminal... Take my portable data storage unit...', 2162, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4258, 116748, 'You''re saving prisoners?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4258, 116749, 'Yes... And I fear you will also be saving... Me...', 2162, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4258, 116750, '(He loses consciousness as his body processes cease. His consciousness hub activates... He is being transferred to the nearest storage hub - the one he claims is broken. To save him and the others you will have to repair that hub.)', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116784, 'We are pleased you escaped Yotunheim with your life... You saved many of our people...', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116785, 'Ra has the Solocris.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116786, 'We are aware of this. It is disappointing, but not all battles can be won.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116787, 'He lost a lot of Jaffa at that station. Loki''s black hole can be seen through a telescope...', 2410, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116788, 'The odds were against you ever recovering the Solocris. It is worriesome that Ra has it, but he will never be able to activate it. His prize is mere decoration.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116789, 'You''ve earned a break...', 2410, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116790, 'Rest?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4259, 116791, 'If you want it. Let someone else fight the war for a few days...', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105735, 'Get through? Are you insane? With the bombardment going on, we''ve restricted access beyond this point. If you went through you''d be dead within seconds.', 2164, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105736, 'Is there any other way in?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105737, 'No. And we have no orders to engage the enemy. As long as those Hataks keep firing the main Burtonol facility is cut off.', 2164, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105738, 'Burtonol controls defense authorizations. If they are cut off...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105739, 'Take it up with Tynan. He''s the boss.', 2164, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105740, 'He said Burtonol is the boss.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105741, 'Kind of. Burtonol is the boss directly over Tech Secure, but they are a subsidiary of Tech Con Group and Tynan is TCG. So, Burtonol is the boss when Tynan isn''t deciding to be the boss. Since you can''t get to the Burtonol facility... ', 2164, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4260, 105742, 'Tynan is the boss.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116610, 'I have disappointing news... Ra is in possession of the Solocris.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116611, 'Impossible. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116612, 'We were acting on hope. While you were gone I ran trhough transport logs. We recovered it and transported it off Yotunheim mere hours before we found the hiding place. ', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116613, 'This is very bad.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116614, 'It is disappointing, but Ra cannot activate the Solocris without the Four Pieces. ', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116615, 'No?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116616, 'They are a requirement for the operation of the device. I have intercepted communications which indicate that Ra is remarkably unhappy about this discovery.', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116617, 'Did you know this before?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4261, 116618, 'Of course. It was part of the reason I did not race to the Nox vault. Without the Four Pieces, the Solocris is a worthless husk. ', 2095, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4262, 117067, 'Destroy the Jaffa weapons cache and mark the Jaffa captians for monitoring. ', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4263, 118316, 'We have already begun tracking Ti''moth, and Zaren. Ulrk''s tracker is not operational yet, but I have technicians working on a solution... ', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4263, 118317, 'Any reports about the weapon cache?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4263, 118318, 'Yes. Your adjustments to their weapons has proven most useful... You may have bought us valuable time to regroup.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4264, 89383, 'Recover Asgard consciousnesses stolen by Ra''s Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4265, 118331, 'Thank you. I will transport these consciousnesses to Orilla. I will not risk putting them back into storage.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4265, 118333, 'The fighting has damaged or destroyed several hubs containing stored minds. These are lost forever...', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4266, 117137, 'Scan Ra''s Jaffa to try to discover their true nature.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4267, 118351, 'This data is strange... These fluctuations seem to indicate that the Jaffa are almost... Not there at times, as if they have become unstuck from our reality.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4267, 118352, 'Unstuck from our reality?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4267, 118353, 'Your assertion that Ra is fusing these Jaffa with Straegis-Furling essence is sound. These creatures appear as a hybrid.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4267, 118354, 'A hybrid?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4267, 118355, 'His crystal technology seems to be based on manipulating Goa''uld bio-technological traits directly with Straegis properties. I will report this to the council. This may help us find a way to fight them.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109173, 'The news from Dakara is hopeful. Ra''s forces fall back in retreat. The Council is restored, although trust is shaken. We Jaffa live free another day.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109174, 'Do you really think it is over? If Ishta takes the Hak''tyl away and the Ruk''yal are no longer allies... ', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109175, 'Dakara is still bleeding Dr. Jackson - this cannot be doubted. The Council is plagued with mistrust and furious at A''lem. We have lost many warriors. Still, Ra has withdrawn... We must savor this victory...', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109176, '... So that it will inspire the next... Famous Jaffa poem... Yul''tak, correct?', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109177, 'Correct. Although what you call a poem, many of us see as a holy text. ', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109178, 'Ra''s decision to rely on deception - kidnapping the Council in an attempt to implement a mind control strategy - indicates that he may lack the military power we have attributed to him. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109179, 'He left the fight against the Hak''tyl after taking minimal losses.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109180, 'He may be weaker than we thought. ', 2568, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109181, 'Let us hope this is so... ', 2323, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4268, 109182, 'Regardless, Ra is managing to keep himself on our radar. The recent intel from Dakara is disturbing, to say the least.', 2410, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4269, 58193, 'You hack into the Tollan computer core.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4270, 116999, 'Gather artifacts from the Furling Vault and deliver them to Omega Site. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4271, 118273, 'These objects are in remarkable condition... They will be very useful in our research regarding the Straegis. I will have our scientists investigate them presently.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4272, 109636, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4273, 110021, 'Thank you. A''lem would launch a witch hunt against me if she knew... Neither you or I would escape alive.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4273, 110022, 'I thought she was a tactical idiot.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4273, 110023, 'What she lacks in martial prowess she makes up for in political skill. There''s a reason the Council dotes on her. I swear on my father''s resting place, if I did not know better I''d say she was half-Goa''uld.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4274, 78349, 'Find the Ancient Knowledge Device Amaterasu believes is in Crevice Lakes', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4275, 78350, 'Lethander has informed me that you have discovered a Goa''uld on Lucia... I would be most interested to know who it is...', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4275, 78351, 'If it is someone of importance?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4275, 78352, 'Open a line of communication... I am willing to meet with any of my old compatriots...', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87225, 'You have discovered my little game, have you?', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87226, 'I have no intention of exposing it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87227, 'Who are you working for?', 195, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87228, 'Baal.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87229, 'Baal? Interesting. I had heard that he was in an alliance of strange bedfellows - non-compliant Jaffa, even humans. Many have spoken ill of it, but the idea intrigues me.', 195, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87230, 'Who are you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87231, 'Amaterasu.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87232, 'Baal would welcome a summit with someone of your stature...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87233, 'I could be open to that. I''d need help first... Much of my interest in this area surrounds a piece of intelligence I received: There is an Ancient Repository of Knowledge in this area.', 972, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87234, 'A face-hugger?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4276, 87235, 'Exactly... I have long coveted such a discovery. If you were to recover this for me, I would be in your debt. The local populace may know where it is, but I haven''t been able to convince them to tell me... Yet. ', 972, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4277, 78362, 'What do you want here?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4277, 78363, 'I''m looking for a device - a face hugger...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4277, 78364, 'I have heard of something like that - Yotho used to speak of it...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4277, 78365, 'Yotho?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4277, 78366, 'Crazy guy... But he used to have all kinds of junk in his yard before he went missing. You should look there... ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4277, 78367, 'Your help just saved your life... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4278, 78368, 'Impressive... Now, give me the device... I have been preparing my mind for this moment over the last...', 972, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4278, 78369, 'Something wrong?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4278, 78370, 'It has been used. ', 972, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4278, 78371, 'So?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4278, 78372, 'So it is worthless... Someone else got the information downloaded into their mind first - probably one of those pathetic vagabonds that live around here. They probably were turned insane within seconds. Wasted opportunities plague me... ', 972, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4278, 78373, 'What about Baal?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4278, 78374, 'Tell him that I will see him. ', 972, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4279, 78375, 'Amaterasu? Interesting. She is one worth having discussions with... You have done well. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4280, 78081, 'Bring back remains of Ra''s Jaffa to Nerus for study.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4281, 118499, 'I hear things... Stories... I heard some very intriging things about Ra''s Unas on Ihpet. They were different...', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4281, 118500, 'He did something to them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4281, 118501, 'I wonder if his Jaffa have been similarly altered... When you visit Dakara I need you to bring me corpses - I''m sure if you run into them down there, there will be corpses...', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4282, 120016, 'These should do nicely... And he certainly has done something to them, hasn''t he? Leave me to my research... Unless...', 2165, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4282, 120017, 'Unless?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4282, 120018, 'Unless you want to bring me one of those human bagels? With the cheese spread? Delicious. I''m famished. ', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4282, 120019, 'Bye Nerus.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4283, 78117, 'Find Zipacna and bring him to Harset.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4284, 118505, 'There have been some interesting rumors coming to me from Dakara... Useful rumors. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4306, 81963, 'I need you to help me... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4284, 118507, 'One of Moh''katan''s more pliable associates claims to have seen Zipacna. He is an old associate of mine... He could prove valuable... See Lo''rak. He can be found in the Bazaar section of Harset. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4285, 78121, 'I did see Zipacna... He was near Nogata''s camp... I do not know what he was doing, but that is a dangerous place. If you seek him, do it with caution. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4286, 87344, 'Well delivered... You are proving quite useful.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4287, 80063, 'Round up the suspicious Jaffa on Harset.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4288, 88825, 'Ra''s Jaffa infect this city...', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4288, 88826, 'Jaffa loyal to Ra?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4288, 88827, 'Remnants of them. They once were and they cannot be trusted. Petbe has had his ear to the ground and discovered one who is openly working for Ra - Bra''hin. It is only a matter of time before they infect us from within.', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4288, 88828, 'Should I find Bra''hin?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4288, 88829, 'You should find all of them - and take them to jail. You''ll find them around the city. Perhaps, in a pathetic effort to save himself, one may reveal where Bra''hin is.', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4288, 88830, 'What should I do with him?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4288, 88831, 'Fill the sand with his blood. ', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4289, 78202, 'UNUSED DIALOGUE', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4290, 80025, 'He is dead, yes?', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4290, 80026, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4290, 80027, 'This pleases me. ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4291, 78504, 'Investigate the shield towers for signs of espionage.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4292, 88870, 'Ra''s bombing of the city has yielded him little - the shields are holding and there is little danger of them coming down. However...', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4292, 88871, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4292, 88872, 'Ra''s genetic manipulation of his minions concerns me. His Ashrak are already remarkably stealthy... I fear that he may use them to pave the way for a larger invasion.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4292, 88873, 'Should I check the city?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4292, 88874, 'Start with the shield towers. If these were compromised he could flood the city within hours... ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4293, 78510, 'UNUSED DIALOGUE', 1426, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4294, 78511, 'These explosives concern me. It is likely Ra is using Ashrak... However, we have a countermeasure.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4294, 78512, 'Oh?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4294, 78513, 'This is a device I built long ago. It taps into the encoded signal Ra uses, allowing me to identify where his signal leads. More than once this saved my life over the years. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4294, 78514, 'Would Ra be using the same signal now?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4294, 78515, 'It is likely. Ra never had reason to suspect anyone had cracked the code. Whomever he unleashed his Ashrak always met the same fate. ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4294, 78516, 'I can use it to identify them within the city?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4294, 78517, 'Exactly. The device will give you a location. From there you must be very careful indeed - Ra''s Ashrak have always been the most effective of their kind.', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4295, 56393, 'Scan Harset for signs of the Straegis.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4296, 88875, 'Nerus has developed a device which may be quite useful - a Straegis scanner... Within a given area it can identify the Straegis life signature.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4296, 88876, 'Very useful.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4296, 88877, 'I need you to test it. I do not expect to find anything on Harset, but... I did not expect Ashrak to be here - and we all know how much Ra personally wants the New Mind Goa''uld erradicated. Report to me when you are done. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4297, 118465, 'Nerus feared they might already be here... How they got in is the real question... I will double our security detail. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4298, 78593, 'Investigate the recent suspicious shipments.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4299, 118555, 'I have heard disturbing news... My contacts in the black market have identified some shipments that they cannot trace. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4299, 118556, 'What types of product?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4299, 118557, 'They cannot tell... There are weight disparities between what we send through the gate and what is listed. This is typical black market behavior... Except that these discrepancies exist on shipments that have no expected black market product.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4299, 118558, 'A second black market?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4299, 118559, 'It''s possible. Black market trading is something we tolerate, but monitor for security reasons. Now it has become a problem. I need you to get to the bottom of these shipments. Start with the Op-CORE operative Hansen... ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4299, 118560, 'He runs the black market?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4299, 118561, 'He is a principal component. ', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4300, 78601, 'I can guarantee those shipments aren''t my people... Baal knows I play the game above board...', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4300, 78602, 'Then point me in the correct direction. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4300, 78603, 'Lo''rak. ', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4300, 78604, 'The Jaffa?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4300, 78605, 'He''s the requisitions officer and he''s the one who ultimately determines what goes through the gate. Anything that gets slipped on would have to get through him somehow... ', 950, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4301, 81934, 'I have no idea what it is you speak of... All the shipments through the gate are properly prepared...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4301, 81935, 'I know that isn''t true.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4301, 81936, 'I manage my post with honor!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4301, 81937, 'I am not debating that. I just want information... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4302, 81939, 'This lock is relatively simple... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4303, 88209, 'This is most unsettling... Petbe has been running a secret black market scheme... I didn''t think he had it in him... And since his sun rises and sets with Anat, you can be certain she is involved as well... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4303, 88210, 'It follows. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4303, 88211, 'We will get to the bottom of this. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4304, 78676, 'Eliminate the traitor Petbe.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4305, 88367, 'Through the documents you recovered, I have discovered the reason for Petbe''s deception... It is your mother and her friends...', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4305, 88368, 'The System Lords?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4305, 88369, 'Yes. It appears that they have been actively using Petbe to secretly build their power base - sending messages through, receiving supplies and preparing for something... What exactly she has in mind is unclear to me, but she is not to be trusted. ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4305, 88370, 'You''re certain?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4305, 88371, 'Yes. What I am not certain about is who else is involved... Marsh? Moh''katan? Lethander? I will work to uncover this information while you deal directly with Petbe...', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4305, 88372, 'Elimination?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4305, 88373, 'Yes. We must disable this pipeline immediately. Do the deed, but hold it to yourself as a secret. Anat cannot know who killed him. ', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4306, 81962, 'You again? I have told you all I know... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4306, 81964, 'I will do no such thing! I will not involve myself in such things. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4307, 78693, 'It is done... And Anat will writhe in agony until she has the culprit... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4307, 78694, 'I did not discard the body. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4307, 78695, 'This is good. We want him to be discovered... That is the only way to determine the depth of the conspiracy... ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4308, 79018, 'Find a solution to Anat''s desire for justice over Petbe''s murder.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118591, 'Something terrible has happened... Something terrible and unacceptable and terrible has happened...', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118592, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118593, 'Petbe - my beloved, loyal, sweet Petbe - was found murdered in the Storage area here on Harset. We were unable to revive him. ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118594, 'That is a tragedy...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118595, 'On so many levels... But it will not be just my tragedy because you - YOU - are going to find me Petbe''s killer. You are going to find the murderous vermin and bring me their head on a platter. Literally. A PLATTER!', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118596, 'Yes my Queen...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118597, 'Start with Lethander - he always slinks around here - he knows something... Lethander ALWAYS knows something.', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118598, 'I will look into it...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4309, 118599, 'If this is more than a simple attack on his life - if this is political - than prepare yourself... Harset''s streets may well run red with blood.', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4310, 79028, 'She spins and twirls and bends herself in all directions... Her anger is a sign - Petbe was doing something important for her and her cadre of System Lords... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4310, 79029, 'What about Lethander?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4310, 79030, 'He is problematic... But he has no love for Anat. I would approach him and see what he knows... The murder wasn''t perfect, so there may be fallout. Lethander might be a worthy ally if we need to cover up your involvement. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79036, 'I heard of Petbe''s demise. Couldn''t have happened to a more sycophantic personality... I''m shocked he was far enough away from Anat for it to have happened...', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79037, 'Anat believes you have information.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79038, 'She is wise... Insane, but wise... I know who did it.', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79039, 'You know?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79040, 'Of course I do. It''s a particular skill I have - a sense, if you will. Would you like me to tell you who the killer is?', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79041, 'Of course...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79042, 'I need something from you first. I need Straegis themes - parts... Life, forces and matter shards... Agnos is simply teeming with the creatures and, because you want my help, you can collect them for me. ', 978, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79043, 'Do not tell anyone else what you know until I return.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4311, 79044, 'Of course not... I shall wait here with baited breath. ', 978, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4312, 81967, 'You are remarkably efficient... ', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4312, 81968, 'Now you tell me what you know.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4312, 81969, 'I know that whoever the murderer is, they must tread carefully... Anat''s little lackey was serving her higher purpose - an overthrow of the council, to be replaced by her sycophantic System Lord friends... A veritable palace coup...', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4312, 81970, 'You are certain of this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4312, 81971, 'Of course... But Petbe''s murder has put her on edge - she fears the plot is exposed... She fears that the murderer is warning Baal, Marsh and especially Moh''katan. Until a killer is found, she will not rest easy. ', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4312, 81972, 'What if one is not found?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4312, 81973, 'Eventually she will discover it is you... Your urgency was a fatal giveaway. Your secret is safe with me, but you must find a way to turn her off your trail. ', 978, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4313, 79052, 'He claims she is after the entire council? This is remarkably unsurprising. For all of her intellect, her motives are often uncomfortably obvious. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4313, 79053, 'Lethander claims that she will not stop until she finds Petbe''s murderer...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4313, 79054, 'Yes... She fears that whoever that might be, they are waiting in the wings to expose her scheme. So we need to give her a killer...', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4314, 79175, 'Set up Lethander to take the fall for Petbe''s murder.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4315, 118600, 'Your exposure to Lethander concerns me... He is never to be trusted - he is far too smart to not try and turn this to his advantage...', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4315, 118601, 'What if he is the murderer?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4315, 118602, 'Interesting.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4315, 118603, 'She already believes he has a finger in every pie.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4315, 118604, 'Yes... He is working closely with Nerus. We can use that connection to our advantage... If you can draw Lethander somewhere public and make a scene... ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4315, 118605, 'The council will want evidence.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4315, 118606, 'You get him exposed, I''ll provide the evidence... Have Nerus send him to the Marketplace. I will meet you there when the time comes. ', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79201, 'You are telling me that it was Lethander that killed Petbe? Unbelievable!', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79202, 'We have the evidence...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79203, 'Baal has evidence? And you need to expose Lethander before he hears of this plan for his capture and escapes into the night... ', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79204, 'Exactly. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79205, 'And Baal knows you have come to me?', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79206, 'He sent me.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79207, 'I can assist you... I can claim a need for supplies. However, you must do something for me... Buy me something delicious to eat... Something fresh and particularly tasty... ', 943, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79208, 'You are serious?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4316, 79209, 'Deadly... I require constant satiation. In exchange for my help it is the least you could do. ', 943, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4317, 79210, 'This will do nicely... I will direct Lethander to the Marketplace presently... ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4318, 79211, 'Lethander? This is so... Unexpected... The evidence is irrfuteable...', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4318, 79212, 'You can rest easy now.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4318, 79213, 'Yes... Yes I can... Be gone.', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4319, 113831, 'There is a child I was close to called Kayin. He has gone missing... I fear he has gone up toward the Red Collar basecamp. They are notorious for "recruiting" young children for indoctrination to their ways. ', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4319, 113832, 'His loss is unfortunate.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4319, 113833, 'His return would inspire my gratitude. I have much you could find useful.', 195, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4320, 79326, 'Collect Streagis samples for Goldam.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4441, 81765, 'Approach Opheltes about being a spy for Moh''katan. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6345, 120091, '<Input text here.>', 3572, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4321, 79327, 'You are very special you know... Your species did not merely evolve - you were designed.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4321, 79328, 'Designed?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4321, 79329, 'Yes, by the Furling. You were their answer to the question of the Fifth Race - designed to protect the Galaxy after the dissolution of the Alliance of the Four Races. They implanted you in a different race, if I remember correctly. But it is very possible that you are related to the Straegis in some way. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4321, 79330, 'What would that mean?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4321, 79331, 'I honestly do not know... But I am confident that we can determine if you have a connection. Ra holds the Straegis together by using basic themes - if you can collect some of those for me I can run some tests... ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4322, 79332, 'Excellent... These will do nicely... Now, use this device on yourself - it will cause an interaction between you and the Straegis material. I will be able to guage if there is any reaction... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4323, 79373, 'Collect Straegis-related technology.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4324, 118617, 'Goldam''s work with the Straegis is just the beginning... Before Lethander met his demise I was working with him to discover the depth of our Furling connection...', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4324, 118618, 'Furling?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4324, 118619, 'Yes - the Furling and Straegis are two sides of the same celestial coin, as it were... We Goa''uld are all "of" the Furling. Ra''s power - Ra''s technological edge over us - existed because he found this connection first and exploited it... ', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4324, 118620, 'And if he can exploit it... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4324, 118621, 'So can we... Theoretically we should be able to use the power of the Furling ourselves. However, this potential is not something I want to share with our leadership... Not yet. ', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4324, 118622, 'I will keep it silent.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4324, 118623, 'I need advanced Straegis remnants to continue my work - samples of Communciation, Knowledge and Conflict... These themes will stay present in the shards even after you have released the Streagis entity. Bring samples to me... ', 943, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4325, 79381, 'UNUSED DIALOGUE', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4326, 79382, 'UNUSED DIALOGUE', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4327, 120015, 'Excellent... It is only a matter of time until this becomes something very, very useful...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4328, 77586, 'You may now see the Queen. Do not displease her. ', 954, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4329, 113944, 'The child has value for me. As promised, I will give you something you may find useful in return. ', 195, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4329, 113945, 'Ra crystal?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4329, 113946, 'Yes. I came across it recently. It has some interesting properties, but I am unable to understand how it works. Perhaps your scientists can benefit.', 195, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4329, 113947, 'Perhaps.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4330, 113948, 'Interesting little morsel, this... Most useful. Well done, $name$.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4331, 88405, 'I don''t get too many visitors down here... ', 1139, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4331, 88406, 'I''ve just never been down here before.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4331, 88407, 'Part of Ra''s old setup on Harset I guess. Kinda smelly but I got used to it... Is there something I can do for you?', 1139, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4332, 114611, 'The plan has worked... I am officially in command of the Spaceport.', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4332, 114612, 'Congratulations to us.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4332, 114613, 'Exactly. But, I need you to fix the landing controls to unscramble the beacon, ASAP. We have to get ships into that station immediately.', 452, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4333, 97737, 'You bring word from my father? ', 758, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4333, 97738, 'He is alive. He is in exile, but Senl''c is with him. He sent me to look for you and Trink''na.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4333, 97739, 'You are a welcome face. The situation here is grave.', 758, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4334, 91945, 'This is Carter...', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4334, 91946, 'Colonel, I don''t have a lot of time but... I believe the Tretonin being produced on Beta Site is the source of the poison...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4334, 91947, 'You''re sure of this?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4334, 91948, 'Almost 100%. I''ve disabled the facility and I''ll bring back a sample... But first I''d like to make sure they can''t re-start the poison process again...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4334, 91949, 'Absolutely. Dismantle what they''ve got... I''m looking forward to your report - I was worried we''d lost you out there. ', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4335, 57407, 'This camp has received a shipment of some nice prospects. Do you also enjoy gladitorial sports?', 1001, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4335, 57408, 'Yes, its a recent hobby since coming to Tollana. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4335, 57409, 'Oh, excellent! Why don''t we make a little wager - we will each select a candidate from this newest batch and pit them against each other. ', 1001, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4335, 57410, 'I would enjoy that.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4335, 57411, 'Quickly, let''s hurry and get there ahead of the riff-raff.', 1001, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4353, 91950, 'This is Carter...', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4353, 91951, 'Colonel, I have limited time, so I will be brief. I believe the Nine Peaks Jaffa on Beta Site have been poisoned via their Tretonin.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4353, 91952, 'You''re sure of this?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4353, 91953, 'I''ve taken the precaution of disabling the facility. I wish to return a sample of the technology used to Mimir for evaluation. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4353, 91954, 'Absolutely. Is there a way for Dakor''s people to re-instate the poison into the pipeline?', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4353, 91955, 'Before my return I will confirm that the poisoning of the pipeline is no longer possible. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4353, 91956, 'Excellent. Glad to hear from you, <<playername>>. I was getting worried about you.', 708, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4354, 99185, 'On Dakor''s body you find a small, crystal transmitter - crafted from a technology similar to everything else you''ve found here - but you get the sense that this tool is designed to track... Dakor. If you can manage to trace the signal...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4355, 101460, 'You just place it over the infected human and then activate the device in this manner. It will seperate the symbiote and host.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4356, 101658, 'This Ion Cannon looks like its been recently picked over by the Lucian Scavengers in the area. It is likely that one of them has an Ion Core.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4357, 58166, 'Present yourself to the Praxis leadership.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4358, 118940, 'It is good to see you, old friend. I hope your stay in the Castle was not unbearable...', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4358, 118941, 'It was endured.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4358, 118942, 'As you can see, we are living in great splendor...', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4358, 118943, 'I have seen Humans and Goa''uld.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4358, 118944, 'Indeed. Our alliance includes them, but not in great numbers. They each provide a useful resource to us. We, in turn, provide them with stability and direction. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4358, 118945, 'We are seen as equals?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80779, 'How do you place it?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4358, 118946, 'Yes. You must be introduced to the other leaders. Do this yourself - impress them. They need us, but we need them too. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4359, 81710, 'UNSUED DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4360, 81711, 'Unsued dialogue', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4361, 81735, 'Unused dialogue', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4362, 81737, 'UNUSED DIALOGUE', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81723, 'Moh''katan has told us of you. You are a warrior of great renown. ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81724, 'Most impressive. ', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81725, 'Your praise is appreciated.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81726, 'Anat, you''re being suspiciously quiet.', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81727, 'It''s a Jaffa. I have seen many in my lifetime. None is more special than another.', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81728, 'I assure you, I am unlike any other.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81729, 'Confidence. Just like that which infects your Moh''katan. I see much confidence in you Loyalists, but I have no action which warrants it. ', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81730, 'Time will tell on that. We appreciate you presenting yourself. ', 941, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81731, 'Yes. You have shown much promise.', 942, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4363, 81732, 'Be gone. Your moment in the sun wilts you.', 944, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4364, 81736, 'UNUSED DIALOGUE', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4365, 81755, 'It went well, I assume.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4365, 81756, 'Queen Anat was less than receptive.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4365, 81757, 'Queen Anat is one whose old world views may lead to some very modern consequences. For now she serves a purpose - she provides fresh symbiotes.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4365, 81758, 'If those days ever end?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4365, 81759, 'Then she may end with them. For now, her ability to provide us with her offspring is a powerful recruitment tool. We need her. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4366, 81761, 'UNUSED DIALOGUE', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4367, 81763, 'UNUSED DIALOGUE', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4368, 80932, 'Engage in Rin''la with Mala''c.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4369, 118953, 'You have been gone for quite some time. Your position within our newly formed clan is undefined. You must re-assert yourself.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4369, 118954, 'Rin''la?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4369, 118955, 'Yes. Mala''c waits for you in the Marketplace. I expect you to acquit yourself honorably.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4369, 118956, 'Always.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4370, 99501, 'Moh''katan has sent you?', 957, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4370, 99502, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4370, 99503, 'We will use the traditional Rin''la staff. We will use the Hak''tyl traditions.', 957, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4370, 99504, 'No movement?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4370, 99505, 'Correct. We use only the traditional Rin''la staff and we do not move as we engage. ', 957, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4370, 99506, 'Good luck to you, Mal''ac.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4370, 99507, 'And to you, $name$.', 957, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4371, 58423, 'No.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4371, 58424, 'Fair enough. The Book of the Gates is a map... A map which, when followed, can lead to great power. Do you have it?', 943, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4371, 58425, 'That''s not your concern.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4371, 58426, 'Why?', 943, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4371, 58427, 'I want information about the Book of the Gates. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4371, 58428, 'An extra rations card? Your efficiency is impressive... And because you have pleased me, I will grant you audience. See how magnanamous I am?', 943, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4372, 120303, 'Your station within our clan is again secured. You bleed, do you require medical attention?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4372, 120304, 'No.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4372, 120305, 'As I suspected. It is good to have you back, old friend. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4373, 80981, 'Present the Lan''toc to Jaffa once loyal to Ra.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4374, 118957, 'There are many Jaffa in Harset who were once loyal to Ra. There are concerns amongst the Council that these Jaffa live here out of convenience, as opposed to honor. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4374, 118958, 'We must test their loyalty.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4374, 118959, 'Indeed. The Lan''toc is the only way. You will approach those in the city who were formerly of Ra. You will engage in Lan''toc. Convert as many as you wish.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4374, 118960, 'I will.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4375, 80986, 'I swear my allegiance to the Praxis and forswear my bond with my former God, Ra. ', 2190, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4375, 80987, 'You have accepted Lan''toc?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4375, 80988, 'On my life. ', 2253, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4376, 80989, 'I will never forswear my god, Ra.', 2190, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4376, 80990, 'You have rejected Lan''toc?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4376, 80991, 'I have rejected Lan''toc. ', 2253, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4376, 80992, 'Then you must leave the city.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4376, 80993, 'On my honor, I will. ', 2253, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4377, 120299, 'There are many who fear Lan''toc and the conversion process. I believe that the old ways are often the most trustworthy. You have done well, $name$. Hopefully this act of Lan''toc will reduce the concern about Jaffa loyalty within the Council.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4378, 81028, 'Speak to Boryl.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4379, 81029, 'You see Boryl - a former comrade who long ago fought side by side with you under a different flag. His System Lord, P''tah became allied with Ra just before Ra''s death over Abydos... Perhaps he can be convinced to join Moh''katan and the Praxis?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4380, 89830, 'You put together a care package filled with foods you are sure will lure the starving Tollan out into the open. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120315, '$name$, it has been a long time. You are on Men''fa but do not wear the adornments of Ra.', 2191, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120316, 'I serve the Praxis, and Moh''katan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120317, 'A woman?', 2191, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120318, 'Indeed. A very capable one.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120319, 'Your honor is diminished if you serve a woman. Instead you should commit to Ra - a true God, not a Jaffa.', 2191, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120320, 'Ra is dead.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120321, 'He shall return. So says the prophecy. You are on sacred ground. Either you choose to follow the path of Ra, or you leave Men''fa. ', 2191, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120322, 'I can do neither.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4381, 120323, 'Then I am afraid, old friend, that only one of us lives to see the sun rise tomorrow.', 2191, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4393, 81040, 'Find evidence of symbiote host experimentation.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4394, 118961, 'This Unas has been modified - clearly some genetic manipulation has occurred. Upon closer inspection you see that the symbiote inside the Unas has been tampered with... You feel a sickness growing - this is desecration. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4394, 118962, 'You decide to collect Jaffa and Unas corpses inside this laboratory - if there is desecration, Moh''katan will want to hear of it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4395, 81075, 'This is disturbing... Each of these corpses shows signs of symbiote tampering. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4395, 81076, 'Desecration.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119013, 'The recent deaths of Petbe and Lethander have convinced me that Queen Anat is up to something.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4395, 81077, 'Indeed. Clearly Ra has little respect for the ways of the past. Any Jaffa or Unas who would accept such desecration from their God does not deserve to live. When you next encounter them, kill them on sight.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4396, 81092, 'Collect Illana''s slaves.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4397, 118963, 'Jaffa, do you have a moment?', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4397, 118964, 'Certainly.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4397, 118965, 'My honor is at stake. Three slaves - simple, putrid, weak - have escaped. I wish to recover them quickly but other, more pressing needs, persist. Can you assist me?', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4397, 118966, 'Your Jaffazon reputation demands that I help you - to honor such a warrior. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4398, 120328, 'You are remarkable in many ways, $name$. Whom do you serve?', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4398, 120329, 'Moh''katan is my leader, we serve no God but the Praxis. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4398, 120330, 'A woman leads you? This is non-traditional - yet you carry yourself with traditional honor.', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4398, 120331, 'Our honor is all we have of value.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4399, 81119, 'Convince Opheltes to let Illana talk to Moh''katan.', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118967, 'You serve no Goa''uld?', 444, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118968, 'No. We serve ourselves.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118969, 'I would be interested in learning more about this... ', 444, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118970, 'I can introduce you to Moh''katan. She would embrace you and your Jaffazon.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118971, 'I cannot simply meet with her. I have pledged my allegiance to Opheltes and he has treated me and my female warriors with great dignity and respect. ', 444, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118972, 'Perhaps I can convince him to let you meet Moh''katan.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118973, 'If he were to agree to such a thing I would be surprised...', 444, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4400, 118974, 'I will make it so.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4401, 81113, 'What you ask is impossible. I need my Jaffazons, they serve me. However...', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4401, 81114, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4401, 81115, 'I would need fewer of them if I was able to electronically tag my slaves - like cattle. I have heard rumors that the vRips have such a device in their junkyard.', 399, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4401, 81116, 'I can get it for you...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4401, 81117, 'I have refrained from sending Illana and her warriors for fear of starting a war with the vRips... You, however, have no allegiances. Bring me that device and I will permit her to see this Moh''katan.', 399, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4402, 81118, 'Your ingenuity is impressive. I will inform Illana that she may speak to Moh''katan as soon as all my slaves have been properly tagged.', 399, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4403, 81296, 'Patrol Harset for signs of intruders.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4404, 118978, 'Ra''s attacks on Harset''s shields are having no impact. I fear that they are a tactic - designed to engender fear and draw our attention away from more subtle methods.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4404, 118979, 'Sabotage attacks?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4404, 118980, 'Yes, that is my fear - he could resort to terrorism. Patrol the area and look for signs of Ra''s presence. Never underestimate him as a military mind. I knew many who did, and none survived.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104385, 'You have the Activator Crystal?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104386, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104387, '(Ball takes the Crystal and combines it with the Key housing you delivered before. Almost like a living system the two Crystals intertwine and become one, gleaming in his hand).', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104388, 'It is as the legend says - the Crystals live. ', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104389, 'We must marshall a force and hit Ihpet quickly. My Jaffa can be ready within days...', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104390, 'We can''t wait for that - we need to get there now and get information...', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104391, 'I will go. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104392, 'You? Why should we let you go?', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104393, 'I have earned the right. Without me there is no Ihpet.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104394, 'You have earned it? You have been doing as you''re told and you think you deserve the honor of this assignment? And dictating that to us? The insolence!', 944, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104395, 'It is deserved. And it will be so. When our people serve us, we embrace that service with reward. Ihpet is a great unknown and the right to be the first of our alliance to cross that threshhold is an honor well earned in this case. Do any here question this?', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104396, 'I do. We do not let serfs determine policy...', 944, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4405, 104397, 'There is one voice. Are there more?... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4406, 81300, 'His Jaffa fought to the death? Predictable. They believe that he is a God. They will be fanatics.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4406, 81301, 'We will see more of them here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4406, 81302, 'He hates the New Mind Goa''uld with an almost deranged passion. He will relentlessly try and break into this city, if only to make an example of them. If he succeeds, we will show no mercy.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4407, 81316, 'Return translated Staff Weapon plans and the Prototype to Moh''katan.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4408, 96374, 'In the crate you find a deployment belt and some body armor for your chest.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4409, 96375, 'In the crate you find an Asgard hologram emitter and a piece of body armor for your chest.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4410, 96373, 'In the crate you find a staff weapon and a piece of armor for your chest.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4411, 81317, 'This console seems to have a listing of all of the Burtonol projects. One catches your eye - a Staff Weapon Program. Specifically, the data seems to indicate that the research team seems to have developed a more powerful staff weapon. You decide to recover the plans and the prototype.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4412, 101708, 'These look very useful... Give me the Prototype... It is very lightweight. They used a non-traditional alloy. I will give Nerus everything. I am certain he can use it to develop similar weapons for our people. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4413, 81353, 'Deliver a message to Moh''katan''s father, Bra''tac.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4414, 118981, 'As you know, I have split from my father. He preaches the way of the Tau''ri, a way of living to which I cannot abide. However, this does not mean my love for him is dead. I wish to get a message to him. We can do this on Dakara. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4414, 118982, 'Won''t his Jaffa reject such a message.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4414, 118983, 'Perhaps. But I am certain we can find someone willing. See Rohurk there. He will know of someone willing to deliver my message.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4415, 101762, 'You show great courage in approaching me. You also show little sense.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4415, 101763, 'I bring a message for Bra''tac.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4415, 101764, 'From his daughter, no doubt. She has disappointed him, betrayed him - why should I accept such a letter?', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4416, 81360, 'Teal''c will deliver it himself? You are most impressive. Teal''c delivering a letter from me to Bra''tac is something I never imagined was possible... Perhaps he wishes to avoid war with us.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4416, 81361, 'He was reluctant. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4416, 81362, 'Still, he accepted. It is a sign of weakness. They do not wish to provoke us because they fear what that might become. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4417, 81363, 'What you ask for is difficult... Most Jaffa would see accepting such a message as treason. Only one with great power can accept such a task. ', 2294, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4417, 81364, 'Teal''c?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4417, 81365, 'He may need convincing, but he is your best option. ', 2294, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4418, 59188, 'Take good care of that card - they''re not easy to come by... I still can''t believe I trust you...', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4418, 59189, 'I can be trusted.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4418, 59190, 'We will see... ', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4419, 89620, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4420, 59264, 'Rescue Yao.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4421, 118984, 'Pen Lai is a world I know well. For a time my God - Apophis - secretly worked with Lord Yu against Ra. I met many honorable Jaffa amongst Yu''s men. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4421, 118985, 'Oshu?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4421, 118986, 'Oshu was honorable, but the one I remember most was Yao. Given Yu''s death has left Pen Lai in chaos, he may have assembled a cadre of Jaffa whose philosophies match our own. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4421, 118987, 'You wish for me to make contact with Yao?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4421, 118988, 'Indeed. And offer him a meeting with me. If he lives, Yao would be a powerful presence to add to our alliance.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4422, 81389, 'You have saved my life. How can repay you? ', 2218, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4422, 81390, 'Moh''katan has sent me. She wishes an audience with you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4422, 81391, 'Moh''katan. An extraordinary warrior. I will most certainly seek her out. Thank you again for your help.', 2218, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4423, 81452, 'Investigate a suspected black market operation. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4424, 118989, 'Our alliance is in danger. Deceit infects us like the plague. There has always been a black market operation in Harset. However, I need information as to the size and scope. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4424, 118990, 'You fear it has grown unweildy?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4424, 118991, 'Yes. Such an operation puts our very security at risk. The people involved are compromised, and therefore cannot be fully trusted. I need names. Begin with the human Hansen, or our own Lorak. Find who controls the operation. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4425, 120335, 'I''ve never heard of a black market operation on Harset... I have no idea what you are talking about. ', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4425, 120336, 'We know you are involved.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4425, 120337, 'Ridiculous. ', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4426, 81420, 'I just run the logistics. Speak to Lethander if you want all the details. ', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4426, 81421, 'Lethander?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4426, 81422, 'He''s the one with the contacts everywhere. I just run the merchandise.', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4427, 120345, 'I am running a Black Market oepration? Me? How very delicious. And who told you of this? Lorak and Hansen?', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4427, 120346, 'How I know doesn''t matter.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4427, 120347, 'But it does - because it is untrue. You have grown fat on wild rumor and innuendo. I assure you. ', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4427, 120348, 'You assurance is hollow.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4428, 120349, 'An interesting proposition. With looming conflicts with both Ra and the Free Jaffa, this is something I must consider... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4429, 81481, 'Get details about Lethander''s offer. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4430, 81478, 'Lethander''s offer intrigues me. Find him and get specific information about what kind of munitions he can truly deliver. I do not wish to be tricked by a greedy Goa''uld. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4431, 81477, 'UNUSED DIALOGUE', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4432, 81472, 'Your timing is impeccable... Those were Free Jaffa - not Ra''s. Moh''katan''s family feud seems to have escalated and found its way here.', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4432, 81473, 'I''ll report their presence.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4432, 81474, 'She has agreed to our little business arrangement?', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4432, 81475, 'She needs details.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4432, 81476, 'She is a smart one, your Lady of Warriordom. I''ll prepare a document with the requisite information. ', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4433, 81467, 'Free Jaffa? ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4433, 81468, 'Lethander claims it to be so... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4433, 81469, 'This is most disturbing. Did he give you information for me?', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4433, 81470, 'Indeed.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4433, 81471, 'This looks acceptable. I do not trust him, but these are times where trust is a convenience we must live without. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4434, 81487, 'Retrieve Ra Jaffa corpses from Agnos.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4435, 118992, 'Ra''s desecration of his Jaffa continues. While I cannot abide by this, it does follow that if he is making his warriors more effective through this process, we must discover what it is he is doing and counteract it.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4435, 118993, 'This is reasonable. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4435, 118994, 'Gather some of the corpses from Ra''s Jaffa and bring them to me here. I will work with Nerus to determine the nature of Ra''s experimentation. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4436, 81486, 'You continue to be most efficient. These corpses will serve our purposes nicely. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4437, 81601, 'Help Goldam determine the true nature of the Jaffa. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4438, 118995, 'You are an interesting creature - do you know that?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4438, 118996, 'I am simply a Jaffa.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4438, 118997, 'Indeed - but you''re magnificent. Do you mind if I scan you?', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4438, 118998, 'No.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4438, 118999, '(He scans you with a small hand device.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4438, 119000, 'I know of my family history, the history of my clan.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4438, 119001, 'But nothing about your own origin story? Go to Agnos city and have Laro scan you. Once she does that we''ll have a full DNA analysis of your makeup. We''ll actually be able to know who - or what - you really are.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4439, 102273, 'Prepare for scan, unknown species. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4439, 102274, 'You scanned me before and analyzed me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4439, 102275, 'That scan was limited to your intellectual capacity. This scan will be a full-body deconstruction. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4439, 102276, 'Why are you using processing power for this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4439, 102277, 'Many of your kind are working directly with the Straegis. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4440, 81614, 'The Fifth Race? We have always been what we are, but it is possible that this connection to the Furling may be something we can use. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4440, 81615, 'Do you not fear desecration?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4440, 81616, 'I do fear it. But I fear untapped potential even more. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119015, 'We need information from within her circle. One of her minion System Lords would be perfect. They worship her...', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119016, 'They seem quite loyal. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119017, 'They are Goa''uld. They are loyal only to themselves. Contact Opheltes. Have him meet you away from the Command Center. Offer him immunity.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119018, 'Immunity from what?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119019, 'Whatever she has planned. We can be certain there is something. If he is in place he will warn us and be thusly rewarded. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119020, 'What if he remains loyal?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119021, 'Then he will die with the rest of them when she turns. If he wavers, tell him Petbe was our operation.', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119022, 'This is not true.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4442, 119023, 'It does not matter. What he believes is all that matters. ', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4443, 81804, 'Predictable... She moves against us in increments.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4443, 81805, 'Should we move against her?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4443, 81806, 'We need her symbiotes. As vile as she is, she holds our safety in her considerable womb. However, I am working - even as we speak - on freeing us from that consideration. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4444, 81522, 'Set up surveillance devices in Harset.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4445, 119024, 'The recent deaths of Petbe and Lethander concern me.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4445, 119025, 'They have died?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4445, 119026, 'They have been murdered. I am most concerned about Lethander - he had his fingers in many pies. For him to be killed implies much.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4445, 119027, 'A coup within the Goa''uld?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4445, 119028, 'It is possible. Unsettlingly possible. They need watching. Set up monitoring devices throughout Harset. I have uploaded the locations to your PDA. We will use these to oversee both Goa''uld and Op-CORE movements. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4446, 102788, 'You met with success?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4446, 102789, 'There was an Op-CORE officer who was disturbed...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4446, 102790, 'Will he be a concern?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4446, 102791, 'No. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4447, 102954, 'What are you doing here?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4447, 102955, 'Installing surveillance devices.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4447, 102956, 'I''m not sure you are supposed to be doing that. I didn''t get any notice... ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4448, 81647, 'Implant a volunteer Jaffa with an artificial symbiote.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4449, 119029, 'Nerus believes that he may have found a solution to our symbiote concerns.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4449, 119030, 'Tretonin?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4449, 119031, 'No, this solution is not a desecration. We are connected to the Furling. Nerus believes that the Furling shards can help us modify symbiotes so that they never mature. Instead each Jaffa would require just a single symbiote for the duration of their life. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4449, 119032, 'We would be freed of the Goa''uld.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4449, 119033, 'Indeed. We would no longer need them as we do now. Nerus needs a symbiote from Anat and some Straegis remains - shards. He will combine them once you have gathered everything.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4449, 119034, 'We will test the new symbiote on me, I hope?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4449, 119035, 'You are too valuable. I have already secured a volunteer. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4450, 81688, 'Mala''c''s death is a tragedy.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4450, 81689, 'He died bravely.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4450, 81690, 'Of that I have no doubt. Still, my heart is heavy...', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4450, 81691, 'I have never seen you like this before.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4450, 81692, 'Because you have never before seen me lose a lover.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4452, 118466, 'Identify yourself.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4452, 118467, 'I am $playername$, spawn of Anat. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4452, 118468, 'Queen Anat is not to be bothered. She is occupied at the moment. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4452, 118469, 'I need to see her...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4452, 118470, 'You will have to much to convince me to let you pass. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4453, 106608, 'I''ll make you a TechSecure security pass... It will be amazing... Just keep it quiet about where you got this. Military Passes are life prison sentences.', 2249, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4453, 106609, 'Less talk, more do.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4453, 106610, 'Right. Doing.', 2249, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4454, 59732, '"Dearest Jess. I don''t even know where to start. How you been? I miss you. I miss my boy. I bet he''s big now.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4454, 59733, '"I''m alive - and I''m sure you didn''t know that. I''m alive in my cage. Time stands still here. My days are a mixture of boredom and dread. . . Mostly dread.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4454, 59734, '"Never believe what they tell you Jess. They have no honor. They got caught playing the game by the wrong set of rules and, instead of acting with honor, they turned us into criminals.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4454, 59735, '"We''re the heroes. And we did so good, Jess. We did so good. We''re not criminals. We''re soldiers. Just like our fathers.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4454, 59736, '"They''re moving me today, into storage like an old box you don''t want to throw away quite yet. They''re telling me it''s like sleep but that''s a lie. When you sleep your mind turns off.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4454, 59737, '"But there''s hope, Jess. There are a few of us left out there, and Marines never leave their guys behind. And I tell you this - if we ever get out? We''ll make the rules."', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4455, 111566, 'You quickly reach down and remove some ornamentation from the Jaffa''s armor. The Ruk''yal tribe... What are they doing here?', 3295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4456, 60171, 'Introduce yourself to the other Praxis leaders.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4457, 90024, 'As you can see, the situation here is highly unorthodox. It never was my intention to create alliances with Goa''uld and a rather militant sect of Jaffa - but this was the only real option given the circumstances. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4457, 90025, 'Are they aware of the Straegis threat?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4457, 90026, 'They are aware, but they are not treating it with the same urgency we are... No matter. We need them for now. Introduce yourself to their leadership. Let them know you are available if they need you... ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4457, 90027, 'Am I the liasion?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4457, 90028, 'One of them, yes. I''m keeping you away from the logistics nightmare for the moment - unless you''d prefer counting ammo boxes?', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4457, 90029, 'No, sir... I prefer liasion duty. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4458, 79514, 'Your Colonel sent you over to me... Professional courtesy?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4458, 79515, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4458, 79516, 'There is something you could do to please me, however... I would like to examine some of your earth weaponry... Can you bring me samples of the hardware?', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4458, 79517, 'Anything specific?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4458, 79518, 'A few samples are all I require... I wish to gain an understanding of how your technology would affect your tactics. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116212, 'I will come to you...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4459, 90044, 'You want to give some of our weapons to the Jaffa? And I''m just supposed to give these to you?', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4459, 90045, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4459, 90046, 'You better tell me one heck of a story for that to ever happen... ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4460, 79522, 'I cannot believe I am doing this... ', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4460, 79523, 'The Colonel would approve... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4460, 79524, 'The Colonel will have my hide. ', 950, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4461, 90047, 'A liasion officer... So you are not a slave, but someone whose services I should take advantage of? I assume you are useful?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4461, 90048, 'I like to think so. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4461, 90049, 'I may put you to the test, liasion officer... Sooner than you think.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4461, 90050, 'I am ready, whenever... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4462, 90051, 'What do you want, human?', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4462, 90052, 'I was sent here by Colonel Marsh.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4462, 90053, 'Well, in that case you are mildly welcome... The Colonel is a useful man... Perhaps you will prove useful as well. You seem athletic...', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4462, 90054, 'Op-CORE places a high premium on fitness.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4462, 90055, 'Do you find my form pleasing?', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4462, 90056, 'Of course... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4462, 90057, 'You hesitate. Do not lie to me human... Do you find this body pleasing to gaze upon?', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4463, 90058, 'I believe you... You can cease groveling... I find it unattractive.', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4463, 90059, 'Is there anything else I can do for you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4463, 90060, 'Right now? You can leave. If I require you later, I will send someone.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4464, 79548, 'UNUSED DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4465, 79556, 'They are an eclectic bunch, aren''t they? ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4465, 79557, 'It''s a little disconcerting.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4465, 79558, 'What? That our Praxis Alliance features a remarkably crafty Jaffa, and two Goa''uld: One brilliantly manipulative and the other certifiable? ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4465, 79559, 'Yes...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4465, 79560, 'You do not always go into battle with the army you want... You go into battle with the army you have. This is what we have been dealt, and this is what we live with. ', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4466, 79549, 'You did this without concern for our differences... This impresses me. Because you understand the value of honor, I will request that you are my liasion officer in the future.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4467, 62214, 'Place monitoring devices on Harset.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4468, 97194, 'While we might have strange bedfellows, we aren''t going to make the mistake of trusting them... I need you to set up these monitoring devices up around our perimeter here in Harset. I want our area watched constantly... ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4468, 97195, 'Just our area?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4468, 97196, 'Correct. I''ve uploaded the specific locations to your PDA... Your instincts are good - we have to watch everything - but for now, I don''t want to create a stir by taking the chance of getting caught setting up spying devices in their areas... ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4469, 79585, 'Nice work... IT has already confirmed they are online and active... ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4470, 79722, 'Tag four suspicious Praxis members with nanotrackers.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4471, 117480, 'There are ways we can monitor our allies without drawing attention... We can monitor them through stealth. This is a technology I picked up a few years back from a planet called Aldera Sena - this little gun fires nanites... They transmit.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4471, 117481, 'A nanobot camera?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4471, 117482, 'Essentially. They will adhere to flesh - it has to be flesh - but once implanted they can be used to monitor the behavior of the target. Sight, sound, etc. I want you to tag some of our allies - low level types are best because they do not go through security checks like the others do... ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4471, 117483, 'Is there a list?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4471, 117484, 'Uploading to your PDA now... When have tagged the list, check in with Security Chief Blackstock. He''ll give you an update as to the transmission status.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4472, 99410, 'It looks like I got four of the five you tagged coming in loud and clear. ', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4472, 99411, 'Who is the one I missed?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4472, 99412, 'Petbe - he wasn''t missed, his signal is just poor. Overall this is a good result. I''ll try and fix his signal, but for now your portion of this mission is over.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4473, 60282, 'Deliver the Tollan Control Technology to Colonel Marsh.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4474, 90068, 'This technology could prove very useful on Harset... I''ve heard rumors.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4474, 90069, 'About?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4474, 90070, 'Goa''uld symbiotes being placed inside our people... I hope it''s just rumors.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4474, 90071, 'What if it is true?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4474, 90072, 'If it''s true then the Colonel has a major problem on his hands. Most of us can''t stand the Goa''uld - New Mind or not, they''re snakes and cannot be trusted. This would be the proof many would need to completely lose their faith in the Praxis project. ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4474, 90073, 'The Alliance could fracture?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4474, 90074, 'It''s in danger of fracturing every single day. ', 968, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4475, 79812, 'This is very useful. I will gather up some test cases... I have a few of us who need to be double-checked. Meet me in Storage Area. There, you''re going to test some people. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4476, 79813, 'This is my greatest fear... They did it... They promised they wouldn''t, but they went and did it. Sleep with your weapon tonight.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4477, 60795, 'Secure a reference symbiote from Anat''s symbiote tank in her chamber.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4478, 97508, 'Anat claims the symbiote inside of Dawson was not hers... I can''t very well call her a liar without evidence... I''ve tried other avenues of persuasion with no effect.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4478, 97509, 'Other avenues?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4478, 97510, 'Diplomatic approaches. I need you to get your hands on a New Mind symbiote - one of the Queen''s babies... I do not care how you do it, but get it done... Get me one of her symbiotes...', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4479, 79915, 'A quick survey of this tank makes it very clear that leaving with a Symbiote is not possible - especially with the Guards waiting to pat you down... Perhaps there is another way...', 1315, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4480, 90209, 'You are not authorized for entry into the Queen''s chamber.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4480, 90210, 'But I am, she sent me...', 954, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4481, 90211, 'Understand that when you leave, you will be searched... ', 954, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4481, 90212, 'Understood. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4481, 90213, 'You may enter. ', 954, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90201, 'You seek a new mind symbiote? Interesting... For comparative purposes, no doubt...', 496, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90202, 'I''m not going into details.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4549, 96018, 'You successfully disable the Replitech Armor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90203, 'Of course not. You''re too discreet for that... I can deliver to you a symbiote, but there is a cost... ', 496, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90204, 'Go on.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90205, 'Jaffa staff weapons... Specifically, Svarog''s Jaffa weapons... I have a business opportunity that requires a collection of them.', 496, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90206, 'How many?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90207, 'Ten. They must be Svarog''s Jaffa - their weapons have very specific adornments... And they must be in good condition. ', 496, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4482, 90208, 'I''ll be back. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4483, 79822, 'Nerus''s contact delivers a symbiote as promised.', 2263, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4484, 79929, 'Excellent... These look to be in fine condition - minus the blood. That can be cleaned. ', 496, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4484, 79930, 'What about my symbiote?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4484, 79931, 'Look at you... So task oriented.', 496, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4485, 79968, 'Meet Lethander''s contact at Machra''s.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4486, 68735, 'Sabotage Ra''s Outposts within the city', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4487, 117485, 'While you were gone, I took care of our little problem. Your little symbiote is waiting for you at Machra''s. He has it and he will provide it. ', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4487, 117486, 'Why Machra?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4487, 117487, 'Let''s just say that there are millions of Jaffa out there who will die if they do not have a symbiote... Queen Anat is not blind to this crisis.', 496, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4487, 117488, 'And Machra sells them on the black market.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4487, 117489, 'And they split the profits... I believe you earth humans call it "capitalism", right?', 496, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4488, 109591, 'Ra has over-extended himself - your ability to get to Jyoleen has proven that. We must push this advantage. That assumes your other mission is complete.', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4488, 109592, 'It is on hold at the moment.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4488, 109593, 'Then I suggest we exploit our personal talents, <<playername>>. I will track down the location of U''lien.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4488, 109594, 'And what will I do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4488, 109595, 'Sabotage Ra''s outposts. We will slow him down at every turn. ', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4489, 109616, 'It makes sense that the Ruk''yal and the Council''s arms have been used against us. Their clan has many members in the Council''s own security operation. And they have chosen to lick the heel of Ra...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4489, 109617, 'U''lien is one of them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4489, 109618, 'Yes. U''lien is the Council''s watch commander. His treachery means the Council is in grave danger, despite the SGU''s recent commitment...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4489, 109619, 'Commitment?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4489, 109620, 'Bra''tac''s SGU has finally sent troops. Apparently I am not the only one who was convinced A''lem is unfit.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4489, 109621, 'Is this going to be a problem?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4489, 109622, 'My people know you work with us, not against us. If you and I work below the surface, there is no danger.', 768, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4490, 109596, 'You notice the weapons you sabotaged bear the markings of the Free Jaffa clan, the Ruk''yal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4491, 109597, 'You notice the grenades yoiu just sabotaged bear the mark of the Jaffa Council''s own stock. Something is clearly amiss.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4492, 80005, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4493, 80004, 'UNUSED DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4494, 80003, 'UNUSED DIALOGUE', 2190, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4495, 80002, 'UNUSED DIALOGUE', 2190, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4496, 80001, 'UNUSED DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4497, 79999, 'UNUSED DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4498, 68944, 'Eradicate the traitor Jaffa U''lien at the Council Complex', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4499, 109623, 'U''lien must be eliminated... ', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4499, 109624, 'So it will be.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4499, 109625, 'However, you must not get mixed up with the Council - too obvious a presence raises questions I cannot afford to answer.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4499, 109626, 'I can do subtle.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4499, 109627, 'Just kill U''lien and find out if he knew more of Ra''s plans for this world. We must leave the Council to their own fate. ', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4500, 109628, 'In all my years, I have never seen devices of Crystal technology like these before... ', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4500, 109629, 'What about the map?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4500, 109630, 'It is not a map, but rather a logistics document. It shows equipment and personnel movements... If I did not know better, I would say they are building something.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4500, 109631, 'Military technology?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4500, 109632, 'I cannot say. It is a mystery. ', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4501, 80084, 'Talk to Blackstock.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4502, 80085, 'Lethander and Nerus seem to have a connection of some kind... My sources have them meeting often. I want you to find out more. Follow Lethander and see what he is up to... Report to Blackstock afterward. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4513, 80132, 'Get information about NID operatives on Lucia by helping Vala.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97538, 'A little birdie was whipsering in my ear the other day... He had a very interesting story. Apparently there are some people - whose whereabouts I know - who do not like Op-CORE. ', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97539, 'Who are they, Vala?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97540, 'Have you ever heard of the NID?', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97541, 'Here, on Lucia?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97542, 'Well, I cannot confirm it... Not yet.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97543, 'You need something from me first.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97544, 'Good, you know how to play the game properly... Specifically I need a subspace decryption device... I had one - once - but I lost it. I have heard that there may be another in Arlos'' Junkyard... ', 156, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97545, 'And if I get it for you?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4514, 97546, 'You get some sugar.', 156, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4515, 109672, '(You hand over the Crystal Tech device recovered from U''lien to Nerus.)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4515, 109673, 'This is what Baal was so interested in?', 943, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4515, 109674, 'Yes. What does it do?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4515, 109675, '(Nerus fiddles with the machine then casts it aside.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4515, 109676, 'You broke it...', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4515, 109677, 'You cannot prove that. ', 943, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4516, 109796, 'The Map points to a section of the greater city on Dakara, resettled since the rebellion.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4516, 109797, 'Who lives there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4516, 109798, 'The Ruk''yal clan was settled there recently by the Council.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4516, 109799, 'The Ruk''yal have gone over to Ra, they''ve helped the invasion.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4516, 109800, 'This was Ra''s plan from the start. Since he does not pursue the SuperWeapon, he has come to Dakara for this construction. ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4517, 112344, '<Input text here.>', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4550, 80415, 'The device seems to suddenly come to life. Operation seems fairly straightforward.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98932, 'No, Lord Ba''al.', 2546, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4518, 117510, 'Well aren''t you adorable... This is just what I needed. Well, more accurately, it''s what my client needed. Do you know how much one of these brings on the open market?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4518, 117511, 'The NID Vala, where are they?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4518, 117512, 'There are three of them... They''re in the Western Crevice, looking for hired help... Be careful. They look rather serious. ', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4519, 90294, 'Are you here for the job?', 2277, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4519, 90295, 'Who''s the target?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4519, 90296, 'Not so fast... We don''t just hire any yahoo off the street. ', 2277, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4520, 117554, 'Fair enough... We''re hunting earth humans - specifically members of a group called Op-CORE. They''re skilled, and they''re dangerous. ', 2277, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4520, 117555, 'You have no idea. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4521, 80150, 'UNSUED DIALOGUE', 2277, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4522, 80157, 'Bounties... I knew they would come after us, but this is pathetic. The situation at home must be bad because these three were green... The NID I know would never have resorted to local help. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4522, 80158, 'There''s likely to be more.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4522, 80159, 'Yes. And if you find them... Don''t be nice. ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4523, 112343, 'Indeed, on Harris'' corpse you find some security codes. It looks like there are two Security Interlocks you''ll need to disable - starting with the West access point.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4524, 111207, 'This is the same device Burtonol was trying to put on Dakara. Some sort of transport portal augmented by Ra''s Crystal Technology. It appears dormant, and you begin to work making sure it stays that way. Permanently.', 467, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4525, 80172, 'UNUSED DIALOGUE', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4526, 80171, 'UNUSED DIALOGUE', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4527, 80170, 'UNUSED DIALOGUE', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4528, 80168, 'UNUSED DIALOGUE', 2278, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4529, 80166, 'UNUSED DIALOGUE', 2278, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4530, 80164, 'UNUSED DIALOGUE', 2278, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4531, 80163, 'UNUSED DIALOGUE', 2279, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4532, 80162, 'UNUSED DIALOGUE', 2279, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4533, 80160, 'UNUSED DIALOGUE', 2279, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4535, 79974, 'You were the one who needed the symbiote, yes?', 470, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4535, 79975, 'Right.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4535, 79976, 'Be very careful with this. It can infect you very quickly if you are careless.', 470, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4535, 79977, 'It''s never leaving the jar.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4536, 79978, 'Excellent work... Was securing the sample tough?', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4536, 79979, 'It was work...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4536, 79980, 'You''re certain this is one of Anat''s symbiotes?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4536, 79981, 'I got it through Lethander.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4536, 79982, 'So we take it with a grain of salt. Still, he has no love for Anat so... Maybe he came through afterall.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4537, 94403, 'Find and meet with Lethander.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4538, 94413, 'I''ve heard some rather disturbing news...', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4538, 94414, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4538, 94415, 'There are rumors that the NID have found their way here. I need you to find Lethander - apparently he knows something. Find him and see if you can get to the bottom of this...', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4539, 90332, 'Have I seen Lethander? Even if I had, why would I tell you, human?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4540, 80191, 'I think he was heading to the Storage Area... You may be able to meet him there. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4541, 94436, 'You saved my life... You are starting to become quite useful... ', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4541, 94437, 'Those were NID?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4541, 94438, 'Yes, and they claim they have more in the Marketplace - lying in wait for your compatriots. Move quickly, there isn''t much time. ', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4542, 94442, 'Excellent work... I will inform the Colonel... There is one question unanswered, however... How did they get here in the first place. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4542, 94443, 'Do you think Lethander knows?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4542, 94444, 'He may be worth asking.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4543, 70472, 'Eliminate a witness to Rohurk''s Praxis dealings and pin the blame on Ra''s invasion', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110036, 'My involvement with the Praxis has caused another snag. One you must rectify quickly.', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110037, 'What happened?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110038, 'I did not know until just now that a witness to my rendezvous with Moh''katan survives. Her name is Saun''ti, of the Hak''tyl. She has said nothing yet, but she threatens...', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110039, 'Why has she kept quiet?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110040, 'She loves me, but I do not share her adoration. When she discovers that I cannot return her affection she will reveal the truth to A''lem and the Council. ', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110041, 'Can we convince her to stay silent?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110042, 'You do not know the Hak''tyl. My perceived betrayal is an insult to her honor... To a Hak''tyl this can only be avenged through blood. ', 768, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110043, 'Where is she?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110044, 'She is with the rest of the Hak''tyl on the outer ring of the city. The area is overrun by Ra''s forces. No one will notice if she dies in the chaos out there, especially if it looks like Ra''s doing.', 768, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110045, 'This is dirty business. You will owe me, Rohurk.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4544, 110046, 'Indeed.', 768, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4545, 110051, 'Now there is no one to impeach me before the Council. Moh''katan''s word will spread among the less committed Jaffa, and your Praxis will grow. You should be proud.', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4545, 110052, 'So you say.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4546, 96831, 'You save me... And you kill Romney. I appreciate.', 1114, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4546, 96832, 'You must get to the Communications Room, immediately.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4546, 96833, 'Why I go there?', 1114, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4546, 96834, 'Capt. Copplemann needs you to open the communciation channels so that she can coordinate the escape.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4546, 96835, 'Copplemann... I will do this - but you tell her she owe me!', 1114, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4547, 80408, 'Disable the Replicator Tech.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4548, 117574, 'The Repli-tech technology we recovered on Hebridan is dangerous... During the move through the Burtonol facility we found some of Devlin''s equipment - including a device we think might be a kill switch. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4548, 117575, 'It can disable all of it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4548, 117576, 'Within a radius... We think. Nerus and I can''t manage to hack this but you seem to have great skills that way... If you can get it to work, take it to the Storage Area and disable the Replitech crates that are there... ', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4548, 117577, 'Are we destroying all of it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4548, 117578, 'We are destroying everything Nerus isn''t directly using... We''re keeping his small cache for research purposes. The rest goes because it is already showing signs of trouble.', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4551, 96005, 'Hacking this might be tough... You begin by pulling off the thin metal covering and exposing the mechanism underneath.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4552, 80419, 'Nice work... That device is probably the best evidence we need about the Replicator Technology.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4552, 80420, 'What do you mean?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4552, 80421, 'When you build in a remote kill switch into every piece of a product, you know you are working on something very, very dangerous. ', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4553, 70652, 'Entice some of the neutral Jaffa clans on Dakara to join Moh''katan', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110071, 'Your presence here has given me an idea.', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110072, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110073, 'The reason I am here and not by Moh''katan''s side is that she has me acting as her eyes and ears amongst the Jaffa who pay attention to the Council. In secret, I am also her voice of persuasion.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110074, 'She never told me this.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110075, 'An oversight. The chaos on Dakara is a bitter lesson about the folly of the Council and their pet A''lem. In contrast the radiant Moh''katan sends you, and suddenly our fortunes were reversed.', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110076, 'And?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110077, 'There are many who could be pursuaded by this, but they have heard me talk already. A strong, fresh voice such as yours may finally convince them that the Council is a fraud. ', 768, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110078, 'I am willing.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4554, 110079, 'Good. Nogata is of the Jade Legion, he was one of those who once served Lord Yu, before his death. El''can served under Camulus, and Fru''auc - I believe her father was Prime to Cronus before his demise. Each leads a tribe of many warriors. I will give you directions to their posts.', 768, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4555, 110106, 'Nogata and El''can send their regards. I could not ask for a better ambassador than you. I believe both are considering a move to the Praxis.', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4555, 110107, 'Fru''auc was a less successful discussion.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4555, 110108, 'Her case was an oversight on my part. You have my apologies... We Jaffa have long memories.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4556, 110080, 'It is true what you say. A''lem is a fool, and the Council weak and distracted. Moh''katan offers a compelling alternative.', 2285, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4556, 110081, 'She will embrace you and your tribe. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4556, 110082, 'With respect, I will not throw my people in immediately. But I will think further on it. Assuming we survive today, I will approach Rohurk with a decision.', 2285, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4557, 110101, 'Your bravery is impressive, <<playername>>. You come through war and destruction to deliver hope. And not the frail mewling hope of the Council.', 2286, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4557, 110102, 'Moh''katan offers you a future which befits a warrior.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4557, 110103, 'As it should be. May we meet again on the battlefield someday.', 2286, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4558, 110832, 'The Praxis sounds like a powerful banner for the Jaffa. I wonder though, how I can trust a fraternity which includes the Goa''uld.', 2287, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4558, 110833, 'Surely Rohurk has told you of the great Moh''katan''s involvement.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4558, 110834, 'No. He did not. Although I am grateful to you enlightening me.', 2287, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4558, 110835, 'You are welcome.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4558, 110836, 'You misunderstand, pig. In the days of the Goa''uld, Moh''katan led an army. A very powerful army. One which wiped out my family. ', 2287, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4558, 110837, 'I did not know that.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4558, 110838, 'You are her surrogate, and as such you will pay her debts.', 2287, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4559, 80279, 'Take the Replitech Armor Prototype to Laro.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4560, 80435, 'So, remember that Replicator Technology Copplemann had you zap? That wasn''t all of it.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4560, 80436, 'There is more?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4560, 80437, 'We secretly saved a sample - that little morsel stays between us. The issue is this - Copplemann and her people are at a manufacturing dead end. We don''t have the hardware to identify exactly how Burtonol managed to create the blocks.', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4560, 80438, 'But Laro does.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4560, 80439, 'Exactly. Take the sample to Laro and get it to evaluate what we''ve got. It''s possible Laro may be able to help increase the stability and power of the tech. ', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4561, 80285, 'Welcome Primitive Gate Traveler. How may I assist you?', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4561, 80286, 'I need you to have a look at something...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4561, 80287, 'You wish for me to do a material scan? Please place the object inside the Scanning Dome.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4562, 96225, 'You try to place the armor awkwardly onto the machine... It''s not designed for something so bulky.', 2288, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4563, 80289, 'The scan finally runs. The armor is beamed off of the scanner bed - it''s gone. ', 2288, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4564, 80290, 'I have completed the analysis of Object 43C32. This object is viral and is unsafe for one of your intellectual capacity to handle. The object has been disposed of. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4564, 80291, 'You just took it from me?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4564, 80292, 'Yes. It was for your own good. Keron-based technologies are beyond your understanding. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4565, 77777, 'Return to Dakara and assist the plot to take over the world from A''lem', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110139, 'The political situation on Dakara has deteriorated further. A''lem - the neophyte commander - has decided to play at dictator. She has dissolved the Free Jaffa Council and seated herself as leader of all Free Jaffa.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110140, 'The Free Jaffa will never stand for that...', 942, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110141, 'They are resisting, but A''lem seems to have learned something about power. She is executing all of the traitors who backed Ra''s invasion... Conveniently labeling all her political foes as traitors.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110142, 'Impressive... This A''lem must not be underestimated. ', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110143, 'Given the fractured nature of the Free Jaffa alliance on Dakara, this feels to me like an opportunity. If we can help push A''lem out we can create a void...', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110144, 'And I can bring many, many Jaffa into the Praxis fold. Rohurk had gathered sufficient members for a new Council, one that understands and embraces the Loyalist Jaffa role within the Praxis. But he has not completed the task.', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110145, 'Rohurk is loyal to you?', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110146, 'Devoted. ', 945, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110147, 'I see... Very clearly...', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110148, '<<Playername>>, you must return to Dakara and make contact with Rohurk... I have been unable to do so...', 945, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110149, 'Perhaps A''lem got to your very devoted ally?', 944, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4566, 110150, 'We shall see.', 945, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4567, 110152, 'You check out Rohurk''s belongings. He was clearly energized by his recent contact with Moh''katan. Recently he was engaged in diplomatic efforts with several Jaffa, including Nogata and El''can.', 2290, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4625, 62139, 'Hello, you...', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4568, 77812, 'Head to where Rohurk''s clandestine meeting was supposed to take place in search of him', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4569, 110153, 'Based on these communications, Rohurk and other Praxis-friendly Jaffa were to meet in a nearby location to finalize their plans. You resolve to head there and investigate.', 2290, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4570, 110161, 'I did not expect to see you, <<player name>>... Moh''katan has not abandoned me after all.', 2294, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4570, 110162, 'What happened?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4570, 110163, 'A''lem has gone mad. Jaffa from her tribe came and they started firing without warning. Nogata and El''can are dead... I saw them fall. The others fled.', 2294, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4570, 110164, 'A''lem found out about Moh''katan?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4570, 110165, 'A''lem knows nothing of that. This is systemic. Her death squads have been attacking groups at random, crying "traitor" as they kill shocked villages. Innocent Jaffa have fallen... ', 2294, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4570, 110166, 'What about the Free Jaffa Council?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4570, 110167, 'Many have fled. Others have been killed. A''lem claims she was the one who stopped Ra''s advance and uses this to confuse leaders - then she strikes while they are unprepared. She has no honor.', 2294, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4571, 80511, 'Collect letters on Harset and find someone on Beta Site to deliver them to Earth.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4572, 80512, 'Beta Site is an opportunity for us - in many ways. I want you to do something special for your fellow Op-CORE troopers - get letters from them down to earth. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4572, 80513, 'Should I go through the gate?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4572, 80514, 'No... We will be working with some SGU personnel down there in a joint operation to remove the Straegis. Collect some letters from our people in Harset and then get someone down there to take them through to earth. ', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4572, 80515, 'One of them might take our letters through?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4572, 80516, 'We''re confident you can find someone willing - and if not, the troops still get the boost of having sent the letter anyway. They''ll never know it didn''t make it home. ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4573, 77846, 'Convince the Jaffa leader Gerak to back a coup against A''lem''s regime', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4574, 80517, 'Thanks for doing this... It will make my mom''s year.', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110176, 'Much of our support in a fight against A''lem lies dead around our feet. But there is still another option. Gerak.', 2294, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110177, 'Gerak?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110178, 'He is a junior member of the Council, assistant to the priest Hubrok. They are of the same blood, but not of the same mind. Gerak is more concerned with power and justice than platitudes. He might listen to reason. ', 2294, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110179, 'Why don''t we just remove A''lem?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110180, 'You are confident... Of that there is no doubt. Removing A''lem will simply cut the head off the wrigging snake. Whose head will replace hers?', 2294, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110181, 'Gerak...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110182, 'We see the same vision... I heard he was fleeing the planet... You must move quickly.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110183, 'I do not have that kind of authority...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4575, 110184, 'Pretend you do. We need him. Now go!', 2294, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4576, 80518, 'I want you to deliver that letter we found on Frost in the Castle. His wife deserves it. ', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4576, 80519, 'What about your family?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4576, 80520, 'I don''t have family, soldier. I just have the corps. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4577, 110288, 'I do not recognize you...', 2295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4577, 110289, 'I was sent by Rohurk. We have something to offer you...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4577, 110290, 'Rohurk? I am certain this will be amusing...', 2295, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4578, 80521, 'I have two - one of them is from Dawson to his kid brother - I hope that is okay?', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4578, 80522, 'I''ll get it through. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4579, 80523, 'I''ve got the enlisted bundle here... Lots of letters - you''re sure you can find someone to do this for us?', 2289, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4579, 80524, 'I''m going to try.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4580, 80525, 'I''d do it in a second but... This whole operation - my connecting with you guys - has made me persona non grata on earth... I''m never going back. ', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4580, 80526, 'Maybe you want to send something through?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4580, 80527, 'I hadn''t thought of that... Give me just a sec. ', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4581, 80528, 'There''s no way I can do that... It''s a court martial offense.', 1014, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4582, 80529, 'You want me to take mail through? Seriously?', 1010, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4582, 80530, 'It would mean a lot to my team...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4582, 80531, 'You''re here in this with me so... I owe you. I''ll get them through.', 1010, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4583, 80532, 'You did a nice job... There''s a lot of vindication in those letters. A lot of people are going to go to bed tonight knowing the truth about Op-CORE, not just the lies. ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4584, 114820, 'Seek information concerning Jaffa items sold in The Zone on Lucia.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4585, 114813, 'The developments on Dakara concern me. The Ruk''yal are not the only Jaffa clan likely to fall under Ra''s influence.', 771, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4585, 114814, 'He could generate an army that way very quickly.', 2410, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4585, 114815, 'If we can discover what Ra''s intentions are on Lucia it is possible that I could reach out to the clans supporting him...', 771, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4585, 114816, 'Weakening him from the inside.', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4585, 114817, 'Precisely.', 771, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4585, 114818, 'Jaffa artifacts and trinkets are sold in The Zone. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4585, 114819, 'Begin there. Our artifacts are often associated with our clan. You will find clues within those artifacts.', 771, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4586, 62519, 'Jaffa items? They roll off the shelves... I buy them from addicts who pawn them and then turn a idy profit by selling them to Hebridan''s elite... Jaffa trinkets are all the rage amongst the well-to-do this year.', 411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4586, 62520, 'You just sell them to tourists?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4586, 62521, 'No. I sell them to local thugs as well. Kassa dealers and hooligans love them - they see them as signs of potency. This is why you rarely see Opheltes'' Jaffazons walking alone - they would get attacked for their adronments.', 411, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4587, 91383, 'This icon is interesting... It is a sign of devotion amongst the Sons of Khepri.', 771, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4587, 91384, 'In Earth lore Khepri was the name of the dung-beetle god who pushed the sun, and later was a name for an aspect of Ra constituting the dawning sun. ', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4587, 91385, 'I remember them serving Ra in the past, but lately they had become more mercenary in their ways, disillusioned following his death.', 771, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4588, 91413, 'Deliver Bra''tac''s message to Kal''ju of the Sons of Khepri using the Tech Con Network.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6335, 120070, '<Input text here.>', 3579, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4589, 114894, 'If we could reach the Khepri we may be able to bring them to the Free Jaffa. I know their leader, Kal''ju. He is a noble warrior whose mind is sharp. He may be open to reason.', 771, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4589, 114895, 'How do we reach him?', 2410, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4589, 114896, 'You could try and use the Tech Con Network... With their mastery of media they are likely to be able to reach everywhere on the world. Anyone with a receiver will hear it. Once you access their network we can link to Bra''tac here...', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4589, 114897, 'I''ll have a message prepared.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4589, 114898, 'Make it happen, people. ', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4590, 62667, 'You want to send a signal over the Company Network? That''s highly against protocol... However. I know that they have been having problems with one of the repeaters in Red Collar territory and they''re having trouble getting Sanderson''s people out there to fix it. ', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4590, 62668, 'So if I fix it...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4590, 62669, 'I am certain they will allow you to broadcast. You can link to your message in the Main Office here in The Zone. I''ll get you clearance and, once you have activated the repeater, I will send the message...', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4591, 114900, 'The transmitter''s cables looks like they were shot as a stupid prank. Fixing them may not be very easy, but you begin the process - that message needs to get out.', 2297, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4592, 114905, 'The message was sent, but there has been no reply from Kal''ju. ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4592, 114906, 'If Kal’ju will not talk to an emissary from Bra’tac, then he is either not on the planet or uninterested in an alliance. ', 771, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4592, 114907, 'What do you suggest we do, Bra''tac?', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4592, 114908, 'We focus on more pressing needs.', 771, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4593, 114909, 'Bring closure to Bra''tac''s quest to convert Kal''ju.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4594, 114910, 'This must be the Kal''ju Bra''tac wanted to speak with. Perhaps an examination of his Data Tablet will reveal what happened with his clan. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4595, 77892, 'Remove Hubrok as an obstacle in the plan to overthrow A''lem', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4596, 62704, 'The tablet reveals a personal response from Kal''ju to Bra''tac''s message that he never sent. Bra''tac should see this...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4597, 110297, 'You will not find Hubrok an easy man to convince.', 2295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4597, 110298, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4597, 110299, 'He is a cohort of Bra''tac. Every other speech he gives is of the great power of democracy, the need for equality. Even now he seeks diplomatic solutions.', 2295, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4597, 110300, 'Is he open to the ideas of Moh''katan?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4597, 110301, 'I do not know their relationship. She is the daughter of Bra''tac, so they must know each other... Her betrayal of the Free Jaffa hurt her father. Many have not forgotten.', 2295, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4597, 110302, 'I should speak to her.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4597, 110303, 'Do so in secret. Her name remains cursed by many on this world.', 2295, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4598, 91328, 'I am unsure why he never sent this... Perhaps he feared a reply would inspire a search for MagmaLife. ', 771, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4598, 91329, 'What does he say?', 2568, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4598, 91330, 'He claims that the Sons of Khepri are allied behind Ra - whom he claims is a real God...', 771, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4598, 91331, 'Probably influenced by Ra''s resurrection...', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4598, 91332, 'He believes that Ra has demonstrated power beyond that of an ordinary Goa''uld. He demands that we surrender or be washed away in a great cleansing. ', 771, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4598, 91333, 'This message supports other intelligence regarding Ra''s intentions. He is ambitious, which makes him a threat. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4598, 91334, 'With clans like the Sons of Khepri behind him, his threat grows.', 771, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110524, 'Hubrok stands in the way... This does not surprise me... He has always been a champion for humanizing our Jaffa culture... ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110525, 'Why does Gerak not act?', 942, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110526, 'Gerak is as I have always known him to be; willing to accept power, but not all of the risks.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110527, 'Surely we can find a way to convince him... His people are desperate for order and A''lem prevents it...', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110528, 'I have known Hubrok my entire life. His wife watched me when my father went to battle, my mother tended his wounds, his children are like my brothers and sisters. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110529, 'Given your affection for him, what do you suggest we do to win him over?', 942, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110530, 'We kill him.', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110531, 'Interesting.', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4599, 110532, 'He will never betray my father, so we must remove him. <<Playername>>, you will see to it that A''lem takes the blame - arrange it so... The news will inflame Gerak''s clan into action. Gerak knew we would do this. He counts on it.', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4600, 110333, 'You have spoken with Moh''katan? I take it you wish to know where to find Hubrok?', 2295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4600, 110334, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4600, 110335, 'He begs the remaning Hak''tyl to stay, despite their vow to leave. You should find him within their settlement.', 2295, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4601, 110372, 'My men inform me A''lem has had Hubrok slain by her death squads. Is this true?', 2295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4601, 110373, 'I believe so.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4601, 110374, '... Then my men will take arms against her troops immediately. My tribe cannot stand for her tyranny any longer. ', 2295, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4601, 110375, 'I will inform Moh''katan.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4601, 110376, 'Do not let here go back on her word to me. If we take this world, I expect support.', 2295, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4601, 110377, 'Her word is unassailable.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4602, 110533, 'Has Gerak been convinced?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4602, 110534, 'Yes. His clan is moving on A''lem''s Jaffa as we speak.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4602, 110535, 'Then now is the time for the final measure. A''lem must die by our hand.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4602, 110536, 'Why not let Gerak do the deed?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4602, 110537, 'Because, if we wish for an influence on Dakara, we must be seen as instrumental. There is much that must be done to make Dakara safe for me again.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4603, 80670, 'Recover the Op-CORE files from the SGC network on Beta Site.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4604, 97548, 'While you''re down there, access their computers. I want you to try and get the official SGC data on our operation...', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4604, 97549, 'So, hack their network?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4604, 97550, 'Yeah. Get in and get the data - keep it between us. ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4605, 80674, 'Take it... Hopefully it will help you stay alive. ', 1014, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4606, 96381, 'You''re going in there? You''re crazy... Straegis are everywhere.', 1014, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4606, 96382, 'Can I use your access card?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4606, 96383, 'For the computers?', 1014, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4606, 96384, 'It might come in handy. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4606, 96385, 'I don''t know. ', 1014, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4607, 80665, 'Any trouble getting this?', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4607, 80666, 'No... I just had to hack a little.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4607, 80667, 'Did you see the data?', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4607, 80668, 'I didn''t have time.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4607, 80669, 'Right. It was pretty crazy down there... Nice work.', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4608, 96551, 'It''s difficult, but you may be able to reach deep into the most secret of the SGC files from here. It will take some elegant work...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4609, 80660, 'Unbelievable. I asked him about this directly and he lied to me without a flinch. Bastard.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4609, 80661, 'So we take him down?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4609, 80662, 'No. Not right away. We wait. For now you take him this data and you do not lead on that you know anything...', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4609, 80663, 'He won''t get away with this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4609, 80664, 'No. He won''t, but we also cannot act rashly. If he goes down there will be a power void. I want to make sure we take care of this the right way. ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4610, 77993, 'Remove A''lem from power', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4611, 110538, 'A''lem has taken over the Council Chambers. You should find her there. Do not simply kill her. Collect anything you can find that will support her corruption... ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4611, 110539, 'You sound concerned.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4611, 110540, 'If we are seen as murdering the leader of the Free Jaffa Nation, we will not be currying favor, we will be declaring war. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4611, 110541, 'I see.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4611, 110542, 'Handle this with great care. Much is at stake.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4612, 77995, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4613, 117605, 'Find the missing Op-CORE team.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4614, 110543, 'Ra is still on Dakara? You are certain of this?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4614, 110544, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4614, 110545, 'Then A''lem has betrayed everything the Jaffa people have held sacred and our plan becomes even more effective. Make her suffer.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4614, 110546, 'I will.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4614, 110547, 'When you kill her, take her head to Teal''c along with anything you can use to tie her to Ra. He is a noble Jaffa, loyal to Bra''tac. He will see value in our deed. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4615, 112584, 'You inspect the Burtonol Portal. It is an exact copy of those you destroyed in the Ruk''yal camp, and at MagmaLife. From the looks of it, this is the focal point of Ra''s attention. But A''lem is not here. She might be closer to the military headquarters section of the complex.', 2305, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4616, 110549, 'You examine the technology hooked into the Free Jaffa defense systems. The device jams sensors from detecting the signatures of Ra''s technology and teleportation effects, concealing his presence. You notice an incoming audio message, intended for A''lem. The message begins to play. ', 2306, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4616, 110550, 'Move your troops away from the Temple immediately. We have begun the final modifications to the device and the Free Jaffa cannot be allowed to interfere. You shall be honored for your long and faithful service to me.', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4616, 110551, 'You quickly download the message to your PDA.', 2306, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117614, 'You''re in the field right now, right?', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117615, 'Yeah, why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117616, 'There''s this Greenhouse here, I had heard about it from some SGC guys.', 404, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117617, 'SGC guys?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117618, 'Yeah - SGU - whatever. Weird uniforms, but they were earth guys. They were saying that they had heard about a Greenhouse. I sent a team out and... ', 404, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117619, 'And you haven''t heard back?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117620, 'Not yet. I''m sure they''re okay, but...', 404, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4617, 117621, 'I''ll check it out.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4618, 80695, 'This team was taken down - but it doesn''t look like an Android attack - these men were killed with standard Earth military slug weapons. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4619, 80702, 'You find my guys?', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4619, 80703, 'Who told you about the Greenhouse? ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4619, 80704, 'SGC guy - Vandermoot - he''s around here somewhere. What happened to my team?', 404, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4619, 80705, 'They''re dead. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4620, 78381, 'Stop Ra''s activation of the Ancient Superweapon within the Temple of Dakara', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4621, 110559, 'A''lem has always been working with Ra - whose master plan was to gain access to the Superweapon without the knowledge of the Free Jaffa. This will go a long way toward vindicating Moh''katan in the eyes of many Jaffa. ', 2306, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4621, 110560, 'You resolve to make your delivery to Teal''c and they making your way to the Superweapon to prevent Ra''s forces from activating it.', 2306, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4622, 79133, 'Atop the Temple of Dakara you witness the Superweapon come to life and emit a pulse of Ancient technological energy that washes over the planet''s surface. Ra must have activated the device already.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4622, 79134, 'A moment passes, and you realize that no harm has come to you or anyone else in sight. Perhaps there is still time to stop Ra and shut down the device.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4623, 110552, 'You complete a reset of the systems controls. With a earth-rumbling shudder, the stone console and the mountain itself come to a halt. You have stopped the Superweapon.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110613, 'We have managed to unravel Ra''s Dakara plot, but we are left without the prize. I have heard that the Free Jaffa are rallying behind the Council - pushing back toward human-style democracy. Dakara will not be under our thumb any time soon.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110614, 'What of Gerak?', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110615, 'Gerak is riding the wave of support over the tragic death of Hubrok into an increased standing. However, he does not have the courage to push for control. Rohurk will keep an eye on him, but the Free Jaffa Nation has survived Ra''s assault intact.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110616, 'What did Ra want with the SuperWeapon?', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110617, 'We don''t know. The Dakara Stargate was used to transmit the pulse to several systems before it was halted. Our early analysis ties the pulse to the portals manufactured by Burtonol...', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110618, 'We know the portals to be linked to the Reins of the Sun Chariot - a link to Ra''s unseen army. Perhaps he has activated thousands more Jaffa from stasis all at once... ', 942, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110619, 'You think this is possible?', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110620, 'I do. ', 942, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110621, 'He may have re-activated the Replicators... We do not know what he has done. Only that he has done something. We will continue to dig...', 968, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110622, 'Could he be using the portals to summon the Straegis?', 941, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110623, 'I had a feeling you would suggest this... Since we do not know what the Straegis are - or that they even exist - I would not count on their emergence being a part of Ra''s plan. ', 942, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110624, 'The Straegis are coming, Baal... ', 941, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110625, 'So you claim...', 942, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4624, 110626, 'Gentlemen... Please. We argue over nothing. ', 945, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4625, 62140, 'Why didn''t you tell me Sorpen was your boyfriend.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4625, 62141, 'FORMER boyfriend... I didn''t think it would matter. I hate him for his smouldering eyes, you hate him for his questionable morality. It''s a win-win. Has Burtonol exiled him?', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4625, 62142, 'He attacked me. He''s dead.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4625, 62143, 'Dead?', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4625, 62144, 'Dead. I''m sorry. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4626, 80847, 'Retrieve Loki''s research on Pocket Black Hole technology.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80850, 'Remember back when we met and I said I find a use for you later?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80851, 'This is later?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80852, 'You are heading to Yotunheim. Long ago I managed to access to Thor''s mind - Thor is the Asgard High Commander... It''s a long story, but while I was inside his brain I gained incredible insight.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80853, 'And?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80854, 'They have a technology called a pocket black hole. I do not know what it does, or how it works but... Pocket-Black-Hole. It simply trickles off the tongue.', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80855, 'You want me to recover it for you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80856, 'Recover it for the Praxis. I want to be the one who presents it to the council, but know that this technology benefits all of us.', 942, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80857, 'Why not use one of your people?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80858, 'There is an upheaval within our ranks. Lethander was traitorous and has been killed. We do not have operatives who can be trusted. You are Op-CORE: Honor bound. You can be trusted. ', 942, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80859, 'Yes, but can you?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4627, 80860, 'No, frankly... However, it is not in my best interests to go against you and your Colonel. I wish to present this technology to the council - that is all. You can even be there as I do it.', 942, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4628, 80861, 'UNUSED DIALOGUE', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4629, 80862, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4630, 97663, 'I will upload the lab location to your PDA device... I appreciate your mercy.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4631, 80866, 'You get inside the terminal - the lab is relatively easy to find once you''re in. Now you just have to get there.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4632, 80875, 'UNUSED DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4633, 80872, 'You''re inside Loki''s firewall. He has numerous projects, but you focus on the Black Hole. The data begins uploading... You hear the buzzing of drones...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4634, 96868, 'You met with success?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4634, 96869, 'I''m not sure. The download was interrupted...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4634, 96870, 'Hmmm. I''ll have Nerus take a look at this... Perhaps he can find something useful. Your effort - however fruitless - is appreciated.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4635, 80902, 'UNUSED DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4636, 80900, 'UNUSE DIALOGUE', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4637, 80898, 'UNUSED DIALOGUE', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4638, 80896, 'UNUSED DIALOGUE', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4639, 80894, 'The player informs Marsh that he/she had to remove the monitoring devices they placed earlier.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4640, 111197, 'Go to Beta Site and talk to Carter.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104987, 'You have no idea what is going on, do you?... This letter is a set of orders telling me to introduce you to the SGU. ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104988, 'The SGU?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104989, 'The Stargate Union. An alliance of humans, Asgard and the Free Jaffa nation. The alliance itself is a secret on your earth.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104990, 'The Omega Site itself is a semi-secret... The site is listed as a research outpost but as you can see - the scope of the project is much more than that. ', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104991, 'The pending closure of the SGC was of great concern to all three of our species. The Omega Site was conceived of by General Hammond as a way to maintain a working relationship...', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104992, 'Even if the SGC closes...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104993, 'Indeed. It was General Hammond who suggested the operation - a consolidation of resources. A clan of Free Jaffa who used to serve the Goa''uld System Lord Cronus offered this site. It was deemed ideal.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104994, 'The Gate Address was a secret kept from all but Cronus'' most trusted advisors. It helps keep everything under the radar... Currently the thing we''re focusing on is trying to find put what happened to Jack - General O''Neill. ', 431, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104995, 'Any progress?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104996, 'Nope. None. He''s disappeared. Even for Jack it''s getting a little ridiculous.', 431, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104997, 'Before his departure, General O''Neill warned of a coming threat. We need you - and others like you - to be very aware of potential anomalies you encounter. We have no details of the nature of this threat - only that it is coming. ', 777, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104998, 'It looks like General Hammond has officially assigned you to help close down Beta Site. Sam - Colonel Carter - is the Commanding Officer there, so you should probably go see her and let her know you know what we know. You know?', 431, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 104999, 'I know. ', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4641, 105000, 'Go. And keep your eyes peeled. We''ll see you again soon.', 431, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4642, 83051, 'UNUSED DIALOGUE', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4643, 105009, 'General Hammond told you about the SGU? ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4643, 105010, 'Yes. He sent me to Omega Site and Dr. Jackson filled me in.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4643, 105011, 'Any word about General O''Neill?', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4643, 105012, 'Nothing yet.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4643, 105013, 'Oh... Well... You''re here and we have a lot going on. We should get to it.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4644, 78478, 'Return to Dakara and meet with a representative from A''lem''s new regime', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112453, 'I have received an vital message from my fellow Free Jaffa Council members on Dakara. There is trouble... ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112454, 'What has happened?', 2410, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112455, 'A''lem has taken it upon herself to bolster the city''s strength. This is in case Ra renews his attack.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112456, 'This seems practical. Ra withdrew with significant firepower at his disposal. ', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112457, 'But, as could be predicted, A''lem has moved rashly. She has put full martial law into effect against the Council''s wishes. Entire families are being executed for treason, even when there is a question of guilt. We need to intervene.', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112458, 'I appreciate your desire to help your people, Bra''tac. However, I must remind you that our resources are limited...', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112459, 'The Asgard and the Tau''ri are unable or unwilling to provide troops to the SGU. Any armies that we can forge comes from the Free Jaffa Nation, let no one forget. ', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112460, 'You believe A''lem threatens the Free Jaffa Nation?', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112461, 'Her actions threaten it. She has turned democracy on Dakara into a dictatorship. However, I still believe she will listen to reason. ', 2323, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112462, 'Why?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112463, 'Because she still listens. Your actions in the defense of Dakara did not go unnoticed and A''lem has agreed to honor you with a commendation. My collegues agree that this could be an opportunity to talk some sense into her without worsening the situation.', 2323, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112464, 'You wish a diplomatic mission, Bra''tac?', 777, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112465, 'Yes. We will use this opportunity to get close to her.', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4645, 112466, 'Teal''c has returned to Dakara as well for a similar honor. <<Playername>>, meet him there. Hopefully A''lem will eventually see reason.', 2410, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4646, 112467, 'A''lem claims that she has too many demands on her time. She has requested you meet a Jaffa named Nomu in a nearby location for the commendation. He is merely a captain in her guard. I believe she wishes to get rid of us as soon as possible.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4646, 112468, 'Why is she so erratic?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4646, 112469, 'Bra''tac believes it to be the stress of the post. I am unconvinced there is not something else at work. Be wary. We have not been given permission to walk freely within the city.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4647, 112470, 'You are bold to come here willingly, <<player race>>. In a way I am sad to lose the pleasure of the hunt.', 2317, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4647, 112471, 'Pleasure of the hunt?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4647, 112472, 'I enjoy hunting traitors. A''lem has produced new evidence which shows that you were instrumental in aiding Ra in his failed bid for the city.', 2317, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4647, 112473, 'Insanity...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4647, 112474, 'The reward for betraying the Free Jaffa nation is death. Prepare for it.', 2317, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4648, 112476, 'The control technology explains much. It is possible we are all being deceived and someone has taken control of A''lem''s will.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4648, 112477, 'Could it be Ra?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4648, 112478, 'Perhaps. But were are hindered in correcting this. The Free Jaffa are unaware A''lem may be compromised and we have no proof. ', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4648, 112479, 'What can we do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4648, 112480, 'We must find a way to shut down this technology...', 2316, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4651, 117543, 'Who the hell are you?', 1010, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4651, 117544, 'Your savior. Tigges sent me. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4651, 117545, 'You''re Praxis?', 1010, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4651, 117546, 'Yes. Here to help. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4651, 117547, 'As long as you''re working against the Straegis, I don''t care who you are. You can tell Tigges that we''re ok here. We''ve got the area secure. You can go. ', 1010, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4651, 117548, 'Tigges wants to know about the Jaffa you tracked.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4651, 117549, 'They fell back to the Shoul''ja Outpost up ahead, but they''ve got serious muscle up there. They called their leader "Mashdra." Dunno more than that. ', 1010, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4652, 112997, 'Are you... Praxis? What are you doing here?', 1019, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4652, 112998, 'Helping you. What happened?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4652, 112999, 'Ra''s Jaffa stormed through here. This titan - I mean he must have been 10 feet tall - Op''raun... He had me pinned on the wall...', 1019, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4652, 113000, 'What was he after?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4652, 113001, 'He called it the "Four Pieces." I figured it must have been that case with the four artifacts we dug up, so it just sort of slipped out. Then I blacked out.', 1019, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4652, 113002, 'Where was this case stored?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4652, 113003, 'I''ll beam it to your PDA.', 1019, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4653, 83478, 'Download library data from the SGC Hub computer.', 1170, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4654, 118002, 'When General O''Neill left the SGC he came here. Security cameras show him rummaging through the science facility and the storage area looking at artifacts. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4654, 118003, 'Do we know what he was looking at?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4654, 118004, 'No. But that doesn''t mean we''re at a dead end... I need you to dowload the artifact data from the Computer Lab. We link to the SGC hub in there, it should have a full listing of everything we have here. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4654, 118005, 'Then I upload the data to Dr. Jackson?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4654, 118006, 'You''ll have to hand it to him personally. I''ve heard Woolsey is monitoring our file sharing. A large upload will draw attention. ', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4655, 103500, 'The SGC Hub is easy enough to get into - you''re authorized for access. However, getting to the artifact data is trickier...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4656, 83483, 'Colonel Carter told me about this... It''s all here?', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4656, 83484, 'Everything they had on Beta Site.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4656, 83485, 'Excellent. Hopefully it will give us some clue about Jack.', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4657, 83589, 'Upload pictures of the Four Pieces Artifacts to Jackson.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4658, 118010, 'I got word back from Daniel. He wants to see the "Four Pieces" artifact. Since we can''t take it to him, I need you to take pictures of it and digitally upload them to him at Omega Site.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4658, 118011, 'Something useful there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4658, 118012, 'I hope so... General O''Neill has been missing for a long time... ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4659, 103530, 'Connecting with Jackson on Omega Site won''t be easy. You''ll have to skirt around the firewall...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4660, 83594, 'Nice work... I''ll let you know if anything comes of it.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4661, 83843, 'Investigate the Ruins of Barak''Ka.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4662, 83844, 'Dr. Novak just mentioned something to me that I want you to look into. Apparently General O''Neill was investigating the Ruins of Barak''Ka. No one seems to know what he was looking for. I''d like you to go there and try and find out.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4663, 83845, 'On a crusty, crystallized rock you find a small post-it note attached with four simple words neatly written: "Take me somewhere safe". You pocket the note and pick up the fossilized rock. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4664, 83846, 'That''s the General''s handwriting. This rock must be important. We''ll need to get it analyzed.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4664, 83847, 'Should I take it to the Omega Site?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4664, 83848, 'No. Woolsey has started having all Gate Travel not directed to the SGC searched. You''ll never get an artifact off-world without his approval. Take the rock to him and convince him to get it analyzed. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4665, 78585, 'Investigate the Ruk''yal settlement for information regarding the remnants of Ra''s invasion', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4666, 112481, 'The Ruk''yal settlement was the site of Ra''s beachhead. That is where the technology left behind would be.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4666, 112482, 'I know the area.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4666, 112483, 'A''lem has been ruthless in punishing the Ruk''yal for their trangressions. Her agent Ocha''re has been checking the Ra technology that was left behind and will have what information there is.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4666, 112484, 'What if the Free Jaffa fight me?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4666, 112485, 'You must protect yourself. ', 2316, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4735, 118021, 'Encrytped. It''s an off-world transmission of some kind. Your job is to get the details.', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4667, 112494, 'We are left with a quandary - who is controlled by Ra and who acts on their own desires? If A''lem and Loth''ta were both in league with Ra, why bother with an execution? Yet the logs indicate she was involved... Is A''lem a traitor?', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4667, 112495, 'I am surprised Loth''ta is alive.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4667, 112496, 'His survival is fortunate. it provides a means to untangle this mystery. Loth''ta must know something.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4667, 112497, 'But his execution...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4667, 112498, 'We must get to him first.', 2316, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4668, 112491, 'You scan a log of the Ruk''yal''s communications. The last message appears to have been directly from Ra himself prior to the invasion.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4668, 112492, 'The hour draws near for our arrival. See to it that A''lem and Loth''ta recieve my final instructions. I am bringing more of the control devices to speed the conversion of the Council. Under no circumstances can our plan be discovered. Your lives depend on this secrecy.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4668, 112493, 'This ties A''lem directly to Ra. No one on the Free Jaffa Council or at SGU considered this possible... But this seems to be irrefutable.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4669, 112488, 'You examine this communication. It is orders from A''lem to Ocha''re concerning the Ruk''yal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4669, 112489, 'Sister Ocha''re, see that the remaining technology items are delivered to the Council chamber at once so that we can continue our studies. I do not want anything to sully the impending execution of the traitor Loth''ta. As for the rest of the Ruk''yal, I care not who kills them.', 2307, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4669, 112490, 'Clearly A''lem has tagged Loth''ta as a primary traitor.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4670, 103612, 'You''re bringing me rocks now? What do I need with rocks. ', 1300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4670, 103613, 'Colonel Carter asked that we have this analyzed.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4670, 103614, 'Colonel Carter is under the false assumption that I care about rocks. Convince me that I should waste manpower and resources analyzing space rocks.', 1300, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4671, 89949, 'Lord Olokun, it''s a pleasure to meet you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4671, 89950, '(You move in for a rather formal and stilted hug - an uncommon Goa''uld greeting. But you have to plant the detonator...)', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4672, 78713, 'Find out what Loth''ta knows about A''lem''s connection to Ra', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4673, 112502, 'Loth''ta will not be pleased to see you - he barely survived your last encounter... However, he is the only one who might be able to shed light on A''lem and her connection to Ra.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4673, 112503, 'Where are they holding him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4673, 112504, 'They converted the Council Library into a temporary holding cell for the Ruk''yal. Loth''ta will be there.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112514, 'You... Have you come to finish the job while I stand here unarmed?', 2335, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112515, 'Tell me about A''lem.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112516, 'A''lem? It is she who should be executed. That pig is the real traitor here.', 2335, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112517, 'You took the Council hostage.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112518, 'Not by my choice. She a device on me... On most of my clan as well. We heard Ra, but we could not ignore his commands. I alone manged to break free.', 2335, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112519, 'How?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112520, 'When you attacked, you killed my symbiote. As I lay dying... It was like the fabled Rite of Mal Sharran - where all illusions fade before death. When I awoke my head was clear and the voice of Ra was gone. They had brought me tretonin so I would survive the execution.', 2335, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112521, 'Why would Ra execute his slave?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4674, 112522, 'I am no longer a slave. I know the truth of Ra and A''lem. I am a threat to her hold over the people. Please, for the sake of all Jaffa, you must take me to Teal''c. The Council needs to know.', 2335, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4675, 112523, 'If A''lem has been Ra''s pawn then the invasion was never repulsed. We have been deceived and Ra holds Dakara. We must put an end to this.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4675, 112524, 'What of Loth''ta?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4675, 112525, 'I will take care of him. He claims to have proof of his story. I will confirm it. The Council must be informed.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4693, 78863, 'Bring the truth about A''lem to the dissolved Council', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4694, 112526, 'When A''lem dismissed the Council, they were escorted by her guards to one of the evacuated camps.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4694, 112527, 'Are they safe?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4694, 112528, 'I fear not. If A''lem realizes we have discovered Ra''s deception, she will move quickly. The Council must be told of her deception. If they spread the truth to the people, the Jaffa will turn on A''lem and we can recover this world.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4695, 84443, 'Gather information about Ra''s technology on Men''fa.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4696, 112560, 'What you say of A''lem confirms what many have suspected. Even as we were ushered off the council grounds she was acting strangely.', 2356, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4696, 112561, 'How so?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4696, 112562, 'She had taken much of the salvaged equipment Ra left behind, telling the council that she would examine it for our purposes. Obviously that was a lie as well.', 2356, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4696, 112563, 'What is next?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4696, 112564, 'We will spread the word. Many will not need much prompting to turn on A''lem. I have heard her forces have already murdered Brother Hubrok of the Council. She must be stopped.', 2356, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4697, 118016, 'Men''fa was one of Ra''s first strongholds. Historically it''s a fantastically important site. The Asgard aren''t especially interested in Goa''uld technology but we are. They gave us a special scanner - it can detect a special energy signature unique to Ra. ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4697, 118017, 'Ra''s tech is was that special?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4697, 118018, 'We didn''t know it either. We want to study it - I''d like to study it for purely cultural reasons. Take the scanner and collect what you can down there. Whatever you get will go a long way toward unlocking the mystery that was Ra. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4698, 112565, 'The Council forces will take time to ready for battle again. The troops are weary and must be reassembled. A''lem must not be allowed that time.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4698, 112566, 'Then we strike?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4698, 112567, 'There is no alternative.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4699, 84448, 'Unused dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4713, 84449, 'These are amazing... Fantastic work... I''ve never seen a technology like this. It''s like Goa''uld tech, but more advanced.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4714, 79074, 'Defeat A''lem and restore control of Dakara to the Free Jaffa', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4715, 112574, 'I will gather the Council''s forces and try to save as many of the controlled Defenders as possible. You must break through and kill A''lem.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4715, 112575, 'I will do it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4715, 112576, 'Speed is vital, <<playername>>. We have all underestimated her, and she has sent Dakara spinning...', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118043, 'I was given the identity of one of Opheltes'' primary slave taggers. ', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118044, 'Slave tagger?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4716, 112582, 'You inspect the Burtonol Portal. It is an exact copy of the one you destroyed at MagmaLife. From the looks of it, this is the focal point of Ra''s attention. But A''lem is not here. She might be closer to the military headquarters section of the complex.', 2305, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4717, 112591, 'You examine the technology hooked into the Free Jaffa defense systems. The device jams sensors from detecting the signatures of Ra''s technology and teleportation effects, concealing his presence. You notice an incoming audio message, intended for A''lem. The message begins to play. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4717, 112592, 'Move your troops away from the Temple immediately. We have begun the final modifications to the device and the Free Jaffa cannot be allowed to interfere. You shall be honored for your long and faithful service to me.', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4717, 112593, 'You quickly download the message to your PDA.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4718, 112597, 'Ra was wise to have taken the Superweapon in this way - the Free Jaffa would have destroyed the Temple had they believed it under threat.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4718, 112598, 'Can we destroy it now?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4718, 112599, 'A''lem has had ample opportunity to undo the self-destruction safeguards. We are left with no choice but to stop it at the source. ', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4719, 79111, 'Stop Ra from activating the Dakara Superweapon', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4720, 112600, 'The Superweapon lies within the great Temple of Dakara. Ra will not hold back now that his deceptions are crashing down. Make all haste.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4721, 112611, 'Atop the Temple of Dakara you witness the Superweapon come to life and emit a pulse of Ancient technological energy that washes over the planet''s surface. Ra must have activated the device already.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4721, 112612, 'A moment passes, and you realize that no harm has come to you or anyone else in sight. Perhaps there is still time to stop Ra and shut down the device.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4722, 110384, 'UNUSED DIALOG. Text is a result of a shared minigame and dialog was identical to PRX.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4723, 112614, 'The pulses from the weapon have stopped. Word is that Ra''s remaining agents have fled the planet. ', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4723, 112615, 'The Superweapon did fire...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4723, 112616, 'Indeed. The SGU will need to investigate the after-effects immediately. Please bring my regards to General Hammond and Master Bra''tac. Your work here will not be forgotten...', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112617, 'Excellent work on Dakara. Whatever Ra was up to, we put a crimp on it... ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112618, 'The Free Jaffa are grateful as well. A''lem''s betrayal was revealed none too soon.', 2323, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112619, 'What do we know about the Superweapon''s activation?', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112620, 'Deep space tracking indicates the Stargates were used to trasmit the signal to multiple worlds.', 2229, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112621, 'The pulse itself was unlike any previous use of the weapon. Those portals that were manufactured by Burtonol were specifically designed to receive the signal that was sent at Dakara. But the portals point to nothing...', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112622, 'The Superweapon was built by the Ancients to control life - to create or destroy. Since it sounds like no one died when this pulse was fired...', 2324, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112623, 'Something must have been created?', 2410, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112624, 'That makes the most sense...', 2324, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112625, 'Except that this pulse indicates that Ra was not using the weapon in any way we have seen before. ', 2568, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112626, 'This most disturbing. If Ra has found a new way to use the weapon, it indicates a technological advancement far beyond that of an ordinary Goa''uld System Lord. ', 2229, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4724, 112627, 'I think he''s already shown us he''s something very, very special.', 2410, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4725, 84541, 'Recover Furling Artifacts from Ihpet.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4726, 79354, 'Look into A''lem''s interest in the technology left behind at the Ruk''yal settlement', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4727, 110662, 'I had planned to deliver this as a gift to Moh''katan, but my injuries make a quick recovery unlikely...', 2294, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4727, 110663, 'What is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4727, 110664, 'Ra left behind technology when he abandoned the planet. A''lem has her minions salvaging it from the Ruk''yal settlement.', 2294, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4727, 110665, 'I will intervene.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4727, 110666, 'You must. Ocha''re, she is the one A''lem sent. She know the most precious items... Please deliver it to Moh''katan with my regards.', 2294, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4728, 84542, 'Ihpet gives us a chance to directly study Ra''s technology. Not even the Asgard truly understand the way he manipulated his technology.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4728, 84543, 'Ihpet may give us some insight.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4728, 84544, 'Exactly. When you get inside the main compound, collect anything of interest you can find. We''d like to take advantage of this find and do some extensive study... Even Heimdall seems excited about the prospect.', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4728, 84545, 'An "excited" Asgard?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4728, 84546, 'Well, as excited as those guys ever get. ', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4729, 110674, 'You examine this communication. It is orders from A''lem to Ocha''re concerning the Ruk''yal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4729, 110675, 'Sister Ocha''re, all items found are to be delivered to me personally. You may find more of the crystal pin devices within the rubble -- these are the highest priority...', 2307, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4729, 110676, 'I fear there may be more traitors in our midst -- let none damage or take what you find, no matter who they are, guard it with your life. Trust only in me.', 2307, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4730, 84547, 'Amazing crystal structures... Reminiscent of the traditional Goa''uld tech but so much more advanced.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4730, 84548, 'He was using this tech to do genetic modification. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4730, 84549, 'Typical of the Goa''uld. They built the Jaffa afterall... Ra may have been the original pioneer when it comes to their genetic engineering.', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4731, 104265, 'If you can decipher this cartouche, you may be able to unlock something valuable. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4732, 110682, 'Rohurk suffers?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4732, 110683, 'He will live...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4732, 110684, 'This looks like a device I had heard about. Ra had the Ruk''yal use it on the Council during his attack. It is designed to control minds - in this case it is tuned specifically to control the minds of Jaffa...', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4732, 110685, 'What would A''lem want with it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4732, 110686, 'Perhaps she realizes her grasp on power is shaky at best. I will personally oversee its study. You and Rohurk are to be commended.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4733, 96062, 'The emergency pumps activate and evacuate the gas through the ventilation system.', 2799, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4734, 84632, 'Investigate strange readings at the Omega Site Ruins.', 1331, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4735, 118019, 'We''re getting some strange signals eminating from the Human area here in Omega Site. May be in that area, or it could be coming from the Ruins beyond. I need you to look into it. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4735, 118020, 'What kind of signals?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4736, 84636, 'Whatever they were setting up must have been creating the strange signal. I''m concerned for several reasons, but mostly I want to know what they were doing...', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4736, 84637, 'They seemed to be an advance team of some kind.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4736, 84638, 'Advance of what? Take the equipment you dismantled to Heimdall. He may be able to figure out what it is supposed to do. How they got here is more my problem. ', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4737, 84639, 'Interesting... These parts were fully assembled?', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4737, 84640, 'Yes. It is a technology of some kind.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4737, 84641, 'Fascinating. I have always found Goa''uld and Jaffa technology interesting. Primitive, but interesting. I will attempt to identify the function of this technology. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4738, 79397, 'Release Gerak''s confederate Yat''yir from A''lem''s custody', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110694, 'If you wish this coup versus A''lem to go smoothly, I am in need of an additional favor.', 2295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110695, 'I am listening.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110696, 'My aid, Yat''yir, brought the attention of A''lem down on himself and is now imprisoned for insolence - for thirty nights.', 2295, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110697, 'Seems minor enough.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110698, 'When A''lem hears I have taken arms against her, Yat''yir will become a pawn. She attempt to use him to stop me. When that fails, he will die. If you free him, I will have additional arms to bear in the coming trial.', 2295, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110699, 'He is one warrior.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110700, 'He is an able lieutenant. In battle his skill and leadership is worth 100 staves. ', 2295, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110701, 'Where is he?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4739, 110702, 'A''lem has kept some important prisoners close to her chest. The Council Library has been converted for the purpose. You should find Yat''yir within.', 2295, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4740, 110703, 'Though I may be unarmed... You will not find me easy prey...', 2408, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4740, 110704, 'This is a rescue.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4740, 110705, 'Gerak sent you? Why? My sentence might have been harsh... But ultimately A''lem is just. She must be or she would not lead.', 2408, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4740, 110706, 'Gerak will explain. Move.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4741, 110710, 'I will keep Yat''yir out of sight until the time comes for our movement. You have further shown your commitment to the cause...', 2295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4741, 110711, 'Make sure you show yours.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4741, 110712, 'Do not doubt.', 2295, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4753, 65122, 'Free Airman Lance from the Jaffa cage.', 754, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96561, 'Uh, excuse me... You''re an Asgard, right?', 754, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96562, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96563, 'I''ve never met one of you guys before... Uh, could you help me out of this cage? I was knocked out during a firefight and ended up here.', 754, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96564, 'Airman Lance?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96565, 'How did you know that?', 754, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96566, 'Colonel Carter showed concern over your absence when it was discovered that the other members of your Security Detachment were killed. She will be most relieved to discover you are alive.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96567, 'They''re all dead?', 754, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4754, 96568, 'Unfortunately.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4755, 84835, 'Place sensor devices around the Omega Site and in the SGC.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4756, 118022, 'Ra''s Jaffa showing up here has me worried. While there is no direct reason for Ra to come after us, it''s clear that he has some interest in what we''re doing. Thor and his people aren''t worried about him but... ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4756, 118023, 'We are...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4756, 118024, 'Yes. And Bra''tac and Teal''c are especially agitated. Dr. Carter has been working on sensors that can detect Ra''s technology. I need you to set these up here on Omega Site and down at the SGC.', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4756, 118025, 'Mr. Woolsey has approved those?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4756, 118026, 'Mr. Woolsey is a headache. I''m trusting you to convince him about the value of these sensors.', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4757, 104526, 'These sensors are designed to detect the energy signature of Ra''s crystal tech. They''re a little complex to set up so - try and stay with me... ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4758, 104542, 'You there... What are you doing?', 1300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4758, 104543, 'General Hammond asked that I set these up in the Gateroom. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4758, 104544, 'Nothing gets set up in the Gateroom without my authority. Nothing. ', 1300, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4758, 104545, 'These sensors can keep you safe.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4758, 104546, 'I don''t care about safety - I care about protocol. So you''d better convince me that these devices are important enough to keep you off the disciplinary report. Because I''m about this close to throw the book at you. ', 1300, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4759, 104489, 'Fair enough. You can continue. But, remember, you are never to engage in this sort of thing again. I will not be so lenient next time... And tell that to Hammond. I am in command here. ', 1300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4763, 84853, 'Woolsey... He''s quite a piece of work... Nice job with the sensors. Carter and Heimdall can monitor them all from here. You''ve gone a long way toward making Omega Site safer. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4764, 102004, 'Disable the Jaffa stasis pods using a computer virus.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4765, 103676, 'So we got a compromise. Our leadership is nervous about letting you run around with these Jaffa everywhere, but I told them it looked like they were being released from stasis. ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4765, 103677, 'By Goa''uld loyal to Ra.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4765, 103678, 'I''m not positive about that. We might have just awakened all of them - even the Goa''uld - by accident... I don''t know for sure... But if you want to stay on this world we have to disable ALL the stasis pods...', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4765, 103679, 'All of them.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4765, 103680, 'They are all over the world - the place is crawling with them - and we have to take them all down at once.', 1959, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4765, 103681, 'How do we do that?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4765, 103682, 'Colonel Carter has provided us with a computer virus that will disable their wakeup sequence. You have upload it into the stasis control modules. Since they''re networked, one hit should buzz the whole system.', 1959, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4766, 102020, 'Well I was skeptical about the whole virus thing but it looks like it worked. It''ll take them awhile to figure out what''s going wrong. Too bad it is only temporary.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4766, 102021, 'Temporary?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4766, 102022, 'Yeah. The virus just whacked the system. As long as its disabled I call that a win. The Jaffa themselves will probably help out by halting the awakening until they figure out what''s wrong. ', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4766, 102023, 'So this is not permanent?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4766, 102024, 'Nope. But it will do for now. If we need something more permanent in the future, we''ll deal with it then.', 1959, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4767, 64197, 'Well, that went better than I thought it might...', 710, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4767, 64198, 'It seems to have phased out. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4767, 64199, 'Yeah. Whew... Hey, do you mind if we keep this between us? No need to worry Colonel Carter about a problem we already sovled, right?', 710, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4767, 64200, 'She has enough to worry about right now...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4767, 64201, 'Yes she does! Thank you, <<Playername>>, I owe you one!', 710, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4768, 103670, 'Disable the Jaffa stasis pods using a computer virus.', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4769, 103745, 'We''re not going anywhere. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4769, 103746, 'What about the waking Jaffa?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4769, 103747, 'I am going to quote the always lovely Queen Anat - " Finish the mission. Or die trying." She''s a peach. Colonel Marsh intervened and got us a little help... He had Nerus supply us with a computer virus that will wipe the minds of the Jaffa as they awaken.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4769, 103748, 'Wipe their minds?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4769, 103749, 'That''s Nerus for you. He''s sick. He actually giggled when he told me how it worked. Take the virus and install it in the computer that controls their stasis cycle.', 1885, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4770, 103769, 'Apparently that virus from Nerus actually worked. It sounded a little too weird to be practical to me... ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4770, 103770, 'The Jaffa will kill the ones that are affected.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4770, 103771, 'And they''ll stop the cycles when they discover the tampering. The solution is temporary but - hopefully - we won''t be here long enough to care. ', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4771, 103481, 'Detonate the crypt destroyer.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4772, 103468, 'We''ve received intelligence that Ra''s elite Jaffa are now awakening. That computer virus we set won''t stop the. We want you to try something simple - detonate a special bomb in one of the crypts.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4772, 103469, 'Just one?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4772, 103470, 'If it works I''ll have other people handle the other crypts. You get to be the guinea pig because, frankly, you''re the best we''ve got here... Plant the device, activate it and report back.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4773, 103485, 'I assume that everything worked?', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4773, 103486, 'It seemed to.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4773, 103487, 'Excellent. We''ll get teams out to all the crypts. Nice work.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4774, 103480, 'Detonate the crypt destroyer.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4775, 103474, 'The virus isn''t working anymore and one of my teams just gave me some truly harrowing news...', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4775, 103475, 'Which is?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4775, 103476, 'Ra''s elite Jaffa are awakening... We''ve got a plan to deal with it, and you get to be the guinea pig. We''ve got a special bomb that we can detonate within the crypts. We need you to try it out. ', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4775, 103477, 'Fine.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4775, 103478, 'Take it in, set it up and activate it, then report back to me.', 1885, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4776, 103491, 'Did it work?', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4776, 103492, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4776, 103493, 'Interesting... I wasn''t sure it would. Nice work. I''ll send teams out to the different crypts. ', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4777, 84933, 'Deliver food to hungry communities on Lucia.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4778, 118034, 'Your relationship with the officers of Tech Con Group could save lives.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4778, 118035, 'What do you mean?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4778, 118036, 'The people in the Lucian Slums are dying - of disease, starvation, inadequate medical supplies... They are destitute. You can help by convincing those insise Tech Con Group to share some of their considerable wealth. ', 398, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4778, 118037, 'I don''t know it they''d listen to me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4778, 118038, 'You must try. I know - firsthand, because I have seen it - that there is food in The Zone that they just store in facilities. It rots and they destroy it. Sewer Falls and the Slums could use that food - they need it. ', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4778, 118039, 'I''ll speak to Eamon about it. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4778, 118040, 'Please do. My people need their help... Whether they know it or not. ', 398, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4779, 104606, 'We certainly have food... But this doesn''t mean that I can just give it to you... ', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4779, 104607, 'Isn''t there some way? Some program?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4779, 104608, 'There is - I could write it off as a community expense but... We have a very extensive auditing process.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4780, 104586, 'You are a very persuasive speaker, $name$. Are you certain you do not have a future in politics?', 611, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4780, 104587, 'I''m certain. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4780, 104588, 'See Sanderson in his office - he has access to the food. I''ll call ahead and make sure he has the food ready.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4781, 84947, 'Ah, the good summaritan arrives to bring food to the needy. Here''s the food. I''ll give you the "almost rotten" crates. You get what you pay for, and you aren''t paying. ', 452, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4782, 84948, 'This food means much to us. Your kindness will not soon be forgotten. ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4783, 96364, 'Graham is dead, savagely assaulted. You collect his tags.', 1878, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4784, 96363, 'Robinson is clearly gone, his face almost unrecognizeable. You collect his tags.', 2405, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4785, 96362, 'Rozgonyi''s wounds are barely visible, and for a moment there''s a faint hope... But he is also gone. You collect his tags.', 2406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4786, 96365, 'Markham died with his eyes open. He looks scared and barely old enough to drive. You close his eyes and collect the tags.', 2407, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4787, 96677, 'the player also finds the crates of artifacts that were already catalogued and taken from the base - they have been smashed apart, obviously not containing the items Dakor is looking for.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4788, 107780, 'On close inspection the transmission was not sent from this terminal after all. It appears false routing information was added to disguise the origin, but you narrow it down to another terminal in something called the Research Facility.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4789, 107779, 'This terminal is also merely a redirector from another location... Someone has obviously gone to great lengths to hide the physical location of Dr. Rick Whelan... Just as you are about to give up, another transmission comes through...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4790, 84978, 'Shut down Ophelte''s Slave Hunter, Garf.', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4791, 107772, 'Hey there $name$, it''s Rick Whelan here.', 2424, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4791, 107773, 'Where are you?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4791, 107774, 'It''s complicated... Listen, I''m chasing down a really amazing opportunity. I connected with Laro - frigging amazing - and she was telling me about the Alteran Vessel Project. Have you heard of it?', 2424, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4791, 107775, 'No.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4791, 107776, 'It was an old plan designed to provide full access to Laro for other worlds - like a copy just for us... I don''t have a lot of time for the details but... You should talk to Laro about it. ', 2424, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4791, 107777, 'You wife is worried sick about you.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4791, 107778, 'She''ll be fine. Talk to Laro. ', 2424, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118041, 'I have some information you may want to take advantage of... If you have time. ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118042, 'I am listening.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118045, 'A traitorous slum dweller who tags fellow dwellers with an electronic marker. This gives Opheltes'' Jaffa an easy target. Their identity is always a tightly held secret, and even when identified I cannot get close to these people - they run from me.', 398, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118046, 'But they don''t know me. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118047, 'Exactly. This particular slaver is called Garf. He lives in Sewer Falls. If you were to tag him with one of their taggers...', 398, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118048, 'The slavers would collect him?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4792, 118049, 'They would. For the sake of secrecy they cannot identify the taggers. It would be a fitting end for Garf''s tagging career.', 398, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4793, 107769, 'The Alteran vessel project was conceived right before the migration to stasis... The design would allow access to the Alteran knowledge base without UICP interface. Rick Whelan volunteered to assist. While he is processing, I could use additional assistance.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4793, 107770, 'He is processing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4793, 107771, 'Correct. There is not much time for delay. Are you able to assist me?', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4794, 84988, 'UNUSED DIALOGUE', 2385, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4795, 104619, 'You find Garf''s tagging gun hidden amongst a variety of knick knacks and trinkets.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4796, 84990, 'You have saved many innocent people. It will not be forgotten. I will keep this tagger - if I discover the identity of any more taggers, they will themselves be tagged. ', 398, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4797, 79485, 'Disable the teleporters allowing Ra''s forces access directly into the Temple of Dakara', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4798, 110822, 'Analysis of Ra''s military setup reveals that his forces have managed to smuggle a set of teleportation rings into the Temple of Dakara. The equipment here masks their location.', 2306, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4798, 110823, 'With the teleporter in operation, Ra can infinitely reinforce his Jaffa. If the Temple is to be taken, the teleporter will need to be found and shut down. You resolve to do just that.', 2306, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4799, 110824, 'You are to be commended for teminating the ring transport. A''lem must have had it erected to allow Ra to enter the Temple in secrecy.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4799, 110825, 'Why would Ra need secrecy?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4799, 110826, 'Ra''s goal was always the Superweapon. If he had revealed it too soon, it is very likely someone - the Free Jaffa, the SGU or even our Praxis alliance - would have destroyed it.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4799, 110827, 'Preventing his access...', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4799, 110828, 'Ra orchestrated the entire invasion so that it cloaked his primary desire.', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4799, 110829, 'Brilliant.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4799, 110830, 'Ra can never be underestimated. To that Baal and I can attest.', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4800, 65132, 'Free Airman Lance from the Jaffa cage.', 754, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4801, 96569, 'Please tell me you are here to break me out...', 754, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4801, 96570, 'Lance? They''ve been looking for you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4801, 96571, 'I was praying they would... I got knocked cold in a firefight and woke up here. They''ve been grilling me for hours... ', 754, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4801, 96572, 'I''ll get you out..', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4801, 96573, 'You wouldn''t know what happened to my unit? The Security Detachment on Platform 2?', 754, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4801, 96574, 'I''m sorry...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4801, 96575, 'All of them? My God.', 754, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4802, 79493, 'Disable the teleporters allowing Ra''s forces access directly into the Temple of Dakara', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4803, 111179, 'Analysis of Ra''s military setup reveals that his forces have managed to smuggle a set of teleportation rings into the Temple of Dakara. The equipment here masks their location', 2306, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4803, 111180, 'With the teleporter in operation, Ra can infinitely reinforce his Jaffa. If the Temple is to be taken, the teleporter will need to be found and shut down. You resolve to do just that.', 2306, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4804, 111188, 'The ring transport was an effectove way for Ra to deceive the Free Jaffa. A''lem must have erected it to all him entry. ', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4804, 111189, 'Why would Ra want secrecy?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4804, 111190, 'If it were known that he sought the SuperWeapon, we would have destroyed it. The entire invasion was a feint.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4804, 111191, 'Just to get to the weapon?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4804, 111192, 'Indeed. Do not underestimate Ra. All who do, perish.', 2316, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4805, 79569, 'Destroy this copy of the Burtonol Portal', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4806, 110831, 'It would be preferable if you could bring this Portal back for study, but that does not look possible. You decide to destroy it, just like the one at MagmaLife on Lucia.', 2305, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4807, 110842, 'The three portals you''ve destroyed all appear to be identical, meaning that somewhere Ra has a facility pumping these things out.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4807, 110843, 'What do they do?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4807, 110844, 'No clue. They''re a technology, but they seem to be in a dormant state. The only record of activity was when the Reins of the Sun Chariot was applied to them. We will have to wait until they become operational to see what they do.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4808, 79570, 'Destroy this copy of the Burtonol Portal', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4809, 111166, 'It would be preferable if you could bring this Portal back for study, but that does not look possible. You decide to destroy it, just like the one at MagmaLife on Lucia.', 2305, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4810, 111172, 'First on Lucia, now Dakara. Burtonol must have made a number of these portals, and they''ve all been dormant.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4810, 111173, 'What are they?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4810, 111174, 'As near as we''ve been able to tell, they are equipped to recieve a specific energy signature.', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4810, 111175, 'A unique signature?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4810, 111176, 'The closest thing we''ve found are the emissions from the Reins of the Sun Chariot. But that isn''t an exact match. It may well be unique. We need more data.', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4811, 85005, 'UNUSED DIALOGUE', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4812, 85001, 'UNSUED DIALOGUE', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4813, 85003, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4814, 79599, 'Transcribe the details of the Superweapon''s configuration used by Ra', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4815, 85233, 'Find Dendra''s Mother.', 2387, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4816, 110945, 'It may be possible to deduce Ra''s plan from the Superweapon''s configuration settings he used. You resolve to transcribe them down precisely before they disappear from the system.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4817, 104666, 'I am Dendra. My mommy is lost. Can you help me?', 2387, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4817, 104667, 'Your mother is lost?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4817, 104668, 'Yes. She went away and I miss her. Can you please help me find her? I am scared without her. ', 2387, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4817, 104669, 'Do you know where she was?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4817, 104670, 'My uncle might know. He''s over there. His name is Krarb.', 2387, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4818, 110952, 'This information is quite strange. Quite the opposite from what I was expecting.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4818, 110953, 'How so?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4818, 110954, 'The device most recently destroyed the Replicators - removed life if you will. But the Ancients originally built the device to seed life throughout the galaxy.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4818, 110955, 'I don''t follow.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4818, 110956, 'Ra''s settings do neither. It''s pulsing to nothingness, but he has precisely defined where that nothing is... It''s almost as if he is communicating with something. I''ll have to look more into this. ', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85239, 'Dendra and her mother... Endless prattle.', 2389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85240, 'Is her mother missing?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85241, 'Yes, she is. And that kid will not shut up about it. ', 2389, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85242, 'Shouldn''t people be looking for her?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85243, 'I know where she is... If you''re so concerned I can tell you.', 2389, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85244, 'I''m concerned. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85245, 'My memory is limited... I''ll need some food. That will certainly jog my memory. ', 2389, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85246, 'You''re unbeliveable.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4819, 85247, 'You want to find her mother or what?', 2389, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4820, 104672, 'Her mother, Karist went to work for Netan... You can find her in the Green Boot area. God only knows what she is doing over there. ', 2389, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85249, 'Dendra sent you?', 2390, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85250, 'She''s your daughter, right?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85251, 'Yes.', 2390, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85252, 'I''ve come to take you home.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85253, 'I am home. This is my world. I don''t need the rest. ', 2390, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85254, 'Your daughter needs you.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85255, 'She''ll survive... I''m not leaving here. This is where I belong.', 2390, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85256, 'You''re an addict.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4821, 85257, 'I am happy. ', 2390, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4822, 104727, 'Did you find mommy?', 2387, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4822, 104728, 'Do you have someone else to live with here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4822, 104729, 'No. I live by myself. I''m eight.', 2387, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4822, 104730, 'You live by yourself?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4822, 104731, 'Yes. People give me food - neighbors - sometimes. Mostly I live alone. I like butterflies.', 2387, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4822, 104732, 'Come wth me, Dendra. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4823, 85264, 'You''re brining a child into a military facility?', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4823, 85265, 'She''s an oprhan. Her mother is a Kassa addict. She doesn''t have anyone... I couldn''t just let her die.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4823, 85266, 'No, we couldn''t do that... I''ll take her to Colonel Carter. We''ll figure something out.', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4823, 85267, 'Thank you General...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4823, 85268, 'You''re welcome - but no more stray kids. We don''t have the bandwidth to run a daycare center. ', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4824, 79600, 'Transcribe the details of the Superweapon''s configuration used by Ra', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4825, 110998, 'It may be possible to deduce Ra''s plan from the Superweapon''s configuration settings he used. You resolve to transcribe them down precisely before they disappear from the system.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4826, 110982, 'These settings are strange... They''re unlike anything I''ve seen. ', 2324, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4826, 110983, 'How so?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4826, 110984, 'The Ancients the SuperWeapon to "restore life to the galaxy" according to the legend. We fired the SuperWeapon to stop the Replicators - we took life away, in theory. ', 2324, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4826, 110985, 'And now?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4826, 110986, 'This doesn''t seem to point in either direction... It''s confusing. Ra has it aimed at something, but that something is... Nothingness. Blank space. But a very precise point in blank space. Fascinating.', 2324, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4827, 96681, 'You are able to cobble some old messages together. Whatever Dakor''s Jaffa were looking for here, wasn''t here. There are some implications in the mission report that SGC personnel may have been here in previous months and recovered it. ', 811, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4828, 64860, 'Dahaka''s double cross means that you''ll have to find another means of getting Branka off Tollana. Machra seems like a good place to start for alternative means of travel.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4829, 79601, 'Analyze the settings of the Superweapon''s configuration used by Ra', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4830, 110946, 'It may be possible to deduce Ra''s plan from the energy settings on the SuperWeapon. You resolve to record them as precisely as possible.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4831, 110987, 'These energy signatures... They have over a 90% conincidence rating with those emitted by the Reins. And what''s more... They match precisely the signal the Burtonol Portals are waiting for. No. I take that back. Not quite identically.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4831, 110988, 'Not quite?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4831, 110989, 'There''s an additional signal. It''s like the wave has an separate dimensional component. It''s unlike anything I''ve ever seen. It would help if we could find what emerges from the Portals now that they''re active. Without that I''m in the dark.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4832, 85295, 'Search Laro''s memory for evidence of O''Neill.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118050, 'How may I assist you, $name$?', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118051, 'Do you collect subspace transmissions?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118052, 'Yes. My sensors collect literally billions of subspace transmissions per sun cycle. This data is stored in Data Banks.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118053, 'Is it translated?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118054, 'Yes. I have a working command of over three hundred thousand language and symbol sets. ', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118055, 'Can I the search database for specific references? ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118056, 'The database is currently undergoing repairs. You can access it directly and perform seach functions on accessible data.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118057, 'Where is it?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4833, 118058, 'I will upload the location to your primitive mobile computing device.', 417, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4834, 105045, 'The database seems like it has been damaged somehow - almost the victim of an electronic attack or maybe a massive power surge. You begin to hack into the system and enter the key words: General. Jack. O''Neill. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4834, 105046, 'Perhaps Laro will be the key to finding the missing General?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4835, 85307, 'It''s amazing how much data is actually here. Apparently Laro has collected transmissions of all kinds - including several terrabytes of O''Neill Data. However, nothing that lists as recent seems to lead to anything useful.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4835, 85308, 'Still, this material - and this very database - could prove useful.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4836, 79602, 'Analyze the settings of the Superweapon''s configuration used by Ra', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4837, 110997, 'It may be possible to deduce Ra''s plan from the energy settings on the SuperWeapon. You resolve to record them as precisely as possible.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4838, 110960, 'The signal from the Superweapon was designed to be sent to those Portals Ra''s been building. The two are related somehow, and through the Reins as well.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4838, 110962, 'There''s a 90% pattern match. But there''s this additional signal information. I''ve never seen it before.', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4838, 110963, 'Didn''t you operate the Superweapon?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4838, 110964, 'Yes, but the controls for these settings were irrelevant to the task at hand. They didn''t appear to affect the signal at all.', 2568, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4838, 110965, 'So what is it?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4838, 110966, 'We need more data. I''m going to try to figure this out, but what we really need is whatever crawls out of those Portals.', 2568, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4839, 82762, 'Investigate the purpose of the Crystal Tech device found on A''lem''s defender Nomu', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4840, 111778, 'This small crystal object is no larger than a pin. It''s presence on Nomu''s body and the hostile reaction of A''lem''s forces may be connected. You resolve to identify the pin''s origin and purpose.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4841, 111784, 'Your analysis of the crystal pin indicates that it was forged using Ra''s crystal-based technology. The pins come from the device you recovered from the Hak''tyl attack on the Council the last time you were on Dakara...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4841, 111785, 'The pin delivers constant signals into the nervous system of the victim, controlling their thoughts and movements remotely. Nomu was mind-controlled.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4842, 120381, 'A clutch of these devices were left behind after Ra''s invasion. It may be that someone among the Jaffa learned of their purpose and now abuses it.', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4842, 120382, 'Any idea who?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4842, 120383, 'I fear it may A''lem herself... She has been most erratic. I will have these items dealt with properly.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4843, 85407, 'Help Lt. Grant find his missing wife.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4844, 118059, 'If you have a moment I need you to check in with Lt. Grant, the Quartermaster Assistant - he''s in the Storage Area.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4844, 118060, 'What''s wrong?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4844, 118061, 'Probably nothing. He''s a newlywed and he and his wife - Sara - are joined at the hip. He claims she has gone missing. I think he is paranoid but...', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4844, 118062, 'Better safe than sorry?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4844, 118063, 'Exactly. Check into it, would you?', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4845, 105396, 'This time they''re trying to infect our people with symbiotes... ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4845, 105397, 'If Ra knows we''re here, why hasn''t he just attacked us?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4845, 105398, 'He doesn''t have the resources... Yet. When he does, we''re in trouble.', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4846, 85330, 'Hey... Sorry to bother you but, Sara never goes anywhere without checking in. We''re like that. We do everything together and she missed lunch and she NEVER misses lunch and...', 2392, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4846, 85331, 'You''re worried.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4846, 85332, 'I''m worried. ', 2392, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4846, 85333, 'Where was she supposed to be?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4846, 85334, 'She was checking out the ruins near basecamp. She''s a workaholic - but she always calls me and she didn''t call and she never doesn''t call and...', 2392, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4846, 85335, 'I got it. I''ll check it out.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4847, 85336, 'UNUSED DIALOGUE', 2392, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4848, 105399, 'Thank you for killing them... They just came out of nowhere.', 2393, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4848, 105400, 'What did they want?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4848, 105401, 'I don''t even know. ', 2393, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4848, 105402, 'Weren''t you here for several hours?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4848, 105403, 'I guess so... I don''t remember much... My head...', 2393, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4848, 105404, 'I''ll get you back to your husband. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4848, 105405, 'Yes... My husband... We miss him. ', 2393, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105416, 'I owe you everything... Sara is my whole life... And you''re okay, aren''t you Sara?', 2392, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105417, 'I''m fine.', 2393, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105418, 'Sweetie... You okay?', 2392, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105419, 'I''m fine.', 2393, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105420, 'You don''t seem fine. You seem different somehow.', 2392, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105421, 'I''m the same as I always am. ', 2393, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105422, 'Really? Because you seem really different to me somehow. ', 2392, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105423, '(Suddenly, Sara''s eyes flash and her voice changes.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105424, 'Sara?', 2392, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4849, 105425, 'Goa''uld!', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4850, 82773, 'Check into A''lem''s past for confirmation of ties to Ra', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4851, 111637, 'I still have trouble believing that A''lem was a willing servant of Ra... ', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4851, 111638, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4851, 111639, 'She comes from a clan who supported the rebellion. A''lem herself was convinced the Goa''uld were our tormentors, not our Gods.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4851, 111640, 'Do you think there may have been others?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4851, 111641, 'It is possible that we may have more traitors to expose. The one who mentored her and convinced the Council to accept her was Kogran. He is on Dakara... But he is unlikely to be of help.', 2316, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4851, 111642, 'Why?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4851, 111643, 'He is her brother. Question him about A''lem, but do not press. He has taken her death badly and is quick tempered. I will consider some other means of getting to the truth while you approach him.', 2316, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4852, 111652, 'You seek information about my sister? She is dead. This is all you need to know.', 2431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4852, 111653, 'She worked with Ra.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4852, 111654, 'You slander the dead?', 2431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4852, 111655, 'I speak the truth.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4852, 111656, 'Why come here and say such things? Do you have no respect?', 2431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4852, 111657, 'We seek the truth about your tribe''s collusion with Ra, nothing more?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4852, 111658, 'You now accuse my PEOPLE? You will not see another sunrise, pig.', 2431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4853, 111754, 'Kogran was always unpredictable. That he met a violent end was fate. According to this letter, he tried to pull his sister back. He was always devoted to her...', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4853, 111755, 'Why did she turn?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4853, 111756, 'Raised all of our lives to believe the Goa''uld were Gods, many Jaffa have seen Ra''s return proves the old myths true... I fear A''lem gave into this.', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4853, 111757, 'Are there more like her?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4853, 111758, 'THis is likely. We must always remember to stay vigilant: Ra''s return has shaken the Jaffa Nation to its core. Kogran''s states that his tribal leaders remain loyal to us, which brings some comfort. ', 2316, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4854, 111684, 'You examine Kogran''s personal tablet which contains an unfinished letter, addressed to A''lem. It is a heartfelt screed as he attempts to talk his sister down from supporting Ra. You decide to return the letter to Teal''c.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4855, 85491, 'Collect data from the computers in the SGC.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6336, 120073, '<Input text here.>', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4856, 118070, 'You''re going to the SGC. If it is at all possible while you are there... ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4856, 118071, 'We want data from our computers.', 2568, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4856, 118072, 'All the data. Drives. Everything. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4856, 118073, 'Woolsey has terminated our network connection there. ', 2568, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4856, 118074, 'We''ve got a lot of stuff we need there. We don''t want you to put yourself in danger but...', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4856, 118075, 'Anything you can get us will help. A lot.', 2568, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4857, 105782, 'We really appreciate this... It''s amazing how much we rely on computers.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4857, 105783, 'Jack was downloading Furling data.', 2568, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4857, 105784, 'It makes sense. The Straegis are related to them and they must be what Jack was trying to warn us about. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4857, 105785, 'Do you think the Straegis got to him?', 2568, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4857, 105786, 'I don''t even want start with that... We don''t know what happened. Jack is out there, Sam. ', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4857, 105787, 'Yeah... Yeah, he is.', 2568, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4858, 105789, 'This archive seems to have been accessed by O''Neill. He seemed to download everything related to the Furling that the SGC had.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4859, 85473, 'Check the sensors on Omega Site that you placed earlier.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4860, 118064, 'Sara Grant''s infestation concerns me. It''s too simple. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4860, 118065, 'Yes. It would make sense that it was part of a larger operation.', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4860, 118066, 'Security teams report no disturbances.', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4860, 118067, 'Still, I want to be doubly sure. I need you to check the sensors you planted on Omega Site - use this laptop to run the diagnostic. ', 2410, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4860, 118068, 'What about the sensor at the SGC?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4860, 118069, 'We''re not welcome there. I think Woolsey may even be preparing court-martial papers for many of us... Just focus on Omega Site - that''s our home now. ', 2410, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4861, 105506, 'The diagnostic is a little tricky to get set up...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4862, 105511, 'The diagnostic is a little tricky to get set up...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4863, 105515, 'The sensor seems like it may have been tampered with... Fixing it may not be easy.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4864, 85483, 'Apparently the Jaffa''s visit from before was about more than infesting Sara Grant with a symbiote... I''m going to have to double security. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4864, 85484, 'Will that be enough?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4864, 85485, 'No. We''ll have to find a way to protect this city technologically. We''re wide open for an invasion - and his Straegis army is exactly the type of enemy we simply cannot handle. ', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4865, 96721, 'I''m getting the images now... The upload is a little glitchy. The text looks pretty faded, but I think I can make it out... ', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4866, 96892, 'I will patch into communication network. This keep Capt. Copplemann happy. While I do this you use terminal there.', 1113, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4866, 96893, 'Why?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4866, 96894, 'Security defenses are activated. Use terminal to find out why.', 1113, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114662, 'You will not be acting alone on Yotunheim. Ha''kur is one of my agents - but he has wormed his way into Ra''s trust. He is at Yotunheim as we speak. The Asgard did not seem to think the location of this base could be discovered. They were taken by completely by surprise.', 798, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114663, 'Does Ha''kur know where the Solocris is?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114664, 'Not as yet. He set up operations away from Ra''s main forces, but he is not free to move around the facility. You are to meet with Ha''kur and work with him to prevent Ra from taking possession of the Solocris.', 798, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114665, 'If the stories are true, this is a weapon even the Asgard are afraid to use. It may be volatile technology. Be mindful.', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114666, 'How will I find Ha''kur?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114667, 'He has an implant that emits low level radiation. I will give you a scanner that detects this emission. Once you meet with him, coordinate your efforts in the search.', 798, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114668, 'Ra must not be allowed to take the Solocris. If you need to destroy it, do it. Ra does not get that weapon. ', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114669, 'We want it to be recovered, Colonel...', 942, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114670, 'We don''t want Ra to get it. That''s first... ', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114671, 'Bring it back to us, $name$.', 944, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4867, 114672, 'If you can. ', 941, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4868, 114708, 'Ra is tearing Yotunheimn apart, but has not been able to find the Solocris. I cannot speak long as he demands constant updates, but I have discovered an Asgard security terminal that is not well protected. You may find information there.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4868, 114709, 'Do we have access?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4868, 114710, 'You will have to hack into their systems. If you cannot find the Solocris, make a record what tactical information you can. It may prove useful.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4869, 114739, 'The data you downloaded indicates that a Thor''s Hammer device is located within Yotunheim, though it was damaged in the initial attack. If that device is reactivated, any Goa''uld or Jaffa here will be neutralized.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4869, 114740, 'That may prevent Ra from acquiring the Solocris...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4869, 114741, 'Ra has other resources available to him - the Straegis quickly come to mind. But an active Thor''s Hammer will certainly hinder us. You must make sure this technology is disabled... Permanently.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4870, 114800, 'Ra has sent troops to investigate the vault... Typically this would not concern us, but the data you supplied indicates that the Asgard use this place to study ancient tech...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4870, 114801, 'The Solocris may be there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4870, 114802, 'While the Solocris was an Asgard invention, it is possible they have secured it there... These vaults have three sub-sections. You will need to check all three.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4870, 114803, 'How did Ra know about this vault?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4870, 114804, 'I do not know... However, his Jaffa are already on their way. Hurry...', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4871, 115216, 'We must change our approach - we must find a way to get to an Asgard whose memory may contain the Solocris. We do this quickly - with each hour the threat of Ra exposing my deception grows.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4871, 115217, 'Have you contacted the Asgard directly?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4871, 115218, 'Given the state of my body it would not be possible... But you? You do not bear the mark of Ra. Were there witnesses when you killed the prisoner?', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4871, 115219, 'Perhaps some Jaffa. No Asgard. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4871, 115220, 'Then approaching the Asgard is still possible...', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4871, 115221, 'We held a temporary alliance on Beta Site...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117124, 'Ra''s forces have downloaded several Asgard consciousnesses. They may be trying to glean technological secrets from them.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4871, 115222, 'If you can convince the Asgard that you are interested only in stopping Ra, they may ally with you again. I will upload the location of an area where you may contact one of them. Be careful, when armed they are formidable - despite their appearance. ', 2059, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4872, 115198, 'The Asgard do not reproduce biologically. They use cloning technology. Specifically, they implant something called a "consciousness hub" into the flesh of the clone body. Ra believes this hub stores additional information or memories for the Asgard to make use of.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4872, 115199, 'They store thier minds in computers?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4872, 115200, 'They store their consciousnesses - although we do not understand the technology. It appears that they upload data to this piece of gadgetry in their brains. We may be able to access this data and find the location of the Solocris.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4872, 115201, 'Can I take the hub from a corpse?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4872, 115202, 'No. When the Asgard die, the hub automatically transfers their data to a mass storage facility... You must disable this function. Ra''s torturers have developed a technology - which I have appropriated - that does this. Target an Asgard with the device, then kill them and remove the hub.', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4872, 115203, 'Any advice on where to do this?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4872, 115204, 'The Asgard are difficult to deal with when armed. I will upload where Ra keeps his prisoners and you can go there to take a hub from one that is unarmed. ', 2059, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4873, 116891, 'The Asgard communicator has proven useful. Apparently, Yotunheim has teleport logs - they use DNA and Consciousness Hub signatures to identify travellers between destinations. You may be able to track Loki in this way. Ra is intensifying his attacks, so be on your guard.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4873, 116892, 'Is he after anything specific?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4873, 116893, 'He vaguely speaks of traitors and incompetents... I think he grows weary of the search... When you reach a teleporter, hack into the log. It might give you some idea as to where Loki may be...', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4874, 115322, 'Ra''s interest in the singularity research is acute... There must be something there... Ra has a research team there as we speak. We have to know what they are after...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4874, 115323, 'I can consult the Asgard...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4874, 115324, 'Do that. In the meantime, I will continue to try and monitor Ra''s communications... And gain control of these headaches... ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4875, 115562, 'Ullr wants you to leave this area, the words "pocket black hole" ring in your ears... If you can fix this console you may be able to figure out what Loki was up to. ', 2086, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4876, 86187, 'Hack into Loki''s computer and determine his location.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115604, 'I have overheard something terrible... ', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115605, 'What is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115606, 'I cannot yet say... Look upon my back...', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115607, '(You look at his back and see a morass of freakish Crystal technology fusing directly into his flesh. Whatever Ra is doing to his Jaffa, it is grotesque. You notice a small electronic pulse flashing on one shard - directly at the base of his skull.)', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115608, 'Does one pulse?', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115609, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115610, 'You must remove it. And you must do it carefully... I do not wish to die.', 2059, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115611, 'This could kill you?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4877, 115612, 'Yes. Please be careful... But we have little time.', 2059, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4878, 115633, 'Loki''s position may be difficult to get to...The data indicated that the Asgard have a useful device - a security bypass. It may be a useful way to get around any defenses Loki has erected.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4878, 115634, 'Where can I get one?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4878, 115635, 'There is a weapons locker which has a supply... Move quickly, Ra is aware of everything we have done or said - he will be after Loki soon.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4878, 115636, 'What will you do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4878, 115637, 'I will find a disguise... I will beam you my location when I have something suitable... I will probably look quite different. Be careful - we have enraged Ra. When this happens, blood tends to spill. Find Loki!', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115659, 'Ra will never secure the Solocris... I have not even seen it myself.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115660, 'You have never seen it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115661, 'No. I have searched for it... I have spent months culling through memory databases searching for the information... I have come to believe that the Solocris is located in the Nox vault here on Yotunheim. Near the center of it.', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115662, 'In the open?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115663, 'The memories I have accessed indicate that the Nox assisted us by using their cloaking technology to hide the Solocris. There should be a disgiuised control panel there that you can use to alter the phase of the cloak, thus revealing the Solocris.', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115664, 'These memories you access, they are data?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115665, 'Yes. We store memories as data. Yotunheim contains many tightly-controlled Asgard secrets. These memories are stored here exclusively.', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115666, 'Anyone can access this data...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115667, 'You fear Ra may have done so? This is reasonable... We must hurry...', 2095, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115668, 'I will go. I will bring the Solocris back here.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4879, 115669, 'As you wish.', 2095, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4880, 115710, '$Name$, please be advised, we are going to destroy Yotunheim. ', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4880, 115711, 'Destroy it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4880, 115712, 'Yes. This facility is in danger of falling out of our control. In order to prevent the exposure of specific technologies, this station will be terminated.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4880, 115713, 'Can we have some time to evacuate our people?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4880, 115714, 'This is reasonable. I will extend the time until detonation. ', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4881, 116603, 'Ra was able to transfer the Solocris to another vessel. It happened before you destroyed the Tel''tac. ', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4881, 116604, 'How do you know this?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4881, 116605, 'I still have inroads to his communications... Recently there has been much discussion - he seems frustrated because the Solocris is not what he imagined it to be... He rants about you...', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4881, 116606, 'Me?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4881, 116607, 'Did you steal the Four Pieces from him?', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4881, 116608, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4881, 116609, 'Well, apparently the Solocris needs them to function... You must go report to Harset of our failure here. I will follow once I inform my other agents that it is time to leave... Good luck. You will need it. ', 2059, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4882, 116586, 'Scans indicate much activity near the loading area. They are moving material to a Tel''tac.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4882, 116587, 'The Solocris?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117125, 'Will that work?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4921, 85721, 'Collect Straegis Shards for the Furling.', 2441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4882, 116588, 'Quite possible. If Ra escapes with the Solocris it may have grave repercussions for the entire galaxy... I have placed some pocket black hole technology in a container for you to use...', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4882, 116589, 'How does it work?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4882, 116590, 'It does not work. When you activate it, the black hole will expand and consume a large chunk of space... You must take this with you and, assuming you cannot recover the Solocris, activate the black hole.', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4882, 116591, 'That could destroy Yotunheim.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4882, 116592, 'Yes. Hopefully this will not be required, but extreme measures are required in extreme circumstances. Ra must not possess the Solocris. Do what is needed. ', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4883, 116910, 'The Asgard are stubbornly refusing to die, but despite their technological advantage they are beginning to succumb. If the Asgard fail it will hamper our efforts considerably.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4883, 116911, 'We must help them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4883, 116912, 'Indeed. I have identified two targets of opportunity... First you must sabotage one of their weapons caches. ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4883, 116913, 'And the second.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4883, 116914, 'Ra''s most talented Lieutenant is a Jaffa called Lor''ka... It would do great damage to his organization if Lor''ka was no more. Make that happen. ', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4884, 116940, 'One of Ra''s Jaffa captured a device which we have not been able to decrypt... They gave it to me...', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4884, 116941, 'Now that we have an alliance with Ullr...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4884, 116942, 'Yes. It is likely that he can decrypt this... It may reveal information about the Solocris - information that would be invaluable. Regardless, it would be useful to know what they are hiding in here.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4885, 117003, 'We must take advantage of the access we have to the Asgard''s research center. They have been studying the Furling. It is quite possible that there is information there that may be useful in fighting the Straegis.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4885, 117004, 'Anything specific?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4885, 117005, 'Gather what you can in the Furling Vault and bring it to me here...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4886, 117033, 'Does Moh''katan not realize the position I am in? If Ra finds out I am working for Praxis, he will kill me slowly over days.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4886, 117034, 'She understands...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4886, 117035, 'They know about me. At least some of them do... The hiding in shadows! I am a warrior! I would rather face an army of millions alone than this.', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4886, 117036, 'Who knows? Specifically.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4886, 117037, 'Ti''moth, Zaren and Urlk - I spoke with them under the influence of drink. I do not know what was said... I fear they have suspicions. Zaren has often made me question his intentions...', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4886, 117038, 'Can we recruit them?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4886, 117039, 'Not without risk. If I am to remain in the Army of the Dawn, those three must die to assure that their suspicions are never raised to Ra himself. They must be eliminated.', 2059, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4887, 115806, 'Yotunheim has not answered our communiqués.', 2117, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4887, 115807, 'Could Ra have attacked already?', 2410, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4887, 115808, 'Possible, but not certain. ', 2117, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4887, 115809, 'We need to know if something has happened at Yotunheim.', 2410, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4887, 115810, 'Agreed. $name$, you have served us well on Agnos. Now you must go to Yotunheim and make contact with Ullr. He is the commander of that space station...', 2117, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4887, 115811, 'If Ra has attacked?', 3216, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4887, 115812, 'Then our situation grows more desperate than it already is.', 2117, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4888, 115830, 'The Asgard have set up a sort of guerilla resistance against Ra''s invasion force. Pockets of areas a already overrun. Information is spotty, but there may be some fighting nearby. Perhaps there you can get some information.', 2061, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4889, 115852, 'The situation here is unfavorable. Most of the station''s defense systems were disabled.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4889, 115853, 'Ra is using Jaffa... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4889, 115854, 'The Thor''s hammer was a viable option, but it is non-fucntional.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4889, 115855, 'Can I look at it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4889, 115856, 'Certainly. If it can be repaired it may greatly aid on our defense. ', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4890, 115863, 'UNUSED DIALOGUE', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4891, 115864, 'Station sensors are detecting significant Jaffa movement around one of our storage vaults.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4891, 115865, 'Is the Solocris there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4891, 115866, 'Unknown, but you must remember that there is far more of value on Yotunheim than just the Solocris. I require you to enter and destroy the vault and it''s contents.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4891, 115867, 'What if it is the Solocris?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4891, 115868, 'It is better destroyed than in the hands of Ra. The explosive I have provided you should be adequate.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4892, 115923, 'Eir left a vague report about some technology Igyn suspected Ra was seeking. The data was garbled. This was some time ago. She has not reported in.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4892, 115924, 'What was she protecting?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4892, 115925, 'Unknown. It is possible that it was the Solocris. Eir held a very high level of security access. ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4892, 115926, 'I will go find her.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4892, 115927, 'Use caution. Sensors indicate a signifcant Jaffa presence.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115943, 'I was assisting Igyn... We were working to prevent Ra from finding the Portable Singularity Apperatus.', 2130, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115944, 'Portable Singularity Apperatus?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115945, 'Loki referred to it as a Pocket Black Hole. ', 2130, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115946, 'That sounds...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115947, 'Terribly dangerous? It is. You must seek out Igyn and help... As quickly as possible. This technology is highly experimental. In the wrong hands it could be catastrophic. There is a problem, however...', 2130, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115948, 'Which is?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115949, 'I do not know where the object is... Igyn was going to inform me, but I was ambushed... You may have to parse through the transporter''s DNA records to determine what floor of the station he is on...', 2130, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115950, 'What about you?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4893, 115951, 'There is not time. Go!', 2130, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116275, 'Ra has compromised the integrity of the database. I am trying to isolate our stored Asgard consciousnesses before Ra deletes them in an effort to get to our technological data.', 2143, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116276, 'You have consciousnesses stored here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116277, 'Yes. Yotunheim''s primary function is to act as a penal storage area. The site preserves over 57,000 Asgard consciousnesses. These are all in jeopardy.', 2143, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116278, 'Prisoners?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4920, 85680, 'Well, I am both relieved and disappointed... Take the data you found on Vokos Primar to Dr. Jackson. You''ll make his year. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116279, 'Correct. I was forced to divide them up and save them all over this network to preserve them. If you can find a portable data storage unit you could download the consciousnesses and get them to safety.', 2143, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116280, 'Is there a unit nearby?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116281, 'This is a question best asked of yourself.', 2143, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116282, 'You don''t have eyes...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116283, 'I am inside a computer... There should be three consoles which each hold approximately 19,000 consciousnesses. You must upload the Asgard from each one. Once you have done that, you may delete the technical data Ra covets.', 2143, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116284, 'And afterward?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116285, 'Deliver them to Ullr. ', 2143, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116286, 'What about you?', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4894, 116287, 'One life does not exceed another in value. Deliver the receptacle to Ullr.', 2143, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4895, 116338, 'Igyn remains trapped within the closed network... ', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4895, 116339, 'I can try to get him out.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4895, 116340, 'You can upload his consciousness to this device - we use this for individual prisoner consciousness transfer because it enables them to communicate if needed. Find the terminal where he uploaded himself and you can download him directly from there.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4895, 116341, 'Do we have a location for his corpse?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4895, 116342, 'Yes. I will upload it to your PDA. ', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4896, 65738, 'Collect samples of plants from the Agnos Greenhouse.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4897, 116399, 'The Singularity may be useful for us... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4897, 116400, 'It seems very dangerous.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4897, 116401, 'You are quite correct, and the object it creates - the Portable Singularity Apperatus - is even more volatile. But a Portable Singularity Appareatus also has value in our circumstance, particularly as an instant self-destruct agent. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4897, 116402, 'The Singularity makes the Pocket Black Hole?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4897, 116403, 'Correct. It is quite simple really. You must initialize Loki''s algorithm from the Singularity Control Console and then activate a Series of Singularity Grids. This produces the power that creates Loki''s toy.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4897, 116404, 'And once I''ve created one?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4897, 116405, 'Find your way to Ullr. He will provide me with an additional body.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4898, 116135, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4899, 116406, 'You must be careful when approaching Loki. He may not trust you, in which case he will treat you as any intruder.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4899, 116407, 'Was he a prisoner here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4899, 116408, 'Originally he was sent here under penal conditions for unauthorized experimentation upon human subjects. However, upon his arrival we were instructed to provide him a body and full support for his experimentation... ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4899, 116409, 'By order of the Asgard Council?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4899, 116410, 'This is correct. He remains controversial, but many Asgard believe that it will take extreme methods to solve the challenge of our failing genome', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4899, 116411, 'Where is he?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4899, 116412, 'I am not certain. I will upload the location of his laboratory to your PDA. I anticipate he will be there.', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116626, 'We cannot allow any more of our technology to fall into the hands of Ra. We must destroy Yotunheim.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116627, 'Destroy Yotunheim?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116628, 'We are losing ground in the battle. The Solocris was just one piece of highly powerful technology stored here. With each hour Ra loots our storage facility... ', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116629, 'What do we do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116630, 'Here are three uniquely crafted explosive charges. You will need to plant them a three key weak spots. When you have completed this task, report to Ullr. ', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116631, 'What about you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116632, 'I am going to rig the Singularity for implosion. Your detonation will inspire mine. The result will be negative space.', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116633, 'Will you be in danger?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4900, 116634, 'We are all in danger. Go, there is not much time...', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118076, 'We''ve got a little bit of a worry up here. Colonel Carter can give you more information.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118077, 'We''re short on food. At least human food...', 2568, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118078, 'What about the Jaffa?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118079, 'Free Jaffa armies are engaged all over the galaxy. This has stretched our supply line very thin.', 2323, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118080, 'I have sent out teams in search of supplies, but this is a temporary solution.', 1333, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118081, 'Laro has genetically modified some plants on Agnos. It''s possible that these modifications could be beneficial to us - but we need to study them.', 2568, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118082, 'We are looking for the non-sentient plants in that area. ', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118083, 'Yes, we don''t want to be killing off new species. ', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118084, 'At least not yet. It''s possible that Laro has the growth data stored someplace. That information would also be useful if you can find it.', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4901, 118085, 'Deliver the plants and data to Colonel Carter when you''ve collected everything. I can''t emphasize enough how important this mission is.', 2410, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4902, 116664, 'We will wait for them to return.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4902, 116665, 'They may be under attack...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4902, 116666, 'It is possible... But they were aware of the danger.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4902, 116667, 'Upload their last known location to my PDA.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4902, 116668, 'You wish to pursue them? There is no time...', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4902, 116669, 'I am going.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4902, 116670, 'As you wish. Please understand that I cannot wait for you. When the time comes, I will destroy this base. If you are on it, you will perish.', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4903, 117075, 'Ra''s Jaffa are gaining ground. Yotunheim is a repository for a vast array of Asgard knowledge. If they continue to make military gains here...', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4903, 117076, 'I can help...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4903, 117077, 'There is a jaffa weapon cache we have discovered that must be destroyed... We also need to track the movements of certain Jaffa captains.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4903, 117078, 'We just want to monitor the captains?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4903, 117079, 'Yes. We will gain much from knowing where they are - more than if they are simply eliminated. We can predict their attacks in this manner. Here is a device which releases a tracking monitor. Use it to plant monitors on the Jaffa captains. ', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4903, 117080, 'And at the weapons cache?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4903, 117081, 'You will need to use your considerable creativity... ', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4904, 85636, 'This is excellent. Heimdall and I can begin work right away. ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6337, 120075, '<Input text here.>', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117126, 'No, for several reasons. Most of the technology contained in Yotunheim is not within common memory. In addition, the consciousnesses stored here are those of criminals. They would not be priivy to our secrets.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117127, 'You want me to recover them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117128, 'Any Asgard they "interrogate" may be lost forever if they choose to download them in an unconsidered manner. We must prevent this.', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117129, 'Even though they are prisoners. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117130, 'Our mission on this station is to protect them, notwithstanding their behavior during sentience.', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117131, 'Understood.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4905, 117132, 'You will find the Jaffa at their staging area, but we do not know which one carries the data crystal. Recover them before the Jaffa can upload them to a computer. Good luck.', 2069, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4906, 117138, 'These Jaffa are unlike any I have encountered before. Normally we do not have such trouble fighting the Goa''uld or their minions.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4906, 117139, 'Ra has modified them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4906, 117140, 'Yes. We have done some research on deceased Jaffa corpses, but live scans may give us details as to how Ra''s Straegis technology is fusing with the internal systems of his Jaffa. ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4906, 117141, 'The Ancient Goldam mentioned that the Goa''uld may have been created by the Furling...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4906, 117142, 'Interesting. Scan the Jaffa and I will run an analysis. ', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4907, 117013, 'Ra''s Jaffa continue to pressure our research strongholds. There is much at stake. ', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4907, 117014, 'Are they destroying things?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4907, 117015, 'That which they do not understand, they destroy. Scans indicate that they are currently misunderstanding things within the Furling Vault. ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4907, 117016, 'Furling Vault?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4907, 117017, 'Much ancient research about the Furling resides there, along with artifacts. It has been many years since the Asgard have actively researched the Furling - I am unfamiliar with what is in there. If you are available...', 2069, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4907, 117018, 'I am available.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4907, 117019, 'Any artifacts you recover you can deliver to an Asgard representative at the SGU. They are not safe here any longer. ', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4908, 89294, 'Recover the Solocris from the Nox vault.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116482, 'What do you know of the Solocris?', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116483, 'Nothing substantial...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116484, 'I have long been searching for it... I have spent months culling through memory databases... I have come to believe that the Solocris is located in the Nox vault here on Yotunheim. Near the center of it.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116485, 'In the open?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116486, 'The memories I have accessed indicate that the Nox assisted us by using their cloaking technology to hide the Solocris. There should be a disgiuised control panel there that we can use to alter the phase of the cloak, thus revealing the Solocris.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116487, 'Why not recover it immediately?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116488, 'The attack happened just as I found the storage location. Given the obscurity of the object I did not consider that Ra would have interest in it... I focused on defending Yotunheim.', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116489, 'These memories you access, they are data?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116490, 'Yes. We store memories as data. Yotunheim contains many tightly-controlled Asgard secrets. These memories are stored here exclusively.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116491, 'Anyone can access this data...', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116492, 'You fear Ra may have done so? This is unlikely...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116493, 'But possible. I will go...', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116494, 'I can assist you.', 2095, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4909, 116495, 'Just wait for me here. ', 0, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4910, 117927, 'This is not the Solocris, but only some sort if storage case... It is gone... Ra must have it...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4911, 116528, 'UNUSED DIALOGUE', 2098, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4912, 116529, 'They have the Solocris? We need to go after it...', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4912, 116530, 'Can we try and track it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4912, 116531, 'No. I have spent months trying to do that. ', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4912, 116532, 'Then what do we do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4912, 116533, 'We track Ra''s minions... Give me a moment...', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4913, 89313, 'Stop the Ashrak and recover the Solocris.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4914, 116593, 'There is no way to get onto the Tel''tak alive... However... The black hole could be transported on board... And then activated...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4915, 112166, 'The window is going to blow! You need to get out of the area and seal it off.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116577, 'Scans indicate much activity near the loading area. They are moving material to a Tel''tac.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116578, 'The Solocris?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116579, 'Quite possible. If Ra escapes with the Solocris it may have grave repercussions for the entire galaxy... I will inform Ullr to prepare the self-destruct.', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116580, 'I may have something with me...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116581, 'A Portable Singularity Apperatus? You withheld this information from me.', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116582, 'How does it work?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116583, 'It does not work. When you activate it, the black hole will expand and consume a large chunk of space... You must take this with you and, assuming you cannot recover the Solocris, activate the black hole.', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116584, 'That could destroy Yotunheim.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4916, 116585, 'Yes. Hopefully this will not be required, but extreme measures are required in extreme circumstances. Ra must not possess the Solocris. Do what is needed. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4917, 65933, 'Search Asgard computers on Yotunheim.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4918, 118086, 'General O''Neill''s disappearance was a great concern to everyone. However, Thor''s response has been puzzling to me.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4918, 118087, 'How so?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4918, 118088, 'He doesn''t seem as concerned. Clearly O''Neill knew the Straegis were coming - or something like them - but Thor''s team seems to be treating this whole thing as something less than a crisis.', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4918, 118089, 'You think they have the General?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4918, 118090, 'Maybe Thor doesn''t but... Loki?', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4918, 118091, 'Loki?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4918, 118092, 'Asgard scientist who occasionally goes out of bounds... It''s not likely but... It''s not outside the realm of possibility. Anyway - while you''re at Yotunheim, see if they have anything about General O''Neill that they are not sharing. It wouldn''t be the first time. ', 2410, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4919, 105946, 'The computer contains no information about O''Neill, however it does contain some files on Vokos Primar which may be of interest to General Hammond.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4922, 118093, 'The creature is fantastical - but slowly, surely you sense that you are being communicated with... You''re just not sure how. It''s confusing at first, but slowly you begin to understand the undulations and currents of the creature''s speech... If that''s what you call it.', 2441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4922, 118094, 'You sense that it is missing something - elements. It wants to tell you something, but it cannot - not without Straegis Shards - specific themes: Communication, Knowledge and Conflict. To find out what the Furling wants to tell you, you have to collect these themes from the Straegis. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85724, 'The Furling first seems to thank you for the shards - explaining that it is limited in its form in this dimension. Then it drops an incredble bomb... Jack O''Neill is on Meridian. He is alive, but he is held. ', 2441, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85725, 'The Furling is telling me where General O''Neill is.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85726, 'Jack?', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85727, 'What''s it saying? Details.', 2410, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85728, 'He''s in a place called Meridian. He''s alive, but he''s... A Prisoner.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85729, 'Jack''s alive.', 431, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85730, 'For now. How do we get to him?', 2410, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4923, 85731, 'It can''t tell us that... Yet...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4924, 117914, 'Ra must have taken the GDOs from the command center. The files with the GDO codes must not have been destroyed before he got to them. Earth is wide open. I''d tell Woolsey but he has cut off communication with me...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4924, 117915, 'Through General Hammond, I shall inform Earth of the codes that Ra knows. Perhaps they can be invalidated.', 1018, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4924, 117916, 'This is only a partial list, Ra may have gotten a more complete version... If he did, Woolsey can close the SGC all he wants - it may not matter.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4924, 117917, 'What about the Four Pieces?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4924, 117918, 'They are safe... But with Earth vulnerable, we may need to find somewhere else to send them...', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4925, 113386, 'These crates are filled with SGC supplies. Amongst the mess, you find GDOs ("Garage Door Openers") - the radio signalers that open the protective iris that protects Earth''s Stargate, given the proper coded entry.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4925, 113387, 'Included in the crates are files - including copies of a list of GDO codes... Passwords for the Iris. Tigges must be informed.', 1059, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4927, 89579, 'Accessing the subroutines is easy enough... Svarog''s system identifies a specific DNA strand within his Jaffa'' s symbiote. A simple switch can have the system identify human DNA instead. The hard part is making the effect temporary...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4933, 118183, 'Return to Harset with the Soil and Grey Goop of the Four Pieces and inform them of your victory
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118184, 'The Straegis have been weakened and we kept the Four Pieces from Ra... I''d say we got it done... Marsh has quite the team working for him.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118185, 'We try.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118186, 'Then there is still the matter of the Four Pieces. I cannot allow the Praxis to possess them... ', 1018, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118187, 'Earth is compromised, they can''t go there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118188, 'The SGU can secure them.', 1018, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118189, 'Not any more effectively than the Praxis can. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118190, 'What if we split them up? Compromise. Colonel Marsh will understand that. We''ll split it down the middle. We''ll take the Soil and the er, Gray Goop. The SGU gets the Rod and the Gas.', 1008, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118191, 'There is a wisdom to it. Are we agreed?', 1018, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118192, 'Yes.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4934, 118193, 'You go on ahead with the pieces. I''ll finish up here... Let Marsh know I''ll be there soon... ', 1008, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113807, 'These pieces will be safe here on Harset. Good job.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113808, 'Hardly... We should have demanded all four.', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113809, 'The SGU would never allow it. They do not trust us... To demand that would start a conflict we cannot yet win...', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113810, 'I wish to know more of these Four Pieces. How is it we did not learn of them sooner?', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113811, 'They were an SGC artifact that they didn''t even know they had... We''ll start analyzing the two parts we got right away... ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113812, 'Earth has been compromised. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113813, 'And why would that concern us in the least?', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113814, 'Some of us care about that quite a bit. But even Woolsey is smart enough to invalidate any of the codes Ra took. Trust me, I have my ear to the ground on this one. If Ra goes after Earth, we''ll know.', 941, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113815, 'But will we care?', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113816, 'You''re starting to piss me off, Queenie.', 941, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4935, 113817, 'Please... Both of you. Stop. I believe our excursion to benefit the Tau''ri is finished. I recommend, $name$, that you return to Agnos and continue your duties there.', 942, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4937, 118210, 'Return to Omega Site with the Rod and the Gas of the Four Pieces and inform them of your success.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118196, 'The Straegis are slowly being neutralized. Ra has retreated from the world... I can''t believe I am saying this but... I think we won...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118197, 'What of the Four Pieces? Earth''s Stargate has been compromised, so storage there is out of the question... ', 1018, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118198, 'I can''t imagine the Praxis leadership would approve of simply giving the Four Pieces away to anyone. If we don''t give them something, we may be looking at a reprisal.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118199, 'Violence?', 1018, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118200, 'Colonel Marsh doesn''t control them. Keeping them away from an artifact so obviously valuable will be seen as a slight by the New Mind Goa''uld and Moh''katan...', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118201, 'Why not split the Four Pieces up?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118202, 'Shared custody... Interesting. And perhaps the safest solution in the long term. Ra would need to strike both the Praxis and SGU to get the pieces back. ', 1018, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118203, 'Baal and - especially - Anat may not like the idea... But there''s nothing political they can do about it.', 1008, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4938, 118204, '$name$, take the Rod and the Gas back to the Omega Site. I will give the Soil and the Metallic Colloid to a Praxis representative. Please let the SGU leadership know of our arrangement.', 1018, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114143, 'Good work. Tigges''s decision is probably the right one, given the circumstances. He''s a good man. It will be a shame to lose him. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114144, 'Lose him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114145, 'Tigges'' choice to involve the Praxis - specifically Colonel Marsh''s Op-CORE - in the Beta Site mission ruffled a lot of feathers politically. Woolsey wants to prosecute him for treason. ', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114146, 'But he saved the planet. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4955, 118404, 'Sulbeck, why is it you question the Straegis?', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114147, 'Perhaps, but the Praxis ravaged the site - they took whatever wasn''t nailed down. Woolsey tends to focus on the negative. Marsh offered Tigges an alternative to a court-martial. ', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114148, 'Mimir informs me that the remaining at-risk personnel have all been evacuated and are being treated for their injuries. Beta Site was a victory, albiet a clouded one.', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114149, 'I assume I should return to Agnos?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114150, 'Absolutely. We need your work there to continue. Its very likely that if a break in the fight with the Straegis is to come, it''ll come from there. ', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4939, 114151, 'I''ll leave immediately. ', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118152, 'The portal is not like the ones before. It is constructed purely of Straegis matter... The readings you bring back are beyond my ability to measure.', 1015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118153, 'Not of the same frequency groups?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118154, 'Not even in the same vocabulary. The portal is connected to something else entirely.', 1015, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118155, 'How do we stop it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118156, 'The portal will continue drawing additional frequency groups through until it is stopped, but the construction of the device makes conventional methods of disabling it ineffective.', 1015, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118157, 'What would happen if we put Straegis shards back into the portal?', 431, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118158, 'Interesting. Those shards are immune to the energy released by the portal... It could cause a blockage. ', 1015, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118159, 'Could that break the portal?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118160, 'It certainly might. Given what we know of the portals, it is a reasonable theory.', 1015, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118161, 'You might be able to force feed some Straegis shards directly into the portal. If the theory works...', 431, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118162, 'No more portal. ', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118163, 'And if it doesn''t, what''s the worse thing that could happen?', 431, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118164, 'Oh, there are several options, Dr. Jackson... The portal could accelerate, causing a hyper-flooding of the Beta Site by Straegis within minutes... Or, the portal could detonate with the force of 300,000 kilotons of...', 1015, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4940, 118165, 'That was a rhetorical question, Heimdall. Rhetorical. ', 431, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118136, 'The portal has been stopped. My calculations show the Straegis forces on this world are reducing in number for the first time in days...', 1015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118137, 'In other words, Ra''s threat of overwhelming the planet with Straegis is now impossible. We won.', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118138, 'We have also learned a substantial amount concerning the Straegis. In the spirit of cooperation against a common enemy, I will forward this data to your Praxis leadership.', 1015, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118139, 'They will appreciate it.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118140, 'I must admit, I didn''t believe you''d come through...', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118141, 'I shared those doubts about you. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118142, 'Well... Thank you for your help. ', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4941, 118143, 'It was most appreciated. ', 1015, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4942, 118345, 'This is the location of Mimir''s vessel, but nothing remains except traces of a massive explosion. Whatever was here is gone.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4943, 113880, 'Disappointing... I will keep my ear to the ground. For now there are more pressing matters to attend to. ', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4944, 103618, 'The Mouth of Ptah would be found amongst the forgotten crypts of Men''fa. We have already sent an Officer to the world - the human, McIntyre. ', 1880, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4944, 103619, 'She has a bit of a attitude, but she''s a good gate liasion. Report to her and begin your investigation. ', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4944, 103620, 'Work quickly... If it can be decrypted, that cipher means great power for our alliance.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4945, 118356, 'Salvage priority supplies from the Beta Site for Praxis use.', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4946, 118357, 'Tigges may have our assistance, but the Praxis is not a charity. Harset has ordered that we take what we need from this world. ', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4946, 118358, 'What about our alliance?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4946, 118359, 'We will let Tigges worry about that. So far he has said nothing when we have "salvaged" equipment and material... Mimir is less compliant, but he says nothing. ', 1023, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4946, 118360, 'What are we after?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4946, 118361, 'Beta Site has a large supply of Naquadah, as well as a facility which produces tretonin. Capture of these valuable resources will bring trade revenue to Harset.', 1023, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4946, 118362, 'Where are they?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4946, 118363, 'Tigges informs me the naquadah is in the Science Facility, stored as fuel stockpiles. The tretonin, which will be of great value to our combat medics, will be in the Command Center Infirmary.', 1023, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4947, 113892, 'Well played... We will find everything of value we can. Our commitment here must be compensated.', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4948, 113889, 'The naquadah supply storage container is locked and too heavy for you to just cart away. You will need to bypass the locking mechanism.', 2483, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4949, 118364, 'You unlock the storage unit and retrieve the valuable refined naquadah.', 2483, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4950, 103793, 'These Jaffa might be an advantage for us... ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4950, 103794, 'How so?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4950, 103795, 'They might be a shortcut. See if we can interrogatate one and get info about the Mouth of Ptah. Don''t worry about subtlety - put the boots to them. And I know the council is in a frantic hurry, but if you also get a shot at finding out why we''re neck deep in Jaffa who still fanatically worship a dead guy, take it.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4951, 103787, 'Saarthon sounds like our most promising lead. The unexpected military presence here worries me, though. This world is making me nervous. Somebody has tapped into these Ra Jaffa and their inner crazy... If it were up to me, we''d just retreat. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4951, 103788, 'Just leave the world?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4951, 103789, 'Absolutely. Or send in strike teams and turn this place into a combat zone. But that''s a decision above my pay grade... Let me ask the council.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4952, 118365, 'Acquire another communication sphere to eavesdrop on Ra', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4953, 118366, 'Your previous attempts to crack Ra''s communication sphere went far toward enraging Ra...', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4953, 118367, 'He is tempermental. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4953, 118368, 'Indeed. And it gives me an idea. Ra''s lesser Jaffa also have spheres, but they are only activated when spoken to. However, one may be able to reverse the signal choke. It may be a means into Ra''s communication network.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4954, 118396, 'You reverse the signal choke as suggested by Mattila. It appears to have stuck. This sphere is now linked into Ra''s network at all times.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4955, 118403, 'You activate the sphere tap. Ra''s voice comes through loud and clear, but the other side of the conversation is lost.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6338, 120077, '<Input text here.>', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4955, 118405, 'They are my gift to you... The endless army that has been foretold and delivered. They are the footsoldiers of the apocalypse that will see the Sun God rule all.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4955, 118406, 'They will not replace the Jaffa. They will not replace you... They will enhance you. They will fuse with you... ', 2547, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4955, 118407, 'I grow tired of this... If I hear any more complaints you and your Jaffa shall know my wrath as dearly as the Tau''ri.', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4955, 118408, 'The tap appears to be working. You switch it off.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4956, 118409, 'So not even the Jaffa are totally enamored with the Straegis... His talk of fusing the Jaffa and the Straegis is curious, given the mutations already seen in his Jaffa abominations. I will monitor more. Good work. ', 1023, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109409, 'Is a mission to Dakara even feasible given Ra''s invasion?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109410, 'That is unknown. The Free Jaffa have many resources backing Dakara. My confederate Rohurk informs me they have prepared for siege. Much depends on the size of Ra''s army...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109411, 'We know it grows by the day. I have heard of several clans moving to join him.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109412, 'As have I. The trend is most disturbing. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109413, 'Ra could eliminate the Free Jaffa as a power if he topples Dakara. However, what if he is after more than control of the city?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109414, 'The SuperWeapon? Anubis sought it to unmake all life the galaxy.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109415, 'It is a powerful piece of technology. I have seen its effects first hand.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109416, 'The Jaffa claim to have destroyed it, but I do not believe them. If Ra were to get that weapon?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109417, 'We would all die. I have no doubt of it. I knew Ra very intimately for many years... He has not forgotten about us, Baal. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109418, 'We are going to help to protect Dakara?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109419, 'They would sooner kill us than have us help. I am no friend of the Council.', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109420, 'I don''t believe any of us are.', 942, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109421, 'The plan should be to infiltrate the planet and stay under the Council''s radar. You can test the Reins on Ra''s forces in action. The Free Jaffa would be none the wiser.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109422, 'Rohurk is well-regarded amongst Jaffa. I will arrange for him to supply a cover identity for you to ensure the Jaffa do not discover who is helping them.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109423, 'What if the Jaffa sense a Goa''uld in thier midst?', 0, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109424, 'The Free Jaffa have a truce with the Tok''ra... Rohurk will claim you are one of them. In the chaos of this attack, no one should look too closely.', 945, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4957, 109425, 'We cannot afford to take risks with Dakara. I am sure Rohurk will find a way to make use of your talents in their defense.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4958, 114305, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4959, 114304, 'UNSUED DIALOGUE', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4960, 114306, 'UNUSED DIALOGUE', 1022, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4961, 103801, 'Moving around this world is a serious headache - I don''t think anyone in the council understands how dangerous it is down here... We need something to divert these zealots so that our teams can move more freely.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4961, 103802, 'I can reprogram their drones.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4961, 103803, 'That''s not bad... And it''s easy to do. Goa''uld drones use a control crystal. Get one of those and then access one of their control computers. You can reprogram the command protocols and then broadcast the new version over their network...', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4961, 103804, 'This will cause havoc.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4961, 103805, 'Absolutely... They will have no idea what hit them.', 1885, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4962, 114312, 'UNUSED DIALOGUE', 1022, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4963, 114314, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4964, 114315, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4965, 103946, 'It should be clear enough for you to go after Saarthon. According to what we''ve found out he should be somewhere near what looks like an archeological dig site. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4965, 103947, 'What is he doing there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4965, 103948, 'No idea... And frankly I don''t care. Find him, question him and find out where the Mouth of Ptah is so we can get out of here.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4966, 118285, 'Finish the archeological research on the history and importance of the Four Pieces.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4967, 118286, 'This base had a functioning archeological team... Before they started shutting it down. It is very possible that they were on the verge of figuring out what the Four Pieces did and why Ra had them.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4967, 118287, 'Did they have theories?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4967, 118288, 'This is unknown. None of the archeological data has been recovered.', 1015, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4967, 118289, 'Is it recoverable?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4967, 118290, 'All the team''s data should still be in the Science Facility. I don''t know why the Straegis would mess with it... If I could just see what they have, I may be able to put something together.', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4967, 118291, 'I''ll get it.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4968, 114351, 'You successfully download the Beta Site archeological findings, however some of the data appears to have been corrupted... Probably due to the combat damage done to the systems.', 2489, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4969, 118293, 'Well this was... Pretty useless. We knew this already: Ra stored the pieces here and they were to be used in some ritual that would grant him unimaginable power... As opposed to imaginable power... Why is it always unimaginable?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4969, 118294, 'Is there more?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4969, 118295, 'Oh, yes, right... Apparently, the history of the Four Pieces was also transcribed... It says here that it was written down... Glory of Ra... More glory... Ra''s really glorious... Hmmm. Here''s something. There are more cartouches.', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4969, 118296, 'What do they say?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4969, 118297, 'I don''t know. Our people haven''t translated them. And the photo files were damaged. There are only three headings: "The Sundering of the Four Pieces", "The Camouflage of the Four Pieces", and "The Search for the Four Pieces." They''re all in the nearby ruins.', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4969, 118298, 'Are they important?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4969, 118299, 'They''d be vauge and lacking technical detail... But they''re all we''ve got. If you can get me a clear transcription I''m sure I can decipher them.', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4970, 114367, 'You digitally transcribe the cartouche labeled "Sundering of the Four Pieces."', 2486, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4971, 114368, 'You digitally transcribe the cartouche labeled "Camouflaging of the Four Pieces."', 2487, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4972, 114366, 'You digitally transcribe the cartouche labeled "The Search for the Four Pieces."', 2488, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118300, 'Alright so in sequence, the "Sundering" took place first. Long ago, very powerful beings "sundered" an object of major power, and took from it the Four Pieces. Strange, the terminology here resembles that of funeral rites -- like they were removing organs from a body.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118301, 'So did they kill something?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118302, 'Perhaps... Next the "Camouflage." To ensure the Four Pieces were never found, they were disguised and scattered "throughout the known universe". A little dramatic licence there I think on Ra''s part.', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118303, 'Someone did not want these Four Pieces found.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118304, 'And apparently Ra found out about them. And once he did, he got obsessive... The "Search" is Ra''s search for the pieces. Apparently he spent centuries... Sending his entire empire combing the galaxy looking for them.', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118305, 'And he found them...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118306, 'Yeah. And he put them in a box. It doesn''t say anything else. ', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118307, 'But what does the thing do?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118308, 'The symbols used to refer to the Four Pieces... They correspond to the four elements of the ancient world: fire, water, wind, earth. And the symbol for what they make together... In Earth culture that symbol means "chrysopoeia " - the philosopher''s stone.', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118309, 'What would that do?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118310, 'We''re just guessing now... Over time the legend obviously would have drifted substantially from the truth. It could mean transmutation, immortality, or simply "enlightenment." It could also refer to the pinnacle of existence...', 431, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118311, 'Interesting.', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4973, 118312, 'Obviously it''s not literal... And given Ra''s homicidal past, I''ll bet power is in there somewhere... It''s a good thing we''re not letting him get those Pieces.', 431, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4974, 103965, 'UNUSED DIALOGUE', 1778, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4975, 104044, 'Obviously we can''t trust Saarthon completely but he''s the only lead we''ve got...', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4975, 104045, 'I have to check the lab area.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4975, 104046, 'Which means removing the key from Safkhet''s First Prime... Even if you don''t find Safkhet inside - and not finding her may be a blessing - you should be able to find out where the Mouth of Ptah is located.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4976, 102586, 'An opportunity has come up for us on Beta Site which takes priority over the Agnos mission, so your request may be fortuitous... Beta Site is teeming with Straegis - they''ve overrun everything. Use the time on Beta Site to do the work Laro requires... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4977, 102585, 'Beta Site''s mission is a priority... However, that world has been assaulted by the Straegis. It should be possible for you to collect the materials Laro requires while completing the primary mission...', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4978, 104188, 'Through the endless love musings and ramblings about Ra''s greatness you come across another key piece of information - the Mouth of Ptah requires an activator crystal. Given the nature of her journal, you leave convinced Safkhet never goes anywhere without it on her person.', 1842, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4979, 104204, 'Safkhet probably has the activator crystal for the Mouth of Ptah. One way or another you will need to get that key from her.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4980, 104211, 'The device is like nothing you''ve ever seen - an almost arcane technology that exudes power. You decide to use the activator key you got from Safkhet - there is a place for it right on the console. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4981, 104232, 'Unsure about exactly what just transpired, you realize you must give the deciphered Book of the Gates to the leadership council...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4982, 113564, 'Do we have any medics on the channel? I have soldiers collapsing with seizures - some of them are in a pretty bad way. I repeat, we need medics...', 1110, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4982, 113565, 'Captain, this is $name$. Are these soldiers just out of stasis pods?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4982, 113566, 'Most of them are from the East Wing stasis pods - why?', 1110, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4982, 113567, 'They''ve got stasis sickness. They need ambernol.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4982, 113568, 'There''s an infirmary on Level 5. Doubletime it there and secure a supply. We''ll be coming behind you as fast as we can with the affected.', 1110, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4983, 96921, 'What''s going on out there? I''ve been recovering from my last bout with Romney. I had no idea.', 2490, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4983, 96922, 'We''re breaking out... ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4983, 96923, 'Oh, thank god... They pulled me out of stasis a few days ago for Romney sessions but... They seemed preoccupied. I figured something was up.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4983, 96924, 'It is. Do you know where they keep the ambernol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4983, 96925, 'Yeah, that med dispenser over there is programmed to control the supply. There is a code for it.', 2490, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4983, 96926, 'Do you know it?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4983, 96927, 'No. i saw them type it in. You''d probably have to hack the dispenser.', 2490, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4984, 96928, 'You''ve modified the Med Dispenser so that it now provides an unlimited supply of Ambernol.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4985, 96929, 'Have you found the ambernol? We''ve got a lot of marines in need.', 1110, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4985, 96930, 'Supply is secure. Ogilvie is here - he''s in charge of it. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4985, 96931, 'Ogilvie? Glad to hear he''s alive... We were worried about him. Get yourself to the Throne Room - we have to override the Goa''uld defenses so we can boost power to communications.', 1110, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4986, 102700, 'The holorecord needs some sort of player, but there is also damage to the data package itself. You''ll need to try to repair it before you can see what''s inside. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4987, 102672, 'The weapons project has clearly stalled, but there still may be something useful in the Ancient Library... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4988, 102735, 'Connecting the generator to the Atmosphere Generation Plant can be done here... Carefully... ', 2719, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4989, 96950, 'Jaffa, kree! I am glad you have survived your captivity. What is your status?', 2499, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4989, 96951, 'I am aiding the Tau''ri in their escape, Moh''katan. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4989, 96952, 'You must also aid our people. The NID Tau''ri removed the symbiotes from our warriors as part of their torture. All are left weakened.', 2499, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4989, 96953, 'Indeed. I suffer as well.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4989, 96954, 'Colonel Marsh tells me that his Op-CORE humans have found symbiotes in storage in the infirmary on level 5. Proceed there and confirm this assertion.', 2499, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4989, 96955, 'Yes, Moh''katan.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4990, 96946, 'You quickly bypass the security protections on the Symbiote Tank. You reach inside and pull out a symbiote from the tank.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4991, 96956, 'Have you found symbiotes?', 2499, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4991, 96957, 'Several tanks are here. The Tau''ri were correct. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4991, 96958, 'Excellent. I will send our warriors there. In the meantime, make your way to the Throne Room and disable the Goa''uld defenses. You must move quickly. There is not much time. ', 2499, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4992, 118381, 'There are many individuals on this world in jeopardy. Some are injured, some are unable to reach the gate, and yet others have an unknown status.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4992, 118382, 'We need to get them out.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6339, 120079, '<Input text here.>', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4992, 118383, 'Correct. I have an Asgard transportation targeting designator which will assist in this process. With it we can safely beam out anyone in danger.', 1018, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4992, 118384, 'How does it work?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4992, 118385, 'Simply scan your target with the designator and we can acquire their pattern.', 1018, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4992, 118386, 'I''ve uploaded an initial list of potentials to your PDA. We can start there and, assuming everything works, we can expand the list as we go.', 1008, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4993, 118395, 'Scan victims of the Beta Site attack with Mimir''s transport enhancing device for evacuation.', 1018, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4994, 118394, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4995, 118392, 'I have received targeting data for two humans and one Jaffa. The lock appears to be holding.', 1018, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4995, 118393, 'Nice work.', 1008, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4996, 118410, 'Scan more victims of the Beta Site attack with Mimir''s transport enhancing device for evacuation.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4997, 118411, 'I have three more names. They all should be in or around the Command Center. Maj. Paul Davis, Dr. Rick Pierce, and Lt. Adam Debeaux. I''ve popped them to your PDA.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4997, 118412, 'Do we have contact with them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4997, 118413, 'Sorry, no. That''s why they''re next on the list.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4998, 118418, 'I have received tracking data for one living human and two that shows no lifesigns.', 1018, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4998, 118419, 'That would be Lt. Debeaux and Dr. Pierce.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4998, 118420, 'We''re losing a lot of good people out there...', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4998, 118421, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (4999, 118430, 'Scan the last batch of victims of the Beta Site attack with Mimir''s transport enhancing device for evacuation.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5000, 118431, 'There are a few of our Jaffa allies that remain unaccounted for... Bra''tac would like them pulled out if possible.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5000, 118432, 'I''ll track them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5000, 118433, 'I figured. But they''re in rough spots. Ras''nor and Jysic fell back to the Ruins of Khen''mer Fa. As for Alesha... the old woman might not have made it out of Camp Shoul''ja. Do what you can.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5001, 118422, 'UNUSED DIALOGUE', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5002, 118423, 'I have acquired the details for two Jaffa survivors and one deceased Jaffa female.', 1018, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5002, 118424, 'The deceased is Alasha.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5002, 118425, 'We were afraid she wouldn''t make it... We''ll beam her body to the ship with the others. We have a Free Jaffa representative up there who will handle the burial rites...', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96984, 'I surrender!', 1093, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96985, 'Why won''t the Stargate dial out?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96986, 'It''s standard protocol. If a prison break occurs, the control crystal is removed. ', 1093, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96987, 'Who holds them?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96988, 'The Warden is supposed to have it, or maybe the officer who removed the crystal... I don''t know exactly. Somebody with clout. Not me.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96989, 'Where can I find them?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96990, 'I can''t really...', 1093, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96991, 'You certainly can. Unless you would prefer to die for the cause.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5003, 96992, 'Forget that. Warden Muelbach is in the communications bunker, probably trying to radio for reinforcements. The officers will be holding up at Checkpoint Bravo, setting up a last line of defense.', 1093, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5004, 96993, 'You run a diagnostic on the Stargate. It seems the DHD''s control crystal is missing - preventing it from sending any signal to the Stargate. The removal was most likely a security measure - and protocol dictates that Warden Muelbach or one of the officers would carry a replacement.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5005, 84450, 'Escort Senl''c back to the gate to assist in relief operations', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5006, 84457, 'Friend, what is going on? Why are we under attack? My people are dying... my family scattered.', 2495, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5006, 84458, 'Ra has invaded. He wants something.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5006, 84459, 'Can he not leave us be? What have the Nine Peaks ever done to him that he continues to trouble us so?', 2495, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5006, 84460, 'Are you alright?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5006, 84461, 'No. I must help fight Ra. How can I do this?', 2495, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5006, 84462, 'There''s a safe zone near the gate. I''ll take you there and you can help them.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5007, 84463, 'Senl''c, I''m glad you made it! What of your father?', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5007, 84464, 'I was separated from my family. When the attack landed he fell back with my people towards the Ruins. I stayed behind to protect the stragglers... but I failed.', 2495, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5007, 84465, 'Well it''s alright now. We''re pushing them back.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5007, 84466, 'I will help. Thank you again, <<player name>> for your assistance.', 2495, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5008, 113573, 'So it was the control crystal that was paralyzing the gate. Resourceful, $name$. Why are you looking at me like that?', 261, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5008, 113574, 'I saw you die.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5008, 113575, 'You saw my future self die. I''ll give you the longer answer someday, but we''ve got a war to prepare for. To start, get the DHD working. I''ll give you the details later.', 261, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5008, 113576, 'Yes, sir.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5009, 96998, 'Jaffa! You have the control crystal?', 2499, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5009, 96999, 'I have it here, Moh''katan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5009, 97000, 'Good. The Tau''ri have not yet figured out why the Stargate does not work. Fix it for them. Show them that Jaffa are not just superior warriors.', 2499, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5009, 97001, 'This alliance with the Tau''ri. . .', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5009, 97002, 'It is very complicated. I can give you details later. First, fix the DHD and then dial the Stargate to Harset. We will discuss the Praxis there.', 2499, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5010, 97007, 'Lead the way to Harset. You''ve earned it.', 261, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5011, 96973, 'Lead the way to Harset, my Jaffa. You have earned the honor.', 2499, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5012, 118435, 'Destroy sensitive data files and documents from the Beta Site computers.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5013, 118447, 'There are documents on our systems that Ra cannot be allowed access to. You have to destroy them first.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5013, 118448, 'Is there a procedure for that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5013, 118449, 'I ordered Lieutenant Debeaux to do the burn, when Ra first landed... But he hasn’t reported back. He has the burn protocol you need to active the data self-destruct.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5013, 118450, 'Where can I find him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5013, 118451, 'He was headed to the range to secure his sidearm... I''d start there.', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5014, 118446, 'Lt. Adam Debeaux is dead at the hands of the Straegis. However, the burn protocol disc is still on his body... The creatures seemed to have ignored him once he killed.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5015, 118452, 'The burn protocol disc works its special magic. Immediately the hard drives of the base computers begin crashing, their inner workings destroyed and their data now unreadable.', 2482, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5016, 118453, 'The burn protocol is only half the mission, I''m afraid. But keep your voice down, I don''t want that Jaffa Mattila to hear.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5016, 118454, 'You''re worried about your new allies, Tigges?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5016, 118455, 'Colonel Carter''s personal terminal could have data on the SGU - it may even have the location of the Omega Site. ', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5016, 118456, 'The Praxis probably would like that address.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5016, 118457, 'Exactly... We can''t allow that. You''ll find Carter''s personal terminal in the Science Facility. Take it down before the Praxis moles find it... ', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5017, 118458, 'The burn disc works equally well on Carter''s computer. Whatever information it may have had on the SGU is now a memory.', 2500, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5018, 118459, 'Excellent... My deal with the Praxis was necessary, but that doesn''t mean I want them to get intel they don''t deserve... ', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5018, 118460, 'What made you turn to the Praxis?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5018, 118461, 'Woolsey wasn''t sending help from the SGC - he cut us off... I knew Colonel Marsh wouldn''t just let us die out here in space... ', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5018, 118462, 'What about the SGU?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5018, 118463, 'Nobody told me about the SGU until they started showing up... By then the call had been made... And Marsh''s team has helped us - love them or hate them, they have helped us. ', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5019, 96351, 'Let''s move out!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5019, 96352, 'I''ll draw their fire! Take a flanking position behind that table.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5019, 96353, 'Crouch down when you''re in cover!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5019, 96354, 'Flank their position while I draw their fire!', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5019, 96355, 'I don''t have much time, so make sure to tell me - I mean the Col. Marsh from this time - everything I''m telling you. The Straegis can sense time travellers. They''ll find me soon enough.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5019, 96356, 'We never found out who controlled the Straegis. It seemed like there were some Goa''uld involved in some way but... We never got any solid intel on it. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5019, 96357, 'O''Neill better convince those pinheads at the Pentagon to pay attention. We''ll never take the Straegis on alone.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5020, 96180, 'It seems you can still follow instructions. Perhaps there hope for you yet. You will need Ambernol to cure your sickness. ', 253, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5020, 96181, 'What about my symbiote?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5020, 96182, 'I have no idea what the NID humans did with that. They''re generally not kind to them, however. ', 253, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5020, 96183, 'Where is the Ambernol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5020, 96184, 'There''s a medical station down the hallway - the Ambernol should be in there. You should hurry, there isn''t much time. ', 253, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5020, 96185, 'Why should I trust you, Goa''uld?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5020, 96186, 'Because if you don''t, you''ll die. Now go. ', 253, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5021, 96126, 'You feel dizzy, don''t you? Stomach aching? Flashes of inexplicable pain... You''re in grave danger, Jaffa. Let me out of this cell and I''ll save you.', 253, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5021, 96127, 'My symbiote will cure me. I will not trust a Goa''uld.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5021, 96128, 'Your symbiote is gone, stolen by these humans when you were in Stasis, and you are never going to find one in time to offset the disease you have. ', 253, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5021, 96129, 'Disease?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5021, 96130, 'You''re suffering from stasis sickness. It starts with nausea and ends with your cells bursting, like little bubbles. You''ll be be dead within the hour unless...', 253, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5021, 96131, 'Unless I let you out?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5021, 96132, 'Precisely, Jaffa. Let me out and live. ', 253, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96261, 'You''re a big one, aren''t you? Wow, my sympathies to your mother. I assume you know Moh''katan? ', 256, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96262, 'Yes, I have sworn my allegiance to her.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96263, 'Well, I''m here to help get you out of here.', 256, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96264, 'I do not need your assistance. I will rescue myself.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96265, 'And I''d be all for that, but I need your help.', 256, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96266, 'I do not help the Tau''ri.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96267, 'Actually, you do. It''s complicated bit... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96268, 'Jaffa, kree! I am Moh''katan of Chulak. You have no reason to trust the Tau''ri - they captured you and threw you into a cell. However, this human - Marsh is not like the others. Trust him to lead you in battle, my warrior.', 2499, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96269, 'I will follow you, as Moh''katan decrees.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5022, 96270, 'There''s a weapon in that locker behind you. Get it. ', 256, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96282, 'Well, what do you think?', 256, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96283, 'It feels... Small. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96284, 'Yeah. It looks small to, but it''s going to have to do for now. We''ve got a lot to do in a little time - there''s a war coming. A big one.', 256, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96285, 'I welcome war. It is why the Goa''uld created the Jaffa.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96286, 'That attitude will come in handy because in a very short time an alien race called the "Straegis" is going to start attacking planets across the galaxy. Moh''katan''s Loyalist Jaffa and my Op-CORE Marines are going to be ready to fight them.', 256, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96287, 'How do you know this?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96288, 'That''s a very complicated question: I saw it happen.', 256, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96289, 'You saw the future?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96290, 'I''m from the future. I know it sounds insane, but I was able to give Moh''katan some very specific proof. For now, trust me, and then you can ask her about it later.', 256, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96291, 'If you deceive me, you will not live out the day. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5023, 96292, 'Fair enough. If I''m lying you can kill me. In the meantime, I need you to use that terminal over there to free more of our people from stasis. ', 256, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5024, 109066, 'Report to Colonel Carter on Beta Site.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118847, 'The stories of your glory precedes you. The Free Jaffa here at the Omega Site welcome you to the Stargate Union. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118848, 'We are pleased you have joined us. ', 1333, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118849, 'Your arrival comes at an opportune time. The Free Jaffa nation is slowly growing - each day new clans join our alliance. Still, there are many challenges which face our people. ', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118850, 'Your willingness to work closely with the humans is highly valued. ', 1333, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118851, 'And needed. The humans are reducing their intergalactic presence. It will be up to the SGU to fill the void created by their departure.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118852, 'Not all of us are going away... It''s just politics - you understand politics, you''re a Jaffa - but the entire idea of closure is a temporary bit of insanity...', 431, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118853, 'We must treat it as fact. We cannot rely on hope, Daniel Jackson. ', 1333, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118854, 'Initially we wish for you to work with the humans on the Beta Site. Your mission is simple enough: Assist Colonel Sam Carter with anything she requires. ', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118855, 'Colonel Carter is assisting the SGU in her role as Commander of Beta Site.', 1333, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118856, 'Remember, the SGU - or at least the scope of it - is a secret amongst the SGC members on that world. It''s important it remains that way. ', 2323, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5025, 118857, 'Indeed. If Woolsey were to discover this operation, many SGC members would face disciplinary action.', 1333, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5026, 87220, 'Welcome... You''re certainly needed. We have a lot to do.', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5028, 109598, 'As I feared, Ra''s forces are closer and more numerous than we thought. The markings indicate Jyoleen is in charge - his leadership is legend. This is not good. ', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5028, 109599, 'How could Ra have outposts within the city already?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5028, 109600, 'Not all Jaffa are committed to the Council''s banner - the Free Jaffa Nation is a nation in turmoil. Some, like myself, wait for the moment we can return Moh''katan to the Council as a hero. Others fight for their own vision of freedom. There is no consensus.', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5028, 109601, 'Have any defected to Ra?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5028, 109602, 'This has happened, although I have not heard specific names... It is not surprising... Ra was the greatest System Lord that ever lived. ', 768, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5029, 111459, 'Confirm the loyalty of some key Free Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5030, 118858, 'The Free Jaffa nation is young. We have many members, but there is dissention infecting the ranks. I have heard stories of a few Jaffa here - even at Omega Site - whose loyalties may be wavering.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5030, 118859, 'We must confirm their allegiance. ', 1333, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5030, 118860, 'There are three leaders here whose intentions are unclear to me. I wish for you to confirm their loyalty.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5030, 118861, 'If you must, engage in Runk''an. ', 1333, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5030, 118862, '(Runk''an... An ancient Jaffa tradition of hand to hand combat. They trade blows and the last one standing has earned the loyalty of their fallen opponent.)', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5030, 118863, 'Teal''c''s thinking is inspired. Runk''an is the most effective way to guarantee loyalty... But resort to this only if needed. The Jaffa you are approaching are powerful warriors.', 2323, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5031, 111538, 'You come to me, in the public square and dare question my loyalty?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5031, 111539, 'I am here only to confirm it. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5031, 111540, 'How is this not an affront to my honor, $name$?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5032, 111542, 'I do not deny my doubts about Bra''tac and his Free Jaffa Council. What have they done for my people? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111769, 'I do not respect Bra''tac and his approach to our sovereignty. We must become more than slaves, but we must do it with honor.', 2512, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111770, 'Bra''tac always acts with honor.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111771, 'But he defies tradition.', 2512, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111772, 'He embraces it. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111773, 'Do you embrace tradition?', 2512, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111774, 'Of course, I am a Jaffa.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111775, 'Then engage me in Runk''an. If you defeat me, I will remain loyal.', 2512, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5033, 111776, 'Runk''an!', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5036, 111481, 'This news is valuable. All three of those Jaffa are influential - not only here but throughout the galaxy. Your vigilance is appreciated.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5037, 109578, 'These plans are tactically brilliant. I am surprised we are not all dead already. But through this recovery we have gained our advantage.', 768, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5037, 109579, 'Ra will simply revise the plan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5037, 109580, 'The name on these plans - U''lien - is our advantage. He is of Dakara. He must be one of those who betrayed us. ', 768, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5038, 103815, 'In the orders you find reference to a safe in a nearby crypt - Hor-Aha. The notes indicate that the Jaffa were following decrees stored in a safe there - decrees they treated like as orders. The crypt itself is nearby...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5039, 103807, 'This was supposed to be an easy mission. Travel to the dead world and find something... These Jaffa were not in the program. We''ve got to find out where they are coming from...', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5039, 103808, 'I''ll look into it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5039, 103809, 'Do. Because until I get some more intel, there''s no way were getting anything useful from Harset...', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5040, 109159, 'Recover Ras''nor''s sacred tribal medallion.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5041, 118864, 'Your willingness to help my people shows you have great honor.', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5041, 118865, 'Your people would be a great addition to the Free Jaffa nation.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5041, 118866, 'Some have feared that the Free Jaffa do not respect the Ancient traditions our people.', 716, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5041, 118867, 'This is not true. We embrace tradition.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5041, 118868, 'Then perhaps you can assist me. Our tribal medallion was taken by Dakor''s supporters. Recovering it will help us when it comes time to reunite our tribe. It was stored in a medallion box... ', 716, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5041, 118869, 'Do you have the cipher?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5041, 118870, 'No. It was destroyed to prevent Dakor from defacing the medallion. You should be able to find the box in the Settlement...', 716, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5042, 109219, 'These boxes are designed to be opened by an ornate key - one that was lost. You begin to try and hack it. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5043, 109221, 'Another tricky box... These things are very difficult to pry open.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5044, 109164, 'You name will be held in high regard by the Nine Peaks Jaffa for this...', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5044, 109165, 'I am most humbled. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5045, 104290, 'So, Ra has a girlfriend - or at least she thinks someday she will be his girlfriend. She''s his former scribe and she''s nuttier than peanut butter... But the fact is, we need to find out what she is working on and if it''s related to all these troops on Men''fa. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5045, 104291, 'You think she is in charge of them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5045, 104292, 'I don''t know. I doubt it. But this world was always about technology, not troops. We have to find out what she has been doing technologically... We''ll deal with the crazy rabble later.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5046, 104383, 'Inside the cell you see Saarthon... You had left him in his sarcophagus - clearly Ra''s minions pulled him out and dragged him here. A debriefing might prove useful...', 1926, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5047, 109235, 'Help Heimdall test the potential antidote to the Jaffa Tretonin sickness. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5048, 118871, 'I have gotten word from Bra''tac, Heimdall - the Asgard scientist - may have concocted a cure for the Tretonin sickness. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5048, 118872, 'They are sending for me?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5048, 118873, 'They want your help in testing it. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5049, 87388, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5070, 69373, 'Were you building the energy creatures?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5050, 103307, 'Saarthon indicated there might be some new-fangled tech in the weapons the Jaffa are using here. This has made our New Mind leaders extremely nervous - given Ra''s blood-thirsty vendetta against them that makes sense. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5050, 103308, 'They fear that Ra loyalists may come after them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5050, 103309, 'It''s a reasonable concern since it has already happened. Go secure a weapons sample for our science team to disassemble. Destroy the rest. ', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5051, 109239, 'The Asgard scientist Heimdall claims he has devised a cure for the Tretonin sickness... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5051, 109240, 'Has it been tested?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5051, 109241, 'Not yet. Find a volunteer on Beta Site. You will apply the cure using this injector and then take readings. Bring the results directly to Heimdall. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5052, 109486, 'You begin to activate the scanner... This Asgard technology is not easy to use. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5053, 109233, 'The machine completes the body scan.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5055, 109497, 'These results are disappointing...', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5055, 109498, 'The cure failed?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5055, 109499, 'Yes. Resoundingly. The toxin consumed. I''m afraid the Jaffa we applied this to has actually had their sickness advance. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5056, 106011, 'Meet the SGU leadership and inform Thor of the Council''s decision. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118730, 'Bra''tac, Teal''c and Daniel Jackson will be pleased - news of your success has preceeded your arrival, $name$. They are all eager to meet you.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118731, 'On behalf of the Free Jaffa we congratulate you on a successful mission. ', 2323, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118732, 'Thor told us you were forced to upload yourself into one of the computer systems?', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118733, 'This is correct. I appreciate all of your accolades. However, I require a moment with Supreme Commander Thor.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118734, 'What concerns you?', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118735, 'The Council has informed me that I am to be deactivated. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118736, 'Deactivated? You are a hero. This makes no sense.', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118737, 'This is not totally unexpected. The operation on Pertho had political ramifications. However, I am surprised they decreed a deactivation.', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118738, 'Why would they place a consciousness into a body only to order an immediate deactivation?', 2409, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118739, 'I ordered the activation. ', 777, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118740, 'Well, can''t someone talk some sense into the Council? They''re reasonable, aren''t they?', 431, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5057, 118741, 'The situation is complex, Dr. Jackson. A deactivation does not equate to death, although it is not a preferred solution by any means.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5058, 104269, 'Even with the death of Safkhet, this place is still dangerous. She was nothing more than a bookworm with delusions of grandeur. But bigger, crazier, off-their-frigging-rocker things are going on here.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5058, 104270, 'Ra''s minions?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5058, 104271, 'Yes. And this makes some of our folks on Harset very, very nervous... Find the garrison commander and eliminate him. Hopefully his death will take the rabid nutjob factor down a notch.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5060, 69367, 'Your return is fortuitous... I have been unable to get Laro under my control. However, I have managed to plug into her monitoring systems, among others. She seems to be transferring energy throughout the world - and much of it is going to the Communications Grid. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5060, 69368, 'Why is Laro sending energy there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5060, 69369, 'I was counting on you to go out there and find out... ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119036, 'This site is home to the Free Jaffa Nation''s first great alliance, the Stargate Union. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119037, 'Welcome.', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119038, 'Unfortunately, the situation on earth makes this a bit of a secret for our guys...', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119039, 'Agent Woolsey would not approve of this.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119040, 'You''ve met him?', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119041, 'He is no warrior.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119042, 'That''s one way to put it. But... He''s the one in charge. So it limits what the SGC contingent of the SGU can do.', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119043, 'The SGU has many goals, and you will help realize our potential. You have worked with the Tau''ri before. You know their ways... This is most valuable. ', 2323, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119044, 'You have already gained their trust. General Hammond''s letter indicates this. We feel it would be beneficial for you to work amongst them.', 1333, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119045, 'Amongst the Tau''ri?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119046, 'It''s difficult for us to send SGC members through the gate. There''s red tape and... It''s just messy. However you can do just about anything you want...', 431, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119047, 'It makes you a perfect liasion for those elements of the SGU who are under close scruntiny from their less-enlightened superiors.', 777, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119048, 'Do you agree to act as liasion?', 1333, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119049, 'I will do as you wish. ', 0, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5061, 119050, 'Excellent. Report to Colonel Carter on Beta Site. She is the commanding officer on that world and she is a part of the SGU. ', 1333, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5066, 106056, 'We see you have returned with Supreme Commander Thor at your side. ', 2509, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5066, 106057, 'I wish to petition the Council to reconsider their earlier deactivation order.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5066, 106058, 'I am here to support this request. The SGU mission has extreme personnel requirements. This operative will be very useful.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5066, 106059, 'We wish to hear directly from the petitioner...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5067, 106031, 'We remain displeased with your behavior. However, your actions were taken in a good faith attempt to save lives. ', 2509, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5067, 106032, 'I appreciate your mercy.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5067, 106033, 'Understand, in the future we do not wish to discover that you have deviated from official mission parameters. Such a discover will reactivate the decree.', 2509, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5067, 106034, 'Understood.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5067, 106035, 'We encourage you, Thor, to use this operative in ways that might help us discover the solution to the Genome problem.', 2509, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5067, 106036, 'That is the stated directive of the Asgard mission with the SGU. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5067, 106037, '$name$, report to Commander Thor on Omega Site. The decree is hereby suspended. ', 2509, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5069, 101702, 'UNUSED DIALOGUE
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5070, 69370, 'Welcome, under-evolved gate-traveler, what is your request?', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5070, 69371, 'What is going on here Laro? ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5070, 69372, 'I am unable to understand your enquiry. I suggest that you clarify by increasing your language specificity. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5070, 69374, 'You are not authorized for access to that information.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5070, 69375, 'You''re not going to answer any questions about the energy beings, are you?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5070, 69376, 'You are not authorized for access to that information.', 417, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5071, 101998, 'On my little sojourn I found signs of where Trik''na was headed. I''ll giving you the coordinates. Start a search pattern there and track him down. Once you locate him bring him back here and we''re head home.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5072, 102065, 'You''re never going to get anywhere on this world with this large an enemy presence. We need a distraction.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5072, 102066, 'I can set the Jaffa''s drones against them...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5072, 102067, 'I like it. That will keep them busy for awhile. Traditionally the Goa''uld program their drones from a main system... If you can find that you can hack them pretty easily.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5072, 102068, 'Do they use security crystals?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5072, 102069, 'Yes. But you can get one from one of the active drones. Once you have the signal tweaked, just broadcast the new drone orders and viola! Chaos.', 1959, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5073, 109583, 'Give Trik''na a proper burial.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5074, 118874, 'This corpse has been forgotten here in the dirt. No Jaffa deserves to be left like this. You resolve to bring Trik''na''s body back to his father, Ras''nor for proper burial. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5075, 110999, 'You continue to act with honor. I am in your debt. My son should be buried in the traditional burial grounds. Yet... I am sorry... When I look at his face... ', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5075, 111000, 'I shall bury him for you. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5075, 111001, 'I should do it myself... Until this very moment there was hope that he lived... And his body already decays.', 716, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5075, 111002, 'Shall I perform Prin''mak?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5075, 111003, 'It is too late for Prin''mak, rest his soul.', 716, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5076, 109590, 'Thank you... My son''s dignity has been preserved. ', 716, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5078, 102384, 'I have a little something for you. You mentioned someone - or something - called Saarthon? ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5078, 102385, 'Yes. He was in Trink''na''s notes...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5078, 102386, 'Our communications team has overheard some Jaffa transmissions regarding him, and it sounds like he''s at some sort of archeological dig. I''ve uploaded the location to your PDA. ', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5079, 109687, 'Test the cure you found on Men''fa to make sure it works. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5080, 118875, 'We must test this cure immediately. Here are the scanner and the injector. Find a willing Jaffa in Beta Site and then bring the result back here. We do not have much time... The sickness has spread to other worlds... We have word it has manifested on Chulak. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5081, 109705, 'The Asgard technology is still a little tricky to use. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5082, 109690, 'You are certain you applied this scanner to a once infected Jaffa?', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5082, 109691, 'Yes. I am sure.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5082, 109692, 'The cure is effective. All signs of the nanite poisoning are gone from that Jaffa. They are completely healed... Inform Bra''tac that I can have quantities of it available very soon. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5083, 109684, 'This is most excellent news... We will begin to distribute the cure as soon as it is available. You have saved many, many Jaffa lives. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5084, 85956, 'Remove dangerous tech from Omega Site.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5086, 118742, 'The humans have amassed a significant amount of potentially dangerous technology over time. In some cases this technology is Asgard in design. They are not evolved enough to have access to this type of technology.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5086, 118743, 'So we should remove it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5086, 118744, 'You will move through the Omega Site and identify potentially dangerous technologies. You will tag them with this device. Our disposal personnel will then beam them out. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5087, 106072, 'There is some interference here. You will need to adjust the tagging device to send out a proper signal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5088, 103966, 'UNUSED DIALOGUE', 1777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5089, 106073, 'Your efficiency is noted, $name$. Despite an initial response of frustration, you have helped save the humans from themselves. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5090, 120367, 'Seek out Marlaat and see if she is willing to help on Dakara.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5091, 118876, 'The situation here is dire. Ra''s Jaffa are powerful and our numbers are limited. ', 1333, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5091, 118877, 'I will join you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5091, 118878, 'Indeed, you will. But you just one warrior and we need many. I have heard word of some discontent amongst the Goa''uld Opheltes''s Jaffazon warriors. Seek out a Jaffa called Marlaat.', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5091, 118879, 'She will help us?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5091, 118880, 'We must try. The Jaffazon are legendary in their skill, and even a few reinforcements will improve morale of the troops we already have. ', 1333, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5091, 118881, 'I will seek her out.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5092, 109754, 'I do not know you. ', 2540, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5092, 109755, 'You know of Teal''c?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5092, 109756, 'Perhaps.', 2540, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5092, 109757, 'He sent me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5092, 109758, 'I do not believe you.', 2540, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5093, 109743, 'What is Teal''c''s offer?', 2540, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5093, 109744, 'Allegiance. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5093, 109745, 'We will be welcomed into the Free Jaffa nation?', 2540, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5093, 109746, 'As valued warriors. And equals.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5093, 109747, 'I will find willing Jaffazons. There are many who feel our Lord misuses us as slavers. I will inform you when we are ready.', 2540, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5094, 109748, 'This is excellent news, $name$. Your skill as a politician is most surprising. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5095, 69813, 'Find information about O"Neill in the SGC.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5096, 118745, 'The human O''Neill is missing. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5096, 118746, 'O''Neill?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5096, 118747, 'Ah, yes - you cannot have known of him. He is a primary contact for our race and the humans. I have grown to trust him more than any other of their species. The humans claim he is missing, but I fear they have shared all the data they have on the matter.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5096, 118748, 'Is there a way to gather improved data?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5096, 118749, 'Go to the SGC. I have already cleared your arrival with General Hammond - another trustworthy human - so entry to the facility will not be problematic. Access their computers and gather all the information you can about O''Neill''s disappearance. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5096, 118750, 'Will they let me access their computers?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5096, 118751, 'Hammond is likely to allow access. He was the one who created the SGU here on Omega Site. He is sympathetic to our race.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5097, 85985, 'Access to the computers isn''t something I have control of. You''ll need to convince Mr. Woolsey to let you log in.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5097, 85986, 'Is this Mr. Woolsey sympathetic to the Asgard?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5097, 85987, 'No. Mr. Woolsey is a headache.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5098, 106452, 'You expect me to just let you access our database? An ALIEN? I don''t think so.', 2963, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5098, 106453, 'This will benefit both of our races.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5098, 106454, 'You''re going to have to concoct quite a story to make me even consider giving you access to our data.', 1300, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5099, 93544, 'Fine. Access the computers. But you better do it quickly before I change my mind.', 1300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5100, 106400, 'These will be most useful. Hopefully this is their complete record. General O''Neill is a very important human. To lose him, is to lose a valuable asset.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5101, 87799, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5102, 87800, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5103, 87801, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5104, 87802, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5105, 87803, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5106, 87804, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5107, 102576, 'Safkhet''s lab is known to us. None of our people have been in there, but we recovered some information from captive Jaffa.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5107, 102577, 'What did they say?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5107, 102578, 'Her First Prime has the key. You''ll have to convince him to give it up.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5107, 102579, 'I assume he is not a negotiator?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5107, 102580, 'He and his crazies knocked out one of our recon teams. These Ra Jaffa are fanatics. ', 1959, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5107, 102581, 'When I get the key from the First Prime I can get into the lab?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5107, 102582, 'Yes. And please hurry. This world keeps waking up... ', 1959, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5108, 104186, 'Amidst the love notes to Ra and endless descriptions of Safkhet''s devotion to him, she does mention a Hall of Secrets... The more you delve the more you realize that the Mouth of Ptah is probably in this hall.', 2015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5108, 104187, 'There is also mention of an activator key - a crystal of some kind... It''s likely you''ll need this to turn the machine on... Given Safkhet''s ramblings, she probably has it.', 2015, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5109, 86057, 'Investigate the ruins on Beta Site.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5110, 118752, 'Mimir has informed me that the Ruins on Beta Site once belonged to Ra. It is possible that these areas may contain samples of his technology. This scanner is difficult to use, but it can identify the technology signature of Ra''s design, even if there is no actual energy emission.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5110, 118753, 'I shall search all the areas where Ra''s relics have been recovered.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5110, 118754, 'The scanner has a limited range. You will need to use it at each location.', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5111, 86035, 'This rock formation is identified as Ra technology, but the scanner seems to indicate that it must be destroyed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5112, 86036, 'This rock formation is identified as Ra technology, but the scanner seems to indicate that it must be destroyed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5113, 106593, 'The scanner indicates you discovered Furling Carapace formations on the world. This is most interesting.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5113, 106594, 'Furling Carapace formations?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5113, 106595, 'Before they left this dimension, Furling aspects existed in this dimension only through the use of Carapace Formations. There is a standard protocol that defines that these are to be destroyed when encountered.', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5113, 106596, 'Why is does this protocol exist?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5113, 106597, 'I do not know. The Carapaces are not organic in nature, but it is possible they can be compromised by a primitive society in some way. Typically destruction protocols protect primitive societies.', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5114, 109772, 'Help build a rapport with A''lem.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5115, 118882, 'Trust does not come easy to A''lem. Yet, we need her to trust us. You must seek her out and earn that trust. Be warned, she may test you. ', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5116, 109862, 'I do not recognize you, Jaffa. Even if Teal''c sent you, I am not one who simply trusts based on the word of another. ', 770, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5116, 109863, 'Let me prove my worth. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5116, 109864, 'What benefit would this give me?', 770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5117, 109814, 'You realize... While the mines may affect Ra''s troops, the reality is that they will most certainly prevent any real counter-attack from being successful. You decide to hold off on planting the mines until you consult with A''lem. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5119, 109793, 'An astute observation, $name$. I will re-assess that avenue for a future counter attack. I believe I was thinking too defensively. ', 770, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5119, 109794, 'Your strategy would have worked...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5119, 109795, 'Only in the short term. Your tactical sense is strong. Thank you. ', 770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5120, 109813, 'A''lem''s failure to see the potential problems with her plan concern me. She is quite capable, but sometimes her inexperience presents problems.', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5121, 109879, 'Recover genetic samples from Ra''s Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5122, 118839, 'I have heard stories of an abomination. Ra has been modifying his Jaffa genetically.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5122, 118840, 'I saw similar things in Ihpet.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5122, 118841, 'The Jaffa are a people formed out of another - for generations human slaves saw us as the abomination. But Ra''s modifications are more drastic than anything I have seen before.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5122, 118842, 'Is it desperation?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5122, 118843, 'I fear it may be inspiration. Use this Genetic Sampler and gather flesh samples from Ra''s Jaffa on Dakara. Bring them back to me and I will work with Heimdall and Colonel Carter to try and discover how severe the modifications are. ', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5123, 109878, 'Your diligence is appreciated. I will pass these samples to the science team. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5124, 103281, 'Laro fixed the facility? Why would it do that?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5124, 103282, 'She must need it in some way...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5124, 103283, 'So you are telling me that the mission wasn''t completed? ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5124, 103284, 'Goldam assured me it was.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5124, 103285, 'Well, I suggest you do not return here until you confirm - with your own eyes - that the mission is complete this time. ', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5124, 103286, 'Understood. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5125, 87642, 'Meet Marlaat and bring her Jaffazon defectors to Teal''c.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5126, 118883, 'We are prepared. I was able only to gather a few warriors.', 2540, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5126, 118884, 'Can you come to Dakara?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5126, 118885, 'I will need assistance getting off Lucia. I will upload the location of a safe meeting place.', 2540, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5126, 118886, 'I will be there. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5127, 120371, 'There was an ambush?', 2226, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5127, 120372, 'Marlaat was dead. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5127, 120373, 'And the call to you was a trap, no doubt. This is unfortunate. Jaffazon warriors would have helped us against Ra''s forces. ', 2226, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5128, 86139, 'Deliver Tretonin to Heimdall.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5129, 110226, 'Contact Oshu and convince him to join the Free Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5130, 118755, 'The Tretonin sickness here is severe. Thor has ordered me to have you collect materials for Heimdall so that we can analyze the nature of the toxin.', 730, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5130, 118756, 'Nature of the toxin?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5130, 118757, 'The belief is that the sickness is some sort of advanced poison. It is possible it may be technological or synthetic. ', 730, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5130, 118758, 'The materials we collect will help us determine this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5130, 118759, 'Correct. The Jaffa tissue samples must come from those who have succumbed to the sickness. Sadly, this will not be difficult to find on Beta Site.', 730, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5131, 118829, 'Lord Yu was a very powerful System Lord, but toward the end of his life his judgment was often suspect. His First Prime, Oshu, was often in charge of his world during Yu''s frequent absences. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5131, 118830, 'You knew Oshu?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5131, 118831, 'Yes. He was a worthy warrior. While he tends toward the old ways, he might be convinced to join us. Yu''s Jaffa army was large - amongst the largest in the galaxy.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5131, 118832, 'I will seek out Oshu on Pen Lai. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5131, 118833, 'Be careful. He is a considerable warrior. If he sees you as a threat, you may be in danger. ', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5133, 104205, 'Safkhet probably has the activator crystal for the Mouth of Ptah. One way or another you will need to get that key from her.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5134, 110466, 'Oshu was not willing to give into Ra''s demands. He was forced to go into hiding.', 2543, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5134, 110467, 'Can you tell me where he is?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5134, 110468, 'If you are worthy. ', 2543, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5134, 110469, 'Shall we prove our worth in Runk''an?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5134, 110470, 'Yes.', 2543, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5135, 106645, 'There are signs of advanced tissue degeneration. These Jaffa have been affected by a very advanced technology. Whatever applied this toxin to the Jaffa was an extremely capable bio-geneticist. ', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5136, 110487, 'Bra''tac? Yet he sends you? Clearly he has forgotten with whom he is dealing.', 2544, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5136, 110488, 'No. He knows you are an honorable warrior. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5136, 110489, 'He has failed to act in such a way. ', 2544, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5136, 110490, 'He wishes that you join his alliance... Is there a greater sign of respect?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5137, 110494, 'I will consider a meeting. Inform Bra''tac of this. ', 2544, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5137, 110495, 'He will be pleased.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5137, 110496, 'You have impressed me, <<playername>>. I will not forget you.', 2544, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5138, 110497, 'This is excellent news. With each day the Free Jaffa Nation grows stronger, in large part because of you. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5138, 110498, 'It is my duty.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5138, 110499, 'If the rumblings are true about the Loyalist Jaffa, we may need all the warriors we can find.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5141, 104210, 'The device is like nothing you''ve ever seen - an almost arcane technology that exudes power. You decide to use the activator key you got from Safkhet - there is a place for it right on the console. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5143, 102713, 'You have what you are certain is the cure for the Tretonin Virus. The best chance the Jaffa have is for you to take it back to Heimdall on Omega Site. The Asgard can mass produce large quantities of the cure quickly.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5144, 102865, 'In Trink''na''s notes you find reference to a safe in a nearby crypt - Hor-Aha. His notes indicate that he believed he could find copies of Ra''s decrees - decrees which his minions are using as orders. The crypt itself is nearby...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5145, 103449, 'Use the Reins of the Sun Chariot on the Furling Carapace. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103450, 'This victory is temporary, you know that...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103451, 'We''ll keep fighting. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103452, 'And you will lose. My research has shown me something: The Straegis are not just related to the Furling - they ARE the Furling. Pieces of it. Ra has, somehow, managed to access the Furling and he is ripping pieces of it away.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103453, 'The Straegis are Furling... Bits?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103454, 'Elements... Themes... It''s all very complex - I am not completely clear on it. The point is, they are infinite. The Straegis will never stop coming. It is an army that can never be killed, because it does not die. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103455, 'Then what do we do?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103456, 'You have to reach the Furling itself. The device you showed Laro - the Reins of the Sun Chariot - can do that... But you would need something else.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103457, 'What?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103458, 'A carapace... You can summon the Furling, but the individual aspect will sustain only with technological help... They used shells - carapaces - to sustain their aspects. ', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5146, 103459, 'I need to get to Harset.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74896, 'The Straegis are the Furling?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74897, 'They are pieces of it. Goldam called them themes. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74898, 'This is all very confusing. ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74899, 'The point is, in order to stop Ra we must cut his army off at the source... ', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74900, 'And the Furling knows the source. ', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74901, 'I''m still confused. ', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74902, 'Try to pay attention, please, Queen Anat... We must bring the Furling Carapace we recovered from the SGC here, at once. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5147, 74903, 'It was placed in the Storage facility. ', 968, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5148, 86160, 'UNUSED DIALOGUE', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5149, 86161, 'UNUSED DIALOGUE', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5150, 86167, 'UNUSED DIALOGUE', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5151, 86168, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5152, 102924, 'It looks like the Goa''uld are excavating an archeological site here on Men''fa. We''re getting high radiation readings from the area. It''s a longshot but... It''s possible that this work is related to the nanotoxin on Beta Site in some way. ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5152, 102925, 'How so?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5152, 102926, 'Radioactive soil might mean it has special properties that were used... Like I said, it''s a longshot. But it''s worth a look.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5152, 102927, 'I will look into it.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5153, 104319, 'We think we''ve located a dig site - could be where the Mouth of Ptah is located. Check out the site and bring me back a soil sample...', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5153, 104320, 'You think the Mouth of Ptah is a natural phenomenon?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5153, 104321, 'I have no idea what it is. Neither do you... But it could be made out of weird dirt. I''ve seen stranger things... So you get to check this out and bring back some samples.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5154, 86238, 'Gather Unas corpses.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5209, 98473, 'Ra can trace it. When you use it, it will connect you to Baal and myself. You will be targeted. ', 2546, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6340, 120081, '<Input text here.>', 3581, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5155, 118760, 'This Unas is not standard. Clearly Ra has modified it in some way which has altered it at a fundamental genetic level. These techniques may prove worth looking into as a means of solving your species'' own genome problems. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5155, 118761, 'You resolve to collect modified Unas flesh samples and prepare them for delivery to Heimdall. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5156, 86241, 'Interesting. Ra''s DNA modification utilizes techniques I have never before seen. This may prove quite useful indeed. ', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5157, 103028, 'This Goa''uld, Safkhet might have valuable insight into Ra''s technology. Look into her work and extract what you can. If we can find a way to understand what he was doing here, it might provide a hook for Heimdall in his search for a cure.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5158, 86276, 'Obtain Arlos''s necklace.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5159, 118762, '(You notice a necklace around Arlos'' neck... He doesn''t know it yet, but he is wearing Pocket Black Hole technology. If he accidentally activates it, it could swallow several hundred meters'' worth of terrain.)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5159, 118763, '(You need to seperate this trader from his shiny, deadly necklace.)', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5160, 86261, 'You''re interested in this necklace? Why?', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5160, 86262, 'I find the external pattern on the metal pleasing.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5160, 86263, 'Well, I can''t just sell it. It''s very valuable to me. I got it for my birthday.', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5160, 86264, 'Would you accept a trade?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5160, 86265, 'A trade... Hmmm... Of course... But, I want something very specific. The Red Collars recently uploaded specifications for modifying an armor technology used by Tech Con Group. Bring me those specs and we have a trade.', 480, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5161, 107246, 'You got the specifications?', 480, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5161, 107247, 'Indeed.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5161, 107248, 'Then we shall trade. Enjoy your pleasing pattern.', 480, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5161, 107249, 'Enjoy your specifications.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5162, 107241, 'These humans... How have they managed to survive this long without destroying themselves?', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5163, 104854, 'Saarthon revealed that Ra''s Jaffa have some new-fangled tech in their weapons. This has made Bra''tac and Teal''c nervous - apparently they worry that a revived Ra cult could draw potential recruits away from the Free Jaffa...', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5163, 104855, 'Is that likely?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5163, 104856, 'It doesn''t matter. We are here to do or die, not to reason why. Bring back a sample of the weaponry so we can give it to the science team for examination. Destroy the rest.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5164, 102779, 'So, they told me this was a dead world... Not so much. There are Jaffa. Crazy Ra loving Jaffa coming from somewhere. While you''re out there...', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5164, 102780, 'You want me to investigate?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5164, 102781, 'If you get a chance. They are coming from somewhere... I just need to be able to tell Command so we can get some informed decisions from them. ', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5164, 102782, 'I will look into it if I get a chance. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5165, 104376, 'I have been informed by Heimdall that the Goa''uld have been performing genetic research on Men''fa. The nature of the research leads me to believe that this information may be helpful towards finding a cure for our condition. You must go to Men''fa and learn what you can of this research.', 2050, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5166, 110500, 'Investigate Cronus'' ruins on Omega Site.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5167, 118826, 'There have been rumors of Jaffa in the Ruins behind the human settlement here on Omega Site.', 1333, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5167, 118827, 'Could it be Cronus'' Jaffa? They see this entire planet as sacred.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5167, 118828, 'It is possible. However, it is also possible that it is something else. I find myself concerned. Check the area and return to me. ', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5168, 110519, 'These orders are from Ra. That transmitter was a locating beacon. ', 1333, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5168, 110520, 'What does it mean?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5168, 110521, 'Ra has taken an interest in Omega Site. A violent interest.', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5169, 110667, 'Find the suicide bomber.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5170, 118887, 'We have received word of something quite disturbing. Loyalist Jaffa have inflitrated Omega Site.', 1333, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5170, 118888, 'An invasion?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5170, 118889, 'Terrorism. They have come to commit suicide with bombs strapped to their backs. The Asgard have provided us with this scanner. It will identify explosive devices. Move quickly. ', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5171, 120277, 'I serve no one. Ra''s return has proved to me that he was the one true God. The fool Moh''katan was unwilling to sanction our deaths because she cannot see the glory of Ra. ', 2573, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5171, 120278, 'But this achieves nothing.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5171, 120279, 'I can bask in his glory. That is my achievement.', 2573, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5172, 110903, 'I cannot go to prison. While you may have convinced me there is no honor in my endeavor, I cannot live in a cage.', 2573, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5172, 110904, 'I cannot let you go free. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5172, 110905, 'No. You cannot. So you must kill me. Dying honorably is my only hope of redemption in Ra''s eyes. I must die in battle. ', 2573, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5172, 110906, 'As you wish.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5173, 110888, 'I do not think this act was sanctioned by Ra. While he is not above terrorism, he rarely acts without reason. These suicides were fool''s errands. ', 1333, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5173, 110889, 'I am not convinced Ra even knows of them.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5173, 110890, 'It is likely he does not. They were Loyalists in the army of Moh''katan. Clearly her army is suffering a crisis of loyalty. ', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5175, 103651, 'It looks like you may be able to intercept that data at the hub buffer...', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5176, 103656, 'The buffer is even more complex than the hub, but you begin working quickly... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5177, 103653, 'You manage to extract the answers and upload them to your PDA.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5178, 71646, 'Inform Hammond about the Lucian outbreak.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5179, 118764, 'We must test human compassion. While we know that they have shown great capacity for it in the past, the return of Ra is a massive distraction. We must test them to see if they are capable of maintaining compassion in a crisis. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5179, 118765, 'How do you propose we do this?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5179, 118766, 'We will create a false crisis. Specifically, we will inform General Hammond of a potential plague ravaging the human slum-dwellers of Lucia. We will observe the human response to this crisis.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5179, 118767, 'What if they demand proof of the crisis?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5179, 118768, 'Use this tool on any samples they require, it will give the impression of a disease the humans have a known cure for. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5180, 86501, 'Are you certain about this?', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5180, 86502, 'Humans in the slum areas have reported loss of life. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5210, 98468, 'You should speak to Ba''al before leaving the Implantation Chamber.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5180, 86503, 'If you can provide me with samples we can run them against our database here and see if we already have some sort of cure. If there''s something we can do about it, we will do it.', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5181, 86504, 'You begin modifying the samples. The process is trickier than you thought it would be.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5182, 86505, 'Hammond''s commitment to a cure is encouraging. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5182, 86506, 'What if they utilize resources to cure this disease?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5182, 86507, 'They will have wasted them, but we may see them as a trade-off. If the humans prove to be worthy replacements for our people once we are no longer viable, this resource expendeture will be forgiven.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5183, 86508, 'We''ll get these looked at. If we need to get medicine to these people, we will get it done.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5184, 86557, 'Help the humans handle the "outbreak".', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5185, 118769, 'The human response to our simulated infection exceeded expectations. They have expended significant resources and are preparing an SG Team for a mission.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5185, 118770, 'They will discover there is no outbreak.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5185, 118771, 'The disease we simulated is carried by local insects. They will first test the local water. Contaminate the water with this agent. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5185, 118772, 'We are going to cause a genuine outbreak?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5185, 118773, 'No. The agent in the water falsely indicates the presence of the disease. You will then help distribute the "cure" to some of the local humans. The cure itself is harmless. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5186, 110907, 'Find Alasha and bring her to Ras''nor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5187, 118890, 'The attack came quickly... We lost many Jaffa. These creatures attack with such coldness...', 1013, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5187, 118891, 'They are incredibly dangerous.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5187, 118892, 'I sent my son Senl''c after Alasha - we lost her during the initial assault. If you can assist him in finding her, that would bring me confort. ', 1013, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5187, 118893, 'Where was he?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5187, 118894, 'He believed she was in the Shoul''ja settlement. He went there for her. ', 1013, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5188, 110913, 'I came here to find Alasha and ended up trapped here. ', 2495, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5188, 110914, 'Where is she?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5188, 110915, 'I think she was swallowed up in the initial attack. She''s in the Shoul''ja settlement. ', 2495, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5188, 110916, 'Stay here with your people. I will try and find her...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5188, 110917, 'I will accompany you.', 2495, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5188, 110918, 'No, you need to stay here... You are needed. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5189, 110937, 'Alasha''s corpse lies dead, discarded by the Straegis. You gather up her broken body in order to take it to Ras''nor. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5190, 110923, 'She is dead... This is indeed a tragedy for our people. She was our Kal''tra.', 1013, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5190, 110924, 'Then her body must be ritualized.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5190, 110925, 'Yes. She must have Prin''mak. And we do not have much time. ', 1013, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5191, 103856, 'The container should be here, but has clearly been moved. It is likely the Burtonol invaders took it. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5192, 107488, 'We''ve got enough medicine here to cover the entire village population...', 2505, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5192, 107489, 'You may require all of it. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5193, 107457, 'The human response was impressive. They are a species which never fails to surprise me.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5194, 107503, 'The pathogen slowly seeps out of the barrel and into the water supply.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5195, 103925, 'The signal orginates from a nearby region on Agnos. Burtonol must have set up camp there. That must be where the container is now.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5196, 111071, 'Interr Alasha according to the ritual of Prin''mak.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5197, 118895, 'We must get her to the burial ground. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5197, 118896, 'A leader cannot leave during a battle. I will take her...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5197, 118897, 'And do Prin''mak? You indeed carry yourself with great honor, $name$. Here is the urn. Our people are grateful.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5202, 111236, 'The preparations are made...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5204, 111225, 'My mother would thank you.', 1013, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5204, 111226, 'It was an honor.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5205, 71846, 'Destroy Kassa stalks on Lucia.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5206, 118774, 'The human addiction problem with Kassa is troubling. Despite the economic benefits, the drug disables humans and inspires criminal conduct.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5206, 118775, 'Lucia is rife with it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5206, 118776, 'Yes. I wish to reduce prevalence of the drug on that world. Use this Neutralizing Agent on the Kassa stalks in the Green Boot farm area. Invisible at first, this will render the crops impotent.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5206, 118777, 'The humans will not immediately recognize the problem.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5206, 118778, 'Correct. They will attribute the failed crop on weather or improper care. In the meantime we will have cut the production of the drug significantly. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5207, 86596, 'Your efficiency is noted. I do have a concern over the Green Boot leader, Netan. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5207, 86597, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5207, 86598, 'His ambition concerns me. He is a very capable leader. Humans whose focus is on their own self-interest can be quite destructive when their ambition goes unchecked. We must watch him closely. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98459, 'You gained control sooner than I''d hoped. Can you speak yet?', 2545, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98460, 'Yes. I think so...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98461, 'We have little time. We must move quickly before Ra discovers us. He has imprisoned your queen, Anat, for creating New Mind Goa''uld like you. You''ll be killed if he discovers you.', 2545, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98462, 'Is she safe?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98463, 'No. None of the New Mind are. I implanted you in this host body to be my spy - it was intended for one of Ra''s spawn. He''ll think you are one of his children, which will let you get close and discover where he is holding Anat. ', 2545, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98464, 'Yes. You need Anat freed before Ra learns that you''re connected to this. I take all the risks and you stay safe.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98465, 'Your very existence is a risk. The New Mind were conceived as a threat to Ra. He knows this. You have no choice but to help me.', 2545, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98466, 'You''re sending me to die.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5208, 98467, 'Your very existence is a death sentence. This host body is the safest place you can be - as long as Ra believes you are his child. Now, find Lethander. We have to get started. ', 2545, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5209, 98469, 'Lord Ba''al has explained the situation?', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5209, 98470, 'I must go pretend to be Ra''s child.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5209, 98471, 'It is the only way to free Anat. I would do it, but Ra already suspects me. Here, take this communication sphere and this ribbon device. Use the sphere only in an emergency.', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5209, 98472, 'Why only in an emergency?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5211, 98491, 'The Door to the Implantation Chamber slides back.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98492, 'Once Lethander and I are gone, you must erase all record that this ring transporter was activated. Don''t give Ra any reason to suspect you.', 2545, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98493, 'A ring transporter being used will make him suspicious?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98494, 'Ra is the Supreme System Lord of the Goa''uld for a reason: He is a paranoid of galactic proportions. Everything makes him suspicious. Be careful.', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98495, 'Ra has discovered technologies that he refuses to share. It makes him capable of things we cannot predict. ', 2545, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98496, 'Why do I think this is all a giant setup?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98497, 'Because you are the child of your Queen. And she, like you, believes everyone cannot be trusted. However, you have no choice. You must eliminate the Jaffa who carries the Ra symbiote intended for your host body. He will arrive soon...', 2545, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98498, 'You wait until now to tell me?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98499, 'If you''d like you can wait and see what happens when they try to implant it in the host you''re currently occupying... ', 2545, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98500, 'I get your point.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5212, 98501, 'Make sure to dispose of the symbiote once the Jaffa is dead.', 2545, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5213, 72581, 'Clear the way for Ba''al and Lethander to escape from the Temple.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5214, 98484, 'You have secured the ribbon device from Lethander... Beyond that door is the ring transporter that Lethander and I must use to escape. We snuck in during a guard change - by now it will be watched.', 2545, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5214, 98485, 'You want me to distract the guard?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5214, 98486, 'Something more permanent than distraction.', 2545, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5214, 98487, 'You want me to attack an armed Jaffa?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5214, 98488, 'No, I want you to kill him. He thinks you are some peasant slave. He knows your human host was intended for Ra''s spawn and will hesitate to destroy it. You have the advantage.', 2545, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5214, 98489, 'And where will you be while I''m out there, with the advantage?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5214, 98490, 'Lord Ba''al is not allowed here, and Ra has already decreed that I am to die. If the Jaffa sees either of us, he''ll attack. He will leave you alone - giving you the advantage of surprise. Listen to Baal. Please.', 2546, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5215, 98504, 'You activate the ring transporter - teleporting Ba''al and Lethander out of the Temple.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5216, 98503, 'You manage to erase all record of the ring transporter being activated.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5217, 104150, 'According to the readings, everything looks good. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5218, 98505, 'You can''t carry the symbiote around with you. You need to dispose of it quickly. Symbiotes don''t respond well to fire... Perhaps you can use one of the braziers in the hallway...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5219, 98506, 'You place the symbiote in the fire. It begins squealing as the flames consume its fragile body. Slowly the quivering stops... Mission accomplished.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5220, 98507, 'You cannot present yourself to Ra in the slave''s rags your host wore. Find clean clothing to wear in the piles lying about.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5221, 98509, 'You select clean clothing from the pile. Clean is about the best thing you can say for this fashion disaster... Still, it is probably what Ra would expect.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5222, 98510, 'Prevent Ra''s Jaffa from discovering his two dead minions by reprogramming the door to the robing room.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5223, 98508, 'You cannot present yourself to Ra wearing peasant''s rags. You should find better clothing in the Robing Room before you leave.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5224, 72222, 'Mogilny. Glad to see you''re not dead.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5224, 72223, 'It''s not for lack of Command trying. Men''fa was filled with Jaffa and this place is filled with Unas. I hate Unas. And watch yourself; these are more aggressive than any I''ve ever dealt with before. We''ve got the gate area secured so we have your back.', 1959, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5224, 72224, 'Thanks. Anything else?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5224, 72225, 'We located a possible energy source, some writing called the "Wall of the the 13th Hour" or something. Maybe that makes sense to the bookworms. Anyway, we didn''t want to press our luck and stir up the Unas so we didn''t investigate any further in, but at least you''ve got a starting point. And here''s a camera if you need to upload any images for analysis.', 1959, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5225, 98511, 'The door to the Robing Room closes behind you.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5226, 98513, 'You''ve reprogrammed the door controls so that the door cannot be opened from this side - conveniently hiding the dead beyond it. It will take another Goa''uld to fix the controls, and additional time for a Jaffa to convince one of them to look into it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5227, 86618, 'UNUSED DIALOGUE', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5228, 86617, 'UNUSED DIALOGUE', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5229, 86619, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5230, 86620, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5231, 86622, 'UNUSED DIALOGUE', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5232, 98514, 'Kneel before your god.', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5232, 98515, 'Yes, Supreme Lord Ra.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5232, 98516, 'Jaffa, kree! Behold my child, the god Onuris. Bow down and show reverence.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5232, 98517, 'I am Onuris...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5232, 98518, 'System Lords of the Goa''uld! Know that Onuris speaks with my voice. Rise Onuris, and greet your peers.', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98536, 'Onuris, isn''t it? That speech was very impressive, wasn''t it? It must feel good for Supreme Lord Ra to welcome you that way.', 2549, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98537, 'I am pleased that my father places his trust in me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98538, 'He gave the same speech for poor Nefer, you know. Then he failed to capture Lethander.', 2549, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98539, 'What became of him?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98540, 'He was tied to a post and eaten by rodents.', 2549, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98541, 'Excellent. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98542, 'I am Safkhet, Supreme Lord Ra''s personal scribe. I record everything about him: the tribute he receives, the enemies he defeats, the wisdom he chooses to share, every commandment he gives. . .', 2549, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98543, 'Like the one he just gave to treat my voice as his own?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98544, 'Precisely. I recorded that command. Just like I did for Nefer, and just like I''ll do for whoever comes after you. His children come and go, but I''m always here.', 2549, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98545, 'You mentioned Lethander...', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98546, 'He was loyal to Anat - Ra''s former Queen - and now he must be killed. It is Ra''s wish.', 2549, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5233, 98547, 'What became of her?', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5234, 98548, 'Supreme Lord Ra told Nerus to take her away, and that''s the last he''s mentioned her. He does not mention those who do not matter.', 2549, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5234, 98549, 'Where did Nerus take her?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5234, 98550, 'What does it matter? Ra got rid of her as soon as I told him what she was doing. He trusted her and she betrayed him with her abominations.', 2549, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5234, 98552, 'Vermin. We must kill them on sight. It is Ra''s wish.', 2549, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5234, 98553, 'Ra kills a lot of things.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5234, 98554, 'It is his nature. He maintains order this way. It is quite impressive, his commitment to order...', 2549, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5235, 111311, 'Collect Android specifications for Teal''c.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5236, 118898, 'I have received word that Laro, the Artificial Intelligence that runs Agnos, utilizes android workers. Is this true?', 1333, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5236, 118899, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5236, 118900, 'Many of our people have difficulty seeing us beyond our warrior heritage. Moh''katan, Bra''tac''s daughter, has drawn many warriors to her Loyalist army because of this. ', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5236, 118901, 'Many Jaffa wish only to tend to the duties of a warrior.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5236, 118902, 'Indeed. Yet a free society needs more than just warriors. Androids could perform duties that traditional minded Jaffa disdain. Secure the schematics for Laro''s Androids. ', 1333, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5236, 118903, 'We may be able to manufacture them ourselves?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5236, 118904, 'This is my thinking exactly, $name$.', 1333, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5237, 111293, 'Your request cannot be met. You are not sufficiently evolved to access this data. This information is likely to result in a warfare-based application of the data. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5237, 111294, 'That is not our intention. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5237, 111295, 'Your intentions are immaterial. Your species is war-like. You cannot escape your nature. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5238, 111281, 'Your ingenuity is impressive. I will bring the recovered Android samples and the data to Bra''tac. Perhaps our engineers can make use of it. ', 1333, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5239, 98560, 'Do not speak! You have failed me again. I do not wish to hear the words of a traitor.The slaves rebel against me, and you do not stop them? And now they have staff weapons! Stolen from my Jaffa, my armies? Onuris!', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5239, 98561, 'Yes, my Lord?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5239, 98562, 'This Jaffa has failed me. You will punish him as he deserves.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5241, 98586, 'Escort Ra to his chambers to take care of some unfinished business.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5242, 98613, 'It won''t take long for the slave army to reach my Temple. We must move quickly, my child. We must make certain that every one of Anat''s brood is destroyed.', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5242, 98614, 'Why, my Lord? Surely it would be safer for you to leave this to me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5242, 98615, 'Anat''s betrayal must be punished, her "New Mind" wiped from Goa''uld memory. No symbiote of her spawn can be allowed to survive.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5242, 98616, 'If we just deal with Anat then the New Mind will naturally perish over time...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5242, 98617, 'I am confused why you offer opinions, Onuris. I do not remember seeking them. I am this close to removing the tongue from your host body and feeding it to you.', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5242, 98618, 'I''d prefer it if you did not do that, my Lord.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5242, 98619, 'Then quietly obey. We have infidels to kill.', 2547, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5243, 98627, 'Kill them, Onuris! None of Anat''s spawn shall survive!', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5243, 98628, 'Stop them! Do not let them take the symbiotes.', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5243, 98629, 'You would steal from your god? Heretics! Onuris, kill them!', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5243, 98630, 'Anat believes she will survive her betrayal. She thinks she will live because I have never killed a Queen. I will do more than kill her. ', 2547, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5243, 98631, 'None of these New Mind can live. None.', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5243, 98632, 'Onuris! Guard the door and let no one approach. If I cannot take this prototype with me, no one else will have it.', 2547, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5244, 98636, 'Bring me a New Mind symbiote!', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5244, 98637, 'From where, Lord Ra?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5244, 98638, 'Take one from its host, Onuris. Rip it from the body if you must. I need one.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5245, 98639, 'My lord, the symbiote was damaged during the fight.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5245, 98640, 'No matter. It is whole enough for what I need.', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5245, 98641, 'Why do you need it for, my lord?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5245, 98642, 'Are you speaking out of turn again, Orunis? You are remarkably chatty. There are still New Mind prisoners in the cells. None of them shall live.', 2547, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5245, 98643, 'Yes, my lord!', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5245, 98644, '(Ra begins eating the still-live symbiote.)', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98675, 'My lord, the last of the New Mind are dead.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98676, 'Good work, Onuris. None of these abominations will escape my wrath. I''ll need more of their symbiotes...', 2547, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98677, 'To eat?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98678, 'Anat''s tampering has altered the chemical structure of her spawn. It''s subtle, but there. Consuming the symbiote allows me to analyze that difference.', 2547, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98679, 'So you can identify New Mind...', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98680, 'Correct. Or at least, eventually I will be able to... As you know, all Goa''uld recognize each other, Onuris. It is part of our nature. But Anat''s tampering has made identifying her children problematic. Consuming the symbiote will allow me to recognize her children quickly.', 2547, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98681, 'Of course...', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98682, 'I thought you said all the prisoners were dead?', 2547, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98683, 'They are, my Lord', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5246, 98684, 'Yet I sense... Others. Another. Near. Quickly, Onuris! Any survivors will seek to free Anat''s symbiotes.', 2547, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5247, 104224, 'The process seems to be working, but the signal output is weak.', 634, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5248, 98685, 'Bring me a symbiote from the tank, Onuris. An undamaged symbiote will strengthen my sense of the New Mind.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5249, 120374, 'Help Heimdall perfect a replacement for your Tretonin. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5250, 104225, 'Boosting the signal shouldn''t be too difficult...', 634, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5251, 118905, 'Heimdall has some very interesting news... He believes that he may have an alternative to Tretonin. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5251, 118906, 'This is remarkable news. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5251, 118907, 'Yes. We are quite hopeful. He needs Straegis crystal remnants - the shards - to finish the process. Collect some on Agnos and bring them here... ', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5252, 98687, 'Lord Ra, here is the New Mind symbiote from the tank.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5252, 98688, '(Ra eats the symbiote. It''s violent, filled with wriggling and moving. Blood drips down Ra''s chin.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5252, 98689, 'My lord?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5252, 98690, 'I still sense one of the New Mind... Very close. You are certain that they are all dead?', 2547, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5252, 98691, 'I believe so, my Lord. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5252, 98692, 'Bring me another. The more I consume, the more refined my sense will grow.', 2547, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5253, 111347, 'This solution should work with your chemistry to provide a simulated symbiote.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5253, 111349, 'Tretonin was used to genetically mask your lack of a symbiote. This solution literally simulates a symbiote within you. Assuming the compound is effective, you should actually feel healthier. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5253, 111350, 'How often do I need to apply the compound?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5253, 111351, 'This solution should be permanent.', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5254, 111342, 'This is excellent news... We have already instructed Free Jaffa throughout the galaxy to begin collecting the shards for use in the compound. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5255, 98693, 'The more symbiotes you bring to Ra, the more likely it is that he''ll discover you are New Mind. You need to sabotage the tank so the remaining symbiotes are destroyed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98694, 'What has happened to the tank - they perish!', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98695, 'Anat''s spawn must have set the tank to destroy itself.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98696, 'And you couldn''t tell? There was a trap and you failed to see it? All the symbiotes are destroyed.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98697, 'Forgive me, Lord Ra.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98698, 'I will never be able to refine my sense of them. If any have escaped, it will be that much harder to hunt them down.', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98699, 'But we know their supply has been destroyed... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98700, 'Symbiotes in a tank are nothing... Symbiotes inside hosts are what I fear. Your idiocy has reduced my ability to track them... ', 2547, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98701, 'Can you sense any more, my Lord?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5256, 98702, 'This room is spattered with their remains. I can sense nothing through this reek. Come! There is one last task we must see to.', 2547, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5257, 98686, 'You use the controls to open a door on the Symbiote Tank. Reaching in, you capture a live symbiote - one of your less-fortunate siblings. It wriggles violently in your hand and you grip it firmly behind the head so it cannot strike.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5258, 111371, 'See Heimdall about your sickness.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5259, 118908, 'Suddenly you feel yourself growing noticeably weaker... Your connection to the simulated symbiote seems to have faded. Something is terribly wrong. You need to see Heimdall.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5261, 111374, 'Apparently the solution is time restrictive. Unfortunately, it also seems to have modified you physiologically. I cannot re-apply the solution without risking further damage. ', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5261, 111375, 'I am willing to take that risk.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5261, 111376, 'I am not. I will supply you with Tretonin. This will balance your systems as before. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5262, 111380, 'I do not say this often but... There are times when I wonder if our people are not cursed. We have already begun to increase Tretonin production to match the projected demand. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5263, 104365, 'You discover the problem - a massive power outage forced the generators off. If you can provide them with temporary energy you can bring the systems back online. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5264, 98713, 'You reek of Anat''s spawn, Onuris. If I didn''t know better I would fear you were one them...', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5264, 98714, 'I was very close to the tank when it exploded... Their essence must have infested my clothes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5264, 98715, 'For your sake I hope that is true. This room holds my treasure, Onuris. The tribute from my slaves, and my greatest secret...', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5264, 98716, 'A secret, my Lord?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5264, 98717, 'Look around you... Somewhere in these hieroglyphs is my secret. Of course, the memories I gave you make it easy to find, right my child?', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5265, 98721, 'Well done, Onuris. Although it took you long enough... I nearly fell asleep... ', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5265, 98722, 'I have a penchant for drama, my Lord.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5265, 98723, 'You have a penchant for delay and slow-wittedness. But, no matter. Beyond is my private laboratory. Come, there is much to do inside.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5266, 104370, 'You hear the slow hum of the generators coming back to life. Using the Naquadah power sources, these generators should stay on for at least a few more days...', 2719, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5267, 98732, 'Unfortunately you''re unable to locate information on Anat''s or Nerus''s whereabouts. However, you do find a rather large encrypted file. You download it to a data crystal which you slip into your pocket for later reference.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5268, 111381, 'Collect Straegis shards for Goldam''s research.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118909, 'You are a truly amazing creature... In many ways you are the most honest form of the "fifth race". ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118910, 'Why is that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118911, 'The solutions for the fifth race were always singular - the Alterran created the human, the Furling created the Goa''uld and so on... But you - you are a hybrid of two scientific approaches. You are human, but you have been modified with Furling technology.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118912, 'Furling...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118913, 'Yes... Whoever created you Jaffa did it by fusing Furling technology with human form. Fascinating bit of DNA creativity... However, they were remarkably selfish - they made you rely on the contents of your pouches.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118914, 'We have removed the need for a Prim''tah by using Tretonin.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118915, 'Which is a masking agent. However, if we can up the Furling aspect of your DNA, it is theoretically possible that we could make your reliance on the pouch a thing of the past.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118916, 'We tried this recently with little success.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5269, 118917, 'But this time it is me you are working with. Collect me Straegis Shards - their crystal leftovers - and let me run some tests... I am certain that this theory is sound...', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5270, 98733, 'Come, Onuris. It is time for us to leave this planet.', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5270, 98734, 'Won''t one of the other System Lords try to access your secrets once you go?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5270, 98735, 'I certainly hope so. This lab will self-destruct shortly in a fiery, violent, acidic explosion. Anyone inside will die.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5271, 111392, 'I cannot do this... I understand the theory but I cannot manipulate matter the way they can... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5271, 111393, 'The way the Furling do?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5271, 111394, 'Yes. Matter is very flexible for them... We searched for years for keys to understanding that aspect of their technology. There is hope however...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5271, 111395, 'Which is?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5271, 111396, 'The Furling themselves. It is a scientific certainty that they can remove your reliance on Tretonin. You just have to get to them... ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5271, 111397, 'Where can I find them?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5271, 111398, 'They have been gone for generations. It makes the whole endeavor a bit... Challenging. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5272, 120292, 'Set''ra, kree! What are these slaves doing in my chambers?', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5272, 120293, 'I have captured these rebels in your name and glory, my god. They were in command of this rebellion.', 2551, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6341, 120083, '<Input text here.>', 3581, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5272, 120294, 'You serve me well, Jaffa. Onuris, dispose of these traitors. Set''ra, come with me.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5273, 98737, 'Jack!', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5274, 98738, 'You serve me well, Onuris. It pleases me to reward you. Jaffa, kree! You may choose one of these Jaffa to serve you. Let this be the beginning of your personal guard.', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5274, 98739, 'You honor me, Lord Ra.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5274, 98740, 'Set''ra, kree! You will bring Anat to me aboard my Hatak. I wish for her to arrive alive so i can torture her personally. Nerus will lead you to Anat''s cell.', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98741, 'Onuris, it is time for us to leave. Enter the ring transport circle.', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98742, 'Lord Ra, let me bring you Anat.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98743, 'I have ordered Set''ra to bring her, Onuris. ', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98744, 'You place this important task in the hands of a lowly Jaffa?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98745, 'You have this disconcerting tendency to question me, Onuris. I am finding it somehwat... Irritating. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98746, 'I simply wish to serve you my Lord. Set''ra is a Jaffa and subject to weakness.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98747, 'You have not shown a penchant for strength yourself, young one... However, I am a benevolent father. It is one of my faults - I indulge my children. You may join Set''ra after I have ringed up to the Hatak. Do not fail me...', 2547, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98748, 'I will not.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5275, 98749, 'Do not take my indulgence in your desire to impress as something you can take advantage of, child. If you fail to bring me Anat, I will kill you without mercy. ', 2547, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5276, 98750, 'You activate the Ring controls, teleporting Ra up to his Hatak.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5277, 72605, 'Investigate the Dakara Superweapon.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5278, 118806, 'The Ancients designed the Dakara Superweapon so that it could seed the Galaxy with human life. Since the failure of our Genome there have been long-standing theoretical discussions about using the Superweapon.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5278, 118807, 'On us?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5278, 118808, 'Yes. It is - theoretically - possible that we could adjust the Superweapon to modify our genetic code. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5278, 118809, 'A possible solution to our degeneration...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5278, 118810, 'If you gain access to the Superweapon and are able to access the data within, I would be most interested in that material.', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5279, 107672, 'You begin to extract the data from the Ancient computers that run the massive Superweapon. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5280, 86647, 'This data has been highly anticipated...', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5280, 86648, 'Is it useful?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5280, 86649, 'At first glance... It is disappointing... Loki - one of our more controversial scientists - had a theory about how the Ancients managed to create the Superweapon. He seems to have been correct.', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5280, 86650, 'There is no hope?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5280, 86651, 'None. The Dakara Superweapon is not a solution to the genome failure. ', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5281, 86667, 'Gather data from Energy Beings and Possessed Humans on Agnos.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5282, 86668, 'I will need data before I am able to make any analysis. Use this scanner - on both free-floating energy beings and those which have possessed a human. This data will provide a starting point for my research. ', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5283, 118811, 'The energy creatures on Agnos pose a severe threat to the humans and Jaffa. Both General Hammond and Master Bra''tac have expressed great concern over their behavior on Agnos. Speak with Heimdall and see if we can find a way to help.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5284, 105534, 'My protocols do not allow me to display the vault location to your race, degenerated Asgard. ', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5284, 105535, 'It is imperative that I get there.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5284, 105536, 'Unfortunately, I cannot override this directive. ', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5284, 105537, 'I apologize for what I must do.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5285, 105588, 'You crack open the console and quickly attempt to access the system data before Laro can kill the Terminal.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5286, 105539, 'You find the vault location - it''s actually relatively close by.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5287, 105586, 'From the looks of it, the Vault storage pods are contained in deep wells, and retrieved and unlocked via this console. Two pods in particular are highlighted. There are indicators which show that these Pods might be able to be opened...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5288, 105587, 'You prepare to engage the revival process on the two stasis pods - if you can just figure it out...', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5289, 86670, 'Interesting. These are not a naturally occurring phenomenon. These creatures are - fundamentally - data. I cannot identify the technology, but they are not of nature. They are a construct. ', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105589, 'It appears we have company, Blix. Are you...? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105590, 'We are dying.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105591, 'I hope you didn''t come here looking for solutions to survival - my people clearly had no answers in that regard. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105592, 'You are scanning for the plague.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105593, 'Yes. And it seems clear... But there is a lot of interference... Laro? Laro? Her conscious process must be somewhere else.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105594, 'You are Goldam?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105595, 'I am. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105596, 'We need your assistance. The future of the Galaxy is at stake.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5290, 105597, 'Why am I not surprised?', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5291, 108175, 'Collect plasma samples.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5292, 118779, 'The energy creatures we recovered have a basic consciousness. Their form sustains this consciousness. In effect, they are a "body" which sustains the consciousness.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5292, 118780, 'Could we use this form?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5292, 118781, 'It is an intriguing possibility. Our own consciousnesses are stored in systems which are exceptionally advanced versions of the basic consciousnesses found within these creatures. The energy creatures are products of the Agnos environment. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5292, 118782, 'We need materials from the world?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5292, 118783, 'Plasma Samples. In great quantity. Preferably samples from the energy creatures themselves. ', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5293, 86717, 'This material will prove quite useful.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5294, 106090, 'This teleporter is still capable of moving us to my research facility.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5294, 106091, 'I should meet you there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5294, 106092, 'Yes. I will disable the androids in a section and begin work on your fascinating creatures. I''ve uploaded the location to your PDA. By the time you arrive, I will have Laro online and the world will be fully operational. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5294, 106093, 'I''m not certain you will get Laro under your control...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5294, 106094, 'Laro is my creation, $name$. Do not be fooled by the beautiful voice, Laro is 100% machine. We will see you at my lab.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5295, 73471, 'Perform Heimdall''s experiment.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5296, 106186, 'Goldam''s storage pod is one of several hundred... You begin the process of figuring out which one is his...', 515, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5297, 108646, 'I have prepared something which may save our race. Thor has suggested that I have you assist with the first test. I have agreed. ', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5297, 108647, 'What is the experiment?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5297, 108648, 'We are placing Asgard consciousnesses inside plasma bodies. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5297, 108649, 'This could mean... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5297, 108650, 'A living solution to the Genome challenge facing our people. The High Council is monitoring this experiment closely. Meet me in the Lab when you are ready to proceed.', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5298, 108597, 'Clearly this was a failure. The High Council wishes to hear the results of this test directly. Please inform them of this failure.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5299, 89653, 'Let''s get started... The less time I''m seen with you, the better. ', 1042, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5300, 73656, 'Search the Research Facilty on Agnos.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5301, 118784, 'You, friend, are such a tragedy... Your race is dying, is it not?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5301, 118785, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5301, 118786, 'There was a time when you looked much different... The Asgard have always been a proud people, but I never imagined that over generations you would devolve in such a way...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5301, 118787, 'We search for a cure.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5301, 118788, 'I may be able to help. We had samples of your people - deceased, corpses - that we kept for scientific purposes. They were kept right here in this research facility. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5301, 118789, 'Preserved?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5301, 118790, 'Unless Laro has deactivated the storage units, yes. It is possible that you can find whatever it was that has afflicted you through comparison with those corpses. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5302, 86800, 'The storage unit is open but contains nothing of value.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5303, 86801, 'The storage unit is open and contains preserved Asgard cadavers. At least they are supposed to be Asgard... They look nothing like you. Still, you begin the process of collecting the corpses for transport. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5304, 86802, 'UNSUED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5305, 86806, 'This is an encouraging find... I should be able to detail exactly how useful it is in just a few moments...', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5305, 86807, 'You seem disappointed.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5305, 86808, 'Our Genome has fundamentally changed. Scientifically speaking, we are unlike this creature - yet it is our ancestor. Somewhere in our past, our Genome was altered beyond recognition. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5306, 74214, 'Consult Goldam.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5307, 118791, 'It is possible the Alterran Goldam has information about our Genome mutation. We have been unable to access reliable data from the AI Laro, but Goldam might have information not contained within Laro''s databanks. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5307, 118792, 'What should I ask him for?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5307, 118793, 'Specifically, we are interested in when or how our Genome was so radically altered. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5308, 86845, 'It was the Solocris.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5308, 86846, 'The Solocris?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5308, 86847, 'Yes. When the decision was made to deactivate the Solocris it reacted. It attempted to defend itself...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5308, 86848, 'It modified us at a genetic level?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5308, 86849, 'Yes. The Solocris wreaked incredible havoc on all the Four Races of the Great Alliance... Before it was finally stopped, your people had been altered forever. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5308, 86850, 'So our mutation is permanent?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5308, 86851, 'The Solocris saw your people as betrayers. It wanted to kill you. Completely. That you still exist is a testament to your will and technological accumen. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5309, 86852, 'This news is most disconcerting. I will inform the High Council.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5310, 106419, 'Clearly Laro has built the nanites to protect herself from the Straegis. I don''t want to interfere with that. Instead, I can work around them. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5310, 106420, 'How?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5310, 106421, 'I''ve created this subroutine which takes advantage of... The science is unimportant, the point is, the device enables communications through the nanite interference. I need you to set this up on the Communications Grid Interface. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5311, 106422, 'The Interface seems reasonably straight forward. You begin to insert Goldam''s Enabler...', 520, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5312, 106418, 'Everything seems perfect, except nothing seems to have happened. You check again - is this working? It seems so.', 520, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5313, 86856, 'Recover three pieces of forgotten tech from Yotunheim.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5314, 86865, 'The High Council wishes us to recover certain technologies that deem necessary from Yotunheim. These are not technologies stored within my memory. Only you and the High Council will know of what you seek.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5315, 86879, 'The failure to recover the Resonator concerns us. Is it possible Ra has procured it?', 2509, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5315, 86880, 'Yes. However, I destroyed his ship. If it was there, it was vaporized.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5315, 86881, 'This brings us comfort, but it is not a certainty.', 2509, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5315, 86882, 'I recovered what I was able to recover. I am sorry to displease the High Council. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5315, 86883, 'You work is appreciated, even if it is incomplete. ', 2509, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5316, 106474, 'This console should give you a decent look at the innder workings of the plant... Hacking past the security should be easy enough. ', 531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5317, 86910, 'Shut down the modified consciousness hubs.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118794, 'There is something you should be aware of. The experimentation done on Pertho didn''t stop on Pertho. ', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118795, 'You did more here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118796, 'Yes. The High Council paid no attention to this facility, which made the process of experimentation more efficient.', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118797, 'But our people were turning into monsters on Pertho.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118798, 'That was a most unfortunate side effect, but it does relate to what has happened here. There is a bank of consciousnesses - criminal minds kept here as a way of isolation - which must be terminated. ', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118799, 'Why can''t they be transferred?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118800, 'They have been modified at the consciousness-hub level. The result is severe instability. I need you to disable them. Ra''s attack has made the facility''s criminal protections unstable... ', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118801, 'Is there more to this than you are sharing?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5318, 118802, 'There is more than we have time to discuss. Terminate the consciousness hubs. Quickly. I''ve uploaded their location to your PDA.', 2095, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5319, 108704, 'The hubs should be relatively easy to shut down - unless Loki has modified them...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5320, 87089, 'You have disabled the hubs, but the end result is not what you expected... Apparently Loki didn''t tell you everything.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5321, 108698, 'I am pleased that you survived...', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5321, 108699, 'These experiments were supposed to be suspended indefinitely. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5321, 108700, 'Yes. There is much you still do not understand about the nature of the Council''s approach to the coming end of our race. Once you inform them of these experiments they will be outraged. However...', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5321, 108701, 'They knew?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5321, 108702, 'I hid nothing from them. We are a desperate people, $name$. There are some who will do whatever is required to save our people. I am one of them.', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5322, 87101, 'There are many who will let Loki do whatever he wishes... They are desperate.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5322, 87102, 'The mutants are like animals. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5322, 87103, 'The argument will be one of sacrifice and saving the majority versus living to the standard we have set for ourselves. Right now the High Council tries to have this both ways. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5322, 87104, 'What will happen to Loki?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5322, 87105, 'He will not get what he deserves.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106540, 'The area is open... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106541, 'What are you attempting?', 417, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106542, 'I''m giving you an escape.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106543, 'I cannot follow that path. This will disconnect me from my primary systems. ', 417, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106544, 'It will save you.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106545, 'I am unable to comply, system preservation protocol 56B4A enacted.', 417, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106546, 'It''s the only you''re going to survive this.', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5323, 106547, 'I cannot follow those instructions. I am incapable of deviating from my priority module. I have been programmed to maintain system integrity. I am sorry to disappoint you. ', 417, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5324, 87112, 'Recover a sample of Ra''s Control Tech from a Straegis Meta.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5325, 118803, 'We know that the Straegis are extracted from the Furling whole, but we do not understand how Ra is able to control them. We believe that there are specific Straegis who serve as translators...', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5325, 118804, 'The Meta Straegis. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5325, 118805, 'That is the current theory. We would like to examine the technology he uses to communicate with them - to control them. Collect an intact piece of this technology from the Meta Straegis and deliver it to Heimdall. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5326, 87120, 'You need to gently remove the technology from within the crystallized shell. It''s going to be difficult...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5327, 87130, 'This will be an interesting insight into how Ra controls the Straegis... Perhaps we will be able to someday modify this so that we may control them. ', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5328, 106721, 'You need to disable this synaptic link so that Laro cannot escape.', 526, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106683, '(You begin to carefully administer the nanobots into Laro''s system...)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106684, 'Please do not do this...', 529, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106685, 'I don''t have a choice...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106686, 'I do not wish to be terminated.', 529, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106687, 'I don''t have a choice.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106688, 'I promise I will allow Goldam to help me... I will allow it. I will comply to all directives. I wish to be a good girl now. Please do not terminate me.', 529, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106689, 'You can be backed up. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106690, 'Self-preservation protocol 32342 invoked. I cannot leave my systems voluntarily. ', 529, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106691, 'Can you stop the Straegis?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106692, 'Overrun is inevitable.', 529, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106693, 'Then I have no choice.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106694, 'What will happen to me?', 529, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5329, 106695, 'I don''t know.', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5330, 106674, 'Systems still have not come online... That nanites will take some time to consume her... Did she talk to you?', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5330, 106675, 'She asked for mercy.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5330, 106676, 'Don''t we all?', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5331, 74905, 'Use the Reins of the Sun Chariot on the Furling Carapace. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106724, 'This victory is temporary, you know that...', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106725, 'We''ll keep pushing.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106726, 'And you will lose. My research has shown me something: The Straegis are not just related to the Furling - they ARE the Furling. Pieces of it. Ra has, somehow, managed to access the Furling and he is ripping pieces of it away.', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106727, 'The Straegis are Furling... Bits?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106728, 'Elements... Themes... It''s all very complex - I am not completely clear on it. The point is, they are infinite. The Straegis will never stop coming. It is an army that can never be killed, because it does not die.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106729, 'Then what do we do?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106730, 'You have to reach the Furling itself. The device you showed Laro - the Reins of the Sun Chariot - can do that... But you would need something else.', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106731, 'What?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106732, 'A carapace... You can summon the Furling, but the individual aspect will sustain only with technological help... The used shells - carapaces - to sustain their aspects.', 406, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5332, 106733, 'I need to get to Omega Site.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119091, 'This is a most interesting development.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119092, 'The mechanism sounds similar to the device we recovered on Beta Site...', 2568, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119093, 'The one that brought through Straegis...', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119094, 'Exactly. If we use the Reins of the Sun Chariot on that carapace we recovered on Beta Site... ', 2568, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119095, 'We might meet a Furling.', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119096, 'We just might.', 2568, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119097, 'I''m going to meet a Furling. How cool.', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119098, 'Where is this Carapace?', 3216, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5333, 119099, 'Last I saw it, it was in the storage area.', 2568, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5334, 108499, 'These orders are pretty straight-forward, Burtonol is after technology that can be repurposed into consumer goods... However, given the company''s history, their presence is worth a report up the ladder. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5335, 75618, 'The operation looks like it is run completely by a "Mr. Metcalfe". Everything - supplies, requisitions, assignments - all come from his desk. You resolve to make contact with him. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5336, 75619, 'He has a spy on Omega Site?', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5336, 75620, 'I think so...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5336, 75621, 'We need to take this to the council. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5337, 75622, 'He has a spy in Harset? ', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5337, 75624, 'We need to take care of this immediately.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5338, 75708, 'A plant? It was exhibiting genuine sentience. Fascinating... ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5338, 75709, 'It was fascinating.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5338, 75710, 'There were a cadre of scientists here, right before the plague arrived, who believed that we could bio-engineer a solution to the plague. All kinds of revolutionary ideas were tried. Nothing came of it and, frankly, I''m shocked the plants have survived...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5338, 75711, 'They have not only survived, they''ve evolved.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5338, 75712, 'Apparently. Rather significantly. I will have to take a look into that someday. ', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75939, 'Well, look who the cat dragged in... ', 2165, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75940, 'We''ve heard that you had a psychic encounter with one of the plants...', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75941, 'Yes. It was very powerful. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75942, 'I want you to bring it here so that we may study it. ', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75943, 'That may be dangerous... ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75944, 'I''m not concerned with the danger. Besides, Morrigan''s plants weren''t psychic... They were just smart... ', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75945, 'Smarter than Morrigan...', 943, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75946, 'Oh, shush... The simple fact is, I think a psychic plant might yield something truly useful. So you will be a dear, and face the danger...', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75947, 'Of course.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75948, 'You''re so much more attractive to me when you comply...', 944, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75949, 'It would help to have some details.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75950, 'In order for that plant to reach out to you, it must have used some sort of gas - plants are constantly emitting gases... We want to study that plant''s gas. If we can replicate it, it could prove to be a very useful chemical. ', 943, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5339, 75951, 'Acquire it at once. Alive. ', 944, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5340, 107347, 'The detonator is in place but... Just to be safe, you leave the connection to the trigger disconnected. You see no reason to leave yourself vulnerable to the whims of the council while you are still down here. ', 585, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5340, 107348, 'If Baal is going to blow this world apart, it won''t be with you on it. ', 585, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5342, 107410, 'What''s this?', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5342, 107411, 'Solution to the enegy being infestation.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5342, 107412, 'Copplemann told you to give it to me?', 404, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5342, 107413, 'You''re the one sending under-qualified people into harm''s way... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5343, 107733, '(The scan is successful and Goldam is none the wiser... )', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5343, 107734, 'Which is why her sentience is so surprising... I need to determine if she actually has personality traits or if we are just assigning them based on our own perceptions... ', 406, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5343, 107735, 'Goldam?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5343, 107736, 'You have to go again?', 406, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5343, 107737, 'Yes.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5343, 107738, 'Be safe, child. ', 406, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5344, 76524, 'I''m ready when you are... ', 599, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5345, 119268, 'We knew the Crystal Key had special properties, but this tranformation is interesting. A change of that nature requires a tremendous amount of energy. I speculate that the structures around you are simply part of a much larger machine. ', 1632, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5346, 107765, 'You begin to hack the Transmission for origin details...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5347, 107768, 'He''s not around, but it is possible he sent something else from this terminal. You decide to hack it and look inside...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5348, 107767, 'Well, clearly the terminals hold the key to finding Rick... You start to interface with it...', 2424, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5349, 107953, '$name$, this Maura Whelan... I''m sure you''re very busy but... I''m really worried about my nerd... I don''t do well without him. Do you have news?', 598, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5349, 107954, 'He''s alive.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5349, 107955, 'Do you know where he is?', 598, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5349, 107956, 'Kind of.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5349, 107957, 'Kind of? What sort of answer is that? Is he in danger? What''s happening?', 598, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5349, 107958, 'I don''t know yet. I will let you know the second I understand it myself... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5350, 108005, 'You have to hack this Output Interface to have any hope of reversing the process... ', 606, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5351, 108277, 'This console may have information about how the ZPMs on the world are distributed... You just have to figure out how to access the data...', 531, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5352, 108276, 'You begin to inspect the machinery for any sign of ZPM connections.', 584, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5353, 108328, 'You start disassembling the power conduit to see the interior architecture...', 610, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107261, 'At ease, and welcome to Stargate Command.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107262, 'Thank you, sir.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107263, 'I see from your file that General O''Neill personally selected you as a replacement member of SG-18. I hope you understand how extraordinary that is.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107264, 'Yes, sir. I''m honored to be part of the SGC.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107265, 'I was talking about the fact that Jack O''Neill personally filled out the paperwork to bring you on board. Gen. O''Neill hates paperwork. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107266, 'I have heard as much, sir.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107267, 'SG-18 is due in from Dakara within the hour. In the meantime you''re my problem. First thing you should know... Jack O''Neill has gone missing. The whole team is focused on figuring out exactly what happened to him...', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107268, 'Is there any information at all?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107269, 'We have leads but this isn''t the time to discuss those. As a member of the SGC, you''ll need to work closely with our off-world allies.', 2609, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107270, 'You mean aliens, sir?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5354, 107271, 'Technically yes. Teal''c, one of our Jaffa allies and a member of SG-1 is waiting to meet you in the Briefing Room. He''ll introduce you to the base while I figure out what to do with you until SG-18 returns.', 2609, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105479, 'What news from Dakara?', 2179, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105480, 'I bring a warning from Master Bra''tac.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105481, 'Tell me.', 2179, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105482, '(You hand Teal''c the message from Bra''tac.)', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105483, 'Bra''tac believes that Ba''al''s soldiers have infiltrated the refugees we are sheltering here. How could this be?', 2179, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105484, 'So many Jaffa from different worlds are now on Dakara. . .', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105485, 'Yes. It would be easy for an enemy to hide among so many strange faces. Thank you for the warning. I will begin questioning the refugees immediately.', 2179, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105486, 'What may I do to aid your search?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5355, 105487, 'General Hammond is in command of this base. He is in the Briefing Room next door. You should speak with him if you wish to volunteer.', 2179, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5356, 97117, '(Cinematic) Unscheduled off-world activation. SG-18''s code is used to open the Iris. You see Jaffa pour through the Stargate and begin attack SGC soldiers.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5356, 97118, 'Airmen, secure the gate room! How did these Jaffa get SG-18''s iris code?', 2609, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5356, 97119, 'I do not know, General Hammond. If the warning I have received is correct, these Jaffa are loyal to Baal. If this is true, I believe we will need every trained soldier armed and prepared.', 2179, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5356, 97120, 'He''s expanding the invasion?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5356, 97121, 'I will do my best, sir.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5356, 97122, 'I don''t doubt it. Have that airman show you the elevator. ', 2609, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5357, 97123, 'The security office is on sub-level 16. This elevator will take you there.', 2181, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5357, 97124, 'Level 16. Understood.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5357, 97125, 'Keep your head down. I think it might get a little crazy around here.', 2181, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5358, 77430, 'You search the Airman''s corpse and find his service pistol.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5359, 97154, 'You hear General Hammond''s voice coming from a radio on the Airman''s body.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5360, 97192, 'Airman Morgan, this is General Hammond. Come in, Morgan... Son, are you out there?', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5360, 97193, 'Repeat, this is General Hammond. ', 2609, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5361, 96133, 'You there! Come, quickly...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5361, 96134, 'Jaffa, kree!', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5361, 96135, 'Over here!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5362, 97182, 'You take the radio from the Airman''s body.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5363, 113458, 'General Hammond, this is $name$. Both airmen are dead, sir.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5363, 113459, 'Killed by Jaffa?', 2609, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5363, 113460, 'Sir, I have an emergency situation. I will give you more details once I have time...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5363, 113461, 'What is the...', 2609, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5363, 113462, '(You click the radio off and move to deactivate the explosive device the Jaffa was setting.)', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5364, 113468, 'Hammond of Texas, this is $name$. I am sorry to say that both of your soldiers are dead.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5364, 113469, 'Dead? Who killed them?', 2609, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5364, 113470, 'I do not know. There is an emergency I must attend to. I will contact you soon.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5364, 113471, 'Wait? What is hap...', 2609, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5364, 113472, '(You turn the radio off and move to defuse the explosive device you saw the Jaffa planting in the room.)', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5365, 113480, 'What the hell is happening down there?', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5365, 113481, 'There was a Jaffa in this room planting an explosive. I deactivated it. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5365, 113482, 'Excellent work... Recently we received intelligence that some of Ba''al''s forces may have hidden among refugees from Dakara. ', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5365, 113483, 'It appears that intel is correct. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5365, 113484, 'Apparently. I need you to check on something for me. Colonel Carter was in her lab at the time of the attack and she hasn''t responded to radio calls. Normally this wouldn''t concern me because she occasionally likes to work undisturbed, but...', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5365, 113485, 'I''ll go confirm she is safe.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5365, 113486, 'She''s on level 19. Keep your eyes peeled, $name$. If Baal''s Jaffa infiltrated the building they can be anywhere. ', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5366, 97387, 'Security, this is Colonel Carter. I''m taking heavy fire in my lab. Do you read?', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5366, 97388, 'I am on Level 19, I need backup!', 2184, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5366, 97389, 'Take cover!', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5366, 97390, 'Whoever you are, there''s only two of them!', 2184, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5367, 97396, 'Thanks for your help. My radio got hit in the initial attack. I guess it wasn''t working.', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5367, 97397, 'General Hammond sent me to investigate.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5367, 97398, 'Well, thank you again for coming when you did. Now we''ve got to get out of here. You just have that service pistol?', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5367, 97399, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5367, 97400, 'There''s another weapon on my lab desk. I think you''ll like that one better.', 2184, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5368, 97401, 'You take the submachinegun from Carter''s desk.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5369, 97408, 'Help Sam Carter neutralize the virus in the SGC''s computers.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117657, 'I think we may have been under attack for some time...', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117658, 'I just saw the Jaffa come through the gate a few minutes ago...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117659, 'It started earlier. This morning I noticed a self-replicating virus in the SGC''s network. Our network uses ISR-Sync Redundant Firewall technology - unhackable from the outside. ', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117660, 'So someone inside the network must have released it. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117661, 'At first I thought it might be related to General O''Neill''s disappearance. However, when I looked closer at the infection... General O''Neill would be trying to communciate with us... This virus is certainly not doing that. ', 2184, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117662, 'Is it an attack?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117663, 'It''s possible. The replication pattern is fascinating - not at all random. It seems to follow specific pathways, completely ignoring others that it should naturally spread to.', 2184, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117664, 'Like it is searching for something?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117665, 'Yes, that could be it! Come on, we have to figure out what it''s searching for. Here, take this. It''ll help you with the network.', 2184, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5370, 117666, '(Colonel Carter gives you her notes on the SGC''s computer protocols.)', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5371, 97472, '(Colonel Carter gives you her notes on the SGC''s computer protocols.)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5372, 97473, 'It looks like you have managed to neutralize the computer virus. Tell Colonel Carter about your success. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5373, 97507, 'Help Carter deactivate the SGC''s self-destruct sequence.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5374, 97572, 'We managed to neutralize the virus, but not before it accomplished its purpose.', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5374, 97573, 'Which was?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5374, 97574, 'They activated the SGC''s Failsafe Device.', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5374, 97575, 'The failsafe device?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5374, 97576, 'Cheyenne Mountain has plans for several defensive scenarios in place. One of them is a foothold scenario - if the facility is overrun, there''s a low yield nuclear device in place that will render the base uninhabitable...', 2184, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5374, 97577, 'And the Jaffa have activated the device?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5374, 97578, 'The virus hacked the codes and ran the scenario. Contact General Hammond and inform him of the situation. You and I have to deactivate that bomb.', 2184, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5375, 97579, 'How can the Failsafe device be active, Colonel? None of the warning systems are engaged.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5375, 97580, 'The virus disabled them, sir. I doubt the Jaffa who planted the virus even know what it''s intended to do.', 2184, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5375, 97581, 'I''m sending reinforcements to your location. Hold your position until they arrive.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5375, 97582, 'Sir, there''s no time. The virus hacked the timers on the nuke. We have no idea how much time is left before the Failsafe activates. We have to go now.', 2184, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5375, 97583, 'You can make it through with only two of you?', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5375, 97584, 'We''ll have to, sir.', 2184, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5376, 97585, 'Let''s go!', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5377, 97612, 'Normally we''d need two senior officers to deactivate the device. Since we don''t have that, and the virus has probably disabled the passwords anyway... ', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5377, 97613, 'We''re going to hack a nuke?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5377, 97614, 'I''ll manually rewire the device while you try to deactivate the self-destruct sequence from the other terminal. We''ve got two chances this way.', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5377, 97615, 'How likely is it that either will work?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5377, 97616, 'Do you really want to know?', 2184, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5378, 113493, 'The Failsafe device is deactivated?', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5378, 113494, 'Mostly. $name$ has frozen the process. I''ll need to remain here and monitor it. I don''t know if the virus is completely gone from the network yet. Can you send down an officer with code authorization?', 2184, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5378, 113495, 'It will have to wait. Ba''al''s forces have taken control of the Stargate and are trying to open the iris. If they succeed, they''ll be able to bring reinforcements in from Dakara. I need all hands on deck.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5378, 113496, 'Sir, I can''t leave the Failsafe Device. If this goes off it won''t matter who came though the gate.', 2184, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5378, 113497, 'Sir, I''ll go.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5378, 113498, 'Make your way here on the double. Take the maintenance elevator up one level, you''ll come out in a requisitions room. There should be some equipment you can use in there. Good luck.', 2609, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5379, 97633, 'I''ll draw their fire! Flank them by going through that room and into the hallway that comes out behind them.', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5379, 97634, 'Good work back there. I can see why General O''Neill was so high on you.', 2184, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5380, 97638, 'We don''t have time for this! I''ll draw their fire while you flank them.', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5380, 97639, 'If you use those desks on the side, they won''t have very good cover against your attack. Go now!', 2184, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5380, 97640, 'We have to hurry. We may only have a few minutes before detonation.', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5381, 93849, 'The Failsafe device is through that door. Come on! Let''s try and flank those Jaffa.', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5382, 77494, 'The Jaffa have already managed to disengage the Iris and activate the Stargate! You need to shut off the gate before they bring more troops through.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5383, 77501, 'You successfully de-activate the Stargate. You need to deal with the remaining Jaffa in the Gate Room before they overwhelm you and reactivate the gate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5384, 77499, '(fade to black) You are back in the Gate Control Room with Hammond, Teal''c and Carter.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5385, 113780, 'You look in the crate and find a light machine gun and a flak jacket.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5386, 77505, 'You look in the crate and find a suit of stealth armor and a combat knife.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5387, 113781, 'You look in the crate and find a deployment belt and a flak jacket.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5388, 113782, 'You look in the crate and find an Asgard hologram belt and a flak jacket.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5389, 113784, 'You look in the crate and find a staff weapon and chest armor.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5390, 97692, 'Go to Dakara to search for the missing members of SG-18.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5391, 97693, 'Go to Dakara to search for the missing members of SG-18.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98199, 'The situation here is under control. There are a few Jaffa holding out, but we have security teams dispatched to handle that. You''ve done well. ', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98200, 'Thank you, sir.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98201, 'The Jaffa opened the protective iris we use on the gate with SG-18''s GDO. This probably means that SG-18 is either killed or captured.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98202, 'On Dakara?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98203, 'On Dakara. That world was invaded by Baal''s forces recently, the situation has been touch and go for a while. Apparently he decided to take the fight to us... ', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98204, 'I''d like to take the fight to him.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98205, 'You may get your chance. For now, I need you to head to Dakara as my liasion. Inform Bra''tac - the Free Jaffa''s leader - of the attack here and ask for assistance in locating SG-18. Once you have information, report to me before you do anything. Understood?', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98206, 'Understood. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5392, 98207, 'I don''t want any cowboys in this outfit. I have enough of them already. Confirm with Harriman that the Stargate is operational and then get a move on.', 2609, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5393, 98208, 'Master Bra''tac''s intelligence was accurate, but even he did not predict a direct attack on Earth to this scale.', 2179, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5393, 98209, 'How did Ba''al''s army gain access to the base?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5393, 98210, 'They used a code belonging to SG-18. This does not bode well for the members of that team. I must remain behind and try to identify any of Ba''al''s forces who remain among the refugees. You must return to Dakara and report these events to Master Bra''tac.', 2179, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5393, 98211, 'I will do this immediately.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5393, 98212, 'If you can, locate the remains of SG-18. They should be returned to Earth, to their families from proper burial. Speak to Sgt. Harriman and confirm that the Stargate is operational.', 2179, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5394, 97708, 'Good luck finding SG-18 and keep your head down. Dakara is a dangerous place these days. ', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5395, 97709, 'Good luck. Bra''tac is waiting.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5396, 97710, 'Tell Master Bra''tac that I hope to see him soon, on a free Dakara.', 2179, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5397, 77696, 'I just get so lonely down here... It''s nice to have someone to talk to...', 1139, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5397, 77697, '(Dawson''s guard is down... The moment is at hand to use the Symbiote on him. )', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5398, 83474, 'What are you trying to do? ', 1139, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5399, 87051, 'You begin to hack the system... The recording should be easy to erase and no one should be the wiser... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5400, 83115, 'I am ready... Follow behind and watch for the killer as we travel. ', 1140, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5401, 110294, 'If you succeed in taking out A''lem, then I am more than willing to assume power and restore a Council which supports true Jaffa tradition and principle. There is much in Moh''katan''s vision that I admire. But there is something you are forgetting...', 2295, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5401, 110295, 'Yes?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5401, 110296, 'Hubrok is my clan''s elder statesman. I cannot move against A''lem without his decree.', 2295, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5402, 80304, 'The inscription looks interesting - a puzzle of some kind... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5403, 80298, 'Much of the translation is mundane gibberish in Ra''s rambling style, but there is one piece which stands out - written in the hand of Ra himself. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5403, 80299, 'This magic - for it cannot be other - seems to come from inside me. From my essence. My connection runs deep - to the core of my very being. When I can control it, when I allow myself to truly feel it, it gives me great power. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5403, 80300, 'This is worth taking back to Baal.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5404, 77943, 'You successfully hook up the monitoring device.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5405, 77942, 'You fail to hook up the monitoring device. Try again.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98903, 'Onuris, respond!', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98904, 'My lord? This is unexpected.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98905, 'What a delight to hear your voice. I was worried about you, down there amongst the rabble. I feared harm might come to you. ', 2547, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98906, 'I am fine, my Lord.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98907, 'The Jaffa who carried you, he is well? ', 2547, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98908, 'When last I saw him, my lord.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98909, 'Hmmm. My scribe Safkhet tells me that she found two dead Jaffa outside of the Implantation Chamber. ', 2547, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98910, 'That is unfortunate, my lord. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98911, 'I have noticed something about you, Onuris.', 2547, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98912, 'Yes, my Lord?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98913, 'All of my children call me "father". A petty attempt to curry favor, but I indulge their whims because family matters to me. Does it matter to you?', 2547, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98914, 'It does. Forgive me, father.', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98915, 'Stop your games, New Mind filth. The remains of Onuris were found burning in a brazier. It was you I sensed in the Temple. ', 2547, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98916, 'But you didn''t act, did you, "Father"?', 0, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98917, 'Play with me, pig, and I will cook your flesh while you still live... ', 2547, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98918, 'You must catch me first. ', 0, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5406, 98919, 'That is perfunctory. Even now my huntress seeks you. You will squirm before me alongside your Queen and that simpleton Lethander - yes, I heard that little exchange over the communication sphere. You will beg for death, pig. I promise you.', 2547, 16);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5407, 78123, 'Thank you for bringing me back...', 971, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5407, 78124, 'Baal wishes to see you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5407, 78125, 'Well, I can''t very well say no, can I? I owe him my life. ', 971, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5408, 84025, 'You want me to tell you where Bra''hin is?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5409, 78207, 'I cannot tell you what I don''t know...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5409, 78208, 'Indeed... Now you can lament that in jail.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5410, 78209, 'I know that he was looking for support in the Marketplace. He may be there with others. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5410, 78210, 'You assistance will be remembered.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5411, 83927, 'I have done nothing wrong...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5411, 83928, 'You were once loyal to Ra.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5411, 83929, 'This is not a crime... ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5411, 83930, 'It is now. Come with me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5412, 83941, 'What is this?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5412, 83942, 'You bear Ra''s symbol.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5412, 83943, 'But I am no longer loyal.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5412, 83944, 'That is not my problem. Come with me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5413, 83939, 'My loyalties are to the Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5413, 83940, 'Prove it by making this easy... Come with me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5433, 87238, 'Rusted and chipped, this box has an unusually complex lock attached. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5434, 80316, 'The box opens and inside you see a battered, chipped Face Hugger... Something about it strikes you as odd, but Amaterasu wants it so - you take it and go. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5435, 88659, 'Do you find me... Beautiful?... You hesitate... ', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5435, 88660, 'No, my Queen you are radiant...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5436, 88663, 'She is like that... Some call her Mercurial... Others call her... She is unpredictable, let''s leave it at that. I will give you some suggestions to keep in mind for the future... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5437, 78427, 'Ba''al offers to help the player talk to Anat (after she kills the player once for failing the "Am I beautiful?" minigame.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5438, 78518, 'Impressive... While we achieved victory now, I am concerned... These Ashrak may be just the beginning... ', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5439, 78614, 'Petbe... He has added to the shipments... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5439, 78615, 'Petbe? Anat''s Petbe?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5439, 78616, 'Yes. He was able to get my family here... In exchange I have let him insert elements to the shipments...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5439, 78617, 'What is he sending out?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5439, 78618, 'I do not know. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5440, 112475, 'You search Nomu''s corpse and discover a small crystalline pin embedded into the skin of his neck. This is the same sort of pin as from the devices Ra intended for use on the Council. You resolve to take this to Teal''c''s attention.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5441, 78619, 'Much to your surprise, there is a stack of neatly ordered documentation - Petbe certainly is orderly in his black market paperwork... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5442, 78696, 'I will send him to the Storage Area... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5442, 78697, 'Good. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5442, 78698, 'Are you going to kill him?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5442, 78699, 'Do you really want an answer?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5442, 78700, 'No. I will send him - on my honor - but you must not call on me again!', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5443, 118612, 'Interesting... ', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5443, 118613, 'You killed Petbe, Lethander...', 942, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5443, 118614, 'I did? How devious of me. And I assume you two are here to deliver unto all the justice I so clearly deserve...', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5443, 118615, 'A justice demanded by Queen Anat herself...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5443, 118616, 'I must say, I underestimated you, $playername$. It will be a shame to put down so much potential.', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5444, 110571, 'This stone console controls the operation of the Ancient Superweapon, concealed within the mountain for millennia. You begin to use the console to shut down the weapon.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5445, 112613, 'This stone console controls the operation of the Ancient Superweapon, concealed within the mountain for millennia. You begin to use the console to shut down the weapon.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5446, 79333, 'The reaction was complete... You are related to the Straegis. Directly. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5446, 79334, 'Is there a way to use this somehow?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5446, 79335, 'I do not know... I still have much work to do to even understand them... I still have to determine how they relate to the Furling. Much to do...', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116210, '$name$ from the SGU. Eir sent me to find you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5448, 106787, 'This is good information. Burtonol is supplying command and control, logitistics, communications, R&D support... The works. Looks like their headquarters are in the city, on their own island. Pretty swank.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5449, 80020, 'You found their leader?', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5449, 80021, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5449, 80022, 'I assume he was dispatched?', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5449, 80023, 'He is no longer an issue.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5449, 80024, 'Nice work...', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5450, 88858, 'There''s a rumor going around that there are Ra''s Jaffa still in Harset, loyal to him...', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5450, 88859, 'In hiding?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5450, 88860, 'No. The Loyalists are a hodge-podge of different Jaffa with different backgrounds. Some former Ra Jaffa now work for Moh''katan. Anat fears that some may be secretly working for Ra...', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5450, 88861, 'His resurrection may sway some of them.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5450, 88862, 'Yes. So we need to clean up the city and try and find their ringleader - a Jaffa called Bra''hin.', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5450, 88863, 'When I find him, what do I do?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5450, 88864, 'Anat wants his head. Assuming he is the guy, just eliminate him - a capture makes things too political. ', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5451, 88850, 'Round up the suspicious Jaffa on Harset.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80086, 'You show up in the darndest places.', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80087, 'What are you doing here Lethander?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80088, 'I''m doing business. Unauthorized business, but business nonetheless.', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80089, 'Black market?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80090, 'Yes. I have managed to make contacts - both on Tollana and Lucia - that have proven to be quite adept at providing high-demand goods.', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80091, 'Why shouldn''t I just turn you in?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80092, 'Because someday you may benefit from it? Understand, this project doesn''t just include me. I have many friends - some of them within your Op-CORE ranks... To expose this to the light would hurt a lot of people. ', 978, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80093, 'If I keep this silent?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5452, 80094, 'I will owe you. And I always pay my debts.', 978, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5453, 80095, 'What''s he up to?', 948, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5453, 80096, 'Nothing... I couldn''t find a thing.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5454, 80196, 'Enough... I do not interest in any more of this. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5455, 117568, 'Vet Petty Officer Grogan as a potential smuggler of NID agents.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117558, 'Your work earlier is much appreciated... ', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117559, 'I believe that is twice I''ve saved your skin.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117560, 'Yes, but who is counting? I have a suspicion as to who is letting those human agents into Harset.', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117561, 'Who?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117562, 'One of your own... The new Quartermaster, Grogan. I suggest you thoroughly examine his behavior. It was in the Storage Area where the NID agents assaulted me... ', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117563, 'They could be coming through that way... ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117564, 'Grogan is not to be trusted.', 978, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117565, 'Says the Goa''uld. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5456, 117566, 'Fair enough. But think of it this way - who better to recognize deception than a master of it?', 978, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5457, 80240, 'Smuggling NID in here? That is crazy... Who told you that?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5457, 80241, 'That''s not important...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5457, 80242, 'Seriously, I want to know.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5457, 80243, 'It''s not important, Grogan. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5457, 80244, 'What? Do you believe them? You know what - look around. Poke around in here and you show me where I could possibly be sticking NID agents.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5457, 80245, 'I''ll do that. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5457, 80246, 'Go ahead. Knock yourself out...', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5458, 94555, 'Nice work... Apparently they got Grogan to comply by threatening his family.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5458, 94556, 'They could do that to any of us.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5458, 94557, 'Yes, they could. And worse, they will.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5459, 80536, 'She took it?', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5459, 80537, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5459, 80538, 'Un-freaking-believable... I want to unplug her myself.', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5460, 83105, 'Please show mercy.', 1144, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5461, 80654, 'No... There''s no way I give that to you - they can trace it back to me.', 1014, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5462, 80653, 'The files are there for the taking and you begin the upload. As you read you slowly realize... This stuff isn''t matching up with stories you have heard. This has Marsh being part of the team that blew the whistle on the Op-CORE program.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5463, 80706, 'Hi there... You don''t look too friendly. Arthur Vandermoot, NID.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5463, 80707, 'You targeting our people?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5463, 80708, 'I can be honest with you here, right? Of course we''re targeting your people. Hell, we''re targeting you. We''re going to get every one of your criminal band back into prison - or six feet under.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5463, 80709, 'I should kill you where you stand.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5463, 80710, 'Then you would be killed. These Androids in the city are feral if they sense violence. You can''t do anything to me.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5463, 80711, 'Your guys in the Greenhouse are dead.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5463, 80712, 'So are yours. And I have more guys... Do you?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5464, 117637, 'You keep staring at me... So angry...', 2843, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5464, 117638, 'Keep pushing it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5464, 117639, 'I''ll do whatever I want. I have unlimited resources. This is a fully funded US Government operation - and I am in charge...', 2843, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5464, 117640, 'You''re the brains?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5464, 117641, 'Why do you think I am in Agnos city. Safe and sound... While my teams are out grabbing your people - a few at a time. And that''s all we need to do. Drip, drip, drip... You guys are all over Agnos - exposed. Target rich environment. ', 2843, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5464, 117642, 'Why don''t you go after the real enemy?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5464, 117643, 'I am.', 2843, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5465, 117645, 'Find a way to kill Vandermoot.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80772, 'Ah, look who it is... My favorite human... And to what do I owe this pleasure?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80773, 'I need a weapon - something subtle. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80774, 'For?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80775, 'An assassination. The target is easy to reach, but the attack cannot be detected. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80776, 'Do you wish to inflict great pain on your target? ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80777, 'I just want him dead.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80778, 'I have something... I''ve developed a remarkably small explosive charge - literally the size of a coin - that burrows its way into the body. It then uses the body''s own electrical charge to arm itself and activate. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5466, 80780, 'Dart gun. Here - it''s experimental but... It should work. You have about 15 seconds to get clear once it is fired. ', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5467, 80840, 'NID on Agnos? This is not good - even if you took out their CO, they''re finding us and draining us of people and resources... I''ve already heard grumblings from the Goa''uld.', 968, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5467, 80841, 'I''ll keep an eye out.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5467, 80842, 'They keep finding us... It''s suspicious.', 968, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5467, 80843, 'You think Marsh?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5467, 80844, 'I wouldn''t have before but, now? If these attacks become targeted? That''s a possibility we have to consider. The Colonel''s a smart guy. He''s going to protect himself. ', 968, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5468, 97664, 'Asgard terminals are never easy to hack. This security terminal looks like something you can get a facility map from...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5469, 96847, 'Loki''s personal computer will be tough to get into. You settle in and begin what figures to be a long process...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5470, 96858, 'You go to finish the download, but the terminal has been infected by some sort of virus - apparently the drones were just one part of Loki''s security plan. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5472, 101710, 'The encoding of the plans is complex - but when they are unlocked the science team at Harset will be able to apply the technology easily. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5473, 81366, 'Your arguments are sound. I will take this letter to him, but know that his daughter''s treachery will not easily be forgiven. ', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5473, 81367, 'She does not ask for forgiveness.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5473, 81368, 'The day may come when she does. ', 2316, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5474, 120332, 'A Black Market? I assure you, friend - and you can assure Moh''katan - that I would not engage in anything so dishonorable. ', 2048, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5474, 120333, 'We know you are involved.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5474, 120334, 'You have been misinformed.', 2048, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5475, 81434, 'Lethander is the mastermind of the operation. I simply ship what he asks and receive what is sent through the gate. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5475, 81435, 'Lethander runs it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5475, 81436, 'Yes. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5476, 81446, 'There is a market - a limited one. Tell your commander, Moh''katan, that in exchange for her tacit complicity her Jaffa will be handsomely rewarded. ', 978, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5476, 81447, 'In what way?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5476, 81448, 'We are always short on equipment. The supply of Naquadah chips is low... I will "re-invest" some of my profits into weapons for your Jaffa. Staff weapons - traditional weapons. ', 978, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5476, 81449, 'She may entertain such an offer. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5476, 81450, 'Then you must question her fitness to lead. I am offering you the tools for your trade. Even the most honor-bound Jaffa can see the long term benefit to such an agreement. ', 978, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5477, 120340, 'Like I''ve said - there is no Black Market.', 950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5478, 120338, 'I have already told you - I know of no such illegal program. Be gone!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5479, 102953, 'Well... If you say the council approved it, Ill leave them be... But if I find out that they aren''t supposed to be there I will destroy them myself. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5480, 102957, 'You know what? I don''t buy this whole story. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5480, 102958, 'I speak the truth. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5480, 102959, 'Well, you can bring me written proof - from Colonel Marsh - and then I''ll let you do this. Otherwise, there''s going to be trouble. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5480, 102960, 'You do not wish for trouble.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5480, 102961, 'Is that a threat? Because it sounded like a threat. And I''ve got a little friend here with some high powered AP rounds that says you better cut your threats out - right quick. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5480, 102962, 'The device stays. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5480, 102963, 'Then we have a problem. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5481, 102278, 'I saw the scan results... They were inconclusive.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5481, 102279, 'Is there something you are not telling me?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5482, 81619, 'You realize that you were a genetic creation, correct? Somebody - Ra maybe - built you. ', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5482, 81620, 'This was known.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5482, 81621, 'Well, what probably isn''t known is that you are very special my friend. You are a hybrid of human and Goa''uld genetic material. Humanity was our answer to the question of the "fifth race" - an answer to the question of who will guide the universe in our absence. The Goa''uld were the Furling solution. ', 406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5482, 81622, 'We are of both.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5482, 81623, 'The technology that gave you that pouch was Furling in nature. Your creator - either knowingly or accidentally - gave you a rather direct connection to the Furling. Similar to the Goa''uld. But you are also primarily human. You are a true mixture.', 406, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5482, 81624, 'What does this mean?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5482, 81625, 'It means you are much more than a race of slaves who rose up against their masters. Genetically you may be the fifth race - literally. I need to do more research but... You''re an amazing scientific achievement. ', 406, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5483, 103151, 'It is an honor to be chosen for this experiment.', 957, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5483, 103152, 'You show much courage.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5483, 103153, 'If our people can live perpetually, without the shame of desecration, I will emerge a hero. ', 957, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5483, 103154, 'Indeed.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5483, 103155, 'You may implant the revised symbiote.', 957, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5484, 103161, 'It feels strange... I can feel the symbiote there but I cannot reach it...', 957, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5484, 103162, 'Pain?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5484, 103163, 'No but... It feels... Wrong...', 957, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5484, 103164, 'Shall I try to remove it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5484, 103165, 'No. I will endure. I must endure.', 957, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5485, 81669, 'And you arrive bearing gifts... Give me, please. Fetch something to eat while I work.', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5485, 81670, 'You cannot be serious?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5485, 81671, 'Oh, I am. This type of work conjures up quite the appetite. If you want this done, bring me something. And make it delicious.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5486, 81675, 'I am done... I will trade you the edible for your symbiote. ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5486, 81676, 'Will it work?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5486, 81677, 'I do not know. I hope, for the sake of your volunteer, that it does.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5487, 120350, 'You wish to see me in the Marketplace?', 964, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5487, 120351, 'Immediately. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5487, 120352, 'What business is this?', 964, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5487, 120353, 'It is a matter of life and death. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5487, 120354, 'I will meet you in the Marketplace presently.', 964, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5488, 120361, 'Moh''katan believes there is a plot afoot? That is preposterous.', 964, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5488, 120362, 'Is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5488, 120363, 'Of course it is... There are no plots - at least not amongst the other System Lords and Anat. ', 964, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5488, 120364, 'Consider a moment, the price you will pay for lying to me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5488, 120365, 'You are threatening me?', 964, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5488, 120366, 'I am advising...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102280, 'There is nothing certain... But she does speak of the future.', 964, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102281, 'And?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102282, 'And Moh''katan is not in it. I am assuming that if I help Moh''katan, I will be rewarded.', 964, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102283, 'Of course.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102284, 'It was not Lethander who killed Petbe, was it?', 964, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102285, 'Your instincts are excellent, Opheltes. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102286, 'They have kept me alive this long. I will trust you, $name$ because you are truly honorable. ', 964, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102287, 'You will trust me because it is prudent.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5489, 102288, 'Fair enough. Inform Moh''katan that we have a deal.', 964, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5490, 81834, 'This shield tower appears to be clear.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5491, 87808, 'There is an explosive device next to the Shield Tower control unit. Disarm it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5492, 81871, 'The scanner shows that this area is clear.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5493, 81869, 'The scanner indicates that there is some Straegis activity in this area.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5495, 113112, 'The Ruins of Khenmer''Fa... They weren''t attacked in the initial wave. Our ally Ras''nor took some of his clan of Nine Peaks Jaffa there for shelter.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5495, 113113, 'Is this Ras''nor alive?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5495, 113114, 'You got me. I briefly picked up a signal, but it''s gone dead again. Happened when some of Ra''s forces fell back to the Ruins, about the same time you scrambled the teleports.', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5495, 113115, 'Then a piece could be there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5495, 113116, 'Ra told them to protect the artifacts. They may be trying to avoid people like you until they can get onto a ship. You should check out what Ras''nor knows, I''ll give you the location.', 1008, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5495, 113117, 'Assuming he lives.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5496, 83497, 'Apparently bureacracy infects every government operation - even the SGC. The artifact data is, in fact, not stored in the main system, but instead can be found in the Science Computer databank. You''ll need to access those computers to get a complete data set. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5497, 117750, 'The Science Console requires an access code. There may be a way around it...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5498, 83499, 'The data upload takes only a few seconds. You now have the data you need to give to Dr. Jackson.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117832, 'I could tell that more strangers had come to my home. I did not expect they would be aiding us. Whoever you are, you have Ras''nor''s respect.', 1013, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117833, 'I seek an artifact taken by Ra...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117834, 'Could it possibly be a rod of glowing light, small enough to be held in the hand?', 1013, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117835, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117836, 'My son Jysic has it. While Edj''dan, Son of Khepri looked the other way, he grabbed the rod. I have been keeping Ra''s forces at bay ever since.', 1013, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117837, 'Why did your son take it?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117838, 'Anything Ra desires can bring no good to this world.', 1013, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117839, 'Where is Jysic now?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5499, 117840, 'We know this area well, he will be hiding in the Ruins. Return him to me and I will deliver to you the object. ', 1013, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5500, 117867, 'What is this? Are you friend or foe?', 1011, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5500, 117868, 'Your father sent me, Jysic...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5500, 117869, 'Why?', 1011, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5500, 117870, 'He wants me to bring you to him. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5500, 117871, 'I will come with you...', 1011, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5501, 83538, 'I saw what you did. You won''t get away with this...', 1147, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5502, 83595, 'The handshake succeeds and you successfully upload the images to Daniel Jackson.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5503, 103048, 'UNUSED DIALOGUE', 1882, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5504, 106320, 'Delancey just hit them. The Jaffa were stunned.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5504, 106321, 'He''s a piece of work. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5504, 106322, 'Oh, yes... He is a bit rough around the edges - a lot rough around the edges - but he''s trying to do something to fight back, which is more than most... It will probably cost him any hope of eventually rising up in TechSecure but... ', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5504, 106323, 'Some things are more important.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5504, 106324, 'Yes. Quite.', 663, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5505, 83852, 'Fair enough. I''ll have one of the people here give it a once-over. You, however, need to find your way back to the Beta Site and help get that place closed. This Jaffa rebellion up there is making me nervous. ', 1300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5506, 83963, 'Why should I tell you?', 2167, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5507, 118182, 'This Portal resembles the one from MagmaLife, except that it appears to be - like the beacons - fashioned purely out of the same crystals that formed the Straegis. You begin to rig it for destruction.', 2457, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5508, 118148, 'The portal has been stopped. My calculations show the Straegis forces on this world are reducing in number for the first time in days...', 1015, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5508, 118149, 'In other words, Ra''s threat of overwhelming the planet in Straegis is now impossible. We won.', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5508, 118150, 'As soon as the situation permits, we will return to the Omega Site. We have only begun to crack the surface of understanding the Straegis and the remaining specimens here provide an opportunity for study...', 1015, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5508, 118151, 'Thank you for your help. We''ll see you at Omega Site. ', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5509, 84551, 'A crystal object tumbles out. It''s a technology you''ve never seen before. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5510, 103953, 'You sealed him inside a sarcophagus?', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5510, 103954, 'It was a convenient option.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5510, 103955, 'There''s a subtle brilliance to that. Anyway, Safkhet is next... If she knows about the Mouth, we need to get to her.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5511, 84854, 'I think you''ve got it. These may be our only protection against Ra if he decides to come after us with a surprise attack... So set these up carefully. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5512, 114711, 'You gain access to the Asgard database and begin downloading information to your PDA as quickly as you can... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5513, 104536, 'No, that''s not quite it. Let''s try this again. ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5514, 115031, 'The device looks in decent shape, although the console has recently been removed... It may be possible to sabotage the internal powerup circuits so that when they powerup the device... They will destroy it. ', 2062, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5515, 115082, 'That "activity" Ha''kur mentioned must have been the Asgard. They''ve placed explosives to destroy this entire area... You need to defuse the explosive to make the area safe for investigation.', 2065, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5620, 117770, 'Eir is alive, but badly hurt. You may be able to find out what happened to her if you can keep her conscious long enough to keep her talking.', 2130, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5516, 115240, 'Your argument is persuasive. Ra is proving more difficult to deal with than anticipated and any additional assistance would be welcome. Take this communicator. We will contact you when we have formulated a strategy.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5516, 115241, 'I am supposed to wait?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5516, 115242, 'Yes. ', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5517, 115210, 'All that you are able to extract is what looks like a memory stick - apparently the Asgard feed memories into themeselves, probably when they change bodies. The stick is not wholly advanced - and a simple decryption reveals that there is no record of the Solocris on it...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5532, 85312, 'The search outputs an ancient data pad - a large one. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5533, 105042, 'Interesting... This entire archive could have amazing historical importance. I''ll dispatch an archeological team immediately. Nice work. ', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5534, 105389, 'We killed her.', 2392, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5534, 105390, 'We had to.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5534, 105391, 'Why? Why did they infect her?', 2392, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5534, 105392, 'She was in the wrong place at the wrong time.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5535, 85486, 'The sensor is functioning correctly.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5536, 85487, 'This sensor has malfunctioned. You will need to repair it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5537, 85488, 'The sensor springs to life and you immediately get an overloading of data. Something nearby is positively pulsing with Ra''s technological signature. The direction of the pulse indicates that the Ruins might be the source. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5538, 98476, 'The first minutes in a host are strange, aren''t they? You look dazed. We have much to talk about, but first you should speak with Lord Ba''al. Hurry.', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5539, 105768, 'Daniel''s passcode seems to have been disabled - probably as a precaution by Woolsey. You''ll have to hack it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5540, 105573, 'You manage to download virtually everything in the archive... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5541, 105776, 'Like Daniel''s machine, Sam''s code has also been rendered invalid. The hack procedure should be pretty similar...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5542, 85558, 'All of Sam''s data has been successfully downloaded.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5543, 105876, 'This appears to be a pretty standard Laro interface. Hopefully the data will be localized.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5544, 85638, 'You successfully download all the growth data Laro has accumulated throughout the generations. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5545, 85684, 'This data indicates there was a city... A settlement where the Four Races met. Sort of a Galactic U.N.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5545, 85685, 'There''s no gate address.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5545, 85686, 'Not yet. Just give me some time to do my magic... Something like this could circumvent literally thousands of years of archeological research. Vokos Primar might be the Galactic equivalent of King Tut''s Tomb. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5546, 115564, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5547, 115565, 'In order to create the proper containment field for the miniature black hole, you must manipulate some singularity grids - power supplies for the Singularity itself. The system should naturally create the pocket black hole once these have been set.', 2086, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5548, 98474, 'You should speak to Lethander before leaving the Implantation Chamber.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5549, 85809, 'You successsfully bypass the Goa''uld Security Station granting you access to the Ring Network Controls', 1856, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5550, 85810, 'You successsfully hack the Ring Network Controls allowing you entry to the Hall of Secrets', 1857, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5551, 104207, 'You find a crystal attached to a handmade necklace made with great care... Clearly Safkhet valued this and it is probably the activtor for the Mouth of Ptah. You''ll next need to find the Mouth and apply this device...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5552, 98512, 'The door to the Robing Room opens.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5553, 85962, 'The device again seems operational. This planet has a remarkable amount of static interference for such primitive evolution.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5554, 106456, 'The human computers are relatively simple designs. Hacking into them should be reasonably simple...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5555, 93548, 'You quickly upload all the relevant data about O''Neill from the human main databank. You are tempted to download EVERYTHING they have, but social protocols hold you back from doing it. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5556, 106501, 'You begin to activate the scanner.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5557, 106565, 'You begin to activate the scanner.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5558, 106571, 'You begin to activate the scanner.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5559, 115577, 'The passcode works and you now have access to Loki''s files. By tracing what systems he has activated within the Yotunheim facility, you believe you have pinpointed the area where he may be, but you cannot decipher the map. You upload the information to your PDA.', 2152, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5560, 107068, 'You begin to prepare the sample for storage and evaluation. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5561, 86243, 'The sample is properly preserved and ready for evaluation.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5562, 106948, 'The sample has become contaminated and must be discarded.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5563, 118814, 'The specifications concern you: They seem to imply that Tech Con Group has been playing with Replicator technology. You should never give a primitive human like Arlos something this dangerous.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5564, 98555, 'Lord Onuris, how may I serve you?', 2550, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5564, 98556, 'Jaffa, tell me your name.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5564, 98557, 'I am Bes''ra, First Prime to Lord Ra, leader of his Jaffa.', 2550, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5564, 98558, 'You look nervous, Jaffa. Tell me what is wrong.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5564, 98559, 'Forgive me, but my news must be given to Lord Ra post haste.', 2550, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5571, 86510, 'You have successfully modified the sample.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5572, 114097, 'UNUSED DIALOG.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5572, 114098, 'You spoke the truth. I will report this to Ullr so we can take these Jaffa by surprise.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5573, 98566, 'Jaffa, kree! Death is the only reward for failure. The slaves are too many. System Lords of the Goa''uld, let us abandon this world. Onuris, take up Bes''ra''s staff. You will be my only guard until we leave this planet.', 2547, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5574, 86511, 'The sample is contaminated. You''ll need to get another sample.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5575, 117163, 'You are resourceful...', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5575, 117164, 'We are going to have a conversation...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5575, 117165, 'There is little you can do to coerce me. I do not fear death. ', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5576, 107532, 'You prepare to disable this crop with the Neutralizer.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5577, 108074, 'You begin to activate the scanner...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5578, 108075, 'You begin to activate the scanner...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5579, 117479, 'Although it looks like no machine you have ever encountered, you begin to adjust the cloak phase as Loki instructed... You are already planning your escape route off Yotunheim with the Solocris...', 2096, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5580, 108595, 'It is time.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116211, 'You have succeeded.', 2143, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5581, 118815, 'We are disappointed. We have been recently considering revoking the resources currently allocated to the SGU project. Little progress has been seen by this body. ', 2509, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5581, 118816, 'Terminating the SGU would be unwise.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5581, 118817, 'Why?', 2509, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5582, 108244, 'You are a very persuasive speaker, $name$. We will grant an extention to the SGU project, but please understand, our resources are not unlimited. ', 2509, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5583, 86876, 'We wish for you to recover three pieces of specific technology: A Trans-Dimensional Resonator, Advanced Artificial Intelligence Algorithms and Nox Cloaking Technology. These cannot fall into the hands of Ra.', 2509, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5583, 86877, 'Where am I to deliver them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5583, 86878, 'Once recovered, return them here. ', 2509, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5584, 86904, 'You realize that the Trans-Dimensional Resonator is not here. It must have already been moved.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5585, 108691, 'Accessing the main computer is easy enough - but finding data for just one object is another story...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5586, 86908, 'You successfully upload the AI data.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5587, 87125, 'You manage to extract the communcations technology from within the crystal encasing...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5588, 87127, 'The crystal shell fractures and the technology is damaged - left useless for study. You''ll need another sample. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5589, 102014, 'You bypass the Stasis Computer''s security and can now download the virus', 2418, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5590, 115829, 'Apparently things are not going well here at all... Ra has this station reeling...', 2061, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5591, 111760, 'Your words are honorable. Inform Bra''tac that my loyalty - and that of my people - is unwavering. ', 2510, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5592, 111786, 'If you wish to have me remain loyal to the Free Jaffa you must prove that those who represent it, do so with honor!', 2510, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5592, 111787, 'Runk''an?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5592, 111788, 'Runk''an!', 2510, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5593, 111741, 'Your words have soothed my temper. I have always suffered for it and am sorry for my outburst.', 2511, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5593, 111742, 'You are forgiven.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5593, 111743, 'Long live the Free Jaffa!', 2511, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5594, 111746, 'If you wish my people to be loyal to the Free Jaffa, you must prove their worth. We shall engage in Runk''an!', 2511, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5594, 111747, 'With pleasure.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5595, 109162, 'The box pops open. It''s empty. You''ll have to find another. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5596, 109163, 'The box pops open and inside you find the medallion.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5597, 109703, 'The Asgard technology is still a little tricky to use. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5599, 110284, 'Oshu was forced into hiding by Ra''s Jaffa. Give the password "Cheeseburgers" to Yim Long. ', 2543, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5600, 110522, 'The transmitter is pretty complex... It may be hard to deactivate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5601, 110508, 'You finally deactivate it. More correctly, you smashed it to pieces - but it is most certainly not transmitting anymore. Job complete. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5602, 87805, 'You succesfully disarm the explosive, removing the detonator as evidence.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5603, 109785, 'You have convinced me you can talk. However, words do not impress me. I require action.', 770, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5603, 109786, 'I am prepared to prove myself.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5603, 109787, 'Ra''s advance must be slowed. Mines will cause delays and allow us time for reinforcements. I will upload a location to your PDA. Place the mines there. We must slow his Jaffa at all costs.', 770, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5604, 118521, 'You successfully dismantle the Straegis Beacon.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5605, 111302, 'It is possible that if you can hack into this monitoring facility database you might be able to find data on all aspects of the Android processing - enabling the Jaffa to reverse engineer the Androids. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5605, 111303, 'The process is difficult - not only is the computer Ancient, but there is a lot of trash data to sift through...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5606, 111285, 'You download the material. It is useful, but without parts for analysis, it is worthless. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5607, 98731, 'Ra is distracted working on his device. Perhaps this console can provide information about Anat or Nerus'' locations... You''ll have to work quickly...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5608, 88273, 'You succesfully plant the Scarab listening device.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5609, 88841, 'You take Zipacna''s corpse.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5610, 102756, 'The mechanism has been successfully jammed. If these activate the Jaffa inside will be trapped... ', 1883, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5611, 104818, 'Apparently Ra kept armies in storage - the Jaffa on this world are coming out of these Stasis pods. You can probably use this control console to prevent this, but you''ll have to hack it first...', 1883, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5612, 103248, 'You successfully rig the weapon locker with explosives', 1919, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5613, 103254, 'You successfully rig the weapon locker with explosives', 1920, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5614, 103259, 'You successfully rig the weapon locker with explosives', 1921, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98780, 'Where is our Queen? Have you found her yet?', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98781, 'Not yet.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98782, 'Do you know where she is?', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98783, 'Nerus knows. He is in a place of safety... ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98784, 'There are several, some of which are already overrun by slaves and decidedly not safe... You must get specifics from one of Ra''s Jaffa. Once you have the details, come meet me at my hideout.', 2546, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98785, 'I am supposed to work with a Jaffa called Set''ra. It should not be difficult.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98786, 'Kill him when you get the information... ', 2546, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5615, 98787, 'I don''t think I will have a choice.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5616, 119817, 'Lord Onuris! Our god has sent you to aid me! Let us kill this rabble that stands in our way.', 2551, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5616, 119818, 'First tell me where I can find Nerus, in case we become separated.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5616, 119819, 'Lord Nerus waits with the other gods in a place of safety. He is not powerful like our Lord Ra and must wait until Jaffa can escort him to Ra''s Chariot in the sky.', 2551, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5616, 119820, 'Where can I find this place of safety?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5616, 119821, 'How is it that you do not know? All of the gods are born knowing where the places of safety lie. Supreme Lord Ra has told us this is so... ', 2551, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5616, 119822, 'Lord Ra was mistaken.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5616, 119823, 'Heresy! Only the children of the traitor Anat would speak of him that way... You are one of them!', 2551, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5617, 88362, 'You carefully gather a sample of the radioactive soil and seal the jar.', 1914, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5618, 104345, 'The tablet doesn''t mention the nanotoxin, but it does tell a fascinating tale of Ra''s resurrection from the Underworld. What strikes you is the specificity - you''ve never seen such detail in the story before. ', 1915, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116209, 'This is Igyn. Identify yourself.', 2143, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116213, 'You have found me. I am inside this portion of the computer network...', 2143, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116214, 'Inside the network? Inside the computer?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116215, 'My only hope for survival was to upload my consciousness into the our systems... However, this portion of the network is closed.', 2143, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116216, 'You are trapped?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5621, 116217, 'Correct.', 2143, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5622, 104060, 'The filter appears fixed now, but a nearby terminal begins sounding an alarm. What now?', 631, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5623, 116751, 'The computer stabilizes. An array of Asgard consciousness files appear on the screen and begin downloading into the portable storage unit.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5624, 104072, 'Cutting the flow of plasma through the damaged section seems to have reduced the number of energy creatures in the area. Better inform Laro of your fix.', 632, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5625, 106043, 'Congratulations on retaining your body.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5625, 106044, 'Your support is appreciated, Supreme Commander. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5625, 106045, 'There is much you need to know. I feel that the High Council is unreasonably optimistic about finding a solution to our termination.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5625, 106046, 'We cannot give up.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5625, 106047, 'We must constantly search for solutions that solve our genetic deficiency. However, we must also prepare for the future in case we are unsuccessful. This second position is less appreciated within the Council. You will work with me toward solving both quandaries.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5626, 118194, 'You''re back. Oh joy. ', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5627, 88844, 'You place Zipacna''s Corpse in the sarcophagus and revive him.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5628, 112074, 'You have safely removed all the consciousnesses from this computer.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5629, 111240, 'Head to Lucia and speak with Eamon, Carter''s old friend. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119361, 'One thing we know for certain - Ra wasn''t "resurrected", there''s got to be some sort of explanation, some kind of technology he used...', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119362, 'It might not even be the real Ra... ', 2568, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119363, 'It is possible his resurrection is some sort of ploy. Ra was the Sun God - the whole Ra myth is steeped in resurrection, re-emergence. There might an answer in there somewhere. ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119364, 'If they believe he was resurrected, there is nothing more needed, Daniel Jackson. Jaffa will follow him. In great numbers.', 2323, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119365, 'The logical choice would be to get inside the cult and find out the truth. If this isn''t really Ra, who is it? And if it is Ra, how did he do it?', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119366, 'Sending an operative into a combat zone in hopes of infiltration seems unnecessarily risky. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119367, 'There have been rumors of Ra''s Jaffa on Lucia, but there has been no news of an invasion. This may be a place worth considering.', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119368, 'Lucia?', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119369, 'I heard stories of Lucia when I was on Hebridan, General. Tech Con Group was in the process of turning it into a massive resort colony - sort of like Las Vegas. Warrick''s brother, Eamon was recently stationed there. ', 2568, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119370, 'We have a contact already? Then it''s worth a look. $name$, we need you to go to Lucia and make contact with Eamon. Find out what he knows about Ra. ', 2410, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119371, 'I''ll contact him and let him know you''re coming...', 2568, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5630, 119372, 'Be careful on Lucia. It is a violent, dangerous place. Only the strong survive there... ', 2323, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5631, 94820, 'Ah, you must be Sam''s friend... She told me you wanted information about Ra? I thought he was dead...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5631, 94821, 'So did we.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5631, 94822, 'The Goa''uld have a way of doing that, don''t they? Popping up after you thought they were dead.', 611, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5632, 109823, 'Head to Lucia and speak with Vala Mal Doran, a contact of Col. Marsh', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119326, 'Ra''s resurrection is a major concern. Beyond the threat he poses our New Mind allies, his victories diminish our own standing in the galaxy...', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119327, 'Ra''s a non-issue. He''s a single System Lord - he''s doing it with smoke and mirrors. We need to focus our energy on the Straegis. ', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119328, 'Oh, Colonel... Honestly, your constant prattling on about the Straegis is beginning to bore me. ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119329, 'Honestly, your constant selfishness is beginning to bore me. ', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119330, 'Can we stop? Please? Perhaps there is a middle ground... The technology we recovered in Ihpet - the Reins of the Sun Chariot - seems to have great power attached to it. If we can decipher his technology...', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119331, 'We can get his power.', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119332, 'And use it against the Straegis.', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119333, 'Yes... The mythical Straegis must be stopped.', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119334, 'Where is the best place to begin research into this tool?', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119335, 'Lucia. It''s a pirate colony - smugglers and traders throughout the galaxy visit there. Any type of technology you might seek can be found there. ', 942, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119336, 'Sounds promising.', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5633, 119337, 'I know just the person we can use... Vala Mal Doran. If she''s still there, she''ll have her fingers in every pie. $name$, find your way to Lucia and make contact with Vala. And be careful, she can''t be trusted.', 941, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5634, 95809, 'Colonel Marsh? Of course I remember Colonel Marsh. He''s quite unforgettable, your Colonel. If I remember correctly, he still owes me 30 Naquada.', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5634, 95810, 'He said you could help us.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5634, 95811, 'That''s very presumptuous of him... He always was a bit pushy... In a sexy way.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5634, 95812, 'Was he wrong about your help?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5634, 95813, 'No. Not entirely.', 156, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5635, 109967, 'Burtonol? Well aren''t you all business? When do you make time for fun?', 156, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5635, 109968, 'It''s important Vala.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5635, 109969, 'I can see that. You have your serious face on. Very serious. Rrrr.', 156, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5636, 95764, 'Welcome to Hebridan, home of the Tech Con family of corporations, land where Serrakin and humans comingle and Grade-A mess.', 683, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5636, 95765, 'How bad is it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5636, 95766, 'Bad. Very. Bad.', 683, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5637, 95694, 'Make contact with Oshu on Pen Lai.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119393, 'An old associate of mine has sent me disturbing news. Ra has struck at Pen Lai.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119394, 'In numbers?', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119395, 'I believe so. Oshu was Lord Yu''s first prime and I have known him for years. After Yu''s death, there was much contention over the world...', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119396, 'Several System Lords vied for it after Lord Yu himself passed away...', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119397, 'And after Anubis'' defeat the world was fought over by Jaffa... The world was torn apart by war, but Ra might be able to unify all the factions into one.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119398, 'Was this a world affected by the pulse on Dakara?', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119399, 'Yes.', 968, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119400, 'Then his presence may be more than political.', 941, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119401, 'We must get there quickly... $name$, you will go first. Make contact with Oshu and report back to us. We don''t have time to assemble a proper entourage - we need information immediately. ', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5638, 119402, 'I advise extreme caution, $name$. If Ra is there in numbers, the world is likely to be in chaos.', 942, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5639, 94915, 'Investigate the strange Jaffa reports on Pen Lai.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119577, 'There have been reports of upheaval on Pen Lai. Ra''s Jaffa have been sighted and there are reports of an invasion. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119578, 'Was Pen Lai one of the worlds affected by the Super Weapon?', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119579, 'I believe this is correct. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119580, 'Pen Lai has been a world filled with upheaval ever since Lord Yu''s death with various factions vying for power. Much blood has been spilled. It is wide open for Ra to take over.', 2323, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119581, 'Clearly we need to get some boots on the ground to make sure that doesn''t happen.', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119582, 'We do not have anything resembling an army available. Our forces are stretched thin throughout the galaxy. ', 2323, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119583, 'Woolsey has the SGC closed. Just keeping us funded and supplied here has been nearly impossible - and major combat operations are outside the scope of our capability already. ', 2410, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119584, 'The High Council will not authorize military deployments based on conjecture.', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119585, 'What about a reconaissance operation?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119586, 'You''d go in there?', 2410, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119587, 'Someone has to. We need information.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5640, 119588, 'Fair enough. You''ve proven yourself more than capable. But this mission is pure reconaissance. Get the lay of the land and get out... ', 2410, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5641, 95644, 'Go to the SGC and figure out exactly what is going on.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95645, 'We intercepted a signal about an hour ago. There was a distress call. The Straegis may have hit the SGC. The Iris on the gate is open - the facility is unprotected.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95646, 'Colonel Marsh is demanding we act.', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95647, 'You''re damn right I am demanding it - earth might be in danger.', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95648, 'We have already discussed this - ad naseum. We have all agreed to look into this issue. ', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95649, 'You are to go through the gate to the SGC and determine what is happening there. You will report to us once you have assessed the situation. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95650, 'If you need backup, we will send people in, but if it''s all a false alarm... ', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95651, 'Or an NID trick...', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95652, 'It''s a dangerous mission, but the potential in terms of information and technology outweighs the possibility of losing a single operative.', 942, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95653, 'We want you to be opportunistic. The SGC are not our friends - take anything and everything of value you can find. ', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95654, 'And if the Straegis are there... Find a way to get them out. Earth must be safe.', 941, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95655, 'Colonel Marsh is correct, despite his personal investment. If earth were to fall to Ra, it would be disastrous.', 942, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5642, 95656, 'Go.', 944, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5643, 119643, 'Go to the SGC and figure out exactly what is going on.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119683, 'Here''s what we know: We got reports of potential Straegis presence in the SGC and the Iris protecting the gate is open.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119684, 'Open?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119685, 'Open. And - as we all know - this is very, very unlike Mr. Woolsey. ', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119686, 'We sent a MALP through... It didn''t come back.', 2568, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119687, 'So we have no idea what is happening in the SGC?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119688, 'None. ', 2568, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119689, 'Someone needs to go down there...', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119690, 'It could be a suicide mission.', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119691, 'Or not. There are no reports of Straegis coming from the media outlets on earth. Assuming something is wrong down there - and we''re not sure there even is - it is probably limited to the SGC. ', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119692, 'For now. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119693, 'We cannot assume anything from the information we have been given. It is too limited.', 777, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119694, 'We need someone to be a MALP. I can do that.', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5644, 119695, 'Be careful down there. And report in the second you know anything. ', 2410, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5645, 89120, 'Leave SGC W2', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5646, 89125, 'Marsh wants the Furling Carapace.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5647, 89129, 'Me Likey Furling Carapace.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5648, 119639, 'Go to the SGC and figure out exactly what is going on.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5649, 119635, 'We''ve lost contact with Earth. I need you to head back and figure out what''s going on. I''m affraid Ra might''ve gotten greedy after his most recent successes around the universe.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5650, 119633, 'What is this artifact you''ve recovered? The log has it listed as a crystal carapace of some sort. It look similar to the Straegis'' armor but different somehow. Find out why Ra was after it as quickly as possible.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5651, 95497, 'Revive the Furling using the Reins of the Sun Chariot.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5652, 95498, 'The question becomes, which of us uses the Reins on the Furling Carapace?', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5652, 95499, 'There should be no question... I should use them.', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5652, 95500, 'You? And why is that?', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5652, 95501, 'Because I am a Queen, Moh''katan. ', 944, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5652, 95502, 'You are a Queen in breed only, Anat. I do not serve you, nor do my Jaffa. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5652, 95503, 'How dare you!', 944, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5652, 95504, 'Why don''t you retrieve the Carapace from the Storage area, <<playername>>. We will sort this out by the time you come back with it.', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5653, 95356, 'Revive the Furling using the Reins of the Sun Chariot.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5654, 95357, '<<Playername>>, it seems to me that you are the one who deserves the honor of using the Reins of the Sun Chariot on the Furling Carapace.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5654, 95358, 'Indeed. I can think of no other more deserving.', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5654, 95359, 'We''re sure this is safe?', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5654, 95360, 'I can''t imagine an Ancient like Goldam misleading us... The Furling is probably our only hope of stopping Ra. ', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5654, 95361, 'I''ll get the Carapace from storage and apply the Reins in here. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5655, 89182, 'Leave Vitrus', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5656, 89181, 'Vitrus is full of bad peoples', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5657, 89183, 'I''ve got nothing for you. This is the end of the game.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5658, 89188, 'Leave Vitrus', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5659, 89199, 'The Straegis are going nuts!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5660, 106232, 'Return to Omega Site and report in about the success on Hebridan.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5661, 106233, 'Our world owes you a great debt of gratitude... The removal of Tynan has unblocked our bureacracy. Our fleet is finally moving to meet Ra and under Caelan''s guidance, TechSecure has struck his strongpoints.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5661, 106234, 'I need to get back to the Omega Site.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5661, 106235, 'Of course. The galaxy is at risk - and we have the situation very much in hand here, finally. Farewell friend. ', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5661, 106236, 'Goodbye. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5662, 89209, 'Cue the dramatic credit sequence.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5663, 106227, 'Hebridan is the first victory against Ra since he re-emerged. Apparently this is in no small part because of you. Well done.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5663, 106228, 'Your success brings hope to many other worlds struggling against his forces.', 2323, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5663, 106229, 'Are we correct in believing that the Hebridan invasion was not a major portion of Ra''s plan, but rather a half-hearted effort to support his Burtonol-based minions?', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5663, 106230, 'Given what I found there, I believe this to be the case.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5663, 106231, 'Then we''ve got to get back to Lucia and into the Burtonol compound.', 2410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5664, 118205, 'You have returned. This is a most welcome occurrance.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5664, 118206, 'We were talking about the Straegis...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5664, 118207, 'That data is still being processed. However, I have a higher priority issue which requires my immediate attention.', 417, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5664, 118208, 'Higher than a galactic invasion?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5664, 118209, 'My programming hierarchy places self-preservation over external concerns. I am unable to direct processes away from vital survival services to deal with lower-priority "potential" threats.', 417, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5665, 116122, 'It''s incredible - contained in a small, secure device is literally a black hole... You can carry it around in your pocket. What happens when you open it is anyone''s guess. You need to inform Igyn of your success. ', 2083, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5666, 116107, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5667, 116364, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5668, 116134, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5669, 116186, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5670, 112210, 'You successfully sabotage the teleporter. The jaffa will no longer be able to use it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5670, 112211, '***Note***
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5671, 118315, 'You decide that you will rig the weapons to detonate once they are used. The Jaffa won''t be able to trust their weapons and it will cause greater problems for them in the long run... It''s the best you can do without proper detonators. You begin the process.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5672, 98795, 'Upgrade your weapons using the supplies in the Slave Pens.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5673, 118725, '$name$, where are you? I have nearly been discovered twice now.', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5673, 118726, 'The slave revolt is making progress difficult.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5673, 118727, 'These shol''va will make it twice as hard to free Anat. Why have the Jaffa not suppressed this rebellion like all the others?', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5673, 118728, 'The slaves carry Goa''uld weapons, Lethander. They outnumber the Jaffa by a large margin.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5673, 118729, 'They must have caches of weapons hidden away. It must have taken years to stockpile enough! Hmmm. We will need better weapons to free Anat. $name$, locate one of these caches.', 2546, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5674, 98797, 'O''Neill, Carter, respond!', 2179, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5674, 98798, 'A minor Goa''uld. Kill it before it can alert the Jaffa!', 2179, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5674, 98799, 'O''Neill! I require assistance!', 2179, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5675, 98800, 'You examine the rebel leader''s body. It is unusually large for a human - Jaffa-sized, in fact. You remove the cloth covering the body''s head and discover the gold symbol of Apophis. This rebel was a First Prime of Apophis!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5676, 98801, 'Impossible! Apophis hasn''t has a First Prime since his last one died in a duel with Chronos'' Jaffa. He has yet to choose another one and been very vocal about it. ', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5676, 98802, 'Vocal?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5676, 98803, 'He constantly bleats about how difficult finding a good First Prime can be... It is tiresome, but it fits Apophis. He is tiresome. Bring me the head of this Jaffa. I will look it over.', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5677, 98814, 'You''re right - this is Apophis'' First Prime. He was posturing for no reason... ', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5677, 98815, 'This Jaffa was leading the rebels...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5677, 98816, 'So Apophis has finally made a move against Ra. Anat always said the alliance between the two borthers wouldn''t last. She wanted me to drive a wedge between them, bring them to war against each other.', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5677, 98817, 'I take it my queen hates Ra intensely. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5677, 98818, 'Your queen hates everyone intensely. But her vitriol regarding Ra is legend. We must report this development to Ba''al. He''ll know how to use this information to our advantage.', 2546, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5678, 98920, 'I just got a very interesting message from a very angry Supreme System Lord... ', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5678, 98921, 'He heard us...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5678, 98922, 'He found a way to monitor transmissions over the communications sphere. Ba''al said it might be possible... Did he offer you the chance to taste your own liver?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5678, 98923, 'No. He focused on burning me alive. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5678, 98924, 'We can make light of this, but Ra never relents. We will be pursued. Use the wall terminal to contact Ba''al. It should be secure.', 2546, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98925, 'So Ra knows of our little ruse? If the other System Lords learn that he can monitor their communications, they may rise against him. This gives us an opportunity, if we use it properly...', 2545, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98926, 'What about his threat? He said his "huntress" was after me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98927, 'He speaks of his Ashrak - highly trained assassins equipped with the latest Goa''uld technology. You have no chance if they find you.', 2545, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98928, 'Ba''al, Apophis may be behind this rebellion. One of the rebel leaders was his new First Prime!', 2546, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98929, 'You have evidence of this?', 2545, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98930, 'We have his head. ', 2546, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98931, 'Apophis is behind this rebelliion and Ra is able to monitor communications... Opportunity knocks... Wait! Did you use my name? Does Ra know that I am connected to this?', 2545, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98933, 'Excellent. Lethander, bring me the First Prime''s head. If Ra knows you have betrayed him, you don''t have much time. ', 2545, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98934, 'And me?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5679, 98935, 'You must locate Nerus and Anat - and watch your back. Don''t use the comm sphere until you have the queen. When you do, don''t say anything Ra can use to trace you. We can win this day afterall... ', 2545, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5680, 119944, 'Locate Nerus to find out where Anat is being imprisoned.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5681, 119948, 'Nerus is probably hiding in the construction site for the second Pyramid. Rooms for Goa''uld of his reknown were built early in the Pyramid''s construction.', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5681, 119949, 'How do I find these rooms?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5681, 119950, 'I was not privy to Ra''s most recent decrees. You''ll have to find another Goa''uld and force him to tell you.', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5682, 108381, 'Keep an eye on Op-CORE by working with them on Tollana', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5683, 99004, 'And who might you be? You certainly don''t belong here. ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5683, 99005, 'I''m one of Anat''s children - maybe the last one. I need to find her.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5683, 99006, 'Fascinating... I can feel you there, through the host, but you do seem different... Scientifically speaking, youa re a marvel. Is it true you lack genetic memory?', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5683, 99007, 'Where is Anat?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5683, 99008, 'I don''t know, but a more pressing question for you might be: Who is that?', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5683, 99009, '(You turn and see Ra''s huntress Ashrak bearing down on you.)', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119051, 'This alliance we have made with the humans concerns me... We know nothing of them.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119052, 'They acted with honor on The Castle.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119053, 'Indeed. But they were also placed there by their own people. Baal is saavy and he would not engage in an alliance without consideration - but I have my doubts. Perhaps you should work with them.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119054, 'As a liasion?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119055, 'Yes. Our Praxis Alliance is focusing on Tollana - a world once controlled by humans until Anubis decimated during his invasion. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119056, 'It is now a wasteland?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119057, 'No. A minor Goa''uld called Svarog has reclaimed the world and built it into a retreat - typical of them to focus on leisure. The human operative Copplemann is already there . I will contact her and inform her that you are available to assist. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119058, 'I will serve honorably.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119059, 'Do as she wishes, but be watchful. We must know what the human motivations are. In some ways the Goa''uld are easier...', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119060, 'Why is that?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5684, 119061, 'We already know we cannot trust them. Go. Copplemann waits.', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5685, 98992, 'That was amazing! I''ve never seen one of Ra''s Ashrak defeated so easily. ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5685, 98993, 'Where is Anat is being held.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5685, 98994, 'Surely someone as talented as you doesn''t need help from someone like me. ', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5685, 98995, 'You know where she is. Tell me. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5685, 98996, 'No. I won''t tell you - and once Ra''s Ashrak fails to report back he''ll send another to find you. And another after that. An endless stream of deadly Ashrak. Ra never forgets a betrayal...', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5685, 98997, 'Oh, I know.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99020, 'We were told not to use the communications sphere. What is so important that you''d risk being discovered again?', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99021, 'I just wanted to tell you how helpful Nerus has been.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99022, 'You''ve found him, then? Did he tell you where to find Anat?', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99023, 'Oh yes, Nerus has agreed to help the New Mind in any way he can. In the name of science.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99024, 'I''ve told you nothing! No one will believe you.', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99025, 'Ra can monitor transmissions over the communications sphere...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99026, 'Of course he can! Who do you think figured it out? I did. ', 943, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99027, 'Impressive!', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99028, 'You think that Ra would believe this type of pedestrain deception? It''s... It''s... Laughable...', 943, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99029, 'Why are you so nervous? We''ll protect you. Just help us. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99030, 'Protect me from Ra? You cannot protect me from Ra. No one can be protected from him... He''s a savage. ', 943, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99031, 'Then pay him a visit and explain the whole thing. ', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5686, 99032, 'You''re very proud of yourself, aren''t you?', 943, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5687, 99065, 'Rescue Anat from the Temple of Ammit', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5688, 119956, 'If I choose to serve Anat instead of Ra, you will guarantee my safety? And care... And feeding... ', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5688, 119957, 'All of it. Tell me. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5688, 119958, 'She is being held at the Temple of Ammit, near the Stargate. She will be executed later today.', 943, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5688, 119959, 'Which cell is she in?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5688, 119960, 'I don''t know. Ra ordered me to give her to the Temple guards. After that, they were responsible for her. I''m sure someone as "clever" as you can figure out a way to find her.', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5689, 99036, 'Please, I surrender... Stop!', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5689, 99037, 'Tell me where the sanctuaries are.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5689, 99038, 'Don''t you know already?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5689, 99039, 'Tell me if you want to live.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5689, 99040, 'You''re one of them! The sanctuaries are hidden behind panels of hieroglyphs. Touch the Eye of Ra and the naquadah in your blood will activate the door. Please, let me live!', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99051, 'Do you have Anat?', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99052, 'Almost. . .', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99053, 'What''s the problem now?', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99054, 'She''s been removed from her host.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99055, 'They must plan on putting her into a canopic jar for transport. Find one and place her in it until we can find a new host body. Where is she?', 2546, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99056, 'The Temple of Ammit.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99057, 'He really planned to kill her. To kill a Queen is... Even Hathor was just imprisoned... He is very, very angry with us... ', 2546, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99058, 'He does not handle his anger gracefully.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5690, 99059, 'No, he does not. Once you have Anat secured, find a way to the back courtyard. We''ll meet you there and escape together.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5691, 99060, 'To have any hope of finding Anat''s cell in this complex, you''ll need to know the Temple''s layout. You decide to find a guard station and access the terminal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5692, 99061, 'The terminal uses a complex cipher. You''ll need to find an encryption key. It''s likely one of the guards may have it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6342, 120085, '<Input text here.>', 3571, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5693, 99062, 'You manage to decrypt the terminal''s info and locate where Anat''s Cell can be found. It''s near. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5694, 119101, 'The Ring Transport controls are locked. You can try hacking them, or look for a security key on one of the Jaffa.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5695, 99064, 'The ring transporter is unlocked and ready for use.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5696, 99069, 'Where are you?', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5696, 99070, 'If you''re in the cargo ship, I''m right below you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5696, 99071, 'Queen in hand?', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5696, 99072, 'Almost literally. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5696, 99073, 'Ringing you up now.', 2546, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119853, 'You have done well. Anat''s children are proving to be very useful. You found her in the Temple of Ammit?', 2545, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119854, 'Yes. Nerus said she was slated for execution.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119855, 'It is hard to believe Ra planned to kill a Queen. It shows us two things. First, his hatred of the New Mind goes much deeper than I thought. That hatred will not fade anytime soon.', 2545, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119856, 'And the second thing?', 2546, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119857, 'He fears nothing politically... Killing a Queen would naturally incite a massive reprisal from the other System Lords... This does not concern him.', 2545, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119858, 'He will be destroyed.', 2546, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119859, 'I know Ra. He does nothing without calculation. If he believes he can withstand their ire, it is because he can. All the manuvering we do will come to nothing...', 2545, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119860, 'Apophis?', 2546, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119861, 'We can use his treachery as a diversion - focus the eye of Ra on family... But...', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119862, 'We will have to go into hiding... ', 2546, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5697, 119863, 'I fear this is so. And, unfortunately, we must make sure he cannot track us. ', 2545, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5698, 89554, 'This device will decode the safe lock. If you can get that far then I will assume you have managed to remove Svarog...', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5698, 89555, 'And you will have your power back. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5698, 89556, 'No, I will have my world back, <<playername>>. The Tollan can be unified as a people once again... ', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5699, 104297, 'The Amduat speaks of Ptah as some sort of source... A font of creation and knowledge... Unlike most of the other material discovered about Ra - that it is always rooted in hard technology - the Mouth of Ptah is described by Safkhet in religious, fantastical terms.', 1917, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5700, 89580, 'The modifications are in place... All you need to do is modify the frequency from one of the Tollan consoles near the Curia. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5701, 89582, 'You access the machine and see your modifications - easily accessed. You set them in place and activate the timer... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5702, 89599, 'Have I heard of the Book of the Gates? An amusing question indeed... ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5702, 89600, 'What do you know?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5702, 89601, 'More than I can possibly share with someone like you...', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5703, 101663, 'Hey, hey, wait a second. There''s no need for violence. I can certainly adjust the order of the manifests... See? Yours just moved to the front. ', 492, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5703, 101664, 'Better.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5703, 101665, 'I think so too... Please don''t kill me. ', 492, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5703, 101666, 'Stop shaking and build the cannon. I will arrange payment.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5704, 89773, 'The Tollan computer system is fairly advanced but it looks like it can be hacked...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5705, 89774, 'The data streams out. The files are wide open and you collect everything you can find. You prepare to take them to Copplemann. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5706, 120033, 'I will give you the extra card, but I guarantee you that this will be confirmed with the Colonel.', 958, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5707, 89833, 'Gaap''s computer isn''t an expecially complex piece of computing technology. This should be an easy hack...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5708, 89876, 'The rebellion will not die with me - I am just the beginning. You can tell Travell that.', 1043, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5708, 89877, 'Very moving. These directions get me to the book?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5708, 89878, 'Yes.', 1043, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5708, 89879, 'You better not be lying to me...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5708, 89880, 'You''ll never get it opened.', 1043, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5708, 89881, 'We shall see.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5709, 89934, 'So she is amazingly hot?', 951, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5709, 89935, 'She has chosen a remarkably beautiful host body.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5709, 89936, 'I can go for that. As long as it doesn''t get creepy.', 951, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5709, 89937, 'I assure you, there is nothing remotely creepy about it. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5710, 89946, 'You are uncommonly physical with your superiors. One wonders if this is a residue of the New Mind''s close association with humans...', 2332, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5710, 89947, 'This is possible, Lord Olokun...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5710, 89948, 'Do not turn their customs into your own... Humans are very limited culturally.', 2332, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5711, 89970, 'Do you love her, or do you just love what she looks like?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5711, 89971, 'Can I take the fifth on that?', 951, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5711, 89972, 'Do what''s right Ogilvie...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5711, 89973, 'I will but... Being wrong is so much more fun...', 951, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5712, 90002, 'They''ve got him isolated. I''ll identify the location on your PDA device. But you never heard this from me. ', 1513, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5713, 101042, 'Begin to look into what the Goa''uld are doing on Tollana.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5714, 101044, 'Please take this data to Marsh on Harset. I can''t spare any of my people but...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5714, 101045, 'I am your liasion.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5714, 101046, 'Right. Thanks.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5715, 101309, 'Lethander is there?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5715, 101310, 'Yes. I secured the Ion Cannon technology files from him.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5715, 101311, 'The Ion technology is nothing surprising. Marsh and his humans tend to be driven simply. Baal, however, is another matter. He is up to something. Obviously the Goa''uld would naturally go to Tollana... But Lethander was part of no official operation.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5715, 101312, 'He works in secret?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5715, 101313, 'Yes. Athena was Baal''s favored Goa''uld for some time. She has been dispatched to Tollana on an administrative task. She is unhappy about this.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5715, 101314, 'You feel she may be vulnerable?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5715, 101315, 'I think we can use her to get details without getting our own hands dirty... Visit her. Mention Lethander... Let her talk... Jealousy is a very powerful emotion in a Goa''uld. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101319, 'Lethander? I thought he was on Harset.', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101320, 'He is on Tollana.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101321, 'Interesting... What is he up to? ', 949, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101322, 'We believed you might know.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6343, 120087, '<Input text here.>', 3571, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101323, 'Moh''katan is interested in what he is doing? ', 949, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101324, 'We felt there may be a mutual interest. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101325, 'There just may be. We shall work together then? You''ll be the brawn, I''ll be the brains?', 949, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101326, 'I will assist you.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5716, 101327, 'First, I need to know who he is working with. Plant these monitoring devices near the entrances and exits of the Goa''uld resort. Once placed, I can monitor them. If Lethander is up to something, it is certain to involve a Goa''uld. ', 949, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5717, 119940, 'I will montior these devices and let you know if anything develops...', 3228, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5717, 119941, 'I look forward to hearing from you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5717, 119942, '(In the meantime, you should probably report to the human, Copplemann. She is expecting you.)', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5718, 90139, 'Find out what Lethander''s interest in Gaap was.', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5719, 119968, 'I have news... Goa''uld have gone missing from the Internment Camp... It is possible that Lethander is behind this?', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5719, 119969, 'Why do you say this.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5719, 119970, 'Lethander was legend for his ability to make enemies disappear... The latest victim was Gaap, a rather forgettable soul with a deep and abiding love for gladiatorial sport. Lethander and Gaap had a past.', 949, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5719, 119971, 'What should I do?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5719, 119972, 'Find out what you can from the Internment Camp. They trained gladiator slaves there... Gaap would be known there... ', 949, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5719, 119973, 'Who is the slave master?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5719, 119974, 'A pig named Clovis.', 949, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5720, 101513, 'You wish to talk about Gaap? I find this interesting since he has gone missing... ', 2727, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5720, 101514, 'I thought you may know something of this?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5720, 101515, 'Perhaps I do... But Gaap me much... If you fulfill his debt, we can have a conversation. ', 2727, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5720, 101516, 'What did he owe you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5720, 101517, 'Supplies from Machra. There was a package I asked Machra to assemble. Gaap was going to pay for it...', 2727, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5720, 101518, 'I will be back soon. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5721, 101532, 'You want the package Clovis had me put togther for Gaap? I don''t know about that... It might cost you more to convince me to let you have it instead of Gaap.', 470, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5721, 101533, 'Gaap does not live.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5721, 101534, 'Oh. Then we really do have something to talk about... The price might have just gone up...', 470, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5721, 101535, 'This does not please me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5722, 101506, 'UNUSED DIALOGUES', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101566, 'These supplies were needed and Svarog is... Not always diligent in supporting this facility... Thank you.', 2727, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101567, 'Gaap.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101568, 'Gaap. He was often here, but he rarely spoke of gladiatorial things... He would trade me supplies I needed to run this operation in exchange for information about the Tollan Computer network...', 2727, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101569, 'Why would he ask you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101570, 'This was not always my life. Before Anubis'' invasion I was a technical officer under Chancellor Travell. I helped run this world''s entire computational infrastructure. This "job" is based on necessity.', 2727, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101571, 'What kinds of questions did he ask?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101572, 'Mostly about data and the network layout. I told him what I remembered. Usually he hid what he was after from me... This world tends to make people paranoid.', 2727, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5723, 101573, 'This informtion was most useful.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5724, 101555, 'The Tollan computer network... Very interesting indeed. You''re a sneaky little bugger, Lethander. ', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5724, 101556, 'What do they want with it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5724, 101557, 'I do not know... But I do know that computer networks are a lot more juicy than gladiators... Lethander''s angle is in there somewhere.', 949, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5725, 90244, 'Find out what Asmodai has been doing on his safaris around Tollana.', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5726, 101574, 'Gaap had a partner... Or an associate... His name was Asmodai. And guess what?', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5726, 101575, 'He has gone missing.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5726, 101576, 'Precisely. I learned from the idiot human who manages the activities at the resort that he enjoyed Safaris into the untamed wilds of Tollana. I learned from his slave that these safaris all went to the same general area.', 949, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5726, 101577, 'He was not on safari. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5726, 101578, 'My thoughts exactly. I''ll upload the location to your PDA. It is worth a look around. ', 949, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5727, 101580, 'This looks like discarded hunting gear, most likely from one of Asmodai''s safaris. What''s interesting to note is that, on closer examination, most of the gear is clearly meant for electronic surveillance rather than hunting. What was he using it for?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5728, 101581, 'A quick cursory check reveals that Asmodai has been using this console to try and break into a secured section of the Tollan computer network. It looks like he failed a lot - the console is frozen and blocked.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5729, 101582, 'Gaap and Asmodai were both after someone named Beleth... It''s likely that he is the one operating the secure system Asmodai was trying to break into... ', 949, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5729, 101583, 'Do we have a location for him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5729, 101584, 'No. If I find something, I will let you know... ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5730, 107537, 'Find out the nature of Beleth''s research.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5731, 96420, 'There are a lot of interested parties in the information collected from Beleth and his computer. Take the information to Athena to make sure that your own parties are looked after in their dispersal.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5732, 107541, 'I''ve talked with Moh''katan and we''ve found out that both Op-CORE and the Goa''uld are interested in the materials you''ve collected, although different pieces of the puzzle. After a lot of discussion about how to best use this to our advantage your crafty leader has come up with a scheme to test the strength of our new alliance. Give the desired materials to Copplemann and Lethander and see if either reports their finds to the rest of the Praxis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5733, 107545, 'Excellent work. I''ll get the best people working on this immediately.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5734, 107549, 'How did you know I was interested in this, Jaffa?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5735, 107553, 'I need you to check in with Nerus to see if he''s recieved either of the materials you handed out earlier.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5736, 107557, 'I have no idea what you''re talking about, but if you want me to do some work for you I''m much too hungry to oblige, you''ll have to find something to satiate my appetite first.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5737, 107568, '[cue dramatic speech calling for full participation by all those involved in the Praxis]', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6093, 101602, 'Yes. They do not trust the New Mind Goa''uld.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5738, 90315, 'Fair enough... We''re hunting earth humans - specifically members of a group called Op-CORE. They''re skilled, and they''re dangerous. ', 2277, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5738, 90316, 'You have no idea. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5739, 101992, 'The monument stone is filled with heiroglphys...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5747, 90360, 'You are immediately struck by this case - ornate and extravagant, this is clearly no standard artifact. The case is hermetically sealed and judging from the damage to the exterior, extremely strong. The objects inside seem mundane - soil, a glow rod and a strange silvery metallic goo.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5747, 90361, 'You note some of the items listed as "unknown" on the human''s list are actually dangerous concealed Goa''uld traps... it occurs to you that they should be disabled as well as restoring the artifact security systems.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119801, 'You''ve done well... I think I speak for all the people on earth when I say thank you. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119802, 'You saved earth - welcome to the club.', 431, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119803, 'We''ll get this fossilized rock analyzed right away. If Ra was after it, it must be valuable. ', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119804, 'It is likely that both the fosillized rock and the Four Pieces are related in some way. Ra has shown a great interest in both - and had preserved them on the Beta Site before his death ten years ago.', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119805, 'But what does he want with them?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119806, 'Hopefully, analysis of all the recovered artifacts will reveal this. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119807, 'I''m getting a little impatient watching him tear the galaxy apart while we try and figure out what he is after.', 2410, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119808, 'We can only do what is within our limitations, General Hammond. ', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5748, 119809, 'I worry that those limitations will be fatal.', 2410, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5749, 118674, 'You have saved earth... On behalf of Op-CORE, I salute you.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5749, 118675, 'You saved earth for now.', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5749, 118676, 'We must have this fossilized rock analyzed. Why did Ra want it?', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5749, 118677, 'Nerus will look into it. The larger question is, what is Ra up to? I knew him and he was always one with a grand scheme. His plans were complex, but brilliant. The Four Pieces on the Beta Site, this Ancient rock - they fit into this in some way... What is he doing?', 942, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5749, 118678, 'We will need to get back to Agnos to find out. ', 941, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95426, 'We have decided who shall be the one to use the Reins on the Carapace.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95427, 'Who?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95428, 'You. You have earned the right. You have proven loyalty to all in this room. You deserve the opportunity for this final, historic moment. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95429, 'You earned it. Wouldn''t you agree, Anat?', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95430, 'I am withholding my opinion on this subject matter. Just get on with it.', 944, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95431, 'Here are the Reins.', 942, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95432, 'Nerus, are we certain this is safe?', 941, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95433, 'No, we''re not. But if we wish to stop Ra and his Straegis army this may be our only hope.', 943, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95434, 'I am now fully in support of <<playername>> being the one to awaken the Furling.', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5750, 95435, 'How unsurprising... <<Playername>>, awaken it...', 945, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95554, '(You don''t speak with the creature so much as feel it... Images and idea seem to meander their way into your mind... You begin to get the sense that an idea is being implanted into your consciousness. It''s so alien, so impossible but... )', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95555, '(You suddenly know what to do - but there is no way you can ever articulate it...)', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95556, 'What''s happening?', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95557, 'It''s talking to me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95558, 'It uses language?', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95559, 'It''s more telepathic - like it''s implanting ideas but...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95560, 'They''re impossible to articulate? This matches with some of the other Furling data I have collected over time. ', 431, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95561, 'As it does with our data. ', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95562, 'Incredible... So it speaks to you, but only to you... It''s an intensely personal form of communication...', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95563, 'Does it know about Ra? And how to stop him?', 2410, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95564, 'I know what to do.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95565, 'But you can''t tell us what it is?', 431, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95566, 'It''s telling me how to stop the Straegis', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5751, 95567, 'Well then... By all means... Get to it. ', 0, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5752, 103950, 'You actually put a Goa''uld inside a sarcophagus for safe keeping?', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5752, 103951, 'I couldn''t kill him. And he is there if we need him later.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5752, 103952, 'Good thinking... Although you must have been tempted. At least we know about the lab. That''s probably the next step.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5753, 113235, 'I''m getting a rather odd reading. There are ancient energy signatures coming from Lucia. Certainly this is unexpected... They''re not consistent, but they are certainly there. You should look into it.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5753, 113236, 'You think there''s an Ancient technology cache here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5753, 113237, 'There''s something there. What it is, exactly, I can''t say. But it''s better to be safe than sorry and I''m stuck up here so...', 2568, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5753, 113238, 'I will investigate.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5754, 113354, 'It sounds like your friend found an Ancient face-hugger somewhere... They can totally devastate the mind. If this technology is legitimate, Tollak and Yotho are two very valuable contacts... With a very dangerous skill set.', 2568, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5755, 91854, 'You finish rigging the cache to self-destruct. Time to get out of here.', 722, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5756, 91892, 'You release Senl''c from the cage.', 1379, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5757, 91897, 'Upon a closer inspection you notice that the device has a crystal component attached to it - a technology similar to the emitter you found before. You notice three distinct depressions in the surface: Keys? Activation crystals? Dakor''s forces would need a way to get between the craters - they must carry the keys you need.', 796, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114497, 'Greetings. Your return is most welcome. Your unique skills are unfortunately necessary.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114498, 'Have the Replicators returned?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114499, 'No. Your return to sentience was the result of a negotiation with the High Council over a colony in crisis. The research colony of Pertho has been unreachable for several weeks. The Council fears the worst.', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114500, 'What inspires this fear?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114501, 'The colony had recently been subject to a series of experiments designed at improving body-consciousness integration in the hopes of restoring our genome. Since that event what little contact we had with the colony has implied a failure. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114502, 'Was the experiment deemed dangerous?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114503, 'There was associated risk. Your mission is to recover survivors, gather information about the experiment and liquidate the colony.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114504, 'This seems an extreme position given our lack of information. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114505, 'The data emerging from the colony indicates a cascade failure. You do not require details. I will give you a Prioritization Algorithm that defines which stored consciousnesses in the colony''s databank are to be preserved. ', 777, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114506, 'I cannot retrieve all of them?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5758, 114507, 'There is insufficient storage space on the Starship. You will save only those the Algorithm defines as priority. I wish you luck, $name$. I do not know what you will encounter down there, but I fear it will be disturbing.', 777, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5759, 112412, 'This creature was, in fact, a cloned Asgard body that has gone through profound genetic mutation. Protruding from the pile of mutated flesh is a smoldering consciousness hub. It is not reclaimable.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5759, 112413, 'The console the mutated Asgard was accessing indicates that it was trying to force the system to send an automated distress call. Somewhere inside that feral beast you just killed was one of your people...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5760, 99105, 'Incoming Transmission. Please stand by. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5761, 99141, 'You examine the downloaded schematics and determine that there are three active Consciousness Databanks within the Genetics Lab. Power in the facility is failing, so you don''t have much time to retrieve the stored minds.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5762, 99367, 'Our ship has received the data you uploaded, as well as the stored consciousnesses. We are pleased with your progress.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5762, 99368, 'Thank you, Supreme Commander.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5762, 99369, 'Heimdall has indicated that the degeneration exhibited in the experiment could be passed to healthy bodies from those infected. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5762, 99370, 'An airborne virus?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5762, 99371, 'It is believed to be passed through physical contact, but it is remarkably tranferrable. Heimdall was removed from his body upon arrival. For now, make your way to the Asgard Dome and process the consciousnesses there.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5762, 99372, 'What of those who are here and uninfected? Are they safe to transport?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5762, 99373, 'It depends on the degree of infection. Some may be saved. However, your primary directive remains: Pertho is to be vaporized. ', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5763, 99174, 'You realize that a security field is active. You will need to deactivate it from the security station to move freely around the Genetics Lab.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5764, 112415, 'This terminal controls the security field aperatus. Turning off this specific field may be difficult - the system seems to be glitching...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5765, 114969, 'Work with Heimdall to upload the stored Asgard minds to the orbiting starship.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115014, 'This is quite unexpected... Are you from the council?', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115015, 'I arrived recently. I was dispatched here because there has been no contact with the colony. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115016, 'No contact with the Colony? This is most disturbing... I was told by Mephir that they were sending distress notifications. This was done days ago - at the beginning of the outbreak. ', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115017, 'No messages made it out. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115018, 'This means the Asgard Dome was compromised... The entire colony is likely to be infected... I fear what might be found up there.', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115019, 'What''s the Asgard Dome?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115020, 'Pertho''s surface is highly volatile. The Colony was originally established in order to save the primitive human population from a series of tectonic shifts that released massive amounts of poison gas into the atmosphere. Domes were built and the population preserved.', 2409, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115021, 'The High Council agreed to this?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115022, 'It was a shock to many and remained controversial for generations. During the war with the Replicators the colony''s function evolved - expanding into a research and consciousness storage facility. ', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115023, 'I am here to preserve the consciousnesses in storage. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5766, 115024, 'As a precaution, no doubt. They are stored in data banks. I will upload the locations onto your personal computing device.', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99263, 'Your actions there destroyed many of those consciousnesses. There are no backups. You have terminated them.This is an egregious mistake...', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99264, 'It was no mistake. There is limited storage capacity on the Starship...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99265, 'The Council picks and chooses who survives? Using what criteria?', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99266, 'This is unknown to me. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99267, 'So you engage in a mindless genocide? ', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99268, 'It is not my wish to harm anyone. I am simply following my directives.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99269, 'What, specifically are those directives?', 2409, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99270, 'I am to collect consciousnesses, gather data on the genome experiment and then vaporize the colony.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99271, 'Vaporize the colony? Who ordered this?', 2409, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99272, 'Supreme Commander Thor.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99273, 'Are you able to directly communicate with him? I wish to speak to him before you proceed.', 2409, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5767, 99274, 'I believe he can be reached via relay through the Starship. ', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116828, 'Supreme Commander Thor, this is Heimdall. Your agent has loaned me this communications device.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116829, 'Heimdall. It pleases me that you are unharmed.', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116830, 'I am more pleased, I assure you. I must ask, why you have taken such drastic action on Pertho?', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116831, 'Lack of communication with the High Council aroused concern over the experiment. Investigation from orbit revealed a plague. Few non-mutated Asgard were detected. Systems were collapsing due to damage by feral subjects. The colony is failing, Heimdall. ', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116832, 'It is that widespread? I had hoped it was confined to the Genetics Lab area.', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116833, 'No. The Asgard Dome is overwhelmed. We must preserve what we can and liquidate the facility. ', 777, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116834, 'Understood. I can assist $name$ with gathering the experimental data. ', 2409, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116835, 'Excellent. After you deliver the data, you will be beamed to the orbiting Starship.', 777, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116836, '(The communicator goes dead.)', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117470, 'This is most gratifying. I was losing hope. I have kept this area clear of infested...', 3414, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5768, 116837, 'In order to get a complete set of data, you will have to follow me to my lab. There is a terminal there with all the requisite materials. The trip will be dangerous. Here is an improved attack confirguration for your drone.', 2409, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5769, 99300, 'I was forced to reprogram the door so that the infected Asgard could not get through. In order to move on we''ll have to reverse the programming. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5769, 99301, 'I will distract them while you take a flanking position for maximum effectiveness. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5769, 99302, 'It saddens me that we must eventually vaporize this Lab - it is the finest genetic manipulation technology we have ever created.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5769, 99303, 'This is a visualization of our DNA sequence. You can clearly see our degredation at the most fundamental level. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5769, 99304, 'I cannot settle myself over these deaths were are perpetrating. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5769, 99305, 'This ambush shows remarkable cerebral activity. Unfortunately my Lab is just down the corridor - through the mutants. There is no other way in.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5770, 114979, 'You stare at the containment field.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5770, 114980, 'Who is that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5770, 114981, 'Tyr. She is my long time research assistant, but she has contracted the mutation. I am unsure if it has progressed enough to effect her consciousness hub.', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5770, 114982, 'What if it has?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5770, 114983, 'Then she is lost. I do not have the heart to test for this myself. Use this device on her and I will gather the research materials required. ', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5770, 114984, 'If the mutation has progressed?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5770, 114985, 'Then she must die. I cannot bring myself to do that. It will be up to you to either beam her up, or terminate her. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5771, 99347, 'Clean. No genetic mutation detected.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5771, 99348, 'Negative. Genetic mutation at advanced stages.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5771, 99349, 'Indeterminate result. Mutation at borderline levels.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5772, 114996, 'Tyr''s death will not soon be forgotten.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5772, 114997, 'I am sorry.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5772, 114998, 'There was no other another option available to you. My files are prepared to be uploaded to the Starship. Use the matter generator to create a transport trigger. The ship can then beam me aboard.', 2409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5772, 114999, 'Your files are encrytped?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5772, 115000, 'Correct. Use the Olphir algorithm to decrypt. Good luck, $name$. I fear you face difficult hours ahead. ', 2409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5773, 113939, 'You use the matter device to create the transport tagger. Now you can apply it to Heimdall. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5774, 99346, 'You Olphir algorithm isn''t the simplest in the galaxy to implement. Leave it to a scientist to assume everyone knows it cold. You begin searching your memories for the process...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5775, 99100, 'Greetings... I hope the reintegration of your consciousness into a body went smoothly. I am Rekyr, commander of this vessel. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5775, 99101, 'Greetings. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5775, 99102, 'It has been several cycles since you were last integrated. The automated memory upgrade should have augmented any memory gaps, but if you have questions please do not hesitate to ask. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5775, 99103, 'We are heading to the Pertho colony, correct?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5775, 99104, 'Correct. Supreme Commander Thor has asked that I send you to the Hologram Terminal as soon as you are able. A transmission from him awaits you there. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5776, 116846, 'Heimdall informed me that you may require a more comprehensive map of the colony. I have uploaded this to your personal device.', 3299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5776, 116847, 'This is appreciated, Captain Rekyr.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5776, 116848, 'The domes were designed to house the primitive humans. However, scans do not show any as present. We fear they were consumed by the feral Asgard.', 3299, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5776, 116849, 'Consumed. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5776, 116850, 'The disease is regrettable. An additional Asgard ship has been detected in Pertho''s orbit, but it is not responding to hails. Scans indicate the communications equipment is damaged. We will investigate. It is possible they will be hostile to you because they may have no knowledge of this operation. ', 3299, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116860, 'Regrettable news: The Asgard Dome is suffering a power loss. This will make it difficult for transmissions eminating from within the dome to reach this ship. ', 3299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116861, 'I must activate the self-destruct.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116862, 'Correct. However, this new development makes your retreival something I cannot guarantee. ', 3299, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116863, 'Understood.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116864, 'As a precaution - if you are unable to contact us directly - upload your personal consciousness into the hub located in the same room as the self-destruct. We will monitor the world and if we detect a spike in energy we will upload that databank.', 3299, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116865, 'Will this work?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116866, 'It is a precautionary measure with a limited chance of success. Given that there is little time and the device must be activated, this is the best safeguard we can offer. ', 3299, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116867, 'I was always deemed expendable.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5777, 116868, 'Correct. I will try and prevent that eventuality. ', 3299, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5778, 110438, 'Captain Rekyr, I am prepared to activate the self destruct. Reply...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5778, 110439, '(There is no response... Just a light static.)', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5778, 110440, 'Repeat. Captain Rekyr, I am prepared to activate the self destruct. Reply...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5778, 110441, '(Again, silence. You grimly realize that you have no choice: You have to activate the self-destruct. After it is processing you must quickly upload your consciousness into the nearby hub computer. And hope.)', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5779, 117365, 'I am quite ready for evacuation. I am tempted to report the delay to High Councillor Otin.', 3406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5779, 117366, 'The delay was beyond my control. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5779, 117367, 'Of course... It is always someone else''s fault. I am ready for transport. ', 3406, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5780, 117369, 'I am pleased you found us. I am certain our rescue was no easy task. ', 3407, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5781, 117255, 'We are ready to be transported off this colony... Your arrival is most welcome.', 3410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5781, 117256, 'What about Rig?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5781, 117257, 'Rig is infected. As I have told you, Sif, he is not recoverable.', 3410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5781, 117258, 'I have a device which can determine if Rig can be saved.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5781, 117259, 'We must scan Rig quickly. The disease is overtaking him at a frightening pace.', 3409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5782, 117266, 'I refuse to stay here and be infected. Please beam me out.', 3410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5782, 117267, 'I will not leave without Rig.', 3409, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5782, 117268, 'I do not know if Rig can be saved.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5782, 117269, 'I understand. It is a decision you must reach yourself. I will stand at your mercy. I owe Rig much and do not wish to live with the ramifications of his death.', 3409, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5782, 117270, 'Can I please be beamed away?', 3410, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5782, 117271, 'Prepare yourself.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5783, 117435, 'Your arrival is most welcome. However, I cannot leave Pertho at this time...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5783, 117436, 'Why not?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5783, 117437, 'I have assembled a life''s work worth of hand collected data in one of the exterior labs. I cannot reach the lab myself, but I also cannot leave this world to be liquidated knowing that everything I have ever worked for is to be destroyed. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5783, 117438, 'If I retrieve your data you will go?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5783, 117439, 'If you do this I would forever be in your debt. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5784, 117278, 'I am feeling like something very bad is happening to me. Do I look different?', 3408, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5784, 117279, 'No.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5784, 117280, 'What are you doing?', 3408, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5784, 117281, 'You are infected. I am scanning you to determine the extent of your infection.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5784, 117282, 'Have I reached terminus?', 3408, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5784, 117283, 'I will know soon.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5785, 117287, 'The scan has returned as indeterminate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5785, 117288, 'You cannot tell if I am terminal?', 3408, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5785, 117289, 'It is unclear. I must speak to Buri.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5786, 117446, 'We have been monitoring the constant interactions with your ship... You are beaming up survivors?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5786, 117447, 'Yes. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5786, 117448, 'I am ready. However, Anvari is not. He has feverishly been collecting his data...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5786, 117449, 'There is not much time.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5786, 117450, 'I had this conversation with him. Perhaps you can try?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5786, 117451, 'I will. In the meantime, prepare for beaming.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5787, 116881, 'Leaving without my IGDs is not an option. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5787, 116882, 'IGDs?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5787, 116883, 'Image Gathering Devices. I have recorded everything that has happened here. It is imperative that this experiment - this abominiation - be preserved so that it may be viewed by the High Council and, if need be, all the Asgard. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5787, 116884, 'How many are out there?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5787, 116885, 'Three. All here in the Northern Dome. I managed to collect the others, but when I came here the feral were too numerous. Help me gather these, $name$. It is the only way to truly prevent this from happening again.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5787, 116886, 'I will get them. Prepare for transport in the interim. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5788, 92307, 'Access to safe rooms beyond security fields.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5789, 117302, 'You have decided to save him. I am most grateful...', 3409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5789, 117303, 'I do not know if it is the right choice. The risk is great...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5789, 117304, 'The result was indeterminate. When two choices are equally possible, should one not err on the side of hope?', 3409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5789, 117305, 'We shall see. Prepare for beaming.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5790, 117361, 'The terminal is straight-forward enough. The trick will be finding and collecting all of Einjar''s data. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5791, 117626, 'You have collected all of it?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5791, 117627, 'I believe this is correct. It is all contained on that data crystal. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5791, 117628, 'I am in your debt. Thank you. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5791, 117629, 'Prepare to be scanned and transported.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5793, 117176, 'Only three survived?', 3299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5793, 117177, 'Theirs were the only uncontaminated genomes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5793, 117178, 'So few. . . I hope you will have better results in the Northern Dome. You will need a shield to travel between the domes. Our readings indicate that atmospheric toxicity is 500% above normal.', 3299, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5793, 117179, 'Where can I find a shield?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5793, 117180, 'The airlock at the northern edge of the dome should have one. I will set a marker for you.', 3299, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5794, 117354, 'The terminal should have the shield technology built into it. Still, the intermittent power surges make coding in the requests tricky... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99608, 'You are here under the orders of Thor?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99609, 'Correct.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99610, 'There must be a new resolution. My team was sent to Pertho as a precaution several days ago. Our communciations equipment has been inoperable so I finally decided that we could no longer wait to act. We came to the surface and discovered this disease...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99611, 'My mission is to save any Asgard I can and then vaporize the planet.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99612, 'These Asgard we find here are feral - they consumed the humans that inhabited this area. Their consciousness hubs have been irreparbly damaged. They cannot be saved.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99613, 'We have been able to save some who were infected.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99614, 'How?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99615, 'Heimdall gave me a device which can detect the degree of mutation.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5796, 99616, 'Idun has contracted the sickness but has not shown symptoms of the disease externally. Can you use your device on her?', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5797, 99604, 'This is most encouraging. We can remove these hubs from infected bodies and preserve the consciousness?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5797, 99605, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5797, 99606, 'Please teleport Idun out. Personally this provides me great relief, Idun is part of my direct family line. To terminate her was a difficult proposition indeed. Hopefully we can work to save others.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5798, 99545, 'Unused Dialogue', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5799, 117455, 'The device you have is most inspirational. Are there others?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5799, 117456, 'I believe I could create one.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5799, 117457, 'Do so. I will give it to my team and we will assist in rescuing survivors. Make this a priority - those infected do not have much time.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5800, 117775, 'This Matter Generator is battered and low on power, but useful. You decide to use your drone''s own power supply to re-power the generator.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5801, 117776, 'In order to create the detection device you now need to re-program the Matter Generator. It''s a delicate task... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5802, 117387, 'We will get started immediately. Your ability to create this device is impressive, $name$.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5802, 117388, 'I will contact you before I activate the self-destruct.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5802, 117389, 'My team will be ready to beam off the planet quickly, when required. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117468, 'Please tell me that you are part of a rescue operation...', 3414, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117469, 'I am. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117471, 'Did you kill these others here?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117472, 'No. Once it became clear to us that that the disease affected the consciousness hubs directly, a decision was reached to self-terminate. I was left behind to monitor our defensive perimeter. ', 3414, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117473, 'All these scientists self-terminated?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117474, 'Correct. We can retrieve their consciousness hubs and preserve them now...', 3414, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117475, 'Before I can teleport you up to the Starship, I must verify that you are free of contamination.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117476, 'Understood. I have had limited contact with the feral, but they have tried to enter here. Some of my comrades are outside my defensive perimeter. Please retrieve their consciousness hubs before transporting me.', 3414, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5803, 117477, 'I will try and retrieve all I can. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5804, 117232, 'My team owes you a great debt of gratitude. You have saved many brilliant and valuable minds with this recovery.', 3414, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5804, 117233, 'Prepare for beam out. I must scan you to ensure you are clean of contamination.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5804, 117234, 'I am ready.', 3414, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100175, 'Your work at Pertho was impressive. We were able to save many of our more valuable consciousnesses. We have transferred some of these into new bodies in order for them to continue their valuable work. However, you mission was not a complete success.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100176, 'Of what do you speak, Councillor Otin?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100177, 'Your mission parameters were to save Asgard lives and vaporize the colony.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100178, 'This was achieved.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100179, 'You were not told to preserve records of the events on the planet.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100180, 'Anvari...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100181, 'Anvari has released the recovered images to the public. The response has been extremely unsettling. The public sector had not been aware of how limited our supply of suitable bodies has become. ', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100182, 'This became public knowledge?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100183, 'Correct. These images have caused great unrest among the Asgard population. There is great societal distress over this revelation. ', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100184, 'This was not my intention.', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100185, 'No matter. This indiscretion has had ramifications which require disciplinary action. The High Council has decreed that you will relenquish your body rights within one day''s time. ', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100186, 'Understood. ', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5805, 100187, '(There is no use in arguing with a decree. However, Thor might be able to help reverse this decision...)', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5806, 100188, 'Thor is on the Capitol Ship - just follow the path I have uploaded to your PDA.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102204, 'Father, we spill our blood on ground we cannot hold. We must withdrawal our forces and hold the Stargate. There we have hope of reinforcement.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102205, 'And we then ignore the rest of the planet. Dakara is a fight about hearts and minds as much as it is about soil and position. We cannot show weakness.', 2323, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102206, 'If we lose the Stargate, we lose the battle. We must reinforce that garrison - at all costs. ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102207, 'Baal has made no attempt on the Stargate. We cannot remove troops from our outposts to protect that which is not threatened.', 2323, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102208, 'Father, you have often preached to me the benefits of battelfield anticipation. The Stargate is crucial to our survival. Baal surely knows this. Loth''ta of the Ruk''yal has the largest force on the planet. Let us transfer his Jaffa to the Stargate. That will ensure its security.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102209, 'What of the naquadah he protects?', 2323, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102210, 'He can transport it here. Surely it is wise to have our naquadah supplies close at hand.', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102211, 'Very well, Moh''katan. Send a runner with the orders.', 2323, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102212, 'Master Bra''tac, I need to speak with Loth''ta already. . .', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102213, 'Then you can transport the orders for us. ', 2323, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5807, 102214, 'Time is of the essence. Each our we delay protecting the Stargate is an hour we are exposed to an attack. ', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5808, 101228, 'These are withdrawal orders... How is this possible? Who gave them to you?', 781, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5808, 101229, 'Bra''tac.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5808, 101230, 'Bra''tac? Impossible. You saw Bra''tac himself give these orders?', 781, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5808, 101231, 'No. Moh''katan issued the orders.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5808, 101232, 'Moh''katan! Always she wants to pull our forces back here. Ba''al does not have to win Dakara when she gives it to him inch by inch! Bra''tac gives his daughter too much power.', 781, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5808, 101233, 'Did you have an answer for me to take back?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5808, 101234, 'No, I will send my own answer to Bra''tac''s daughter.', 781, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5809, 97711, 'The Jaffa tweaked some of the systems, but the Stargate is safe enough for travel. Ready to dial up Dakara on your signal.', 843, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97866, 'Welcome to Dakara. You bring news about the warning we sent?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97867, 'Ba''al''s forces invaded the SGC. They used SG-18''s iris code to gain access to the base.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97868, 'Defeated? That is surprising given the power of Baal''s Jaffa... General O''Neill is a fine warrior.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97869, 'General O''Neill is missing. General Hammond is in command of the SGC.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97870, 'O''Neill is still missing? I had hoped he would have returned by now...', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97871, 'I''ve been sent to find SG-18...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97872, 'Of course. They were delivering supplies to Loth''ta, one of our clan leaders, at the naquadah repository. You can begin your search there.', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97873, 'I fear that if their Iris Device was used by Baal, they may be dead. ', 945, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5810, 97874, 'Let''s hope not.', 0, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97883, 'Welcome back, my friend. Did Teal''c hear our warning?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97884, 'It came too late, Master Bra''tac. Ba''al''s forces invaded the Tau''ri base, and were defeated.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97885, 'Defeated? General O''Neill is a fine warrior.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97886, 'General O''Neill was not present. Hammond of Texas is in command of the SGC.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97887, 'O''Neill remains missing? I had hoped he would return by now.', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97888, 'As did I. With O''Neill missing, we no longer receive the meager support the Tau''ri have given us in the past. The alliance with earth becomes a stone around our necks...', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97889, 'Enough, daughter. Your views on the Tau''ri are known. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97890, 'Master Bra''tac, Teal''c has asked me to search for SG-18. He fears that if Ba''al''s forces have used their iris code, they have come to great harm.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98262, 'He is a Goa''uld! You can no more trust him than you can trust... ', 2323, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5811, 97891, 'If their device was used, Teal''c is right to fear. They were delivering supplies to Loth''ta of the Ruk''yal, at the Naquadah repository. Search for them there.', 2323, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5812, 97892, 'What is one of the Tau''ri doing here?', 781, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5812, 97893, 'I am looking for SG-18.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5812, 97894, 'I do not have time to keep track of the Tau''ri. My Jaffa have held these naquadah stores for three weeks - three weeks with no reinforcements and no supplies. ', 781, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5812, 97895, 'SG-18 was bringing you supplies...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5812, 97896, 'I did not know this... I am sorry for my insolence. It has been many days without sleep or rest.', 781, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5812, 97897, 'Do you have any idea where they could be?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5812, 97898, 'There are several routes here from the supply stores. I will mark them on your map. You must know, there has been heavy fighting in these areas for several days. ', 781, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5813, 97906, 'Welcome, Jaffa! Are you the first of my reinforcements?', 781, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5813, 97907, 'No, Loth''ta of the Ruk''yal. I am in search of SG-18.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5813, 97908, 'Tau''ri? Why does a Jaffa waste time playing nursemaid to humans?', 781, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5813, 97909, 'Teal''c has asked me to search for them, and Master Bra''tac agrees.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5813, 97910, 'Teal''c is almost Tau''ri himself. It is no wonder he cares more for them than his own people. We battle for Dakara, for our people''s future, and he is on Earth. In safety.', 781, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5813, 97911, 'SG-18 was bringing you supplies when they went missing. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5813, 97912, 'If this is true then I have been rash in my judgment of you and the Tau''ri. There are various routes they could have taken from the supply stores. Llet me mark them for you on your map. Be cautious. These areas have seen heavy fighting.', 781, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5814, 97913, 'You detect a weak radio signal coming from nearby. Possibly an S.O.S.? ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5815, 97921, 'You''ve located SG-18?', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5815, 97922, 'Yes, sir. They did not make it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5815, 97923, 'Understood... Please arrange with Bra''tac to have their bodies returned to Earth for their families. I''ll write up the service letters...', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5815, 97924, 'Sir, I think this is too convenient.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5815, 97925, 'What do you mean?', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5815, 97926, 'Ba''al''s forces needed a GDO and SG-18 was left very exposed...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5815, 97927, 'You think there is a spy somewhere inside Bra''tac''s army... Well, we owe it to those kids to look into this... Find out what you can. ', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97928, 'You''ve located SG-18?', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97929, 'Hammond of Texas, I am sorry.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97930, 'Thank you for your efforts... Please make arrangements with Master Bra''tac to have their bodies returned to Earth.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97931, 'I will continue to investigate here.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97932, 'What are you investigating?', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97933, 'The circumstances of their death leaves me uneasy. They were left exposed in their mission. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97934, 'You believe the recovery of their GDO may have been more than a happy accident? This would mean there is a spy somewhere inside Bra''tac''s army.', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97935, 'I fear it is possible.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97936, 'Well, I can''t order you to do anything but... I can tell you that anything you can find out will be greatly appreciated. ', 2609, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5816, 97937, 'I will keep you appraised, General. ', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5817, 97944, 'What news of SG-18?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5817, 97945, 'They are dead, Master Bra''tac.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5817, 97946, 'The tragedies of this fight continue to mount. I will arrange to have their bodies returned to Earth.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5819, 102215, 'The death of SG-18 is very serious. We need Tau''ri support in order to maintain our control of the Stargate. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5819, 102216, 'I thought you did not approve of that alliance.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5819, 102217, 'I a serve the Free Jaffa. My personal opinions about the alliances my father makes are not important. Strategically we have come to rely on the Tau''ri and the death of their agents could damage that relationship. We must discover how Ba''al knew SG-18 was on Dakara.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5819, 102218, 'How can I help?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5819, 102219, 'I have several scouts who have infiltrated Ba''al''s forces. It is easier than you think to infiltrate a Jaffa army made from many tribes.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5819, 102220, 'What do you want me to do?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5819, 102221, 'I communicate with my spies using coded messages placed at secret drop points. I need someone to place the orders at the designated locations. I will identify their positions on your map. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5820, 97991, 'The orders were delivered successfully?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5820, 97992, 'One per location.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5820, 97993, 'Excellent.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5820, 97994, 'They will be able to tell me who set up SG-18?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5820, 97995, 'If I am not mistaken, that information will be made clear to you very, very soon.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5821, 97985, 'You hide the coded orders in the drop location.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102231, 'While we wait for word from my spies, you can be of some use to me.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102232, 'What do you need?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102233, 'My spies tell me that Ba''al is massing his forces to attack the Inner Ring around the Stargate. He will try to overwhelm our guards and take the gate. I believe he will attack through the Western Gate.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102234, 'This is why you wanted it defended?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102235, 'Yes. Go to the Jaffa captain at the eastern tents. Our forces at the western gate need supplies - and a commander.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102236, 'A commander?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102237, 'I require you to lead them in defense of the Inner Ring. You will see how badly we need Loth''ta''s forces.', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102238, 'Should we inform Bra''tac of this?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5822, 102239, 'The attack is not certain. Until we know for sure we will not disturb him with theories. I know him well. He will not appreciate the interruption.', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5823, 102162, 'Moh''katan says that Ba''al plans an attack soon?', 2958, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5823, 102163, 'I am to command our defenses at the western gate. You have supplies for the forces there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5823, 102164, 'Our Jaffa at the eastern gate have greater need.', 2958, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5823, 102165, 'Moh''katan believes that Ba''al will attack from the west.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5823, 102166, 'Of course. Good luck, $race$.', 2958, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5824, 102118, 'Yes?', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5824, 102119, 'There is no sign of Ba''al''s forces. Are you sure your spies were correct?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5880, 103277, 'Yes... It is very nice to meet you. Now, I really must be going...', 1778, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5824, 102120, 'It is possible they were misled. But they insist that Ba''al will attack today. You must have patience. Baal is a master strategist. His forces will not attack when we expect.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5825, 98024, '. . . help. . . nder atta. . .', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5825, 98025, 'Say again. Your transmission was not clear.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5825, 98026, 'We are und. . . eed help! We are und... attack!', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5826, 102255, 'Thank you for coming to our aid.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5826, 102256, 'Moh''katan''s spies got it wrong.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5826, 102257, 'It would not be the first time.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5826, 102258, 'This has happened before?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5826, 102259, 'I am loyal to Moh''katan, let me be clear. But her spies are legendary... For reasons one would not covet.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102130, 'I heard about the attack on the Eastern Gate. Your quick decision to assist was well considered. Well done. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102131, 'I pulled resources away to defend the wrong gate.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102132, 'Perhaps.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102133, 'Perhaps?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102134, 'Did it occur to you that Ba''al might attack at both gates? Your decision to leave your post left the Western Gate without leadership. In the future I expect you to consult me before you make strategic adjustments.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102135, 'The Eastern Gate garrison was being overwhelmed.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102136, 'And I could have sent reinforcements. You rashly abandoned one gate to save the other - and did not inform me of this choice. This army - my army - is disciplined, always. Do you understand?', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102137, 'Yes. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5827, 102138, 'I value your heroism. I require your loyalty. The first is worthless without the second. ', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5828, 98067, 'You delivered the withdrawal orders to Loth''ta at the naquadah repository?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5828, 98068, 'Yes, Master Bra''tac.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5828, 98069, 'He has not yet withdrawn his forces. I need you to go and speak to him. Find out when we can expect his Ruk''yal to defend the Stargate.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5829, 98073, 'Withdraw? I will never withdraw. The Ruk''yal do not run like cowards, not over ground we earned with our blood. We will never allow the naquadah to fall into Ba''al''s hands.', 781, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5829, 98074, 'Master Bra''tac wants you to bring the naquadah with you.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5829, 98075, 'This is impossible! Bra''tac knows this. Even if we took just the weapons-grade naquadah, it would leave behind a dangerous arsenal for Baal to control. No. Tell your Master Bra''tac that Loth''ta of the Ruk''yal will not abandon this post.', 781, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5830, 98081, 'I feared as much. And his point about transporting the Naquadah is reasoned. We have no choice. Moh''katan, order reinforcements sent to the Naquadah Repository.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5830, 98082, 'Reinforcements? He defies you, father. ', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5830, 98083, 'As do you - at every turn! Order your troops to support Loth''ta. Now.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5830, 98084, 'This is a mistake, father.', 945, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5830, 98085, 'This is my will. Serve it with no more debate. ', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5830, 98086, 'As you wish. I request that after I give the order, you allow me to retire for some time... I grow fatigued. ', 945, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5830, 98087, 'Do as you will, daughter. But give the order to reinforce Loth''ta first.', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5831, 102240, 'Something isn''t sitting right with you about Moh''katan. Her behavior seems almost... Erratic? You decide to investigate further.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5832, 98160, 'You must forgive my daughter. She is young and passionate. Her talent sometimes exceeds her experience.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5832, 98161, 'She seemed surprised that the invasion of the SGC was defeated.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5832, 98162, 'Moh''katan does not have faith in the Tau''ri. The NID did much to reinforce that when they took some of her Jaffa in a misconsidered raid. O''Neill and Hammond have failed to return them to us... This has not sat well with her.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5832, 98163, 'And her anger towards Loth''ta?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5832, 98164, 'My daughter holds Jaffa traditions dear. Loth''ta''s defiance would have cost him his life just a generation ago. She often laments that she was born in the wrong age. Worry not about Moh''katan. Her emotions pass quickly.', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5833, 98165, 'You wish for information about Bra''tac''s daughter? It has been many years since he last saw her. When the Free Jaffa began rebelling against our Goa''uld masters, he sent her into hiding on Chulak for her protection.', 2179, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5833, 98166, 'Is she committed to the Free Jaffa?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5833, 98167, 'She and Bra''tac fought bitterly about his dream at first - she is like many Jaffa, trapped by tradition. Eventually she stood at his side and has since never wavered.', 2179, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5833, 98168, 'Do you trust her?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5833, 98169, 'I trust Master Bra''tac with my life.', 2179, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5833, 98170, 'That wasn''t what I asked.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5833, 98171, 'I know. ', 2179, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5834, 94204, 'You download Moh''katan''s recent orders. You find conflicting messages sent to troops, orders to withdraw at odd times, and other discrepancies. Each of these orders occurred right before Ba''al''s forces gained ground on Dakara.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5835, 92437, 'You find one of Moh''katan''s coded messages, still in its hiding spot.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5836, 92441, 'The message you placed here has already been taken.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5837, 94206, 'You decode the message and discover that it contains orders to deliver a message directly to Ba''al. The message describes the failure of his invasion of the SGC.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5838, 113513, 'What is this? These are orders... Moh''katan''s orders? You question my daughter''s competence?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5838, 113514, 'Not her competence. Her loyalty.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5838, 113515, 'Be very careful, $name$. My daughter and I may disagree, but you are questioning the honor of one in my family. ', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5838, 113516, '(You hand Bra''tac the message to Ba''al)', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5838, 113517, 'This... what is this? Where did you get this?', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5838, 113518, 'It is one of Moh''katan''s messages to her spies. She had me deliver them.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5838, 113519, 'This... I must speak with my daughter.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5839, 101236, 'Moh''katan has not left her tent since our earlier fight. You will meet me at her tent and see that she can explain this message. She would never betray me.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98257, 'What is this?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98258, 'Father...', 945, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98259, 'This is awkward.', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98260, 'Baal... You betray your family to serve Baal? A Goa''uld?', 2323, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98261, 'I serve no one, father. I am his equal.', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6344, 120089, '<Input text here.>', 3572, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98263, 'You? I can trust you? You, who spits upon our traditions - makes us dependent upon the Tau''ri for Tretonin, turns our warrior culture into a bureaucracy... You I should trust?', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98264, 'I helped give us freedom! His kind enslaved us for thousands of years.', 2323, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98265, 'Baal and his Praxis alliance offers us a future of honor, father. Not as farmers or bankers or refuse collectors... but as warriors in our tradition. We were bred for glory, not politics.', 945, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98266, 'Do not do this...', 2323, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5840, 98267, 'It is done already. ', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5841, 98269, 'Search the room... If she was working with him there may be something of use here... ', 771, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5841, 98270, 'Are you alright?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5841, 98271, 'I am in shock... Please... We haven''t much time. ', 771, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5842, 98277, 'This seems to imply that they have been working together for some time... Why would she do this?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5842, 98278, 'Master Bra''tac, what do we do now?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5842, 98279, 'She lied. . .', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5842, 98280, 'Master Bra''tac! ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5842, 98281, 'I must return to the command tent. Ba''al will launch a full scale attack. My daughter made it easy for him. ', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98291, 'You have seen the Hataks?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98292, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98293, 'Ba''al has launched a full assault. Moh''katan lied when she said his ships were destroyed. He was merely holding them in reserve.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98294, 'And your armies?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98295, 'We are getting reports that many of our forces are allying with Ba''al. It seems Moh''katan''s influence is stronger than I thought.', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98296, 'She is her father''s daughter.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98297, 'We must bring those Hataks down, but we have nothing here that can do it. Defeat is inevitable.', 2323, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98298, 'Perhaps the SGC and General Hammond can help. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5843, 98299, 'It is worth a try. We cannot last long given the current situation.', 2323, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104877, 'I cannot commit troops to a war on another planet. The Pentagon would never authorize it - I''m already trying to keep them from closing the SGC because of the recent Jaffa invasion here.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104878, 'General Hammond, we have to support the Jaffa. If they lose Dakara, it will fracture the Free Jaffa Nation. Our strongest ally in the galaxy would be gone.', 2184, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104879, 'I need another option besides boots on the ground.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104880, 'What about equipment?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104881, 'That''s not a bad idea! General, remember how Jack destroyed Ra''s ship, on the first trip to Abydos? We could do the same thing...', 2184, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104882, 'There is no way I''d get authorization to deploy a nuclear weapon to Dakara.', 2609, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104883, 'We don''t need a nuke, General. An overloaded naquadah generator has as much destructive potential, and is much more stable. ', 2184, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104884, 'And it''s portable. There are times when you frighten me, Colonel. I assume you have a naquadah generator on hand?', 2609, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104885, 'Yes, sir. Two of them.', 2184, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5844, 104886, 'Colonel Carter, bring them to the Gate Room.', 2609, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5845, 104862, 'These naquadah generators are designed to provide power. In order to produce a detonation, you''ll have to force them into an overload state.', 2184, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5845, 104863, 'How do I do that?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5845, 104864, 'Carefully. Once they''ve entered overload, you have a limited period of time to place them on the ring transporter and send them up to the Hatak. If you don''t make it...', 2184, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5845, 104865, 'They detonate.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5845, 104866, 'Right.', 2184, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5846, 102241, 'Ba''al''s Hataks have taken position above two plazas to the south. Those plazas were being held by forces under Moh''katan''s control. They''ve allied themselves with Ba''al.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5846, 102242, 'Do they have ring transporters set up there?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5846, 102243, 'Yes. Ba''al is using them to bring fresh troops and supplies down to the surface. They will be well defended... I can send troops with you but a large force might alert Baal to our plan...', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5846, 102244, 'No, this must be a covert operation.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5846, 102245, 'It will be dangerous. Keep yourself safe.', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5847, 102263, 'Did they send any help?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5847, 102264, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5847, 102265, 'That is a relief. Master Bra''tac is waiting for you at the command tent.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5848, 99471, 'I would ask if you have been successful, but everyone on Dakara knows that it is so. Sadly, our time for celebration is short.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5848, 99472, 'What happened?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5848, 99473, 'Ba''al''s forces have taken control of the Superweapon courtyard. If they gain access to the weapon''s controls... It is not just Dakara that is in danger.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5848, 99474, 'I will come help.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5848, 99475, 'Baal has turrets set up which prevent me from sending in troops. If those could be disabled...', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5848, 99476, 'I will do what I can. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5849, 98342, 'What news? Do Ba''al''s forces still control the Superweapon?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5849, 98343, 'I''ve destroyed the turrets...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5849, 98344, 'I will send the reinforcements in. The Free Jaffa will remember your actions for generations.It is only a matter of time. Dakara is ours!', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5850, 102246, 'Ba''al''s forces are in retreat. The Free Jaffa Nation will finally be able to take control of Dakara.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5850, 102247, 'What about Moh''katan?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5850, 102248, 'She is dead to me. Please tell Hammond of Texas that the Tau''ri will no longer be required to support our refugees. They will soon return to their homes on Dakara and the Free Jaffa Nation will be able to assist in the search for O''Neill.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5850, 102249, 'I will give him the good news.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5851, 98355, 'Ba''al''s forces are in retreat. The Free Jaffa Nation will finally be able to take control of Dakara.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5851, 98356, 'What of Moh''katan?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5851, 98357, 'She has damaged my reputation amongst the council. For now, inform Hammond of Texas that the Tau''ri will no longer be required to support our refugees. They will soon return to their homes and the Free Jaffa Nation will be able to assist in the search for O''Neill.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5851, 98358, 'I will inform him of this.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5851, 98359, 'I want you to be a new liason between the Free Jaffa and the Tau''ri. You have accomplished much already. I know you can do more. Will you accept?', 2323, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5851, 98360, 'It would be an honor, Master Bra''tac.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95571, 'The energy signature is similar to that of a Straegis. This is a Furling. ', 943, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5852, 98365, 'So the situation on Dakara is under control? That will give me some good news to report to the Pentagon. Hopefully they will consider it before making their decision.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5852, 98366, 'Sir?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5852, 98367, 'Agent Woolsey is recommending that the Stargate program be terminated. Ba''al''s invasion did not succeed as a direct attack, but it''s making people in Washington evaluate how vulnerable the Stargate makes earth...', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5852, 98368, 'Sir, they can''t really be thinking of closing the SGC.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5852, 98369, 'Well, they are. No one ever accused politicians of being forward thinkers. For now, let''s get you placed with another SG team...', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5853, 98377, 'The victory at Dakara is good news. Congratulations. Your people earned it. Please congratulate Master Bra''tac for me. I''ll have Sgt. Harriman dial the Stargate back to Dakara for you.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5853, 98378, 'General Hammond, Master Bra''tac has asked me to serve as liason between the Free Jafa and the Tau''ri.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5853, 98379, 'I would be honored to have you. However, I do not know how much longer the SGC will remain open.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5853, 98380, 'I do not understand.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5853, 98381, 'Members of our government on Earth are afraid that the Stargate makes us too vulnerable to attack. They are pushing to shut down the program.', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5853, 98382, 'I will remain, and trust that your Earth government understands how vital the SGC is.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5853, 98383, 'I hope your trust is well founded.', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5854, 98402, '...and so we have decided, after much deliberation, to discontinue the Stargate program. General Hammond will arrange your transfer to another post.', 1300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5854, 98403, 'You''re actually closing it?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5854, 98404, 'Yes, I am. The resources this program has wasted will be better spent elsewhere. The Stargate program has repeatedly placed earth in jeopardy. It won''t happen again. ', 1300, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5854, 98405, 'Respectfully, sir, that is a short-sighted view of the situation.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5854, 98406, 'Respectfully, you''re not paid to think. You''re paid to follow orders. See General Hammond for your new assignment.', 1300, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5855, 98407, '...with that decision being made, your services as liason to the Jaffa on Dakara are no longer needed.', 1300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5855, 98408, 'Master Bra''tac will tell me when my services are no longer needed.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5855, 98409, 'You are no longer authorized to be on this base. Speak to General Hammond to arrange a time when you can return to Dakara, or I can have the MP''s confine you until I''ve made the arrangements. Your choice.', 1300, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5855, 98410, 'I will speak to Hammond of Texas. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5855, 98411, 'You do that.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5856, 117738, 'I''m afraid Mr. Woolsey is correct. Without the IOA''s support, the Pentagon cannot afford the Stargate program.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5856, 117739, 'Sir, can''t you convince them to keep the gate open?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5856, 117740, 'I''ve fought this battle for a long time, $name$. In fact I''m still fighting it... ', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5856, 117741, 'There has got to be something we can do...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5856, 117742, 'I''m doing a lot more than I can discuss here... But the fact remains, the IOA wants to close the SGC and right now they are in charge.', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5856, 117743, 'Sir, General O''Neill is still missing. If the SGC shuts down...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5856, 117744, 'That''s a decision that''s above your pay grade, soldier. Now, gather yourself up. I need you to deliver a message to Dr. Jackson at one of our off-world bases. Have Sgt. Harriman dial the gate for you. See me before you go, I''ll have your transfer orders ready.', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5857, 100410, 'You were sent to me directly by General Hammond?', 843, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5857, 100411, 'Yes, he''s sending me to...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5857, 100412, 'He''s already informed me that I should send you along to the classified location. Good luck!', 843, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5858, 100429, 'Welcome to the Omega Site. Daniel Jackson and the Leadership Council are expecting you. I will upload his location to your personal computing device. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5858, 100430, 'What is this place?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5858, 100431, 'You humans call it a "secret". ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5859, 96367, 'Find a way out of the Cellblock. Without Marsh.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96782, 'Woah! Where did you come from? Were you the one that cleared the armory?', 1109, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96783, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96784, 'I never thought I''d be thanking a Jaffa, but thank you! We''ve got a real shot at getting out of this place now that we''ve got weapons.', 1109, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96785, 'I have been ordered to assist you by Moh''katan of Chulak.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96786, 'We need all the help we can get. One of our officers - Capt. Copplemann - led a fire team out to rescue one of our scientists. They haven''t come back. ', 1109, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96787, 'I will find this Capt. Copplemann.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96788, 'Please do. We''d like her back alive... ', 1109, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5861, 96789, 'This is my intention.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5862, 93218, 'This is Moh''katan of Chulak. Do any Jaffa receive this message? I repeat, this is Moh''katan of Chulak. Are any of my Jaffa warriors inside the Castle?', 2499, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5862, 93219, 'I hear you, Moh''katan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5862, 93220, 'Have you seen more of my warriors? What is your situation? Have you seen Col. Marsh?', 2499, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5862, 93221, 'Marsh is dead - killed by a creature. Perhaps one of the ''Straegis.'' There are many Tau''ri here, and some Jaffa.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5862, 93222, 'Work with the humans to break out of the Castle. We wait for you by the Stargate.', 2499, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5863, 95013, 'Items and Inventory
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5863, 95014, 'Equipping Items
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6064, 101318, 'Thank you. I''ll get my people in it right away. ', 941, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5863, 95015, 'Activating Items
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5863, 95016, 'Item Information
