INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5869, 94900, 'Gate Mail
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5870, 95035, 'Trainer
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5870, 95036, 'Skill Branches
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5871, 95099, 'Vendor
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5871, 95100, 'Buying Equipment
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5871, 95101, 'Selling Equipment
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5880, 103278, 'Stop. You''ve got a choice. You can answer some questions at Omega Site and then go free... Or you can negotiate with Ra''s people here...', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5880, 103279, 'Your choices are terrible. However, I will visit your Omega Site. ', 1778, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5880, 103280, 'That''s gratitude for you. Thanks <player name>. We''ll take him from here.', 1959, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5871, 95102, 'Buying Back Equipment
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5871, 95103, 'Repairing Equipment
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5872, 95091, 'Minigame Prompt
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5872, 95092, 'Playing the Minigame
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5872, 95093, 'Calling for Assistance
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5872, 95094, 'Player Tab
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5872, 95095, 'Contacts Tab
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5872, 95096, 'Observing Minigames
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5873, 103821, 'You successfully hack the safe and remove the coded decrees.', 1894, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5875, 117667, 'I''m afraid Mr. Woolsey is correct. Our government has decided to end the Stargate program. Please give my apologies to Bra''tac.', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5875, 117668, 'You must be outraged.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5875, 117669, 'Oh, you have no idea... However, there isn''t much I can do... Yet.', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5875, 117670, 'What of your O''Neill?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5875, 117671, 'I was hoping Bra''tac would continue the search for him. But our ability to support that search is limited at best.', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5875, 117672, 'We we look for O''Neill regardless of Tau''ri support. We owe him much. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5875, 117673, 'We appreciate that, perhaps more than you know. I have a message for you to deliver to Bra''tac. He''s at one of our most secret locations. Speak to Sgt. Harriman about dialing the gate address for you.', 2609, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5876, 104244, 'My timing is perfect: I arrive here just in time to see you save the Jaffa people. Case closed. Well done, <<playername>>.', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5876, 104245, 'You may have saved millions of lives - a revolution within the Jaffa culture was possible. We will deliver the cure as soon as it is ready. ', 2323, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5876, 104246, 'The Free Jaffa owe you a debt of gratitude... ', 1333, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5876, 104247, 'What about this Mouth of Ptah. The technology is amazing. It could be useful.', 2410, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5876, 104248, 'The activator key was absorbed upon use, was it not?', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5876, 104249, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5876, 104250, 'We will send a science detachment to Men''fa to try and determine the nature of this tecnhology. It is beyond what was known to be used by Ra. <<Playername>>, your work on Men''fa was most commendable.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5878, 104805, 'The situation on Beta Site remains problematic... We need you to take this antidote to Colonel Carter and get it distributed, right away. ', 2410, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5878, 104806, 'Ras''nor''s people are in great need.', 1333, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5878, 104807, 'There is much to consider here. While we have found an antidote to the Tretonin poisoning, we have not solved the larger question: Why?', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5878, 104808, 'Indeed. There is now time for this question to be answered.', 1333, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5878, 104809, 'The Jaffa Dakor would seem a logical starting point for an investigation. ', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5878, 104810, 'If I know Colonel Carter, she is already looking into it... First things first - let''s get this antidote down there, pronto. We''ll worry about Dakor after we''ve stopped this disease cold. ', 2410, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5879, 95018, 'Controls and Movement
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5879, 95019, 'The W, A, S, and D keys on your keyboard move your character forward, left, back, and to the right.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5879, 95020, 'Use the C key on your keyboard to enter crouch mode. When you crouch, you move more slowly but gain defensive benefits in combat. Press C again to leave crouch mode.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5880, 103276, 'This is Saarthon...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5881, 104384, 'Inside the cell you see Saarthon... You had left him in his sarcophagus - clearly Ra''s minions pulled him out and dragged him here. If he is desperate, he might turn out to be a valuable source of information...', 1926, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5882, 95024, 'Equipping a Weapon
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5882, 95025, 'With your inventory open (press ''i''), right-click on the weapon icon to equip it. The icon disappears - this means it''s been equipped to your Character Sheet (press ''z'' to open).
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5882, 95026, 'Once your weapon is active, create an ability shortcut to use with that weapon. Open your ability window (press ''T''). Find the ''Pistol Shot'' ability by mousing over the active icons - the ability name will appear in a tooltip.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5883, 95073, 'Combat
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5883, 95074, 'Targeting
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5883, 95075, 'Attacking
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5883, 95076, 'Reloading
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5883, 95077, 'Cover
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5883, 95078, 'The Cover Indicator
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5883, 95079, 'Health and Focus
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5884, 99090, 'There is an electronic locking mechanism on this shipping container. It should be easy enough to hack.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5885, 95087, 'World Interaction and Feedback
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5885, 95088, 'World Interaction
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5885, 95089, 'Mouse Cursors
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5885, 95090, 'Particle Feedback
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5887, 95378, 'It''s amazing... How do we communicate with it?', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5887, 95379, '(You feel a strange pulling... The Furling - it wants to communicate with you.)', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5887, 95380, 'It wants to speak to me.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5887, 95381, 'Telepathy?', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5887, 95382, 'Yes. Or something even more complex.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5887, 95383, 'Do I have permission?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5887, 95384, 'Yes, <<playername>>... Please engage.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5888, 95390, 'Your mission was a success... There has already been a marked drop in Straegis energy signatures within the galaxy.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5888, 95391, 'I don''t think I''m quite done...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5888, 95392, 'The Furling calls you?', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5888, 95393, 'Yes.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95568, 'Is it going to speak?', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95569, 'Can it speak?', 500, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95570, 'I do not know... It is certainly alive enough... ', 942, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6202, 107790, 'I can calibrate it for you, for a fee.', 492, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95572, '(You feel a strange pulling... The Furling - it wants to communicate with you.)', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95573, 'It wants to speak to me...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95574, 'How do you know this?', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95575, 'It is likely that it speaks using directed telepathy or something similar. If it wants to speak with <<Playername>> we should not resist. ', 943, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95576, 'Why does it not want to speak to me?', 944, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5889, 95577, 'No one answer that question. We need to focus. <<Playername>>, find out what it wants. ', 942, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5891, 95532, 'You seem to have succeeded.', 942, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5891, 95533, 'Throughout the galaxy there has been a reduction in Straegis energy signatures already... ', 943, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5891, 95534, 'I don''t think I am finished.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5891, 95535, 'It''s talking to you again? You guys are getting close.', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5891, 95536, 'There''s more?', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5891, 95537, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95538, '(You don''t speak with the creature so much as feel it... Images and idea seem to meander their way into your mind... You begin to get the sense that an idea is being implanted into your consciousness. It''s so alien, so impossible but...)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95539, '(You suddenly know what to do - but there is no way you can ever articulate it...)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95540, 'What is happening?', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95541, 'It''s talking to me.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95542, 'It uses language?', 943, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95543, 'It''s more telepathic - like it''s implanting ideas but...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95544, 'What kind of ideas?', 944, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95545, 'Perhaps it utilizes a form of mind control...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95546, 'I have read that the Furling communicated in a way unknown by other species. They would implant ideas, speaking almost as we Goa''uld do with our hosts - intrinsically. However, there was always this notion of not being able to articulate what was communicated... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95547, 'I know what to do... How to stop the Straegis. But I cannot describe it to you...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95548, 'We are just supposed to trust you? You have contacted an ancient, powerful being and now you wish to just leave us without any explanation? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95549, 'It does seem a tad convenient.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95550, 'There is no way to explain this... But I can stop the Straegis.', 0, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95551, 'You are just unable to tell us how?', 942, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95552, 'You must trust me. I can stop them.', 0, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5892, 95553, 'Then stop them. And if anyone in this room raises a finger to stop you? They will die where they stand. ', 945, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5893, 95729, 'Enough. We have come to a decision. Please see Supreme Commander Thor for your answer.', 929, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5894, 95822, 'Crafting
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5895, 95906, 'Find and dispose of the Burtonol spy within the Praxis.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5896, 95907, 'Marsh tells the player about the Burtonol spy within the Praxis. He advises the player that there may be digital evidence of the spy''s activity within the computer network. He tells the player to take out the spy.', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5897, 95913, 'The player somehow needs to use the computer to figure out where the spy is going to be (he''s going to be in the market).', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5898, 95914, 'The player succesfully hacks the computer network and finds that the Burtonol spy is meeting his contact at a stall in the covered market. The player can kill tow "birds" with one stone.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5899, 95916, 'The player wants to buy some explosives and a remote detonator from Hansen.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5900, 95918, 'The player has succesfully placed the bomb. He/she should now hide and wait for the Spy and the Burtonol rep to meet up.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5901, 95920, 'The player tells Marsh that the spy and the burtonol contact have been taken care of. Marsh makes excuses for why his fantasy team lost in the first week.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5902, 95955, 'You compile the behavior data into simulated conciousness matricies. This should allow them to be run in a simulator to see how they react under programmed circumstances.', 2357, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5903, 95953, 'The simulator briefly processes and returns the results.', 2357, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5904, 95954, 'You summarize the simulation results for Mimir.', 2357, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5905, 96386, 'You will need a network access card to gain entry to the system.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5907, 103875, 'I am injured. Too much damage... My host will perish if you do not get me to a sarcophagus.', 1777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5907, 103876, 'Then you better tell me where the Mouth of P''tah is.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5907, 103877, 'Please, I don''t know.', 1777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5907, 103878, 'You''re in no position to play games.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5907, 103879, 'Just get me to a sarcophagus... Once there I will tell you everything I know...', 1777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5908, 102543, 'I am injured. Too much damage... My host will perish if you do not get me to a sarcophagus.', 1777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5908, 102544, 'I need the cure for the Jaffa plague.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5908, 102545, 'Get me to a sarcophagus and I will help you...', 1777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5908, 102546, 'How can I trust you?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5908, 102547, 'I am going to die! Please!', 1777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5908, 102548, 'Let''s get going.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5909, 104480, 'This - thing - seems to be able to see directly into you, burrowing into your mind. It speaks in ideas and concepts that solidify and then recede. It knows what you want. Within a few seconds it has modified the Book of the Gates. It has been decrypted - within seconds... Amazing.', 1876, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5910, 104481, 'This - thing - seems to be able to see directly into you, burrowing into your mind. It speaks in ideas and concepts that solidify and then recede. It knows what you want. Within a few seconds it has conjured up an object - seemingly out of nothing. It''s a cure for the poisoning. You''re sure of it. ', 1876, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5911, 104887, 'UNUSED DIALOG', 2801, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5912, 103483, 'The stasis bomb is now active...', 2801, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5913, 104377, 'You carefully gather the genetic material sample', 1918, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5914, 104378, 'You carefully gather the genetic material sample', 2660, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5915, 104379, 'You carefully gather the genetic material sample', 2661, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5933, 96722, 'You successfully translate the primary Goa''uld script of the Barak''Ka''Ra Wall.', 813, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5953, 104456, 'Can you believe this place smells worse than Men''fa? Seriously. Unas... Not a clean species.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5953, 104457, 'Any information?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5953, 104458, 'No. The only thing we found was a fancy wall with some stuff we couldn''t translate. When I reported this to Harset, Baal told me to give you this - a video transmitter - and call Nerus. ', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5953, 104459, 'Anything else?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6202, 107791, 'Calibrate it?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5953, 104460, 'The Unas are nasty. And violent - so watch yourself. I am sure you expected nothing less after Men''fa... Ra left behind some very loyal, violent followers.', 1885, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5954, 104405, 'You successfully activate the Wall of the 13th Hour.', 1127, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97362, 'What the hell is happening down there?', 2609, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97363, 'I apologize, General Hammond. When I entered this room I witnessed a Jaffa planting an explosive device. I disabled it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97364, 'A Jaffa? Is this one of the refugee Jaffa from Dakara that Teal''c just warned me about?', 2609, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97365, 'I believe this to be the case, General.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97366, 'Well, excellent work on the explosive. I need you to do something else for me, if possible. ', 2609, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97367, 'I am here to serve you. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97368, 'Colonel Carter was in her lab at the time of the attack and she hasn''t responded to radio calls. Normally this wouldn''t concern me because she occasionally likes to work undisturbed, but...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97369, 'You wish for me to confirm she is safe?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5955, 97370, 'Yes. Her lab is on level 19.', 2609, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5956, 97528, 'Welcome to Svarog''s Goa''uld Resort. Your documentation seems to be in order. My name is Bryn and I''m so happy you chose us to satify your vacation needs.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5957, 97618, 'Somehow - you''re not quite sure how - you manage to get the countdown to stop. The Failsafe has been re-routed, at least for now...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5958, 97757, 'You are the friend to Ras''nor who has been making trouble for Dakor?', 1772, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5958, 97758, 'True.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5958, 97759, 'Then you will want to help, quickly. Jysic and Trik''na took many men into the Tretonin Facility... I fear not many have survived but they still hold out... as far as I know...', 1772, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5958, 97760, 'Do you know where they are inside the facility?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5958, 97761, 'I suggest you follow the bodies.', 1772, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5959, 98213, 'You discover something truly shocking... There, in the encoded note, are Bra''tac''s orders... And note for Baal. Is Moh''katan betraying her own father?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5960, 99096, 'This shipping container is empty.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5978, 99437, 'This barrel is empty.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5979, 117506, 'Nestled amongst a pile of dirty rags you find the subspace decryption device.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5980, 99445, 'Deliver withdrawal orders to Loth''ta at the Naquadah Repository.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5981, 99443, 'Plant coded messages for Moh''katan''s scouts.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5982, 102168, 'Defend the Western Gate from Ba''al''s attack.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5983, 99451, 'Find out why Loth''ta has not withdrawn his forces.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5984, 99464, 'Investigate Moh''katan', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5985, 99459, 'Confront Moh''katan with the evidence you gathered.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5986, 99461, 'Use the naquadah generators to destroy Ba''al''s Hataks.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5987, 99463, 'Report back to General Hammond.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5988, 99481, 'The SGC is closing: speak to General Hammond for reassignment.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5989, 104665, 'So, Unas... Stinky. Foul. Ugly. This is standard... But they''re not always quite so maliciously psychotic... We need to know why. Head into their living areas and see if you can find one that will talk to you. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5990, 104708, 'Find out why the Unas fight so valiantly in the Ihpet Crater.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5991, 104714, 'The Unas here... They don''t seem like their hearts are in the fight - but they never give up...', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5991, 104715, 'You think someone controls them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5991, 104716, 'It''s very possible. Check the settlement nearby and see if you can find one that is reasonable. Let''s find out what is driving them...', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5992, 104705, 'Ra implanted these stinky idiots with something? Brilliant... Boy, if we could free them? We would have a large cadre of stinky idiots who owe us bigtime... I dislike Unas but, I know this would make Harset giddy. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5993, 104717, 'Interesting... Clearly we''ve got to see what the heck is going on here. The concept is brilliant - damned if they do, damned if they don''t. But it may go deeper than that.', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5993, 104718, 'What do you mean.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5993, 104719, 'This is Ra we''re talking about. They may all be literally wired to blow if someone goes into the big temple... It would be a hell of a shortcut when it comes to stopping them, but - I don''t quite see Omega Site approving that approach.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5993, 104720, 'No.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5994, 111070, 'After a detailed analysis of the object you conclude this must be the Kalas Relic that Vey''Ka mentioned.', 3031, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5995, 104749, 'You are uncomfortably devious, <<playername>>. Remind me never to loan you Naquadah.', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5996, 104747, 'Excellent. If we can save these creatures we can comfortably enter Ra''s temple without the moral implications we were facing before. ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5997, 115690, 'Well? Effective?', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5997, 115691, 'Very. Although it takes forever for it to warm up... It works like a charm. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5997, 115692, 'I''ll inform Harset.', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99870, '$name$$, it has been a long time. You are on Men''fa but do not wear the adornments of Ra.', 2191, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99871, 'I serve the Praxis, and Moh''katan.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99872, 'A woman?', 2191, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99873, 'Indeed. A very capable one.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99874, 'Your honor is diminished if you serve a woman. Instead you should commit to Ra - a true God, not a Jaffa.', 2191, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99875, 'Ra is dead.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99876, 'He shall return. So says the prophecy. You are on sacred ground. Either you choose to follow the path of Ra, or you leave Men''fa. ', 2191, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99877, 'I can do neither.', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5998, 99878, 'Then I am afraid, old friend, that only one of us lives to see the sun rise tomorrow.', 2191, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5999, 117335, 'I am sorry you deem Rig''s life less valuable than I do.', 3409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5999, 117336, 'I cannot risk bringing a highly infected patient onto the ship.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5999, 117337, 'I understand. I will stay with him.', 3409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5999, 117338, 'You will die.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5999, 117339, 'Correct.', 3409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (5999, 117340, 'I wish you luck.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6000, 117314, 'Prepare for beaming.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6000, 117315, 'You have decided to save me. ', 3408, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6000, 117316, 'I hope that it is not too late.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6000, 117317, 'Thank you. It is inadequate, but all that I can offer.', 3408, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6018, 110432, 'Greetings. You are preparing to activate the self destruct mechanism?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6018, 110433, 'Yes. It will be active soon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6093, 101601, 'Very useful. I assume the humans have their own device? ', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6018, 110434, 'My team will beam off-world immediately. By utilizing the scanning device we have saved many more of our people from certain death. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6018, 110435, 'This pleases me. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6018, 110436, 'Hopefully we will see you again?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6018, 110437, 'Hopefully.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6019, 115344, 'UNUSED DIALOGUE', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6020, 115366, 'Buck Mulligan. I know him - I''m sure he''d sign the form. He''ll be horrified to discover the Tech Secure authorizations haven''t happened yet.', 663, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6020, 115367, 'Any idea where he may be?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6020, 115368, 'He lives in Friendship Block. When the Jaffa hit there, many of the residents made their way back to protect their homes. ', 663, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6020, 115369, 'Wasn''t that Tech Secure''s job?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6020, 115370, 'Powerful people, like Buck, know better than to rely on Tech Secure. Companies like SecuriTech provide security teams for private people.', 663, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6020, 115371, 'So Buck is probably alive?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6020, 115372, 'We can always hope. ', 663, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6021, 105967, 'You need to configure this terminal''s satellite to send out the blast transmission on the frequency Ra''s Hataks are using to jam signals.', 686, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6022, 100336, 'I have heard that Supreme Commander Thor is at the Omega Site... ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6022, 100337, 'The Omega Site?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6022, 100338, 'A very controversial alliance which Thor has pursued despite the disapproval of the council. It is a joint operation with Asgard, Humans and the newly formed Free Jaffa nation. ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6022, 100339, 'We have an alliance with Jaffa?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6022, 100340, 'Precisely the reaction of many of the Council members... Thor is there now, helping to organize the base. ', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6023, 100273, 'You are here... This is a pleasantly unexpected occurrance. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6024, 105993, 'With RepliTech dead, you start to look for additional data connecting Ra, Devlin and Burtonol.', 687, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6025, 105986, 'The system greets you as Miles Hagan and acknowledges your access to the Burtonol Compound.', 704, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6026, 100639, 'Please don''t kill me. I will come with you.', 2196, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6027, 100638, 'Spare my life and I will do as you say.', 2197, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6028, 100637, 'No more please! I will follow you.', 2198, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6029, 100524, 'Welcome to the Omega Site. Bra''tac and the Leadership Council are expecting you. I will upload his location to your personal computing device. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6029, 100525, 'What is this place?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6029, 100526, 'The humans call it a "secret". ', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6030, 100510, 'Report to Colonel Carter on Beta Site.', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6031, 100504, 'Bra''tac told you about the SGU? ', 708, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6031, 100505, 'Yes. The SGU is a secret for the Tau''ri.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6031, 100506, 'Yes. Woolsey wouldn''t approve. ', 708, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6031, 100507, 'Understood. I have been assigned to help you.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6031, 100508, 'Excellent. We could use the help.', 708, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6032, 106447, 'We haven''t fought the Goa''uld for generations... What are they doing here?', 792, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6033, 100573, 'Hammond gave you this to give to me? Boy, you must have really made an impression.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6034, 100536, 'This was given to you by Hammond of Texas?', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6034, 100537, 'Yes.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6034, 100538, 'This letter says much about how he feels about you.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6035, 106382, 'This note is incredibly overwritten for a simple thank you. Perhaps La''el is trying to send you some sort of hidden message.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6036, 100706, 'There is an old electronic lock on the safe. It looks hackable.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6037, 100861, 'Interesting. You have convinced me that you are a good choice for this mission. ', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6037, 100862, 'Your contribution on both Dakara and the Beta Site have shown you are capable.', 1333, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6037, 100863, 'Teal''c speaks true. You deserve the chance.', 2323, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6037, 100864, 'Congratulations. You just bought yourself a free trip to Men''fa. ', 1332, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6038, 100812, 'It is unlikely we will quickly find a cure for this toxin. It is simply too advanced. Perhaps the missing Jaffa, Trink''na, is after a more expedient solution.', 777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6058, 115412, 'TechSecure? Why scam them? I''m sure they''d gladly hire anyone who doesn''t mind getting shot at. I mean that''s a really tough design to match...', 2249, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6058, 115413, 'Just make it.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6058, 115414, 'Hey, don''t get tough with me... ', 2249, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6059, 115431, 'Say... Haven''t seen you around. Is that special issue gear?', 726, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6059, 115432, 'Just transferred...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6059, 115433, 'I need to get myself transferred.', 726, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6059, 115434, 'Yeah. What do you know about Burtonol?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6060, 115427, 'New here? Looks like we take all kinds now.', 727, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6060, 115428, 'I''m just making a living.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6060, 115429, 'I hear you... Anything I can do...', 727, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6060, 115430, 'Well, you can explain Burtonol to me...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6061, 100981, 'Ah, a familiar face! And just in time... I''m in a bit of a bind and could use some help...', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6061, 100982, 'You are always in distress.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6061, 100983, 'Such attitude - especially since I saved you from Ambernol sickness in the Castle. I see a return to Moh''katan hasn''t softened your mercenary soul.', 1101, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6061, 100984, 'You speak much, but say little. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6061, 100985, 'Ah, a Jaffa who likes thing simple. How... Original... Let''s cut to the chase: I found something here that the humans have been searching for. Clear out the Jaffa who are after me and it''s yours. ', 496, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6062, 101001, 'You''re very tall and very useful. Here is my end of the bargain. ', 1101, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6062, 101002, 'What are these?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6062, 101003, 'The humans will be pleased... Deliver them to Copplemann. You are their liasion, correct? ', 496, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6062, 101004, 'How do you know this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6062, 101005, 'There''s not much I don''t know. It''s a talent. ', 1101, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6063, 101016, 'You got this from a Goa''uld?', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6063, 101017, 'Lethander. He is of the New Mind.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6063, 101018, 'I didn''t know he was down here rooting around... Anyway, you hit the jackpot with this data disc... These are schematics for an Ion Cannon. The file is corrupted so it''s only a partial, but it''s a promising start...', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6063, 101019, 'He said you would find them valuable.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6063, 101020, 'He''s not supposed to know what we''re looking for... But he''s right... These are useful. ', 469, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6064, 101316, 'This is material related to the Ion Cannons?', 941, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6064, 101317, 'Yes. A partial file. Corrupted, but useful.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6065, 106876, 'You successfully tap into a series of log files Tomakin made shortly before his final mission...', 692, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6065, 106877, 'TechSecure has been paralyzed due to lack of authorization... I fear that this is not the typical bureacracy, but instead it centers around Tynan. He - or his aide, Cyric - are always at the heart of every delay. ', 682, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6065, 106878, 'This current mission to Togetherness Block has been authorized only because I threatened to use my family connections if Tynan didn''t comply. It''s insanity. Our people are dying and he''s delaying. ', 682, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6065, 106879, 'I''ve attempted to scan Tynan''s files, but it''s impossible. Cyric might be the only option there... He''s weak-minded and easily manipulated. I''ll try when I get back.', 682, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6065, 106880, 'The log ends... Tynan must be holding a big secret. It''s unlikely he''ll give up the clearance to his own files, but you resolve to try to get it out of Cyric.', 692, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6066, 106884, 'Please don''t tell Branni- Mr. Tynan that I questioned him...', 673, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6066, 106885, 'Of course not. You were just being properly careful.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6066, 106886, 'Alright, I''ve authorized you to access the files back at headquarters. Access the Mainframe and you can get in.', 673, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6066, 106887, 'Well done, Cyric.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6066, 106888, 'Thank you... ', 673, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6078, 106889, 'You search through the data manager in the mainframe for Tynan''s concealed files.', 692, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6079, 101146, 'Please rescue a group of SGC Personnel who were trapped when Ra''s forces came through.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6080, 101140, 'Some of my SGC colleagues locked themselves in the nearby holding cell when Ra''s forces first came through in order to protect themselves. However now they can''t get out and there are Jaffa between us and them preventing me from helping them. If you could help me get them free and to the Stargate so I can help evacuate them someplace safe, I''ll help you catch up with Ra''s forces on level 19.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6081, 101162, 'You hack the door controls to open the blast doors trapping the SGC Personnel in the Holding Cell.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6082, 101170, 'Walter sent you to get us out of here? Wow, I thought all he did was count how many chevrons were engaged.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6083, 101181, 'Thank you. I''ll get these people to safety. The nearby elevator is waiting to take you to level 19 - that''s where Ra''s forces were headed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6084, 101332, 'Welcome back. What was Marsh''s reaction to the Ion Cannon data?', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6084, 101333, 'He seemed pleased. He said your scientists would analyze the material.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6085, 118924, 'So far we haven''t had much success finding defense technology beyond the Ion Cannon data card. One of our guys, Sgt. Ogilvie, reported that there may be a concentration of Tollan survivors in a clutch of destroyed buildings. Recon the area and see if the rumors are true. ', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6085, 118925, 'If there are survivors?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6085, 118926, 'See if they have tech they will part with... Be careful, a lot of the Tollan see Jaffa as slave traders. It may take some work to convince them otherwise.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101370, 'I do not know you, Jaffa. Do you work for Svarog?', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101371, 'I seek technology. I have heard there may be some in this area. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101372, 'Predictable. To my great regret, Tollana has become a galactic junkyard... Are you one of the Free Jaffa? ', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101373, 'Never. I embrace my traditions. I am a warrior.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101374, 'Then this is serendipity. I have received word that a Lucian swindler named Mareck is on his way here with dark intentions... I cannot defend myself against him.', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101375, 'Why does he come?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101376, 'There''s a dispute. He was to use me to feed his technology business... I won''t be his slave.', 1102, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101377, 'In return for my services?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101378, 'Technology.', 1102, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6086, 101379, 'Where is this Mareck?', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6087, 101390, 'Your success allows me to breathe easier. As promised, here is my end of the bargain. That is a fully functional Control Device - capable of separating a Goa''uld symbiote from its host. I figured this might be very useful for a Jaffa.', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6087, 101391, 'It is useful. How does it work?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6087, 101392, 'That information will remain with me... For now...', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6087, 101393, 'More bargains?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6087, 101394, 'I''m alone on a very hostile world, <<Playername>>. I need all the help I can get.', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6088, 101414, 'My daughter was taken by Svarog''s Jaffa to an internment camp. I fear she and he family will be sold into slavery. ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6088, 101415, 'You wish for me to rescue them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6088, 101416, 'Yes. If you do that, I''ll give you the key to the control technology...', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6088, 101417, 'I am growing weary of this. I do not risk my life lightly.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6088, 101418, 'These are innocent people. My daughter''s name is Sagrine. Orlak is her husband. Mylon is my grandson... ', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6088, 101419, 'I will be back soon.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6089, 101446, 'You have held up your end of the bargain... My daughter has been through an ordeal, but she is alive and I am grateful. I owe you much. ', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6089, 101447, 'Technology. You owe me that.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6089, 101448, 'Tollan technology is very dangerous in the hands of outsiders. There is much that a race at your primitive evolutionary stage cannot yet comprehend... ', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6089, 101449, 'I suggest you consider your next words very carefully.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6090, 101462, 'You just place it over the infected human and then activate the device in this manner. It will seperate the symbiote and host.', 1102, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6090, 101463, 'I need an additional unit.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6090, 101464, 'I already gave you one.', 1102, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6090, 101465, 'I require two.You will provide them...', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6090, 101466, 'Or what?', 1102, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6090, 101467, 'I will ruin your reuinion with you daughter. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6090, 101468, 'Take it... Just take it...', 1102, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6091, 101475, 'You certainly have a knack for securing the hearts and minds of these Tollans. Keep it up.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6091, 101476, 'Thank you, Ma''am. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6091, 101477, 'This Control Technology may turn out to be very useful, <<Playername>>. Nice work.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6092, 101527, 'I will get you the package... And I''ll even throw in some extras... ', 470, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6092, 101528, 'This is apprecaited...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6092, 101529, 'So is your decision not to pummel me. ', 470, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6093, 101599, 'Excellent work... You will keep vigilant looking for this Beleth... Whatever he is up to, it will have the stench of Baal upon it. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6093, 101600, 'I recovered some Tollan Control Technology from one of the Tollan humans.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6093, 101603, 'Nor should we. However, the Op-CORE humans may be a different story. ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6094, 101614, 'There''s a Black Market nearby that''s selling scavenged technology - including weapons. Check it for Ion Cannon data.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6095, 118933, 'The humans hunt for Ion Cannons. Colonel Marsh is frantic about a future menace... Most of us listen and nod... But his desperation is an opportunity.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6095, 118934, 'We give them cannons...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6095, 118935, 'And they owe us loyalty - something they value and respect. I have heard of a black market on the world - run by Machra.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6095, 118936, 'I''ve been there.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6095, 118937, 'Visit it. See if we can''t help the humans and, by extention, help ourselves...', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6095, 118938, 'What of Beleth?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6095, 118939, 'For now, help the humans. If an opportunity comes about, or Athena has more information, re-focus on that...', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6096, 101651, 'Ah, you. What can I do for you?', 492, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6096, 101652, 'I seek Ion Cannons.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6096, 101653, 'Wow. That''s a bit of a tall order. The Tollan Ion Cannons were destroyed in Anubis'' attack. However it is possible to manually assemble them. ', 492, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6096, 101654, 'And you can do this?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6096, 101655, 'Sure. It''s pretty easy really. But, you should know that Ion Cannons require specially designed Ion Cores. Very expensive pieces of hardware, Ion Cores.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6096, 101656, 'If I buy them from you, you''ll build the Cannon...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6096, 101657, 'I don''t have Ion Cores... However, you may be able to find one at one of the old Ion Cannon sites nearby. And if you did happen to find one... And bring it back to me... We''d have something to talk about.', 492, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6097, 101695, 'Go for Copplemann.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6097, 101696, 'I have an Ion Cannon under construction. I am downloading details. Payment must be arranged.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6097, 101697, 'You found an Ion Cannon? Unbelieveable... ', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6097, 101698, 'Moh''katan and the Loyalist Jaffa wish to serve all of the needs of the Praxis. Not just our own.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6097, 101699, 'We''re in your debt. I''ll tell Colonel Marsh and I''m sending one of my people down to negotiate payment. ', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6097, 101700, 'I do not fully trust the contact. ', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6097, 101701, 'I''ll let my guy know to keep his eyes peeled... Amazing stuff, <<playername>>. Earth owes you. Copplemann out.', 1100, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6099, 101752, 'You open the file cabinet and thumb through stacks of technical documents before finding the staff weapon information.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6100, 101771, 'Bullet casings and blast marks tell you that a confrontation took place here. You also find a piece of torn fabric with the symbol of Lord Yu embroidered on it. Tracks leading off from the area indicate that someone was dragged away from the skirmish. It would appear that Yao has been captured by someone...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6101, 101769, 'The tracks lead into a different direction here...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6104, 102178, 'It''s not a very sophisticated system, but the decay due to a lack of maintenence makes hacking it tougher than it should be... ', 2418, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6105, 104447, 'You apply the crystal to the drone control console... It shouldn''t take too long to get into the system...', 1835, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6106, 102171, 'Moh''katan sends one of the Tau''ri to command us?', 2959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6106, 102172, 'For the moment, yes. Ba''al''s forces may attack at any moment.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6107, 102175, 'What news of the war?', 2959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6107, 102176, 'We hold our ground. Moh''katan believes that Ba''al''s forces will attack here soon.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6108, 102180, 'The naquadah bomb will explode in a few seconds. Hopefully it will destroy the Hata.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6109, 102182, 'The naquadah bomb will explode and destroy the Hatak in a few seconds.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6110, 102197, 'Welcome back to Dakara. Did the Tau''ri listen to Master Bra''tac''s warning?', 2956, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6110, 102198, 'Unfortunately it came too late. Ba''al''s forces invaded as I was delivering my warning.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6110, 102199, 'Ha''shak! Master Bra''tac must hear of this as soon as possible. He has moved his command tent just to the east of the Stargate, next to the healing tent.', 2956, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6111, 102200, 'Welcome to Dakara, human. Do you bring word from Teal''c?', 2956, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6111, 102201, 'I must speak with Master Bra''tac. Where can I find him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6111, 102202, 'He has moved his command tent just east of the Stargate, next to the healing tent. What is so urgent?', 2956, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6111, 102203, 'Ba''al''s forces attacked the SGC. I''m here to figure out how they gained access.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6112, 104840, 'Please, open it. I am too weak.', 1778, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6112, 104841, 'You promised me answers.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6112, 104842, 'You seek the Mouth of Ptah. That is what you need.', 1778, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6112, 104843, 'The Mouth of Ptah?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6112, 104844, 'A technology. Find Safkhet... She was Ra''s scribe... Devoted to him. She knows about the Mouth of Ptah. That technology was different and strange, but Ra ceased his research here long before he died. He left her in charge of it.', 1778, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6112, 104845, 'Where is she?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6112, 104846, 'She is often in her lab... Please... I do not wish to die... I grow weak.', 1778, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6113, 102465, 'Reynolds is dead, his body ravaged by plasma burns and gunfire. It appears as though he was not slain by the androids, but by the energy beings in this sector. This is not good.', 512, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6114, 102869, 'The junction contains the Inverse Straegis Crystal you worked so hard to make... you take it.', 2720, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6115, 102930, 'One of the Recon teams came across a tablet that they can''t translate. ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6115, 102931, 'Did they get images?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6115, 102932, 'No, they were pushed off by Jaffa. The thing is, the tablet is in an area teeming with other tablets they could read... Medical tablets.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6115, 102933, 'You think this may be related to the nanotoxin?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6115, 102934, 'It''s possible... If we''re lucky it''s the freaking recipe and we can all go home. ', 1959, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6116, 102967, 'The tablet talks about the "Four Pillars of Light" that''s... Totally boring me. Fell free to tell somebody who will understand the significance of this find, but it''s over my head... No offense. ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6116, 102968, 'None taken.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6116, 102969, 'You understand, right? Book stuff - just goes right past me. Football, now we''re talking.', 1959, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6117, 103003, 'You have succesfully planted the surveillance device.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6118, 102988, 'You withdraw the "Pocket Singularity Power Source" from the storage pod, but suddenly you hear a familar sound... the Straegis... they''re here.', 519, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6119, 103006, 'You hide Crogan''s body in the empty crate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116517, 'But possible. I will go...', 0, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6120, 103031, 'Thanks. I''ll get this sent through the gate to Omega Site ASAP. ', 1959, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6121, 103135, 'You have freed me... I will make my own way out.', 1777, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6121, 103136, 'You are coming with me.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6121, 103137, 'But...', 1777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6121, 103138, 'I insist. ', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6122, 119920, 'You grab a wriggling symbiote from Anat''s tank.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6123, 103304, 'I can tell Laro has diverted energy to repair her androids at the Repair Node... the plan was a success.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6124, 103305, 'My information on their movement is limited, but it does appear that Ra is reinforcing where you hit... and taking forces from the Tower.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6125, 103420, 'You need to disable this synaptic link so that Laro cannot escape.', 527, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6126, 103421, 'You need to disable this synaptic link so that Laro cannot escape.', 528, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6127, 110050, 'You manage to adjust Saun''ti''s corpse... She looks like she died in battle. Only you will ever know the truth...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6128, 103961, 'You collect several samples of the crystal artifact.', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6129, 103942, 'You locate a source of Ra''s technology in Safkhet''s Lab.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6130, 103739, 'This crate contains an obscure artifact obtained on an alien world, but nothing about it seems noteworthy enough to warrent a Ra invasion of the SGC.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6131, 103765, 'The Computer gives you an idea of what Ra''s forces may be after - a crate containing a large hunk of crystal found on an alien world. The catalog makes it sound like the crystal is similar to those that the Straegis are made up of.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6132, 103726, 'This crate looks to contain what Ra''s forces are after - its appears to be the crystal carapace of an alien race.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6133, 103944, 'As you close the Sarcophagus you decide to seal it... Just in case you need Saarthon again.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6134, 103941, 'You succesfully scan the Hall of Secrets.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6135, 103958, 'You do not have the container.', 417, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6135, 103959, 'The Burtonol agents took it. I need to know where they went.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6136, 104264, 'If you can decipher this cartouche, you may be able to unlock something valuable. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6137, 104263, 'If you can decipher this cartouche, you may be able to unlock something valuable. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6138, 104332, 'One of my Recon teams came across a tablet that they can''t translate. ', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6138, 104333, 'Did they get images?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6138, 104334, 'No, they were pushed off by Jaffa. The thing is, the tablet is in an area teeming with other tablets they could read... So this one may be special...', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6138, 104335, 'Could be the Mouth of Ptah?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6138, 104336, 'It''s possible... Regardless, we can''t leave any stones unturned.', 1885, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6139, 104351, 'This tablet is beyond me... Four pillars?', 1885, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6139, 104352, 'It''s a major discovery... It describes Ra''s travels through death into light and...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6139, 104353, 'And yadda, yadda... I''ll forward it to Harset and the egghead division. I''m sure they''ll lose their sauce over it... In the meantime, let''s get back on track...', 1885, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6140, 104347, 'The tablet doesn''t mention the Mouth of Ptah, but it does tell a fascinating tale of Ra''s resurrection from the Underworld. What strikes you is the specificity - you''ve never seen such detail in the story before. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6141, 104368, 'The generators are hooked up, now all that remains is to start them up at the plant''s power link.', 514, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6142, 104485, 'This device is too large to take with you, but you may be able to remove a few components to help identify it later.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6148, 110927, 'Using Nerus decryption code, you are able to touch runes in the proper order... From there you insert the key... The wall glows and begins to shift... ', 1127, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6149, 104490, 'You succesfully remove several important looking pieces of the device.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6150, 104493, 'The sensor beeps twice, telling you that it is correctly set up.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6151, 104527, 'Hopefully you can remember the instructions Lt. Colonel Carter gave you for setting up these sensors...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6152, 104528, 'Hopefully you can remember the instructions Lt. Colonel Carter gave you for setting up these sensors...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6153, 104552, 'Hopefully you can remember the instructions Lt. Colonel Carter gave you for setting up these sensors...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6154, 104530, 'Hopefully you can remember the instructions Lt. Colonel Carter gave you for setting up these sensors...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6155, 110933, 'You begin deciphering the code... You slowly realize that whatever Ra is guarding, it must be something special - this is quite an elaborate ritual.', 2950, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6156, 104594, 'Unlike the previous parts of the ritual - the key spits back two pieces. The Anamorphic Crystals are still intact, but there is another object... It seems to pulse and glow, like it may be alive in some way... But it does not feel complete... Perhaps the Western Temple will explain this...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6157, 104598, 'The Anamorphic Crystals are gone, but the temple spits out another crystal entity - symmetrical to the first... Two halves to a whole. This piece too seems to pulse and glow, like it may be alive in some way... But it does not feel complete either.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6159, 115732, 'This stone is the lock to the temple... You can feel the key prodding you to use it on the stone - the whole experience is a little disconcerting: This key talks to you in images and feelings. It feels almost supernatural... ', 1134, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6160, 104617, 'The stone is no longer in the way... The solution to the mystery of Ra''s Ihpet Temple lays at your feet. The Crystal Entity is gone...', 1134, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6161, 104710, 'The pickings are slim, but you manage to quickly gather some near expired rations from the crate.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6162, 104766, 'You fix us?', 1655, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6162, 104767, 'This device will set you free... Bring your people around...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6162, 104768, 'Come near! <<Playername>> must be heard.', 1655, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6162, 104769, 'I am your God now. You will do as I say, or you will perish.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6162, 104770, 'Heresy! Ra is God. ', 1655, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6162, 104771, 'Not anymore.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6168, 105429, 'Welcome to Omega Site. I have indicated a path for you to follow. Please do not stray from it.', 3218, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6168, 105430, 'What is this place?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6168, 105431, 'All will be explained in due time.', 3218, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6169, 117158, 'Keep moving... Lots of wounded coming through here, we need room.', 3219, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6169, 117159, 'What is this place?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6169, 117160, 'You''re on Harset now - once the site of one of Ra''s archeological digs, it is now your hot, sweaty, sand-blasted home. Feel free to explore. ', 3219, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6169, 117161, 'Where do I report?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116518, 'I can assist you.', 2095, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6169, 117162, 'Ah, right. Make sure you report in at the command center for debriefing. I''ll upload a path to your PDA. ', 3219, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6170, 105510, 'The diagnostic is a little tricky to get set up...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6171, 105563, 'The Self Destruct has been activated. You need to turn it off or deal with the threat that has caused the Pentagon to remotely activate it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6172, 105747, 'The Pentagon fears that this base has been compromised and to prevent a foothold situation they''ve remotely armed the self destruct. You have to disarm the Self Destruct on site or remove the threat of Ra''s invasion.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6173, 105684, 'The timer for the self destruct ticks away menacingly...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6174, 105683, 'You manage to stop the self destruct timer as well as sever the connection to the Pentagon so they can''t reactivate it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6175, 105692, 'Now that you''ve disabled the Self Destruct you need to stop Ra''s forces before they start a full scale invasion of Earth.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6176, 105726, 'Thank you for preventing the destruction of the SGC. I''ve managed to get the Iris working again so I can lock the base down after you leave to make sure Ra doesn''t send any more of his forces here.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6177, 115357, 'The drone controls seem simple enough... You quickly begin hacking the system.', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6178, 105994, 'Loki''s computer is heavily encrypted. It will take some effort to get any usable information out of his files...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6179, 110352, 'You wish to join us? You are most welcome. We need every able bodied warrior we can get... But know this... There is no retreat.', 3223, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6179, 110353, 'Only death?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6179, 110354, '(She laughs, a little maniacially)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6180, 106185, 'You withdraw the "Pocket Singularity Power Source" from the storage pod, but suddenly you hear a familar sound... the Straegis... they''re here.', 519, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6181, 106238, 'As you near the base of the Tower, a small port senses the presence of Goldam''s probe and automatically opens up, ready to receive.', 522, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6182, 106572, 'The scanner reveals a source of Ra''s technology nearby.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6183, 106573, 'The scanner reveals a source of Ra''s technology nearby.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6184, 106574, 'The scanner fails to locate any additional sources of Ra''s technology.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6185, 106627, 'Like before, critical functions go through this junction. You begin to tear it apart.', 525, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6186, 106634, 'Laro is rebuilding... but at the cost of resources from the Tower defenses.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6187, 106641, 'Crude, but effective. Ra has moved his reserves from the Tower to replace the ones you killed.', 406, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6188, 106696, 'You need to disable this synaptic link so that Laro cannot escape.', 527, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6189, 106697, 'You need to disable this synaptic link so that Laro cannot escape.', 528, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6190, 106723, 'You quickly remove a tissue sample from the corpse.', 2409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6191, 115423, 'You are large. ', 727, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6191, 115424, 'I am here as an advisor.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6191, 115425, 'Really? A giant advisor... Advise me.', 727, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6191, 115426, 'Instead I seek information... Tell me of Burtonol.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6192, 115419, 'What the hell are you doing here Jaffa... We''re letting your kind in here now?', 726, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6192, 115420, 'I am here to help.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6192, 115421, 'Your people are out there killing our citizens. ', 726, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6192, 115422, 'I am not loyal to Ra. I require information about Burtonol.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6193, 115480, 'The drone controls seem simple enough... You quickly begin hacking the system.', 685, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6194, 106987, 'Find out where Beleth is and get his research materials.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6195, 107673, 'I have something else for you... There''s a Goa''uld on this world called Beleth...', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6195, 107674, 'I have not heard of him...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6195, 107675, 'Well, he is after something - something inside the Tollan computer network. Using network activity, we''ve isolated an area where we believe he is operating. We want to know what he is after.', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6195, 107676, 'You wish for me to go there?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6195, 107677, 'We need to know what he is trolling around for in their systems... It could be something very big.', 1100, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107824, 'You''ve found Beleth?', 3228, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107825, 'I believe so.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107826, 'How?', 3228, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107827, 'My methods are my own.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107828, 'That''s a very Jaffa answer but, no matter... I''ve gotten word from reliable sources - Beleth is after the Crystal Key - THE Crystal Key. Ra used these keys to keep enemies out of his most trusted areas... ', 3228, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107829, 'Is Ra not dead?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107830, 'Dead and gone. But his technology remains behind... It''s mostly untouched because no one can get inside his facilities... But a Crystal Key means we can unlock his secrets...', 3228, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107831, 'You believe Beleth has found one of these keys?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6196, 107832, 'If not he knows where one is. ', 3228, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6197, 107807, 'Good work. I''m weary of Baal and Marsh, they haven''t mentioned anything of their activities searching for Beleth. Perhaps we should be so hasty to give away our treasures.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6198, 107072, 'Track Beleth''s Research Materials through the command chain to make sure that proper protocols are observed.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6199, 107781, 'This secrecy is an epidemic. If our alliance is to survive, there must be honor and trust.', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6199, 107782, 'We work with Goa''uld and humans... You seek a miracle.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6199, 107783, 'I am the one who can raise an army. Both factions repsect power and I will use it to maintain order... Still, without direct proof they will all deny their dealings. We will use you to provide us the proof of their deceit.', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6199, 107784, 'Me?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6199, 107785, 'Yes. Make your way to the black market. Acquire Tollan tracking technology and apply it to both the data crystal and the crystal key. Then deliver that material to your contacts... ', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6199, 107786, 'I see... Because they will have the techology they seek...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6199, 107787, 'And we can then monitor how forthcoming they will be with us... Go. They are expecting you. ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6200, 107077, 'You quickly modify the specifications document so that the design would never work. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6201, 107081, 'This dialog is not seen by players. It is used to have an uncompletable task on invasion step of mission. (Mission timer will complete the step).', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6202, 107788, 'Tollan tracking technology... Tricky technology for a Jaffa... You need it to apply to potential slaves? I see many Jaffa who come to Tollana to be slavers...', 492, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6202, 107789, 'Yes. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6202, 107792, 'You need to calibrate the tracking tech so that it is cloaked... It''s a fairly complex process for a Jaffa to wrap their mind around... ', 492, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6202, 107793, 'I will calibrate it. Just hand it over.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6202, 107794, 'Oh? Fair enough. ', 492, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6203, 107799, 'You found it? Baal will be very pleased... And Lethander will be crushed...', 3228, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6203, 107800, 'You will deliver it to him?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6203, 107801, 'Immediately.', 3228, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6204, 107835, 'Great work. I''ll make sure to put your name in for a commendation.', 1100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6204, 107836, 'You will deliver this to your Colonel Marsh?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6204, 107837, 'Absolutely. He''ll want to see the right away. ', 1100, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6205, 107838, 'There has been no news to me since your delivery to Copplemann and Athena... ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6205, 107839, 'They deceive us then?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6205, 107840, 'It appears to be so. Use the Tollan Tracking Device to find them... Identify that they are here, in Harset, and then return to me with the tracker. Jaffa Kree!', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108109, 'Colonel Marsh, Lord Baal, Queen Anat... I hope that we are all forthcoming with each other. For a Jaffa, deceit is dishonor. If you lie to me, you dishonor me. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108110, 'Who are you accusing of lying, Jaffa?', 944, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108111, 'You tell me, Queen Anat. Is there something you or Lord Baal wish to share with the rest of us?', 945, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108112, 'Accusing them of deceit is silly, isn''t it? They''re Goa''uld, it goes with the territory...', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108113, 'But you share everything, Colonel?', 945, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108114, 'Of course. Anything important is brought to this chamber.', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108115, 'So your discovery that The Book of Gates - the map to Ra''s long lost hideaway at Ihpet - may be on Tollana? That wasn''t important?', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108116, 'You found The Book of Gates? ', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108117, 'We have a lead. How did you know about that?', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108118, 'I am thorough. Your deceit is not isolated, Colonel. The New Mind Goa''uld have found a Crystal Key - a key that will unlock that same Ihpet. They also believed this discovery was unimportant.', 945, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108119, 'I know nothing of what you say.', 944, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108120, 'Lord Baal? ', 945, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108121, 'I am impressed Moh''katan. I underestimated you. I will not do it again. My agents did find a Crystal Key - not yet active, but we have the apperatus. ', 942, 12);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108122, 'And you did not inform me of this?', 944, 13);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108123, 'Apparently not.', 942, 14);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108124, 'These petty deceptions nearly cost the Praxis a golden opportunity. The Loyalist Jaffa will not stand for it again. If a similar deception is discovered in the future, the Praxis will dissolve, and blood will flow. I pledge my loyalty to this alliance, but only with that understanding...', 945, 15);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108125, 'We all should pledge the same... No more deception. On my honor, I am first to agree.', 941, 16);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108126, 'As do I.', 942, 17);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108127, 'I don''t know why I must declare loyalty when I wasn''t even involved in dec--', 944, 18);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108128, 'Declare your loyalty, Queen Anat, or leave the city. ', 945, 19);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108129, 'Obviously I will be loyal... But you watch your tone with me, Jaffa. Your insolence will not be forgotten.', 944, 20);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6206, 108130, 'Nor will yours.', 945, 21);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6207, 118812, 'This primitive human safe should be easy enough to open...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6208, 107218, 'The safe springs open and you quickly locate the files Arlos was looking for amongst a variety of other technical documents.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6209, 107434, 'This is not your first time destroying one of this. You begin.', 635, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6210, 107530, 'The Neutralizer canister spins to life. It will dispense the chemical agent slowly over the next few hours.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6215, 107833, 'Beleth was working on this console... However, to get to his work you will have to hack in...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6216, 107834, 'He was looking for something... Something the Tollans seem to have stolen from Anubis - The Book of the Gates. You download all of his research to a data crystal. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6217, 107744, 'Indeed, Beleth seems to have the Key Athena described... However, it seems lifeless - like a dead stone and not a complete piece of technology. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6218, 108174, 'The scan of the energy creature has succesfully uploaded.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6219, 107988, 'These files should explain what is happening to Rick Whelan. Better get these to Goldam.', 2425, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6220, 108007, 'The scan of the possessed human has succesfully uploaded.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6221, 108257, 'Following Laro''s instructions, you begin to remove a plasma drain attachement from this machinery. This will allow you to tap the energy beings to recharge the drained life support system.', 584, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6222, 108692, 'You carefully remove the Nox Cloaking Technology.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6223, 108963, 'You must inform Teal''c that the Ruk''yal not only took the Council, but the military headquarters as well. Ra is listening to A''lem''s every command!', 775, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6223, 108964, 'No wonder the defense has been failing...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6223, 108965, 'Inform Teal''c - push him to respond to the Ruk''yal''s invasion of the military headquarters... A''lem''s effectiveness will be reduced as long as Ra loyalists hold that location. ', 775, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6223, 108966, 'You are sure you were unaffected by the Jaffa device?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6223, 108967, 'There is no time to know... Go.', 775, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6224, 109698, 'You search Major Louis''s body and retrieve his dog tags.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6225, 109696, 'You search Lieutenant Nguyn''s body and retrieve his dog tags.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6226, 109702, 'You search Lieutenant Waters'' body and retrieve his dog tags.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6227, 110345, 'You toss the A''lem Insignia onto Hubrok''s dead body. Not the most convincing staging, but Gerak won''t need much to go on.', 2302, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6228, 109997, 'As you reach for the Rimal you notice two thugs step into view. One of them... is Netan.', 1356, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6229, 110024, 'Vala''s plan seem to be holding so far - with the security disabled, you should be able to take the Rimal without any of the Green Boots suspecting.', 388, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6230, 111237, 'You have managed to disable the masking technology that was hiding the transporter energy signature. Still, the transporter will remain active until you manually disable it. ', 2306, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6231, 111202, 'You have successfully disabled the ring transporter. Ra''s secret entry way into the SuperWeapon has been terminated.', 2427, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6232, 111194, 'This is the Ring Transporter you need to disable... The task isn''t too daunting...', 2427, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6233, 110116, 'MGS Stub: player hacks the portal, damaging it beyond repair.', 2305, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116519, 'There is no need. I will return with it.', 0, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6234, 110943, 'You manage to transcribe the settings on the SuperWeapon quickly... It has been in configured in a way you have never seen before, manipulated by and expert hand.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6235, 110944, 'You gather the settings and note the energy signatures the weapon is slated to produce. It''s calling for signatures you have never seen before.', 2310, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6236, 110491, 'What is the password?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6236, 110492, 'Cheesburgers.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6236, 110493, 'Oshu will be right with you.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6237, 110564, 'I do not know you...', 2316, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6237, 110565, 'Listen to this...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6237, 110566, '(You play the recording of Ra and hand Teal''c the head of A''lem.)
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6237, 110567, 'She learned of A''lem''s corruption.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6237, 110568, 'She seeks redemption amongst the Jaffa for her past betrayal?', 2316, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6237, 110569, 'No. She sought justice. It has been served.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6237, 110570, 'Indeed.', 2316, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6238, 111064, 'You successfully crack the electronic lock for the Red Collar item.', 1524, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6239, 111066, 'You successfully crack the electronic lock for the Red Collar item.', 1525, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6240, 111150, 'The Chlorafate quickly flows into the ductwork. New alarms sound the presence of chemical agents... the main building is to be evacuated. Time to grab Rychen.', 415, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6241, 111164, 'These heavier explosives will destroy the conduits nicely, and probably take out most of the facility with it.', 440, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6242, 114808, 'The explosive has been rendered inactive... Now you can check the three sub-sections for any signs of the Solocris. ', 2065, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6243, 114811, 'After a careful search, you are confident the Solocris is not in this area.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6244, 118493, 'This looks like a detailed schematic map for building the Ancient androids. ', 2064, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6245, 118494, 'This is a Furling artifact of some kind... You notice the Crystal technology... It is called a Transdimensional Shift Stabilization Core. Harset will be pleased. ', 2100, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6246, 118495, 'This is a classic Nox artifact - a cloaking device in the shape of a biological... Perhaps it can be reverse engineered by Nerus.', 3368, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6247, 118172, 'You decide that you will rig the weapons to detonate once they are used... The Jaffa won''t be able to trust their weapons and it will cause greater problems for them in the long run... You begin the process.', 2108, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6248, 116948, 'The upload went smoothly enough... However... This data indicates that the device wasn''t holding data at all - at least not in the traditional sense. You note the readings on the device and decide to check with Ha''kur for confirmation...', 2163, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6249, 116965, 'Given what you know of the Straegis Crystal Skeletons, this appears to be a Furling version - perfectly intact... The science team may be able to get some data about the Straegis Skeletons from studying such a pristine specimen. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6250, 116966, 'It is difficult to determine exactly what this device does, but you detect a gentle humming from within - almost like a music. It is possible this device allows for communciation with the Furling. Perhaps it can be used to reach the Straegis.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6251, 116968, 'This device is strange; it appears solid but is actually almost like a gas... It is difficult to pick up and store... When you touch it, you feel a shift in your very being - a connection to something else which you cannot define. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6252, 117924, 'Do not think because you defeated my drones that you can threaten me, intruder.', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6252, 117925, 'I am working with Ullr...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6252, 117926, 'I will require proof of this.', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6253, 112407, 'These heavier explosives will destroy the conduits nicely, and probably take out most of the facility with it.', 440, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6254, 112418, 'The journey ahead will be dangerous. Take this attack program for your drone - it will increase its effectiveness in combat.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6255, 112552, 'You wish for me to believe that A''lem works for Ra? Do not speak with a loose tongue.', 2356, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6255, 112553, 'I know it to be true.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6255, 112554, 'Then speak.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118242, 'Wow... I wasn''t expecting this... You''re a Goa''uld.', 1008, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118243, 'Observant.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118244, 'Colonel Marsh sent you?', 1008, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118245, 'Correct. More will follow - humans and Jaffa. What is the situation?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118246, 'We''re in an overrun scenario. You''re looking at the only territory not crawling with hostiles. It was all I could do to get a message out.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118247, 'There is additional information you should have, $name$...', 1018, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118248, 'Mimir here was in charge of the Asgard contingent on this world. He informs me the SGU has also rallied in defense of the Beta Site. They''re sending people.', 1008, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118249, 'They do not concern us.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118250, 'I was hoping that we could work together...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118251, 'The SGU is willing to operate under truce conditions to stop the invasion...
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118252, 'Make they abide by their agreement. ', 0, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6256, 118253, 'You''ve got your own little monitor watching for that right there - Mattila the Jaffa... She''s here to keep me in line. See Dr. Jackson. He needs to know you are here.', 1008, 11);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118261, 'A Goa''uld... How... Unexpected. And yet expected. You guys aren''t exactly known for your humanitarian side... What are you doing here?', 431, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118262, 'We fight Ra. He hunts us. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118263, 'I''d heard that - New Mind, right? ', 431, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118264, 'Correct.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118265, 'Heimdall and I came to find a way to slow down the Straegis. Is that part of your deal?
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118266, 'Yes.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118267, 'Perhaps you will deign to provide assistance with our research? Without a way to deter them, the Straegis will surely overwhelm this world. Your assistance may prove vital.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118268, 'I am here to assist. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6257, 118269, 'Excellent. When we''re ready, your help will be appreciated...', 431, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6258, 113927, 'You check the day''s manifest for the location of a shipment marked "Medical Supplies" bound for Opheltes and note where it is being stored.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6259, 113958, 'Escort Heimdall to his lab.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6260, 115028, 'Are you prepared for the trip to my lab?', 3300, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6260, 115029, 'I am curious - why do we not teleport directly to your lab?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6260, 115030, 'Most point-to-point teleportation systems were disabled days ago. A few remain active, but I was required to allocate them towards our security checkpoints. Containing the mutations was of paramount importance. We must take the direct - and dangerous - path.', 3300, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6261, 115626, 'You successfully re-set the Asgard anti-cloaking protections... However, the machine is in disrepair and you are unsure how long this effect will last...', 2061, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6262, 114347, 'You pull out Jax''s notes to determine where the thieves are probably hiding out.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6263, 118313, 'This terminal looks like where the archeological data should be stored. It has been damaged during the recent combat, however you may still be able to extract the data.', 2489, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6264, 114673, 'You activate the scanner Moh''katan gave you... As predicted, Ha''kur''s location is pinpointed. You upload the coordinates to your personal PDA. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6265, 114463, 'There were no records of the Solocris in the Yotunheim database. You decide to download the archives anyway to take to Ha''Kur.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6266, 115532, 'Rescue supplies stolen from the residents of Pen-Lai by Ra''s Forces.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6267, 115537, 'The Jaffa have taken everything from us. Could you please help us get our things back?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6268, 114728, 'Thank you for returning our supplies, but what''s going to happen if the Jaffa come back?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6269, 114615, '(You place some scraps of Jaffazon armor around Rowen''s body. Now it looks like they killed him.)', 455, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6270, 114719, '(Dawson''s guard is down... The moment is at hand to use the Symbiote on him. )', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6271, 116887, 'You''ve never seen a technology quite like this before... It is incredibly advanced. You may be working to simply try and get whatever you can from it - because you''re never going to figure this thing out completely. ', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6272, 116897, 'This console seems to be a primary control for the massive device in the room. You resolve to hack your way into the system and figure out what that thing is...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6273, 115410, 'This crate is full of goods the Jaffa stole from the residents of Pen-Lai.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116423, 'This is most disturbing... The Goa''uld scientists he employs are using shield technology... Your weapons are unlikely to penetrate it.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116424, 'How do I stop them?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116425, 'An idea comes to mind which is most dangerous... However, I am certain it will work.', 2069, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116426, 'I am listening.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116427, 'You should be able to increase the intensity of the singularity. The Goa''uld energy shield produces a very high powered energy signature. If you were to adjust the intensity, it should naturally be attracted to the Goa''uld energy shields. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116428, 'It would suck them in?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116429, 'Potentially. Or it may disrupt their matter, breaking it into ever-smaller pieces until they cease existence. It should destroy them, one way or another. But be careful, this is a highly dangerous task. ', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116430, 'How do I do this?', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6274, 116431, 'Find the Singularity Control Panel. You can enable this from there.', 2069, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6275, 116918, 'The console looks pretty badly damaged... Still, with a little luck, you should be able to make Ullr''s plan work...', 2086, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6276, 115568, 'It''s incredible - contained in a small, secure device is literally a black hole... You can carry it around in your pocket. What happens when you open it is anyone''s guess. You decide to take it to Ha''kur.', 2083, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6277, 117020, '(You have managed to pull the pulsing shard from his neck without killing him...)', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6277, 117021, 'Ra has discovered us... I overheard a transmission not meant for me. He has sent an Ashrak to terminate me and then you...', 2059, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6277, 117022, 'We can handle an Ashrak.', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6277, 117023, 'Not with the cloaking technology she employs. You must disable her technology. The Asgard security consoles have this function - Ra had us disable them when we arrived...', 2059, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6277, 117024, 'What are you going to be doing?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6277, 117025, 'I must find a way to hide... Meet me here once you have deactivated her protections. ', 2059, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6278, 115725, 'They are destroying the base? This is a smart decision, albiet one that was probably inevitable.', 2059, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6278, 115726, 'I got them to extend the time...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6278, 115727, 'We can use that time to our advantage... There are several Asgard technological assets that could be useful to deliver to Harset. I will upload their location to your PDA. Collect these and meet me here. ', 2059, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6278, 115728, 'Last minute looting?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6278, 115729, 'We prevented their weapon from falling into Ra''s hands. Payment is due.', 2059, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6279, 117646, 'Clearly Ra has launched an attack on this station. Perhaps this security terminal can lead you to the Asgard Command Center so you can get a situation report. ', 2061, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6280, 116343, 'What happened to them?', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6280, 116344, 'They are... Gone. ', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6280, 116345, 'Excellent. But there is still much to do...', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6281, 117863, 'The console looks pretty badly damaged... Still, with a little luck, you should be able to increase the intensity and make Igyn''s plan work...', 2086, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6282, 116361, 'The repairs should hold... You initialize Loki''s algorithm and the machine hums with even greater activity.', 2086, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6283, 116228, 'Commander Thor''s instructions were to use the Prioritization Algorithm on this Consciousness Databank. This will sort through the stored Asgard minds, find those of greatest value, and transmit them to the orbiting starship.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6284, 116232, 'Commander Thor''s instructions were to use the Prioritization Algorithm on this Consciousness Databank. This will sort through the stored Asgard minds, find those of greatest value, and transmit them to the orbiting starship.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6285, 116234, 'Commander Thor''s instructions were to use the Prioritization Algorithm on this Consciousness Databank. This will sort through the stored Asgard minds, find those of greatest value, and transmit them to the orbiting starship.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116508, 'What do you know of the Solocris?', 2095, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116509, 'Nothing substantial...', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116510, 'I have long been searching for it... I have spent months culling through memory databases... I have come to believe that the Solocris is located in the Nox vault here on Yotunheim. Near the center of it.', 2095, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116511, 'In the open?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116512, 'The memories I have accessed indicate that the Nox assisted us by using their cloaking technology to hide the Solocris. There should be a disgiuised control panel there that we can use to alter the phase of the cloak, thus revealing the Solocris.', 2095, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116513, 'Why didn''t you recover it immediately?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116514, 'The attack happened just as I found the storage location. Given the obscurity of the object I did not consider that Ra would have interest in it...', 2095, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116515, 'Anyone can access this data...', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6286, 116516, 'You fear Ra may have done so? This is unlikely...', 2095, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6287, 117928, 'Although it looks like no machine you have ever encountered, you begin to adjust the cloak phase as Loki instructed... You are already planning your escape route off Yotunheim with the Solocris...', 2096, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116683, 'We will wait for them to return.', 2069, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116684, 'They may be under attack.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116685, 'It is possible... But they were aware of the danger.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116686, 'I wish to preserve them.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116687, 'As you wish. Please understand that I cannot wait for you. When the time comes, I will destroy this base. If you are on it, you will perish.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116688, 'I expect nothing less.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116689, '$name$, you are a hero to our people. ', 2069, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6288, 116690, 'Thank you, Ullr. ', 0, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6289, 116753, 'The download stops... You realize that the time it took pushes you toward the edge of getting out alive... You need to get to the gate...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6290, 116840, 'The Databank was damaged by the Mutated Asgard. Repair it.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6291, 117184, 'No Asgard structures should exist within these domes. It is potentially a landing party from the other ship we''ve detected.', 3299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6291, 117185, 'Have you managed to establish contact?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6291, 117186, 'No, their communication systems appear damaged. You will need to make contact with any survivors. Be careful, they will be unable to distinguish healthy Asgard from contaminated.', 3299, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6292, 117188, 'The colony''s records indicate that Gedheim Fjordi was equipped with a matter generator. Hopefully it is still intact.', 3299, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6293, 117409, '. . . You will not save me.', 3408, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6293, 117410, 'I cannot take the risk. This contamination must not spread beyond Pertho.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6293, 117411, 'And what will become of Sif?', 3408, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6293, 117412, 'She will choose to remain with you.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6293, 117413, 'Do not let her. Her mind is too valuable for this plague to destroy.', 3408, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6293, 117414, 'I do not know if I can force her to leave.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6293, 117415, 'But you are capable of doing nothing, letting her die by your inaction? If I cannot be saved, then you must save her.', 3408, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6294, 117347, 'I am sorry you deem Rig''s life less valuable than I do.', 3409, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6294, 117348, 'I cannot risk bringing a highly infected patient onto the ship.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6294, 117349, 'I understand. I will stay with him.', 3409, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6294, 117350, 'You would die. I cannot allow this pointless sacrifice. Rig does not want it. Prepare for beaming.', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6294, 117351, 'No, this is my choice! I will remain with him.', 3409, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6294, 117352, 'Prepare for beaming.', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6295, 117376, 'A grave error has occurred, $name$. I have no signs of infection and have had no contact with the ferals. Freyr will not listen to me.', 3411, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6295, 117377, 'I have a device from Heimdall that will allow me to analyze your genome for traces of infection.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6295, 117378, 'Quickly, now! Prove that I am uninfected so I can be released.', 3411, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6296, 117427, 'Create a duplicate Genetic Analyzer for Commander Freyr.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6297, 117396, 'Collect the consciousness hubs from fallen Asgard.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6298, 117398, 'You quickly begin uploading your mind from your consciousness hub into the computer. Hopefully the transmission will make it to Rekyr''s Starship.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6299, 117429, 'Determine whether Rig can be transported off of the colony.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6300, 117418, 'Help Anvari retrieve his Image Gathering Devices.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6301, 117422, 'You found them all?', 3413, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6301, 117423, 'Yes. Were these really worth risking yourself for?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6301, 117424, 'Of course, $name$. We must know the truth of what happened here. It cannot happen again.', 3413, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6302, 117426, 'Recover Einjar''s data.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6303, 117818, 'Error: The carrier is full.', 2142, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6304, 118181, 'You attempt to jam the Straegis Portal by forcing Straegis Shards into the vortex of energy coming from it.', 2457, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6305, 118169, 'You insert the shards. The Portal begins to shake, but a random burst of energy ejects the shards. You will have to try again with another set of shards.', 2457, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6306, 118170, 'You insert the shards. The Portal begins to shake, and you notice the shards changing form - creating a seal on the Portal itself. Immediately the Portal grows dark. You plan has worked.', 2457, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6307, 119447, 'These Straegis certainly have lived up to your words, Colonel. ', 945, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6307, 119448, 'I don''t relish the phrase "I told you so".', 941, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6307, 119449, 'You do not relish it, but you have used it with annoying frequency since the arrival of your Straegis...', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6307, 119450, 'That is because I''m convinced you''re deaf, Queenie my dear... You always seem to need things repeated...', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6307, 119451, 'Please... Both of you... This infighting grows tiresome... And it does not help us defeat Ra or destroy his minions. However, Dakara may have given us something that might inspire hope... ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6308, 119571, 'This new army of Ra''s has ravaged the galaxy... I have heard of entire Jaffa tribes being slaughtered within hours. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6308, 119572, 'The Asgard Council shares your concern... These creatures show a viral nature not unlike that of the Replicators... ', 777, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6308, 119573, 'You think Ra could take over the entire galaxy?', 2410, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6308, 119574, 'It is a possibility. We must find a means of counteracting the Straegis menace... And we must do this quickly. ', 777, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6308, 119575, 'Perhaps the Dakara discovery is something we should seriously look into?', 431, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6308, 119576, 'Dakara discovery?', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6309, 118511, 'You have successfully disarmed the bomb, saving the shield tower in the process.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6310, 118520, 'Find out what Ra has hidden in the Temple of Ihpet', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119189, 'I request permission to go in.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119190, '<<Playername>>, this is General Hammond. We cannot authorize that at this time... We don''t know what you''ll be facing in there. It could be suicide to go in.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119191, 'General, with all due respect, <<playername>> must go immediately. We do not know how long the door will remain open and through this ritual process we have lost the transmorphing crystal key... This may be our only opportunity. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119192, 'I see.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119193, '<<Playername>> has proven to be a valiant warrior. Given the time concerns, there seems to be little choice. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6332, 120064, '<Input text here.>', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6333, 120066, '<Input text here.>', 715, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6334, 120068, '<Input text here.>', 3574, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119194, 'Fine. But be careful in there. Ra''s people have been working towards something and Ra himself went to great lengths to prevent anyone else from seeing what it was he had inside that temple. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119195, 'The General is quite correct. When you proceed, exercise great caution. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6311, 119196, 'Report back when you can. Good luck.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119197, 'Ra''s return has wreaked havoc on the Galaxy. Many Jaffa see his return as a sign that he is, indeed a God. ', 2323, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119198, 'His army grows with each victory.', 3216, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119199, 'The technology he utilizes is remarkable. But the return of a single System Lord is of little concern to us. ', 777, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119200, 'He is invading worlds, Thor.', 431, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119201, 'His advantages are based on surprise, not technology, Dr. Jackson. The invasions can be overcome, given the proper resources.', 777, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119202, 'Are your Asgard going to provide those resources?', 2323, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119203, 'Currently the Council does not see Ra as a true galactic threat. However, they are watching him closely.', 777, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119204, 'Well, I see him as a galactic threat. How did he get an army so large so quickly?', 2410, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119205, 'He prepared for this, sir - or something like it. There have been reports from several worlds that Jaffa have emerged from stasis - in some cases they have launched immediate surprise attacks. ', 2568, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119206, 'I do not believe Ra is a threat that can be underestimated. We will need to act quickly to countermand him. ', 2323, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6312, 119207, 'Yes, we will... ', 2410, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6313, 118567, 'Find out what Ra has hidden in the Temple of Ihpet', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119258, 'Given that we do not know how long the temple will be open, what do you plan on doing?', 943, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119259, 'I''m going in. Now.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119260, 'I believe you take orders, you do not give them.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119261, 'Queen Anat? 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119262, 'We are all here, <<playername>>, monitoring your progress. It would be wise to wait until reinforcements can arrive before you proceed. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119263, 'It might be too late by then. The Crystal Key has been consumed... The door is open, but we don''t know for how long... This may be our window of opportunity... 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119264, 'Then what are we waiting for? <<Playername>>, get inside. Now. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119265, 'Keep your eyes peeled. Ra Loyalists are determined to get to that rock any way they can - and Ra himself went to great lengths keep the world a secret. Whatever is hidden inside there will be well guarded.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119266, 'I will not fail.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6314, 119267, 'See to it that you do not. 
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119338, 'Your failure on Ihpet has had severe ramifications', 944, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119339, 'Failure?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119340, 'You brought Ra back to life, did you not? Your little walk in the park has brought these attacks directly down upon our heads. Those shields outside are all that protects us from him... ', 944, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119341, 'No one could have predicted what happened in Ihpet... ', 941, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119342, 'A little discretion wouldn''t have hurt... ', 942, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119343, 'Where did Ra have this army stashed... They seem to have come out of nowhere. ', 941, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119344, 'Many have, Colonel. Mostly his army consists of Jaffa he had kept in stasis... Others have seen his return as proof of his divine nature and joined to fight for the cause... Many Jaffa join him, from many worlds... ', 945, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119345, 'Something must be done to stop him - before he comes after us. ', 944, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119346, 'He seems to have other interests... ', 941, 8);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119347, 'Ra has a long memory, Colonel. He will take his revenge. His determination is his greatest asset.', 942, 9);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6315, 119348, 'And his greatest vulnerability.', 945, 10);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119911, 'We''re here to help...', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119912, 'You''re here to help? You?', 2992, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119913, 'You would prefer we left?', 0, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119914, 'No... No... These things are all over the place... We need all hands...', 2992, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119915, 'First stages of an invasion?', 0, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119916, 'No... Ra''s not here to invade, he''s here looking for something. We''ve locked down levels 15 and up, but Ra''s forces are content staying below - searching through our collected off world artifacts.', 2992, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119917, 'No idea what they are after?', 0, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6316, 119918, 'None. ', 2992, 7);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6317, 119904, 'Thank God you''re here! These things are all over the place...', 2992, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6317, 119905, 'Have they hit everything?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6317, 119906, 'Ra''s not here to invade, he''s here looking for something. We''ve locked down levels 15 and up, but Ra''s forces are content staying below - searching through our collected off world artifacts.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6317, 119907, 'Anything specific?', 0, 3);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6317, 119908, 'We don''t know... But we''re pretty certain it''s not an invasion... It''s something else.', 2992, 4);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6317, 119909, 'Interesting...', 0, 5);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6317, 119910, 'Good luck down there. You''ll need it.', 2992, 6);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6318, 118821, 'A team is a permanent organization that can have up to 6 members and a unique name.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6319, 118825, 'A command is a permanent organization that can accept a large number of people. Commands can be created starting at level 10. Commands receive a common vault, a modifiable rank structure, and a unique name.', 0, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6320, 119989, 'The Jaffa who seeks Anat is dead?', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6320, 119990, 'Not yet.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6320, 119991, 'We cannot allow him to reach Anat! You must find him and kill him.', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6321, 119995, 'Have you completed your search of the slave camps?', 2546, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6321, 119996, 'Not yet.', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6321, 119997, 'Time runs short! We''ll need more weapons than we have to rescue Anat.', 2546, 2);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6322, 120023, 'So, do we evacuate now or can you fix it?', 404, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6322, 120024, 'We need a source of additional power to jumpstart the generator. Do we have any naquadah generators here?', 0, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (6322, 120025, 'I think we can spare some.', 404, 2);
