INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (100006, 100006, 'Welcome to the sandbox!
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (100007, 100007, 'I''m an NPC with multiple interactions.
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (100007, 100008, 'In addition to this dialog, I have a dialog for level 10 (or more) players, SGU/Praxis only players, a dialog to accept or complete a test mission, ', NULL, 1);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (100008, 100009, 'Level ten+ test dialog.', NULL, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (100009, 100010, 'This dialog is only visible for SGU players.', NULL, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (100010, 100011, 'This dialog is only visible for Praxis players.', NULL, 0);
INSERT INTO dialog_screens (dialog_id, screen_id, text, speaker_id, index) VALUES (100011, 100012, 'Mission accept test', NULL, 0);
